INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '7-Java Database Connectivity.pdf', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', '{"chunks": [{"id": "CHUNK_001", "text": "What is JDBC?\n• JDBC (Java Database Connectivity) API allows Java programs to connect to databases\n• Database access is the same for all database vendors\n• The JVM uses a JDBC driver to translate generalized JDBC calls into vendor specific database calls", "pages": [1], "end_pos": 192, "summary": "Defines JDBC as a vendor-neutral database connectivity API and introduces the role of JDBC drivers in translation.", "start_pos": 0, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Why JDBC? \n• Platform independent and vendor independent \n• A developer can create JDBC applications without targeting a specific DBMS \n• Java classes in the form of JDBC drivers operate as a software layer between the Java program using JDBC and the actual database \n• Industry standard for database-connectivity between the Java language and a wide range of databases\n• Generic\n• Leverage existing database APIs\n• Simple", "pages": [1], "end_pos": 469, "summary": "Explains motivations for JDBC adoption: portability, abstraction, industry standardization, and simplicity.", "start_pos": 193, "chunk_type": "rationale", "has_examples": false, "main_concepts": ["CONC_001", "CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_003", "text": "JDBC Architecture\nSybase\nDB\nJava\nApplication\nDriverManager\nSybase Driver\nMySQL Driver\nOracle Driver\nMySQL\nDB\nOracle \nDB\n• Java Application connect with the database via the DrirverManager.", "pages": [1], "end_pos": 622, "summary": "Describes JDBC architecture components and their interconnections, highlighting DriverManager''s central role.", "start_pos": 470, "chunk_type": "diagram_description", "has_examples": false, "main_concepts": ["CONC_002", "CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_004", "text": "Connection object \n• The Connection object creates a specific connection with a specific database and enables you to use the JDBC facilities to manage SQL queries \n• Connections represent the client’s connection to the database", "pages": [2], "end_pos": 807, "summary": "Defines Connection as the session object representing client-database connectivity and SQL management capability.", "start_pos": 623, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Connections\n• Has various methods to interact with database factory methods such as \n• createStatement(),\n• prepareStatement(), \n• prepareCall() \n• →creates Statement objects which hold the SQL\n• transaction commands: commit(), rollback() etc\n• get metadata about the database", "pages": [2], "end_pos": 1005, "summary": "Details Connection''s capabilities: statement creation, transaction control, and metadata access.", "start_pos": 808, "chunk_type": "feature_list", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": ["CONC_004", "CONC_005"]}, {"id": "CHUNK_006", "text": "Statement\nObtain connection\nSpecify the SQL you want to execute\nExecute the statement with the SQL\nMake sure correct package is imported \nimport java.sql.Statement;", "pages": [2], "end_pos": 1134, "summary": "Provides step-by-step guidance for using Statement including import, creation, and execution.", "start_pos": 1006, "chunk_type": "usage_guide", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_007", "text": "PreparedStatement\nObtain connection\nSpecify the SQL you want to execute\nExecute \nSpecify the SQL when creating the PreparedStatement", "pages": [2], "end_pos": 1242, "summary": "Outlines PreparedStatement usage workflow emphasizing SQL specification during creation.", "start_pos": 1135, "chunk_type": "usage_guide", "has_examples": false, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_008", "text": "Register the database driver \n• Register corresponding database driver\n• Unique name for each database vendor\nSpecifying database driver obtains the DriverManager\n• System.setProperty(\"jdbc.drivers\", \"driverClassName\")\n• Class.forName(driverClassName)\nOnce a JDBC driver has been loaded, the DriverManager class can be used to create and manage database connections", "pages": [2], "end_pos": 1490, "summary": "Explains JDBC driver registration mechanisms and their relationship to DriverManager initialization.", "start_pos": 1243, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001", "CONC_003"]}, {"id": "CHUNK_009", "text": "getConnection with DriverManager\nDatabase Info\n• URL\n• Username \n• password\nThe database URL specify Jdbc protocol how to connect the database", "pages": [2], "end_pos": 1618, "summary": "Identifies essential connection parameters: URL, username, and password, with emphasis on URL semantics.", "start_pos": 1491, "chunk_type": "configuration", "has_examples": false, "main_concepts": ["CONC_003", "CONC_012"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "Statement vs PreparedStatement\nStatement\nStatement stmt = \nconnection.createStatement();\nString sql= \"UPDATE COFFEES SET \nSALES = 75 WHERE NAME = \n‘Colombian’ \"; \nstmt.executeUpdate(sql);\n\nPreparedStatement\nString sql = \"UPDATE COFFEES\nSET SALES = ? WHERE NAME =\n? “\nPreparedStatement pstmt = \nconnection.prepareStatement(sql\n);\npstmt.setInt (1, 75); \npstmt.setString (2, \"Colombian\");\npstmt.executeUpdate();", "pages": [2], "end_pos": 1930, "summary": "Contrasts Statement and PreparedStatement with side-by-side code examples demonstrating static vs parameterized SQL.", "start_pos": 1619, "chunk_type": "comparison", "has_examples": true, "main_concepts": ["CONC_004", "CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_011", "text": "Prepared Statements - SQL\n• ability to set up a statement once, and then execute it many times with different parameters.\n• replace building ad hoc query strings, and do so in a more efficient manner.", "pages": [2], "end_pos": 2078, "summary": "Highlights PreparedStatement benefits: efficiency through reuse and safety through parameterization.", "start_pos": 1931, "chunk_type": "benefit_summary", "has_examples": false, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_013"]}, {"id": "CHUNK_012", "text": "JDBC – PreparedStatement\n• ? is called placeholder\n• query is parsed only once and only 1 execution plan is created and caches for it\n• executed many times after binding variables\n• MUCH MORE EFFICIENT!", "pages": [2], "end_pos": 2225, "summary": "Emphasizes PreparedStatement''s placeholder mechanism and performance advantages.", "start_pos": 2079, "chunk_type": "feature_summary", "has_examples": false, "main_concepts": ["CONC_005", "CONC_013"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_013", "text": "How to handle result set\n• Access the data in a ResultSet object through a cursor\n• cursor is a pointer that points to one row of data in the ResultSet.\n• Initially, the cursor is positioned before the first row. \n• The method ResultSet.next moves the cursor to the next row. \n• This method returns false if the cursor is positioned after the last row. \n• This method repeatedly calls the ResultSet.next method with a while loop to iterate through all the data in the ResultSet.", "pages": [3], "end_pos": 2490, "summary": "Explains ResultSet navigation using cursor and next() method in iterative loops.", "start_pos": 2226, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_004", "CONC_005"]}, {"id": "CHUNK_014", "text": "ResultSet\n• To examine a ResultSet object, an iterative loop can be set up as follows: \nwhile  (rs.next()) { \n//  examine  a  row  from  the  results\n}\n• A ResultSet object is initially positioned before its first row \n• Execution of next() advances the cursor to point to the next row", "pages": [3], "end_pos": 2665, "summary": "Provides canonical ResultSet iteration pattern and clarifies initial cursor position semantics.", "start_pos": 2491, "chunk_type": "code_pattern", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_015", "text": "Accessor methods\n• Use various accessor methods to inspect individual rows Such methods return the value of the column with a given column number or name \nXxx getXxx(int columnNumber) \nor \nXxx getXxx(String columnName) \n• where Xxx is a type such as int, double, String, Date, etc", "pages": [3], "end_pos": 2835, "summary": "Documents ResultSet accessor method signatures and usage patterns for column retrieval.", "start_pos": 2666, "chunk_type": "api_reference", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_016", "text": "Object Relationship Mapping (ORM) \n• Our design is a simplify version of  Object Relationship Mapping (ORM) \n• Translate and map objects between relational table.\n• Translate the logical representation of the objects into an atomized form that is capable of being stored in the database.\n• Hide the SQL statement\n• Exposes API for other component", "pages": [3], "end_pos": 3040, "summary": "Introduces simplified ORM as object-table mapping that abstracts SQL and exposes clean APIs.", "start_pos": 2836, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_009", "CONC_010"]}, {"id": "CHUNK_017", "text": "For example, \nPet.java and PetDB.java\n• Pet.java is a JavaBean class, which represents a record of Pet table. \n• The Pet class is the model role in MVC Design.\n• PetDB.java is used to mange the Pet.java\n• It support the database CRUD operations\n• Create\n• Retrieve/Search\n• Update\n• Delete", "pages": [3], "end_pos": 3240, "summary": "Illustrates ORM implementation with Pet.java (model) and PetDB.java (DAO) supporting full CRUD.", "start_pos": 3041, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_008", "CONC_009", "CONC_010", "CONC_011"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_018", "text": "package ict.bean;\nimport java.io.Serializable;\npublic class Pet implements Serializable {\nprivate int id;\nprivate String name;\nprivate String specie;\nprivate String owner;\npublic Pet(){}\npublic int getId() { }\npublic void setId(int id) { } \n/*  other getter and setter */\n}\npackage ict.db;\npublic class PetDB {\npublic Connection getConnection()     \npublic void createPetsTable() {}\npublic void dropPetsTable() { }\npublic ArrayList<Pet> getPets() {} \npublic void addRecord(Pet p) { }\npublic boolean deleteRecord(String id) { }\npublic boolean updateRecord(Pet p) { }\n}", "pages": [3], "end_pos": 3640, "summary": "Shows JavaBean (Pet) and DAO (PetDB) source code implementing ORM and CRUD operations.", "start_pos": 3241, "chunk_type": "code_sample", "has_examples": true, "main_concepts": ["CONC_009", "CONC_010", "CONC_011"], "has_definitions": false, "secondary_concepts": ["CONC_003", "CONC_005"]}, {"id": "CHUNK_019", "text": "Connection URL\nSyntax: jdbc:subprotocol name:other stuff\n• \"subprotocol name\" \n• the specific driver used by JDBC to connect to the database\n• Example: odbc if the jdbc-odbc bridge driver is being used \n• \"other_stuff\" - Normally, the data source of the database \n• Example\n• JavaDB / Derby\n• jdbc:derby://localhost/sample \n• Pointbase\n• jdbc:pointbase:server://localhost/sample \n• MySql\n• jdbc:mysql://localhost:3306/sample \"", "pages": [3], "end_pos": 3931, "summary": "Documents JDBC URL syntax with subprotocol and subname components plus vendor-specific examples.", "start_pos": 3641, "chunk_type": "syntax_reference", "has_examples": true, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}], "concepts": [{"id": "CONC_001", "title": "JDBC (Java Database Connectivity)", "aliases": ["Java Database Connectivity API"], "keywords": ["database connectivity", "API", "driver", "vendor independence"], "confidence": 1.0, "difficulty": 3, "description": "JDBC is a Java API that enables Java applications to interact with relational databases in a vendor-neutral manner. It provides a standardized interface for connecting to, querying, and updating databases through JDBC drivers that translate generic JDBC calls into database-specific protocols. JDBC abstracts database access details, allowing developers to write portable database code without targeting specific DBMS implementations. It supports key operations including connection management, SQL statement execution, result set handling, transaction control, and metadata retrieval.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003", "CONC_007"]}, {"id": "CONC_002", "title": "JDBC Driver", "aliases": ["database driver"], "keywords": ["driver manager", "vendor-specific", "translation layer", "registration"], "confidence": 1.0, "difficulty": 4, "description": "A JDBC driver is a Java class that implements the JDBC API to enable communication between a Java application and a specific database management system. It acts as a translation layer, converting JDBC method calls into database-specific network protocols. Drivers are registered via System.setProperty or Class.forName, and are identified by unique class names such as ''com.mysql.jdbc.Driver''. The JVM uses the driver to establish connections, execute statements, and handle results, ensuring database vendor independence at the application level.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_003", "CHUNK_008"], "related_concepts": ["CONC_001", "CONC_003", "CONC_007"]}, {"id": "CONC_003", "title": "Connection", "aliases": ["database connection"], "keywords": ["session", "database URL", "transaction", "metadata"], "confidence": 1.0, "difficulty": 3, "description": "A Connection object represents a session between a Java application and a database. It is obtained via DriverManager.getConnection() using database URL, username, and password. The Connection provides factory methods to create Statement, PreparedStatement, and CallableStatement objects, supports transaction control (commit/rollback), and allows retrieval of database metadata. Connections must be explicitly closed to prevent resource leaks and are central to all JDBC operations.", "concept_type": "component", "extracted_from": ["CHUNK_004", "CHUNK_005", "CHUNK_009"], "related_concepts": ["CONC_001", "CONC_002", "CONC_004", "CONC_005"]}, {"id": "CONC_004", "title": "Statement", "aliases": [], "keywords": ["static SQL", "SQL compilation", "executeQuery", "executeUpdate"], "confidence": 1.0, "difficulty": 3, "description": "A Statement object is used to execute static SQL queries that do not require parameterization. It is created via Connection.createStatement() and supports executeQuery() for SELECT statements (returning ResultSet), executeUpdate() for DML operations (INSERT/UPDATE/DELETE), and execute() for mixed or DDL operations. Each Statement execution compiles the SQL anew, making it less efficient than PreparedStatement for repeated use with varying parameters.", "concept_type": "component", "extracted_from": ["CHUNK_006", "CHUNK_010"], "related_concepts": ["CONC_003", "CONC_005", "CONC_007"]}, {"id": "CONC_005", "title": "PreparedStatement", "aliases": [], "keywords": ["parameterized query", "placeholder", "precompilation", "SQL injection prevention"], "confidence": 1.0, "difficulty": 4, "description": "A PreparedStatement is a precompiled SQL statement that supports parameterized queries using placeholders (''?''). Created via Connection.prepareStatement(), it improves performance by compiling the SQL once and reusing the execution plan across multiple executions with different parameter values. It prevents SQL injection, handles type conversion automatically, and supports setter methods like setString() and setInt(). PreparedStatement is preferred over Statement for dynamic or repeated queries.", "concept_type": "component", "extracted_from": ["CHUNK_007", "CHUNK_011", "CHUNK_012"], "related_concepts": ["CONC_003", "CONC_004", "CONC_007", "CONC_013"]}, {"id": "CONC_006", "title": "ResultSet", "aliases": [], "keywords": ["cursor", "row iteration", "accessor methods", "tabular data"], "confidence": 1.0, "difficulty": 3, "description": "A ResultSet object represents the tabular results of a database query. It maintains a cursor initially positioned before the first row; the next() method advances the cursor row-by-row. ResultSet provides accessor methods (e.g., getString(), getInt()) to retrieve column values by index or name. By default, it is forward-only and read-only. ResultSet is returned by executeQuery() and must be iterated using while(rs.next()) to process all rows.", "concept_type": "object", "extracted_from": ["CHUNK_013", "CHUNK_014", "CHUNK_015"], "related_concepts": ["CONC_004", "CONC_005", "CONC_007"]}, {"id": "CONC_007", "title": "JDBC Architecture", "aliases": [], "keywords": ["layered architecture", "DriverManager", "abstraction", "portability"], "confidence": 1.0, "difficulty": 4, "description": "JDBC architecture consists of four layers: (1) Java Application, (2) JDBC API, (3) JDBC Driver Manager, and (4) Database-specific JDBC Driver. The application uses JDBC API interfaces (Connection, Statement, ResultSet). DriverManager loads and manages drivers, routing calls to the appropriate vendor driver. The driver translates JDBC calls into native database protocols. This layered design ensures portability, abstraction, and separation of concerns between application logic and database implementation.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_001", "CONC_002", "CONC_003"]}, {"id": "CONC_008", "title": "Object-Relational Mapping (ORM)", "aliases": ["simplified ORM"], "keywords": ["mapping", "JavaBean", "DAO", "abstraction", "CRUD"], "confidence": 1.0, "difficulty": 4, "description": "ORM is a programming technique that maps object-oriented domain models to relational database schemas. In this context, it refers to a simplified ORM pattern where JavaBean classes (e.g., Pet.java) represent database tables, and DAO classes (e.g., PetDB.java) encapsulate CRUD operations. ORM abstracts SQL, enables type-safe data access, and supports relationships between entities. While JDBC provides low-level control, ORM frameworks like Hibernate build upon it to automate mapping and persistence.", "concept_type": "theory", "extracted_from": ["CHUNK_016", "CHUNK_017"], "related_concepts": ["CONC_009", "CONC_010", "CONC_011"]}, {"id": "CONC_009", "title": "JavaBean", "aliases": ["bean class"], "keywords": ["DTO", "MVC model", "serialization", "getter/setter"], "confidence": 1.0, "difficulty": 2, "description": "A JavaBean is a reusable, serializable Java class following conventions: private fields with public getter/setter methods, a no-argument constructor, and implementation of java.io.Serializable. In JDBC contexts, JavaBeans (e.g., Pet.java) model database records—each field corresponds to a table column. They serve as data transfer objects (DTOs) between database layers and business logic, enabling clean separation in MVC architectures.", "concept_type": "object", "extracted_from": ["CHUNK_016", "CHUNK_017", "CHUNK_018"], "related_concepts": ["CONC_008", "CONC_010", "CONC_011"]}, {"id": "CONC_010", "title": "DAO (Data Access Object)", "aliases": ["PetDB", "data access layer"], "keywords": ["abstraction", "CRUD", "separation of concerns", "persistence layer"], "confidence": 1.0, "difficulty": 3, "description": "A DAO is a design pattern that abstracts and encapsulates database access logic. In this material, PetDB.java exemplifies a DAO: it manages database connections, executes CRUD operations on the Pet table, and returns JavaBean instances. DAO separates persistence logic from business logic, improving testability, maintainability, and database independence. It typically exposes methods like addRecord(), getPets(), updateRecord(), and deleteRecord(), hiding SQL implementation details.", "concept_type": "pattern", "extracted_from": ["CHUNK_016", "CHUNK_017", "CHUNK_018"], "related_concepts": ["CONC_008", "CONC_009", "CONC_011"]}, {"id": "CONC_011", "title": "CRUD Operations", "aliases": ["create-read-update-delete"], "keywords": ["data manipulation", "INSERT", "SELECT", "UPDATE", "DELETE"], "confidence": 1.0, "difficulty": 2, "description": "CRUD stands for Create, Retrieve (or Read), Update, and Delete—the four fundamental data manipulation operations supported by persistent storage systems. In JDBC, these map to SQL INSERT, SELECT, UPDATE, and DELETE statements. The PetDB class implements CRUD via methods like addRecord(), getPets(), updateRecord(), and deleteRecord(). Each operation interacts with the database through Connection and PreparedStatement objects and returns appropriate data structures or status indicators.", "concept_type": "process", "extracted_from": ["CHUNK_016", "CHUNK_017", "CHUNK_018"], "related_concepts": ["CONC_008", "CONC_010", "CONC_005"]}, {"id": "CONC_012", "title": "Database URL", "aliases": ["JDBC URL"], "keywords": ["connection string", "subprotocol", "JDBC protocol", "host", "port"], "confidence": 1.0, "difficulty": 3, "description": "A JDBC database URL is a string that specifies how to connect to a database, following the syntax ''jdbc:subprotocol:subname''. The ''subprotocol'' identifies the driver (e.g., ''mysql'', ''derby''), and ''subname'' contains connection details like host, port, and database name. Examples include ''jdbc:mysql://localhost:3306/sample'' and ''jdbc:derby://localhost/sample''. The URL is passed to DriverManager.getConnection() along with credentials to establish a Connection.", "concept_type": "object", "extracted_from": ["CHUNK_009", "CHUNK_019"], "related_concepts": ["CONC_003", "CONC_002"]}, {"id": "CONC_013", "title": "Placeholder", "aliases": [], "keywords": ["parameter binding", "setter methods", "SQL injection", "index-based"], "confidence": 1.0, "difficulty": 3, "description": "A placeholder is a ''?'' character in a PreparedStatement SQL string that represents a parameter to be bound at execution time. Placeholders enable safe, efficient parameter substitution without string concatenation. Each placeholder is assigned an integer index starting from 1, and corresponding setter methods (e.g., setString(1, value)) bind values before execution. This mechanism prevents SQL injection and allows query plan reuse.", "concept_type": "object", "extracted_from": ["CHUNK_007", "CHUNK_011", "CHUNK_012"], "related_concepts": ["CONC_005", "CONC_006"]}], "relationships": [{"id": "REL_001", "type": "implements", "source": "CONC_001", "target": "CONC_007", "evidence": "JDBC is realized through its layered architecture.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "part_of", "source": "CONC_002", "target": "CONC_007", "evidence": "JDBC Driver is a core component within the JDBC architecture.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "part_of", "source": "CONC_003", "target": "CONC_007", "evidence": "Connection is a foundational element of the JDBC architecture.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "produces", "source": "CONC_004", "target": "CONC_003", "evidence": "Connection creates Statement objects via createStatement().", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "produces", "source": "CONC_005", "target": "CONC_003", "evidence": "Connection creates PreparedStatement objects via prepareStatement().", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "produces", "source": "CONC_006", "target": "CONC_004", "evidence": "executeQuery() on Statement returns a ResultSet.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "produces", "source": "CONC_006", "target": "CONC_005", "evidence": "executeQuery() on PreparedStatement returns a ResultSet.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "example_of", "source": "CONC_008", "target": "CONC_009", "evidence": "JavaBean (Pet.java) is a concrete example of the ORM pattern.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "example_of", "source": "CONC_008", "target": "CONC_010", "evidence": "DAO (PetDB.java) implements the ORM pattern''s persistence layer.", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "manages", "source": "CONC_010", "target": "CONC_009", "evidence": "PetDB.java manages Pet.java instances and their database persistence.", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "part_of", "source": "CONC_011", "target": "CONC_010", "evidence": "CRUD operations are implemented by the DAO pattern.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "requires", "source": "CONC_012", "target": "CONC_003", "evidence": "Connection requires a database URL to establish connectivity.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "part_of", "source": "CONC_013", "target": "CONC_005", "evidence": "Placeholders are syntactic elements within PreparedStatement SQL.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 20, "missing_links": [], "coverage_score": 1.0, "total_concepts": 13, "consistency_score": 1.0, "total_relationships": 13}, "processing_notes": {"ambiguous_terms": [], "suggested_review": []}, "document_metadata": {"title": "Java Database Connectivity (JDBC)", "language": "English", "main_topic": "Enterprise System Development", "difficulty_level": "Intermediate", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "JDBC (Java Database Connectivity)", "context": "What is JDBC?", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "JDBC (Java Database Connectivity)", "context": "Why JDBC?", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "JDBC Driver", "context": "The JVM uses a JDBC driver to translate generalized JDBC calls into vendor specific database calls", "chunk_id": "CHUNK_001", "positions": [120], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "JDBC Driver", "context": "DriverManager\nSybase Driver\nMySQL Driver\nOracle Driver", "chunk_id": "CHUNK_003", "positions": [65], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Connection", "context": "Connection object", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Connection", "context": "Connections", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Statement", "context": "Statement", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "PreparedStatement", "context": "PreparedStatement", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "PreparedStatement", "context": "PreparedStatement\nString sql = \"UPDATE COFFEES\nSET SALES = ? WHERE NAME =\n? \"", "chunk_id": "CHUNK_010", "positions": [100], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "ResultSet", "context": "How to handle result set", "chunk_id": "CHUNK_013", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "JDBC Architecture", "context": "What is JDBC?", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "JDBC Architecture", "context": "Why JDBC?", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_007", "importance": "secondary"}, {"concept": "Object-Relational Mapping (ORM)", "context": "Object Relationship Mapping (ORM)", "chunk_id": "CHUNK_016", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "JavaBean", "context": "Pet.java is a JavaBean class, which represents a record of Pet table.", "chunk_id": "CHUNK_017", "positions": [45], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "DAO (Data Access Object)", "context": "PetDB.java is used to mange the Pet.java", "chunk_id": "CHUNK_017", "positions": [90], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "CRUD Operations", "context": "It support the database CRUD operations", "chunk_id": "CHUNK_017", "positions": [130], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "Database URL", "context": "Database Info", "chunk_id": "CHUNK_009", "positions": [0], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Placeholder", "context": "? is called placeholder", "chunk_id": "CHUNK_012", "positions": [20], "concept_id": "CONC_013", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 22, "difficulty_score": 7, "total_structures": 18, "total_applications": 16}', '"[{\"id\":\"CHUNK_001\",\"text\":\"What is JDBC?\\n• JDBC (Java Database Connectivity) API allows Java programs to connect to databases\\n• Database access is the same for all database vendors\\n• The JVM uses a JDBC driver to translate generalized JDBC calls into vendor specific database calls\",\"pages\":[1],\"start_pos\":0,\"end_pos\":192,\"summary\":\"Defines JDBC as a vendor-neutral database connectivity API and introduces the role of JDBC drivers in translation.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"Why JDBC? \\n• Platform independent and vendor independent \\n• A developer can create JDBC applications without targeting a specific DBMS \\n• Java classes in the form of JDBC drivers operate as a software layer between the Java program using JDBC and the actual database \\n• Industry standard for database-connectivity between the Java language and a wide range of databases\\n• Generic\\n• Leverage existing database APIs\\n• Simple\",\"pages\":[1],\"start_pos\":193,\"end_pos\":469,\"summary\":\"Explains motivations for JDBC adoption: portability, abstraction, industry standardization, and simplicity.\",\"chunk_type\":\"rationale\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_003\",\"text\":\"JDBC Architecture\\nSybase\\nDB\\nJava\\nApplication\\nDriverManager\\nSybase Driver\\nMySQL Driver\\nOracle Driver\\nMySQL\\nDB\\nOracle \\nDB\\n• Java Application connect with the database via the DrirverManager.\",\"pages\":[1],\"start_pos\":470,\"end_pos\":622,\"summary\":\"Describes JDBC architecture components and their interconnections, highlighting DriverManager''s central role.\",\"chunk_type\":\"diagram_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\",\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_004\",\"text\":\"Connection object \\n• The Connection object creates a specific connection with a specific database and enables you to use the JDBC facilities to manage SQL queries \\n• Connections represent the client’s connection to the database\",\"pages\":[2],\"start_pos\":623,\"end_pos\":807,\"summary\":\"Defines Connection as the session object representing client-database connectivity and SQL management capability.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_005\",\"text\":\"Connections\\n• Has various methods to interact with database factory methods such as \\n• createStatement(),\\n• prepareStatement(), \\n• prepareCall() \\n• →creates Statement objects which hold the SQL\\n• transaction commands: commit(), rollback() etc\\n• get metadata about the database\",\"pages\":[2],\"start_pos\":808,\"end_pos\":1005,\"summary\":\"Details Connection''s capabilities: statement creation, transaction control, and metadata access.\",\"chunk_type\":\"feature_list\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CHUNK_006\",\"text\":\"Statement\\nObtain connection\\nSpecify the SQL you want to execute\\nExecute the statement with the SQL\\nMake sure correct package is imported \\nimport java.sql.Statement;\",\"pages\":[2],\"start_pos\":1006,\"end_pos\":1134,\"summary\":\"Provides step-by-step guidance for using Statement including import, creation, and execution.\",\"chunk_type\":\"usage_guide\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_007\",\"text\":\"PreparedStatement\\nObtain connection\\nSpecify the SQL you want to execute\\nExecute \\nSpecify the SQL when creating the PreparedStatement\",\"pages\":[2],\"start_pos\":1135,\"end_pos\":1242,\"summary\":\"Outlines PreparedStatement usage workflow emphasizing SQL specification during creation.\",\"chunk_type\":\"usage_guide\",\"has_examples\":false,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_008\",\"text\":\"Register the database driver \\n• Register corresponding database driver\\n• Unique name for each database vendor\\nSpecifying database driver obtains the DriverManager\\n• System.setProperty(\\\"jdbc.drivers\\\", \\\"driverClassName\\\")\\n• Class.forName(driverClassName)\\nOnce a JDBC driver has been loaded, the DriverManager class can be used to create and manage database connections\",\"pages\":[2],\"start_pos\":1243,\"end_pos\":1490,\"summary\":\"Explains JDBC driver registration mechanisms and their relationship to DriverManager initialization.\",\"chunk_type\":\"procedure\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CHUNK_009\",\"text\":\"getConnection with DriverManager\\nDatabase Info\\n• URL\\n• Username \\n• password\\nThe database URL specify Jdbc protocol how to connect the database\",\"pages\":[2],\"start_pos\":1491,\"end_pos\":1618,\"summary\":\"Identifies essential connection parameters: URL, username, and password, with emphasis on URL semantics.\",\"chunk_type\":\"configuration\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\",\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_010\",\"text\":\"Statement vs PreparedStatement\\nStatement\\nStatement stmt = \\nconnection.createStatement();\\nString sql= \\\"UPDATE COFFEES SET \\nSALES = 75 WHERE NAME = \\n‘Colombian’ \\\"; \\nstmt.executeUpdate(sql);\\n\\nPreparedStatement\\nString sql = \\\"UPDATE COFFEES\\nSET SALES = ? WHERE NAME =\\n? “\\nPreparedStatement pstmt = \\nconnection.prepareStatement(sql\\n);\\npstmt.setInt (1, 75); \\npstmt.setString (2, \\\"Colombian\\\");\\npstmt.executeUpdate();\",\"pages\":[2],\"start_pos\":1619,\"end_pos\":1930,\"summary\":\"Contrasts Statement and PreparedStatement with side-by-side code examples demonstrating static vs parameterized SQL.\",\"chunk_type\":\"comparison\",\"has_examples\":true,\"main_concepts\":[\"CONC_004\",\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_011\",\"text\":\"Prepared Statements - SQL\\n• ability to set up a statement once, and then execute it many times with different parameters.\\n• replace building ad hoc query strings, and do so in a more efficient manner.\",\"pages\":[2],\"start_pos\":1931,\"end_pos\":2078,\"summary\":\"Highlights PreparedStatement benefits: efficiency through reuse and safety through parameterization.\",\"chunk_type\":\"benefit_summary\",\"has_examples\":false,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_013\"]},{\"id\":\"CHUNK_012\",\"text\":\"JDBC – PreparedStatement\\n• ? is called placeholder\\n• query is parsed only once and only 1 execution plan is created and caches for it\\n• executed many times after binding variables\\n• MUCH MORE EFFICIENT!\",\"pages\":[2],\"start_pos\":2079,\"end_pos\":2225,\"summary\":\"Emphasizes PreparedStatement''s placeholder mechanism and performance advantages.\",\"chunk_type\":\"feature_summary\",\"has_examples\":false,\"main_concepts\":[\"CONC_005\",\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_013\",\"text\":\"How to handle result set\\n• Access the data in a ResultSet object through a cursor\\n• cursor is a pointer that points to one row of data in the ResultSet.\\n• Initially, the cursor is positioned before the first row. \\n• The method ResultSet.next moves the cursor to the next row. \\n• This method returns false if the cursor is positioned after the last row. \\n• This method repeatedly calls the ResultSet.next method with a while loop to iterate through all the data in the ResultSet.\",\"pages\":[3],\"start_pos\":2226,\"end_pos\":2490,\"summary\":\"Explains ResultSet navigation using cursor and next() method in iterative loops.\",\"chunk_type\":\"procedure\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CHUNK_014\",\"text\":\"ResultSet\\n• To examine a ResultSet object, an iterative loop can be set up as follows: \\nwhile  (rs.next()) { \\n//  examine  a  row  from  the  results\\n}\\n• A ResultSet object is initially positioned before its first row \\n• Execution of next() advances the cursor to point to the next row\",\"pages\":[3],\"start_pos\":2491,\"end_pos\":2665,\"summary\":\"Provides canonical ResultSet iteration pattern and clarifies initial cursor position semantics.\",\"chunk_type\":\"code_pattern\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_015\",\"text\":\"Accessor methods\\n• Use various accessor methods to inspect individual rows Such methods return the value of the column with a given column number or name \\nXxx getXxx(int columnNumber) \\nor \\nXxx getXxx(String columnName) \\n• where Xxx is a type such as int, double, String, Date, etc\",\"pages\":[3],\"start_pos\":2666,\"end_pos\":2835,\"summary\":\"Documents ResultSet accessor method signatures and usage patterns for column retrieval.\",\"chunk_type\":\"api_reference\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_016\",\"text\":\"Object Relationship Mapping (ORM) \\n• Our design is a simplify version of  Object Relationship Mapping (ORM) \\n• Translate and map objects between relational table.\\n• Translate the logical representation of the objects into an atomized form that is capable of being stored in the database.\\n• Hide the SQL statement\\n• Exposes API for other component\",\"pages\":[3],\"start_pos\":2836,\"end_pos\":3040,\"summary\":\"Introduces simplified ORM as object-table mapping that abstracts SQL and exposes clean APIs.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_009\",\"CONC_010\"]},{\"id\":\"CHUNK_017\",\"text\":\"For example, \\nPet.java and PetDB.java\\n• Pet.java is a JavaBean class, which represents a record of Pet table. \\n• The Pet class is the model role in MVC Design.\\n• PetDB.java is used to mange the Pet.java\\n• It support the database CRUD operations\\n• Create\\n• Retrieve/Search\\n• Update\\n• Delete\",\"pages\":[3],\"start_pos\":3041,\"end_pos\":3240,\"summary\":\"Illustrates ORM implementation with Pet.java (model) and PetDB.java (DAO) supporting full CRUD.\",\"chunk_type\":\"example\",\"has_examples\":true,\"main_concepts\":[\"CONC_008\",\"CONC_009\",\"CONC_010\",\"CONC_011\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_018\",\"text\":\"package ict.bean;\\nimport java.io.Serializable;\\npublic class Pet implements Serializable {\\nprivate int id;\\nprivate String name;\\nprivate String specie;\\nprivate String owner;\\npublic Pet(){}\\npublic int getId() { }\\npublic void setId(int id) { } \\n/*  other getter and setter */\\n}\\npackage ict.db;\\npublic class PetDB {\\npublic Connection getConnection()     \\npublic void createPetsTable() {}\\npublic void dropPetsTable() { }\\npublic ArrayList<Pet> getPets() {} \\npublic void addRecord(Pet p) { }\\npublic boolean deleteRecord(String id) { }\\npublic boolean updateRecord(Pet p) { }\\n}\",\"pages\":[3],\"start_pos\":3241,\"end_pos\":3640,\"summary\":\"Shows JavaBean (Pet) and DAO (PetDB) source code implementing ORM and CRUD operations.\",\"chunk_type\":\"code_sample\",\"has_examples\":true,\"main_concepts\":[\"CONC_009\",\"CONC_010\",\"CONC_011\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_003\",\"CONC_005\"]},{\"id\":\"CHUNK_019\",\"text\":\"Connection URL\\nSyntax: jdbc:subprotocol name:other stuff\\n• \\\"subprotocol name\\\" \\n• the specific driver used by JDBC to connect to the database\\n• Example: odbc if the jdbc-odbc bridge driver is being used \\n• \\\"other_stuff\\\" - Normally, the data source of the database \\n• Example\\n• JavaDB / Derby\\n• jdbc:derby://localhost/sample \\n• Pointbase\\n• jdbc:pointbase:server://localhost/sample \\n• MySql\\n• jdbc:mysql://localhost:3306/sample \\\"\",\"pages\":[3],\"start_pos\":3641,\"end_pos\":3931,\"summary\":\"Documents JDBC URL syntax with subprotocol and subname components plus vendor-specific examples.\",\"chunk_type\":\"syntax_reference\",\"has_examples\":true,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"JDBC (Java Database Connectivity)\",\"aliases\":[\"Java Database Connectivity API\"],\"keywords\":[\"database connectivity\",\"API\",\"driver\",\"vendor independence\"],\"confidence\":1,\"difficulty\":3,\"description\":\"JDBC is a Java API that enables Java applications to interact with relational databases in a vendor-neutral manner. It provides a standardized interface for connecting to, querying, and updating databases through JDBC drivers that translate generic JDBC calls into database-specific protocols. JDBC abstracts database access details, allowing developers to write portable database code without targeting specific DBMS implementations. It supports key operations including connection management, SQL statement execution, result set handling, transaction control, and metadata retrieval.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_002\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_007\"]},{\"id\":\"CONC_002\",\"title\":\"JDBC Driver\",\"aliases\":[\"database driver\"],\"keywords\":[\"driver manager\",\"vendor-specific\",\"translation layer\",\"registration\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A JDBC driver is a Java class that implements the JDBC API to enable communication between a Java application and a specific database management system. It acts as a translation layer, converting JDBC method calls into database-specific network protocols. Drivers are registered via System.setProperty or Class.forName, and are identified by unique class names such as ''com.mysql.jdbc.Driver''. The JVM uses the driver to establish connections, execute statements, and handle results, ensuring database vendor independence at the application level.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_003\",\"CHUNK_008\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\",\"CONC_007\"]},{\"id\":\"CONC_003\",\"title\":\"Connection\",\"aliases\":[\"database connection\"],\"keywords\":[\"session\",\"database URL\",\"transaction\",\"metadata\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A Connection object represents a session between a Java application and a database. It is obtained via DriverManager.getConnection() using database URL, username, and password. The Connection provides factory methods to create Statement, PreparedStatement, and CallableStatement objects, supports transaction control (commit/rollback), and allows retrieval of database metadata. Connections must be explicitly closed to prevent resource leaks and are central to all JDBC operations.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_005\",\"CHUNK_009\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_004\",\"title\":\"Statement\",\"aliases\":[],\"keywords\":[\"static SQL\",\"SQL compilation\",\"executeQuery\",\"executeUpdate\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A Statement object is used to execute static SQL queries that do not require parameterization. It is created via Connection.createStatement() and supports executeQuery() for SELECT statements (returning ResultSet), executeUpdate() for DML operations (INSERT/UPDATE/DELETE), and execute() for mixed or DDL operations. Each Statement execution compiles the SQL anew, making it less efficient than PreparedStatement for repeated use with varying parameters.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_006\",\"CHUNK_010\"],\"related_concepts\":[\"CONC_003\",\"CONC_005\",\"CONC_007\"]},{\"id\":\"CONC_005\",\"title\":\"PreparedStatement\",\"aliases\":[],\"keywords\":[\"parameterized query\",\"placeholder\",\"precompilation\",\"SQL injection prevention\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A PreparedStatement is a precompiled SQL statement that supports parameterized queries using placeholders (''?''). Created via Connection.prepareStatement(), it improves performance by compiling the SQL once and reusing the execution plan across multiple executions with different parameter values. It prevents SQL injection, handles type conversion automatically, and supports setter methods like setString() and setInt(). PreparedStatement is preferred over Statement for dynamic or repeated queries.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_007\",\"CHUNK_011\",\"CHUNK_012\"],\"related_concepts\":[\"CONC_003\",\"CONC_004\",\"CONC_007\",\"CONC_013\"]},{\"id\":\"CONC_006\",\"title\":\"ResultSet\",\"aliases\":[],\"keywords\":[\"cursor\",\"row iteration\",\"accessor methods\",\"tabular data\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A ResultSet object represents the tabular results of a database query. It maintains a cursor initially positioned before the first row; the next() method advances the cursor row-by-row. ResultSet provides accessor methods (e.g., getString(), getInt()) to retrieve column values by index or name. By default, it is forward-only and read-only. ResultSet is returned by executeQuery() and must be iterated using while(rs.next()) to process all rows.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_013\",\"CHUNK_014\",\"CHUNK_015\"],\"related_concepts\":[\"CONC_004\",\"CONC_005\",\"CONC_007\"]},{\"id\":\"CONC_007\",\"title\":\"JDBC Architecture\",\"aliases\":[],\"keywords\":[\"layered architecture\",\"DriverManager\",\"abstraction\",\"portability\"],\"confidence\":1,\"difficulty\":4,\"description\":\"JDBC architecture consists of four layers: (1) Java Application, (2) JDBC API, (3) JDBC Driver Manager, and (4) Database-specific JDBC Driver. The application uses JDBC API interfaces (Connection, Statement, ResultSet). DriverManager loads and manages drivers, routing calls to the appropriate vendor driver. The driver translates JDBC calls into native database protocols. This layered design ensures portability, abstraction, and separation of concerns between application logic and database implementation.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_002\",\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\"]},{\"id\":\"CONC_008\",\"title\":\"Object-Relational Mapping (ORM)\",\"aliases\":[\"simplified ORM\"],\"keywords\":[\"mapping\",\"JavaBean\",\"DAO\",\"abstraction\",\"CRUD\"],\"confidence\":1,\"difficulty\":4,\"description\":\"ORM is a programming technique that maps object-oriented domain models to relational database schemas. In this context, it refers to a simplified ORM pattern where JavaBean classes (e.g., Pet.java) represent database tables, and DAO classes (e.g., PetDB.java) encapsulate CRUD operations. ORM abstracts SQL, enables type-safe data access, and supports relationships between entities. While JDBC provides low-level control, ORM frameworks like Hibernate build upon it to automate mapping and persistence.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_016\",\"CHUNK_017\"],\"related_concepts\":[\"CONC_009\",\"CONC_010\",\"CONC_011\"]},{\"id\":\"CONC_009\",\"title\":\"JavaBean\",\"aliases\":[\"bean class\"],\"keywords\":[\"DTO\",\"MVC model\",\"serialization\",\"getter/setter\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A JavaBean is a reusable, serializable Java class following conventions: private fields with public getter/setter methods, a no-argument constructor, and implementation of java.io.Serializable. In JDBC contexts, JavaBeans (e.g., Pet.java) model database records—each field corresponds to a table column. They serve as data transfer objects (DTOs) between database layers and business logic, enabling clean separation in MVC architectures.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_016\",\"CHUNK_017\",\"CHUNK_018\"],\"related_concepts\":[\"CONC_008\",\"CONC_010\",\"CONC_011\"]},{\"id\":\"CONC_010\",\"title\":\"DAO (Data Access Object)\",\"aliases\":[\"PetDB\",\"data access layer\"],\"keywords\":[\"abstraction\",\"CRUD\",\"separation of concerns\",\"persistence layer\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A DAO is a design pattern that abstracts and encapsulates database access logic. In this material, PetDB.java exemplifies a DAO: it manages database connections, executes CRUD operations on the Pet table, and returns JavaBean instances. DAO separates persistence logic from business logic, improving testability, maintainability, and database independence. It typically exposes methods like addRecord(), getPets(), updateRecord(), and deleteRecord(), hiding SQL implementation details.\",\"concept_type\":\"pattern\",\"extracted_from\":[\"CHUNK_016\",\"CHUNK_017\",\"CHUNK_018\"],\"related_concepts\":[\"CONC_008\",\"CONC_009\",\"CONC_011\"]},{\"id\":\"CONC_011\",\"title\":\"CRUD Operations\",\"aliases\":[\"create-read-update-delete\"],\"keywords\":[\"data manipulation\",\"INSERT\",\"SELECT\",\"UPDATE\",\"DELETE\"],\"confidence\":1,\"difficulty\":2,\"description\":\"CRUD stands for Create, Retrieve (or Read), Update, and Delete—the four fundamental data manipulation operations supported by persistent storage systems. In JDBC, these map to SQL INSERT, SELECT, UPDATE, and DELETE statements. The PetDB class implements CRUD via methods like addRecord(), getPets(), updateRecord(), and deleteRecord(). Each operation interacts with the database through Connection and PreparedStatement objects and returns appropriate data structures or status indicators.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_016\",\"CHUNK_017\",\"CHUNK_018\"],\"related_concepts\":[\"CONC_008\",\"CONC_010\",\"CONC_005\"]},{\"id\":\"CONC_012\",\"title\":\"Database URL\",\"aliases\":[\"JDBC URL\"],\"keywords\":[\"connection string\",\"subprotocol\",\"JDBC protocol\",\"host\",\"port\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A JDBC database URL is a string that specifies how to connect to a database, following the syntax ''jdbc:subprotocol:subname''. The ''subprotocol'' identifies the driver (e.g., ''mysql'', ''derby''), and ''subname'' contains connection details like host, port, and database name. Examples include ''jdbc:mysql://localhost:3306/sample'' and ''jdbc:derby://localhost/sample''. The URL is passed to DriverManager.getConnection() along with credentials to establish a Connection.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_009\",\"CHUNK_019\"],\"related_concepts\":[\"CONC_003\",\"CONC_002\"]},{\"id\":\"CONC_013\",\"title\":\"Placeholder\",\"aliases\":[],\"keywords\":[\"parameter binding\",\"setter methods\",\"SQL injection\",\"index-based\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A placeholder is a ''?'' character in a PreparedStatement SQL string that represents a parameter to be bound at execution time. Placeholders enable safe, efficient parameter substitution without string concatenation. Each placeholder is assigned an integer index starting from 1, and corresponding setter methods (e.g., setString(1, value)) bind values before execution. This mechanism prevents SQL injection and allows query plan reuse.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_007\",\"CHUNK_011\",\"CHUNK_012\"],\"related_concepts\":[\"CONC_005\",\"CONC_006\"]}]"',