INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'Lecture 6 Event and Modularization.pptx', '3379edcbeeff9688ed8fca4310b051da982376435f31c355279da028540ffa40', '{"chunks": [{"id": "CHUNK_002", "text": "ABAP is an event-driven language\nThis means that the general flow of an ABAP program is controlled by external event\nThe system always starts a processing block when the corresponding event occurs\nWhat is a processing block?\nYou can define processing block in your ABAP program by using event keyword \nAll statements between two event keywords or between an event keyword and a FORM statement form a processing block\nWhen an event occurs, the system processes the processing block after the corresponding event keyword\nEach statement in an ABAP program is part of a processing block or a subroutine", "pages": [2], "end_pos": 598, "summary": "Defines ABAP as event-driven and introduces the core concept of processing blocks, including their definition, scope, and execution semantics.", "start_pos": 204, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "INITIALIZATION\nPoint before the selection screen is displayed\nAT SELECTION-SCREEN\nPoint after processing user input on the selection screen while the selection screen is still active\nSTART-OF-SELECTION\nPoint after processing the selection screen\nGET <table>\nPoint at which the logical database offers a  line of the database table <table>\nEND-OF-SELECTION\nPoint after processing all lines offered logical database", "pages": [3], "end_pos": 952, "summary": "Lists fundamental ABAP event keywords with concise descriptions of their timing and purpose in report processing.", "start_pos": 599, "chunk_type": "reference", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Event occurring during processing of output list of a report:\nTOP-OF-PAGE - Point during list processing when a new page is started\nEND-OF-PAGE - Point during list processing when a page is ended\nEvent keyword to write a program for interactive reporting:\nAT LINE-SELECTION - Point at which the user selects a line\nAT USER-COMMAND - Point at which the user presses a function key or enters a command in the command  field\nAT PF<nn> - Point at which the user presses the function key with the function code PF<n>", "pages": [4], "end_pos": 1322, "summary": "Documents event keywords specific to list output and interactive reporting, extending the set of ABAP events beyond basic report lifecycle.", "start_pos": 953, "chunk_type": "reference", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "When you start a program in which a selection screen is defined (either in the program itself or in the linked logical database program), the system normally processes this selection screen first\nIf you want to execute a processing block before the selection screen is processed, you can assign it to the event keyword INITIALIZATION\nExample:\nPARAMETERS airlinet TYPE spfli-carrid DEFAULT ''AA''. PARAMETERS airline? TYPE spfli-carrid. Output | INITIALIZATION. | ® | a@irline2 = \"LH''. AIRLINE1 [aa | AIRLINE2 6\nPARAMETERS airlinet TYPE spfli-carrid DEFAULT ‘AA‘, PARAMETERS airline? TYPE spflt-carrid, INITIALIZATION, airline2 @ ‘ZH!''", "pages": [5], "end_pos": 1821, "summary": "Explains the INITIALIZATION event with practical usage and includes a concrete code example demonstrating early initialization of selection screen parameters.", "start_pos": 1323, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_006", "text": "The event keyword AT SELECTION-SCREEN provides you with several possibilities to carry out processing blocks while the system is processing the selection screen\nTo react on different events, that can occur when the selection screen is processed, the keyword AT SELECTION-SCREEN has various options:\nAT SELECTION-SCREEN ON <field>.\nAT SELECTION-SCREEN ON END OF <seltab>.\nAT SELECTION-SCREEN ON VALUE-REQUEST FOR <field>.\nAT SELECTION-SCREEN ON HELP-REQUEST FOR <field>.\nAT SELECTION-SCREEN ON RADIOBUTTON GROUP <radi>.\nAT SELECTION-SCREEN ON BLOCK <block>.\nAT SELECTION-SCREEN OUTPUT.", "pages": [6], "end_pos": 2249, "summary": "Details advanced variants of the AT SELECTION-SCREEN event for fine-grained control over selection screen processing, including field-specific and UI-element-specific triggers.", "start_pos": 1822, "chunk_type": "reference", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "Example:\nSCREEN-GROUP1\nWhen the user selects the radio button, the runtime environment triggers the event AT SELECTION-SCREEN.\nPARAMETERS option1 GROUP rbg DEFAULT ''X'' USER-COMMAND ucom. PARAMETERS option? GROUP rbg. PARAMETERS carrid TYPE spfli-carrid MODIF ID sci. PARAMETERS connid TYPE spfli-connid MODIF ID sc2. SCREEN- GROUP1 AT SELECTION-SCREEN OUTPUT. | Output = LOOP AT SCREEN. | ® CASE ''X''. | fay WHEN optioni. @OPTION1 IF screen-groupi EQ ''SCc2''. i screen-active = 0. CARRID i of ENDIF. : 6 WHEN option2. sis iE IF screen-groupi EQ ''SCi'' screen-active = 0. ® | ENDIF. ENDCASE. 8 MODIFY SCREEN. @opTIon2 ENDLOOP. CONNID", "pages": [7], "end_pos": 2864, "summary": "Demonstrates AT SELECTION-SCREEN OUTPUT with a working example that dynamically modifies screen fields based on radio button selection, illustrating real-world event-driven UI logic.", "start_pos": 2250, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_008", "text": "The event START-OF-SELECTION gives you the possibility of creating a processing block after processing the selection screen and before accessing database table\nIf you do not specify any event keywords in your program, all statements of the program before a FORM statement form the START-OF-SELECTION processing block\nNote: All statements between an ENDFORM statement and an event keyword or between an ENDFORM statement and the end of the program form a processing block that is never processed\nDo not place any statements there and place all subroutines at the end of your program", "pages": [8], "end_pos": 3331, "summary": "Explains START-OF-SELECTION as the default entry point for database access logic and emphasizes correct placement of subroutines relative to event blocks.", "start_pos": 2865, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_003", "CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_009", "text": "From your program, you can send a message with different message types:\nA - Abend; The message appears in a dialog box, and the program terminates.\nE - Error; Depending on the program context, an error dialog appears or the program terminates.\nI - Information; Appears in a dialog box, the system continues processing\nS - Status; displayed along the footer; the system continues processing\nW - Warning; Depending on the program context, an error dialog appears or the program terminates.\nX - Exit; exits session processing", "pages": [11], "end_pos": 3734, "summary": "Describes ABAP message types (A,E,I,S,W,X) and their behavioral impact on program flow and user interaction.", "start_pos": 3332, "chunk_type": "reference", "has_examples": false, "main_concepts": [], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "MESSAGE EO001(MCLASS). Nc |MESSAGE = ABAP statement E = Type of message (can also be 1,W,S,A,X) ‘001 = Message number MCLASS = Message Class", "pages": [11], "end_pos": 3861, "summary": "Shows syntax for MESSAGE statement with message class and number, clarifying message structure.", "start_pos": 3735, "chunk_type": "example", "has_examples": true, "main_concepts": [], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_011", "text": "The following section explains:\nInclude Program\nMacro\nSubroutine\t\nField Symbol\nData Cluster", "pages": [12], "end_pos": 3931, "summary": "Enumerates the five core modularization techniques covered in the remainder of the document, serving as a conceptual roadmap.", "start_pos": 3862, "chunk_type": "outline", "has_examples": false, "main_concepts": ["CONC_004", "CONC_005", "CONC_006", "CONC_007", "CONC_009", "CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_012", "text": "Each ABAP program has a modular structure\nABAP programs are divided into:\nProcessing blocks that are controlled by events when the program is a report program (Program of type 1)\nModules that are controlled by the screen flow logic when the program is an dialog program (Module pool of type M)\nYou can modularize either your source code or tasks which are to be performed repeatedly", "pages": [13], "end_pos": 4172, "summary": "Introduces modular architecture in ABAP, distinguishing between report programs (event-driven) and dialog programs (flow logic-driven), and framing modularization goals.", "start_pos": 3932, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_002", "CONC_003"]}, {"id": "CHUNK_013", "text": "To modularize source codes the following two methods apply:\nInclude program\nMacro\nTo modularize tasks the following two methods apply:\nSubroutine\nFunctional module", "pages": [14], "end_pos": 4304, "summary": "Categorizes modularization approaches: include/macro for source code reuse, subroutine/functional module for task encapsulation.", "start_pos": 4173, "chunk_type": "classification", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_005", "CONC_006", "CONC_007"]}, {"id": "CHUNK_014", "text": "If you want to use the same sequence of statements in several programs, you can code them once in an include program\nYou can use the INCLUDE statement to put include program into your main program\nExample:\nPERFORM get_data. O Example: i INCLUDE z99r 11 modularisation ppt £01. 295R_11_MODULARISATION_PPT_FO1| Active a * fees ILAR get_data . 1 6 ENDFORM. \" GET DATA", "pages": [15], "end_pos": 4614, "summary": "Defines include programs as reusable source code modules and demonstrates inclusion via INCLUDE statement with a minimal example.", "start_pos": 4305, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_004"]}, {"id": "CHUNK_015", "text": "You can create callable modules of program code within your ABAP program by defining macro\nTo define a macro which contains part of the source code, you use the DEFINE statement as follows:\nSyntax:\nDEFINE <macro>.\n\t<statements>\nEND-OF-DEFINITION.\nYou must specify complete statements between DEFINE and END-OF-DEFINITION\nNotice: The coding within macro cannot be debugged", "pages": [16], "end_pos": 4873, "summary": "Introduces macros as compile-time callable code modules, specifies DEFINE/END-OF-DEFINITION syntax, and notes critical limitation: non-debuggability.", "start_pos": 4615, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_004"]}, {"id": "CHUNK_016", "text": "Example:\nDefining the macro\nCalling the macro two times with parameters\nDATA: BEGIN OF 1s_student, name TYPE chari0, gender TYPE chari, age TYPE i, END OF Ls_student, it_student LIKE TABLE OF is_student. Q DEFINE £111 field. clear 1s_student. 1s_student-name is_student-gender 1s_student-age = 63. append 1s_student to 1t_student. END-OF-DEFINITION. Defining the macro fill_field: ‘May’ ''F'' 123\", tana! tt tose, Calling the macro two times with parameters EILOOP AT lt_student INTO 1s_student. 18 | WRITE: / 1s_student-name, 1s_student-gender, 1s_student-age. ENDLOOP.", "pages": [17], "end_pos": 5319, "summary": "Illustrates macro definition and invocation with parameters, showing how macros reduce repetition in data initialization and table population.", "start_pos": 4874, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_017", "text": "Subroutine is program module which can be called from ABAP program\nInternal subroutine\nThe source code of internal subroutine is in the same ABAP program as the calling procedure (internal call)\nExternal subroutine\nThe source code of external subroutine is in an ABAP program other than the calling procedure (external call)", "pages": [18], "end_pos": 5542, "summary": "Defines subroutines as callable program modules and distinguishes internal vs. external subroutines by source location.", "start_pos": 5320, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_018", "text": "A subroutine is a block of code introduced by FORM and concluded by ENDFORM\nTo define a subroutine, use the following syntax:\nSyntax:\nFORM <subr> [<pass>].\n\t<statement block>\nENDFORM.\n<subr> - The name of the subroutine\n<pass> - You specify how to pass data to and from the subroutine {mainly for external call}.", "pages": [19], "end_pos": 5771, "summary": "Specifies FORM/ENDFORM syntax for subroutine definition and explains the optional <pass> parameter clause for data exchange.", "start_pos": 5543, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_019", "text": "Calling Internal Subroutine\nTo call an internal subroutine, use the PERFORM statement as follows:\nSyntax:\nPERFORM <subr> [<pass>].\nCalling External Subroutine\nTo call an external subroutine, use the PERFORM statement as follows:\nSyntax:\nPERFORM <subr> (IN PROGRAM <prog>) [<pass>] [IF FOUND].", "pages": [20], "end_pos": 6024, "summary": "Documents PERFORM syntax for invoking both internal and external subroutines, highlighting the IN PROGRAM clause for cross-program calls.", "start_pos": 5772, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_020", "text": "Example:\nPERFORM get_data. Example: PERFORM get_data2 IN PROGRAM z99r_1l_perform2 IF FOUND.  “g--------------------------------------------------------------------- * *& Form GET_DATA text * --> pl text <-- p2 text ee get_data | \" GET DATA © In the case of internal subroutine, you do not have to use the <pass> option, because the subroutine can access all data objects declared in the main ABAP program O In the case of external subroutine, you must decide whether to use the <pass> option or declare data objects in common parts of the memory 22\nPERFORM gev_dava, PERFORM ge_dacaz IN PROGRAM IF FOUND, SFORM ger_daca « l ENDFORM,", "pages": [21], "end_pos": 6441, "summary": "Provides PERFORM examples for internal and external subroutines and explains parameter passing considerations for each type.", "start_pos": 6025, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_007"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_021", "text": "You can pass data between calling program and subroutine by using parameter\nParameter which is defined during the definition of a subroutine with the FORM statement are called formal parameter\nParameter which is specified during the call of a subroutine with the PERFORM statement are called actual parameter\nSyntax:\nPERFORM <subr>[(IN PROGRAM <prog>)] [TABLES <actual  table list>]\n                          \t                                    [USING <actual  input list>]\n                        \t                                  [CHANGING <actual output list>].\n\nFORM <subr>   [TABLES <formal  table list>]\n                          [USING <formal  input list>]\n        \t                   [CHANGING <formal output list>].", "pages": [22], "end_pos": 6860, "summary": "Introduces formal/actual parameter distinction and documents full PERFORM/FORM syntax with TABLES, USING, and CHANGING clauses.", "start_pos": 6442, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_022", "text": "Calling by Reference \nDuring a subroutine call, only the address of the actual parameter is transferred to the formal parameter\nThe formal parameter has no memory of its own, so if you change the formal parameter, the field contents in the calling program also change\nCalling by Value\nDuring a subroutine call, the formal parameters are created as copies of the actual parameters\nThe formal parameters have memory of their own\nChanges to the formal parameter have no effect on the actual parameter\nCalling by Value and Result\nDuring a subroutine call, the formal parameters are created as copies of the actual parameter\nThe formal parameters have their own memory space, so changes to the formal parameters are copied to the actual parameter at the end of the subroutine", "pages": [23], "end_pos": 7379, "summary": "Explains the three subroutine parameter passing mechanisms—by reference, by value, and by value-and-result—with behavioral consequences for data mutation.", "start_pos": 6861, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_023", "text": "To pass data between calling program and subroutine by reference, use USING or CHANGING for the <pass> option of the FORM and PERFORM statements as follows:\nSyntax:\nPERFORM ..... [USING <ai1> ... <ain>] \n                         [CHANGING <ao1> ... <aon>] …\n\nFORM ..... [USING <fi1> ... <fin>] \n                  [CHANGING <fo1> ... <fon>] ...\nYou specify the formal and actual parameter in the list behind USING and CHANGING without any addition", "pages": [25], "end_pos": 7681, "summary": "Specifies exact syntax for reference-based parameter passing using USING and CHANGING clauses in both PERFORM and FORM statements.", "start_pos": 7380, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_024", "text": "To ensure that an input parameter is not changed in the calling program, even if it is changed in the subroutine, you can pass data to a subroutine by value\nFor this, use USING for the <pass> option of the FORM and PERFORM statements as follows:\nSyntax:\nPERFORM ..... USING ,,...< ai > \n\nFORM..... USING ..... VALUE (<fii>) ....", "pages": [27], "end_pos": 7910, "summary": "Documents syntax for value-based parameter passing using VALUE() in FORM and plain USING in PERFORM.", "start_pos": 7682, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_025", "text": "If you want to return a changed output parameter from a subroutine to the calling program only after the subroutine has run successfully, use CHANGING for the <pass> option of the FORM and PERFORM statements as follows:\nSyntax:\nPERFORM ..... CHANGING .....<aii> …\n\nFORM..... CHANGING ..... VALUE (<fii>) ....", "pages": [29], "end_pos": 8137, "summary": "Documents syntax for value-and-result parameter passing using CHANGING VALUE() in FORM and CHANGING in PERFORM.", "start_pos": 7911, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_026", "text": "Example:\nDATA: gqv_texti TYPE char4 gv_text4 TYPE char4 t2 r Q¥_text PE r4, tS 1 Gv_text E r4. MOVE ''ABAP'' TO: qv 1 Qv_text2, gv gv_text4, gv_tex gv_ RM show gv_textl HANGING gv_t gv_text4. : / ‘Out RMS\". : / ''Tex {G) gv_te /'' {G) 1 ovit : / ''Text (G) gqv_te /'' {G) , if (G) gv_te. /'' {G) 1 Vt", "pages": [30], "end_pos": 8485, "summary": "Demonstrates mixed parameter passing (USING, CHANGING) in a PERFORM call, showing how input and output parameters are declared and used.", "start_pos": 8138, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": false, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_027", "text": "Example (Continue…):\nFORM show text USING iv_texti TYPE char4 \" By reference value (iv_text2) TYPE char4 \" By value CHANGING iv_text3 TYPE char4 \" By reference value (iv_text4) TYPE char4. \" By value and result DATA: gqv_text5 TYPE char4. MOVE ''XYZ'' TO: iv_texti, iv_text2, iv_text3, iv_text4, gv_text5, gv_texté. WRITE: ‘Inside FORM:''. 1 \"Text 1 (L): '', iv_texti, \"Text 2 (L): '', iv_text2, \"Text 1 (G): '', gv_texti. \"Text 2 (G): '', Qv_text2. \"Text 3 (L): '', iv_text3, \"Text 3 (G): '', gv_text3. \"Text 4 (L): '', iv_text4, \"Text 4 (G): '', gv_text4. \"Text 5 (L): '', gv_text5, / ''Text @ (G): '', gv_texté. sos / / / / sos = a KI Bi NNN WRITE: I + ENDFORM. \" SHOW TEXT", "pages": [31], "end_pos": 9072, "summary": "Shows a complete FORM definition with mixed parameter modes (reference, value, value-and-result), illustrating declaration syntax and local/global variable interaction.", "start_pos": 8486, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": false, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_028", "text": "To terminate the processing of a subroutine, you can proceed in a similar way as for terminating a loop by using the EXIT or CHECK statements\nUse EXIT to terminate a subroutine unconditionally\nUse CHECK to terminate a subroutine according to a condition\nIf you terminate a subroutine using EXIT or CHECK, the system terminates the processing of the subroutine at this point, passes the parameters, and continues with the statement after the PERFORM statement", "pages": [33], "end_pos": 9379, "summary": "Explains EXIT and CHECK statements for early subroutine termination, emphasizing parameter passing behavior upon exit.", "start_pos": 9073, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_029", "text": "Field Symbol is placeholder or symbolic name for the other field\nDo not physically reserve space for a field, but points to its content\nCan point to any data object\nThe data object to which a field symbol points is assigned to it after it has been declared in the program\nTyping Field Symbol:\nThe <type> addition allows you to specify the type of a field symbol\nSyntax:\nFIELD-SYMBOLS <FS> <type>\nExample:\nFIELD-SYMBOLS <fs_spfii> TYPE spfli. FIELD-SYMBOLS <fs_carrid> TYPE spfli-carrid.", "pages": [34], "end_pos": 9703, "summary": "Defines field symbols as dynamic aliases, explains their zero-memory footprint, and shows FIELD-SYMBOLS declaration with typing.", "start_pos": 9380, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_030", "text": "The name of the data object you want to assign to a field symbol before run time\nSyntax: \nASSIGN <f>  TO <FS>.\nExample:\nFIELD-SYMBOLS: <fi> TYPE\nFIELD-SYMBOLS: <f1> TYPE any, <t2> TYPE 4. DATA: num TYPE 4 VALUE S, text TYPE ¢ LENGTH 20 VALUE ASSIGN text TO <£t>. ASSIGN num TO <f2>. WAITE: / <ft>, <t2>.\nOatpat HELLO", "pages": [35], "end_pos": 10007, "summary": "Demonstrates static ASSIGN syntax for binding field symbols to known data objects at compile time, with a working example.", "start_pos": 9704, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_031", "text": "The name of the data object you want to assign to a field symbol only at  run time\nSyntax: \nASSIGN (<f>)  TO <FS>.\nExample:\nFIELD-SYMBOLS: <£2> TYPE any, <t2> TYPE any. DATA: text TYPE © LENGTH 20 VALUE ‘HELLO'', hello TYPE ¢ LENGTH 20 VALUE ‘WORLD’, ASSIGN text TO <f1>. ASSIGH (text) TO <£2>. WRITE: / <t2>, <f2>.\nMELLO woaLD", "pages": [36], "end_pos": 10314, "summary": "Demonstrates dynamic ASSIGN syntax using parentheses for runtime resolution of data object names, with a working example.", "start_pos": 10008, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_032", "text": "Storing Data Objects as Clusters You can group any complex internal data objects of an ABAP/4 program together in data clusters and store them temporarily in ABAP/4 memory or for longer periods in databases. data cluster = set of data objects fleld stings data hase 3 8", "pages": [37], "end_pos": 10534, "summary": "Introduces data clusters as logical groupings of ABAP data objects for storage in memory or database, defining the cluster concept.", "start_pos": 10315, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_033", "text": "You can store data cluster in ABAP memory\nABAP memory is not dependent on the ABAP program or program module which generates it during a transaction\nThis means that an object stored in ABAP memory can be read again by any ABAP program during the same transaction\nFor example, you can pass data between:\nReport and other Report called with SUBMIT\nTransaction and Report\nProgram and Function Module\nNote : The memory is released again when you leave the transaction", "pages": [38], "end_pos": 10847, "summary": "Explains ABAP memory as a transaction-scoped, program-agnostic storage area for data clusters, listing common inter-program communication scenarios.", "start_pos": 10535, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_034", "text": "To write data objects from an ABAP program to ABAP memory, you use the following statement:\nSyntax:\nEXPORT <f1>  <f2> ... TO MEMORY ID <key>.\nExample:\nDATA lv_vext TYPE ¢ LENGTH 20 VALUE ‘Hello Werl EXPORT Iv_xext TO MEMORY ID ''UPTOMEM''. form ppt? AND RETURN.", "pages": [39], "end_pos": 11099, "summary": "Documents EXPORT syntax for persisting data clusters to ABAP memory with a memory ID key, including a code example.", "start_pos": 10848, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_035", "text": "To read data object from ABAP memory into an ABAP program, you use the following statement:\nSyntax:\nIMPORT <f1> [TO <g1>] <f2> [TO <g2>] ... FROM MEMORY ID <key>.\nExample:\nDATA lv_vexe TYPE ¢ LENGTH 20. IMPORT Iv_vexe FROM ID WRITE: / Iv_cexe,", "pages": [40], "end_pos": 11325, "summary": "Documents IMPORT syntax for retrieving data clusters from ABAP memory, supporting optional renaming (TO <g>), with a code example.", "start_pos": 11100, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Event-driven language", "aliases": ["event-based programming"], "keywords": ["event", "processing block", "control flow", "runtime trigger"], "confidence": 1.0, "difficulty": 3, "description": "An event-driven language like ABAP controls program flow through external events rather than sequential execution. The runtime system triggers predefined processing blocks in response to events such as user input, screen display, or database access. Each event keyword (e.g., INITIALIZATION, START-OF-SELECTION) defines the start of a processing block, and the system executes statements between consecutive event keywords or between an event and a FORM statement. This paradigm decouples logic from control flow, enabling responsive, interactive applications.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_002", "title": "Processing block", "aliases": ["event handler block"], "keywords": ["event keyword", "statement block", "execution context", "ABAP report"], "confidence": 1.0, "difficulty": 3, "description": "A processing block in ABAP is a contiguous sequence of executable statements bounded by event keywords (e.g., INITIALIZATION, AT SELECTION-SCREEN) or by an event keyword and a FORM statement. Every statement in an ABAP report must belong to exactly one processing block or subroutine. The system executes each block only when its associated event occurs. Processing blocks define the logical units of work executed at specific points in the program lifecycle—before selection screens, after user input, during list output, or before database access.", "concept_type": "component", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001", "CONC_003", "CONC_004"]}, {"id": "CONC_003", "title": "ABAP event keyword", "aliases": ["event handler", "ABAP event"], "keywords": ["INITIALIZATION", "AT SELECTION-SCREEN", "START-OF-SELECTION", "GET", "TOP-OF-PAGE"], "confidence": 1.0, "difficulty": 4, "description": "An ABAP event keyword is a reserved identifier (e.g., INITIALIZATION, START-OF-SELECTION, AT LINE-SELECTION) that marks the beginning of a processing block and signals the runtime system to execute the subsequent statements when the corresponding event occurs. Events are categorized by phase: selection screen (INITIALIZATION, AT SELECTION-SCREEN), database processing (START-OF-SELECTION, GET), list output (TOP-OF-PAGE, END-OF-PAGE), and interactive reporting (AT LINE-SELECTION, AT USER-COMMAND). Each keyword enforces strict scoping rules for statement grouping.", "concept_type": "component", "extracted_from": ["CHUNK_003", "CHUNK_004", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_002", "CONC_007"]}, {"id": "CONC_004", "title": "Modularization", "aliases": ["ABAP modularity"], "keywords": ["code reuse", "encapsulation", "subroutine", "include program"], "confidence": 1.0, "difficulty": 3, "description": "Modularization in ABAP refers to structuring source code or reusable tasks into independent, maintainable units. It supports two orthogonal strategies: structural modularization (include programs, macros) for source code reuse across programs, and functional modularization (subroutines, function modules) for task encapsulation and parameterized invocation. Modularization improves readability, testability, and reusability while reducing redundancy and maintenance overhead. It is foundational for both report programs (event-controlled) and dialog programs (screen-flow controlled).", "concept_type": "process", "extracted_from": ["CHUNK_014"], "related_concepts": ["CONC_005", "CONC_006", "CONC_007", "CONC_008"]}, {"id": "CONC_005", "title": "Include program", "aliases": ["include", "ABAP include"], "keywords": ["INCLUDE", "source reuse", "compile-time insertion", "code sharing"], "confidence": 1.0, "difficulty": 2, "description": "An include program is an ABAP source code module stored separately and inserted into another program using the INCLUDE statement. It enables structural modularization by allowing identical code sequences (e.g., data declarations, utility logic) to be defined once and reused across multiple programs. Includes are resolved at compile time and have no runtime overhead. They cannot contain executable statements outside of processing blocks or subroutines, and are commonly used for standard interfaces, constants, or boilerplate declarations.", "concept_type": "component", "extracted_from": ["CHUNK_016"], "related_concepts": ["CONC_004", "CONC_006"]}, {"id": "CONC_006", "title": "Macro", "aliases": ["ABAP macro"], "keywords": ["DEFINE", "END-OF-DEFINITION", "text replacement", "compile-time expansion"], "confidence": 1.0, "difficulty": 3, "description": "A macro in ABAP is a compile-time text substitution mechanism defined with DEFINE and END-OF-DEFINITION. It allows reusable sequences of complete statements to be invoked inline with parameterized values. Macros improve conciseness but lack debugging support—their expanded code is not traceable step-by-step. They are appropriate for simple, repetitive patterns (e.g., initialization, field clearing) but unsuitable for complex logic or error handling due to limited scope and no runtime introspection.", "concept_type": "component", "extracted_from": ["CHUNK_017"], "related_concepts": ["CONC_004", "CONC_005"]}, {"id": "CONC_007", "title": "Subroutine", "aliases": ["FORM routine"], "keywords": ["FORM", "ENDFORM", "PERFORM", "parameter passing", "internal call", "external call"], "confidence": 1.0, "difficulty": 4, "description": "A subroutine is a callable program unit in ABAP defined with FORM and terminated with ENDFORM. It supports functional modularization by encapsulating reusable logic with explicit parameter interfaces. Subroutines can be internal (within the same program) or external (in another program), and support three parameter-passing mechanisms: by reference (USING/CHANGING), by value (USING VALUE), and by value-and-result (CHANGING VALUE). They enable structured, maintainable code and are essential for separating concerns in larger ABAP applications.", "concept_type": "component", "extracted_from": ["CHUNK_019", "CHUNK_020", "CHUNK_023"], "related_concepts": ["CONC_004", "CONC_008", "CONC_009"]}, {"id": "CONC_008", "title": "Parameter passing in subroutines", "aliases": ["subroutine parameter mode"], "keywords": ["USING", "CHANGING", "VALUE", "reference", "copy", "atomic update"], "confidence": 1.0, "difficulty": 4, "description": "Parameter passing in ABAP subroutines governs how data flows between calling and called routines. Three mechanisms exist: (1) By reference: formal parameters alias actual memory locations (using USING or CHANGING); changes affect the caller. (2) By value: formal parameters are copies (using USING VALUE); caller data remains unchanged. (3) By value-and-result: formal parameters are copied initially and written back on exit (using CHANGING VALUE); ensures atomic updates only after successful execution. Choice impacts correctness, performance, and side-effect visibility.", "concept_type": "process", "extracted_from": ["CHUNK_024", "CHUNK_026", "CHUNK_028", "CHUNK_030"], "related_concepts": ["CONC_007", "CONC_009"]}, {"id": "CONC_009", "title": "Field symbol", "aliases": ["ABAP pointer"], "keywords": ["FIELD-SYMBOLS", "ASSIGN", "dynamic reference", "alias", "generic access"], "confidence": 1.0, "difficulty": 4, "description": "A field symbol is a dynamic reference variable in ABAP that acts as an alias for any existing data object without allocating memory. Declared with FIELD-SYMBOLS, it is assigned at runtime via ASSIGN <data_object> TO <fs>. Field symbols support generic programming, dynamic data access, and pointer-like indirection. Typing (e.g., TYPE spfli-carrid) ensures type safety. Unlike regular variables, field symbols provide runtime flexibility for accessing fields whose names or structures are unknown at compile time, especially useful in generic utilities and database abstractions.", "concept_type": "component", "extracted_from": ["CHUNK_035", "CHUNK_036", "CHUNK_037"], "related_concepts": ["CONC_007", "CONC_010"]}, {"id": "CONC_010", "title": "Data cluster", "aliases": ["cluster", "ABAP shared memory"], "keywords": ["EXPORT", "IMPORT", "ABAP memory", "transaction scope", "SUBMIT", "memory ID"], "confidence": 1.0, "difficulty": 4, "description": "A data cluster in ABAP is a logical grouping of related internal data objects (structures, tables, scalars) stored together in ABAP memory or database for temporary or persistent sharing. Clusters are managed via EXPORT and IMPORT statements using a unique memory ID key. ABAP memory is transaction-scoped and accessible across program boundaries (e.g., report-to-report via SUBMIT, program-to-function-module), enabling stateful inter-program communication. Clusters abstract serialization complexity and ensure data integrity across heterogeneous program types.", "concept_type": "component", "extracted_from": ["CHUNK_038", "CHUNK_039", "CHUNK_040", "CHUNK_041"], "related_concepts": ["CONC_007", "CONC_009"]}], "relationships": [{"id": "REL_001", "type": "produces", "source": "CONC_001", "target": "CONC_002", "evidence": "ABAP being event-driven means the general flow is controlled by external events, and the system starts a processing block when the corresponding event occurs.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "part_of", "source": "CONC_002", "target": "CONC_003", "evidence": "All statements between two event keywords or between an event keyword and a FORM statement form a processing block; event keywords define processing block boundaries.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "part_of", "source": "CONC_004", "target": "CONC_005", "evidence": "To modularize source codes, include programs and macros apply; include programs are one of the two methods for source code modularization.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "part_of", "source": "CONC_004", "target": "CONC_006", "evidence": "Macros are listed as one method to modularize source code alongside include programs.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "part_of", "source": "CONC_004", "target": "CONC_007", "evidence": "To modularize tasks, subroutines and functional modules apply; subroutines are explicitly named as a task modularization method.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "implements", "source": "CONC_007", "target": "CONC_008", "evidence": "Subroutines support parameter passing by reference, value, and value-and-result; the description of parameter passing directly elaborates how subroutines implement data exchange.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "similar_to", "source": "CONC_007", "target": "CONC_009", "evidence": "Both subroutines and field symbols support indirection and dynamic behavior—subroutines via callable logic, field symbols via dynamic referencing—but serve different abstraction layers.", "strength": 0.9, "bidirectional": true}, {"id": "REL_008", "type": "consumes", "source": "CONC_009", "target": "CONC_010", "evidence": "Field symbols are often used to dynamically reference data objects that are later grouped into clusters for export/import; they enable flexible cluster composition.", "strength": 0.95, "bidirectional": false}, {"id": "REL_009", "type": "requires", "source": "CONC_010", "target": "CONC_007", "evidence": "Data clusters frequently store subroutine outputs or parameters; exporting/importing clusters relies on subroutine logic for preparation and consumption.", "strength": 0.95, "bidirectional": false}, {"id": "REL_010", "type": "before", "source": "CONC_003", "target": "CONC_007", "evidence": "Event keywords like START-OF-SELECTION occur before subroutine calls in typical ABAP report flow; subroutines are invoked within processing blocks triggered by events.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 35, "missing_links": [], "coverage_score": 1.0, "total_concepts": 10, "consistency_score": 1.0, "total_relationships": 10}, "document_metadata": {"title": "ABAP Event-Driven Programming and Modularization", "language": "English", "main_topic": "ABAP programming fundamentals: event handling and code modularization", "difficulty_level": "Intermediate", "estimated_reading_time": "12 minutes"}, "concept_chunk_mapping": [{"concept": "Event-driven language", "context": "ABAP is an event-driven language\nThis means that the general flow of an ABAP program is controlled by external event", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Processing block", "context": "What is a processing block?\nYou can define processing block in your ABAP program by using event keyword \nAll statements between two event keywords or between an event keyword and a FORM statement form a processing block", "chunk_id": "CHUNK_002", "positions": [67], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "ABAP event keyword", "context": "INITIALIZATION\nPoint before the selection screen is displayed\nAT SELECTION-SCREEN\nPoint after processing user input on the selection screen while the selection screen is still active", "chunk_id": "CHUNK_003", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "ABAP event keyword", "context": "Event occurring during processing of output list of a report:\nTOP-OF-PAGE - Point during list processing when a new page is started\nEND-OF-PAGE - Point during list processing when a page is ended", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "ABAP event keyword", "context": "When you start a program in which a selection screen is defined (either in the program itself or in the linked logical database program), the system normally processes this selection screen first\nIf you want to execute a processing block before the selection screen is processed, you can assign it to the event keyword INITIALIZATION", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "ABAP event keyword", "context": "The event keyword AT SELECTION-SCREEN provides you with several possibilities to carry out processing blocks while the system is processing the selection screen\nTo react on different events, that can occur when the selection screen is processed, the keyword AT SELECTION-SCREEN has various options:", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Modularization", "context": "The following section explains:\nInclude Program\nMacro\nSubroutine\t\nField Symbol\nData Cluster", "chunk_id": "CHUNK_011", "positions": [26], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Modularization", "context": "Each ABAP program has a modular structure\nABAP programs are divided into:\nProcessing blocks that are controlled by events when the program is a report program (Program of type 1)\nModules that are controlled by the screen flow logic when the program is an dialog program (Module pool of type M)", "chunk_id": "CHUNK_012", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Include program", "context": "If you want to use the same sequence of statements in several programs, you can code them once in an include program\nYou can use the INCLUDE statement to put include program into your main program", "chunk_id": "CHUNK_014", "positions": [0], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Macro", "context": "You can create callable modules of program code within your ABAP program by defining macro\nTo define a macro which contains part of the source code, you use the DEFINE statement as follows:", "chunk_id": "CHUNK_015", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Subroutine", "context": "Subroutine is program module which can be called from ABAP program\nInternal subroutine\nThe source code of internal subroutine is in the same ABAP program as the calling procedure (internal call)", "chunk_id": "CHUNK_017", "positions": [0], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Subroutine", "context": "A subroutine is a block of code introduced by FORM and concluded by ENDFORM\nTo define a subroutine, use the following syntax:", "chunk_id": "CHUNK_018", "positions": [0], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Parameter passing in subroutines", "context": "You can pass data between calling program and subroutine by using parameter\nParameter which is defined during the definition of a subroutine with the FORM statement are called formal parameter\nParameter which is specified during the call of a subroutine with the PERFORM statement are called actual parameter", "chunk_id": "CHUNK_021", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Parameter passing in subroutines", "context": "Calling by Reference \nDuring a subroutine call, only the address of the actual parameter is transferred to the formal parameter\nThe formal parameter has no memory of its own, so if you change the formal parameter, the field contents in the calling program also change", "chunk_id": "CHUNK_022", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Field symbol", "context": "Field Symbol is placeholder or symbolic name for the other field\nDo not physically reserve space for a field, but points to its content\nCan point to any data object", "chunk_id": "CHUNK_029", "positions": [0], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "Data cluster", "context": "Storing Data Objects as Clusters You can group any complex internal data objects of an ABAP/4 program together in data clusters and store them temporarily in ABAP/4 memory or for longer periods in databases.", "chunk_id": "CHUNK_032", "positions": [0], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Data cluster", "context": "You can store data cluster in ABAP memory\nABAP memory is not dependent on the ABAP program or program module which generates it during a transaction\nThis means that an object stored in ABAP memory can be read again by any ABAP program during the same transaction", "chunk_id": "CHUNK_033", "positions": [0], "concept_id": "CONC_010", "importance": "primary"}]}', '{"total_modules": 4, "total_concepts": 28, "difficulty_score": 9, "total_structures": 18, "total_applications": 12}', '"[{\"id\":\"CHUNK_001\",\"text\":\"At the end of this topic, you will be able to: perform some common daily operations of major modules of an ERP system; customise an ERP system using an appropriate programming environment; and develop programs to support the integration of business transactions among business partners in the supply chain.\",\"pages\":[1],\"start_pos\":0,\"end_pos\":280,\"summary\":\"Learning outcomes for ERP system operations, customization, and integration.\",\"chunk_type\":\"learning_objectives\",\"has_examples\":false,\"main_concepts\":[],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"At the end of this topic, you will be able to: Understand the ABAP Dictionary, Create domain, data element, structure, table and view, Display and update table content.\",\"pages\":[2],\"start_pos\":281,\"end_pos\":430,\"summary\":\"Specific learning objectives focused on ABAP Dictionary operations.\",\"chunk_type\":\"learning_objectives\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\",\"CONC_004\",\"CONC_005\",\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"ABAP Dictionary centrally manages data definitions of data elements, structures and table types. It describes the logical structure of the objects used in application development and shows how they are mapped to the underlying relational database in tables or views. All system components can access activated objects of ABAP Dictionary.\",\"pages\":[3],\"start_pos\":431,\"end_pos\":670,\"summary\":\"Core definition and role of ABAP Dictionary.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\",\"CONC_006\",\"CONC_007\"]},{\"id\":\"CHUNK_004\",\"text\":\"SE11 is the transaction code used to access the ABAP Dictionary. From here, users can create and manage database tables, views, data types, and other dictionary objects. The initial screen allows selection of object types such as tables, views, data elements, and domains.\",\"pages\":[4],\"start_pos\":671,\"end_pos\":840,\"summary\":\"Access method and interface for ABAP Dictionary via SE11.\",\"chunk_type\":\"procedural\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_005\",\"text\":\"Once a table is defined in ABAP Dictionary, a table is then created in the database layer. Table in ABAP Dictionary has the same structure as the table in the underlying database. The fields of the table are defined with their data types, lengths and decimal places.\",\"pages\":[5],\"start_pos\":841,\"end_pos\":1050,\"summary\":\"Mapping between ABAP Dictionary tables and physical database tables.\",\"chunk_type\":\"explanatory\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_006\",\"text\":\"Field name - The field name can have a maximum of 16 characters and can contain letters, digits and underscores. The field name must begin with a letter. Key flag - Determines whether the field belongs to the table key. Key fields are always given initial values. Initial Value Indicator - Set this indicator if a field must have an initial value. Initial value depends on the data type of the field.\",\"pages\":[6],\"start_pos\":1051,\"end_pos\":1350,\"summary\":\"Rules and attributes for defining table fields in ABAP Dictionary.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_007\",\"text\":\"Field type - Data type of the field in the ABAP Dictionary. Field length - Determines the number of valid places in the field. Decimal places - The number of places after the decimal point, specifying numeric data types. Short description - Short text describing the meaning of the field. Data element - The data type, field length, decimal places and short description are determined from the domain of the data element.\",\"pages\":[7],\"start_pos\":1351,\"end_pos\":1650,\"summary\":\"Attributes of a table field with emphasis on data element inheritance.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_008\",\"text\":\"Create references to Currency (data type CURR) or Quantity (data type QUAN) Fields. Reference field – currency key (data type CUKY) or unit of measure (data type UNIT). Reference table – table contains the reference field. Reference field can reside in the table itself.\",\"pages\":[8],\"start_pos\":1651,\"end_pos\":1880,\"summary\":\"Method for linking currency and quantity fields to reference units.\",\"chunk_type\":\"procedural\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_009\",\"text\":\"Define relationships between tables and create value checks for input fields. Foreign key relationships ensure referential integrity and allow for input validation by checking field values against a check table.\",\"pages\":[9],\"start_pos\":1881,\"end_pos\":2070,\"summary\":\"Purpose and function of foreign key relationships in data modeling.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_010\",\"text\":\"Defines how the table is handled when it is created in the database. Specify whether the table is buffered and whether changes to the table''s data records are logged. Technical settings affect performance and data management.\",\"pages\":[10],\"start_pos\":2071,\"end_pos\":2300,\"summary\":\"Overview of technical settings governing table behavior in the database.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_011\",\"text\":\"Each data class corresponds to a physical area in which all the tables assigned to this data class are stored. APPL0 (Master data) - Data which is seldom changed like customer master with name, address and telephone number. APPL1 (Transaction data) - Data that is frequently changed such as the goods in a warehouse. APPL2 (Organizational data) - Customizing data defined at installation and seldom changed.\",\"pages\":[11],\"start_pos\":2301,\"end_pos\":2650,\"summary\":\"Explanation of data classes and their storage implications.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_012\",\"text\":\"Defines the expected space required for the table in the database. Each category is assigned a certain fixed memory size in the database, which depends on the database system used. When a table is created, initial space is reserved. If more space is required later, additional memory will be added depending on the selected size category.\",\"pages\":[12],\"start_pos\":2651,\"end_pos\":2950,\"summary\":\"Role of size category in allocating and growing table space.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_013\",\"text\":\"Selecting the correct size category prevents a large number of very small extents and prevents space from being wasted if extents which are too large are created. Proper sizing optimizes performance and storage efficiency.\",\"pages\":[13],\"start_pos\":2951,\"end_pos\":3150,\"summary\":\"Importance of appropriate size category selection.\",\"chunk_type\":\"explanatory\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_014\",\"text\":\"Controls the transport of table data for installation, upgrade, client copy and when transporting between customer systems. Delivery class determines whether data is included in transports and how it behaves during system updates.\",\"pages\":[14],\"start_pos\":3151,\"end_pos\":3380,\"summary\":\"Function of delivery class in system transport and upgrade scenarios.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_015\",\"text\":\"Delivery (development) Class: A - Application table (master and transaction data). Data Browser/Table View Maint.: Display/Maintenance Allowed – enable editing. Other classes include C (Customizing), S (System), and W (System with transportable contents).\",\"pages\":[15],\"start_pos\":3381,\"end_pos\":3600,\"summary\":\"Types of delivery classes and their maintenance permissions.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_016\",\"text\":\"Creating Tables and Table Fields: 1. Maintain technical settings. 2. The technical settings are a separate object and can be activated and transported separately. 3. Maintain foreign key relationships. 4. Create secondary indexes. 5. Save and assign to development class. 6. Choose enhancement category. 7. Activate.\",\"pages\":[16],\"start_pos\":3601,\"end_pos\":3900,\"summary\":\"Step-by-step process for creating and activating database tables.\",\"chunk_type\":\"procedural\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\",\"CONC_008\",\"CONC_009\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_017\",\"text\":\"Once a view is defined in ABAP Dictionary, a view is then created in the database layer. View in ABAP Dictionary has the same structure as the view in the underlying database. 4 view types: Database views (Inner Join), Projection views (hide fields), Help views (Outer Join for search helps), Maintenance views (Outer Join for multi-table maintenance).\",\"pages\":[17],\"start_pos\":3901,\"end_pos\":4250,\"summary\":\"Creation and classification of views in ABAP Dictionary.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_018\",\"text\":\"User-defined data type is defined globally in ABAP Dictionary. This type can be used in ABAP programs. Changes to this type automatically take effect in all the ABAP programs. Examples of type categories: Data elements, Elementary types, Structures, Table types.\",\"pages\":[18],\"start_pos\":4251,\"end_pos\":4550,\"summary\":\"Global definition and reuse of data types across ABAP programs.\",\"chunk_type\":\"explanatory\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\",\"CONC_006\",\"CONC_007\"]},{\"id\":\"CHUNK_019\",\"text\":\"System converts the Dictionary data types of the object fields to the corresponding ABAP data types. Examples: CHAR → c(m), CLNT → c(3), CURR → p((m+1)/2), DATS → d, INT4 → i, NUMC → n(m). This mapping ensures compatibility between database and program layers.\",\"pages\":[19],\"start_pos\":4551,\"end_pos\":4800,\"summary\":\"Data type conversion between ABAP Dictionary and ABAP programs.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_020\",\"text\":\"Define the type of a table field, structure component or the row type of a table type. It can also be referenced in ABAP programs with TYPES. Data element information is automatically available to all screen fields that refer to the data element, ensuring consistency in UI representation.\",\"pages\":[20],\"start_pos\":4801,\"end_pos\":5050,\"summary\":\"Usage of data elements in various contexts and their propagation to UI.\",\"chunk_type\":\"explanatory\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\",\"CONC_007\"]},{\"id\":\"CHUNK_021\",\"text\":\"Types are defined for the components (multiple fields). Structures are used to define the data at the interface of module pools and screens and to define the parameter types of function modules. They provide a reusable template for complex data.\",\"pages\":[21],\"start_pos\":5051,\"end_pos\":5300,\"summary\":\"Role of structures in defining data interfaces and parameters.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_022\",\"text\":\"Describe the structure and functional attributes of an internal table in ABAP. A table type is defined by: its line type (defines structure), options for managing/accessing data, and primary/secondary keys. Access mode (standard, sorted, hashed) determines performance characteristics.\",\"pages\":[22],\"start_pos\":5301,\"end_pos\":5600,\"summary\":\"Definition and components of table types for internal tables.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_023\",\"text\":\"A domain defines a value range. A domain is assigned to a data element. All table fields or structure components that use this data element have the value range defined by the domain. Changing the domain propagates changes to all dependent fields, ensuring consistency.\",\"pages\":[23],\"start_pos\":5601,\"end_pos\":5850,\"summary\":\"Function of domains in enforcing value ranges across fields.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\",\"CONC_004\"]},{\"id\":\"CHUNK_024\",\"text\":\"Define fixed value intervals either by entering upper and lower limits or by specifying single values. This is done within the domain definition to restrict allowable field entries and maintain data integrity.\",\"pages\":[24],\"start_pos\":5851,\"end_pos\":6100,\"summary\":\"Methods for setting value intervals in domains.\",\"chunk_type\":\"procedural\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_025\",\"text\":\"Proposes the value table as check table when trying to define a foreign key for the field. The check against the value table only takes effect when a foreign key has been defined. Example: If defining a foreign key for a field referring to S_CARR_ID, SCARR is proposed as the check table.\",\"pages\":[25],\"start_pos\":6101,\"end_pos\":6400,\"summary\":\"Integration between value tables and foreign key definition.\",\"chunk_type\":\"explanatory\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_009\"]},{\"id\":\"CHUNK_026\",\"text\":\"Search help: A list of possible input values that appears for the input. It assists users in selecting valid entries and reduces data entry errors. Search helps can be linked to data elements, domains, or fields.\",\"pages\":[26],\"start_pos\":6401,\"end_pos\":6650,\"summary\":\"Function and purpose of search helps in user input.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_011\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\"]},{\"id\":\"CHUNK_027\",\"text\":\"Lock object: Used to synchronize access to the same data by more than one user. Prevents concurrent modifications that could lead to inconsistent states. Implemented via enqueue/dequeue function modules in ABAP.\",\"pages\":[26],\"start_pos\":6651,\"end_pos\":6900,\"summary\":\"Purpose of lock objects in managing concurrent data access.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"ABAP Dictionary\",\"aliases\":[\"ABAP Data Dictionary\"],\"keywords\":[\"data definition\",\"SAP\",\"logical structure\",\"relational database\",\"application development\"],\"confidence\":1,\"difficulty\":4,\"description\":\"The ABAP Dictionary is a central repository that manages data definitions such as data elements, structures, and table types in SAP systems. It defines the logical structure of objects used in application development and maps them to the underlying relational database tables or views. Activated objects are accessible by all system components, enabling consistent data usage across applications. It supports creation of domains, data elements, tables, views, and structures, and ensures referential integrity through foreign key relationships.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_003\",\"CHUNK_004\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_002\",\"title\":\"Domain\",\"aliases\":[],\"keywords\":[\"value range\",\"data type\",\"length\",\"decimal places\",\"fixed values\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A domain in the ABAP Dictionary defines the value range for a data element, including data type, length, decimal places, and fixed value intervals. It serves as a template that enforces consistency across fields using the same data element. Domains can specify allowed values via lower/upper limits or discrete entries. Changes to a domain automatically propagate to all dependent data elements and fields, ensuring uniform constraints throughout the system.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_028\",\"CHUNK_029\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CONC_003\",\"title\":\"Data Element\",\"aliases\":[],\"keywords\":[\"semantic meaning\",\"technical attributes\",\"field definition\",\"metadata\",\"screen fields\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A data element in ABAP Dictionary describes the semantic meaning and technical attributes of a field, such as its data type, length, and description. It acts as an intermediate layer between a domain and a table field, inheriting technical properties from the domain while adding documentation and display characteristics. Data elements ensure consistent field definitions across multiple tables and provide metadata for screen fields referencing them.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_007\",\"CHUNK_024\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_004\"]},{\"id\":\"CONC_004\",\"title\":\"Database Table\",\"aliases\":[\"Transparent Table\"],\"keywords\":[\"physical table\",\"relational database\",\"fields\",\"primary key\",\"technical settings\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A database table in ABAP Dictionary represents a physical table in the underlying relational database with identical structure. It consists of fields defined with specific data types, lengths, and optional decimal places. Tables are created in the database layer upon activation and include technical settings like buffering, data class, size category, and logging. Key fields define primary keys and are initialized automatically.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\",\"CHUNK_006\",\"CHUNK_017\"],\"related_concepts\":[\"CONC_001\",\"CONC_005\",\"CONC_006\"]},{\"id\":\"CONC_005\",\"title\":\"View\",\"aliases\":[],\"keywords\":[\"virtual table\",\"base tables\",\"database view\",\"projection view\",\"help view\",\"maintenance view\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A view in ABAP Dictionary is a virtual table derived from one or more base tables, used to simplify data access and enforce security. Four types exist: database views (inner join), projection views (hide fields), help views (outer join for search helps), and maintenance views (outer join for multi-table data maintenance). Views are implemented at the database level and reflect changes in underlying tables.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_018\",\"CHUNK_019\"],\"related_concepts\":[\"CONC_001\",\"CONC_004\"]},{\"id\":\"CONC_006\",\"title\":\"Structure\",\"aliases\":[],\"keywords\":[\"composite data type\",\"components\",\"module pool\",\"function module\",\"work area\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A structure in ABAP Dictionary is a composite data type consisting of multiple components, each with its own type. Structures are used to define interfaces in module pools and screens, and parameter types for function modules. They do not correspond to database tables but serve as templates for internal tables or work areas in ABAP programs.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_025\",\"CHUNK_026\"],\"related_concepts\":[\"CONC_001\",\"CONC_007\"]},{\"id\":\"CONC_007\",\"title\":\"Table Type\",\"aliases\":[],\"keywords\":[\"internal table\",\"line type\",\"access mode\",\"key configuration\",\"ranges table\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A table type in ABAP Dictionary describes the structure and behavior of an internal table in ABAP programs. It is defined by its line type (structure or data element), access mode (standard, sorted, hashed), and key configuration. Table types allow reusable definitions for internal tables and support ranges tables for selection criteria. They enable consistent handling of dynamic datasets within applications.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_026\",\"CHUNK_027\"],\"related_concepts\":[\"CONC_001\",\"CONC_006\"]},{\"id\":\"CONC_008\",\"title\":\"Technical Settings\",\"aliases\":[],\"keywords\":[\"data class\",\"buffering\",\"size category\",\"logging\",\"storage area\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Technical settings in ABAP Dictionary define how a table is handled in the database, including data class, buffering, size category, and logging options. Data class determines storage area (e.g., APPL0 for master data). Buffering improves performance by caching table contents. Size category allocates initial space and growth increments. Logging tracks data changes. These settings impact performance, scalability, and transportability.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_010\",\"CHUNK_011\",\"CHUNK_012\",\"CHUNK_013\",\"CHUNK_014\",\"CHUNK_015\"],\"related_concepts\":[\"CONC_004\"]},{\"id\":\"CONC_009\",\"title\":\"Foreign Key Relationship\",\"aliases\":[],\"keywords\":[\"referential integrity\",\"check table\",\"input validation\",\"value check\",\"cascading update\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A foreign key relationship in ABAP Dictionary enforces referential integrity between two tables by linking a field in one table (foreign key) to the primary key of another (check table). It enables input validation, value checks, and navigation between related data. Foreign keys support cascading updates and deletions and can be defined with cardinality and update rules. They are essential for maintaining data consistency in normalized databases.\",\"concept_type\":\"relationship\",\"extracted_from\":[\"CHUNK_009\",\"CHUNK_016\"],\"related_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_010\",\"title\":\"Value Table\",\"aliases\":[],\"keywords\":[\"valid values\",\"domain\",\"check table\",\"input assistance\",\"dropdown\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A value table in ABAP Dictionary contains a list of valid values for a domain. When defining a foreign key, the system proposes the value table as the check table. The actual value check only takes effect once a foreign key is explicitly defined. Value tables help maintain data consistency by restricting field entries to predefined options, serving as a basis for input assistance and dropdown lists.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_030\",\"CHUNK_031\"],\"related_concepts\":[\"CONC_002\",\"CONC_009\"]},{\"id\":\"CONC_011\",\"title\":\"Search Help\",\"aliases\":[\"Input Help\"],\"keywords\":[\"input values\",\"F4 help\",\"usability\",\"data accuracy\",\"contextual suggestions\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A search help in SAP provides a list of possible input values for a field during data entry, improving usability and data accuracy. It can be linked to data elements or fields and may retrieve values from tables, views, or custom logic. Search helps support filtering, sorting, and multiple selection, and are often triggered by pressing F4. They enhance user experience by guiding input with contextual suggestions.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_032\"],\"related_concepts\":[\"CONC_010\"]},{\"id\":\"CONC_012\",\"title\":\"Lock Object\",\"aliases\":[],\"keywords\":[\"concurrent access\",\"data synchronization\",\"optimistic locking\",\"pessimistic locking\",\"transactional processing\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A lock object in SAP is used to synchronize concurrent access to the same data records by multiple users, preventing inconsistencies due to simultaneous modifications. It implements optimistic or pessimistic locking strategies and is typically used in transactional processing. Lock objects are generated as function modules (ENQUEUE/DEQUEUE) and integrated into dialog programs to ensure data integrity during critical operations.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_032\"],\"related_concepts\":[]},{\"id\":\"CONC_013\",\"title\":\"Delivery Class\",\"aliases\":[\"Development Class\"],\"keywords\":[\"transport behavior\",\"upgrade\",\"customizing\",\"system table\",\"application table\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Delivery class in ABAP Dictionary specifies how a table is delivered and maintained, affecting transport and upgrade behavior. For example, class ''A'' denotes application tables (master/transaction data), ''C'' for customizing tables maintained only by customers, and ''S'' for system tables maintained only by SAP. It controls whether data is transported, overwritten during upgrades, or protected from changes.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_016\",\"CHUNK_017\"],\"related_concepts\":[\"CONC_004\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"ABAP Dictionary manages domains as part of its data definition capabilities.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_003\",\"evidence\":\"Data elements are centrally managed in ABAP Dictionary.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_004\",\"evidence\":\"Tables are defined and managed within ABAP Dictionary.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_005\",\"evidence\":\"Views are created and maintained in ABAP Dictionary.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_006\",\"evidence\":\"Structures are defined in ABAP Dictionary for use in ABAP programs.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"part_of\",\"source\":\"CONC_001\",\"target\":\"CONC_007\",\"evidence\":\"Table types are defined in ABAP Dictionary to describe internal tables.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"requires\",\"source\":\"CONC_003\",\"target\":\"CONC_002\",\"evidence\":\"A data element is assigned a domain which defines its technical attributes.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"part_of\",\"source\":\"CONC_004\",\"target\":\"CONC_003\",\"evidence\":\"Table fields are defined using data elements.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"part_of\",\"source\":\"CONC_006\",\"target\":\"CONC_003\",\"evidence\":\"Structure components refer to data elements or other types.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"requires\",\"source\":\"CONC_007\",\"target\":\"CONC_006\",\"evidence\":\"A table type''s line type can be a structure.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"managed_by\",\"source\":\"CONC_004\",\"target\":\"CONC_008\",\"evidence\":\"Technical settings control how a database table is handled in the database.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"implements\",\"source\":\"CONC_004\",\"target\":\"CONC_009\",\"evidence\":\"Foreign key relationships are defined on table fields to ensure referential integrity.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"produces\",\"source\":\"CONC_002\",\"target\":\"CONC_010\",\"evidence\":\"A domain can have a value table that lists valid values.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_014\",\"type\":\"example_of\",\"source\":\"CONC_010\",\"target\":\"CONC_009\",\"evidence\":\"The value table is proposed as the check table when defining a foreign key.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_015\",\"type\":\"consumes\",\"source\":\"CONC_011\",\"target\":\"CONC_010\",\"evidence\":\"Search helps can use value tables as a source of possible input values.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_016\",\"type\":\"has\",\"source\":\"CONC_004\",\"target\":\"CONC_013\",\"evidence\":\"Tables are assigned a delivery class that defines their transport and maintenance behavior.\",\"strength\":1,\"bidirectional\":false}]"', '2026-04-03 16:37:34.903228', '2026-04-03 16:37:34.903228', NULL, '[{"id": "module_1", "name": "ABAP Event-Driven Programming", "topic_count": 12}, {"id": "module_2", "name": "ABAP Modularization Methods", "topic_count": 10}, {"id": "module_3", "name": "Subroutines and Parameter Passing", "topic_count": 15}, {"id": "module_4", "name": "Advanced Modularization Techniques", "topic_count": 8}]', NULL, 'IT114105 Higher Diploma in Software Engineering

