INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'AY2526-ITP4511-Project-Brief.docx', 'ea6670c3540ed2f1f740f06f4496c1065058f0fa534c0ed25ba11da5660bceae', '{"chunks": [{"id": "CHUNK_001", "text": "Higher Diploma in Software Engineering (IT114105) Coursework (Semester 5 - 2025/2026) Enterprise Systems Development (ITP4511) Students are required to upload the software project implementation and the related documents to http://moodle.vtc.edu.hk on or before the submission date. Date of Source and Report Submission: 26th April, 2026 Demonstration Period / Video Demonstration Submission : TBC Students are required to submit their work on the Moodle platform and demonstrate their assignment during the lab session. Late submissions will NOT be accepted, and any late assignment will score a zero.", "pages": [1], "end_pos": 598, "summary": "Submission guidelines for coursework including deadlines, platform, and consequences of late submission.", "start_pos": 0, "chunk_type": "administrative", "has_examples": false, "main_concepts": ["CONC_013"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "The Community Care Health Consortium (CCHC) operates five community clinics across Hong Kong (Chai Wan, Tseung Kwan O, Sha Tin, Tuen Mun, and Tsing Yi). These clinics offer outpatient services such as general consultations, vaccinations, and basic health screenings. Currently, each clinic manages appointments and walk-in queues with separate spreadsheets and manual processes, resulting in inefficiencies, long wait times, and limited visibility of service utilisation. To resolve these issues, CCHC plans to implement a centralised, web-based system called the CCHC Community Clinic Appointment & Queue System. This system will unify appointment management across all clinics, enhance queue transparency, minimise missed appointments, and offer operational reports.", "pages": [1], "end_pos": 1056, "summary": "Introduction of CCHC and the need for a centralised appointment and queue system to replace inefficient manual processes.", "start_pos": 599, "chunk_type": "scenario", "has_examples": true, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "The implementation of the CCHC Community Clinic Appointment & Queue System aims to support the following users: Patients, Clinic Staff, and Administrators. Public users will be required to register as patients. Clinic Staff and Administrators will be created by the system administrator. Patients use the system to: Register/log in, View clinic services and available timeslots, Book, reschedule, and cancel appointments, Join a same-day walk-in queue (if the clinic accepts walk-ins), View personal booking records and queue status, Receive system notifications, Update password and personal profile information. Clinic Staff (Front Desk / Nurse) use the system to: View daily appointment lists and walk-in queues, Approve or reject booking requests, Manage check-in (arrived / no-show) and queue progression (call next, skip, completed), Record visit outcomes, Report operational issues. Administrator creates and manages user accounts, Configures clinics, services, opening hours, and capacity rules, Views analytics and generates reports, Reviews incident logs, Enforces policy settings.", "pages": [2], "end_pos": 1800, "summary": "Detailed description of system users and their respective functionalities and responsibilities.", "start_pos": 1057, "chunk_type": "requirements", "has_examples": true, "main_concepts": ["CONC_002", "CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Core Function Requirements: Appointment Booking and Management includes Clinic & Service Listing (display list of clinics and services, filter by clinic, service type, date, and availability), Book Appointments (patients select clinic, service, date, and available time slot; system prevents double bookings; booking confirmation and record saved), Rescheduling and Cancellation (patients reschedule within allowed rules, cancel bookings; staff can cancel on behalf of clinic with reason stored). Check-in and Attendance: Staff mark ''Arrived'', ''Completed'', or ''No-show''; patients view appointment status.", "pages": [2], "end_pos": 2350, "summary": "Core appointment-related functions including booking, rescheduling, cancellation, and attendance tracking.", "start_pos": 1801, "chunk_type": "functional_requirements", "has_examples": true, "main_concepts": ["CONC_005", "CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Walk-in Queue Management: Patients join same-day queue for a clinic/service if enabled; system assigns queue number and estimated waiting time. Queue Progression: Staff call next, skip, or mark as served; patients view live (or near real-time) queue status (refresh-based acceptable). Queue Rules: Prevent multiple active queue tickets for same patient in same clinic/service/day. Notifications: Implement at least three types shown after login: Appointment confirmed or updated, Appointment or clinic cancelled, Reminder for upcoming appointment, Queue called, skipped, or expired. Ensure notifications are role-specific (Patient vs Staff vs Admin dashboards). Analytics / Reporting (for Administrators): View appointment records with filters, Utilisation Rate (Booking Rate by clinic and service), No-show Summary (count of no-shows by clinic/service/month).", "pages": [3], "end_pos": 3100, "summary": "Queue management, notifications, and administrative reporting functionalities.", "start_pos": 2351, "chunk_type": "functional_requirements", "has_examples": true, "main_concepts": ["CONC_007", "CONC_008", "CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "Account and Role Management: User Management (Admin): List users, Create, edit, or delete users, Assign roles and clinic links for staff. Profile Management (All roles): Update passwords and personal details. Login Control: Role-based access to pages/features, Session management to secure restricted pages. Extra Feature examples: Batch import services/timeslots/users (CSV upload), Basic charts for utilisation/no-shows, Admin policy settings page (max bookings, cancellation cutoff, queue enable/disable), Email-style formatting of notifications, Audit trail table for staff actions.", "pages": [3], "end_pos": 3650, "summary": "User account management, security controls, and suggested extra features for enhancement.", "start_pos": 3101, "chunk_type": "functional_requirements", "has_examples": true, "main_concepts": ["CONC_010", "CONC_014"], "has_definitions": true, "secondary_concepts": ["CONC_012"]}, {"id": "CHUNK_007", "text": "Description of Tasks: Task 1 - Requirements Analysis and System Design: Analyse scenario and define functional requirements. Design sitemap, navigation flow, and database schema (ERD). Define system rules and constraints. Task 2 - MVC Architecture Implementation: Develop the system using Servlets (Controller), JSP (View), and JavaBeans/DAO (Model). Ensure proper separation of responsibilities. Task 3 - Authentication and Access Control: Implement login, logout, session management, and role-based access control. Protect restricted resources. Tasks 4-7 cover Appointment Management, Queue Management, Notification System, and Administration and Reporting implementation.", "pages": [4], "end_pos": 4100, "summary": "Breakdown of development tasks including MVC implementation and security setup.", "start_pos": 3651, "chunk_type": "task_description", "has_examples": true, "main_concepts": ["CONC_011", "CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_013"]}, {"id": "CHUNK_008", "text": "Project Requirement: Design and develop a web application using Java EE / Jakarta EE features. Form a project group of two members with equal workload distribution (50%/50%). Skills requirements: Use JSP/servlets to dynamically generate HTML and accept inputs, Use JSP Actions and Custom Tags (Taglib), Use JavaBean, Use JDBC for database connection, Use session checking and login control, Apply the MVC model (not embedded SQL in JSP). Assessment Criteria: Technical Implementation (correct tech use, MVC, DB integration), Functional Completeness and Design (usability, interface), Written Report (requirements, sitemap, MVC explanation, DB design, etc.), Demonstration Requirement (recompile, explain, answer questions).", "pages": [4], "end_pos": 4700, "summary": "Technical requirements, group work expectations, skills checklist, and assessment criteria for the project.", "start_pos": 4101, "chunk_type": "project_guidelines", "has_examples": false, "main_concepts": ["CONC_013"], "has_definitions": true, "secondary_concepts": ["CONC_011", "CONC_012"]}], "concepts": [{"id": "CONC_001", "title": "CCHC Community Clinic Appointment & Queue System", "aliases": ["CCHC Appointment System"], "keywords": ["appointment system", "queue management", "centralised system", "web application"], "confidence": 1.0, "difficulty": 4, "description": "A centralised, web-based enterprise application designed to unify appointment and walk-in queue management across five community clinics operated by the Community Care Health Consortium (CCHC) in Hong Kong. The system aims to improve operational efficiency, reduce wait times, enhance service visibility, and provide reporting capabilities. It is implemented using Java EE / Jakarta EE technologies following MVC architecture with Servlets, JSP, and DAO patterns.", "concept_type": "system", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_002", "title": "Patient", "aliases": [], "keywords": ["user role", "registration", "booking"], "confidence": 1.0, "difficulty": 2, "description": "A registered user role in the CCHC system who can log in, view clinic services and available time slots, book, reschedule, or cancel appointments, join same-day walk-in queues if enabled, view personal booking records and queue status, receive notifications, and update their password and profile information. Public users must first register to become patients before accessing these functions.", "concept_type": "role", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_005", "CONC_006"]}, {"id": "CONC_003", "title": "Clinic Staff", "aliases": ["Front Desk / Nurse"], "keywords": ["front desk", "nurse", "check-in", "queue progression"], "confidence": 1.0, "difficulty": 3, "description": "A system user role representing front desk personnel or nurses responsible for managing daily operations at a clinic. Responsibilities include viewing appointment lists and walk-in queues, approving or rejecting limited-quota booking requests, managing patient check-ins (arrived, no-show), progressing the queue (call next, skip, mark completed), recording visit outcomes, and reporting operational issues such as doctor unavailability or suspended services.", "concept_type": "role", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_007", "CONC_008"]}, {"id": "CONC_004", "title": "Administrator", "aliases": ["System Administrator", "Clinic Manager"], "keywords": ["admin", "configuration", "reporting", "policy enforcement"], "confidence": 1.0, "difficulty": 4, "description": "A privileged user role (System Administrator or Clinic Manager) with full control over system configuration and user management. Tasks include creating and managing all user accounts (Patients, Staff, Admins), configuring clinics, services, opening hours, and capacity rules, viewing analytics and generating reports, reviewing incident logs, and enforcing policy settings such as maximum active bookings per patient.", "concept_type": "role", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_009", "CONC_010"]}, {"id": "CONC_005", "title": "Appointment Booking", "aliases": [], "keywords": ["booking", "time slot", "double booking prevention"], "confidence": 1.0, "difficulty": 3, "description": "The core functionality allowing patients to select a clinic, service, date, and available time slot to schedule an outpatient visit. The system prevents double bookings both per patient and per slot capacity. Upon successful booking, a confirmation page is displayed and the record is saved in the database. This feature supports filtering by clinic, service type, date, and availability.", "concept_type": "process", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_002", "CONC_006"]}, {"id": "CONC_006", "title": "Rescheduling and Cancellation", "aliases": [], "keywords": ["reschedule", "cancel", "cutoff time", "status update"], "confidence": 1.0, "difficulty": 3, "description": "Functions that allow patients to modify existing appointments within defined rules, such as rescheduling before a cutoff time or cancelling bookings to free up slots. Clinic staff also have the authority to cancel appointments on behalf of the clinic, with the reason for cancellation stored in the system. These actions update the appointment status and affect queue and availability logic.", "concept_type": "process", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_005", "CONC_003"]}, {"id": "CONC_007", "title": "Walk-in Queue Management", "aliases": [], "keywords": ["queue", "walk-in", "waiting time", "queue progression"], "confidence": 1.0, "difficulty": 4, "description": "A subsystem enabling patients to join a same-day walk-in queue for a specific clinic and service if walk-ins are accepted. The system assigns a queue number and provides an estimated waiting time. Staff manage queue progression by calling the next patient, skipping, or marking them as served. Patients can view live or near real-time queue status via refresh-based updates.", "concept_type": "process", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_008", "title": "Notifications", "aliases": [], "keywords": ["alerts", "dashboard", "role-specific"], "confidence": 1.0, "difficulty": 3, "description": "A role-specific messaging system that delivers timely updates to users after login. At least three types must be implemented: appointment confirmation/updates, cancellations (appointment or clinic), reminders for upcoming appointments, and queue events (called, skipped, expired). Notifications are displayed on dashboards tailored to Patient, Staff, and Admin roles to ensure relevance and usability.", "concept_type": "component", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_009", "title": "Analytics and Reporting", "aliases": ["Reporting"], "keywords": ["utilisation rate", "no-show summary", "filtering", "report generation"], "confidence": 1.0, "difficulty": 4, "description": "Administrative functionality providing insights into system usage and performance. Features include viewing filtered appointment records, calculating utilisation rates (booked vs offered slots), summarising no-show counts by clinic/service/month, and generating reports per clinic, service, or month. Simple tables are acceptable, but charts may be included as extra features.", "concept_type": "process", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_004", "CONC_010"]}, {"id": "CONC_010", "title": "Account and Role Management", "aliases": ["User Management"], "keywords": ["user management", "role assignment", "profile update"], "confidence": 1.0, "difficulty": 4, "description": "Core administrative functions for managing user identities and access rights. Includes listing, creating, editing, or deleting users; assigning roles (Patient, Staff, Admin); linking staff to clinics; and allowing all users to update passwords and personal details. Access to these functions is restricted to Administrators, ensuring secure user lifecycle management.", "concept_type": "process", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_004", "CONC_002", "CONC_003"]}, {"id": "CONC_011", "title": "MVC Architecture Implementation", "aliases": ["Model-View-Controller"], "keywords": ["MVC", "Servlet", "JSP", "DAO"], "confidence": 1.0, "difficulty": 4, "description": "The software design pattern used to structure the application, separating concerns into Model (JavaBeans/DAO for data and business logic), View (JSP for presentation), and Controller (Servlets for handling requests and responses). This ensures proper separation of responsibilities, maintainability, and adherence to enterprise development best practices using Java EE / Jakarta EE technologies.", "concept_type": "architecture", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_012", "CONC_013"]}, {"id": "CONC_012", "title": "Authentication and Access Control", "aliases": ["Login Control"], "keywords": ["login", "session", "RBAC", "access control"], "confidence": 1.0, "difficulty": 4, "description": "Security mechanisms including login/logout functionality, session management, and role-based access control (RBAC). Ensures only authenticated users can access protected resources and that each user''s permissions align with their role (Patient, Staff, Admin). Sessions are managed to secure restricted pages and prevent unauthorized access.", "concept_type": "security", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_013", "title": "Java EE / Jakarta EE", "aliases": ["Enterprise Java"], "keywords": ["Jakarta EE", "JSP", "Servlet", "JDBC", "MVC"], "confidence": 1.0, "difficulty": 5, "description": "The enterprise Java platform used for developing the web application. Technologies include JSP and Servlets for dynamic HTML generation and input handling, JavaBeans for encapsulating data, JDBC for database connectivity, custom tags (Taglib), and session management. The implementation must follow MVC principles rather than embedding SQL in JSP pages.", "concept_type": "technology", "extracted_from": ["CHUNK_001", "CHUNK_007"], "related_concepts": ["CONC_011", "CONC_012"]}, {"id": "CONC_014", "title": "Extra Features", "aliases": ["Additional Features"], "keywords": ["CSV upload", "charts", "audit trail", "policy settings"], "confidence": 1.0, "difficulty": 4, "description": "Optional enhancements expected to be implemented beyond core requirements. Examples include batch import of services/timeslots/users via CSV upload, basic charts for visualising utilisation and no-shows, an admin policy settings page for configuring max bookings and cancellation cutoffs, email-style notification formatting, and an audit trail table logging staff actions for accountability and debugging.", "concept_type": "feature", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_004", "CONC_008"]}], "relationships": [{"id": "REL_001", "type": "uses", "source": "CONC_002", "target": "CONC_001", "evidence": "Patients use the system to book appointments, view services, and manage profiles.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "uses", "source": "CONC_003", "target": "CONC_001", "evidence": "Clinic Staff use the system to manage appointments, queues, and report issues.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "manages", "source": "CONC_004", "target": "CONC_001", "evidence": "Administrator creates users and configures system-wide settings for the CCHC system.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "used_by", "source": "CONC_005", "target": "CONC_002", "evidence": "Patients book appointments through this function.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "used_by", "source": "CONC_006", "target": "CONC_002", "evidence": "Patients reschedule and cancel their own bookings.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "used_by", "source": "CONC_006", "target": "CONC_003", "evidence": "Staff can cancel appointments on behalf of the clinic.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "used_by", "source": "CONC_007", "target": "CONC_002", "evidence": "Patients join same-day walk-in queues if enabled.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "managed_by", "source": "CONC_007", "target": "CONC_003", "evidence": "Staff call next, skip, or mark patients as served in the queue.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "consumes", "source": "CONC_008", "target": "CONC_002", "evidence": "Patients receive appointment and queue notifications.", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "consumes", "source": "CONC_008", "target": "CONC_003", "evidence": "Staff receive relevant notifications based on their role.", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "used_by", "source": "CONC_009", "target": "CONC_004", "evidence": "Administrators view analytics and generate reports.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "managed_by", "source": "CONC_010", "target": "CONC_004", "evidence": "Administrators create and manage all user accounts and roles.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "implements", "source": "CONC_011", "target": "CONC_013", "evidence": "MVC architecture is implemented using Java EE technologies like Servlets, JSP, and DAO.", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "requires", "source": "CONC_012", "target": "CONC_013", "evidence": "Authentication and access control are built using Java EE features like session checking and login control.", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "used_by", "source": "CONC_014", "target": "CONC_004", "evidence": "Admin policy settings and audit trails are accessed by Administrators.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 8, "missing_links": [], "coverage_score": 1.0, "total_concepts": 14, "consistency_score": 1.0, "total_relationships": 15}, "document_metadata": {"title": "Higher Diploma in Software Engineering Coursework - Enterprise Systems Development (ITP4511)", "language": "English", "main_topic": "Design and implementation of a centralised clinic appointment and queue management system using Java EE / Jakarta EE", "difficulty_level": "Advanced", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "CCHC Community Clinic Appointment & Queue System", "context": "Definition and purpose of the centralised system.", "chunk_id": "CHUNK_002", "positions": [599], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Patient", "context": "Role definition and associated functions.", "chunk_id": "CHUNK_003", "positions": [1057], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Clinic Staff", "context": "Role definition and associated functions.", "chunk_id": "CHUNK_003", "positions": [1057], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Administrator", "context": "Role definition and associated functions.", "chunk_id": "CHUNK_003", "positions": [1057], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Appointment Booking", "context": "Core function described with rules and workflow.", "chunk_id": "CHUNK_004", "positions": [1801], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Rescheduling and Cancellation", "context": "Functionality for modifying appointments.", "chunk_id": "CHUNK_004", "positions": [1801], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Walk-in Queue Management", "context": "Queue joining, progression, and rules.", "chunk_id": "CHUNK_005", "positions": [2351], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Notifications", "context": "Types and role-specific delivery of notifications.", "chunk_id": "CHUNK_005", "positions": [2351], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Analytics and Reporting", "context": "Administrative reporting features and metrics.", "chunk_id": "CHUNK_005", "positions": [2351], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "Account and Role Management", "context": "User lifecycle and access management functions.", "chunk_id": "CHUNK_006", "positions": [3101], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "MVC Architecture Implementation", "context": "Task description for implementing MVC with Servlets, JSP, DAO.", "chunk_id": "CHUNK_007", "positions": [3651], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "Authentication and Access Control", "context": "Security implementation task including session and role-based control.", "chunk_id": "CHUNK_007", "positions": [3651], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Java EE / Jakarta EE", "context": "Mentioned as required technology for project development.", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_013", "importance": "primary"}, {"concept": "Extra Features", "context": "List of suggested additional features for implementation.", "chunk_id": "CHUNK_006", "positions": [3101], "concept_id": "CONC_014", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 12, "difficulty_score": 11, "total_structures": 25, "total_applications": 18}', '"[{\"id\":\"CHUNK_001\",\"text\":\"Higher Diploma in Software Engineering (IT114105) Coursework (Semester 5 - 2025/2026) Enterprise Systems Development (ITP4511) Students are required to upload the software project implementation and the related documents to http://moodle.vtc.edu.hk on or before the submission date. Date of Source and Report Submission: 26th April, 2026 Demonstration Period / Video Demonstration Submission : TBC Students are required to submit their work on the Moodle platform and demonstrate their assignment during the lab session. Late submissions will NOT be accepted, and any late assignment will score a zero.\",\"pages\":[1],\"start_pos\":0,\"end_pos\":598,\"summary\":\"Submission guidelines for coursework including deadlines, platform, and consequences of late submission.\",\"chunk_type\":\"administrative\",\"has_examples\":false,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"The Community Care Health Consortium (CCHC) operates five community clinics across Hong Kong (Chai Wan, Tseung Kwan O, Sha Tin, Tuen Mun, and Tsing Yi). These clinics offer outpatient services such as general consultations, vaccinations, and basic health screenings. Currently, each clinic manages appointments and walk-in queues with separate spreadsheets and manual processes, resulting in inefficiencies, long wait times, and limited visibility of service utilisation. To resolve these issues, CCHC plans to implement a centralised, web-based system called the CCHC Community Clinic Appointment & Queue System. This system will unify appointment management across all clinics, enhance queue transparency, minimise missed appointments, and offer operational reports.\",\"pages\":[1],\"start_pos\":599,\"end_pos\":1056,\"summary\":\"Introduction of CCHC and the need for a centralised appointment and queue system to replace inefficient manual processes.\",\"chunk_type\":\"scenario\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"The implementation of the CCHC Community Clinic Appointment & Queue System aims to support the following users: Patients, Clinic Staff, and Administrators. Public users will be required to register as patients. Clinic Staff and Administrators will be created by the system administrator. Patients use the system to: Register/log in, View clinic services and available timeslots, Book, reschedule, and cancel appointments, Join a same-day walk-in queue (if the clinic accepts walk-ins), View personal booking records and queue status, Receive system notifications, Update password and personal profile information. Clinic Staff (Front Desk / Nurse) use the system to: View daily appointment lists and walk-in queues, Approve or reject booking requests, Manage check-in (arrived / no-show) and queue progression (call next, skip, completed), Record visit outcomes, Report operational issues. Administrator creates and manages user accounts, Configures clinics, services, opening hours, and capacity rules, Views analytics and generates reports, Reviews incident logs, Enforces policy settings.\",\"pages\":[2],\"start_pos\":1057,\"end_pos\":1800,\"summary\":\"Detailed description of system users and their respective functionalities and responsibilities.\",\"chunk_type\":\"requirements\",\"has_examples\":true,\"main_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Core Function Requirements: Appointment Booking and Management includes Clinic & Service Listing (display list of clinics and services, filter by clinic, service type, date, and availability), Book Appointments (patients select clinic, service, date, and available time slot; system prevents double bookings; booking confirmation and record saved), Rescheduling and Cancellation (patients reschedule within allowed rules, cancel bookings; staff can cancel on behalf of clinic with reason stored). Check-in and Attendance: Staff mark ''Arrived'', ''Completed'', or ''No-show''; patients view appointment status.\",\"pages\":[2],\"start_pos\":1801,\"end_pos\":2350,\"summary\":\"Core appointment-related functions including booking, rescheduling, cancellation, and attendance tracking.\",\"chunk_type\":\"functional_requirements\",\"has_examples\":true,\"main_concepts\":[\"CONC_005\",\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_005\",\"text\":\"Walk-in Queue Management: Patients join same-day queue for a clinic/service if enabled; system assigns queue number and estimated waiting time. Queue Progression: Staff call next, skip, or mark as served; patients view live (or near real-time) queue status (refresh-based acceptable). Queue Rules: Prevent multiple active queue tickets for same patient in same clinic/service/day. Notifications: Implement at least three types shown after login: Appointment confirmed or updated, Appointment or clinic cancelled, Reminder for upcoming appointment, Queue called, skipped, or expired. Ensure notifications are role-specific (Patient vs Staff vs Admin dashboards). Analytics / Reporting (for Administrators): View appointment records with filters, Utilisation Rate (Booking Rate by clinic and service), No-show Summary (count of no-shows by clinic/service/month).\",\"pages\":[3],\"start_pos\":2351,\"end_pos\":3100,\"summary\":\"Queue management, notifications, and administrative reporting functionalities.\",\"chunk_type\":\"functional_requirements\",\"has_examples\":true,\"main_concepts\":[\"CONC_007\",\"CONC_008\",\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_006\",\"text\":\"Account and Role Management: User Management (Admin): List users, Create, edit, or delete users, Assign roles and clinic links for staff. Profile Management (All roles): Update passwords and personal details. Login Control: Role-based access to pages/features, Session management to secure restricted pages. Extra Feature examples: Batch import services/timeslots/users (CSV upload), Basic charts for utilisation/no-shows, Admin policy settings page (max bookings, cancellation cutoff, queue enable/disable), Email-style formatting of notifications, Audit trail table for staff actions.\",\"pages\":[3],\"start_pos\":3101,\"end_pos\":3650,\"summary\":\"User account management, security controls, and suggested extra features for enhancement.\",\"chunk_type\":\"functional_requirements\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\",\"CONC_014\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_012\"]},{\"id\":\"CHUNK_007\",\"text\":\"Description of Tasks: Task 1 - Requirements Analysis and System Design: Analyse scenario and define functional requirements. Design sitemap, navigation flow, and database schema (ERD). Define system rules and constraints. Task 2 - MVC Architecture Implementation: Develop the system using Servlets (Controller), JSP (View), and JavaBeans/DAO (Model). Ensure proper separation of responsibilities. Task 3 - Authentication and Access Control: Implement login, logout, session management, and role-based access control. Protect restricted resources. Tasks 4-7 cover Appointment Management, Queue Management, Notification System, and Administration and Reporting implementation.\",\"pages\":[4],\"start_pos\":3651,\"end_pos\":4100,\"summary\":\"Breakdown of development tasks including MVC implementation and security setup.\",\"chunk_type\":\"task_description\",\"has_examples\":true,\"main_concepts\":[\"CONC_011\",\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_013\"]},{\"id\":\"CHUNK_008\",\"text\":\"Project Requirement: Design and develop a web application using Java EE / Jakarta EE features. Form a project group of two members with equal workload distribution (50%/50%). Skills requirements: Use JSP/servlets to dynamically generate HTML and accept inputs, Use JSP Actions and Custom Tags (Taglib), Use JavaBean, Use JDBC for database connection, Use session checking and login control, Apply the MVC model (not embedded SQL in JSP). Assessment Criteria: Technical Implementation (correct tech use, MVC, DB integration), Functional Completeness and Design (usability, interface), Written Report (requirements, sitemap, MVC explanation, DB design, etc.), Demonstration Requirement (recompile, explain, answer questions).\",\"pages\":[4],\"start_pos\":4101,\"end_pos\":4700,\"summary\":\"Technical requirements, group work expectations, skills checklist, and assessment criteria for the project.\",\"chunk_type\":\"project_guidelines\",\"has_examples\":false,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_011\",\"CONC_012\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"CCHC Community Clinic Appointment & Queue System\",\"aliases\":[\"CCHC Appointment System\"],\"keywords\":[\"appointment system\",\"queue management\",\"centralised system\",\"web application\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A centralised, web-based enterprise application designed to unify appointment and walk-in queue management across five community clinics operated by the Community Care Health Consortium (CCHC) in Hong Kong. The system aims to improve operational efficiency, reduce wait times, enhance service visibility, and provide reporting capabilities. It is implemented using Java EE / Jakarta EE technologies following MVC architecture with Servlets, JSP, and DAO patterns.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_002\",\"title\":\"Patient\",\"aliases\":[],\"keywords\":[\"user role\",\"registration\",\"booking\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A registered user role in the CCHC system who can log in, view clinic services and available time slots, book, reschedule, or cancel appointments, join same-day walk-in queues if enabled, view personal booking records and queue status, receive notifications, and update their password and profile information. Public users must first register to become patients before accessing these functions.\",\"concept_type\":\"role\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_005\",\"CONC_006\"]},{\"id\":\"CONC_003\",\"title\":\"Clinic Staff\",\"aliases\":[\"Front Desk / Nurse\"],\"keywords\":[\"front desk\",\"nurse\",\"check-in\",\"queue progression\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A system user role representing front desk personnel or nurses responsible for managing daily operations at a clinic. Responsibilities include viewing appointment lists and walk-in queues, approving or rejecting limited-quota booking requests, managing patient check-ins (arrived, no-show), progressing the queue (call next, skip, mark completed), recording visit outcomes, and reporting operational issues such as doctor unavailability or suspended services.\",\"concept_type\":\"role\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_007\",\"CONC_008\"]},{\"id\":\"CONC_004\",\"title\":\"Administrator\",\"aliases\":[\"System Administrator\",\"Clinic Manager\"],\"keywords\":[\"admin\",\"configuration\",\"reporting\",\"policy enforcement\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A privileged user role (System Administrator or Clinic Manager) with full control over system configuration and user management. Tasks include creating and managing all user accounts (Patients, Staff, Admins), configuring clinics, services, opening hours, and capacity rules, viewing analytics and generating reports, reviewing incident logs, and enforcing policy settings such as maximum active bookings per patient.\",\"concept_type\":\"role\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_009\",\"CONC_010\"]},{\"id\":\"CONC_005\",\"title\":\"Appointment Booking\",\"aliases\":[],\"keywords\":[\"booking\",\"time slot\",\"double booking prevention\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The core functionality allowing patients to select a clinic, service, date, and available time slot to schedule an outpatient visit. The system prevents double bookings both per patient and per slot capacity. Upon successful booking, a confirmation page is displayed and the record is saved in the database. This feature supports filtering by clinic, service type, date, and availability.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_002\",\"CONC_006\"]},{\"id\":\"CONC_006\",\"title\":\"Rescheduling and Cancellation\",\"aliases\":[],\"keywords\":[\"reschedule\",\"cancel\",\"cutoff time\",\"status update\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Functions that allow patients to modify existing appointments within defined rules, such as rescheduling before a cutoff time or cancelling bookings to free up slots. Clinic staff also have the authority to cancel appointments on behalf of the clinic, with the reason for cancellation stored in the system. These actions update the appointment status and affect queue and availability logic.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_005\",\"CONC_003\"]},{\"id\":\"CONC_007\",\"title\":\"Walk-in Queue Management\",\"aliases\":[],\"keywords\":[\"queue\",\"walk-in\",\"waiting time\",\"queue progression\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A subsystem enabling patients to join a same-day walk-in queue for a specific clinic and service if walk-ins are accepted. The system assigns a queue number and provides an estimated waiting time. Staff manage queue progression by calling the next patient, skipping, or marking them as served. Patients can view live or near real-time queue status via refresh-based updates.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\"]},{\"id\":\"CONC_008\",\"title\":\"Notifications\",\"aliases\":[],\"keywords\":[\"alerts\",\"dashboard\",\"role-specific\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A role-specific messaging system that delivers timely updates to users after login. At least three types must be implemented: appointment confirmation/updates, cancellations (appointment or clinic), reminders for upcoming appointments, and queue events (called, skipped, expired). Notifications are displayed on dashboards tailored to Patient, Staff, and Admin roles to ensure relevance and usability.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_009\",\"title\":\"Analytics and Reporting\",\"aliases\":[\"Reporting\"],\"keywords\":[\"utilisation rate\",\"no-show summary\",\"filtering\",\"report generation\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Administrative functionality providing insights into system usage and performance. Features include viewing filtered appointment records, calculating utilisation rates (booked vs offered slots), summarising no-show counts by clinic/service/month, and generating reports per clinic, service, or month. Simple tables are acceptable, but charts may be included as extra features.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_004\",\"CONC_010\"]},{\"id\":\"CONC_010\",\"title\":\"Account and Role Management\",\"aliases\":[\"User Management\"],\"keywords\":[\"user management\",\"role assignment\",\"profile update\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Core administrative functions for managing user identities and access rights. Includes listing, creating, editing, or deleting users; assigning roles (Patient, Staff, Admin); linking staff to clinics; and allowing all users to update passwords and personal details. Access to these functions is restricted to Administrators, ensuring secure user lifecycle management.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_004\",\"CONC_002\",\"CONC_003\"]},{\"id\":\"CONC_011\",\"title\":\"MVC Architecture Implementation\",\"aliases\":[\"Model-View-Controller\"],\"keywords\":[\"MVC\",\"Servlet\",\"JSP\",\"DAO\"],\"confidence\":1,\"difficulty\":4,\"description\":\"The software design pattern used to structure the application, separating concerns into Model (JavaBeans/DAO for data and business logic), View (JSP for presentation), and Controller (Servlets for handling requests and responses). This ensures proper separation of responsibilities, maintainability, and adherence to enterprise development best practices using Java EE / Jakarta EE technologies.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_012\",\"CONC_013\"]},{\"id\":\"CONC_012\",\"title\":\"Authentication and Access Control\",\"aliases\":[\"Login Control\"],\"keywords\":[\"login\",\"session\",\"RBAC\",\"access control\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Security mechanisms including login/logout functionality, session management, and role-based access control (RBAC). Ensures only authenticated users can access protected resources and that each user''s permissions align with their role (Patient, Staff, Admin). Sessions are managed to secure restricted pages and prevent unauthorized access.\",\"concept_type\":\"security\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_013\",\"title\":\"Java EE / Jakarta EE\",\"aliases\":[\"Enterprise Java\"],\"keywords\":[\"Jakarta EE\",\"JSP\",\"Servlet\",\"JDBC\",\"MVC\"],\"confidence\":1,\"difficulty\":5,\"description\":\"The enterprise Java platform used for developing the web application. Technologies include JSP and Servlets for dynamic HTML generation and input handling, JavaBeans for encapsulating data, JDBC for database connectivity, custom tags (Taglib), and session management. The implementation must follow MVC principles rather than embedding SQL in JSP pages.\",\"concept_type\":\"technology\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_007\"],\"related_concepts\":[\"CONC_011\",\"CONC_012\"]},{\"id\":\"CONC_014\",\"title\":\"Extra Features\",\"aliases\":[\"Additional Features\"],\"keywords\":[\"CSV upload\",\"charts\",\"audit trail\",\"policy settings\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Optional enhancements expected to be implemented beyond core requirements. Examples include batch import of services/timeslots/users via CSV upload, basic charts for visualising utilisation and no-shows, an admin policy settings page for configuring max bookings and cancellation cutoffs, email-style notification formatting, and an audit trail table logging staff actions for accountability and debugging.\",\"concept_type\":\"feature\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_004\",\"CONC_008\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"uses\",\"source\":\"CONC_002\",\"target\":\"CONC_001\",\"evidence\":\"Patients use the system to book appointments, view services, and manage profiles.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"uses\",\"source\":\"CONC_003\",\"target\":\"CONC_001\",\"evidence\":\"Clinic Staff use the system to manage appointments, queues, and report issues.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"manages\",\"source\":\"CONC_004\",\"target\":\"CONC_001\",\"evidence\":\"Administrator creates users and configures system-wide settings for the CCHC system.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"used_by\",\"source\":\"CONC_005\",\"target\":\"CONC_002\",\"evidence\":\"Patients book appointments through this function.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"used_by\",\"source\":\"CONC_006\",\"target\":\"CONC_002\",\"evidence\":\"Patients reschedule and cancel their own bookings.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"used_by\",\"source\":\"CONC_006\",\"target\":\"CONC_003\",\"evidence\":\"Staff can cancel appointments on behalf of the clinic.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"used_by\",\"source\":\"CONC_007\",\"target\":\"CONC_002\",\"evidence\":\"Patients join same-day walk-in queues if enabled.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"managed_by\",\"source\":\"CONC_007\",\"target\":\"CONC_003\",\"evidence\":\"Staff call next, skip, or mark patients as served in the queue.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"consumes\",\"source\":\"CONC_008\",\"target\":\"CONC_002\",\"evidence\":\"Patients receive appointment and queue notifications.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"consumes\",\"source\":\"CONC_008\",\"target\":\"CONC_003\",\"evidence\":\"Staff receive relevant notifications based on their role.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"used_by\",\"source\":\"CONC_009\",\"target\":\"CONC_004\",\"evidence\":\"Administrators view analytics and generate reports.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"managed_by\",\"source\":\"CONC_010\",\"target\":\"CONC_004\",\"evidence\":\"Administrators create and manage all user accounts and roles.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"implements\",\"source\":\"CONC_011\",\"target\":\"CONC_013\",\"evidence\":\"MVC architecture is implemented using Java EE technologies like Servlets, JSP, and DAO.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_014\",\"type\":\"requires\",\"source\":\"CONC_012\",\"target\":\"CONC_013\",\"evidence\":\"Authentication and access control are built using Java EE features like session checking and login control.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_015\",\"type\":\"used_by\",\"source\":\"CONC_014\",\"target\":\"CONC_004\",\"evidence\":\"Admin policy settings and audit trails are accessed by Administrators.\",\"strength\":1,\"bidirectional\":false}]"', '2026-03-25 09:38:20.056366', '2026-03-25 09:38:20.056366', NULL, '[{"id": "module_1", "name": "Project Requirements and System Analysis", "topic_count": 10}, {"id": "modul