INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '6-Taglib-2024.pdf', '4d63f95ceafb35deacb79203b2bef622086a3b75c14f7ac366d33fe7917db75f', '{"chunks": [{"id": "CHUNK_001", "text": "Observation: JSPs can be “Ugly” • HTML and scripting elements are often heavily mixed <html> <head><title>JSP Example 2 - Mixed Feelings</title></head> <body> <% for(int i = 1; i <= 5; ++i) { %> <font size=\"<%=i%>\">Not so nice but growing ...</font><br/> <% } %> </body></html>", "pages": [1], "end_pos": 392, "summary": "Illustrates the ''ugly'' nature of JSP due to tight mixing of HTML and Java scripting, undermining maintainability and separation of concerns.", "start_pos": 0, "chunk_type": "problem_statement", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "One Solution: Using Class Methods <%@page contentType=\"text/html\" pageEncoding=\"UTF=8\"%> <!DOCTYPE html> ... private String dispText(String text, int nMin, int nMax) { StringBuffer buf = new StringBuffer(\"\"); for (int i = nMin; i <= nMax; ++i) { buf.append( \"<font size=\\\"\" + i + \"\\\">\" + text + \"</font><br/>\\n\") ; } return buf.toString(); } ... <body> <%= dispText(\"Better and still growing\", 2, 6)%>| </body>", "pages": [3], "end_pos": 827, "summary": "Demonstrates using embedded Java class methods as a partial fix for mixed code, but still violates clean separation principles.", "start_pos": 393, "chunk_type": "partial_solution", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": false, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_005", "text": "The Drawbacks of Using Class Methods • HTML and scripting elements are still mixed • scripting elements might not be familiar to web designers • A Better Solution: • JSP provides standard action (tags), like • <jsp:useBean> Instantiate JavaBean object • <jsp:getProperty> Allow accessing bean properties • <jsp:setProperty> Allow setting bean properties • define your own JSP actions ⇒Custom Tags", "pages": [5], "end_pos": 1405, "summary": "Identifies limitations of class methods and introduces Custom JSP Tags as a superior solution for separating concerns and improving designer-developer collaboration.", "start_pos": 1020, "chunk_type": "solution_introduction", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_008", "CONC_007"]}, {"id": "CHUNK_006", "text": "Why Custom Tags? • Separate presentation from business (and other functionality) logic • page authors author presentation • Business logic developers create custom tags • Encapsulate business logic • Reusable & Maintainable • Help page authors • Page authors use simpler syntax", "pages": [6], "end_pos": 1702, "summary": "Explains core motivations for Custom Tags: separation of concerns, encapsulation, reusability, and usability for non-Java web designers.", "start_pos": 1406, "chunk_type": "rationale", "has_examples": false, "main_concepts": ["CONC_001", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "The Benefits of Using Custom Tags • web designers do not have to learn JSP / Java • leads to “cleaner” JSP • logic can be separated from the presentation • code is easy to re-use • can do pretty much everything", "pages": [7], "end_pos": 1947, "summary": "Enumerates key benefits of Custom Tags, reinforcing separation of concerns, simplicity for designers, and technical flexibility.", "start_pos": 1703, "chunk_type": "benefits_summary", "has_examples": false, "main_concepts": ["CONC_001", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "Components of Tag Library • Tag handler class • Defines the tag’s behavior • Tag library descriptor file ( TLD file) • Maps the XML element names to the tag implementation • JSP file • That uses the tag library", "pages": [10], "end_pos": 2371, "summary": "Defines the three essential components of a Custom Tag system: Tag Handler Class, TLD, and consuming JSP file.", "start_pos": 2130, "chunk_type": "architecture_overview", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_012", "text": "Tag Library Descriptor Files (TLD) • refer to an XML document containing data about a whole library as well as about the tags the library contains. • Associate a particular XML tag to the tag handler class • In XML format • Just like other descriptor file is put in WEB-INF\\tlds <?xml version=\"1.0\" encoding=\"UTF-8\"?> <taglib xmlns=\"http://java.sun.com/xml/ns/j2ee\" ... <short-name>ict</short-name> <uri>/WEB-INF/tlds/ict-taglib.tld</uri> <tag> <name>example</name> <tag-class>ict.tag.ExampleTag</tag-class> <body-content>empty</body-content> <description> Simplest example: Inserts one line of output </description> </tag> </taglib>", "pages": [12], "end_pos": 3124, "summary": "Provides formal definition and concrete XML example of a TLD, showing critical elements: uri, short-name, tag name, tag-class, and body-content.", "start_pos": 2520, "chunk_type": "definition_and_example", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": ["CONC_001", "CONC_002"]}, {"id": "CHUNK_013", "text": "A Tag Handler • A tag handler java class • Define the logic • implement own tag • communicate with the JSP page. • JSP context (javax.servlet.jsp.JspContext) for simple tag • the page context (javax.servlet.jsp.PageContext) • retrieve all the other implicit objects (request, session, and application) • Attributes are accessed using • [set|get]Attribute methods.", "pages": [13], "end_pos": 3498, "summary": "Describes the Tag Handler Class as the Java implementation unit, emphasizing its role in defining logic, interacting with JSP context, and managing attributes.", "start_pos": 3125, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_015", "text": "Use Custom Tags -- Front End Developer • Configure custom tag libray, • Use the taglib directive to link with your tld file • Define prefix • Use the tag • <ict:example /> <%@ taglib uri=\"/WEB-INF/tlds/ict-taglib.tld\" prefix=\"ict\" %>", "pages": [15], "end_pos": 3952, "summary": "Explains how front-end developers configure and use Custom Tags via the taglib directive, specifying URI and prefix, then invoking tags with the prefix.", "start_pos": 3722, "chunk_type": "usage_guide", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_018", "text": "To implement a TagHandler class • extends SimpleTagSupport • define setter method if necessary • Override void doTag() • Obtain output stream • output the tag content", "pages": [18], "end_pos": 4312, "summary": "Lists essential implementation steps for a Tag Handler Class: extend SimpleTagSupport, define setters, override doTag(), obtain JspWriter, and output content.", "start_pos": 4137, "chunk_type": "implementation_steps", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_019", "text": "ict.tag.ExampleTag.java package ict.tag; import javax.servlet.jsp.*; import java.io.*; import javax.servlet.jsp.tagext.SimpleTagSupport; public class ExampleTag extends SimpleTagSupport { @Override public void doTag() { try { PageContext pageContext = (PageContext) getJspContext(); JspWriter out = pageContext.getOut(); out.print(\"Custom tag example \" + \"(Example Tag)\"); } catch (IOException e) {} } }", "pages": [19], "end_pos": 4742, "summary": "Shows a complete, minimal Tag Handler Class implementation extending SimpleTagSupport and overriding doTag() to write static output.", "start_pos": 4313, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_002"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_020", "text": "ict-taglib.tld <Version 2.1> <?xml version=\"1.0\" encoding=\"UTF-8\"?> <taglib xmlns=\"http://java.sun.com/xml/ns/j2ee\" ... <tlib-version>1.0</tlib-version> <jsp-version>2.0</jsp-version> <short-name>ict</short-name> <uri>/WEB-INF/tlds/ict-taglib.tld</uri> <tag> <name>example</name> <tag-class>ict.tag.ExampleTag</tag-class> <body-content>empty</body-content> <description> Simplest example: Inserts one line of output </description> </tag> </taglib>", "pages": [20], "end_pos": 5240, "summary": "Presents a full TLD file declaring a single ''example'' tag, mapping it to the ExampleTag class and specifying empty body-content.", "start_pos": 4743, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_001", "CONC_002"]}, {"id": "CHUNK_023", "text": "• Configure the taglib directive in your JSP file • The uri value set to the uri value specified in the TLD file. <%@ taglib uri=\"/WEB-INF/tlds/ict-taglib.tld\" prefix=\"ict\" %> Use the tag is <prefix:name /> <ict:example />", "pages": [23], "end_pos": 5715, "summary": "Reiterates taglib directive configuration and usage syntax, clarifying URI alignment with TLD and prefix:name invocation pattern.", "start_pos": 5432, "chunk_type": "usage_guide", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_024", "text": "<%@ taglib uri=\"/WEB-INF/tlds/ict-taglib.tld\" prefix=\"ict\" %> <h1><ict:example /></h1> SimpleExample.jsp", "pages": [24], "end_pos": 5882, "summary": "Minimal JSP file demonstrating taglib directive declaration and usage of a custom tag inside HTML.", "start_pos": 5716, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_025", "text": "Custom Tag to Action Class Mapping • TagHandler class • implements the custom action • tag library declaration • a tag library descriptor (TLD) • in WEB-INF • the “correct” TLD is identified by the URI in the TLD • URIs are mapped when the server starts • globally unique URI required <%@ taglib uri=\"/WEB-INF/tlds/ict-taglib.tld\" prefix=\"ict\" %> <ict:example/> ict-taglib.tld ict.tag.ExampleTag", "pages": [25], "end_pos": 6272, "summary": "Explains the runtime mapping mechanism: URI in taglib directive resolves to TLD file, which maps tag name to Tag Handler Class.", "start_pos": 5883, "chunk_type": "mapping_explanation", "has_examples": true, "main_concepts": ["CONC_001", "CONC_002", "CONC_003"], "has_definitions": true, "secondary_concepts": ["CONC_004"]}, {"id": "CHUNK_034", "text": "Steps -- Assigning Attributes to Tags • Define setter method in tag handler class • Add attribute elements with tld file • set appropriate attribute in the JSP when using tag lib", "pages": [34], "end_pos": 7225, "summary": "Outlines the three-step process to add attributes to a custom tag: implement setter, declare in TLD, and use in JSP.", "start_pos": 7022, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_002", "CONC_003"]}, {"id": "CHUNK_035", "text": "private String message=\"Default message\"; public void setMessage(String value1) { message = value1; }", "pages": [35], "end_pos": 7350, "summary": "Java code snippet showing a private field and corresponding setter method for a ''message'' attribute.", "start_pos": 7226, "chunk_type": "code_snippet", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_037", "text": "Add attribute elements with tld file <tag> <name>attribute</name> <tag-class>ict.tag.AttributeTag</tag-class> <body-content>empty</body-content> <description> A simple example showing the use of attribute </description> <attribute> <name> message </name> <required>false</required> <type>java.lang.String</type> <rtexprvalue>true</rtexprvalue> </attribute> </Tag> Multiple attributes can be set within a tag", "pages": [37], "end_pos": 7899, "summary": "TLD XML snippet demonstrating declaration of an attribute with name, required, type, and rtexprvalue properties.", "start_pos": 7491, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_005", "CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_038", "text": "Attribute Subelements • Description (optional) • A description of the attribute. information for user • Name • The unique name of the attribute being declared. A translation error results if more than one attribute element appears in the same tag with the same name. • <name>message</name> • required • (optional) Whether the attribute is required. The default is false. • <required>false</required> • type • The runtime type of the attribute''s value. Defaults to java.lang.String if not specified. • <type>java.lang.String</type>", "pages": [38], "end_pos": 8338, "summary": "Details the mandatory and optional subelements of a TLD <attribute>: name, required, type, and description.", "start_pos": 7900, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_039", "text": "Attribute Subelements • rtexprvalue • Whether the attribute''s value can be dynamically calculated at runtime by an EL expression. The default is false. • <rtexprvalue>true</rtexprvalue> • (optional) Whether the attribute''s value can be dynamically calculated at runtime • true ⇒request-time expressions are allowed: • < ... attr = \"<%=request.getParameter(\\\"parName\\\")%>\"/>", "pages": [39], "end_pos": 8685, "summary": "Explains the rtexprvalue attribute subelement, its purpose for enabling dynamic values (e.g., scriptlets, EL), and its default behavior.", "start_pos": 8339, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_048", "text": "Interacting with body content • Set the body-content to scriptless • <ict:MyMsg > value within the content can accessible with the tag handler • </ict:MyMsg> <body-content>scriptless</body-content>", "pages": [48], "end_pos": 9640, "summary": "Introduces body content interaction and specifies that scriptless body-content allows safe access to enclosed content in the tag handler.", "start_pos": 9412, "chunk_type": "introduction", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_049", "text": "How to get body content <%@ taglib uri=\"/WEB-INF/tlds/ict-taglib.tld\" prefix=\"ict\" %> <ict:MyMsg > Hello </ict:MyMsg> StringWriter sw = new StringWriter(); getJspBody().invoke(sw); sw stores the “hello” Within the doTag method, apply the following code", "pages": [49], "end_pos": 9920, "summary": "Describes the code pattern to retrieve body content in a tag handler: instantiate StringWriter and invoke getJspBody() on it.", "start_pos": 9641, "chunk_type": "procedure", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_050", "text": "<tag> <name>MyMsg</name> <tag-class>ict.tag.Detail</tag-class> <body-content>scriptless</body-content> </tag> <body-content>scriptless</body-content> itc-taglib.tld", "pages": [50], "end_pos": 10113, "summary": "TLD snippet declaring a tag with scriptless body-content, enabling body access.", "start_pos": 9921, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_003", "CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_051", "text": "public class Detail extends SimpleTagSupport { //StringWriter object StringWriter sw = new StringWriter(); public void doTag() throws JspException, IOException { getJspBody().invoke(sw); JspWriter out = getJspContext().getOut(); out.println(sw.toString()); } } Detail.java", "pages": [51], "end_pos": 10378, "summary": "Complete Java implementation of a tag handler that reads and outputs its body content using StringWriter.", "start_pos": 10114, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_002", "CONC_006"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_057", "text": "• <body-content>scriptless</body-content> • Body is JSP elements and HTML StringWriter sw = new StringWriter(); this.getJspBody().invoke(sw); Descriptor File", "pages": [57], "end_pos": 11017, "summary": "Reinforces that scriptless body-content permits inclusion of JSP elements/HTML and reiterates the StringWriter access pattern.", "start_pos": 10840, "chunk_type": "note", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_066", "text": "Some Comments on JSP • Good points – 2-tier is easier to setup than 3-tier • 2-tier – presentation logic and business logic mix up in the same layer • 3-tier – presentation logic and business logic separated • Many web sites do not need 3-tier architecture • Bank application needs 3-tier, of course • Bad points – JSP is too easy to mix up presentation logic with business logic, since it uses Java as the scripting language – As a presentation layer only, JSP is too easy to mix up presentation template and presentation logic", "pages": [66], "end_pos": 11991, "summary": "Analyzes JSP''s architectural trade-offs, identifying the 2-tier limitation (mixing logic) as the root cause of ''ugly'' code and motivating separation strategies.", "start_pos": 11522, "chunk_type": "analysis", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_067", "text": "Good Uses of JSP • If vigorous business logic exists, confine the use of JSP on presentation logic only. Use EJB for business tier! • Even as a presentation layer only, separate presentation templates from presentation logic – JSP pages contain the HTML templates – Tag handler classes, JavaBeans hold the presentation logic and data-manipulation logic – De-emphasize the use of scriptlet", "pages": [67], "end_pos": 12390, "summary": "Prescribes best practices for JSP: strict confinement to presentation logic and explicit separation of templates (JSP files) from logic (tag handlers, beans).", "start_pos": 11992, "chunk_type": "best_practice", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_001", "CONC_002"]}], "concepts": [{"id": "CONC_001", "title": "Custom JSP Tag", "aliases": ["user-defined tag", "custom action"], "keywords": ["custom tag", "JSP tag", "tag handler", "TLD"], "confidence": 1.0, "difficulty": 4, "description": "A reusable, user-defined JSP action element with HTML-like syntax that encapsulates presentation logic and separates it from business logic. Implemented via a tag handler class and declared in a Tag Library Descriptor (TLD) file. Enables page authors to use simplified syntax without knowledge of Java or JSP scripting, promoting cleaner code, reusability, and maintainability.", "concept_type": "component", "extracted_from": ["CHUNK_005", "CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_002", "title": "Tag Handler Class", "aliases": ["tag implementation class"], "keywords": ["tag handler", "SimpleTagSupport", "doTag", "setter method"], "confidence": 1.0, "difficulty": 4, "description": "A Java class that implements the behavior of a custom JSP tag, typically extending SimpleTagSupport. It defines logic for tag execution, accesses JSP implicit objects (e.g., PageContext, JspWriter), handles attributes via setter methods, and outputs content via doTag(). Must be compiled and placed in WEB-INF/classes.", "concept_type": "component", "extracted_from": ["CHUNK_010", "CHUNK_013", "CHUNK_018", "CHUNK_019"], "related_concepts": ["CONC_001", "CONC_003", "CONC_005"]}, {"id": "CONC_003", "title": "Tag Library Descriptor (TLD)", "aliases": ["tag library definition"], "keywords": ["TLD", "tag library descriptor", "XML mapping", "uri"], "confidence": 1.0, "difficulty": 4, "description": "An XML file that maps custom tag names to their corresponding tag handler classes and defines tag metadata including attributes, body-content type, and descriptions. Located in WEB-INF/tlds, it is referenced by URI in the JSP taglib directive. Ensures runtime binding between tag usage and implementation.", "concept_type": "component", "extracted_from": ["CHUNK_010", "CHUNK_012", "CHUNK_020", "CHUNK_025"], "related_concepts": ["CONC_001", "CONC_002", "CONC_004"]}, {"id": "CONC_004", "title": "Taglib Directive", "aliases": ["tag library import"], "keywords": ["taglib", "directive", "prefix", "URI"], "confidence": 1.0, "difficulty": 3, "description": "A JSP directive (<%@ taglib %>) used to declare and configure a custom tag library within a JSP page. Specifies the URI (matching the TLD''s <uri> element) and assigns a prefix for namespace qualification of custom tags (e.g., <ict:example/>). Required before any custom tag usage.", "concept_type": "component", "extracted_from": ["CHUNK_015", "CHUNK_023", "CHUNK_024"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_005", "title": "Tag Attribute", "aliases": ["tag parameter"], "keywords": ["attribute", "setter method", "rtexprvalue", "required", "type"], "confidence": 1.0, "difficulty": 4, "description": "A configurable parameter of a custom JSP tag, defined via setter methods in the tag handler class and declared in the TLD using <attribute> subelements. Supports properties like name, required (boolean), type (e.g., java.lang.String), and rtexprvalue (enabling EL/scriptlet evaluation). Enables dynamic, reusable tag behavior.", "concept_type": "component", "extracted_from": ["CHUNK_034", "CHUNK_035", "CHUNK_037", "CHUNK_038", "CHUNK_039"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_006", "title": "Body Content Handling", "aliases": ["tag body processing"], "keywords": ["body-content", "scriptless", "getJspBody", "StringWriter"], "confidence": 1.0, "difficulty": 4, "description": "The mechanism by which a custom tag processes content enclosed between its opening and closing tags. Controlled by the <body-content> element in the TLD (values: empty, scriptless, tagdependent). For scriptless, the body is evaluated (EL/standard actions processed) and accessed in the tag handler via getJspBody().invoke(StringWriter).", "concept_type": "process", "extracted_from": ["CHUNK_048", "CHUNK_049", "CHUNK_050", "CHUNK_051", "CHUNK_057"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_007", "title": "Separation of Concerns in JSP", "aliases": ["SoC", "layer separation"], "keywords": ["separation of concerns", "presentation logic", "business logic", "clean JSP"], "confidence": 1.0, "difficulty": 3, "description": "An architectural principle applied in JSP development where presentation logic (HTML, styling, rendering) is decoupled from business logic (data processing, validation, domain rules). Custom tags support this by allowing web designers to use declarative syntax while backend developers implement reusable, encapsulated logic in tag handlers.", "concept_type": "theory", "extracted_from": ["CHUNK_006", "CHUNK_007", "CHUNK_067"], "related_concepts": ["CONC_001", "CONC_008"]}, {"id": "CONC_008", "title": "JSP 2-Tier Architecture Limitation", "aliases": ["JSP coupling problem"], "keywords": ["2-tier", "3-tier", "mixed logic", "ugly JSP"], "confidence": 1.0, "difficulty": 3, "description": "A structural weakness of traditional JSP where presentation and business logic are co-located in the same layer, leading to ''ugly'' code mixing HTML and Java. This contrasts with 3-tier architecture (presentation, business, data layers) and motivates solutions like custom tags and JavaBeans to enforce logical separation even within the presentation tier.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_001", "CHUNK_002", "CHUNK_066"], "related_concepts": ["CONC_001", "CONC_007"]}], "relationships": [{"id": "REL_001", "type": "implements", "source": "CONC_001", "target": "CONC_002", "evidence": "Custom JSP Tags are implemented via Tag Handler Classes.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "requires", "source": "CONC_001", "target": "CONC_003", "evidence": "A Custom JSP Tag requires a Tag Library Descriptor (TLD) to map the tag name to its handler.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "consumes", "source": "CONC_001", "target": "CONC_004", "evidence": "Custom JSP Tags are used in JSP pages only after declaring them with the taglib directive.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "has", "source": "CONC_002", "target": "CONC_005", "evidence": "Tag Handler Classes define setter methods to support Tag Attributes.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "defines", "source": "CONC_003", "target": "CONC_005", "evidence": "The TLD declares Tag Attributes using <attribute> elements.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "handles", "source": "CONC_002", "target": "CONC_006", "evidence": "Tag Handler Classes process body content using getJspBody() when body-content is not ''empty''.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "supports", "source": "CONC_001", "target": "CONC_007", "evidence": "Custom JSP Tags enable Separation of Concerns by encapsulating presentation logic.", "strength": 1.0, "bidirectional": false}, {"