INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '4-ServletLifecycle-2024.pptx', '59ff3fbd2a008b6795d7d669d48d63fac7cb9533aa4a00f2f5e2802958bd5ec4', '{"chunks": [{"id": "CHUNK_001", "text": "The servlet classes are maintained by the container. Client makes request to the container. Container (itself has main program) manages the servlet. It instantiates and initiates the servlet by calling the method defined in the HttpServlet class.", "pages": [1], "end_pos": 232, "summary": "Overview of servlet-container relationship and lifecycle initiation.", "start_pos": 0, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Why main() is not written in servlet programs? The servlet classes are maintained by the container. Client makes request to the container. Container (itself has main program) manages the servlet. It instantiates and initiates the servlet by calling the method defined in the HttpServlet class.", "pages": [2], "end_pos": 465, "summary": "Explanation why servlets lack a main method due to container management.", "start_pos": 233, "chunk_type": "question_answer", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_003", "text": "Servlet/JSP Containers and Dynamic Pages: Client (Web Browser) connects to Web Server, which forwards to Application Server hosting Servlet Container. Components include JSP, Servlets, EJB, DB Server via JDBC.", "pages": [3], "end_pos": 630, "summary": "System architecture showing interaction between client, web server, application server, and database.", "start_pos": 466, "chunk_type": "diagram_description", "has_examples": true, "main_concepts": ["CONC_002"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Servlets are designed to service clients. Their primary job is to receive a client''s request and return a response. The request carries important data that the servlet must interpret, and the response contains information needed by the browser to render a page or redirect to another resource.", "pages": [4], "end_pos": 850, "summary": "Core responsibility of servlets in handling requests and responses.", "start_pos": 631, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_008", "CONC_009"]}, {"id": "CHUNK_005", "text": "The servlet lifecycle consists of five phases: class loading, instantiation (constructor), init() call (once), repeated service() calls for each request, and finally destroy() for cleanup before garbage collection.", "pages": [5], "end_pos": 1040, "summary": "Stages of servlet lifecycle from creation to destruction.", "start_pos": 851, "chunk_type": "process_description", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": ["CONC_004", "CONC_005"]}, {"id": "CHUNK_006", "text": "The init() method is called by the container after servlet instantiation but before handling any client requests. It provides a chance for one-time initialization such as setting up database connections or loading configuration. Override init() if your servlet requires initialization code.", "pages": [6], "end_pos": 1250, "summary": "Purpose and usage of the init() method in servlet lifecycle.", "start_pos": 1041, "chunk_type": "method_description", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_007", "text": "The service() method is invoked by the container upon each client request. It examines the HTTP method and calls the appropriate doGet(), doPost(), or other doXXX() method. Developers should not override service() in HttpServlet; instead, override doGet() or doPost().", "pages": [7], "end_pos": 1470, "summary": "Role of service() method in routing HTTP requests to specific handlers.", "start_pos": 1251, "chunk_type": "method_description", "has_examples": false, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_006", "CONC_007"]}, {"id": "CHUNK_008", "text": "The doGet() and doPost() methods are where servlet logic begins, analogous to a main() method. They are called by service() based on the HTTP request method. At least one must be overridden. They can call each other to handle both GET and POST uniformly.", "pages": [8], "end_pos": 1680, "summary": "Usage and implementation guidance for doGet and doPost methods.", "start_pos": 1471, "chunk_type": "method_comparison", "has_examples": false, "main_concepts": ["CONC_006", "CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_009", "text": "The HttpServletRequest object provides access to client data including headers (e.g., User-Agent), cookies, session info, HTTP method, input stream, and parameters via getParameter() for single values or getParameterValues() for multiple (e.g., checkboxes).", "pages": [9], "end_pos": 1890, "summary": "Features and access methods of the request object in servlets.", "start_pos": 1681, "chunk_type": "object_description", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "The HttpServletResponse object is used to send data back to the browser. Obtain a Writer to output text (e.g., HTML), set content type (MIME type) like text/html or image/jpeg, and optionally redirect or forward to another resource before committing the response.", "pages": [10], "end_pos": 2100, "summary": "Capabilities and usage of the response object for output and redirection.", "start_pos": 1891, "chunk_type": "object_description", "has_examples": false, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": ["CONC_010", "CONC_011"]}, {"id": "CHUNK_011", "text": "Example code: public void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException, ServletException { String typeParam = request.getParameter(\"type\"); String sizeParam = request.getParameter(\"size\"); } URL: http://127.0.0.1/servlet?type=froffy&size=grande", "pages": [11], "end_pos": 2300, "summary": "Code snippet demonstrating parameter extraction from request object.", "start_pos": 2101, "chunk_type": "code_example", "has_examples": true, "main_concepts": ["CONC_008"], "has_definitions": false, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_012", "text": "Forward vs Redirect: Forward is internal (browser unaware, URL unchanged, request data preserved), suitable for SELECT operations. Redirect involves browser fetching new URL (address changes, no request data carryover), slower, used for INSERT/UPDATE/DELETE to prevent duplicate submissions.", "pages": [12], "end_pos": 2550, "summary": "Differences between server-side forward and client-side redirect with usage guidelines.", "start_pos": 2301, "chunk_type": "comparison", "has_examples": true, "main_concepts": ["CONC_011", "CONC_010"], "has_definitions": true, "secondary_concepts": ["CONC_009"]}, {"id": "CHUNK_013", "text": "Model-View-Controller (MVC) separates application logic: Model (business/data), View (presentation, e.g., JSP), Controller (request handler, e.g., servlet). Promotes reusability, maintainability, and team specialization. Not limited to web applications.", "pages": [13], "end_pos": 2750, "summary": "Overview of MVC design pattern and its benefits in enterprise development.", "start_pos": 2551, "chunk_type": "pattern_description", "has_examples": false, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_014", "text": "In MVC: Model manages data/state (e.g., shopping cart), View displays content (JSP), Controller routes requests, processes input, updates model, and selects view. Controller acts as intermediary ensuring loose coupling between model and view.", "pages": [14], "end_pos": 2950, "summary": "Detailed roles of each MVC component in a web application context.", "start_pos": 2751, "chunk_type": "detailed_explanation", "has_examples": true, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_001", "CONC_009"]}, {"id": "CHUNK_015", "text": "GenericServlet provides basic servlet functionality independent of protocol. HttpServlet extends GenericServlet and implements HTTP-specific behavior including service() method that dispatches to doGet(), doPost(), etc. HttpServlet is abstract and requires overriding doXXX() methods.", "pages": [15], "end_pos": 3150, "summary": "Relationship between GenericServlet and HttpServlet with focus on HTTP method handling.", "start_pos": 2951, "chunk_type": "class_hierarchy", "has_examples": false, "main_concepts": ["CONC_013", "CONC_014"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}], "concepts": [{"id": "CONC_001", "title": "Servlet", "aliases": ["HTTP servlet", "Java servlet"], "keywords": ["servlet", "java", "server-side", "web component"], "confidence": 1.0, "difficulty": 3, "description": "A Java class that runs on a server and handles client requests, typically over HTTP. Servlets are managed by a container which controls their lifecycle including loading, initialization, servicing requests via service() method, and destruction. They do not have a main() method as execution is orchestrated by the container in response to web requests.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_002", "title": "Servlet Container", "aliases": ["Web container", "Servlet engine"], "keywords": ["container", "web container", "application server"], "confidence": 1.0, "difficulty": 3, "description": "A runtime environment within an application server that manages the lifecycle of servlets. It loads servlet classes, instantiates them, calls their init(), service(), and destroy() methods, and handles threading for concurrent requests. Examples include Tomcat and Jetty.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_003"], "related_concepts": ["CONC_001", "CONC_008"]}, {"id": "CONC_003", "title": "Servlet Lifecycle", "aliases": ["Servlet life cycle"], "keywords": ["lifecycle", "init", "service", "destroy"], "confidence": 1.0, "difficulty": 3, "description": "The sequence of stages a servlet goes through: loading into JVM, instantiation via constructor, initialization via init(), request processing via service(), and cleanup via destroy(). The container manages this entire process, ensuring each phase occurs only once except service() which may be called multiple times.", "concept_type": "process", "extracted_from": ["CHUNK_004", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_006", "CONC_007"]}, {"id": "CONC_004", "title": "init() Method", "aliases": ["init method"], "keywords": ["init", "initialization", "setup"], "confidence": 1.0, "difficulty": 3, "description": "A lifecycle method in servlets called once after instantiation. It allows developers to perform one-time setup such as initializing data structures, establishing database connections, or loading configuration files. Overriding this method is optional but common when initialization logic is required before handling client requests.", "concept_type": "method", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_003", "CONC_001"]}, {"id": "CONC_005", "title": "service() Method", "aliases": ["service method"], "keywords": ["service", "request handling", "routing"], "confidence": 1.0, "difficulty": 4, "description": "The core method in a servlet that gets invoked for every client request. It determines the HTTP method (GET, POST, etc.) and dispatches the request to the corresponding doGet(), doPost(), or other doXXX() methods. Developers should not override this method in HttpServlet subclasses since it already contains proper routing logic.", "concept_type": "method", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_003", "CONC_009", "CONC_010"]}, {"id": "CONC_006", "title": "doGet() Method", "aliases": ["doGet method"], "keywords": ["doGet", "GET", "retrieve"], "confidence": 1.0, "difficulty": 3, "description": "A method in HttpServlet that handles HTTP GET requests. It is called by the service() method when a GET request arrives. This method should be overridden by developers to define behavior for retrieving data or rendering pages. It receives HttpServletRequest and HttpServletResponse objects for reading input and writing output.", "concept_type": "method", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_005", "CONC_001"]}, {"id": "CONC_007", "title": "doPost() Method", "aliases": ["doPost method"], "keywords": ["doPost", "POST", "submit"], "confidence": 1.0, "difficulty": 3, "description": "A method in HttpServlet that handles HTTP POST requests. Invoked by the service() method upon receiving a POST request. Used primarily for submitting form data or performing state-changing operations. Like doGet(), it takes request and response parameters and must be overridden to implement custom logic.", "concept_type": "method", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_005", "CONC_001"]}, {"id": "CONC_008", "title": "Request Object", "aliases": ["HTTP request object"], "keywords": ["request", "HttpServletRequest", "input"], "confidence": 1.0, "difficulty": 3, "description": "An instance of HttpServletRequest that encapsulates all data from the client''s HTTP request. It provides access to headers, cookies, session information, request parameters, HTTP method type, and input streams. Servlets use this object to extract user input and contextual data needed to generate responses.", "concept_type": "object", "extracted_from": ["CHUNK_009"], "related_concepts": ["CONC_001", "CONC_011"]}, {"id": "CONC_009", "title": "Response Object", "aliases": ["HTTP response object"], "keywords": ["response", "HttpServletResponse", "output"], "confidence": 1.0, "difficulty": 3, "description": "An instance of HttpServletResponse used to send data back to the client. It allows setting content type (MIME type), status codes, headers, and obtaining output streams (Writer or OutputStream) for sending text or binary data such as HTML, JSON, images, or files.", "concept_type": "object", "extracted_from": ["CHUNK_010"], "related_concepts": ["CONC_001", "CONC_008"]}, {"id": "CONC_010", "title": "Redirect", "aliases": ["HTTP redirect"], "keywords": ["redirect", "sendRedirect", "302 redirect"], "confidence": 1.0, "difficulty": 4, "description": "A technique where the server instructs the browser to make a new request to a different URL using HttpServletResponse.sendRedirect(). It results in two HTTP requests, changes the browser’s address bar, and does not preserve request-scoped attributes. Best used after data-modifying operations like INSERT, UPDATE, DELETE to prevent duplicate submissions.", "concept_type": "process", "extracted_from": ["CHUNK_012"], "related_concepts": ["CONC_011", "CONC_009"]}, {"id": "CONC_011", "title": "Forward", "aliases": ["server-side forward"], "keywords": ["forward", "RequestDispatcher", "include"], "confidence": 1.0, "difficulty": 4, "description": "A server-side mechanism that transfers control internally from one component (like a servlet) to another (like a JSP) without informing the browser. Achieved via RequestDispatcher.forward(). The original URL remains unchanged in the browser, and request-scoped data is preserved. Suitable for SELECT operations where safe repetition is acceptable.", "concept_type": "process", "extracted_from": ["CHUNK_012"], "related_concepts": ["CONC_010", "CONC_009"]}, {"id": "CONC_012", "title": "Model-View-Controller", "aliases": ["MVC pattern"], "keywords": ["MVC", "design pattern", "separation of concerns"], "confidence": 1.0, "difficulty": 4, "description": "A software architectural pattern that separates concerns into three interconnected components: Model (data and business logic), View (presentation layer, e.g., JSP), and Controller (request handler that routes input and updates model). In web applications, servlets often act as controllers while JSPs serve as views.", "concept_type": "architecture", "extracted_from": ["CHUNK_014"], "related_concepts": ["CONC_001", "CONC_013"]}, {"id": "CONC_013", "title": "GenericServlet", "aliases": [], "keywords": ["GenericServlet", "servlet", "protocol-independent"], "confidence": 1.0, "difficulty": 3, "description": "An abstract class implementing the Servlet interface with protocol-independent functionality. It provides basic lifecycle management but lacks HTTP-specific features. Used as a base for creating non-HTTP servlets. For HTTP-based applications, HttpServlet (which extends GenericServlet) is preferred.", "concept_type": "component", "extracted_from": ["CHUNK_015"], "related_concepts": ["CONC_001", "CONC_014"]}, {"id": "CONC_014", "title": "HttpServlet", "aliases": [], "keywords": ["HttpServlet", "HTTP", "doGet", "doPost"], "confidence": 1.0, "difficulty": 4, "description": "A concrete extension of GenericServlet tailored for HTTP communication. It implements the service() method to route HTTP requests based on method type (GET, POST, etc.) to corresponding protected methods like doGet() and doPost(). As an abstract class, it requires subclassing and overriding these doXXX() methods to provide actual behavior.", "concept_type": "component", "extracted_from": ["CHUNK_015"], "related_concepts": ["CONC_013", "CONC_005"]}], "relationships": [{"id": "REL_001", "type": "managed_by", "source": "CONC_001", "target": "CONC_002", "evidence": "The servlet classes are maintained by the container", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "has_a", "source": "CONC_001", "target": "CONC_003", "evidence": "Life of Servlet: First loaded, instantiated, init(), service(), destroy()", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "includes", "source": "CONC_003", "target": "CONC_004", "evidence": "init() method is called only once during lifecycle", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "includes", "source": "CONC_003", "target": "CONC_005", "evidence": "service() method is called repeatedly to handle requests", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "includes", "source": "CONC_003", "target": "CONC_006", "evidence": "doGet is part of request handling in service phase", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "includes", "source": "CONC_003", "target": "CONC_007", "evidence": "doPost is part of request handling in service phase", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "invokes", "source": "CONC_005", "target": "CONC_006", "evidence": "service() method invokes doGet() based on HTTP method", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "invokes", "source": "CONC_005", "target": "CONC_007", "evidence": "service() method invokes doPost() based on HTTP method", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "consumes", "source": "CONC_008", "target": "CONC_001", "evidence": "Servlet uses request object to get client data", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "produces", "source": "CONC_009", "target": "CONC_001", "evidence": "Servlet uses response object to send data back", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "uses", "source": "CONC_010", "target": "CONC_009", "evidence": "response.sendRedirect() performs redirect", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "uses", "source": "CONC_011", "target": "CONC_009", "evidence": "RequestDispatcher obtained from request and used with response", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "implemented_by", "source": "CONC_012", "target": "CONC_001", "evidence": "Servlet acts as controller in MVC", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "uses", "source": "CONC_012", "target": "CONC_009", "evidence": "JSP (view) renders response sent via response object", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "parent_of", "source": "CONC_013", "target": "CONC_014", "evidence": "HttpServlet extends GenericServlet", "strength": 1.0, "bidirectional": false}, {"id": "REL_016", "type": "implements", "source": "CONC_014", "target": "CONC_005", "evidence": "HttpServlet provides default implementation of service()", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 15, "missing_links": [], "coverage_score": 1.0, "total_concepts": 14, "consistency_score": 1.0, "total_relationships": 16}, "document_metadata": {"title": "ITP4511 – Enterprise System Development", "language": "English", "main_topic": "Servlet Lifecycle and Enterprise Web Application Architecture", "difficulty_level": "Intermediate", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "Servlet", "context": "The servlet classes are maintained by the container", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Servlet", "context": "Why main() is not written in servlet programs?", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Servlet", "context": "Servlets are designed to service clients.", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Servlet Container", "context": "Container manages the servlet", "chunk_id": "CHUNK_001", "positions": [50], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Servlet Container", "context": "Servlet Container", "chunk_id": "CHUNK_003", "positions": [40], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Servlet Lifecycle", "context": "The servlet lifecycle consists of five phases", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "init() Method", "context": "The init() method is called by the container", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "service() Method", "context": "The service() method is invoked by the container", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "doGet() Method", "context": "The doGet() and doPost() methods are where servlet logic begins", "chunk_id": "CHUNK_008", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "doPost() Method", "context": "The doGet() and doPost() methods are where servlet logic begins", "chunk_id": "CHUNK_008", "positions": [20], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Request Object", "context": "The HttpServletRequest object provides access to client data", "chunk_id": "CHUNK_009", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Request Object", "context": "request.getParameter(\"type\")", "chunk_id": "CHUNK_011", "positions": [100], "concept_id": "CONC_008", "importance": "secondary"}, {"concept": "Response Object", "context": "The HttpServletResponse object is used to send data back", "chunk_id": "CHUNK_010", "positions": [0], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "Redirect", "context": "Redirect involves browser fetching new URL", "chunk_id": "CHUNK_012", "positions": [50], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Forward", "context": "Forward is internal (browser unaware, URL unchanged)", "chunk_id": "CHUNK_012", "positions": [0], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "Model-View-Controller", "context": "Model-View-Controller (MVC) separates application logic", "chunk_id": "CHUNK_013", "positions": [0], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Model-View-Controller", "context": "In MVC: Model manages data/state", "chunk_id": "CHUNK_014", "positions": [0], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "GenericServlet", "context": "GenericServlet provides basic servlet functionality", "chunk_id": "CHUNK_015", "positions": [0], "concept_id": "CONC_013", "importance": "primary"}, {"concept": "HttpServlet", "context": "HttpServlet extends GenericServlet and implements HTTP-specific behavior", "chunk_id": "CHUNK_015", "positions": [80], "concept_id": "CONC_014", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 25, "difficulty_score": 9, "total_structures": 18, "total_applications": 12}', '"[{\"id\":\"CHUNK_001\",\"text\":\"The servlet classes are maintained by the container. Client makes request to the container. Container (itself has main program) manages the servlet. It instantiates and initiates the servlet by calling the method defined in the HttpServlet class.\",\"pages\":[1],\"start_pos\":0,\"end_pos\":232,\"summary\":\"Overview of servlet-container relationship and lifecycle initiation.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"Why main() is not written in servlet programs? The servlet classes are maintained by the container. Client makes request to the container. Container (itself has main program) manages the servlet. It instantiates and initiates the servlet by calling the method defined in the HttpServlet class.\",\"pages\":[2],\"start_pos\":233,\"end_pos\":465,\"summary\":\"Explanation why servlets lack a main method due to container management.\",\"chunk_type\":\"question_answer\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_003\",\"text\":\"Servlet/JSP Containers and Dynamic Pages: Client (Web Browser) connects to Web Server, which forwards to Application Server hosting Servlet Container. Components include JSP, Servlets, EJB, DB Server via JDBC.\",\"pages\":[3],\"start_pos\":466,\"end_pos\":630,\"summary\":\"System architecture showing interaction between client, web server, application server, and database.\",\"chunk_type\":\"diagram_description\",\"has_examples\":true,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Servlets are designed to service clients. Their primary job is to receive a client''s request and return a response. The request carries important data that the servlet must interpret, and the response contains information needed by the browser to render a page or redirect to another resource.\",\"pages\":[4],\"start_pos\":631,\"end_pos\":850,\"summary\":\"Core responsibility of servlets in handling requests and responses.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_008\",\"CONC_009\"]},{\"id\":\"CHUNK_005\",\"text\":\"The servlet lifecycle consists of five phases: class loading, instantiation (constructor), init() call (once), repeated service() calls for each request, and finally destroy() for cleanup before garbage collection.\",\"pages\":[5],\"start_pos\":851,\"end_pos\":1040,\"summary\":\"Stages of servlet lifecycle from creation to destruction.\",\"chunk_type\":\"process_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CHUNK_006\",\"text\":\"The init() method is called by the container after servlet instantiation but before handling any client requests. It provides a chance for one-time initialization such as setting up database connections or loading configuration. Override init() if your servlet requires initialization code.\",\"pages\":[6],\"start_pos\":1041,\"end_pos\":1250,\"summary\":\"Purpose and usage of the init() method in servlet lifecycle.\",\"chunk_type\":\"method_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_007\",\"text\":\"The service() method is invoked by the container upon each client request. It examines the HTTP method and calls the appropriate doGet(), doPost(), or other doXXX() method. Developers should not override service() in HttpServlet; instead, override doGet() or doPost().\",\"pages\":[7],\"start_pos\":1251,\"end_pos\":1470,\"summary\":\"Role of service() method in routing HTTP requests to specific handlers.\",\"chunk_type\":\"method_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\",\"CONC_007\"]},{\"id\":\"CHUNK_008\",\"text\":\"The doGet() and doPost() methods are where servlet logic begins, analogous to a main() method. They are called by service() based on the HTTP request method. At least one must be overridden. They can call each other to handle both GET and POST uniformly.\",\"pages\":[8],\"start_pos\":1471,\"end_pos\":1680,\"summary\":\"Usage and implementation guidance for doGet and doPost methods.\",\"chunk_type\":\"method_comparison\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\",\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_009\",\"text\":\"The HttpServletRequest object provides access to client data including headers (e.g., User-Agent), cookies, session info, HTTP method, input stream, and parameters via getParameter() for single values or getParameterValues() for multiple (e.g., checkboxes).\",\"pages\":[9],\"start_pos\":1681,\"end_pos\":1890,\"summary\":\"Features and access methods of the request object in servlets.\",\"chunk_type\":\"object_description\",\"has_examples\":true,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_010\",\"text\":\"The HttpServletResponse object is used to send data back to the browser. Obtain a Writer to output text (e.g., HTML), set content type (MIME type) like text/html or image/jpeg, and optionally redirect or forward to another resource before committing the response.\",\"pages\":[10],\"start_pos\":1891,\"end_pos\":2100,\"summary\":\"Capabilities and usage of the response object for output and redirection.\",\"chunk_type\":\"object_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\",\"CONC_011\"]},{\"id\":\"CHUNK_011\",\"text\":\"Example code: public void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException, ServletException { String typeParam = request.getParameter(\\\"type\\\"); String sizeParam = request.getParameter(\\\"size\\\"); } URL: http://127.0.0.1/servlet?type=froffy&size=grande\",\"pages\":[11],\"start_pos\":2101,\"end_pos\":2300,\"summary\":\"Code snippet demonstrating parameter extraction from request object.\",\"chunk_type\":\"code_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_012\",\"text\":\"Forward vs Redirect: Forward is internal (browser unaware, URL unchanged, request data preserved), suitable for SELECT operations. Redirect involves browser fetching new URL (address changes, no request data carryover), slower, used for INSERT/UPDATE/DELETE to prevent duplicate submissions.\",\"pages\":[12],\"start_pos\":2301,\"end_pos\":2550,\"summary\":\"Differences between server-side forward and client-side redirect with usage guidelines.\",\"chunk_type\":\"comparison\",\"has_examples\":true,\"main_concepts\":[\"CONC_011\",\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_009\"]},{\"id\":\"CHUNK_013\",\"text\":\"Model-View-Controller (MVC) separates application logic: Model (business/data), View (presentation, e.g., JSP), Controller (request handler, e.g., servlet). Promotes reusability, maintainability, and team specialization. Not limited to web applications.\",\"pages\":[13],\"start_pos\":2551,\"end_pos\":2750,\"summary\":\"Overview of MVC design pattern and its benefits in enterprise development.\",\"chunk_type\":\"pattern_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_014\",\"text\":\"In MVC: Model manages data/state (e.g., shopping cart), View displays content (JSP), Controller routes requests, processes input, updates model, and selects view. Controller acts as intermediary ensuring loose coupling between model and view.\",\"pages\":[14],\"start_pos\":2751,\"end_pos\":2950,\"summary\":\"Detailed roles of each MVC component in a web application context.\",\"chunk_type\":\"detailed_explanation\",\"has_examples\":true,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\",\"CONC_009\"]},{\"id\":\"CHUNK_015\",\"text\":\"GenericServlet provides basic servlet functionality independent of protocol. HttpServlet extends GenericServlet and implements HTTP-specific behavior including service() method that dispatches to doGet(), doPost(), etc. HttpServlet is abstract and requires overriding doXXX() methods.\",\"pages\":[15],\"start_pos\":2951,\"end_pos\":3150,\"summary\":\"Relationship between GenericServlet and HttpServlet with focus on HTTP method handling.\",\"chunk_type\":\"class_hierarchy\",\"has_examples\":false,\"main_concepts\":[\"CONC_013\",\"CONC_014\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Servlet\",\"aliases\":[\"HTTP servlet\",\"Java servlet\"],\"keywords\":[\"servlet\",\"java\",\"server-side\",\"web component\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A Java class that runs on a server and handles client requests, typically over HTTP. Servlets are managed by a container which controls their lifecycle including loading, initialization, servicing requests via service() method, and destruction. They do not have a main() method as execution is orchestrated by the container in response to web requests.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_002\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_002\",\"title\":\"Servlet Container\",\"aliases\":[\"Web container\",\"Servlet engine\"],\"keywords\":[\"container\",\"web container\",\"application server\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A runtime environment within an application server that manages the lifecycle of servlets. It loads servlet classes, instantiates them, calls their init(), service(), and destroy() methods, and handles threading for concurrent requests. Examples include Tomcat and Jetty.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_008\"]},{\"id\":\"CONC_003\",\"title\":\"Servlet Lifecycle\",\"aliases\":[\"Servlet life cycle\"],\"keywords\":[\"lifecycle\",\"init\",\"service\",\"destroy\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The sequence of stages a servlet goes through: loading into JVM, instantiation via constructor, initialization via init(), request processing via service(), and cleanup via destroy(). The container manages this entire process, ensuring each phase occurs only once except service() which may be called multiple times.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_005\"],\"related_concepts\":[\"CONC_001\",\"CONC_006\",\"CONC_007\"]},{\"id\":\"CONC_004\",\"title\":\"init() Method\",\"aliases\":[\"init method\"],\"keywords\":[\"init\",\"initialization\",\"setup\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A lifecycle method in servlets called once after instantiation. It allows developers to perform one-time setup such as initializing data structures, establishing database connections, or loading configuration files. Overriding this method is optional but common when initialization logic is required before handling client requests.\",\"concept_type\":\"method\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_003\",\"CONC_001\"]},{\"id\":\"CONC_005\",\"title\":\"service() Method\",\"aliases\":[\"service method\"],\"keywords\":[\"service\",\"request handling\",\"routing\"],\"confidence\":1,\"difficulty\":4,\"description\":\"The core method in a servlet that gets invoked for every client request. It determines the HTTP method (GET, POST, etc.) and dispatches the request to the corresponding doGet(), doPost(), or other doXXX() methods. Developers should not override this method in HttpServlet subclasses since it already contains proper routing logic.\",\"concept_type\":\"method\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_003\",\"CONC_009\",\"CONC_010\"]},{\"id\":\"CONC_006\",\"title\":\"doGet() Method\",\"aliases\":[\"doGet method\"],\"keywords\":[\"doGet\",\"GET\",\"retrieve\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A method in HttpServlet that handles HTTP GET requests. It is called by the service() method when a GET request arrives. This method should be overridden by developers to define behavior for retrieving data or rendering pages. It receives HttpServletRequest and HttpServletResponse objects for reading input and writing output.\",\"concept_type\":\"method\",\"extracted_from\":[\"CHUNK_008\"],\"related_concepts\":[\"CONC_005\",\"CONC_001\"]},{\"id\":\"CONC_007\",\"title\":\"doPost() Method\",\"aliases\":[\"doPost method\"],\"keywords\":[\"doPost\",\"POST\",\"submit\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A method in HttpServlet that handles HTTP POST requests. Invoked by the service() method upon receiving a POST request. Used primarily for submitting form data or performing state-changing operations. Like doGet(), it takes request and response parameters and must be overridden to implement custom logic.\",\"concept_type\":\"method\",\"extracted_from\":[\"CHUNK_008\"],\"related_concepts\":[\"CONC_005\",\"CONC_001\"]},{\"id\":\"CONC_008\",\"title\":\"Request Object\",\"aliases\":[\"HTTP request object\"],\"keywords\":[\"request\",\"HttpServletRequest\",\"input\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An instance of HttpServletRequest that encapsulates all data from the client''s HTTP request. It provides access to headers, cookies, session information, request parameters, HTTP method type, and input streams. Servlets use this object to extract user input and contextual data needed to generate responses.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_009\"],\"related_concepts\":[\"CONC_001\",\"CONC_011\"]},{\"id\":\"CONC_009\",\"title\":\"Response Object\",\"aliases\":[\"HTTP response object\"],\"keywords\":[\"response\",\"HttpServletResponse\",\"output\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An instance of HttpServletResponse used to send data back to the client. It allows setting content type (MIME type), status codes, headers, and obtaining output streams (Writer or OutputStream) for sending text or binary data such as HTML, JSON, images, or files.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_010\"],\"related_concepts\":[\"CONC_001\",\"CONC_008\"]},{\"id\":\"CONC_010\",\"title\":\"Redirect\",\"aliases\":[\"HTTP redirect\"],\"keywords\":[\"redirect\",\"sendRedirect\",\"302 redirect\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A technique where the server instructs the browser to make a new request to a different URL using HttpServletResponse.sendRedirect(). It results in two HTTP requests, changes the browser’s address bar, and does not preserve request-scoped attributes. Best used after data-modifying operations like INSERT, UPDATE, DELETE to prevent duplicate submissions.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_012\"],\"related_concepts\":[\"CONC_011\",\"CONC_009\"]},{\"id\":\"CONC_011\",\"title\":\"Forward\",\"aliases\":[\"server-side forward\"],\"keywords\":[\"forward\",\"RequestDispatcher\",\"include\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A server-side mechanism that transfers control internally from one component (like a servlet) to another (like a JSP) without informing the browser. Achieved via RequestDispatcher.forward(). The original URL remains unchanged in the browser, and request-scoped data is preserved. Suitable for SELECT operations where safe repetition is acceptable.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_012\"],\"related_concepts\":[\"CONC_010\",\"CONC_009\"]},{\"id\":\"CONC_012\",\"title\":\"Model-View-Controller\",\"aliases\":[\"MVC pattern\"],\"keywords\":[\"MVC\",\"design pattern\",\"separation of concerns\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A software architectural pattern that separates concerns into three interconnected components: Model (data and business logic), View (presentation layer, e.g., JSP), and Controller (request handler that routes input and updates model). In web applications, servlets often act as controllers while JSPs serve as views.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_014\"],\"related_concepts\":[\"CONC_001\",\"CONC_013\"]},{\"id\":\"CONC_013\",\"title\":\"GenericServlet\",\"aliases\":[],\"keywords\":[\"GenericServlet\",\"servlet\",\"protocol-independent\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An abstract class implementing the Servlet interface with protocol-independent functionality. It provides basic lifecycle management but lacks HTTP-specific features. Used as a base for creating non-HTTP servlets. For HTTP-based applications, HttpServlet (which extends GenericServlet) is preferred.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_015\"],\"related_concepts\":[\"CONC_001\",\"CONC_014\"]},{\"id\":\"CONC_014\",\"title\":\"HttpServlet\",\"aliases\":[],\"keywords\":[\"HttpServlet\",\"HTTP\",\"doGet\",\"doPost\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A concrete extension of GenericServlet tailored for HTTP communication. It implements the service() method to route HTTP requests based on method type (GET, POST, etc.) to corresponding protected methods like doGet() and doPost(). As an abstract class, it requires subclassing and overriding these doXXX() methods to provide actual behavior.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_015\"],\"related_concepts\":[\"CONC_013\",\"CONC_005\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"managed_by\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"The servlet classes are maintained by the container\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"has_a\",\"source\":\"CONC_001\",\"target\":\"CONC_003\",\"evidence\":\"Life of Servlet: First loaded, instantiated, init(), service(), destroy()\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"includes\",\"source\":\"CONC_003\",\"target\":\"CONC_004\",\"evidence\":\"init() method is called only once during lifecycle\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"includes\",\"source\":\"CONC_003\",\"target\":\"CONC_005\",\"evidence\":\"service() method is called repeatedly to handle requests\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"includes\",\"source\":\"CONC_003\",\"target\":\"CONC_006\",\"evidence\":\"doGet is part of request handling in service phase\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"includes\",\"source\":\"CONC_003\",\"target\":\"CONC_007\",\"evidence\":\"doPost is part of request handling in service phase\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"invokes\",\"source\":\"CONC_005\",\"target\":\"CONC_006\",\"evidence\":\"service() method invokes doGet() based on HTTP method\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"invokes\",\"source\":\"CONC_005\",\"target\":\"CONC_007\",\"evidence\":\"service() method invokes doPost() based on HTTP method\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"consumes\",\"source\":\"CONC_008\",\"target\":\"CONC_001\",\"evidence\":\"Servlet uses request object to get client data\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"produces\",\"source\":\"CONC_009\",\"target\":\"CONC_001\",\"evidence\":\"Servlet uses response object to send data back\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"uses\",\"source\":\"CONC_010\",\"target\":\"CONC_009\",\"evidence\":\"response.sendRedirect() performs redirect\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"uses\",\"source\":\"CONC_011\",\"target\":\"CONC_009\",\"evidence\":\"RequestDispatcher obtained from request and used with response\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"implemented_by\",\"source\":\"CONC_012\",\"target\":\"CONC_001\",\"evidence\":\"Servlet acts as controller in MVC\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_014\",\"type\":\"uses\",\"source\":\"CONC_012\",\"target\":\"CONC_009\",\"evidence\":\"JSP (view) renders response sent via response object\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_015\",\"type\":\"parent_of\",\"source\":\"CONC_013\",\"target\":\"CONC_014\",\"evidence\":\"HttpServlet extends GenericServlet\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_016\",\"type\":\"implements\",\"source\":\"CONC_014\",\"target\":\"CONC_005\",\"evidence\":\"HttpServlet provides default implementation of service()\",\"strength\":1,\"bidirectional\":false}]"', '2026-03-25 13:17:59.66117', '2026-03-25 13:17:59.66117', NULL, '[{"id": "module_1", "name": "Servlet Container and Lifecycle", "topic_count": 12}, {"id": "module_2", "name": "Servlet Classes and HTTP Methods", "topic_count": 10}, {"id": "module_3", "name": "Request and Response Objects", "topic_count": 10}, {"id": "module_4", "name": "Request Dispatching (Forward vs Redirect)", "topic_count": 8}, {"id": "module_5", "name": "Model-View-Controller (MVC) Pattern", "topic_count": 8}]', NULL, 'ITP4511 – Enterprise System Development

