INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'Lecture 10 Business Functions 2019 (1).pptx', '603cecf6a65ee4f376e683bc7d5502f2af5cbb3261ad3de796e0eb97f5c71d3c', '{"chunks": [{"id": "CHUNK_001", "text": "At the end of this topic, you will be able to: identify and explain business values in providing appropriate information to different management levels in business operations and decision making; identify and explain business functions, marketing functions, and financial functions related to adaptation of information technology for local SMEs based on the characteristics of target audiences and expectation of stakeholders in different business scenarios.", "pages": [1, 2], "end_pos": 346, "summary": "Learning outcomes focused on business, marketing, and financial functions in IT context for SMEs.", "start_pos": 0, "chunk_type": "learning_objectives", "has_examples": false, "main_concepts": ["CONC_001", "CONC_009", "CONC_012"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "At the end of this topic, you will be able to: demonstrate and understand the business; explain management and the management functions; understand the strategy-making and strategy-implementing roles of managers in business; describe the role of the marketing function within business; use and apply basic accounting terminology, concepts and techniques.", "pages": [3, 4], "end_pos": 612, "summary": "Learning objectives covering management, marketing, and accounting fundamentals.", "start_pos": 347, "chunk_type": "learning_objectives", "has_examples": false, "main_concepts": ["CONC_004", "CONC_006", "CONC_009", "CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_008"]}, {"id": "CHUNK_003", "text": "All of the commercial and industrial activities that seek profits by providing goods and services for sale. Earnings that remain in a firm after the costs of operations and taxes → Profits = Revenues – Costs. The purpose of a business is to earn a profit or make money for its owners. It rewards a business for providing the desired goods and services to consumers in an economical and efficient manner. In non-profit or not-for-profit organizations, any revenue earned above expenses is used to improve the organization – Red Cross.", "pages": [4, 5], "end_pos": 978, "summary": "Definition of business, profit, and organizational purpose.", "start_pos": 613, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_001", "CONC_002", "CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Business Management and Marketing Customer Relationship Management Supply Chain Human Resource Management Manufacturing.", "pages": [6], "end_pos": 1067, "summary": "List of key business functional areas covered in the course.", "start_pos": 979, "chunk_type": "topic_list", "has_examples": false, "main_concepts": ["CONC_004", "CONC_009", "CONC_020", "CONC_017"], "has_definitions": false, "secondary_concepts": ["CONC_018", "CONC_019"]}, {"id": "CHUNK_005", "text": "The process of planning, organizing, directing and controlling the activities of employees and combination with other resources to achieve organizational goals effectively and efficiently.", "pages": [7], "end_pos": 1236, "summary": "Definition of business management.", "start_pos": 1068, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_006", "text": "Managers are responsible for business performance and effectiveness. Managers are accountable to all key stakeholders.", "pages": [7, 8], "end_pos": 1358, "summary": "Role and accountability of effective managers.", "start_pos": 1237, "chunk_type": "statement", "has_examples": false, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "Planning: Defining the relationship among resources including materials, staff and financial backing. Directing: Ordering work tasks and even motivating teams to contribute to the organization. Controlling: Establishing performance standards, comparing actual performance with planned performance, reviewing and making adjustment.", "pages": [8], "end_pos": 1646, "summary": "Breakdown of planning, directing, and controlling functions.", "start_pos": 1359, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_004"]}, {"id": "CHUNK_008", "text": "It defines an organization’s goals. What does the organization do for its customers? What does the organization do for its employees? What does the organization do for its owner? Apple Computer’s 2017 mission statement: ''Apple designs Macs, the best personal computers in the world, along with OS X, iLife, iWork and professional software. Apple leads the digital music revolution with its iPods and iTunes online store. Apple has reinvented the mobile phone with its revolutionary iPhone and App store, and is defining the future of mobile media and computing devices with iPad.''", "pages": [9], "end_pos": 2088, "summary": "Explanation and example of a mission statement.", "start_pos": 1647, "chunk_type": "definition_and_example", "has_examples": true, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_009", "text": "Creation of strategies to meet goals at all levels, responsive to new challenges and new needs. Analyze the Organization and its Environment, Set Strategic Goals, Formulate Strategy.", "pages": [10], "end_pos": 2310, "summary": "Overview of strategic planning process.", "start_pos": 2089, "chunk_type": "process_description", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_010", "text": "The process of planning and implementing the conception, pricing, promotion, and distribution of ideas, goods and services to create exchanges that satisfy individual & organizational objectives. An exchange takes place when two parties give something of value to each other to satisfy their needs.", "pages": [11], "end_pos": 2632, "summary": "Definition of marketing and exchange concept.", "start_pos": 2311, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_011", "text": "Developing a marketing strategy: Identifies a potential target market of consumer through market segmentation; Analyses the needs of the identified target market by marketing research; Creates a marketing mix to satisfy the target market.", "pages": [11], "end_pos": 2880, "summary": "Steps in developing a marketing strategy.", "start_pos": 2633, "chunk_type": "process_description", "has_examples": false, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": ["CONC_011"]}, {"id": "CHUNK_012", "text": "Accounting is concerned primarily with the measurement and communication of financial information to aid decisions and control in a variety of business and other organizations.", "pages": [14], "end_pos": 3047, "summary": "Core definition of accounting.", "start_pos": 2881, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_013", "text": "Trial Balance: Internal report that lists the balances of all accounts that are related to assets, liabilities, revenues, expenses, gains, losses etc.", "pages": [14], "end_pos": 3205, "summary": "Definition of trial balance.", "start_pos": 3048, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_013"], "has_definitions": true, "secondary_concepts": ["CONC_012"]}, {"id": "CHUNK_014", "text": "Recording accounting data: Businesses need to record cash received and paid out. They will also record goods bought and sold, items bought to use rather than to sell, etc. Classifying and summarizing: Recorded data must be sorted out so as to be most useful to the business. It will be possible to work out how much profit or loss has been made by the business during a particular period. It will also be possible to show what resources are owned by the business, and what is owed by it. Communicating information: It reflects business performance and what the strengths and weaknesses of the business are.", "pages": [15], "end_pos": 3698, "summary": "Three core phases of accounting: recording, classifying, communicating.", "start_pos": 3206, "chunk_type": "process_description", "has_examples": false, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_002", "CONC_015"]}, {"id": "CHUNK_015", "text": "It is a formal report of the financial activities of a business, person, or other entity. A collection of reports about an organization''s financial results and condition. Financial Reports of MTR: https://www.mtr.com.hk/en/corporate/investor/financialinfo.html", "pages": [16], "end_pos": 3942, "summary": "Definition and example of financial reporting.", "start_pos": 3699, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_014"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_016", "text": "To determine the ability of a business to generate cash, and the sources and uses of that cash. To determine whether a business has the capability to pay back its debts. To derive financial ratios from the statements that can indicate the condition of the business. To investigate the details of certain business transactions.", "pages": [17], "end_pos": 4230, "summary": "Purposes of analyzing financial statements.", "start_pos": 3943, "chunk_type": "purpose_statement", "has_examples": false, "main_concepts": ["CONC_014"], "has_definitions": false, "secondary_concepts": ["CONC_016"]}, {"id": "CHUNK_017", "text": "One of basic financial statements which is a snapshot of a company’s financial position on a particular date. This statement includes all elements in the accounting equation and show the balance between assets on one side and liabilities and owners’ equity on the other side. Assets - Things that a firm owns. Liabilities - Debts of the firm. Owners’ Equity - Difference between what firm owns and what it owes to others. Assets = Liabilities + Owners’ Equity.", "pages": [18], "end_pos": 4660, "summary": "Detailed explanation of the balance sheet and accounting equation.", "start_pos": 4231, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_015"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_018", "text": "Another basic financial statements which summarizes the results of the firm’s operations over a period time monthly, quarterly, or annually. Show total revenues and expenses for the time period. Show different measures of profit. Consolidated Statement of Comprehensive Income of MTR: Half year ended 30 June 2018, Profit for the period 7,533 HK$ million.", "pages": [19], "end_pos": 5048, "summary": "Definition and real-world example of income statement.", "start_pos": 4661, "chunk_type": "definition_and_example", "has_examples": true, "main_concepts": ["CONC_016"], "has_definitions": true, "secondary_concepts": ["CONC_014"]}, {"id": "CHUNK_019", "text": "All activities that occur between the growing or mining of raw materials and the appearance of finished products on the store shelf. Supply Chain Management (SCM) from raw materials to consumer: Supplier → Manufacturer → Wholesaler → Retailer → Customer.", "pages": [21], "end_pos": 5368, "summary": "Definition of supply chain and its stages.", "start_pos": 5049, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_017"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_020", "text": "Materials management: To ensure materials are available for production, and products are available for delivery to customers. To maintain the lowest possible material and product levels in store. To plan manufacturing activities, delivery schedules, and purchasing activities. Logistics: To analyze and manage the status and make forecasts about the supply chain.", "pages": [22], "end_pos": 5770, "summary": "Definitions of materials management and logistics.", "start_pos": 5369, "chunk_type": "dual_definition", "has_examples": false, "main_concepts": ["CONC_018", "CONC_019"], "has_definitions": true, "secondary_concepts": ["CONC_017"]}, {"id": "CHUNK_021", "text": "To manage all data relating to a customer to improve the quality of the interaction. Example of CRM – Odoo CRM.", "pages": [24], "end_pos": 5930, "summary": "Definition and example of CRM.", "start_pos": 5771, "chunk_type": "definition_and_example", "has_examples": true, "main_concepts": ["CONC_020"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_022", "text": "One-to-One Marketing: It emphasizes personalized interactions with customers that build greater customer loyalty. Sales Force Automation: It automates business tasks such as tracking of customer interactions / history and analyzing sales forecasts and performance. Call Center Automation: It improves efficiency that screening qualified target customers from a large volume of customers (cold calling).", "pages": [25], "end_pos": 6358, "summary": "Set of CRM-related automation and marketing techniques.", "start_pos": 5931, "chunk_type": "definition_set", "has_examples": false, "main_concepts": ["CONC_021", "CONC_022", "CONC_023"], "has_definitions": true, "secondary_concepts": ["CONC_020"]}, {"id": "CHUNK_023", "text": "Examples of tools that provide CRM functionality within the SAP ERP system: Contact management tool – To make sure that information about sales contacts is available throughout the organization. Sales activity manager – Supports a strategic and organized approach to sales activity planning and can help make sure that follow-up activities are accomplished. Employing a separate CRM system that communicates with the ERP system.", "pages": [26], "end_pos": 6802, "summary": "CRM tools within SAP ERP environment.", "start_pos": 6359, "chunk_type": "example_list", "has_examples": true, "main_concepts": ["CONC_020"], "has_definitions": false, "secondary_concepts": ["CONC_022"]}, {"id": "CHUNK_024", "text": "A software delivery model: A software product is hosted by a company—such as SAP—on its servers and is accessed by customers via a Web browser. Sometimes described as a utility. A subset of cloud computing.", "pages": [27], "end_pos": 7110, "summary": "Definition of Software as a Service (SaaS).", "start_pos": 6803, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_024"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_025", "text": "Initial affordability: Lower cost to implement software provided through SaaS. Shorter implementation time: Implementation time usually shorter as the user does not have to worry about technical issues. Lower support costs and complexity: Do not need to hire additional IT personnel to implement new systems and applications.", "pages": [28], "end_pos": 7534, "summary": "Advantages of SaaS adoption.", "start_pos": 7111, "chunk_type": "benefits_list", "has_examples": false, "main_concepts": ["CONC_025"], "has_definitions": true, "secondary_concepts": ["CONC_024"]}, {"id": "CHUNK_026", "text": "Security, Bandwidth/response time, Flexibility, No frills, Technical, not business focus.", "pages": [29], "end_pos": 7652, "summary": "List of SaaS limitations and concerns.", "start_pos": 7535, "chunk_type": "challenge_list", "has_examples": false, "main_concepts": ["CONC_026"], "has_definitions": false, "secondary_concepts": ["CONC_024"]}], "concepts": [{"id": "CONC_001", "title": "Business", "aliases": ["enterprise", "company"], "keywords": ["profit", "goods", "services", "non-profit"], "confidence": 1.0, "difficulty": 2, "description": "An organization or entity engaged in commercial, industrial, or professional activities aimed at generating profit by providing goods and services. The primary purpose is to earn money for owners, achieved through efficient and economical delivery of desired products or services. Non-profit organizations reinvest surplus revenue into organizational improvement rather than distributing profits to owners.", "concept_type": "object", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_002", "title": "Profit", "aliases": ["net income"], "keywords": ["revenue", "costs", "earnings", "taxes"], "confidence": 1.0, "difficulty": 2, "description": "The financial gain realized when revenue exceeds the costs of operations and taxes. Calculated as Profits = Revenues - Costs. It serves as a key performance indicator for businesses and acts as a reward for delivering value to consumers efficiently.", "concept_type": "formula", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_018"]}, {"id": "CONC_003", "title": "Business Purpose", "aliases": ["organizational purpose"], "keywords": ["mission", "profit motive", "value creation"], "confidence": 1.0, "difficulty": 2, "description": "The fundamental reason an organization exists, which is typically to generate profit for its owners by meeting customer needs effectively. For non-profits, the purpose shifts toward societal benefit, with any surplus used to enhance the organization’s mission, such as in the case of the Red Cross.", "concept_type": "theory", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_012"]}, {"id": "CONC_004", "title": "Business Management", "aliases": ["management process"], "keywords": ["planning", "organizing", "directing", "controlling"], "confidence": 1.0, "difficulty": 3, "description": "The process of planning, organizing, directing, and controlling employee activities and resource combinations to achieve organizational goals efficiently and effectively. Managers are accountable for performance and must balance stakeholder expectations while ensuring operational success.", "concept_type": "process", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_005", "CONC_006"]}, {"id": "CONC_005", "title": "Effective Manager", "aliases": ["manager"], "keywords": ["accountability", "performance", "leadership"], "confidence": 1.0, "difficulty": 2, "description": "A manager who ensures business performance and effectiveness by aligning team efforts with organizational objectives. They are accountable to stakeholders and responsible for guiding resources toward goal achievement through leadership and oversight.", "concept_type": "person", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_004", "CONC_006"]}, {"id": "CONC_006", "title": "Management Functions", "aliases": ["five functions of management"], "keywords": ["planning", "organizing", "directing", "controlling"], "confidence": 1.0, "difficulty": 3, "description": "Core responsibilities of managers including planning (setting goals), organizing (allocating resources), directing (leading teams), and controlling (monitoring performance). These functions ensure that organizational objectives are met efficiently and adaptively in dynamic environments.", "concept_type": "process", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_004", "CONC_005"]}, {"id": "CONC_007", "title": "Mission Statement", "aliases": ["business mission"], "keywords": ["organizational goals", "purpose", "identity"], "confidence": 1.0, "difficulty": 3, "description": "A formal summary defining an organization''s core purpose and focus, answering what it does for customers, employees, and owners. It guides strategic decisions and reflects identity, as exemplified by Apple’s 2017 statement emphasizing innovation in personal computing and digital media.", "concept_type": "object", "extracted_from": ["CHUNK_009"], "related_concepts": ["CONC_003", "CONC_008"]}, {"id": "CONC_008", "title": "Business Strategy", "aliases": ["strategic management"], "keywords": ["strategic planning", "goal alignment", "market adaptation"], "confidence": 1.0, "difficulty": 4, "description": "The creation of long-term plans to meet organizational goals in response to market challenges and evolving needs. Involves analyzing internal and external environments, setting objectives, matching capabilities, and formulating actionable strategies, such as Apple’s approach to product differentiation and ecosystem integration.", "concept_type": "process", "extracted_from": ["CHUNK_010"], "related_concepts": ["CONC_007", "CONC_006"]}, {"id": "CONC_009", "title": "Marketing", "aliases": ["marketing function"], "keywords": ["promotion", "pricing", "distribution", "exchange"], "confidence": 1.0, "difficulty": 3, "description": "The process of planning and executing the conception, pricing, promotion, and distribution of ideas, goods, and services to create exchanges that satisfy individual and organizational objectives. An exchange occurs when both parties provide value, driven by understanding consumer needs through research and segmentation.", "concept_type": "process", "extracted_from": ["CHUNK_011"], "related_concepts": ["CONC_010", "CONC_011"]}, {"id": "CONC_010", "title": "Marketing Strategy", "aliases": ["strategic marketing"], "keywords": ["market segmentation", "marketing mix", "consumer needs"], "confidence": 1.0, "difficulty": 3, "description": "A plan developed to reach target markets by identifying consumer segments through market segmentation, analyzing their needs via marketing research, and creating a tailored marketing mix (product, price, place, promotion) to fulfill those needs and drive satisfaction and loyalty.", "concept_type": "process", "extracted_from": ["CHUNK_011"], "related_concepts": ["CONC_009", "CONC_011"]}, {"id": "CONC_011", "title": "Marketing Mix", "aliases": ["4Ps of marketing"], "keywords": ["4Ps", "product", "price", "place", "promotion"], "confidence": 0.95, "difficulty": 3, "description": "A set of controllable tactical tools—product, price, place, and promotion—used to produce the desired response in the target market. It is central to marketing strategy and enables businesses to deliver value propositions aligned with customer expectations and competitive positioning.", "concept_type": "component", "extracted_from": ["CHUNK_011"], "related_concepts": ["CONC_010", "CONC_009"]}, {"id": "CONC_012", "title": "Accounting", "aliases": ["financial accounting"], "keywords": ["financial information", "decision aid", "control"], "confidence": 1.0, "difficulty": 3, "description": "The discipline concerned with measuring and communicating financial information to support decision-making and control within organizations. It involves recording transactions, classifying data, summarizing results, and producing reports like trial balances and financial statements to reflect performance and condition.", "concept_type": "process", "extracted_from": ["CHUNK_014"], "related_concepts": ["CONC_013", "CONC_014"]}, {"id": "CONC_013", "title": "Trial Balance", "aliases": ["trial balance report"], "keywords": ["ledger", "balance verification", "error detection"], "confidence": 1.0, "difficulty": 3, "description": "An internal accounting report listing the balances of all ledger accounts related to assets, liabilities, revenues, expenses, gains, and losses. Used to verify arithmetic accuracy before preparing formal financial statements and detect potential errors in bookkeeping.", "concept_type": "object", "extracted_from": ["CHUNK_014"], "related_concepts": ["CONC_012", "CONC_015"]}, {"id": "CONC_014", "title": "Financial Reporting", "aliases": ["financial reports"], "keywords": ["financial statements", "disclosure", "transparency"], "confidence": 1.0, "difficulty": 3, "description": "The formal communication of a business’s financial activities and condition through standardized reports such as income statements, balance sheets, and cash flow statements. These reports help stakeholders assess performance, solvency, and investment potential, as seen in MTR Corporation’s disclosures.", "concept_type": "process", "extracted_from": ["CHUNK_016"], "related_concepts": ["CONC_015", "CONC_016"]}, {"id": "CONC_015", "title": "Balance Sheet", "aliases": ["statement of financial position"], "keywords": ["assets", "liabilities", "equity", "financial position"], "confidence": 1.0, "difficulty": 3, "description": "A fundamental financial statement presenting a company''s financial position on a specific date. It reflects the accounting equation: Assets = Liabilities + Owners’ Equity. Assets represent owned resources, liabilities are debts, and equity is the residual interest after deducting liabilities from assets.", "concept_type": "object", "extracted_from": ["CHUNK_018"], "related_concepts": ["CONC_013", "CONC_012"]}, {"id": "CONC_016", "title": "Income Statement", "aliases": ["profit and loss account", "statement of comprehensive income"], "keywords": ["revenue", "expenses", "profit", "comprehensive income"], "confidence": 1.0, "difficulty": 3, "description": "A basic financial statement summarizing a firm’s operating results over a period (monthly, quarterly, annually). It shows total revenues, expenses, and various profit measures such as net income and comprehensive income, enabling evaluation of profitability and operational efficiency.", "concept_type": "object", "extracted_from": ["CHUNK_019"], "related_concepts": ["CONC_014", "CONC_015"]}, {"id": "CONC_017", "title": "Supply Chain", "aliases": ["value chain"], "keywords": ["raw materials", "manufacturing", "distribution"], "confidence": 1.0, "difficulty": 3, "description": "All activities from raw material sourcing to finished product delivery to consumers. Includes stages such as supplier, manufacturer, wholesaler, and retailer. Supply Chain Management (SCM) coordinates this flow to optimize availability, cost, and logistics forecasting.", "concept_type": "process", "extracted_from": ["CHUNK_021"], "related_concepts": ["CONC_018", "CONC_019"]}, {"id": "CONC_018", "title": "Materials Management", "aliases": ["inventory management"], "keywords": ["inventory", "production planning", "purchasing"], "confidence": 1.0, "difficulty": 3, "description": "Ensures materials are available for production and products for customer delivery while minimizing inventory levels. Involves planning manufacturing schedules, deliveries, and purchasing to maintain efficiency and reduce holding costs across the supply chain.", "concept_type": "process", "extracted_from": ["CHUNK_022"], "related_concepts": ["CONC_017", "CONC_019"]}, {"id": "CONC_019", "title": "Logistics", "aliases": ["supply chain logistics"], "keywords": ["forecasting", "distribution", "supply chain monitoring"], "confidence": 1.0, "difficulty": 3, "description": "The analysis and management of supply chain status, including forecasting demand, tracking shipments, and optimizing distribution networks. It supports materials management by ensuring timely movement of goods and responsiveness to disruptions.", "concept_type": "process", "extracted_from": ["CHUNK_022"], "related_concepts": ["CONC_017", "CONC_018"]}, {"id": "CONC_020", "title": "Customer Relationship Management (CRM)", "aliases": ["CRM"], "keywords": ["customer data", "interaction", "loyalty"], "confidence": 1.0, "difficulty": 3, "description": "A system for managing all data relating to customers to improve interaction quality and build loyalty. Examples include Odoo CRM and SAP-based tools like contact managers and sales activity trackers, which automate tasks and centralize customer information across the organization.", "concept_type": "system", "extracted_from": ["CHUNK_024"], "related_concepts": ["CONC_021", "CONC_022"]}, {"id": "CONC_021", "title": "One-to-One Marketing", "aliases": ["personalized marketing"], "keywords": ["personalization", "customer loyalty", "individual targeting"], "confidence": 1.0, "difficulty": 3, "description": "A personalized marketing approach focusing on individual customer interactions to increase loyalty and satisfaction. It leverages CRM data to tailor communications and offers, enhancing perceived value and long-term engagement.", "concept_type": "process", "extracted_from": ["CHUNK_025"], "related_concepts": ["CONC_020", "CONC_022"]}, {"id": "CONC_022", "title": "Sales Force Automation", "aliases": ["SFA"], "keywords": ["sales tracking", "automation", "performance analysis"], "confidence": 1.0, "difficulty": 3, "description": "Technology that automates sales-related tasks such as tracking customer interactions, managing follow-ups, and analyzing forecasts. Integrated within CRM systems, it improves sales efficiency and accuracy in performance measurement.", "concept_type": "process", "extracted_from": ["CHUNK_025"], "related_concepts": ["CONC_020", "CONC_021"]}, {"id": "CONC_023", "title": "Call Center Automation", "aliases": ["automated call centers"], "keywords": ["lead qualification", "cold calling", "efficiency"], "confidence": 1.0, "difficulty": 3, "description": "Use of technology to improve call center efficiency by screening qualified leads from large volumes of cold calls. Automates workflows and prioritizes high-potential customers, increasing conversion rates and reducing manual effort.", "concept_type": "process", "extracted_from": ["CHUNK_025"], "related_concepts": ["CONC_020", "CONC_022"]}, {"id": "CONC_024", "title": "Software as a Service (SaaS)", "aliases": ["SaaS"], "keywords": ["cloud computing", "web-based access", "hosted software"], "confidence": 1.0, "difficulty": 3, "description": "A software delivery model where applications are hosted by a provider (e.g., SAP) and accessed by users via web browsers. Part of cloud computing, it offers lower implementation costs, faster deployment, reduced IT overhead, but raises concerns about security and customization.", "concept_type": "architecture", "extracted_from": ["CHUNK_027"], "related_concepts": ["CONC_025", "CONC_026"]}, {"id": "CONC_025", "title": "Initial Affordability of SaaS", "aliases": ["SaaS affordability"], "keywords": ["low cost", "implementation", "SME adoption"], "confidence": 1.0, "difficulty": 3, "description": "Refers to the lower upfront cost of implementing SaaS solutions compared to traditional on-premise software. This makes it particularly attractive for SMEs seeking scalable IT infrastructure without significant capital investment.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_028"], "related_concepts": ["CONC_024", "CONC_026"]}, {"id": "CONC_026", "title": "SaaS Limitations", "aliases": ["SaaS challenges"], "keywords": ["security", "bandwidth", "flexibility", "customization"], "confidence": 1.0, "difficulty": 3, "description": "Key drawbacks of Software as a Service include security vulnerabilities, bandwidth dependency, limited flexibility in customization, generic features (''no frills''), and a technical rather than business-focused design orientation, potentially misaligned with strategic objectives.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_029"], "related_concepts": ["CONC_024", "CONC_025"]}], "relationships": [{"id": "REL_001", "type": "produces", "source": "CONC_001", "target": "CONC_002", "evidence": "Business seeks profits as defined by revenue minus costs.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "has", "source": "CONC_001", "target": "CONC_003", "evidence": "Every business has a purpose, primarily to earn profit.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "implements", "source": "CONC_004", "target": "CONC_006", "evidence": "Business management executes the five management functions.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "performs", "source": "CONC_005", "target": "CONC_004", "evidence": "Managers carry out business management processes.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "defines", "source": "CONC_007", "target": "CONC_003", "evidence": "Mission statement articulates the business purpose.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "guided_by", "source": "CONC_008", "target": "CONC_007", "evidence": "Strategy is created based on mission and goals.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "requires", "source": "CONC_009", "target": "CONC_010", "evidence": "Marketing relies on a well-defined strategy.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "creates", "source": "CONC_010", "target": "CONC_011", "evidence": "Marketing strategy produces a marketing mix.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "uses", "source": "CONC_012", "target": "CONC_013", "evidence": "Accounting uses trial balance for reporting.", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "includes", "source": "CONC_014", "target": "CONC_015", "evidence": "Financial reports contain balance sheets.", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "includes", "source": "CONC_014", "target": "CONC_016", "evidence": "Financial reports include income statements.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "measures", "source": "CONC_015", "target": "CONC_002", "evidence": "Balance sheet reflects profitability context.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "managed_by", "source": "CONC_017", "target": "CONC_018", "evidence": "Materials management is part of SCM.", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "managed_by", "source": "CONC_017", "target": "CONC_019", "evidence": "Logistics manages supply chain flow.", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "enables", "source": "CONC_020", "target": "CONC_021", "evidence": "CRM supports one-to-one marketing.", "strength": 1.0, "bidirectional": false}, {"id": "REL_016", "type": "implements", "source": "CONC_020", "target": "CONC_022", "evidence": "CRM systems automate sales force tasks.", "strength": 1.0, "bidirectional": false}, {"id": "REL_017", "type": "implements", "source": "CONC_020", "target": "CONC_023", "evidence": "CRM includes call center automation features.", "strength": 1.0, "bidirectional": false}, {"id": "REL_018", "type": "has", "source": "CONC_024", "target": "CONC_025", "evidence": "SaaS offers initial affordability as a benefit.", "strength": 1.0, "bidirectional": false}, {"id": "REL_019", "type": "has", "source": "CONC_024", "target": "CONC_026", "evidence": "SaaS comes with inherent limitations.", "strength": 1.0, "bidirectional": false}, {"id": "REL_020", "type": "involves", "source": "CONC_008", "target": "CONC_006", "evidence": "Strategy-making is a role of managers using management functions.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 26, "missing_links": [], "coverage_score": 1.0, "total_concepts": 26, "consistency_score": 1.0, "total_relationships": 20}, "document_metadata": {"title": "IT114105 Higher Diploma in Software Engineering", "language": "English", "main_topic": "Business Management, Marketing, and Accounting Fundamentals in IT Context", "difficulty_level": "Intermediate", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "Business", "context": "Defined as profit-seeking entity providing goods/services.", "chunk_id": "CHUNK_003", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Profit", "context": "Defined mathematically and contextually within business operations.", "chunk_id": "CHUNK_003", "positions": [80], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Business Purpose", "context": "Explained as earning profit for owners, with non-profit contrast.", "chunk_id": "CHUNK_003", "positions": [180], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Business Management", "context": "Defined as planning, organizing, directing, controlling.", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Effective Manager", "context": "Described as responsible for performance and stakeholder accountability.", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Management Functions", "context": "Detailed breakdown of planning, directing, controlling.", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Mission Statement", "context": "Defined and illustrated with Apple example.", "chunk_id": "CHUNK_008", "positions": [0], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Business Strategy", "context": "Described as goal-oriented planning responsive to change.", "chunk_id": "CHUNK_009", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Marketing", "context": "Defined as process creating exchanges satisfying objectives.", "chunk_id": "CHUNK_010", "positions": [0], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "Marketing Strategy", "context": "Explained through segmentation, research, mix creation.", "chunk_id": "CHUNK_011", "positions": [0], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Marketing Mix", "context": "Implied as output of marketing strategy development.", "chunk_id": "CHUNK_011", "positions": [150], "concept_id": "CONC_011", "importance": "secondary"}, {"concept": "Accounting", "context": "Defined as measurement and communication of financial info.", "chunk_id": "CHUNK_012", "positions": [0], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Trial Balance", "context": "Defined as internal report listing account balances.", "chunk_id": "CHUNK_013", "positions": [0], "concept_id": "CONC_013", "importance": "primary"}, {"concept": "Financial Reporting", "context": "Defined as formal report of financial activities and condition.", "chunk_id": "CHUNK_015", "positions": [0], "concept_id": "CONC_014", "importance": "primary"}, {"concept": "Balance Sheet", "context": "Defined as snapshot of financial position using accounting equation.", "chunk_id": "CHUNK_017", "positions": [0], "concept_id": "CONC_015", "importance": "primary"}, {"concept": "Income Statement", "context": "Defined as summary of operational results over time period.", "chunk_id": "CHUNK_018", "positions": [0], "concept_id": "CONC_016", "importance": "primary"}, {"concept": "Supply Chain", "context": "Defined as full journey from raw materials to consumer.", "chunk_id": "CHUNK_019", "positions": [0], "concept_id": "CONC_017", "importance": "primary"}, {"concept": "Materials Management", "context": "Defined as ensuring availability while minimizing inventory.", "chunk_id": "CHUNK_020", "positions": [0], "concept_id": "CONC_018", "importance": "primary"}, {"concept": "Logistics", "context": "Defined as analysis and forecasting of supply chain status.", "chunk_id": "CHUNK_020", "positions": [200], "concept_id": "CONC_019", "importance": "primary"}, {"concept": "Customer Relationship Management (CRM)", "context": "Defined as managing customer data to improve interaction.", "chunk_id": "CHUNK_021", "positions": [0], "concept_id": "CONC_020", "importance": "primary"}, {"concept": "One-to-One Marketing", "context": "Defined as personalized interaction building loyalty.", "chunk_id": "CHUNK_022", "positions": [0], "concept_id": "CONC_021", "importance": "primary"}, {"concept": "Sales Force Automation", "context": "Defined as automation of customer tracking and forecasting.", "chunk_id": "CHUNK_022", "positions": [100], "concept_id": "CONC_022", "importance": "primary"}, {"concept": "Call Center Automation", "context": "Defined as improving efficiency in lead screening.", "chunk_id": "CHUNK_022", "positions": [250], "concept_id": "CONC_023", "importance": "primary"}, {"concept": "Software as a Service (SaaS)", "context": "Defined as hosted software accessed via web browser.", "chunk_id": "CHUNK_024", "positions": [0], "concept_id": "CONC_024", "importance": "primary"}, {"concept": "Initial Affordability of SaaS", "context": "Described as lower cost and faster implementation.", "chunk_id": "CHUNK_025", "positions": [0], "concept_id": "CONC_025", "importance": "primary"}, {"concept": "SaaS Limitations", "context": "Listed as security, bandwidth, flexibility, focus issues.", "chunk_id": "CHUNK_026", "positions": [0], "concept_id": "CONC_026", "importance": "primary"}]}', '{"total_modules": 6, "total_concepts": 28, "difficulty_score": 5, "total_structures": 12, "total_applications": 8}', '"[{\"id\":\"CHUNK_001\",\"text\":\"At the end of this topic, you will be able to: identify and explain business values in providing appropriate information to different management levels in business operations and decision making; identify and explain business functions, marketing functions, and financial functions related to adaptation of information technology for local SMEs based on the characteristics of target audiences and expectation of stakeholders in different business scenarios.\",\"pages\":[1,2],\"start_pos\":0,\"end_pos\":346,\"summary\":\"Learning outcomes focused on business, marketing, and financial functions in IT context for SMEs.\",\"chunk_type\":\"learning_objectives\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_009\",\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"At the end of this topic, you will be able to: demonstrate and understand the business; explain management and the management functions; understand the strategy-making and strategy-implementing roles of managers in business; describe the role of the marketing function within business; use and apply basic accounting terminology, concepts and techniques.\",\"pages\":[3,4],\"start_pos\":347,\"end_pos\":612,\"summary\":\"Learning objectives covering management, marketing, and accounting fundamentals.\",\"chunk_type\":\"learning_objectives\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\",\"CONC_006\",\"CONC_009\",\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_008\"]},{\"id\":\"CHUNK_003\",\"text\":\"All of the commercial and industrial activities that seek profits by providing goods and services for sale. Earnings that remain in a firm after the costs of operations and taxes → Profits = Revenues – Costs. The purpose of a business is to earn a profit or make money for its owners. It rewards a business for providing the desired goods and services to consumers in an economical and efficient manner. In non-profit or not-for-profit organizations, any revenue earned above expenses is used to improve the organization – Red Cross.\",\"pages\":[4,5],\"start_pos\":613,\"end_pos\":978,\"summary\":\"Definition of business, profit, and organizational purpose.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Business Management and Marketing Customer Relationship Management Supply Chain Human Resource Management Manufacturing.\",\"pages\":[6],\"start_pos\":979,\"end_pos\":1067,\"summary\":\"List of key business functional areas covered in the course.\",\"chunk_type\":\"topic_list\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\",\"CONC_009\",\"CONC_020\",\"CONC_017\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_018\",\"CONC_019\"]},{\"id\":\"CHUNK_005\",\"text\":\"The process of planning, organizing, directing and controlling the activities of employees and combination with other resources to achieve organizational goals effectively and efficiently.\",\"pages\":[7],\"start_pos\":1068,\"end_pos\":1236,\"summary\":\"Definition of business management.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_006\",\"text\":\"Managers are responsible for business performance and effectiveness. Managers are accountable to all key stakeholders.\",\"pages\":[7,8],\"start_pos\":1237,\"end_pos\":1358,\"summary\":\"Role and accountability of effective managers.\",\"chunk_type\":\"statement\",\"has_examples\":false,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_007\",\"text\":\"Planning: Defining the relationship among resources including materials, staff and financial backing. Directing: Ordering work tasks and even motivating teams to contribute to the organization. Controlling: Establishing performance standards, comparing actual performance with planned performance, reviewing and making adjustment.\",\"pages\":[8],\"start_pos\":1359,\"end_pos\":1646,\"summary\":\"Breakdown of planning, directing, and controlling functions.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_008\",\"text\":\"It defines an organization’s goals. What does the organization do for its customers? What does the organization do for its employees? What does the organization do for its owner? Apple Computer’s 2017 mission statement: ''Apple designs Macs, the best personal computers in the world, along with OS X, iLife, iWork and professional software. Apple leads the digital music revolution with its iPods and iTunes online store. Apple has reinvented the mobile phone with its revolutionary iPhone and App store, and is defining the future of mobile media and computing devices with iPad.''\",\"pages\":[9],\"start_pos\":1647,\"end_pos\":2088,\"summary\":\"Explanation and example of a mission statement.\",\"chunk_type\":\"definition_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_009\",\"text\":\"Creation of strategies to meet goals at all levels, responsive to new challenges and new needs. Analyze the Organization and its Environment, Set Strategic Goals, Formulate Strategy.\",\"pages\":[10],\"start_pos\":2089,\"end_pos\":2310,\"summary\":\"Overview of strategic planning process.\",\"chunk_type\":\"process_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_010\",\"text\":\"The process of planning and implementing the conception, pricing, promotion, and distribution of ideas, goods and services to create exchanges that satisfy individual & organizational objectives. An exchange takes place when two parties give something of value to each other to satisfy their needs.\",\"pages\":[11],\"start_pos\":2311,\"end_pos\":2632,\"summary\":\"Definition of marketing and exchange concept.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_011\",\"text\":\"Developing a marketing strategy: Identifies a potential target market of consumer through market segmentation; Analyses the needs of the identified target market by marketing research; Creates a marketing mix to satisfy the target market.\",\"pages\":[11],\"start_pos\":2633,\"end_pos\":2880,\"summary\":\"Steps in developing a marketing strategy.\",\"chunk_type\":\"process_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_011\"]},{\"id\":\"CHUNK_012\",\"text\":\"Accounting is concerned primarily with the measurement and communication of financial information to aid decisions and control in a variety of business and other organizations.\",\"pages\":[14],\"start_pos\":2881,\"end_pos\":3047,\"summary\":\"Core definition of accounting.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_013\",\"text\":\"Trial Balance: Internal report that lists the balances of all accounts that are related to assets, liabilities, revenues, expenses, gains, losses etc.\",\"pages\":[14],\"start_pos\":3048,\"end_pos\":3205,\"summary\":\"Definition of trial balance.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_012\"]},{\"id\":\"CHUNK_014\",\"text\":\"Recording accounting data: Businesses need to record cash received and paid out. They will also record goods bought and sold, items bought to use rather than to sell, etc. Classifying and summarizing: Recorded data must be sorted out so as to be most useful to the business. It will be possible to work out how much profit or loss has been made by the business during a particular period. It will also be possible to show what resources are owned by the business, and what is owed by it. Communicating information: It reflects business performance and what the strengths and weaknesses of the business are.\",\"pages\":[15],\"start_pos\":3206,\"end_pos\":3698,\"summary\":\"Three core phases of accounting: recording, classifying, communicating.\",\"chunk_type\":\"process_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\",\"CONC_015\"]},{\"id\":\"CHUNK_015\",\"text\":\"It is a formal report of the financial activities of a business, person, or other entity. A collection of reports about an organization''s financial results and condition. Financial Reports of MTR: https://www.mtr.com.hk/en/corporate/investor/financialinfo.html\",\"pages\":[16],\"start_pos\":3699,\"end_pos\":3942,\"summary\":\"Definition and example of financial reporting.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_014\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_016\",\"text\":\"To determine the ability of a business to generate cash, and the sources and uses of that cash. To determine whether a business has the capability to pay back its debts. To derive financial ratios from the statements that can indicate the condition of the business. To investigate the details of certain business transactions.\",\"pages\":[17],\"start_pos\":3943,\"end_pos\":4230,\"summary\":\"Purposes of analyzing financial statements.\",\"chunk_type\":\"purpose_statement\",\"has_examples\":false,\"main_concepts\":[\"CONC_014\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_016\"]},{\"id\":\"CHUNK_017\",\"text\":\"One of basic financial statements which is a snapshot of a company’s financial position on a particular date. This statement includes all elements in the accounting equation and show the balance between assets on one side and liabilities and owners’ equity on the other side. Assets - Things that a firm owns. Liabilities - Debts of the firm. Owners’ Equity - Difference between what firm owns and what it owes to others. Assets = Liabilities + Owners’ Equity.\",\"pages\":[18],\"start_pos\":4231,\"end_pos\":4660,\"summary\":\"Detailed explanation of the balance sheet and accounting equation.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_015\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_018\",\"text\":\"Another basic financial statements which summarizes the results of the firm’s operations over a period time monthly, quarterly, or annually. Show total revenues and expenses for the time period. Show different measures of profit. Consolidated Statement of Comprehensive Income of MTR: Half year ended 30 June 2018, Profit for the period 7,533 HK$ million.\",\"pages\":[19],\"start_pos\":4661,\"end_pos\":5048,\"summary\":\"Definition and real-world example of income statement.\",\"chunk_type\":\"definition_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_016\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_014\"]},{\"id\":\"CHUNK_019\",\"text\":\"All activities that occur between the growing or mining of raw materials and the appearance of finished products on the store shelf. Supply Chain Management (SCM) from raw materials to consumer: Supplier → Manufacturer → Wholesaler → Retailer → Customer.\",\"pages\":[21],\"start_pos\":5049,\"end_pos\":5368,\"summary\":\"Definition of supply chain and its stages.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_017\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_020\",\"text\":\"Materials management: To ensure materials are available for production, and products are available for delivery to customers. To maintain the lowest possible material and product levels in store. To plan manufacturing activities, delivery schedules, and purchasing activities. Logistics: To analyze and manage the status and make forecasts about the supply chain.\",\"pages\":[22],\"start_pos\":5369,\"end_pos\":5770,\"summary\":\"Definitions of materials management and logistics.\",\"chunk_type\":\"dual_definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_018\",\"CONC_019\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_017\"]},{\"id\":\"CHUNK_021\",\"text\":\"To manage all data relating to a customer to improve the quality of the interaction. Example of CRM – Odoo CRM.\",\"pages\":[24],\"start_pos\":5771,\"end_pos\":5930,\"summary\":\"Definition and example of CRM.\",\"chunk_type\":\"definition_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_020\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_022\",\"text\":\"One-to-One Marketing: It emphasizes personalized interactions with customers that build greater customer loyalty. Sales Force Automation: It automates business tasks such as tracking of customer interactions / history and analyzing sales forecasts and performance. Call Center Automation: It improves efficiency that screening qualified target customers from a large volume of customers (cold calling).\",\"pages\":[25],\"start_pos\":5931,\"end_pos\":6358,\"summary\":\"Set of CRM-related automation and marketing techniques.\",\"chunk_type\":\"definition_set\",\"has_examples\":false,\"main_concepts\":[\"CONC_021\",\"CONC_022\",\"CONC_023\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_020\"]},{\"id\":\"CHUNK_023\",\"text\":\"Examples of tools that provide CRM functionality within the SAP ERP system: Contact management tool – To make sure that information about sales contacts is available throughout the organization. Sales activity manager – Supports a strategic and organized approach to sales activity planning and can help make sure that follow-up activities are accomplished. Employing a separate CRM system that communicates with the ERP system.\",\"pages\":[26],\"start_pos\":6359,\"end_pos\":6802,\"summary\":\"CRM tools within SAP ERP environment.\",\"chunk_type\":\"example_list\",\"has_examples\":true,\"main_concepts\":[\"CONC_020\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_022\"]},{\"id\":\"CHUNK_024\",\"text\":\"A software delivery model: A software product is hosted by a company—such as SAP—on its servers and is accessed by customers via a Web browser. Sometimes described as a utility. A subset of cloud computing.\",\"pages\":[27],\"start_pos\":6803,\"end_pos\":7110,\"summary\":\"Definition of Software as a Service (SaaS).\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_024\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_025\",\"text\":\"Initial affordability: Lower cost to implement software provided through SaaS. Shorter implementation time: Implementation time usually shorter as the user does not have to worry about technical issues. Lower support costs and complexity: Do not need to hire additional IT personnel to implement new systems and applications.\",\"pages\":[28],\"start_pos\":7111,\"end_pos\":7534,\"summary\":\"Advantages of SaaS adoption.\",\"chunk_type\":\"benefits_list\",\"has_examples\":false,\"main_concepts\":[\"CONC_025\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_024\"]},{\"id\":\"CHUNK_026\",\"text\":\"Security, Bandwidth/response time, Flexibility, No frills, Technical, not business focus.\",\"pages\":[29],\"start_pos\":7535,\"end_pos\":7652,\"summary\":\"List of SaaS limitations and concerns.\",\"chunk_type\":\"challenge_list\",\"has_examples\":false,\"main_concepts\":[\"CONC_026\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_024\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Business\",\"aliases\":[\"enterprise\",\"company\"],\"keywords\":[\"profit\",\"goods\",\"services\",\"non-profit\"],\"confidence\":1,\"difficulty\":2,\"description\":\"An organization or entity engaged in commercial, industrial, or professional activities aimed at generating profit by providing goods and services. The primary purpose is to earn money for owners, achieved through efficient and economical delivery of desired products or services. Non-profit organizations reinvest surplus revenue into organizational improvement rather than distributing profits to owners.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\"]},{\"id\":\"CONC_002\",\"title\":\"Profit\",\"aliases\":[\"net income\"],\"keywords\":[\"revenue\",\"costs\",\"earnings\",\"taxes\"],\"confidence\":1,\"difficulty\":2,\"description\":\"The financial gain realized when revenue exceeds the costs of operations and taxes. Calculated as Profits = Revenues - Costs. It serves as a key performance indicator for businesses and acts as a reward for delivering value to consumers efficiently.\",\"concept_type\":\"formula\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_018\"]},{\"id\":\"CONC_003\",\"title\":\"Business Purpose\",\"aliases\":[\"organizational purpose\"],\"keywords\":[\"mission\",\"profit motive\",\"value creation\"],\"confidence\":1,\"difficulty\":2,\"description\":\"The fundamental reason an organization exists, which is typically to generate profit for its owners by meeting customer needs effectively. For non-profits, the purpose shifts toward societal benefit, with any surplus used to enhance the organization’s mission, such as in the case of the Red Cross.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_012\"]},{\"id\":\"CONC_004\",\"title\":\"Business Management\",\"aliases\":[\"management process\"],\"keywords\":[\"planning\",\"organizing\",\"directing\",\"controlling\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The process of planning, organizing, directing, and controlling employee activities and resource combinations to achieve organizational goals efficiently and effectively. Managers are accountable for performance and must balance stakeholder expectations while ensuring operational success.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_005\",\"CONC_006\"]},{\"id\":\"CONC_005\",\"title\":\"Effective Manager\",\"aliases\":[\"manager\"],\"keywords\":[\"accountability\",\"performance\",\"leadership\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A manager who ensures business performance and effectiveness by aligning team efforts with organizational objectives. They are accountable to stakeholders and responsible for guiding resources toward goal achievement through leadership and oversight.\",\"concept_type\":\"person\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_004\",\"CONC_006\"]},{\"id\":\"CONC_006\",\"title\":\"Management Functions\",\"aliases\":[\"five functions of management\"],\"keywords\":[\"planning\",\"organizing\",\"directing\",\"controlling\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Core responsibilities of managers including planning (setting goals), organizing (allocating resources), directing (leading teams), and controlling (monitoring performance). These functions ensure that organizational objectives are met efficiently and adaptively in dynamic environments.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_008\"],\"related_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_007\",\"title\":\"Mission Statement\",\"aliases\":[\"business mission\"],\"keywords\":[\"organizational goals\",\"purpose\",\"identity\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A formal summary defining an organization''s core purpose and focus, answering what it does for customers, employees, and owners. It guides strategic decisions and reflects identity, as exemplified by Apple’s 2017 statement emphasizing innovation in personal computing and digital media.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_009\"],\"related_concepts\":[\"CONC_003\",\"CONC_008\"]},{\"id\":\"CONC_008\",\"title\":\"Business Strategy\",\"aliases\":[\"strategic management\"],\"keywords\":[\"strategic planning\",\"goal alignment\",\"market adaptation\"],\"confidence\":1,\"difficulty\":4,\"description\":\"The creation of long-term plans to meet organizational goals in response to market challenges and evolving needs. Involves analyzing internal and external environments, setting objectives, matching capabilities, and formulating actionable strategies, such as Apple’s approach to product differentiation and ecosystem integration.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_010\"],\"related_concepts\":[\"CONC_007\",\"CONC_006\"]},{\"id\":\"CONC_009\",\"title\":\"Marketing\",\"aliases\":[\"marketing function\"],\"keywords\":[\"promotion\",\"pricing\",\"distribution\",\"exchange\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The process of planning and executing the conception, pricing, promotion, and distribution of ideas, goods, and services to create exchanges that satisfy individual and organizational objectives. An exchange occurs when both parties provide value, driven by understanding consumer needs through research and segmentation.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_011\"],\"related_concepts\":[\"CONC_010\",\"CONC_011\"]},{\"id\":\"CONC_010\",\"title\":\"Marketing Strategy\",\"aliases\":[\"strategic marketing\"],\"keywords\":[\"market segmentation\",\"marketing mix\",\"consumer needs\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A plan developed to reach target markets by identifying consumer segments through market segmentation, analyzing their needs via marketing research, and creating a tailored marketing mix (product, price, place, promotion) to fulfill those needs and drive satisfaction and loyalty.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_011\"],\"related_concepts\":[\"CONC_009\",\"CONC_011\"]},{\"id\":\"CONC_011\",\"title\":\"Marketing Mix\",\"aliases\":[\"4Ps of marketing\"],\"keywords\":[\"4Ps\",\"product\",\"price\",\"place\",\"promotion\"],\"confidence\":0.95,\"difficulty\":3,\"description\":\"A set of controllable tactical tools—product, price, place, and promotion—used to produce the desired response in the target market. It is central to marketing strategy and enables businesses to deliver value propositions aligned with customer expectations and competitive positioning.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_011\"],\"related_concepts\":[\"CONC_010\",\"CONC_009\"]},{\"id\":\"CONC_012\",\"title\":\"Accounting\",\"aliases\":[\"financial accounting\"],\"keywords\":[\"financial information\",\"decision aid\",\"control\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The discipline concerned with measuring and communicating financial information to support decision-making and control within organizations. It involves recording transactions, classifying data, summarizing results, and producing reports like trial balances and financial statements to reflect performance and condition.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_014\"],\"related_concepts\":[\"CONC_013\",\"CONC_014\"]},{\"id\":\"CONC_013\",\"title\":\"Trial Balance\",\"aliases\":[\"trial balance report\"],\"keywords\":[\"ledger\",\"balance verification\",\"error detection\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An internal accounting report listing the balances of all ledger accounts related to assets, liabilities, revenues, expenses, gains, and losses. Used to verify arithmetic accuracy before preparing formal financial statements and detect potential errors in bookkeeping.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_014\"],\"related_concepts\":[\"CONC_012\",\"CONC_015\"]},{\"id\":\"CONC_014\",\"title\":\"Financial Reporting\",\"aliases\":[\"financial reports\"],\"keywords\":[\"financial statements\",\"disclosure\",\"transparency\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The formal communication of a business’s financial activities and condition through standardized reports such as income statements, balance sheets, and cash flow statements. These reports help stakeholders assess performance, solvency, and investment potential, as seen in MTR Corporation’s disclosures.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_016\"],\"related_concepts\":[\"CONC_015\",\"CONC_016\"]},{\"id\":\"CONC_015\",\"title\":\"Balance Sheet\",\"aliases\":[\"statement of financial position\"],\"keywords\":[\"assets\",\"liabilities\",\"equity\",\"financial position\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A fundamental financial statement presenting a company''s financial position on a specific date. It reflects the accounting equation: Assets = Liabilities + Owners’ Equity. Assets represent owned resources, liabilities are debts, and equity is the residual interest after deducting liabilities from assets.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_018\"],\"related_concepts\":[\"CONC_013\",\"CONC_012\"]},{\"id\":\"CONC_016\",\"title\":\"Income Statement\",\"aliases\":[\"profit and loss account\",\"statement of comprehensive income\"],\"keywords\":[\"revenue\",\"expenses\",\"profit\",\"comprehensive income\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A basic financial statement summarizing a firm’s operating results over a period (monthly, quarterly, annually). It shows total revenues, expenses, and various profit measures such as net income and comprehensive income, enabling evaluation of profitability and operational efficiency.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_019\"],\"related_concepts\":[\"CONC_014\",\"CONC_015\"]},{\"id\":\"CONC_017\",\"title\":\"Supply Chain\",\"aliases\":[\"value chain\"],\"keywords\":[\"raw materials\",\"manufacturing\",\"distribution\"],\"confidence\":1,\"difficulty\":3,\"description\":\"All activities from raw material sourcing to finished product delivery to consumers. Includes stages such as supplier, manufacturer, wholesaler, and retailer. Supply Chain Management (SCM) coordinates this flow to optimize availability, cost, and logistics forecasting.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_021\"],\"related_concepts\":[\"CONC_018\",\"CONC_019\"]},{\"id\":\"CONC_018\",\"title\":\"Materials Management\",\"aliases\":[\"inventory management\"],\"keywords\":[\"inventory\",\"production planning\",\"purchasing\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Ensures materials are available for production and products for customer delivery while minimizing inventory levels. Involves planning manufacturing schedules, deliveries, and purchasing to maintain efficiency and reduce holding costs across the supply chain.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_022\"],\"related_concepts\":[\"CONC_017\",\"CONC_019\"]},{\"id\":\"CONC_019\",\"title\":\"Logistics\",\"aliases\":[\"supply chain logistics\"],\"keywords\":[\"forecasting\",\"distribution\",\"supply chain monitoring\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The analysis and management of supply chain status, including forecasting demand, tracking shipments, and optimizing distribution networks. It supports materials management by ensuring timely movement of goods and responsiveness to disruptions.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_022\"],\"related_concepts\":[\"CONC_017\",\"CONC_018\"]},{\"id\":\"CONC_020\",\"title\":\"Customer Relationship Management (CRM)\",\"aliases\":[\"CRM\"],\"keywords\":[\"customer data\",\"interaction\",\"loyalty\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A system for managing all data relating to customers to improve interaction quality and build loyalty. Examples include Odoo CRM and SAP-based tools like contact managers and sales activity trackers, which automate tasks and centralize customer information across the organization.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_024\"],\"related_concepts\":[\"CONC_021\",\"CONC_022\"]},{\"id\":\"CONC_021\",\"title\":\"One-to-One Marketing\",\"aliases\":[\"personalized marketing\"],\"keywords\":[\"personalization\",\"customer loyalty\",\"individual targeting\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A personalized marketing approach focusing on individual customer interactions to increase loyalty and satisfaction. It leverages CRM data to tailor communications and offers, enhancing perceived value and long-term engagement.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_025\"],\"related_concepts\":[\"CONC_020\",\"CONC_022\"]},{\"id\":\"CONC_022\",\"title\":\"Sales Force Automation\",\"aliases\":[\"SFA\"],\"keywords\":[\"sales tracking\",\"automation\",\"performance analysis\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Technology that automates sales-related tasks such as tracking customer interactions, managing follow-ups, and analyzing forecasts. Integrated within CRM systems, it improves sales efficiency and accuracy in performance measurement.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_025\"],\"related_concepts\":[\"CONC_020\",\"CONC_021\"]},{\"id\":\"CONC_023\",\"title\":\"Call Center Automation\",\"aliases\":[\"automated call centers\"],\"keywords\":[\"lead qualification\",\"cold calling\",\"efficiency\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Use of technology to improve call center efficiency by screening qualified leads from large volumes of cold calls. Automates workflows and prioritizes high-potential customers, increasing conversion rates and reducing manual effort.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_025\"],\"related_concepts\":[\"CONC_020\",\"CONC_022\"]},{\"id\":\"CONC_024\",\"title\":\"Software as a Service (SaaS)\",\"aliases\":[\"SaaS\"],\"keywords\":[\"cloud computing\",\"web-based access\",\"hosted software\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A software delivery model where applications are hosted by a provider (e.g., SAP) and accessed by users via web browsers. Part of cloud computing, it offers lower implementation costs, faster deployment, reduced IT overhead, but raises concerns about security and customization.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_027\"],\"related_concepts\":[\"CONC_025\",\"CONC_026\"]},{\"id\":\"CONC_025\",\"title\":\"Initial Affordability of SaaS\",\"aliases\":[\"SaaS affordability\"],\"keywords\":[\"low cost\",\"implementation\",\"SME adoption\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Refers to the lower upfront cost of implementing SaaS solutions compared to traditional on-premise software. This makes it particularly attractive for SMEs seeking scalable IT infrastructure without significant capital investment.\",\"concept_type\":\"phenomenon\",\"extracted_from\":[\"CHUNK_028\"],\"related_concepts\":[\"CONC_024\",\"CONC_026\"]},{\"id\":\"CONC_026\",\"title\":\"SaaS Limitations\",\"aliases\":[\"SaaS challenges\"],\"keywords\":[\"security\",\"bandwidth\",\"flexibility\",\"customization\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Key drawbacks of Software as a Service include security vulnerabilities, bandwidth dependency, limited flexibility in customization, generic features (''no frills''), and a technical rather than business-focused design orientation, potentially misaligned with strategic objectives.\",\"concept_type\":\"phenomenon\",\"extracted_from\":[\"CHUNK_029\"],\"related_concepts\":[\"CONC_024\",\"CONC_025\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"produces\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"Business seeks profits as defined by revenue minus costs.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"has\",\"source\":\"CONC_001\",\"target\":\"CONC_003\",\"evidence\":\"Every business has a purpose, primarily to earn profit.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"implements\",\"source\":\"CONC_004\",\"target\":\"CONC_006\",\"evidence\":\"Business management executes the five management functions.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"performs\",\"source\":\"CONC_005\",\"target\":\"CONC_004\",\"evidence\":\"Managers carry out business management processes.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"defines\",\"source\":\"CONC_007\",\"target\":\"CONC_003\",\"evidence\":\"Mission statement articulates the business purpose.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"guided_by\",\"source\":\"CONC_008\",\"target\":\"CONC_007\",\"evidence\":\"Strategy is created based on mission and goals.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"requires\",\"source\":\"CONC_009\",\"target\":\"CONC_010\",\"evidence\":\"Marketing relies on a well-defined strategy.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"creates\",\"source\":\"CONC_010\",\"target\":\"CONC_011\",\"evidence\":\"Marketing strategy produces a marketing mix.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"uses\",\"source\":\"CONC_012\",\"target\":\"CONC_013\",\"evidence\":\"Accounting uses trial balance for reporting.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"includes\",\"source\":\"CONC_014\",\"target\":\"CONC_015\",\"evidence\":\"Financial reports contain balance sheets.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"includes\",\"source\":\"CONC_014\",\"target\":\"CONC_016\",\"evidence\":\"Financial reports include income statements.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"measures\",\"source\":\"CONC_015\",\"target\":\"CONC_002\",\"evidence\":\"Balance sheet reflects profitability context.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"managed_by\",\"source\":\"CONC_017\",\"target\":\"CONC_018\",\"evidence\":\"Materials management is part of SCM.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_014\",\"type\":\"managed_by\",\"source\":\"CONC_017\",\"target\":\"CONC_019\",\"evidence\":\"Logistics manages supply chain flow.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_015\",\"type\":\"enables\",\"source\":\"CONC_020\",\"target\":\"CONC_021\",\"evidence\":\"CRM supports one-to-one marketing.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_016\",\"type\":\"implements\",\"source\":\"CONC_020\",\"target\":\"CONC_022\",\"evidence\":\"CRM systems automate sales force tasks.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_017\",\"type\":\"implements\",\"source\":\"CONC_020\",\"target\":\"CONC_023\",\"evidence\":\"CRM includes call center automation features.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_018\",\"type\":\"has\",\"source\":\"CONC_024\",\"target\":\"CONC_025\",\"evidence\":\"SaaS offers initial affordability as a benefit.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_019\",\"type\":\"has\",\"source\":\"CONC_024\",\"target\":\"CONC_026\",\"evidence\":\"SaaS comes with inherent limitations.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_020\",\"type\":\"involves\",\"source\":\"CONC_008\",\"target\":\"CONC_006\",\"evidence\":\"Strategy-making is a role of managers using management functions.\",\"strength\":1,\"bidirectional\":false}]"', '2026-03-26 05:57:43.960047', '2026-03-26 05:57:43.960047', NULL, '[{"id": "module_1", "name": "Business Fundamentals and Purpose", "topic_count": 7}, {"id": "module_2", "name": "Management Functions and Strategy", "topic_count": 8}, {"id": "module_3", "name": "Marketing Function and Strategy", "topic_count": 6}, {"id": "module_4", "name": "Accounting Principles and Financial Statements", "topic_count": 12}, {"id": "module_5", "name": "Supply Chain and Customer Relationship Management", "topic_count": 9}, {"id": "module_6", "name": "Software as a Service (SaaS) for Business", "topic_count": 6}]', NULL, 'IT114105 Higher Diploma in Software Engineering

