INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'Lecture 11 Decision Making.pptx', 'ed05817ba2df6844649bf42f5396880d1a4b172562c18462ad242585e5eb0d34', '{"chunks": [{"id": "CHUNK_001", "text": "At the end of this topic, you will be able to: identify source of information in business and explain business values in providing appropriate information to different management levels in business operations and decision making.", "pages": [1, 2], "end_pos": 156, "summary": "Learning objectives focusing on information sources and their value across management levels.", "start_pos": 0, "chunk_type": "learning_objective", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "When decisions must be made, the time taken to make a decision depends very much on the level at which it is made. Information needs are different at different organizational levels.", "pages": [4], "end_pos": 302, "summary": "Decision timing and information needs vary by organizational level.", "start_pos": 157, "chunk_type": "principle", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Strategic decisions are made by senior managers, possibly at board level. They require external, qualitative, highly summarized information and set the main aims and objectives of an organization.", "pages": [5], "end_pos": 448, "summary": "Characteristics of strategic-level decisions and information needs.", "start_pos": 303, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_004"]}, {"id": "CHUNK_004", "text": "Tactical decisions are made by middle managers and require information that is both external and internal, quantitative and qualitative, and summarized. They assist in achieving strategic objectives.", "pages": [5], "end_pos": 592, "summary": "Description of tactical decisions and associated information requirements.", "start_pos": 449, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_005", "text": "Operational decisions are made by the lowest level of management and relate to day-to-day operations. They require internal, quantitative, and detailed information. Examples include ordering new stock.", "pages": [5], "end_pos": 738, "summary": "Overview of operational decisions and their data characteristics.", "start_pos": 593, "chunk_type": "explanation", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_006", "text": "A system is a group of related procedures for a specific business function. It processes and transforms input into accurate, meaningful business information. Procedures govern the operation of a computer system. Data is the raw material, and information is derived from data.", "pages": [6], "end_pos": 918, "summary": "Fundamental definitions of system, data, and information.", "start_pos": 739, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "Transaction Processing Systems (TPS) collect and store data about transactions. A transaction is an event of interest to the organization. TPS serve elementary day-to-day activities, handle structured tasks, have high I/O volume, and supply data for higher-level decisions. Examples: payroll, order processing, shipments.", "pages": [8], "end_pos": 1148, "summary": "Core features and examples of TPS.", "start_pos": 919, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_001", "CONC_011"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_008", "text": "Management Information Systems (MIS) condense and convert TPS data into information for monitoring performance. They analyze large data volumes and produce summary reports. MIS supports middle managers in structured decision-making. Examples: sales management, budgeting, HR systems.", "pages": [9], "end_pos": 1378, "summary": "Purpose and functionality of MIS with practical examples.", "start_pos": 1149, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_009", "text": "Drill-down allows managers to navigate from summary information to detailed data views. It provides friendly functions for exploring underlying details, such as breaking down regional sales to office and product levels to identify problems.", "pages": [10, 11], "end_pos": 1562, "summary": "Explanation of drill-down functionality and its managerial application.", "start_pos": 1379, "chunk_type": "process", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_010", "text": "Decision Support Systems (DSS) support middle and top managers in making unstructured decisions by analyzing and modeling data. They provide possible solutions for comparison. Examples: financial planning systems, bank loan management systems.", "pages": [12], "end_pos": 1762, "summary": "Role and examples of DSS in supporting complex decisions.", "start_pos": 1563, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_011", "text": "Executive Information Systems (EIS) serve the strategic level and are used by senior executives. They provide summarized, user-friendly information tailored to individual needs. EIS allows CEOs to access all organizational levels and optionally drill down into details.", "pages": [13], "end_pos": 1976, "summary": "Features and purpose of EIS for executive decision-making.", "start_pos": 1763, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_012", "text": "Group DSS emphasize communications and decision models. Interactive computer-based systems help groups solve problems collaboratively. Groupware supports electronic communication, scheduling, document sharing, and other group productivity activities.", "pages": [14], "end_pos": 2180, "summary": "Collaborative extensions of DSS using groupware technologies.", "start_pos": 1977, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_010", "CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_003"]}], "concepts": [{"id": "CONC_001", "title": "Transaction Processing System (TPS)", "aliases": ["TPS"], "keywords": ["transaction", "processing", "structured tasks", "data capture", "operational level"], "confidence": 1.0, "difficulty": 3, "description": "A Transaction Processing System (TPS) is an information system that captures and processes data from business transactions. It supports the most basic operational activities of an organization by recording, storing, and managing transactional data such as order processing, payroll, shipments, and receipts. TPS handles high volumes of structured, predefined tasks and provides accurate, detailed internal data primarily used by lower-level management for day-to-day operations. The system often integrates with other systems like inventory management to trigger actions automatically, such as reordering low stock.", "concept_type": "system", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_002", "CONC_006", "CONC_009"]}, {"id": "CONC_002", "title": "Management Information System (MIS)", "aliases": ["MIS"], "keywords": ["summary reports", "middle management", "structured decisions", "performance monitoring", "TPS integration"], "confidence": 1.0, "difficulty": 3, "description": "A Management Information System (MIS) transforms raw data from Transaction Processing Systems into summarized reports for monitoring performance and supporting middle management in structured decision-making. It analyzes large volumes of input data and produces periodic output such as sales summaries or budget reports. MIS enhances organizational efficiency and effectiveness by providing timely, relevant information. Examples include sales management, budgeting, and human resource systems. It serves tactical-level decisions and relies heavily on TPS outputs.", "concept_type": "system", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_001", "CONC_003", "CONC_004"]}, {"id": "CONC_003", "title": "Decision Support System (DSS)", "aliases": ["DSS"], "keywords": ["unstructured decisions", "modeling", "scenario analysis", "interactive system", "managerial support"], "confidence": 1.0, "difficulty": 4, "description": "A Decision Support System (DSS) assists middle and top-level managers in making semi-structured or unstructured decisions by analyzing and modeling complex data sets. Unlike MIS, which focuses on routine reporting, DSS provides interactive tools for scenario analysis, forecasting, and comparison of alternative solutions. It supports strategic planning and problem-solving in areas such as financial planning and loan management. DSS can integrate both internal and external data sources to support dynamic decision environments.", "concept_type": "system", "extracted_from": ["CHUNK_010"], "related_concepts": ["CONC_002", "CONC_005", "CONC_012"]}, {"id": "CONC_004", "title": "Executive Information System (EIS)", "aliases": ["EIS"], "keywords": ["executive level", "strategic decisions", "summarized information", "user-friendly interface", "drill-down capability"], "confidence": 1.0, "difficulty": 4, "description": "An Executive Information System (EIS) is designed for senior executives at the strategic level of an organization. It delivers highly summarized, external and internal information tailored to individual executive needs. EIS emphasizes user-friendliness and enables CEOs to access data across all organizational levels. While typically focused on high-level overviews, it also allows drilling down into details when necessary. It supports long-term planning and goal setting by presenting key performance indicators and trends.", "concept_type": "system", "extracted_from": ["CHUNK_011"], "related_concepts": ["CONC_003", "CONC_005", "CONC_006"]}, {"id": "CONC_005", "title": "Drill-down Capability", "aliases": ["drilling down"], "keywords": ["data navigation", "detailed view", "hierarchical exploration", "performance analysis", "interactive reporting"], "confidence": 1.0, "difficulty": 3, "description": "Drill-down capability refers to the functionality in information systems that allows users to navigate from summary-level data to increasingly detailed views. This process helps managers investigate underlying causes of performance issues by exploring data hierarchically—such as moving from regional sales totals to office-level results, then to product-line specifics. It is commonly supported in MIS and EIS to enable deeper analysis while maintaining a high-level overview, enhancing decision accuracy and problem identification.", "concept_type": "process", "extracted_from": ["CHUNK_009", "CHUNK_011"], "related_concepts": ["CONC_002", "CONC_004"]}, {"id": "CONC_006", "title": "Organizational Decision Levels", "aliases": ["decision levels", "management levels"], "keywords": ["strategic decisions", "tactical decisions", "operational decisions", "management hierarchy", "information needs"], "confidence": 1.0, "difficulty": 3, "description": "Organizational decision levels refer to the hierarchical structure of decision-making within a company: strategic (senior management), tactical (middle management), and operational (lower-level management). Each level has distinct information requirements: strategic decisions require external, qualitative, and summarized data; tactical decisions use both internal and external data in summarized form; operational decisions rely on internal, quantitative, and detailed data. The time frame and scope of decisions vary accordingly, influencing the design and function of information systems.", "concept_type": "theory", "extracted_from": ["CHUNK_004", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_007", "title": "Data vs Information", "aliases": ["data-information hierarchy"], "keywords": ["raw material", "meaningful output", "processing", "interpretation", "business value"], "confidence": 1.0, "difficulty": 2, "description": "Data refers to raw, unprocessed facts and figures collected during business operations, serving as the foundational input for information systems. Information is derived from processed, organized, and interpreted data, making it meaningful and useful for decision-making. The transformation from data to information occurs through systems like TPS and MIS, where context and structure are added. Accurate and timely information increases business value by supporting effective managerial decisions across organizational levels.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_002"]}, {"id": "CONC_008", "title": "Business Function System", "aliases": ["functional system"], "keywords": ["procedures", "business operation", "workflow", "policy governance", "function-specific"], "confidence": 1.0, "difficulty": 3, "description": "A business function system is a group of related procedures designed to support a specific business operation, such as payroll or inventory management. These systems follow defined policies and workflows to transform inputs into meaningful outputs. They involve coordination among users, managers, and IS staff, governed by procedural rules. Such systems are integral to organizational efficiency and serve as building blocks for larger information architectures like TPS and MIS.", "concept_type": "architecture", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_006"]}, {"id": "CONC_009", "title": "Structured vs Unstructured Decisions", "aliases": ["decision types"], "keywords": ["routine decisions", "non-routine decisions", "predictability", "judgment-based", "decision complexity"], "confidence": 1.0, "difficulty": 4, "description": "Structured decisions are routine, well-defined, and based on predictable processes, typically made at the operational level using internal, quantitative data. Unstructured decisions are complex, non-routine, and require judgment, intuition, and external data, usually occurring at strategic levels. Semi-structured decisions fall between these extremes. Information systems are tailored accordingly: TPS supports structured decisions, while DSS aids in semi-structured or unstructured ones, reflecting differing data needs and analytical requirements.", "concept_type": "theory", "extracted_from": ["CHUNK_004", "CHUNK_010"], "related_concepts": ["CONC_001", "CONC_003", "CONC_006"]}, {"id": "CONC_010", "title": "Group Decision Support System (GDSS)", "aliases": ["Group DSS"], "keywords": ["collaborative decision", "groupware", "electronic communication", "consensus building", "interactive modeling"], "confidence": 1.0, "difficulty": 4, "description": "A Group Decision Support System (GDSS) enhances collaborative decision-making by integrating communication tools and analytical models. It enables multiple decision-makers to work together interactively using computer-based platforms. GDSS supports group productivity through features like electronic brainstorming, document sharing, scheduling, and real-time modeling. It is particularly useful for solving complex problems requiring consensus and diverse perspectives, extending traditional DSS capabilities to team environments.", "concept_type": "system", "extracted_from": ["CHUNK_012"], "related_concepts": ["CONC_003", "CONC_012"]}, {"id": "CONC_011", "title": "Transaction", "aliases": ["business transaction"], "keywords": ["event of interest", "data recording", "state change", "business activity", "atomic operation"], "confidence": 1.0, "difficulty": 2, "description": "In the context of information systems, a transaction is any event of interest to the organization that triggers data recording and processing. Examples include customer orders, payments, shipments, and employee time entries. Transactions are discrete, measurable, and typically involve a change in state, such as inventory levels or account balances. TPS is specifically designed to handle high volumes of such transactions reliably and accurately, forming the foundation for higher-level information systems.", "concept_type": "object", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_012", "title": "Groupware", "aliases": ["collaborative software"], "keywords": ["collaboration tools", "shared workspace", "electronic communication", "team coordination", "distributed teams"], "confidence": 1.0, "difficulty": 3, "description": "Groupware refers to software applications that facilitate electronic collaboration among groups, including communication, scheduling, document sharing, and task management. It supports Group DSS by enabling seamless interaction between geographically dispersed team members. Features like shared calendars, real-time editing, and discussion forums enhance group productivity and decision quality. Groupware plays a critical role in modern distributed organizations by reducing coordination overhead and improving information flow.", "concept_type": "component", "extracted_from": ["CHUNK_012"], "related_concepts": ["CONC_010"]}], "relationships": [{"id": "REL_001", "type": "supports", "source": "CONC_001", "target": "CONC_006", "evidence": "TPS serves elementary day-to-day activities at the operational level.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "supports", "source": "CONC_002", "target": "CONC_006", "evidence": "MIS supports middle managers in structured decision making.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "supports", "source": "CONC_003", "target": "CONC_006", "evidence": "DSS supports middle/top managers in unstructured decision making at strategic/tactical levels.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "supports", "source": "CONC_004", "target": "CONC_006", "evidence": "EIS serves the strategic level used by senior executives.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "transforms", "source": "CONC_001", "target": "CONC_007", "evidence": "TPS processes raw data into meaningful business information.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "produces", "source": "CONC_002", "target": "CONC_007", "evidence": "MIS converts TPS data into summarized information for monitoring.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "enhances", "source": "CONC_005", "target": "CONC_002", "evidence": "Drill-down allows managers to explore details behind MIS summary reports.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "enhances", "source": "CONC_005", "target": "CONC_004", "evidence": "EIS allows focusing on details of particular aspects despite being summary-oriented.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "feeds_into", "source": "CONC_001", "target": "CONC_002", "evidence": "TPS supplies data for higher-level management decisions via MIS.", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "is_a", "source": "CONC_008", "target": "CONC_001", "evidence": "TPS is a type of business function system for transaction handling.", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "part_of", "source": "CONC_011", "target": "CONC_001", "evidence": "A transaction is an event processed by TPS.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "classifies", "source": "CONC_009", "target": "CONC_006", "evidence": "Decision types (structured/unstructured) correspond to different management levels.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "specialization_of", "source": "CONC_010", "target": "CONC_003", "evidence": "Group DSS extends DSS functionality to group settings.", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "implements", "source": "CONC_012", "target": "CONC_010", "evidence": "Groupware supports Group DSS through communication and collaboration tools.", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "similar_to", "source": "CONC_004", "target": "CONC_003", "evidence": "Both EIS and DSS support higher-level decision-making but differ in structure and audience.", "strength": 0.8, "bidirectional": true}], "quality_metrics": {"total_chunks": 12, "missing_links": [], "coverage_score": 1.0, "total_concepts": 12, "consistency_score": 1.0, "total_relationships": 15}, "document_metadata": {"title": "Higher Diploma in Software Engineering - Information Systems and Business Decision Making", "language": "English", "main_topic": "Information Systems in Business Management and Decision Support", "difficulty_level": "Intermediate", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "Organizational Decision Levels", "context": "Learning objective mentions explaining business values across management levels.", "chunk_id": "CHUNK_001", "positions": [50], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Organizational Decision Levels", "context": "Directly states differences in decision timing and information needs by level.", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Organizational Decision Levels", "context": "Describes strategic decisions made by senior managers.", "chunk_id": "CHUNK_003", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Organizational Decision Levels", "context": "Explains tactical decisions by middle managers.", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Organizational Decision Levels", "context": "Details operational decisions at the lowest management level.", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Transaction Processing System (TPS)", "context": "Full definition and characteristics of TPS provided.", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Transaction", "context": "Defined as an event of interest to the organization.", "chunk_id": "CHUNK_007", "positions": [60], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "Management Information System (MIS)", "context": "Complete explanation of MIS functionality and examples.", "chunk_id": "CHUNK_008", "positions": [0], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Drill-down Capability", "context": "Defined and illustrated with a sales example.", "chunk_id": "CHUNK_009", "positions": [0], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Decision Support System (DSS)", "context": "Core definition and examples of DSS provided.", "chunk_id": "CHUNK_010", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Executive Information System (EIS)", "context": "Comprehensive description of EIS features and usage.", "chunk_id": "CHUNK_011", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Group Decision Support System (GDSS)", "context": "Introduction to Group DSS and its collaborative nature.", "chunk_id": "CHUNK_012", "positions": [0], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Groupware", "context": "Defined as supporting communication and group productivity.", "chunk_id": "CHUNK_012", "positions": [120], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Data vs Information", "context": "Explicit distinction between raw data and derived information.", "chunk_id": "CHUNK_006", "positions": [150], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Business Function System", "context": "System defined as group of procedures for a business function.", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Structured vs Unstructured Decisions", "context": "Operational decisions imply structured nature.", "chunk_id": "CHUNK_005", "positions": [100], "concept_id": "CONC_009", "importance": "secondary"}, {"concept": "Structured vs Unstructured Decisions", "context": "DSS supports unstructured decisions.", "chunk_id": "CHUNK_010", "positions": [20], "concept_id": "CONC_009", "importance": "secondary"}]}', '{"total_modules": 5, "total_concepts": 18, "difficulty_score": 5, "total_structures": 8, "total_applications": 5}', '"[{\"id\":\"CHUNK_001\",\"text\":\"At the end of this topic, you will be able to: identify source of information in business and explain business values in providing appropriate information to different management levels in business operations and decision making.\",\"pages\":[1,2],\"start_pos\":0,\"end_pos\":156,\"summary\":\"Learning objectives focusing on information sources and their value across management levels.\",\"chunk_type\":\"learning_objective\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"When decisions must be made, the time taken to make a decision depends very much on the level at which it is made. Information needs are different at different organizational levels.\",\"pages\":[4],\"start_pos\":157,\"end_pos\":302,\"summary\":\"Decision timing and information needs vary by organizational level.\",\"chunk_type\":\"principle\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"Strategic decisions are made by senior managers, possibly at board level. They require external, qualitative, highly summarized information and set the main aims and objectives of an organization.\",\"pages\":[5],\"start_pos\":303,\"end_pos\":448,\"summary\":\"Characteristics of strategic-level decisions and information needs.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\"]},{\"id\":\"CHUNK_004\",\"text\":\"Tactical decisions are made by middle managers and require information that is both external and internal, quantitative and qualitative, and summarized. They assist in achieving strategic objectives.\",\"pages\":[5],\"start_pos\":449,\"end_pos\":592,\"summary\":\"Description of tactical decisions and associated information requirements.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_005\",\"text\":\"Operational decisions are made by the lowest level of management and relate to day-to-day operations. They require internal, quantitative, and detailed information. Examples include ordering new stock.\",\"pages\":[5],\"start_pos\":593,\"end_pos\":738,\"summary\":\"Overview of operational decisions and their data characteristics.\",\"chunk_type\":\"explanation\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_006\",\"text\":\"A system is a group of related procedures for a specific business function. It processes and transforms input into accurate, meaningful business information. Procedures govern the operation of a computer system. Data is the raw material, and information is derived from data.\",\"pages\":[6],\"start_pos\":739,\"end_pos\":918,\"summary\":\"Fundamental definitions of system, data, and information.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_008\",\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_007\",\"text\":\"Transaction Processing Systems (TPS) collect and store data about transactions. A transaction is an event of interest to the organization. TPS serve elementary day-to-day activities, handle structured tasks, have high I/O volume, and supply data for higher-level decisions. Examples: payroll, order processing, shipments.\",\"pages\":[8],\"start_pos\":919,\"end_pos\":1148,\"summary\":\"Core features and examples of TPS.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\",\"CONC_011\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_007\"]},{\"id\":\"CHUNK_008\",\"text\":\"Management Information Systems (MIS) condense and convert TPS data into information for monitoring performance. They analyze large data volumes and produce summary reports. MIS supports middle managers in structured decision-making. Examples: sales management, budgeting, HR systems.\",\"pages\":[9],\"start_pos\":1149,\"end_pos\":1378,\"summary\":\"Purpose and functionality of MIS with practical examples.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_009\",\"text\":\"Drill-down allows managers to navigate from summary information to detailed data views. It provides friendly functions for exploring underlying details, such as breaking down regional sales to office and product levels to identify problems.\",\"pages\":[10,11],\"start_pos\":1379,\"end_pos\":1562,\"summary\":\"Explanation of drill-down functionality and its managerial application.\",\"chunk_type\":\"process\",\"has_examples\":true,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_010\",\"text\":\"Decision Support Systems (DSS) support middle and top managers in making unstructured decisions by analyzing and modeling data. They provide possible solutions for comparison. Examples: financial planning systems, bank loan management systems.\",\"pages\":[12],\"start_pos\":1563,\"end_pos\":1762,\"summary\":\"Role and examples of DSS in supporting complex decisions.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_011\",\"text\":\"Executive Information Systems (EIS) serve the strategic level and are used by senior executives. They provide summarized, user-friendly information tailored to individual needs. EIS allows CEOs to access all organizational levels and optionally drill down into details.\",\"pages\":[13],\"start_pos\":1763,\"end_pos\":1976,\"summary\":\"Features and purpose of EIS for executive decision-making.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_012\",\"text\":\"Group DSS emphasize communications and decision models. Interactive computer-based systems help groups solve problems collaboratively. Groupware supports electronic communication, scheduling, document sharing, and other group productivity activities.\",\"pages\":[14],\"start_pos\":1977,\"end_pos\":2180,\"summary\":\"Collaborative extensions of DSS using groupware technologies.\",\"chunk_type\":\"explanation\",\"has_examples\":false,\"main_concepts\":[\"CONC_010\",\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Transaction Processing System (TPS)\",\"aliases\":[\"TPS\"],\"keywords\":[\"transaction\",\"processing\",\"structured tasks\",\"data capture\",\"operational level\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A Transaction Processing System (TPS) is an information system that captures and processes data from business transactions. It supports the most basic operational activities of an organization by recording, storing, and managing transactional data such as order processing, payroll, shipments, and receipts. TPS handles high volumes of structured, predefined tasks and provides accurate, detailed internal data primarily used by lower-level management for day-to-day operations. The system often integrates with other systems like inventory management to trigger actions automatically, such as reordering low stock.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_002\",\"CONC_006\",\"CONC_009\"]},{\"id\":\"CONC_002\",\"title\":\"Management Information System (MIS)\",\"aliases\":[\"MIS\"],\"keywords\":[\"summary reports\",\"middle management\",\"structured decisions\",\"performance monitoring\",\"TPS integration\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A Management Information System (MIS) transforms raw data from Transaction Processing Systems into summarized reports for monitoring performance and supporting middle management in structured decision-making. It analyzes large volumes of input data and produces periodic output such as sales summaries or budget reports. MIS enhances organizational efficiency and effectiveness by providing timely, relevant information. Examples include sales management, budgeting, and human resource systems. It serves tactical-level decisions and relies heavily on TPS outputs.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_008\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_003\",\"title\":\"Decision Support System (DSS)\",\"aliases\":[\"DSS\"],\"keywords\":[\"unstructured decisions\",\"modeling\",\"scenario analysis\",\"interactive system\",\"managerial support\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A Decision Support System (DSS) assists middle and top-level managers in making semi-structured or unstructured decisions by analyzing and modeling complex data sets. Unlike MIS, which focuses on routine reporting, DSS provides interactive tools for scenario analysis, forecasting, and comparison of alternative solutions. It supports strategic planning and problem-solving in areas such as financial planning and loan management. DSS can integrate both internal and external data sources to support dynamic decision environments.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_010\"],\"related_concepts\":[\"CONC_002\",\"CONC_005\",\"CONC_012\"]},{\"id\":\"CONC_004\",\"title\":\"Executive Information System (EIS)\",\"aliases\":[\"EIS\"],\"keywords\":[\"executive level\",\"strategic decisions\",\"summarized information\",\"user-friendly interface\",\"drill-down capability\"],\"confidence\":1,\"difficulty\":4,\"description\":\"An Executive Information System (EIS) is designed for senior executives at the strategic level of an organization. It delivers highly summarized, external and internal information tailored to individual executive needs. EIS emphasizes user-friendliness and enables CEOs to access data across all organizational levels. While typically focused on high-level overviews, it also allows drilling down into details when necessary. It supports long-term planning and goal setting by presenting key performance indicators and trends.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_011\"],\"related_concepts\":[\"CONC_003\",\"CONC_005\",\"CONC_006\"]},{\"id\":\"CONC_005\",\"title\":\"Drill-down Capability\",\"aliases\":[\"drilling down\"],\"keywords\":[\"data navigation\",\"detailed view\",\"hierarchical exploration\",\"performance analysis\",\"interactive reporting\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Drill-down capability refers to the functionality in information systems that allows users to navigate from summary-level data to increasingly detailed views. This process helps managers investigate underlying causes of performance issues by exploring data hierarchically—such as moving from regional sales totals to office-level results, then to product-line specifics. It is commonly supported in MIS and EIS to enable deeper analysis while maintaining a high-level overview, enhancing decision accuracy and problem identification.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_009\",\"CHUNK_011\"],\"related_concepts\":[\"CONC_002\",\"CONC_004\"]},{\"id\":\"CONC_006\",\"title\":\"Organizational Decision Levels\",\"aliases\":[\"decision levels\",\"management levels\"],\"keywords\":[\"strategic decisions\",\"tactical decisions\",\"operational decisions\",\"management hierarchy\",\"information needs\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Organizational decision levels refer to the hierarchical structure of decision-making within a company: strategic (senior management), tactical (middle management), and operational (lower-level management). Each level has distinct information requirements: strategic decisions require external, qualitative, and summarized data; tactical decisions use both internal and external data in summarized form; operational decisions rely on internal, quantitative, and detailed data. The time frame and scope of decisions vary accordingly, influencing the design and function of information systems.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_005\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_007\",\"title\":\"Data vs Information\",\"aliases\":[\"data-information hierarchy\"],\"keywords\":[\"raw material\",\"meaningful output\",\"processing\",\"interpretation\",\"business value\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Data refers to raw, unprocessed facts and figures collected during business operations, serving as the foundational input for information systems. Information is derived from processed, organized, and interpreted data, making it meaningful and useful for decision-making. The transformation from data to information occurs through systems like TPS and MIS, where context and structure are added. Accurate and timely information increases business value by supporting effective managerial decisions across organizational levels.\",\"concept_type\":\"phenomenon\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\"]},{\"id\":\"CONC_008\",\"title\":\"Business Function System\",\"aliases\":[\"functional system\"],\"keywords\":[\"procedures\",\"business operation\",\"workflow\",\"policy governance\",\"function-specific\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A business function system is a group of related procedures designed to support a specific business operation, such as payroll or inventory management. These systems follow defined policies and workflows to transform inputs into meaningful outputs. They involve coordination among users, managers, and IS staff, governed by procedural rules. Such systems are integral to organizational efficiency and serve as building blocks for larger information architectures like TPS and MIS.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_001\",\"CONC_006\"]},{\"id\":\"CONC_009\",\"title\":\"Structured vs Unstructured Decisions\",\"aliases\":[\"decision types\"],\"keywords\":[\"routine decisions\",\"non-routine decisions\",\"predictability\",\"judgment-based\",\"decision complexity\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Structured decisions are routine, well-defined, and based on predictable processes, typically made at the operational level using internal, quantitative data. Unstructured decisions are complex, non-routine, and require judgment, intuition, and external data, usually occurring at strategic levels. Semi-structured decisions fall between these extremes. Information systems are tailored accordingly: TPS supports structured decisions, while DSS aids in semi-structured or unstructured ones, reflecting differing data needs and analytical requirements.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_010\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\",\"CONC_006\"]},{\"id\":\"CONC_010\",\"title\":\"Group Decision Support System (GDSS)\",\"aliases\":[\"Group DSS\"],\"keywords\":[\"collaborative decision\",\"groupware\",\"electronic communication\",\"consensus building\",\"interactive modeling\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A Group Decision Support System (GDSS) enhances collaborative decision-making by integrating communication tools and analytical models. It enables multiple decision-makers to work together interactively using computer-based platforms. GDSS supports group productivity through features like electronic brainstorming, document sharing, scheduling, and real-time modeling. It is particularly useful for solving complex problems requiring consensus and diverse perspectives, extending traditional DSS capabilities to team environments.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_012\"],\"related_concepts\":[\"CONC_003\",\"CONC_012\"]},{\"id\":\"CONC_011\",\"title\":\"Transaction\",\"aliases\":[\"business transaction\"],\"keywords\":[\"event of interest\",\"data recording\",\"state change\",\"business activity\",\"atomic operation\"],\"confidence\":1,\"difficulty\":2,\"description\":\"In the context of information systems, a transaction is any event of interest to the organization that triggers data recording and processing. Examples include customer orders, payments, shipments, and employee time entries. Transactions are discrete, measurable, and typically involve a change in state, such as inventory levels or account balances. TPS is specifically designed to handle high volumes of such transactions reliably and accurately, forming the foundation for higher-level information systems.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_001\",\"CONC_007\"]},{\"id\":\"CONC_012\",\"title\":\"Groupware\",\"aliases\":[\"collaborative software\"],\"keywords\":[\"collaboration tools\",\"shared workspace\",\"electronic communication\",\"team coordination\",\"distributed teams\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Groupware refers to software applications that facilitate electronic collaboration among groups, including communication, scheduling, document sharing, and task management. It supports Group DSS by enabling seamless interaction between geographically dispersed team members. Features like shared calendars, real-time editing, and discussion forums enhance group productivity and decision quality. Groupware plays a critical role in modern distributed organizations by reducing coordination overhead and improving information flow.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_012\"],\"related_concepts\":[\"CONC_010\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"supports\",\"source\":\"CONC_001\",\"target\":\"CONC_006\",\"evidence\":\"TPS serves elementary day-to-day activities at the operational level.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"supports\",\"source\":\"CONC_002\",\"target\":\"CONC_006\",\"evidence\":\"MIS supports middle managers in structured decision making.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"supports\",\"source\":\"CONC_003\",\"target\":\"CONC_006\",\"evidence\":\"DSS supports middle/top managers in unstructured decision making at strategic/tactical levels.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"supports\",\"source\":\"CONC_004\",\"target\":\"CONC_006\",\"evidence\":\"EIS serves the strategic level used by senior executives.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"transforms\",\"source\":\"CONC_001\",\"target\":\"CONC_007\",\"evidence\":\"TPS processes raw data into meaningful business information.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"produces\",\"source\":\"CONC_002\",\"target\":\"CONC_007\",\"evidence\":\"MIS converts TPS data into summarized information for monitoring.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"enhances\",\"source\":\"CONC_005\",\"target\":\"CONC_002\",\"evidence\":\"Drill-down allows managers to explore details behind MIS summary reports.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"enhances\",\"source\":\"CONC_005\",\"target\":\"CONC_004\",\"evidence\":\"EIS allows focusing on details of particular aspects despite being summary-oriented.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"feeds_into\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"TPS supplies data for higher-level management decisions via MIS.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"is_a\",\"source\":\"CONC_008\",\"target\":\"CONC_001\",\"evidence\":\"TPS is a type of business function system for transaction handling.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"part_of\",\"source\":\"CONC_011\",\"target\":\"CONC_001\",\"evidence\":\"A transaction is an event processed by TPS.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"classifies\",\"source\":\"CONC_009\",\"target\":\"CONC_006\",\"evidence\":\"Decision types (structured/unstructured) correspond to different management levels.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"specialization_of\",\"source\":\"CONC_010\",\"target\":\"CONC_003\",\"evidence\":\"Group DSS extends DSS functionality to group settings.\",\"strength\":1,