INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'Lecture 7 Function Module_2019.pptx', 'a5a2c0f89050a558d93008505e94baba9486d75472cabbc467e4e76e8378ccc1', '{"chunks": [{"id": "CHUNK_001", "text": "At the end of this lecture, you will be able to: Understand how to create and use function module.", "pages": [2], "end_pos": 98, "summary": "Learning objective for understanding function modules.", "start_pos": 0, "chunk_type": "learning objective", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "If there is a common activity (e.g., calculate interest) that may span multiple ABAP programs, we can code that logic in a function module. This function module can then be called by a wide variety of programs. This differs from a subroutine, which can only be called by the program it resides in.", "pages": [3], "end_pos": 376, "summary": "Introduction to function modules and contrast with subroutines.", "start_pos": 99, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_009"]}, {"id": "CHUNK_003", "text": "Function group is a container for function modules. When you create a function module, you must assign it to function group. The function group is the main program in which a function module is embedded. The function group is a program type F, and not executable.", "pages": [4], "end_pos": 675, "summary": "Definition and role of function groups in ABAP.", "start_pos": 377, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_004", "text": "The entire function group is loaded in a program the first time that you call a function module that belongs to it. Function group is used to define global data for function modules. A DATA statement in the global memory of a function group is shared by all the function modules that belong to that function group.", "pages": [5], "end_pos": 974, "summary": "Loading behavior and data sharing in function groups.", "start_pos": 676, "chunk_type": "explanation", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_005", "text": "Function module is a code that can be called from any ABAP program, therefore making it a globally accessible object. ABAP program pass data to function module from import parameters or internal tables. Function module receives data from a program, process the information in its own code, and then sends back information in the export parameters or internal tables.", "pages": [8], "end_pos": 1355, "summary": "Overview of function module functionality and data flow.", "start_pos": 975, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_003", "CONC_004"]}, {"id": "CHUNK_006", "text": "Function module contains the following interface elements: Export parameters - Passed from the calling program to the function module. Import parameters - Passed from the function module to the calling program. Changing parameters - Passed to the function module and can be modified by it. Exceptions - Information about any errors that may have occurred when executing the function module.", "pages": [10], "end_pos": 1745, "summary": "Breakdown of function module interface components.", "start_pos": 1356, "chunk_type": "list", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_003", "CONC_004", "CONC_005", "CONC_006"]}, {"id": "CHUNK_007", "text": "Function module documentation shows classification options including Normal function module, Remote-enabled module, and Update module. Example includes BC402_FMDD_GET_FREE_SEATS with parameters like IP_PLANETYPE and EP_SEATSFREE.", "pages": [11, 12], "end_pos": 2035, "summary": "Example of function module with interface details.", "start_pos": 1746, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_001", "CONC_010"], "has_definitions": false, "secondary_concepts": ["CONC_003", "CONC_004"]}, {"id": "CHUNK_008", "text": "Steps in implementing Function Module: Create an ABAP program. Use the PATTERN push button to find the function module. Remove the comments from the import, export, changing, and exception parameters which are not required.", "pages": [17], "end_pos": 2330, "summary": "Implementation steps for using a function module.", "start_pos": 2036, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": ["CONC_003", "CONC_004", "CONC_006"]}, {"id": "CHUNK_009", "text": "Example ABAP program calling function module Z_FMTEST with parameters number1, number2, and result. Uses EXCEPTIONS clause with invalid_number and OTHERS. Checks SY-SUBRC to determine if an exception occurred.", "pages": [23], "end_pos": 2620, "summary": "Code example demonstrating function module invocation and error handling.", "start_pos": 2331, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_001", "CONC_006", "CONC_007"], "has_definitions": false, "secondary_concepts": ["CONC_003", "CONC_004"]}, {"id": "CHUNK_010", "text": "IF sy-subrc <> 0. WRITE: / ''Invalid Number!''. ELSE. WRITE: / result. ENDIF.", "pages": [23], "end_pos": 2700, "summary": "Conditional check based on SY-SUBRC value.", "start_pos": 2621, "chunk_type": "code snippet", "has_examples": true, "main_concepts": ["CONC_007"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_011", "text": "FUNCTION z_fntest. IMPORTING REFERENCE(NUMBER1) TYPE I REFERENCE(NUMBER2) TYPE I. EXPORTING REFERENCE(RESULT) TYPE I. EXCEPTIONS INVALID_NUMBER. IF number2 LE 0 OR number2 GE 10. RAISE invalid_number. ELSE. result = number1 ** number2. ENDIF. ENDFUNCTION.", "pages": [21], "end_pos": 2950, "summary": "Implementation of a function module with exception raising.", "start_pos": 2701, "chunk_type": "code", "has_examples": true, "main_concepts": ["CONC_001", "CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_003", "CONC_004"]}, {"id": "CHUNK_012", "text": "Syntax: CATCH SYSTEM-EXCEPTIONS <error type> = <n>. <statements – generate runtime error>. ENDCATCH. IF SY-SUBRC = <n>. ..... ENDIF.", "pages": [30], "end_pos": 3150, "summary": "Syntax for trapping system exceptions in ABAP.", "start_pos": 2951, "chunk_type": "syntax", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_013", "text": "Example: DATA num TYPE i. CATCH SYSTEM-EXCEPTIONS conversion_errors = 2. MOVE ''ABC'' TO num. ENDCATCH. IF sy-subrc = 2. WRITE: / ''Assign wrong data type to variable num''.", "pages": [32], "end_pos": 3400, "summary": "Example usage of CATCH SYSTEM-EXCEPTIONS for type conversion errors.", "start_pos": 3151, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_008", "CONC_007"], "has_definitions": false, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Function Module", "aliases": ["FM"], "keywords": ["function module", "ABAP", "global access", "reusable code"], "confidence": 1.0, "difficulty": 3, "description": "A function module is a reusable piece of code in ABAP that can be called from any ABAP program, making it a globally accessible object. It encapsulates specific logic such as calculations or data retrieval and communicates with calling programs via import, export, changing parameters, and exceptions. Unlike subroutines, function modules are not limited to the program they reside in and are managed within function groups.", "concept_type": "component", "extracted_from": ["CHUNK_002", "CHUNK_003", "CHUNK_006"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_002", "title": "Function Group", "aliases": [], "keywords": ["function group", "container", "global data", "program type F"], "confidence": 1.0, "difficulty": 3, "description": "A function group is a container program (type F) in ABAP that serves as the main program for embedding one or more function modules. It defines global data shared across all its function modules through DATA statements in its global memory. The entire function group is loaded into memory when any of its function modules is first called by an external program.", "concept_type": "architecture", "extracted_from": ["CHUNK_003", "CHUNK_004"], "related_concepts": ["CONC_001", "CONC_005"]}, {"id": "CONC_003", "title": "Import Parameters", "aliases": [], "keywords": ["import parameters", "input", "interface"], "confidence": 1.0, "difficulty": 2, "description": "Import parameters are interface elements of a function module that receive input data from the calling ABAP program. These values are passed into the function module for processing and must be provided unless marked as optional. They form part of the contract between the caller and the function module.", "concept_type": "component", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_004"]}, {"id": "CONC_004", "title": "Export Parameters", "aliases": [], "keywords": ["export parameters", "output", "return values"], "confidence": 1.0, "difficulty": 2, "description": "Export parameters are interface elements used by a function module to return processed data back to the calling program. After execution, the function module populates these parameters, which are then accessible in the caller''s scope. They enable output communication in a structured way.", "concept_type": "component", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_005", "title": "Changing Parameters", "aliases": [], "keywords": ["changing parameters", "bidirectional", "pass by reference"], "confidence": 1.0, "difficulty": 3, "description": "Changing parameters in a function module serve dual purposes: they allow passing initial values from the calling program and permit modification within the function module. The updated value is returned to the caller, combining features of both import and export parameters.", "concept_type": "component", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_003", "CONC_004"]}, {"id": "CONC_006", "title": "Exceptions in Function Modules", "aliases": [], "keywords": ["exceptions", "error handling", "RAISE", "MESSAGE"], "confidence": 1.0, "difficulty": 4, "description": "Exceptions are error-handling mechanisms in function modules that signal problems during execution. When triggered, they interrupt normal flow and transfer control back to the caller, allowing graceful error recovery. Each exception can have custom messages and must be declared in the interface and raised using RAISE or MESSAGE statements.", "concept_type": "process", "extracted_from": ["CHUNK_006", "CHUNK_011"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_007", "title": "SY-SUBRC", "aliases": [], "keywords": ["SY-SUBRC", "return code", "system variable"], "confidence": 1.0, "difficulty": 3, "description": "SY-SUBRC is a system variable in ABAP that stores the return code after executing a function module or certain operations. A value of 0 typically indicates success, while non-zero values indicate errors or specific conditions. It is commonly checked after function calls to handle exceptions or runtime errors programmatically.", "concept_type": "object", "extracted_from": ["CHUNK_010", "CHUNK_013"], "related_concepts": ["CONC_006", "CONC_008"]}, {"id": "CONC_008", "title": "CATCH SYSTEM-EXCEPTIONS", "aliases": [], "keywords": ["CATCH SYSTEM-EXCEPTIONS", "runtime error", "exception handling"], "confidence": 1.0, "difficulty": 4, "description": "CATCH SYSTEM-EXCEPTIONS is an ABAP construct used to trap predefined runtime errors such as division by zero or conversion issues. It maps specific error types to numeric codes, allowing developers to detect and handle them via SY-SUBRC checks, preventing program termination due to unhandled exceptions.", "concept_type": "process", "extracted_from": ["CHUNK_012", "CHUNK_013"], "related_concepts": ["CONC_007", "CONC_009"]}, {"id": "CONC_009", "title": "Subroutine", "aliases": [], "keywords": ["subroutine", "local procedure", "FORM"], "confidence": 1.0, "difficulty": 2, "description": "A subroutine in ABAP is a self-contained block of code defined within a single program using FORM/ENDFORM. It can only be called from within the same program, unlike function modules which are globally accessible. Subroutines promote modularity but lack reusability across different programs.", "concept_type": "component", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001"]}, {"id": "CONC_010", "title": "Remote-Enabled Function Module", "aliases": ["REM"], "keywords": ["remote-enabled", "RFC", "integration"], "confidence": 0.8, "difficulty": 4, "description": "A remote-enabled function module is a special type of function module that can be invoked from external systems via RFC (Remote Function Call). This enables integration between SAP and non-SAP systems, supporting distributed computing architectures and cross-system data exchange.", "concept_type": "component", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_001"]}], "relationships": [{"id": "REL_001", "type": "part_of", "source": "CONC_001", "target": "CONC_002", "evidence": "Function modules must be assigned to a function group.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "contains", "source": "CONC_002", "target": "CONC_001", "evidence": "Function group acts as a container for function modules.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "has", "source": "