INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'pitchingAndPersuasiveExample.docx', '48d151fdd14ea90645f9a999df42ed9fa8976b03c9c0a8aee0739fca86e7cbf2', '{"chunks": [{"id": "CHUNK_001", "text": "Opening + problem identification + team introduction\nGood afternoon, honourable judges. We are the ElderWatch team, a group of Higher Diploma students in information Technology. It’s our pleasure to present our proposed strategies to combat scam calls and messages to protect elderly residents in Hong Kong today. Picture a typical afternoon in a Hong Kong flat. An elderly resident is having tea and watching TV when the phone suddenly rings. A frantic voice on the line pleads, “Ah Ma, it’s me! I’m in trouble and I need money right now!” In moments like these, many elderly residents fall for scam calls or messages, unable to distinguish them from genuine ones. As a result, they not only suffer devastating financial losses but also experience a deep erosion of trust, a wound that can be difficult to heal later in life.\nAnother reason elderly residents easily fall into scam traps is the lack of user-friendly anti-scam tools. As shown on this slide, our survey revealed that over 70% of Hong Kong’s elderly are unable to use existing solutions, such as the HK Police’s Scameter or built-in smartphone call-blocking features, because these tools require users to actively input scam details and navigate complex settings, which is a significant barrier for those with limited digital literacy.\nTherefore, it is alarming that over 50% of victims in reported telephone and message scam cases are elderly.", "pages": [1], "end_pos": 1482, "summary": "Introduction of the ElderWatch team and definition of the problem: high vulnerability of elderly to scams due to digital literacy barriers.", "start_pos": 0, "chunk_type": "Introduction", "has_examples": true, "main_concepts": ["CONC_001", "CONC_002", "CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "That’s why we’re here today: to share practical strategies that simplify scam detection for the elderly and provide them with real protection.\nAs a group of High Diploma students in information Technology, our team is passionate about using our knowledge in telecommunications and AI technology to create a scam-free environment for Hong Kong’s elderly. Now, my teammate, Peter, will explain how our proposed Strategies can effectively combat scam calls and messages targeting the elderly.", "pages": [1], "end_pos": 1728, "summary": "Team mission to leverage telecomm and AI knowledge for protection and handover to next speaker.", "start_pos": 1483, "chunk_type": "Mission Statement", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Thank you for the introduction, Alex. Let’s explore the strategies we propose for detecting and blocking scam calls and messages.\nOur first strategy is to empower elderly users with effective, easy-to-use protection through an AI-powered scam detector app installed on their smartphones.\nOur team has developed ScamShield, a mobile app designed specifically for seniors. It runs automatically in the background of the smartphone and detects fraudulent calls and messages in real time. As you can see here, our pilot test with 50 elderly participants showed that ScamShield flagged 92% of scam attempts within 3 seconds.\nLet me explain how ScamShield works. ScamShield users advanced AI to automatically scan incoming calls, SMS and WhatsApp messages for known scam patterns and phrases. When a potential threat is detected, a large, clear pop-up warning in Cantonese immediately appears on the user’s screen; for example, ‘POTETIAL SCAM DETECTED! DO NOT SHARE PERSONAL OR BANKING INFORMATION’. At the same time, the app sends an alert via SMS or WhatsApp to up to three pre-set family members, enabling them to promptly check on their elderly relative. Best of all, everything happens automatically, no action is needed from the elderly user.", "pages": [2], "end_pos": 3052, "summary": "Detailed explanation of ScamShield app functionality, AI detection methods, and family alert mechanisms.", "start_pos": 1729, "chunk_type": "Solution Details", "has_examples": true, "main_concepts": ["CONC_003", "CONC_004", "CONC_005"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Here is a real example from our pilot test: Auntie Mei, a 78-year-old participant from Kwun Tong, received a call from someone pretending to be a police officer claiming her identity had been stolen and demanding immediate payment. ScamShield identified the scam within 2 seconds, blocked the call, displayed a full-screen warning, and instantly notified her daughter. Thanks to the alert, her daughter called back right away and stopped Auntie Mei from transferring HK$48000, a loss that would have been devastating.\nTo make this protection available to seniors across Hong Kong, we will partner with community centres and elderly homes to introduce, install, and set up the app for them free of charge.\nIn summary, ScamShield provides real-time hands-free protection that empowers seniors and give families peace of mind. In Hong Kong’s rapidly evolving scam landscape, this solution delivers a direct and effective safeguard. We project that within one month of use, at least 85% of users will be shielded from detected scam attempts, significantly reducing both financial loss and emotional distress.\nNext up, Nora will explain how we’re going to add another powerful layer of security to combat scam calls and messages.", "pages": [2], "end_pos": 4345, "summary": "Real-world success story (Auntie Mei) and plan for wide-scale deployment via community partnerships.", "start_pos": 3053, "chunk_type": "Case Study & Deployment", "has_examples": true, "main_concepts": ["CONC_007", "CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_005", "text": "Addressing limitations + conclusion + closing\nAnother solution: [Content omitted per instructions]. Addressing limitations + conclusion + closing\nThanks, Nora. While our strategies are practical, we know they might come with challenges. For our ScamShield app, the primary challenge could be limited engagement because some elderly users may feel intimidated by new technology. To address this, we’ll conduct simple training sessions and hands-on demonstrations at community centres and elderly homes. Trained volunteers will also help with installation and setup, ensuring every senior feels confident and comfortable using the app.\nIn addition, we understand that some telecom providers may resist making changes due to implementation costs or operational concerns. To overcome this, we’ll propose low-risk pilot programmes and actively pursue government grants or anti-scam funding to cover the expenses. Our goal is to address resistance to change, ensuring that the solution can gain the support needed for successful implementation.\nTo conclude, we envision a safer future where Hong Kong’s elderly residents are shielded from scam calls and messages, free from fear and financial loss. With the AI-powered ScamShield app and the network-level scam filter, we aim to drive meaningful change. Through collaboration with telecom providers, elderly homes and community centres, and the authorities, we will deliver real protection for our aging population, safeguarding their golden years, one blocked scam at a time.\n\nThank you for the opportunity to present our strategies for the Smart City and STEAM Challenge Cup. We greatly appreciate your time and attention. Your insights and advice will be invaluable in strengthening our strategies. We welcome your questions and feedback. Thank you very much for your consideration.", "pages": [3], "end_pos": 5928, "summary": "Discussion of challenges like user intimidation and provider resistance, along with mitigation strategies and final concluding vision.", "start_pos": 4346, "chunk_type": "Challenges & Conclusion", "has_examples": false, "main_concepts": ["CONC_008", "CONC_010", "CONC_009"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}], "concepts": [{"id": "CONC_001", "title": "ElderWatch Team", "aliases": ["Higher Diploma IT Group"], "keywords": ["team", "students", "elderly protection", "Hong Kong"], "confidence": 1.0, "difficulty": 2, "description": "A group of Higher Diploma students in Information Technology proposing strategies to combat scam calls and messages targeting elderly residents in Hong Kong.", "concept_type": "person", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_003", "CONC_006"]}, {"id": "CONC_002", "title": "Telecommunications Scam Vulnerability", "aliases": ["Elderly Phone Fraud Risk"], "keywords": ["scam", "financial loss", "vulnerability", "telecommunications"], "confidence": 1.0, "difficulty": 3, "description": "The phenomenon where elderly residents suffer financial loss and erosion of trust due to inability to distinguish scam calls from genuine ones, accounting for over 50% of reported cases.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_003"]}, {"id": "CONC_003", "title": "ScamShield Mobile Application", "aliases": ["Scam Shield", "Mobile Protection Tool"], "keywords": ["app", "AI detector", "smartphone", "background process"], "confidence": 1.0, "difficulty": 4, "description": "An AI-powered mobile app designed specifically for seniors that runs automatically in the background to detect and block fraudulent calls and messages in real-time.", "concept_type": "component", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_004"]}, {"id": "CONC_004", "title": "AI Pattern Detection", "aliases": ["Fraud Detection AI"], "keywords": ["artificial intelligence", "pattern recognition", "real-time scanning"], "confidence": 1.0, "difficulty": 4, "description": "The technical process used by the application to automatically scan incoming communications for known scam patterns and phrases without user intervention.", "concept_type": "process", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_003"]}, {"id": "CONC_005", "title": "Family Alert Mechanism", "aliases": ["Relative Alert", "Emergency Contact Trigger"], "keywords": ["alert system", "family notification", "SMS", "WhatsApp"], "confidence": 1.0, "difficulty": 2, "description": "A notification feature that sends SMS or WhatsApp alerts to pre-set family members when a potential threat is detected, enabling external verification.", "concept_type": "component", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_003", "CONC_008"]}, {"id": "CONC_006", "title": "Digital Literacy Barrier", "aliases": ["Technology Adoption Gap"], "keywords": ["digital literacy", "usability barrier", "complex settings"], "confidence": 0.9, "difficulty": 2, "description": "The lack of familiarity with complex settings required by existing tools like HK Police''s Scameter, which prevents 70% of elderly users from utilizing them.", "concept_type": "object", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_003"]}, {"id": "CONC_007", "title": "Community Outreach Strategy", "aliases": ["On-Site Setup Plan"], "keywords": ["partnership", "installation", "community centre", "deployment"], "confidence": 1.0, "difficulty": 2, "description": "The method of partnering with community centres and elderly homes to introduce, install, and set up the app free of charge to ensure adoption.", "concept_type": "process", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_003", "CONC_009"]}, {"id": "CONC_008", "title": "Implementation Challenges", "aliases": ["Adoption Obstacles"], "keywords": ["resistance", "engagement", "costs", "intimidation"], "confidence": 1.0, "difficulty": 3, "description": "Specific obstacles including limited engagement due to technological intimidation by seniors and resistance from telecom providers regarding operational concerns.", "concept_type": "object", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_007", "CONC_010"]}, {"id": "CONC_009", "title": "Stakeholder Collaboration", "aliases": ["Ecosystem Partners"], "keywords": ["stakeholders", "collaboration", "telecom", "government"], "confidence": 1.0, "difficulty": 3, "description": "Cooperation involving telecom providers, elderly homes, community centres, and authorities to deliver protection for the aging population.", "concept_type": "architecture", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_007"]}, {"id": "CONC_010", "title": "Pilot Programme Mitigation", "aliases": ["Funding & Testing Strategy"], "keywords": ["pilot test", "grants", "funding", "implementation"], "confidence": 1.0, "difficulty": 3, "description": "Strategies to address provider resistance through low-risk pilot programmes and pursuing government grants or anti-scam funding.", "concept_type": "process", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_008"]}], "relationships": [{"id": "REL_001", "type": "implements", "source": "CONC_001", "target": "CONC_003", "evidence": "We are the ElderWatch team... developed ScamShield", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "produces", "source": "CONC_003", "target": "CONC_002", "evidence": "ScamShield... detects fraudulent calls... protecting elderly residents", "strength": 0.9, "bidirectional": false}, {"id": "REL_003", "type": "requires", "source": "CONC_003", "target": "CONC_004", "evidence": "ScamShield users advanced AI to automatically scan incoming calls", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "part_of", "source": "CONC_003", "target": "CONC_005", "evidence": "App sends an alert via SMS... to pre-set family members", "strength": 0.9, "bidirectional": false}, {"id": "REL_005", "type": "opposite_of", "source": "CONC_006", "target": "CONC_002", "evidence": "Existing solutions require active input... significant barrier", "strength": 0.8, "bidirectional": false}, {"id": "REL_006", "type": "managed_by", "source": "CONC_007", "target": "CONC_003", "evidence": "Partner with community centres... to introduce, install... free of charge", "strength": 0.9, "bidirectional": false}, {"id": "REL_007", "type": "requires", "source": "CONC_008", "target": "CONC_007", "evidence": "To address this, we''ll conduct simple training sessions... at community centres", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "implements", "source": "CONC_007", "target": "CONC_009", "evidence": "Through collaboration with telecom providers... and the authorities", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 5, "missing_links": [], "coverage_score": 0.95, "total_concepts": 10, "consistency_score": 0.98, "total_relationships": 8}, "document_metadata": {"title": "ElderWatch Presentation: Strategies to Combat Elderly Scams", "language": "English", "main_topic": "AI-Powered Anti-Scam Solutions for Seniors", "difficulty_level": "Intermediate", "estimated_reading_time": "5 minutes"}, "concept_chunk_mapping": [{"concept": "CONC_001", "context": "Introduces the ElderWatch team.", "chunk_id": "CHUNK_001", "positions": [68], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "CONC_002", "context": "Describes the scam scenario affecting elderly residents.", "chunk_id": "CHUNK_001", "positions": [400], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "CONC_006", "context": "Explains the lack of user-friendly tools causing barriers.", "chunk_id": "CHUNK_001", "positions": [750], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "CONC_003", "context": "Defines ScamShield as the developed mobile app.", "chunk_id": "CHUNK_003", "positions": [450], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "CONC_004", "context": "Describes the AI pattern detection mechanism.", "chunk_id": "CHUNK_003", "positions": [800], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "CONC_005", "context": "Details the alert sending to family members.", "chunk_id": "CHUNK_003", "positions": [1100], "concept_id": "CONC_005", "importance": "secondary"}, {"concept": "CONC_007", "context": "Mentions partnership with community centres.", "chunk_id": "CHUNK_004", "positions": [1400], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "CONC_008", "context": "Discusses challenges like user intimidation.", "chunk_id": "CHUNK_005", "positions": [180], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "CONC_009", "context": "Lists stakeholders for collaboration.", "chunk_id": "CHUNK_005", "positions": [1100], "concept_id": "CONC_009", "importance": "secondary"}]}', '{"total_modules": 3, "total_concepts": 5, "difficulty_score": 4, "total_structures": 3, "total_applications": 4}', '[]', '[]', '[]', '2026-04-27 14:40:12.014441', '2026-04-27 14:40:12.014441', NULL, '[{"id": "module_1", "name": "Problem Identification and Context", "topic_count": 4}, {"id": "module_2", "name": "AI-Powered ScamShield App Solution", "topic_count": 5}, {"id": "module_3", "name": "Implementation Challenges and Mitigation", "topic_count": 3}]', NULL, 'Opening + problem identification + team introduction
Good afternoon, honourable judges. We are the ElderWatch team, a
group of Higher Diploma students in information Technology. It’s
our pleasure to present our proposed strategies to combat scam calls
and messages to protect elderly residents in Hong Kong today.
Picture a typical afternoon in a Hong Kong flat. An elderly resident
is having tea and watching TV when the phone suddenly rings. A
frantic voice on the line pleads, “Ah Ma, it’s me! I’m in trouble and
I need money right now!” In moments like these, many elderly
residents fall for scam calls or messages, unable to distinguish them
from genuine ones. As a result, they not only suffer devastating
financial losses but also experience a deep erosion of trust, a wound
that can be difficult to heal later in life.
Another reason elderly residents easily fall into scam traps is the
lack of user-friendly anti-scam tools. As shown on this slide, our
survey revealed that over 70% of Hong Kong’s elderly are unable to
use existing solutions, such as the HK Police’s Scameter or built-in
smartphone call-blocking features, because these tools require users
to actively input scam details and navigate complex settings, which
is a significant barrier for those with limited digital literacy.
Therefore, it is alarming that over 50% of victims in reported
telephone and message scam cases are elderly.
That’s why we’re here today: to share practical strategies that
simplify scam detection for the elderly and provide them with real
protection.
As a group of High Diploma students in information Technology,
our team is passionate about using our knowledge in
telecommunications and AI technology to create a scam-free
environment for Hong Kong’s elderly. Now, my teammate, Peter,
will explain how our proposed Strategies can effectively combat
scam calls and messages targeting the elderly.

Solutions
Thank you for the introduction, Alex. Let’s explore the strategies we
propose for detecting and blocking scam calls and messages.
Our first strategy is to empower elderly users with effective, easy-
to-use protection through an AI-powered scam detector app
installed on their smartphones.
Our team has developed ScamShield, a mobile app designed
specifically for seniors. It runs automatically in the background of
the smartphone and detects fraudulent calls and messages in real
time. As you can see here, our pilot test with 50 elderly participants
showed that ScamShield flagged 92% of scam attempts within 3
seconds.
Let me explain how ScamShield works. ScamShield users advanced
AI to automatically scan incoming calls, SMS and WhatsApp
messages for known scam patterns and phrases. When a potential
threat is detected, a large, clear pop-up warning in Cantonese
immediately appears on the user’s screen; for example, ‘POTETIAL
SCAM DETECTED! DO NOT SHARE PERSONAL OR BANKING
INFORMATION’. At the same time, the app sends an alert via SMS
or WhatsApp to up to three pre-set family members, enabling them
to promptly check on their elderly relative. Best of all, everything
happens automatically, no action is needed from the elderly user.
Here is a real example from our pilot test: Auntie Mei, a 78-year-old
participant from Kwun Tong, received a call from someone
pretending to be a police officer claiming her identity had been
stolen and demanding immediate payment. ScamShield identified
the scam within 2 seconds, blocked the call, displayed a full-screen
warning, and instantly notified her daughter. Thanks to the alert,
her daughter called back right away and stopped Auntie Mei from
transferring HK$48000, a loss that would have been devastating.
To make this protection available to seniors across Hong Kong, we
will partner with community centres and elderly homes to
introduce, install, and set up the app for them free of charge.
In summary, ScamShield provides real-time hands-free protection

that empowers seniors and give families peace of mind. In Hong
Kong’s rapidly evolving scam landscape, this solution delivers a
direct and effective safeguard. We project that within one month of
use, at least 85% of users will be shielded from detected scam
attempts, significantly reducing both financial loss and emotional
distress.
Next up, Nora will explain how we’re going to add another
powerful layer of security to combat scam calls and messages.
Another solution: 省略，说明要点参考课件。
Addressing limitations + conclusion + closing
Thanks, Nora. While our strategies are practical, we know they
might come with challenges. For our ScamShield app, the primary
challenge could be limited engagement because some elderly users
may feel intimidated by new technology. To address this, we’ll
conduct simple training sessions and hands-on demonstrations at
community centres and elderly homes. Trained volunteers will also
help with installation and setup, ensuring every senior feels
confident and comfortable using the app.
In addition, we understand that some telecom providers may resist
making changes due to implementation costs or operational
concerns. To overcome this, we’ll propose low-risk pilot
programmes and actively pursue government grants or anti-scam
funding to cover the expenses. Our goal is to address resistance to
change, ensuring that the solution can gain the support needed for
successful implementation.
To conclude, we envision a safer future where Hong Kong’s elderly
residents are shielded from scam calls and messages, free from fear
and financial loss. With the AI-powered ScamShield app and the
network-level scam filter, we aim to drive meaningful change.
Through collaboration with telecom providers, elderly homes and
community centres, and the authorities, we will deliver real
protection for our aging population, safeguarding their golden
years, one blocked scam at a time.

Thank you for the opportunity to present our strategies for the
Smart City and STEAM Challenge Cup. We greatly appreciate your
time and attention. Your insights and advice will be invaluable in
strengthening our strategies. We welcome your questions and
feedback. Thank you very much for your consideration.') ON CONFLICT DO NOTHING;
INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'S2_U8_WB.pdf', '604d5fe4ec646035a8092b0b47a784b0a2f9b470e793b5b5159c5a2e0fc5a775', '{"chunks": [{"id": "CHUNK_001", "text": "1 In Hong Kong, mains voltage is 220 V. 2 Electricity is supplied to our homes through two wires: the live wire and the neutral wire. 3 We should avoid connecting too many appliances to a mains socket, because they will draw a large current and overloading occurs. 4 A short circuit provides a branch with a very low resistance for current to flow. It may be caused by a loose wire, or even dust and moisture on the circuit. This must be avoided. 5 The earth wire connects the metal case of an electrical appliance to the ground. It protects us from an electric shock.", "pages": [1], "end_pos": 452, "summary": "Defines core household electricity concepts: mains voltage, live/neutral/earth wires, overloading, short circuit, and electric shock.", "start_pos": 0, "chunk_type": "fill_in_the_blanks", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Label different parts of the mains socket and the three-pin plug shown below with the words given. blue brown greenand yellow connecting wire fuse earthhole earth pin earth wire livehole livepin live wire neutralhole neutral pin neutral wire Mains socket Three-pin plug (front) 1] earth hole (1) 4§] earth pin (1) 28 live hole (1) 5 Wiring of three-pin plug (back) 78 earth wire (i) Colour: 8 green and yellow (1) 98 neutral wire (1) Colour: 10 8 blue (1)", "pages": [2], "end_pos": 910, "summary": "Identifies physical components and color coding of three-pin plugs and sockets, emphasizing safety wiring conventions.", "start_pos": 453, "chunk_type": "labelling", "has_examples": false, "main_concepts": ["CONC_002", "CONC_003", "CONC_004", "CONC_009", "CONC_014"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "2 Sockets at home are connected in parallel to the mains supply. 3 When more parallel branches are added to a circuit, the current in the main loop decreases. 4 The rating of a fuse shows the average current which can flow through it without breaking the circuit.", "pages": [1], "end_pos": 1120, "summary": "Tests understanding of parallel circuit behavior and fuse functionality, correcting misconceptions about current distribution.", "start_pos": 911, "chunk_type": "true_or_false", "has_examples": false, "main_concepts": ["CONC_015", "CONC_009"], "has_definitions": false, "secondary_concepts": ["CONC_016"]}, {"id": "CHUNK_004", "text": "3 Which of the following devices has the same function as the fuse? A Ammeter B Rheostat C Switch D Circuit breaker 5 Which of the following statements about the earth wire is / are correct? (1) The earth wire connects the metal case of the appliance to the ground. (2) The current flows to the ground through the earth wire when the live wire touches the metal case accidentally. (3) The earth wire blows when a fault occurs.", "pages": [3], "end_pos": 1412, "summary": "Assesses functional equivalence of protective devices and validates earth wire properties including fault-path role.", "start_pos": 1121, "chunk_type": "multiple_choice", "has_examples": false, "main_concepts": ["CONC_008", "CONC_004", "CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "1 We use electrical power to tell how fast an appliance converts electrical energy to other forms. 2 The unit of power is the watt (W). A larger unit of power is the kilowatt (kW). 3 The power rating is the power of the appliance when it is working at the indicated voltage rating. 4 Efficiency = useful power output / power input x 100% 5 Many appliances have an energy label to show how efficient they are. 6 A joulemeter or a kilowatt-hour meter can be used to measure the electrical energy consumed by appliances.", "pages": [4], "end_pos": 1825, "summary": "Introduces power fundamentals, units, efficiency calculation, labeling, and energy measurement tools.", "start_pos": 1413, "chunk_type": "fill_in_the_blanks", "has_examples": false, "main_concepts": ["CONC_010", "CONC_011", "CONC_012", "CONC_013"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "a Calculate the power of the bulb. (2 marks) Power = energy / time = 1200 / 60 = 20 W b Find the useful power output of the bulb. Light energy = 1200 − 300 = 900 J → Useful power output = 900 / 60 = 15 W c Calculate the efficiency of the bulb. Efficiency = 15/20 × 100% = 75%", "pages": [5], "end_pos": 2120, "summary": "Applies power and efficiency formulas to real-world LED lamp data, demonstrating quantitative reasoning.", "start_pos": 1826, "chunk_type": "structured_question", "has_examples": true, "main_concepts": ["CONC_010", "CONC_012"], "has_definitions": false, "secondary_concepts": ["CONC_013"]}, {"id": "CHUNK_007", "text": "10 Electrical appliances are connected in parallel to the mains socket. Which of the following are the advantages? (1) All appliances can work at the same voltage. (2) Each appliance can be switched on and off independently. (3) The power consumed by each appliance is the same.", "pages": [6], "end_pos": 2345, "summary": "Evaluates understanding of practical benefits of parallel domestic wiring configurations.", "start_pos": 2121, "chunk_type": "multiple_choice", "has_examples": false, "main_concepts": ["CONC_015"], "has_definitions": false, "secondary_concepts": ["CONC_010"]}, {"id": "CHUNK_008", "text": "A student connects a thick nichrome wire, an ammeter and a bulb in series with a battery. ... e The wire is then connected back to the circuit. What will happen to the reading of the ammeter? The ammeter reading decreases. The wire becomes longer and thinner. Hence its resistance increases. As the resistance in the circuit increases, the current decreases.", "pages": [9], "end_pos": 2690, "summary": "Illustrates series circuit behavior and resistance dependence on geometry, linking physical changes to electrical outcomes.", "start_pos": 2346, "chunk_type": "high_order_question", "has_examples": true, "main_concepts": ["CONC_016"], "has_definitions": false, "secondary_concepts": ["CONC_009"]}], "concepts": [{"id": "CONC_001", "title": "Mains voltage", "aliases": ["supply voltage", "domestic voltage"], "keywords": ["220 V", "AC supply", "Hong Kong standard"], "confidence": 1.0, "difficulty": 2, "description": "The standard electrical potential difference supplied to residential buildings. In Hong Kong, it is 220 V alternating current (AC), providing the baseline energy source for all household appliances. This voltage is maintained across the live and neutral wires and must be strictly regulated to ensure safe and consistent operation of devices rated for this supply.", "concept_type": "object", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_002", "title": "Live wire", "aliases": ["phase wire", "hot wire"], "keywords": ["brown wire", "high potential", "fused conductor"], "confidence": 1.0, "difficulty": 2, "description": "A current-carrying conductor in a mains circuit that maintains a high potential (220 V relative to earth) and delivers electrical energy from the supply. It is typically color-coded brown in three-pin plug systems and must always be fused on the live side for safety. Contact with the live wire while grounded poses severe risk of electric shock.", "concept_type": "component", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_001", "CONC_003", "CONC_007"]}, {"id": "CONC_003", "title": "Neutral wire", "aliases": ["return wire"], "keywords": ["blue wire", "return path", "near-zero potential"], "confidence": 1.0, "difficulty": 2, "description": "A return path conductor in a mains circuit that completes the electrical loop by carrying current back to the supply transformer. It is maintained near earth potential (0 V) under normal conditions and is color-coded blue. While less hazardous than the live wire, it can become energized during faults and must never be assumed safe without verification.", "concept_type": "component", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_001", "CONC_002", "CONC_007"]}, {"id": "CONC_004", "title": "Earth wire", "aliases": ["ground wire", "protective earth"], "keywords": ["green-and-yellow", "safety ground", "fault path"], "confidence": 1.0, "difficulty": 3, "description": "A safety conductor that connects the metal casing of an appliance directly to the ground (earth). Its purpose is to provide a low-resistance path for fault current to flow safely away if the live wire contacts the casing, thereby preventing electric shock by triggering the circuit breaker or fuse. It is color-coded green-and-yellow and is not intended to carry current under normal operation.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_004"], "related_concepts": ["CONC_007", "CONC_008"]}, {"id": "CONC_005", "title": "Overloading", "aliases": ["circuit overload"], "keywords": ["excessive current", "thermal hazard", "circuit capacity"], "confidence": 1.0, "difficulty": 3, "description": "A hazardous condition that occurs when too many appliances draw excessive current through a single circuit or socket, exceeding its designed capacity. This causes overheating of wires, insulation damage, and fire risk. It is prevented by using appropriately rated fuses or circuit breakers and distributing loads across multiple circuits.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_008", "CONC_012"]}, {"id": "CONC_006", "title": "Short circuit", "aliases": ["short"], "keywords": ["low resistance path", "fault current", "live-neutral contact"], "confidence": 1.0, "difficulty": 3, "description": "An abnormal low-resistance connection between two points of different potential in a circuit—typically between live and neutral or live and earth. It bypasses the normal load, causing dangerously high current flow, rapid heating, and potential fire or equipment damage. Common causes include damaged insulation, loose wires, or moisture ingress.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_005", "CONC_008"]}, {"id": "CONC_007", "title": "Electric shock", "aliases": ["shock hazard"], "keywords": ["current through body", "physiological hazard", "safety failure"], "confidence": 1.0, "difficulty": 3, "description": "Physiological injury caused by electric current passing through the human body. Severity depends on current magnitude, pathway, duration, and frequency. In household contexts, it most commonly results from contact with a live conductor while grounded or from faulty earthing. Prevention relies on proper insulation, earthing, double insulation, and protective devices like RCDs or circuit breakers.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_002", "CONC_004"]}, {"id": "CONC_008", "title": "Circuit breaker", "aliases": ["MCB", "breaker"], "keywords": ["resettable protection", "overcurrent detection", "thermal-magnetic"], "confidence": 1.0, "difficulty": 3, "description": "An automatically operated electrical switch designed to protect a circuit from damage due to overcurrent or short circuit. Unlike a fuse, it is resettable after tripping. It detects excess current via thermal or magnetic mechanisms and interrupts the live conductor. In modern installations, it replaces fuses as the primary overcurrent protection device.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_004"], "related_concepts": ["CONC_005", "CONC_006", "CONC_012"]}, {"id": "CONC_009", "title": "Fuse", "aliases": ["cartridge fuse"], "keywords": ["sacrificial device", "melting element", "ampere rating"], "confidence": 1.0, "difficulty": 2, "description": "A sacrificial overcurrent protection device containing a metal wire or strip that melts when excessive current flows, thereby breaking the circuit. Rated in amperes (e.g., 5 A, 13 A), it must be placed in series on the live wire. Its rating should match the cable''s current-carrying capacity—not the appliance''s demand—to prevent fire hazards.", "concept_type": "component", "extracted_from": ["CHUNK_002", "CHUNK_004"], "related_concepts": ["CONC_008", "CONC_012"]}, {"id": "CONC_010", "title": "Electrical power", "aliases": ["power consumption", "instantaneous power"], "keywords": ["watt", "energy transfer rate", "P = VI"], "confidence": 1.0, "difficulty": 2, "description": "The rate at which electrical energy is transferred by an electric circuit, measured in watts (W). For resistive loads, power equals voltage multiplied by current (P = VI). It quantifies how fast an appliance converts electrical energy into other forms such as heat, light, or motion. Larger units include kilowatt (kW) for appliances and megawatt (MW) for grid-scale generation.", "concept_type": "theory", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_011", "CONC_013"]}, {"id": "CONC_011", "title": "Power rating", "aliases": ["rated power"], "keywords": ["nameplate value", "rated voltage", "design load"], "confidence": 1.0, "difficulty": 2, "description": "The nominal electrical power an appliance is designed to consume when operating at its specified voltage (e.g., 220 V). It appears on nameplates and determines appropriate fuse sizing, wiring gauge, and circuit loading. Exceeding this rating may cause overheating or failure; operating below it typically reduces performance but not safety.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_010", "CONC_012"]}, {"id": "CONC_012", "title": "Energy efficiency", "aliases": ["efficiency", "energy conversion ratio"], "keywords": ["efficiency formula", "useful output", "energy label"], "confidence": 1.0, "difficulty": 3, "description": "The ratio of useful energy output to total energy input, expressed as a percentage. For electrical appliances, it measures how effectively they convert electricity into desired outputs (e.g., light, heat, motion) versus waste (e.g., heat loss in motors, standby consumption). Higher efficiency reduces electricity bills and environmental impact, and is indicated by energy labels (e.g., Grade 1 in Hong Kong).", "concept_type": "theory", "extracted_from": ["CHUNK_005", "CHUNK_006"], "related_concepts": ["CONC_010", "CONC_013"]}, {"id": "CONC_013", "title": "Kilowatt-hour meter", "aliases": ["electricity meter", "utility meter"], "keywords": ["utility meter", "energy billing", "kW·h"], "confidence": 1.0, "difficulty": 2, "description": "A measuring instrument that records the cumulative electrical energy consumed over time, expressed in kilowatt-hours (kW·h). One kW·h equals 3.6 million joules—the energy used by a 1-kW device operating for one hour. Utilities use it for billing; it differs from a wattmeter, which measures instantaneous power.", "concept_type": "component", "extracted_from": ["CHUNK_005", "CHUNK_007"], "related_concepts": ["CONC_010", "CONC_012"]}, {"id": "CONC_014", "title": "Three-pin plug", "aliases": ["BS 1363 plug"], "keywords": ["live-neutral-earth", "polarized plug", "HK standard"], "confidence": 1.0, "difficulty": 2, "description": "A standardized electrical connector used in Hong Kong and other regions with 220–240 V AC supply. It contains three pins: live (brown wire), neutral (blue wire), and earth (green-and-yellow wire), each corresponding to dedicated holes in the socket. Designed for safety, polarity, and grounding, it ensures correct connection of appliances with exposed metal parts.", "concept_type": "object", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_015", "title": "Parallel circuit", "aliases": ["shunt circuit"], "keywords": ["independent branches", "voltage uniformity", "additive current"], "confidence": 1.0, "difficulty": 3, "description": "An electrical configuration where components are connected across common nodes, providing multiple independent paths for current flow. In household wiring, sockets and appliances are connected in parallel so that each receives full mains voltage (220 V), operates independently, and does not affect others if switched off or faulty. Total current equals sum of branch currents.", "concept_type": "architecture", "extracted_from": ["CHUNK_003", "CHUNK_007"], "related_concepts": ["CONC_002", "CONC_003", "CONC_016"]}, {"id": "CONC_016", "title": "Series circuit", "aliases": ["daisy-chain"], "keywords": ["single path", "current uniformity", "voltage division"], "confidence": 1.0, "difficulty": 2, "description": "An electrical configuration where components are connected end-to-end in a single path, so the same current flows through all elements. Voltage is divided among components proportionally to their resistance. Not used for household power distribution due to dependency—if one device fails, the entire circuit opens—but common in simple experiments and some control circuits.", "concept_type": "architecture", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_015"]}], "relationships": [{"id": "REL_001", "type": "produces", "source": "CONC_001", "target": "CONC_002", "evidence": "Mains voltage is present on the live wire.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "produces", "source": "CONC_001", "target": "CONC_003", "evidence": "Mains voltage is referenced between live and neutral.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "requires", "source": "CONC_002", "target": "CONC_004", "evidence": "Earth wire provides safety against live-wire faults.", "strength": 0.95, "bidirectional": false}, {"id": "REL_004", "type": "managed_by", "source": "CONC_005", "target": "CONC_009", "evidence": "Fuses protect circuits from overloading.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "managed_by", "source": "CONC_006", "target": "CONC_009", "evidence": "Fuses interrupt short-circuit currents.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "prevented_by", "source": "CONC_007", "target": "CONC_004", "evidence": "Earth wire prevents electric shock during casing faults.", "strength": 0.98, "bidirectional": false}, {"id": "REL_007", "type": "similar_to", "source": "CONC_008", "target": "CONC_009", "evidence": "Both provide overcurrent protection; circuit breaker is resettable, fuse is sacrificial.", "strength": 0.9, "bidirectional": true}, {"id": "REL_008", "type": "example_of", "source": "CONC_010", "target": "CONC_011", "evidence": "Power rating is a specific instance of electrical power specification.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "requires", "source": "CONC_012", "target": "CONC_010", "evidence": "Efficiency calculation requires power input and output values.", "strength": 0.95, "bidirectional": false}, {"id": "REL_010", "type": "measures", "source": "CONC_013", "target": "CONC_012", "evidence": "Kilowatt-hour meter data enables annual efficiency assessment.", "strength": 0.9, "bidirectional": false}, {"id": "REL_011", "type": "part_of", "source": "CONC_014", "target": "CONC_002", "evidence": "Live pin is a physical component of the three-pin plug.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "part_of", "source": "CONC_014", "target": "CONC_003", "evidence": "Neutral pin is a physical component of the three-pin plug.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "part_of", "source": "CONC_014", "target": "CONC_004", "evidence": "Earth pin is a physical component of the three-pin plug.", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "located_in", "source": "CONC_015", "target": "CONC_002", "evidence": "Household sockets connect in parallel to the live supply.", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "located_in", "source": "CONC_015", "target": "CONC_003", "evidence": "Household sockets connect in parallel to the neutral supply.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 8, "missing_links": [], "coverage_score": 1.0, "total_concepts": 16, "consistency_score": 1.0, "total_relationships": 15}, "document_metadata": {"title": "Household Electricity and Power Concepts", "language": "English", "main_topic": "Electrical safety, circuit design, power calculation, and energy efficiency in domestic contexts", "difficulty_level": "Intermediate", "estimated_reading_time": "45 minutes"}, "concept_chunk_mapping": [{"concept": "Mains voltage", "context": "In Hong Kong, mains voltage is 220 V.", "chunk_id": "CHUNK_001", "positions": [4, 21], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Live wire", "context": "the live wire and the neutral wire.", "chunk_id": "CHUNK_001", "positions": [76, 87], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Neutral wire", "context": "the live wire and the neutral wire.", "chunk_id": "CHUNK_001", "positions": [98, 111], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Earth wire", "context": "The earth wire connects the metal case...", "chunk_id": "CHUNK_001", "positions": [270, 281], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Overloading", "context": "overloading occurs.", "chunk_id": "CHUNK_001", "positions": [172, 185], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Short circuit", "context": "A short circuit provides a branch...", "chunk_id": "CHUNK_001", "positions": [200, 213], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Electric shock", "context": 