INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'ITP4511-202324-JarkataEE-Netbeans24.pptx', 'fe54c26b43780bbca510380d0a60ac8d571d8be7f57d9999bd8f3da153fde5a4', '{"chunks": [{"id": "CHUNK_001", "text": "NetBean IDE (Development / Test & Debugging) XAMPP / MAMP (MySQL Server & phpmyadmin)", "pages": [1], "end_pos": 86, "summary": "Lists primary development tools: NetBeans IDE and XAMPP/MAMP stacks.", "start_pos": 0, "chunk_type": "overview", "has_examples": false, "main_concepts": ["CONC_001", "CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_002", "text": "Install JDK (version 17) Install Netbeans IDE 24 Initial Setup for Web Application & Glassfish Server Build and Run Project", "pages": [2], "end_pos": 175, "summary": "Outlines key steps for environment setup including JDK and IDE installation.", "start_pos": 87, "chunk_type": "process", "has_examples": false, "main_concepts": ["CONC_002", "CONC_001", "CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_008"]}, {"id": "CHUNK_003", "text": "Netbeans requires Java 17 only. Install Java Development Kit (JDK) 17, not JRE. https://www.oracle.com/java/technologies/downloads/#java17", "pages": [3], "end_pos": 265, "summary": "Specifies JDK 17 as mandatory for NetBeans operation.", "start_pos": 176, "chunk_type": "requirement", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_004", "text": "Install Netbeans 24 Built-in JakartaEE supports Available for both Windows/macOS/Linux Download and install of your platform: https://netbeans.apache.org/front/main/download/nb24/", "pages": [4], "end_pos": 390, "summary": "Provides download instructions for NetBeans IDE 24 with Jakarta EE support.", "start_pos": 266, "chunk_type": "instruction", "has_examples": false, "main_concepts": ["CONC_001", "CONC_007"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Launch Netbeans Create a new project Java with Maven > Web Application Setup a project (try your own project name & package name) For the first time, this may take a few minutes to activate the plugin.", "pages": [5], "end_pos": 510, "summary": "Describes initial project creation steps in NetBeans using Maven template.", "start_pos": 391, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_001", "CONC_008"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "Settings For the first name, you need to setup the server. Click “Add…” button. (It will prompt “Add Server Instance” dialog.) Select GlassFish Server 7.0.0 at the “Choose a server to download” Check the checkbox “I have read and accept the license agreement…” Click “Download Now…” Click “Next >” upon the competition of download.", "pages": [6], "end_pos": 680, "summary": "Details server setup process in NetBeans by downloading GlassFish.", "start_pos": 511, "chunk_type": "configuration", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_007", "text": "At the “New Web Application” Dialog Server : GlassFish Server Java EE Version: Jakarta EE 10 Web* *Java EE Is rebranded to Jakarta EE. Complete the creation of the project by clicking “Finish”.", "pages": [7], "end_pos": 780, "summary": "Configures new web app to use GlassFish and Jakarta EE 10 specification.", "start_pos": 681, "chunk_type": "configuration", "has_examples": false, "main_concepts": ["CONC_007", "CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_008"]}, {"id": "CHUNK_008", "text": "Installing XAMPP /MAMP XAMPP / MAMP - A local server environment with Web & MySQL server which supports PHP development. Provide an easily-setup MySQL Server with GUI. Comes with phpmyadmin portal for managing the server. In this module, we will use the MySQL Server for JDBC connection with Java EE / Jakarta EE.", "pages": [8], "end_pos": 930, "summary": "Defines XAMPP/MAMP as local server environments containing MySQL and phpMyAdmin.", "start_pos": 781, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_003", "CONC_004", "CONC_005"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_009", "text": "Launch XAMPP application Click Start or Start All Make sure the Apache & MYSQL Server are started up (Green dots) Check out if you can get access to phpmyadmin portal: http://localhost/phpmyadmin/", "pages": [9], "end_pos": 1050, "summary": "Instructions for launching XAMPP and verifying phpMyAdmin accessibility.", "start_pos": 931, "chunk_type": "procedure", "has_examples": true, "main_concepts": ["CONC_003", "CONC_005"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "Launch MAMP application Click Start Servers Make sure the Apache & MYSQL Server are started up (Green dots) Check out if you can get access to phpmyadmin portal: http://localhost:8888/MAMP/phpmyadmin.php?lang=en", "pages": [10], "end_pos": 1170, "summary": "Procedure for starting MAMP servers and accessing its phpMyAdmin instance.", "start_pos": 1051, "chunk_type": "procedure", "has_examples": true, "main_concepts": ["CONC_004", "CONC_005"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_011", "text": "At the source package, right-click the package, then click ''Servlet''. Setup the new Servlet accordingly. Configure Servlet Deployment Information: Register the Servlet with the application by giving it a name and URL pattern.", "pages": [11], "end_pos": 1300, "summary": "Guides user through creating and configuring a servlet in NetBeans.", "start_pos": 1171, "chunk_type": "procedure", "has_examples": false, "main_concepts": ["CONC_009"], "has_definitions": false, "secondary_concepts": ["CONC_008"]}, {"id": "CHUNK_012", "text": "Click Build and Run to Test Run the Project. Netbeans will prompt the browser and show the result.", "pages": [12], "end_pos": 1380, "summary": "Final step to compile, deploy, and test the web application.", "start_pos": 1301, "chunk_type": "action", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_013", "text": "Alternative IDE: NetBeans is the IDE used by this module. However, you may try other IDEs like IntelliJ IDEA Ultimate (with student license) or Eclipse for Java EE. Please consult your module lecturer before using alternatives.", "pages": [13], "end_pos": 1520, "summary": "Permits alternative IDEs with instructor approval.", "start_pos": 1381, "chunk_type": "note", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}], "concepts": [{"id": "CONC_001", "title": "NetBeans IDE", "aliases": ["Apache NetBeans"], "keywords": ["IDE", "Java", "development", "debugging", "NetBeans"], "confidence": 1.0, "difficulty": 2, "description": "An integrated development environment (IDE) primarily used for Java application development. NetBeans provides tools for coding, debugging, testing, and deploying applications. It supports various project types including Java with Maven, Gradle, and Ant. In this context, it is used for developing Jakarta EE web applications with built-in support for GlassFish Server and Maven-based project templates.", "concept_type": "component", "extracted_from": ["CHUNK_001", "CHUNK_004"], "related_concepts": ["CONC_002", "CONC_007", "CONC_008"]}, {"id": "CONC_002", "title": "JDK 17", "aliases": ["Java Development Kit 17"], "keywords": ["JDK", "Java", "development kit", "version 17", "LTS"], "confidence": 1.0, "difficulty": 3, "description": "Java Development Kit version 17, a long-term support (LTS) release of the Java platform required to run and develop Java applications. JDK includes the Java Runtime Environment (JRE), compilers, and tools necessary for Java development. NetBeans IDE 24 specifically requires JDK 17, not the JRE, to function correctly. It is freely usable in production under Oracle''s No-Fee Terms and Conditions until September 2024.", "concept_type": "component", "extracted_from": ["CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_001", "CONC_009"]}, {"id": "CONC_003", "title": "XAMPP", "aliases": [], "keywords": ["XAMPP", "local server", "MySQL", "Apache", "phpMyAdmin"], "confidence": 1.0, "difficulty": 2, "description": "A cross-platform local server environment that bundles Apache, MySQL, PHP, and Perl. XAMPP simplifies the setup of a local web server for development purposes. It includes phpMyAdmin for managing MySQL databases through a graphical interface. In this module, XAMPP''s MySQL server is used for JDBC connections from Java EE or Jakarta EE applications developed in NetBeans.", "concept_type": "architecture", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_004", "CONC_005"]}, {"id": "CONC_004", "title": "MAMP", "aliases": [], "keywords": ["MAMP", "Mac", "server", "MySQL", "PHP"], "confidence": 1.0, "difficulty": 2, "description": "A local server solution for macOS and Windows that includes Apache, MySQL, and PHP. Similar to XAMPP, MAMP allows developers to create a local server environment for testing dynamic websites. It provides a control panel to start/stop servers and includes phpMyAdmin for database management. Used in this course as an alternative to XAMPP for hosting MySQL server for JDBC connectivity.", "concept_type": "architecture", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_003", "CONC_005"]}, {"id": "CONC_005", "title": "phpMyAdmin", "aliases": [], "keywords": ["phpMyAdmin", "database", "GUI", "MySQL", "management"], "confidence": 1.0, "difficulty": 2, "description": "A free and open-source web-based tool written in PHP for managing MySQL and MariaDB databases. It provides a graphical user interface to perform common database operations such as creating, modifying, and deleting databases, tables, fields, and rows. Accessible via localhost after starting XAMPP or MAMP, it is used here to manage the MySQL instance for backend storage in Java web applications.", "concept_type": "component", "extracted_from": ["CHUNK_006", "CHUNK_008"], "related_concepts": ["CONC_003", "CONC_004"]}, {"id": "CONC_006", "title": "GlassFish Server", "aliases": ["GlassFish Server 7.0"], "keywords": ["GlassFish", "application server", "Jakarta EE", "Java EE", "server"], "confidence": 1.0, "difficulty": 3, "description": "An open-source application server for the Jakarta EE (formerly Java EE) platform. GlassFish Server 7.0.0 is integrated with NetBeans IDE to deploy and run web applications during development. It acts as a runtime environment that supports servlets, JSP, EJB, and other Jakarta EE specifications. The IDE can automatically download and configure GlassFish when setting up a new web project.", "concept_type": "component", "extracted_from": ["CHUNK_005", "CHUNK_009"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_007", "title": "Jakarta EE 10 Web", "aliases": ["Jakarta Enterprise Edition"], "keywords": ["Jakarta EE", "Java EE", "web application", "specification", "enterprise"], "confidence": 1.0, "difficulty": 4, "description": "The rebranded successor to Java EE, Jakarta EE 10 Web is a platform specification for building enterprise-grade web applications in Java. It includes technologies such as Servlets, JSP, JSF, and RESTful web services. When creating a new web project in NetBeans, selecting Jakarta EE 10 Web ensures compatibility with modern Java web standards and enables features like annotation-based servlet configuration.", "concept_type": "architecture", "extracted_from": ["CHUNK_005", "CHUNK_010"], "related_concepts": ["CONC_006", "CONC_001"]}, {"id": "CONC_008", "title": "Web Application Project", "aliases": ["Java Web Application"], "keywords": ["web application", "project", "Maven", "NetBeans", "template"], "confidence": 1.0, "difficulty": 3, "description": "A type of software project in NetBeans IDE designed for developing dynamic websites using Java technologies. Created using the ''Java with Maven > Web Application'' template, it includes standard directory structure, build scripts, and deployment descriptors. The project integrates with GlassFish Server and supports servlet development, enabling rapid creation and testing of web components.", "concept_type": "object", "extracted_from": ["CHUNK_004", "CHUNK_010"], "related_concepts": ["CONC_001", "CONC_006"]}, {"id": "CONC_009", "title": "Servlet", "aliases": ["Java Servlet"], "keywords": ["servlet", "Java", "HTTP", "web", "dynamic content"], "confidence": 1.0, "difficulty": 4, "description": "A Java class that extends the capabilities of servers hosting web applications. Servlets respond to incoming HTTP requests and generate dynamic content. In NetBeans, a servlet is created within a package and registered either via annotations or web.xml. It typically overrides methods like doGet() or doPost() to handle specific request types and writes output using PrintWriter.", "concept_type": "object", "extracted_from": ["CHUNK_011", "CHUNK_012"], "related_concepts": ["CONC_008", "CONC_007"]}, {"id": "CONC_010", "title": "Alternative IDEs", "aliases": ["Alternate IDEs"], "keywords": ["IDE", "IntelliJ", "Eclipse", "alternative", "development"], "confidence": 1.0, "difficulty": 2, "description": "Other integrated development environments that can be used for Java EE/Jakarta EE development besides NetBeans. These include IntelliJ IDEA Ultimate (offering student licenses) and Eclipse for Java EE developers. While permitted, their use requires prior consultation with the module lecturer due to potential differences in configuration and tooling support.", "concept_type": "component", "extracted_from": ["CHUNK_013"