INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( 'Lecture 2 Basic ABAP.pptx', 'e136cf79e52a8786b9369e845eafcc8d4b6cfaa5492f5d0e9ef723a36812c984', '{"chunks": [{"id": "CHUNK_001", "text": "At the end of this topic, you will be able to:\nperform some common daily operations of major modules of an ERP system;\ncustomise an ERP system using an appropriate programming environment; and\ndevelop programs to support the integration of business transactions among business partners in the supply chain.\n\nAt the end of this topic, you will be able to:\ndeclare data object in ABAP programing\nwrite output in ABAP report\ndevelop ABAP program with predefined functions and control blocks", "pages": [1], "end_pos": 428, "summary": "Introduces high-level learning outcomes covering ERP operations, ABAP customization, and program development with focus on data declaration, output, and control structures.", "start_pos": 0, "chunk_type": "learning_objective", "has_examples": false, "main_concepts": ["CONC_007", "CONC_012", "CONC_016"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_002", "text": "The first word of a statement which determines the use of the entire statement\nTypes of Keywords\nDeclarative keywords\nDefines data type or declare data object\nExample - TYPES, DATA, TABLES\nModularization keywords\nDefines the processing block in an ABAP program\nThe modularization keywords can be further divided into: \nEvent Keyword\nExample - AT SELECTION SCREEN, START-OF-SELECTION,  AT USER-COMMAND\nDefining Keyword\nExample - FORM ..... ENDFORM, FUNCTION ..... ENDFUNCTION, MODULE ..... ENDMODULE", "pages": [2], "end_pos": 962, "summary": "Defines ABAP keywords and classifies them into declarative (e.g., DATA, TYPES) and modularization types (event and defining keywords).", "start_pos": 429, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_001", "CONC_002", "CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Control keywords\nControls the flow of an ABAP program within a processing block\nExample - IF, WHILE, DO, FOR, CASE\nCalling keywords\nCalls processing blocks that you have already defined\nExample - PERFORM, CALL, SET USER-COMMAND, SUBMIT, LEAVE TO\nOperational keywords\nProcesses the data that you have defined using declarative statements\nExample - WRITE, MOVE, ADD", "pages": [3], "end_pos": 1412, "summary": "Classifies ABAP keywords into control (IF, WHILE), calling (PERFORM, CALL), and operational (WRITE, MOVE) categories with examples.", "start_pos": 963, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_004", "CONC_005", "CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Declare data object\n* Syntax\nDATA  var[(length)]  [TYPE type | LIKE  Table-Field]  \n\t\t\t\t\t\t[Decimals number] [VALUE  initial value].\n\nDATA: tmp(20) TYPE c, tmp2 TYPE i, tmp3(8) TYPE p DECIMALS 2 VALUE ''2.50'', tmp4 TYPE n, tmp5 TYPE a,\nDATA vendorno TYPE char10, DATA custemerno LIKE vendorno, DATA maar LIKE mara-matnr.", "pages": [4], "end_pos": 1854, "summary": "Presents syntax and concrete examples for DATA statement, showing type specification (TYPE), dictionary reference (LIKE), and initialization (VALUE).", "start_pos": 1413, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_002", "CONC_009"]}, {"id": "CHUNK_005", "text": "Describes the technical attributes of all the objects with that type\nThere are three categories of types\nPredefined standard\nLocal\nGlobal\n\nTypes only exist in the program and hence can only be used there\nTo define your own local data type, use the TYPES statement\nExample:\n\tTYPES fnumber TYPE I.\n\tDATA flightANum TYPE fnumber.\n\nDefined in the ABAP Dictionary\nCan be used throughout the entire system\nExamples:\n\nmara is a table\nmatnr is a field in table mara", "pages": [5], "end_pos": 2392, "summary": "Explains ABAP type categories (predefined, local, global) and distinguishes local (TYPES) vs global (ABAP Dictionary) type definitions with examples.", "start_pos": 1855, "chunk_type": "definition", "has_examples": true, "main_concepts": ["CONC_008", "CONC_009"], "has_definitions": true, "secondary_concepts": ["CONC_002", "CONC_007"]}, {"id": "CHUNK_006", "text": "Texts which are written between the statements to explain the purpose\nComment is flagged by special characters which causes system to ignore them\nABAP comments:\nAn asterisk (*) in column 1 flags the whole line as a comment\nA quotation mark (\") within a line flags the remainder of the line as a comment\n\nReport Z99R_01_HELLOWORLD Active REPORT zS9r_0i_helloworld.\n* Print Hello World on screen\nWRITE: ''Hello World!'', ''Hello again.''. \" Print once more", "pages": [6], "end_pos": 2814, "summary": "Defines ABAP comment syntax (line-start * and inline \") and shows commented code in a working report example.", "start_pos": 2393, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "You can concatenate several consecutive statements with an identical first part into a chain statement\nWhen doing this, conclude the identical first part with a colon (:)\nAfter the colon, separate each concatenated part from the next with a comma (,)\n\nWRITE: ''XYZ'', NAME, COUNTER.\nADD 1 TO: COUNTER1, COUNTER2, COUNTER3.", "pages": [7], "end_pos": 3126, "summary": "Explains chain statement syntax (colon + comma-separated items) and demonstrates with WRITE and ADD examples.", "start_pos": 2815, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_011"], "has_definitions": true, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_008", "text": "WRITE statement outputs the contents of a field or constant in the format appropriate for the type\n\nReport Z99R_01_HELLOWORLD. REPORT z99r_01_helloworld.\n* Print Hello World on screen\nWRITE: ''Hello World!'', ''Hello again.''. \" Print once more\nSKIP.\nWRITE: ''You are'', sy-uname.", "pages": [8], "end_pos": 3464, "summary": "Defines WRITE functionality and shows multi-part output, SKIP, and system field usage in a complete report snippet.", "start_pos": 3127, "chunk_type": "definition_and_example", "has_examples": true, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": ["CONC_014"]}, {"id": "CHUNK_009", "text": "Consecutive WRITE statements output data on the same line separated with one space\n\tWRITE ''Hello''.\n\tWRITE ''World''.\nIf there is no more space on one line, the output continues on the next line\nSlash (/) in the WRITE statement will start the output on a new line\n\tWRITE ''Hello''.\n\tWRITE / ''World''.\n\n* Syntax\nWRITE <f> <AT position(length)>\n                    <OPTION>\n\t           <AS CHECKBOX>\n\t                         <AS SYMBOL>\n\t           <AS ICON>\n\t           <AS LINE>", "pages": [9], "end_pos": 3924, "summary": "Details WRITE behavior (spacing, line breaks) and presents full syntax with formatting options like AT, AS, and OPTIONS.", "start_pos": 3465, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_012"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "Constant declaration\n* Syntax\nCONSTANTS const [TYPE type] VALUE  initial value.\n\nCONSTANTS ctext(11) TYPE c VALUE ''Hello World'' CONSTANTS max_no TYPE i VALUE 999. counter TYPE i VALUE max_no.\n\n* Constant variable\nCONSTANTS etext(22) TYPE c VALUE ''Hello World''.\nCONSTANTS max_no TYPE i VALUE 999,\nDATA counter TYPE i VALUE max_no.", "pages": [10], "end_pos": 4324, "summary": "Presents CONSTANTS syntax and shows declaration with type/length and initialization, including usage in DATA initialization.", "start_pos": 3925, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_013"], "has_definitions": true, "secondary_concepts": ["CONC_007"]}, {"id": "CHUNK_011", "text": "| Name | Type | Length | Meaning |\n| --- | --- | --- | --- |\n| SY-DATUM | DATS | 8 | Current Date of Application Server |\n| SY-UZEIT | TIMS | 6 | Current Time of Application Server |\n| SY-UNAME | CHAR | 12 | User Name |\n| SY-SUBRC | INT4 | 10 | Return Value of ABAP Statements |\n| SY-CPROG | CHAR | 40 | Calling Program |\n| SY-TCODE | CHAR | 20 | Current Transaction Code |\n| SY-LANGU | LANG | 1 | Language Key of Current Text Environment |", "pages": [11], "end_pos": 4708, "summary": "Tabular reference of key ABAP system fields with their data types, lengths, and semantic meanings.", "start_pos": 4325, "chunk_type": "reference_table", "has_examples": false, "main_concepts": ["CONC_014"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_012", "text": "To write a high-quality program, you should keep certain layout standards for ABAP Program\nFollow when structuring your program flow, and use as many as informative comments as possible\nIf you follow these suggestions your program will be\nMore readable\nEasier to test and change\nMore reliable\n\nTo improve the quality of your programs, use the following techniques: \nIndenting statement block\nCombine statements that belong together into a single block \nIndent each block by at least two columns\nUsing modularization tool\nWrite larger processing blocks as subroutines, the logical structure of the program becomes easier to identify\nIt also allows you to sort the subroutines according to the tasks they perform\nInserting program comment\nAvoid placing comments on statement line\nPlace comment on separate line to improve the readability of the program\nInsert subroutine heading and comment in your program by using the ready-made structures available in ABAP Editor", "pages": [12], "end_pos": 5504, "summary": "Outlines ABAP layout standards emphasizing indentation, modularization, and comment discipline to enhance program quality metrics.", "start_pos": 4709, "chunk_type": "guideline", "has_examples": false, "main_concepts": ["CONC_015"], "has_definitions": true, "secondary_concepts": ["CONC_003", "CONC_010"]}, {"id": "CHUNK_013", "text": "ABAP provides a set of predefined functions\nReturns a return value for one or more arguments\nSyntax\nFunction with an Unnamed Argument\n... func( arg ) ...\nFunction with Named Arguments \n... func( val = arg p1 = arg1 p2 = arg2 ... ) ...\n\nFunction categories include: Boolean (boolc), string predicates (contains), floating point (sqrt, round), numerical (abs, ceil), length (strlen), search (find), substring (substring), case (to_upper), and more.", "pages": [13], "end_pos": 5952, "summary": "Introduces ABAP built-in functions, syntax variants (named/unnamed args), and categorizes common function families.", "start_pos": 5505, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_016"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_014", "text": "Four Types of loop in ABAP:\nUnconditional loop using the DO statement\nConditional loop using the WHILE statement\nLoops through internal table and extract dataset using the LOOP statement (will be introduced in other chapter)\nLoops through datasets from database table using SELECT statement (will be introduced in other chapter)\n\nExample\nDO 3 TIMES.\n  WRITE /(2) SY-INDEX.\n  WRITE ''Hello''.\nENDDO.\n\nDATA cnt TYPE i VALUE 3.\nWHILE cnt >= 1.\n  WRITE /(2) SY-INDEX.\n  WRITE ''Hello''.\n  cnt = cnt - 1.\nENDWHILE.\n\nBypass the following statements in a loop and go to next iteration\nExample:\nDATA rem TYPE i.\nDO 20 TIMES.\n  rem = SY-INDEX MOD 5.\n  IF rem EQ 0.\n    CONTINUE.\n  ENDIF.\n  WRITE (2) SY-INDEX.\nENDDO.\n\nBypass the following statements in a loop and go to next iteration if the condition return FALSE\nExample:\nDATA rem TYPE i.\nDO 20 TIMES.\n  rem = SY-INDEX MOD 5.\n  CHECK rem EQ 0.\n  WRITE (2) SY-INDEX.\nENDDO.\n\nTerminate a loop or subroutine\nExample:\nDATA rem TYPE i.\nDO 20 TIMES.\n  rem = SY-INDEX MOD 5.\n  IF rem EQ 0.\n    EXIT.\n  ENDIF.\n  WRITE (2) SY-INDEX.\nENDDO.", "pages": [14], "end_pos": 7221, "summary": "Documents all four ABAP loop types, with emphasis on DO/WHILE syntax, and demonstrates CONTINUE, CHECK, and EXIT loop control.", "start_pos": 5953, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_017"], "has_definitions": true, "secondary_concepts": ["CONC_004", "CONC_019"]}, {"id": "CHUNK_015", "text": "Example\nDATA mark TYPE i VALUE 50.\nIF mark <= 40.\n  WRITE ''F''.\nELSEIF mark <= 60.\n  WRITE ''B''.\nELSE.\n  WRITE ''A''.\nENDIF.\n\nExample:\nDATA grade TYPE c VALUE ''A''.\nCASE grade.\n  WHEN ''A''.\n    WRITE ''Excellent''.\n  WHEN ''B''.\n    WRITE ''Good''.\n  WHEN OTHERS.\n    WRITE ''Bad''.\nENDCASE.\n\n| Operators | Operations |\n| --- | --- |\n| EQ = | Equal to |\n| NE <> >< | Not equal to |\n| GT > | Greater than |\n| GE >= => | Greater than or equal to |\n| LT < | Smaller than |\n| LE <= =< | Smaller than or equal to |\n| BETWEEN f1 and f2 | Interval |\n| IS INITIAL | Initial value |\n\nAND, OR, NOT\nExamples\n\nCOUNTER GT 0 AND FLAG IS INITIAL\n\n( FLAG1 NE SPACE OR FLAG2 NE SPACE ) \n\t\t\t\t\t\tAND COUNTER BETWEEN 0 AND 100\n\nCOUNTER EQ 0 AND NOT ( FLAG1 EQ SPACE AND FLAG2 EQ SPACE )", "pages": [15], "end_pos": 8220, "summary": "Shows IF-ELSEIF-ELSE and CASE-WHEN syntax, then tabulates relational operators (EQ, BETWEEN) and logical connectives (AND, OR, NOT) with usage examples.", "start_pos": 7222, "chunk_type": "syntax_and_example", "has_examples": true, "main_concepts": ["CONC_018", "CONC_019"], "has_definitions": true, "secondary_concepts": ["CONC_004", "CONC_012"]}], "concepts": [{"id": "CONC_001", "title": "ABAP Keyword", "aliases": ["ABAP reserved word"], "keywords": ["keyword", "ABAP statement", "syntax"], "confidence": 1.0, "difficulty": 3, "description": "An ABAP keyword is the first word of a statement that determines its syntactic category and semantic function. Keywords are classified into five types: declarative (e.g., DATA, TYPES), modularization (e.g., FORM, AT SELECTION SCREEN), control (e.g., IF, WHILE), calling (e.g., PERFORM, CALL), and operational (e.g., WRITE, MOVE). Each type governs distinct aspects of program structure, data handling, or execution flow. Proper keyword usage ensures correct parsing, maintainability, and adherence to SAP''s runtime semantics.", "concept_type": "object", "extracted_from": ["CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_002", "CONC_004", "CONC_005"]}, {"id": "CONC_002", "title": "Declarative Keyword", "aliases": ["data definition keyword"], "keywords": ["DATA", "TYPES", "TABLES", "declaration"], "confidence": 1.0, "difficulty": 2, "description": "A declarative keyword in ABAP defines data types or declares data objects. It establishes the technical attributes (type, length, decimals, initial value) of variables and types used throughout the program. Key examples include DATA (for variable declaration), TYPES (for local type definition), and TABLES (for dictionary table references). Declarative statements must precede any usage and form the foundational data layer upon which all other ABAP logic operates.", "concept_type": "object", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001", "CONC_006", "CONC_007"]}, {"id": "CONC_003", "title": "Modularization Keyword", "aliases": ["block definition keyword"], "keywords": ["FORM", "FUNCTION", "MODULE", "AT SELECTION SCREEN", "START-OF-SELECTION"], "confidence": 1.0, "difficulty": 3, "description": "A modularization keyword defines processing blocks that encapsulate reusable logic in ABAP programs. These fall into two subcategories: event keywords (e.g., START-OF-SELECTION, AT USER-COMMAND) that bind code to system-triggered events, and defining keywords (e.g., FORM...ENDFORM, FUNCTION...ENDFUNCTION, MODULE...ENDMODULE) that create named, callable units. Modularization improves readability, testability, and maintainability by separating concerns and enabling structured control flow.", "concept_type": "object", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001", "CONC_008", "CONC_009"]}, {"id": "CONC_004", "title": "Control Keyword", "aliases": ["flow control keyword"], "keywords": ["IF", "CASE", "DO", "WHILE", "LOOP"], "confidence": 1.0, "difficulty": 3, "description": "A control keyword governs the conditional or iterative flow of execution within an ABAP processing block. Examples include IF...ENDIF (branching), CASE...ENDCASE (multi-way selection), DO...ENDDO (unconditional loop), and WHILE...ENDWHILE (conditional loop). These keywords implement imperative logic constructs, allowing dynamic decision-making and repetition based on runtime conditions, and are essential for implementing business rules and algorithms.", "concept_type": "object", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_010", "CONC_011"]}, {"id": "CONC_005", "title": "Calling Keyword", "aliases": ["invocation keyword"], "keywords": ["PERFORM", "CALL", "SUBMIT", "LEAVE TO"], "confidence": 1.0, "difficulty": 3, "description": "A calling keyword invokes previously defined processing blocks or system services. Examples include PERFORM (to call a FORM routine), CALL (to invoke functions or screens), SUBMIT (to execute another report), LEAVE TO (to navigate between transactions), and SET USER-COMMAND (to trigger GUI events). These keywords enable program composition, inter-report communication, and integration with SAP GUI and application logic.", "concept_type": "object", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_003", "CONC_008"]}, {"id": "CONC_006", "title": "Operational Keyword", "aliases": ["data processing keyword"], "keywords": ["WRITE", "MOVE", "ADD", "SUBTRACT", "MULTIPLY", "DIVIDE"], "confidence": 1.0, "difficulty": 2, "description": "An operational keyword processes data declared via declarative statements. It performs actions such as output (WRITE), assignment (MOVE), arithmetic (ADD, SUBTRACT), or string manipulation. Unlike declarative or control keywords, operational keywords act directly on data values and memory locations, forming the ''executable'' core of ABAP programs. Their behavior depends on operand types and formatting options, making them central to user interaction and data transformation.", "concept_type": "object", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_002", "CONC_012"]}, {"id": "CONC_007", "title": "Data Object Declaration", "aliases": ["ABAP variable declaration"], "keywords": ["DATA", "declaration", "variable", "type"], "confidence": 1.0, "difficulty": 2, "description": "Data object declaration in ABAP assigns a name, type, length, and optional initial value to a variable using the DATA statement. Syntax supports fixed-length types (e.g., TYPE c LENGTH 20), dictionary references (e.g., LIKE mara-matnr), and numeric precision (e.g., TYPE p DECIMALS 2). Declarations must occur in the program''s declaration section and establish memory allocation and data semantics before use in operational statements.", "concept_type": "process", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_002", "CONC_008", "CONC_013"]}, {"id": "CONC_008", "title": "Local Data Type", "aliases": ["program-local type"], "keywords": ["TYPES", "local type", "program scope"], "confidence": 1.0, "difficulty": 3, "description": "A local data type is defined within an ABAP program using the TYPES statement and exists only in that program''s scope. It enables abstraction and reuse of complex type definitions (e.g., TYPES flight_num TYPE i). Local types support maintainability by decoupling data structure from implementation details and allow consistent typing across multiple DATA declarations. They differ from global types (defined in ABAP Dictionary) and predefined standard types.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_007", "CONC_014"]}, {"id": "CONC_009", "title": "Global Data Type", "aliases": ["dictionary type"], "keywords": ["ABAP Dictionary", "SE11", "MATNR", "LIKE", "TYPE"], "confidence": 1.0, "difficulty": 3, "description": "A global data type is defined in the ABAP Dictionary (transaction SE11) and is available system-wide for use in any ABAP program, database table, or interface. Examples include data elements like MATNR (material number) and domains like CHAR. Global types ensure consistency, enforce business semantics, and support centralized maintenance. They are referenced in programs via LIKE (for fields) or TYPE (for data elements) in DATA or TYPES statements.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_007", "CONC_014"]}, {"id": "CONC_010", "title": "ABAP Comment", "aliases": ["ABAP documentation"], "keywords": ["*", "\"", "comment", "documentation"], "confidence": 1.0, "difficulty": 1, "description": "An ABAP comment is non-executable text used to document code intent. It is ignored by the runtime system and flagged by either an asterisk (*) in column 1 (full-line comment) or a quotation mark (\") anywhere in a line (inline comment). Comments improve readability, support debugging, and aid long-term maintenance. Best practices recommend placing comments on separate lines rather than embedding them within executable statements.", "concept_type": "object", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_015"]}, {"id": "CONC_011", "title": "Chain Statement", "aliases": ["statement chaining"], "keywords": ["chain", "colon", "WRITE:", "concatenation"], "confidence": 1.0, "difficulty": 2, "description": "A chain statement concatenates multiple ABAP statements sharing the same initial keyword and colon (:) syntax. For example, ''WRITE: ''''XYZ'''', NAME, COUNTER.'' replaces three separate WRITE statements. Chaining reduces redundancy, improves compactness, and enhances readability when outputting related values. The colon terminates the common prefix, and comma-separated items follow, each interpreted as a continuation of the base statement.", "concept_type": "process", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_006", "CONC_012"]}, {"id": "CONC_012", "title": "WRITE Statement", "aliases": ["ABAP output statement"], "keywords": ["WRITE", "output", "formatting", "list display"], "confidence": 1.0, "difficulty": 2, "description": "The WRITE statement outputs data to the list screen in ABAP reports. It supports formatting options including position (AT pos), length (n), justification (LEFT-JUSTIFIED, CENTERED), alignment (UNDER), spacing (NO-GAP), and specialized display (CURRENCY, DECIMALS, UNIT). Consecutive WRITEs appear on the same line separated by spaces; a slash (/) forces a new line. WRITE is fundamental for user-facing output and debugging, with behavior dependent on data type, length, and modifiers.", "concept_type": "object", "extracted_from": ["CHUNK_008", "CHUNK_009"], "related_concepts": ["CONC_006", "CONC_011", "CONC_016"]}, {"id": "CONC_013", "title": "Constant Declaration", "aliases": ["ABAP constant"], "keywords": ["CONSTANTS", "immutable", "literal", "VALUE"], "confidence": 1.0, "difficulty": 2, "description": "Constant declaration in ABAP creates immutable named values using the CONSTANTS statement. Syntax specifies name, optional type, and mandatory VALUE clause (e.g., CONSTANTS ctext TYPE c VALUE ''Hello''). Constants improve code clarity and maintainability by replacing magic literals with meaningful identifiers. They are evaluated at compile time and cannot be reassigned, ensuring data integrity and simplifying refactoring across large codebases.", "concept_type": "process", "extracted_from": ["CHUNK_010"], "related_concepts": ["CONC_002", "CONC_007"]}, {"id": "CONC_014", "title": "ABAP System Fields", "aliases": ["sy-field"], "keywords": ["SY-DATUM", "SY-UNAME", "SY-SUBRC", "system field"], "confidence": 1.0, "difficulty": 2, "description": "ABAP system fields are predefined global variables (prefixed with SY-) that provide contextual runtime information such as current date (SY-DATUM), time (SY-UZEIT), user name (SY-UNAME), return code (SY-SUBRC), transaction code (SY-TCODE), and language key (SY-LANGU). They are read-only and automatically populated by the system, enabling dynamic behavior based on environment state without explicit initialization.", "concept_type": "object", "extracted_from": ["CHUNK_011"], "related_concepts": ["CONC_007", "CONC_012"]}, {"id": "CONC_015", "title": "ABAP Layout Standard", "aliases": ["ABAP best practice"], "keywords": ["indentation", "modularization", "comment placement", "layout"], "confidence": 1.0, "difficulty": 2, "description": "ABAP layout standards are coding conventions promoting readability, testability, and reliability. Key techniques include indentation (≥2 columns per block), modularization (subroutines for logical separation), and dedicated comment placement (separate lines, subroutine headers). Adhering to these standards reduces cognitive load, accelerates peer review, and minimizes regression risk during enhancements — aligning with SAP’s recommended development practices.", "concept_type": "process", "extracted_from": ["CHUNK_012"], "related_concepts": ["CONC_003", "CONC_010", "CONC_016"]}, {"id": "CONC_016", "title": "ABAP Built-in Function", "aliases": ["ABAP intrinsic function"], "keywords": ["function", "built-in", "SQRT", "FIND", "TO_UPPER"], "confidence": 1.0, "difficulty": 3, "description": "An ABAP built-in function is a predeclared routine that accepts arguments and returns a value, supporting operations across domains like mathematics (SQRT, ROUND), strings (FIND, REPLACE), dates (CONVERT_DATE_TO_INTERNAL), and conversions (TO_UPPER). Functions can be invoked with unnamed arguments (func(arg)) or named arguments (func(val = arg)). They abstract low-level logic, reduce boilerplate, and ensure consistent, optimized execution across ABAP applications.", "concept_type": "object", "extracted_from": ["CHUNK_013"], "related_concepts": ["CONC_006", "CONC_012", "CONC_017"]}, {"id": "CONC_017", "title": "ABAP Loop Statement", "aliases": ["ABAP iteration"], "keywords": ["DO", "WHILE", "LOOP", "SELECT", "CONTINUE", "CHECK", "EXIT"], "confidence": 1.0, "difficulty": 3, "description": "ABAP loop statements implement iterative execution: DO (unconditional, with TIMES or WHILE), WHILE (conditional), LOOP (internal tables), and SELECT (database access). DO and WHILE are foundational for algorithmic repetition, supporting CONTINUE (skip iteration), CHECK (conditional skip), and EXIT (terminate loop). Loops must be carefully scoped to avoid infinite execution and are often paired with SY-INDEX for iteration tracking.", "concept_type": "process", "extracted_from": ["CHUNK_014"], "related_concepts": ["CONC_004", "CONC_011", "CONC_018"]}, {"id": "CONC_018", "title": "ABAP Conditional Statement", "aliases": ["ABAP branching"], "keywords": ["IF", "CASE", "EQ", "BETWEEN", "AND", "OR"], "confidence": 1.0, "difficulty": 3, "description": "ABAP conditional statements evaluate Boolean expressions to control program flow. IF...ELSEIF...ELSE...ENDIF supports multi-branch logic with arbitrary nesting depth. CASE...WHEN...ENDCASE provides efficient multi-value dispatch for discrete values or ranges (WHEN OTHERS). Both require proper termination and rely on relational operators (EQ, NE, GT, BETWEEN) and logical connectives (AND, OR, NOT) to express business rules precisely.", "concept_type": "process", "extracted_from": ["CHUNK_015"], "related_concepts": ["CONC_004", "CONC_017", "CONC_019"]}, {"id": "CONC_019", "title": "ABAP Relational Operator", "aliases": ["comparison operator"], "keywords": ["EQ", "NE", "BETWEEN", "CO", "CA", "CS", "CP"], "confidence": 1.0, "difficulty": 3, "description": "ABAP relational operators compare values and return Boolean results. They include equality (EQ, =), inequality (NE, <>), ordering (GT, LT, GE, LE), interval checks (BETWEEN), and character/string predicates (CO, CA, CS, CP). String operators support pattern matching (* for wildcard, + for single char), containment, and case-insensitive comparisons. These operators are used exclusively in conditional contexts (IF, CASE, CHECK) and define decision boundaries in business logic.", "concept_type": "object", "extracted_from": ["CHUNK_015"], "related_concepts": ["CONC_004", "CONC_018"]}], "relationships": [{"id": "REL_001", "type": "example_of", "source": "CONC_001", "target": "CONC_002", "evidence": "Declarative keywords (e.g., DATA, TYPES) are explicitly listed as a subtype of ABAP keyword.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "example_of", "source": "CONC_001", "target": "CONC_003", "evidence": "Modularization keywords (e.g., FORM, AT SELECTION SCREEN) are explicitly listed as a subtype of ABAP keyword.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "example_of", "source": "CONC_001", "target": "CONC_004", "evidence": "Control keywords (e.g., IF, WHILE) are explicitly listed as a subtype of ABAP keyword.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "example_of", "source": "CONC_001", "target": "CONC_005", "evidence": "Calling keywords (e.g., PERFORM, CALL) are explicitly listed as a subtype of ABAP keyword.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "example_of", "source": "CONC_001", "target": "CONC_006", "evidence": "Operational keywords (e.g., WRITE, MOVE) are explicitly listed as a subtype of ABAP keyword.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "implements", "source": "CONC_002", "target": "CONC_007", "evidence": "DATA is the primary declarative keyword used to declare data objects.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "implements", "source": "CONC_002", "target": "CONC_008", "evidence": "TYPES is the declarative keyword used to define local data types.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "requires", "source": "CONC_003", "target": "CONC_008", "evidence": "FORM routines may use locally defined types (via TYPES) for parameter typing.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "requires", "source": "CONC_003", "target": "CONC_009", "evidence": "FORM parameters or internal tables often reference global dictionary types (e.g., LIKE mara-matnr).", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "part_of", "source": "CONC_004", "target": "CONC_017", "evidence": "DO and WHILE are classified as control keywords and also constitute loop constructs.", "strength": 1.0, "bidirectional": false}, {"id": "REL_011", "type": "part_of", "source": "CONC_004", "target": "CONC_018", "evidence": "IF and CASE are classified as control keywords and constitute conditional constructs.", "strength": 1.0, "bidirectional": false}, {"id": "REL_012", "type": "calls", "source": "CONC_005", "target": "CONC_003", "evidence": "PERFORM calls FORM routines; CALL invokes FUNCTION modules.", "strength": 1.0, "bidirectional": false}, {"id": "REL_013", "type": "implements", "source": "CONC_006", "target": "CONC_012", "evidence": "WRITE is the primary operational keyword for output.", "strength": 1.0, "bidirectional": false}, {"id": "REL_014", "type": "requires", "source": "CONC_007", "target": "CONC_008", "evidence": "DATA declarations may reference local types defined via TYPES.", "strength": 1.0, "bidirectional": false}, {"id": "REL_015", "type": "requires", "source": "CONC_007", "target": "CONC_009", "evidence": "DATA declarations may reference global types via LIKE or TYPE.", "strength": 1.0, "bidirectional": false}, {"id": "REL_016", "type": "opposite_of", "source": "CONC_008", "target": "CONC_009", "evidence": "Local types exist only in one program; global types exist system-wide.", "strength": 1.0, "bidirectional": true}, {"id": "REL_017", "type": "supports", "source": "CONC_010", "target": "CONC_015", "evidence": "Comments are a core component of ABAP layout standards.", "strength": 1.0, "bidirectional": false}, {"id": "REL_018", "type": "specializes", "source": "CONC_011", "target": "CONC_012", "evidence": "Chain statements are a syntactic variation of the WRITE statement.", "strength": 1.0, "bidirectional": false}, {"id": "REL_019", "type": "uses", "source": "CONC_012", "target": "CONC_014", "evidence": "WRITE statements commonly output system fields (e.g., WRITE sy-uname).", "strength": 1.0, "bidirectional": false}, {"id": "REL_020", "type": "similar_to", "source": "CONC_013", "target": "CONC_002", "evidence": "CONSTANTS and DATA are both declarative statements with analogous syntax.", "strength": 1.0, "bidirectional": true}, {"id": "REL_021", "type": "extends", "source": "CONC_016", "target": "CONC_006", "evidence": "Functions (e.g., abs(), to_upper()) are often used in operational contexts like WRITE or MOVE.", "strength": 1.0, "bidirectional": false}, {"id": "REL_022", "type": "contrasts_with", "source": "CONC_017", "target": "CONC_018", "evidence": "Loops (iterative) and conditionals (branching) represent distinct control flow paradigms.", "strength": 1.0, "bidirectional": true}, {"id": "REL_023", "type": "uses", "source": "CONC_018", "target": "CONC_019", "evidence": "IF and CASE statements depend on relational operators to evaluate conditions.", "strength": 1.0, "bidirectional": false}, {"id": "REL_024", "type": "supports", "source": "CONC_019", "target": "CONC_004", "evidence": "Relational operators are used exclusively within control keywords (IF, CASE, CHECK).", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 15, "missing_links": [], "coverage_score": 1.0, "total_concepts": 19, "consistency_score": 1.0, "total_relationships": 24}, "document_metadata": {"title": "ABAP Programming Fundamentals for ERP Customization", "language": "English", "main_topic": "ABAP Syntax, Data Declaration, and Control Structures", "difficulty_level": "Intermediate", "estimated_reading_time": "25 minutes"}, "concept_chunk_mapping": [{"concept": "ABAP Keyword", "context": "First sentence defines keyword as ''the first word of a statement which determines the use of the entire statement''", "chunk_id": "CHUNK_002", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Declarative Keyword", "context": "Section titled ''Declarative keywords'' with definition and examples TYPES, DATA, TABLES", "chunk_id": "CHUNK_002", "positions": [82], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Modularization Keyword", "context": "Section titled ''Modularization keywords'' with definition and subcategories", "chunk_id": "CHUNK_002", "positions": [158], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Control Keyword", "context": "Section titled ''Control keywords'' with definition and examples IF, WHILE, DO, CASE", "chunk_id": "CHUNK_003", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Calling Keyword", "context": "Section titled ''Calling keywords'' with definition and examples PERFORM, CALL, SUBMIT", "chunk_id": "CHUNK_003", "positions": [134], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Operational Keyword", "context": "Section titled ''Operational keywords'' with definition and examples WRITE, MOVE, ADD", "chunk_id": "CHUNK_003", "positions": [265], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Data Object Declaration", "context": "Header ''Declare data object'' followed by syntax and multiple DATA examples", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Local Data Type", "context": "Section ''Types only exist in the program...'' with TYPES example", "chunk_id": "CHUNK_005", "positions": [162], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "Global Data Type", "context": "Section ''Defined in the ABAP Dictionary'' with mara/matnr example", "chunk_id": "CHUNK_005", "positions": [275], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "ABAP Comment", "context": "Header ''Texts which are written between the statements...'' and syntax rules for * and \"", "chunk_id": "CHUNK_006", "positions": [0], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Chain Statement", "context": "Header ''You can concatenate several consecutive statements...'' and colon/comma syntax", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "WRITE Statement", "context": "Header ''WRITE statement outputs the contents...'' and report example with WRITE/SKIP", "chunk_id": "CHUNK_008", "positions": [0], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Constant Declaration", "context": "Header ''Constant declaration'' followed by CONSTANTS syntax and examples", "chunk_id": "CHUNK_010", "positions": [0], "concept_id": "CONC_013", "importance": "primary"}, {"concept": "ABAP System Fields", "context": "Table header and rows listing SY-DATUM, SY-UNAME, etc. with meanings", "chunk_id": "CHUNK_011", "positions": [0], "concept_id": "CONC_014", "importance": "primary"}, {"concept": "ABAP Layout Standard", "context": "Header ''To write a high-quality program...'' and bullet points on indentation, modularization, comments", "chunk_id": "CHUNK_012", "positions": [0], "concept_id": "CONC_015", "importance": "primary"}, {"concept": "ABAP Built-in Function", "context": "Header ''ABAP provides a set of predefined functions'' and syntax/function category descriptions", "chunk_id": "CHUNK_013", "positions": [0], "concept_id": "CONC_016", "importance": "primary"}, {"concept": "ABAP Loop Statement", "context": "Header ''Four Types of loop in ABAP:'' and subsequent DO/WHILE/CONTINUE/CHECK/EXIT examples", "chunk_id": "CHUNK_014", "positions": [0], "concept_id": "CONC_017", "importance": "primary"}, {"concept": "ABAP Conditional Statement", "context": "First two code blocks showing IF-ELSEIF-ELSE and CASE-WHEN syntax", "chunk_id": "CHUNK_015", "positions": [0], "concept_id": "CONC_018", "importance": "primary"}, {"concept": "ABAP Relational Operator", "context": "Table titled ''| Operators | Operations |'' listing EQ, NE, BETWEEN, IS INITIAL and logical connectives", "chunk_id": "CHUNK_015", "positions": [425], "concept_id": "CONC_019", "importance": "primary"}]}', '{"total_modules": 6, "total_concepts": 42, "difficulty_score": 7, "total_structures": 18, "total_applications": 26}', '"[{\"id\":\"CHUNK_001\",\"text\":\"At the end of this topic, you will be able to:\\nperform some common daily operations of major modules of an ERP system;\\ncustomise an ERP system using an appropriate programming environment; and\\ndevelop programs to support the integration of business transactions among business partners in the supply chain.\\n\\nAt the end of this topic, you will be able to:\\ndeclare data object in ABAP programing\\nwrite output in ABAP report\\ndevelop ABAP program with predefined functions and control blocks\",\"pages\":[1],\"start_pos\":0,\"end_pos\":428,\"summary\":\"Introduces high-level learning outcomes covering ERP operations, ABAP customization, and program development with focus on data declaration, output, and control structures.\",\"chunk_type\":\"learning_objective\",\"has_examples\":false,\"main_concepts\":[\"CONC_007\",\"CONC_012\",\"CONC_016\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_002\",\"text\":\"The first word of a statement which determines the use of the entire statement\\nTypes of Keywords\\nDeclarative keywords\\nDefines data type or declare data object\\nExample - TYPES, DATA, TABLES\\nModularization keywords\\nDefines the processing block in an ABAP program\\nThe modularization keywords can be further divided into: \\nEvent Keyword\\nExample - AT SELECTION SCREEN, START-OF-SELECTION,  AT USER-COMMAND\\nDefining Keyword\\nExample - FORM ..... ENDFORM, FUNCTION ..... ENDFUNCTION, MODULE ..... ENDMODULE\",\"pages\":[2],\"start_pos\":429,\"end_pos\":962,\"summary\":\"Defines ABAP keywords and classifies them into declarative (e.g., DATA, TYPES) and modularization types (event and defining keywords).\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"Control keywords\\nControls the flow of an ABAP program within a processing block\\nExample - IF, WHILE, DO, FOR, CASE\\nCalling keywords\\nCalls processing blocks that you have already defined\\nExample - PERFORM, CALL, SET USER-COMMAND, SUBMIT, LEAVE TO\\nOperational keywords\\nProcesses the data that you have defined using declarative statements\\nExample - WRITE, MOVE, ADD\",\"pages\":[3],\"start_pos\":963,\"end_pos\":1412,\"summary\":\"Classifies ABAP keywords into control (IF, WHILE), calling (PERFORM, CALL), and operational (WRITE, MOVE) categories with examples.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_004\",\"CONC_005\",\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Declare data object\\n* Syntax\\nDATA  var[(length)]  [TYPE type | LIKE  Table-Field]  \\n\\t\\t\\t\\t\\t\\t[Decimals number] [VALUE  initial value].\\n\\nDATA: tmp(20) TYPE c, tmp2 TYPE i, tmp3(8) TYPE p DECIMALS 2 VALUE ''2.50'', tmp4 TYPE n, tmp5 TYPE a,\\nDATA vendorno TYPE char10, DATA custemerno LIKE vendorno, DATA maar LIKE mara-matnr.\",\"pages\":[4],\"start_pos\":1413,\"end_pos\":1854,\"summary\":\"Presents syntax and concrete examples for DATA statement, showing type specification (TYPE), dictionary reference (LIKE), and initialization (VALUE).\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\",\"CONC_009\"]},{\"id\":\"CHUNK_005\",\"text\":\"Describes the technical attributes of all the objects with that type\\nThere are three categories of types\\nPredefined standard\\nLocal\\nGlobal\\n\\nTypes only exist in the program and hence can only be used there\\nTo define your own local data type, use the TYPES statement\\nExample:\\n\\tTYPES fnumber TYPE I.\\n\\tDATA flightANum TYPE fnumber.\\n\\nDefined in the ABAP Dictionary\\nCan be used throughout the entire system\\nExamples:\\n\\nmara is a table\\nmatnr is a field in table mara\",\"pages\":[5],\"start_pos\":1855,\"end_pos\":2392,\"summary\":\"Explains ABAP type categories (predefined, local, global) and distinguishes local (TYPES) vs global (ABAP Dictionary) type definitions with examples.\",\"chunk_type\":\"definition\",\"has_examples\":true,\"main_concepts\":[\"CONC_008\",\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_002\",\"CONC_007\"]},{\"id\":\"CHUNK_006\",\"text\":\"Texts which are written between the statements to explain the purpose\\nComment is flagged by special characters which causes system to ignore them\\nABAP comments:\\nAn asterisk (*) in column 1 flags the whole line as a comment\\nA quotation mark (\\\") within a line flags the remainder of the line as a comment\\n\\nReport Z99R_01_HELLOWORLD Active REPORT zS9r_0i_helloworld.\\n* Print Hello World on screen\\nWRITE: ''Hello World!'', ''Hello again.''. \\\" Print once more\",\"pages\":[6],\"start_pos\":2393,\"end_pos\":2814,\"summary\":\"Defines ABAP comment syntax (line-start * and inline \\\") and shows commented code in a working report example.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_007\",\"text\":\"You can concatenate several consecutive statements with an identical first part into a chain statement\\nWhen doing this, conclude the identical first part with a colon (:)\\nAfter the colon, separate each concatenated part from the next with a comma (,)\\n\\nWRITE: ''XYZ'', NAME, COUNTER.\\nADD 1 TO: COUNTER1, COUNTER2, COUNTER3.\",\"pages\":[7],\"start_pos\":2815,\"end_pos\":3126,\"summary\":\"Explains chain statement syntax (colon + comma-separated items) and demonstrates with WRITE and ADD examples.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_011\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_008\",\"text\":\"WRITE statement outputs the contents of a field or constant in the format appropriate for the type\\n\\nReport Z99R_01_HELLOWORLD. REPORT z99r_01_helloworld.\\n* Print Hello World on screen\\nWRITE: ''Hello World!'', ''Hello again.''. \\\" Print once more\\nSKIP.\\nWRITE: ''You are'', sy-uname.\",\"pages\":[8],\"start_pos\":3127,\"end_pos\":3464,\"summary\":\"Defines WRITE functionality and shows multi-part output, SKIP, and system field usage in a complete report snippet.\",\"chunk_type\":\"definition_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_014\"]},{\"id\":\"CHUNK_009\",\"text\":\"Consecutive WRITE statements output data on the same line separated with one space\\n\\tWRITE ''Hello''.\\n\\tWRITE ''World''.\\nIf there is no more space on one line, the output continues on the next line\\nSlash (/) in the WRITE statement will start the output on a new line\\n\\tWRITE ''Hello''.\\n\\tWRITE / ''World''.\\n\\n* Syntax\\nWRITE <f> <AT position(length)>\\n                    <OPTION>\\n\\t           <AS CHECKBOX>\\n\\t                         <AS SYMBOL>\\n\\t           <AS ICON>\\n\\t           <AS LINE>\",\"pages\":[9],\"start_pos\":3465,\"end_pos\":3924,\"summary\":\"Details WRITE behavior (spacing, line breaks) and presents full syntax with formatting options like AT, AS, and OPTIONS.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_012\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_010\",\"text\":\"Constant declaration\\n* Syntax\\nCONSTANTS const [TYPE type] VALUE  initial value.\\n\\nCONSTANTS ctext(11) TYPE c VALUE ''Hello World'' CONSTANTS max_no TYPE i VALUE 999. counter TYPE i VALUE max_no.\\n\\n* Constant variable\\nCONSTANTS etext(22) TYPE c VALUE ''Hello World''.\\nCONSTANTS max_no TYPE i VALUE 999,\\nDATA counter TYPE i VALUE max_no.\",\"pages\":[10],\"start_pos\":3925,\"end_pos\":4324,\"summary\":\"Presents CONSTANTS syntax and shows declaration with type/length and initialization, including usage in DATA initialization.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_013\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_007\"]},{\"id\":\"CHUNK_011\",\"text\":\"| Name | Type | Length | Meaning |\\n| --- | --- | --- | --- |\\n| SY-DATUM | DATS | 8 | Current Date of Application Server |\\n| SY-UZEIT | TIMS | 6 | Current Time of Application Server |\\n| SY-UNAME | CHAR | 12 | User Name |\\n| SY-SUBRC | INT4 | 10 | Return Value of ABAP Statements |\\n| SY-CPROG | CHAR | 40 | Calling Program |\\n| SY-TCODE | CHAR | 20 | Current Transaction Code |\\n| SY-LANGU | LANG | 1 | Language Key of Current Text Environment |\",\"pages\":[11],\"start_pos\":4325,\"end_pos\":4708,\"summary\":\"Tabular reference of key ABAP system fields with their data types, lengths, and semantic meanings.\",\"chunk_type\":\"reference_table\",\"has_examples\":false,\"main_concepts\":[\"CONC_014\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_012\",\"text\":\"To write a high-quality program, you should keep certain layout standards for ABAP Program\\nFollow when structuring your program flow, and use as many as informative comments as possible\\nIf you follow these suggestions your program will be\\nMore readable\\nEasier to test and change\\nMore reliable\\n\\nTo improve the quality of your programs, use the following techniques: \\nIndenting statement block\\nCombine statements that belong together into a single block \\nIndent each block by at least two columns\\nUsing modularization tool\\nWrite larger processing blocks as subroutines, the logical structure of the program becomes easier to identify\\nIt also allows you to sort the subroutines according to the tasks they perform\\nInserting program comment\\nAvoid placing comments on statement line\\nPlace comment on separate line to improve the readability of the program\\nInsert subroutine heading and comment in your program by using the ready-made structures available in ABAP Editor\",\"pages\":[12],\"start_pos\":4709,\"end_pos\":5504,\"summary\":\"Outlines ABAP layout standards emphasizing indentation, modularization, and comment discipline to enhance program quality metrics.\",\"chunk_type\":\"guideline\",\"has_examples\":false,\"main_concepts\":[\"CONC_015\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_003\",\"CONC_010\"]},{\"id\":\"CHUNK_013\",\"text\":\"ABAP provides a set of predefined functions\\nReturns a return value for one or more arguments\\nSyntax\\nFunction with an Unnamed Argument\\n... func( arg ) ...\\nFunction with Named Arguments \\n... func( val = arg p1 = arg1 p2 = arg2 ... ) ...\\n\\nFunction categories include: Boolean (boolc), string predicates (contains), floating point (sqrt, round), numerical (abs, ceil), length (strlen), search (find), substring (substring), case (to_upper), and more.\",\"pages\":[13],\"start_pos\":5505,\"end_pos\":5952,\"summary\":\"Introduces ABAP built-in functions, syntax variants (named/unnamed args), and categorizes common function families.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_016\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_014\",\"text\":\"Four Types of loop in ABAP:\\nUnconditional loop using the DO statement\\nConditional loop using the WHILE statement\\nLoops through internal table and extract dataset using the LOOP statement (will be introduced in other chapter)\\nLoops through datasets from database table using SELECT statement (will be introduced in other chapter)\\n\\nExample\\nDO 3 TIMES.\\n  WRITE /(2) SY-INDEX.\\n  WRITE ''Hello''.\\nENDDO.\\n\\nDATA cnt TYPE i VALUE 3.\\nWHILE cnt >= 1.\\n  WRITE /(2) SY-INDEX.\\n  WRITE ''Hello''.\\n  cnt = cnt - 1.\\nENDWHILE.\\n\\nBypass the following statements in a loop and go to next iteration\\nExample:\\nDATA rem TYPE i.\\nDO 20 TIMES.\\n  rem = SY-INDEX MOD 5.\\n  IF rem EQ 0.\\n    CONTINUE.\\n  ENDIF.\\n  WRITE (2) SY-INDEX.\\nENDDO.\\n\\nBypass the following statements in a loop and go to next iteration if the condition return FALSE\\nExample:\\nDATA rem TYPE i.\\nDO 20 TIMES.\\n  rem = SY-INDEX MOD 5.\\n  CHECK rem EQ 0.\\n  WRITE (2) SY-INDEX.\\nENDDO.\\n\\nTerminate a loop or subroutine\\nExample:\\nDATA rem TYPE i.\\nDO 20 TIMES.\\n  rem = SY-INDEX MOD 5.\\n  IF rem EQ 0.\\n    EXIT.\\n  ENDIF.\\n  WRITE (2) SY-INDEX.\\nENDDO.\",\"pages\":[14],\"start_pos\":5953,\"end_pos\":7221,\"summary\":\"Documents all four ABAP loop types, with emphasis on DO/WHILE syntax, and demonstrates CONTINUE, CHECK, and EXIT loop control.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_017\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\",\"CONC_019\"]},{\"id\":\"CHUNK_015\",\"text\":\"Example\\nDATA mark TYPE i VALUE 50.\\nIF mark <= 40.\\n  WRITE ''F''.\\nELSEIF mark <= 60.\\n  WRITE ''B''.\\nELSE.\\n  WRITE ''A''.\\nENDIF.\\n\\nExample:\\nDATA grade TYPE c VALUE ''A''.\\nCASE grade.\\n  WHEN ''A''.\\n    WRITE ''Excellent''.\\n  WHEN ''B''.\\n    WRITE ''Good''.\\n  WHEN OTHERS.\\n    WRITE ''Bad''.\\nENDCASE.\\n\\n| Operators | Operations |\\n| --- | --- |\\n| EQ = | Equal to |\\n| NE <> >< | Not equal to |\\n| GT > | Greater than |\\n| GE >= => | Greater than or equal to |\\n| LT < | Smaller than |\\n| LE <= =< | Smaller than or equal to |\\n| BETWEEN f1 and f2 | Interval |\\n| IS INITIAL | Initial value |\\n\\nAND, OR, NOT\\nExamples\\n\\nCOUNTER GT 0 AND FLAG IS INITIAL\\n\\n( FLAG1 NE SPACE OR FLAG2 NE SPACE ) \\n\\t\\t\\t\\t\\t\\tAND COUNTER BETWEEN 0 AND 100\\n\\nCOUNTER EQ 0 AND NOT ( FLAG1 EQ SPACE AND FLAG2 EQ SPACE )\",\"pages\":[15],\"start_pos\":7222,\"end_pos\":8220,\"summary\":\"Shows IF-ELSEIF-ELSE and CASE-WHEN syntax, then tabulates relational operators (EQ, BETWEEN) and logical connectives (AND, OR, NOT) with usage examples.\",\"chunk_type\":\"syntax_and_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_018\",\"CONC_019\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_004\",\"CONC_012\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"ABAP Keyword\",\"aliases\":[\"ABAP reserved word\"],\"keywords\":[\"keyword\",\"ABAP statement\",\"syntax\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An ABAP keyword is the first word of a statement that determines its syntactic category and semantic function. Keywords are classified into five types: declarative (e.g., DATA, TYPES), modularization (e.g., FORM, AT SELECTION SCREEN), control (e.g., IF, WHILE), calling (e.g., PERFORM, CALL), and operational (e.g., WRITE, MOVE). Each type governs distinct aspects of program structure, data handling, or execution flow. Proper keyword usage ensures correct parsing, maintainability, and adherence to SAP''s runtime semantics.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_002\",\"CHUNK_003\"],\"related_concepts\":[\"CONC_002\",\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_002\",\"title\":\"Declarative Keyword\",\"aliases\":[\"data definition keyword\"],\"keywords\":[\"DATA\",\"TYPES\",\"TABLES\",\"declaration\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A declarative keyword in ABAP defines data types or declares data objects. It establishes the technical attributes (type, length, decimals, initial value) of variables and types used throughout the program. Key examples include DATA (for variable declaration), TYPES (for local type definition), and TABLES (for dictionary table references). Declarative statements must precede any usage and form the foundational data layer upon which all other ABAP logic operates.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_001\",\"CONC_006\",\"CONC_007\"]},{\"id\":\"CONC_003\",\"title\":\"Modularization Keyword\",\"aliases\":[\"block definition keyword\"],\"keywords\":[\"FORM\",\"FUNCTION\",\"MODULE\",\"AT SELECTION SCREEN\",\"START-OF-SELECTION\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A modularization keyword defines processing blocks that encapsulate reusable logic in ABAP programs. These fall into two subcategories: event keywords (e.g., START-OF-SELECTION, AT USER-COMMAND) that bind code to system-triggered events, and defining keywords (e.g., FORM...ENDFORM, FUNCTION...ENDFUNCTION, MODULE...ENDMODULE) that create named, callable units. Modularization improves readability, testability, and maintainability by separating concerns and enabling structured control flow.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_001\",\"CONC_008\",\"CONC_009\"]},{\"id\":\"CONC_004\",\"title\":\"Control Keyword\",\"aliases\":[\"flow control keyword\"],\"keywords\":[\"IF\",\"CASE\",\"DO\",\"WHILE\",\"LOOP\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A control keyword governs the conditional or iterative flow of execution within an ABAP processing block. Examples include IF...ENDIF (branching), CASE...ENDCASE (multi-way selection), DO...ENDDO (unconditional loop), and WHILE...ENDWHILE (conditional loop). These keywords implement imperative logic constructs, allowing dynamic decision-making and repetition based on runtime conditions, and are essential for implementing business rules and algorithms.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_010\",\"CONC_011\"]},{\"id\":\"CONC_005\",\"title\":\"Calling Keyword\",\"aliases\":[\"invocation keyword\"],\"keywords\":[\"PERFORM\",\"CALL\",\"SUBMIT\",\"LEAVE TO\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A calling keyword invokes previously defined processing blocks or system services. Examples include PERFORM (to call a FORM routine), CALL (to invoke functions or screens), SUBMIT (to execute another report), LEAVE TO (to navigate between transactions), and SET USER-COMMAND (to trigger GUI events). These keywords enable program composition, inter-report communication, and integration with SAP GUI and application logic.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\",\"CONC_008\"]},{\"id\":\"CONC_006\",\"title\":\"Operational Keyword\",\"aliases\":[\"data processing keyword\"],\"keywords\":[\"WRITE\",\"MOVE\",\"ADD\",\"SUBTRACT\",\"MULTIPLY\",\"DIVIDE\"],\"confidence\":1,\"difficulty\":2,\"description\":\"An operational keyword processes data declared via declarative statements. It performs actions such as output (WRITE), assignment (MOVE), arithmetic (ADD, SUBTRACT), or string manipulation. Unlike declarative or control keywords, operational keywords act directly on data values and memory locations, forming the ''executable'' core of ABAP programs. Their behavior depends on operand types and formatting options, making them central to user interaction and data transformation.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_012\"]},{\"id\":\"CONC_007\",\"title\":\"Data Object Declaration\",\"aliases\":[\"ABAP variable declaration\"],\"keywords\":[\"DATA\",\"declaration\",\"variable\",\"type\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Data object declaration in ABAP assigns a name, type, length, and optional initial value to a variable using the DATA statement. Syntax supports fixed-length types (e.g., TYPE c LENGTH 20), dictionary references (e.g., LIKE mara-matnr), and numeric precision (e.g., TYPE p DECIMALS 2). Declarations must occur in the program''s declaration section and establish memory allocation and data semantics before use in operational statements.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_002\",\"CONC_008\",\"CONC_013\"]},{\"id\":\"CONC_008\",\"title\":\"Local Data Type\",\"aliases\":[\"program-local type\"],\"keywords\":[\"TYPES\",\"local type\",\"program scope\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A local data type is defined within an ABAP program using the TYPES statement and exists only in that program''s scope. It enables abstraction and reuse of complex type definitions (e.g., TYPES flight_num TYPE i). Local types support maintainability by decoupling data structure from implementation details and allow consistent typing across multiple DATA declarations. They differ from global types (defined in ABAP Dictionary) and predefined standard types.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_002\",\"CONC_007\",\"CONC_014\"]},{\"id\":\"CONC_009\",\"title\":\"Global Data Type\",\"aliases\":[\"dictionary type\"],\"keywords\":[\"ABAP Dictionary\",\"SE11\",\"MATNR\",\"LIKE\",\"TYPE\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A global data type is defined in the ABAP Dictionary (transaction SE11) and is available system-wide for use in any ABAP program, database table, or interface. Examples include data elements like MATNR (material number) and domains like CHAR. Global types ensure consistency, enforce business semantics, and support centralized maintenance. They are referenced in programs via LIKE (for fields) or TYPE (for data elements) in DATA or TYPES statements.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_002\",\"CONC_007\",\"CONC_014\"]},{\"id\":\"CONC_010\",\"title\":\"ABAP Comment\",\"aliases\":[\"ABAP documentation\"],\"keywords\":[\"*\",\"\\\"\",\"comment\",\"documentation\"],\"confidence\":1,\"difficulty\":1,\"description\":\"An ABAP comment is non-executable text used to document code intent. It is ignored by the runtime system and flagged by either an asterisk (*) in column 1 (full-line comment) or a quotation mark (\\\") anywhere in a line (inline comment). Comments improve readability, support debugging, and aid long-term maintenance. Best practices recommend placing comments on separate lines rather than embedding them within executable statements.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_015\"]},{\"id\":\"CONC_011\",\"title\":\"Chain Statement\",\"aliases\":[\"statement chaining\"],\"keywords\":[\"chain\",\"colon\",\"WRITE:\",\"concatenation\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A chain statement concatenates multiple ABAP statements sharing the same initial keyword and colon (:) syntax. For example, ''WRITE: ''''XYZ'''', NAME, COUNTER.'' replaces three separate WRITE statements. Chaining reduces redundancy, improves compactness, and enhances readability when outputting related values. The colon terminates the common prefix, and comma-separated items follow, each interpreted as a continuation of the base statement.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_006\",\"CONC_012\"]},{\"id\":\"CONC_012\",\"title\":\"WRITE Statement\",\"aliases\":[\"ABAP output statement\"],\"keywords\":[\"WRITE\",\"output\",\"formatting\",\"list display\"],\"confidence\":1,\"difficulty\":2,\"description\":\"The WRITE statement outputs data to the list screen in ABAP reports. It supports formatting options including position (AT pos), length (n), justification (LEFT-JUSTIFIED, CENTERED), alignment (UNDER), spacing (NO-GAP), and specialized display (CURRENCY, DECIMALS, UNIT). Consecutive WRITEs appear on the same line separated by spaces; a slash (/) forces a new line. WRITE is fundamental for user-facing output and debugging, with behavior dependent on data type, length, and modifiers.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_008\",\"CHUNK_009\"],\"related_concepts\":[\"CONC_006\",\"CONC_011\",\"CONC_016\"]},{\"id\":\"CONC_013\",\"title\":\"Constant Declaration\",\"aliases\":[\"ABAP constant\"],\"keywords\":[\"CONSTANTS\",\"immutable\",\"literal\",\"VALUE\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Constant declaration in ABAP creates immutable named values using the CONSTANTS statement. Syntax specifies name, optional type, and mandatory VALUE clause (e.g., CONSTANTS ctext TYPE c VALUE ''Hello''). Constants improve code clarity and maintainability by replacing magic literals with meaningful identifiers. They are evaluated at compile time and cannot be reassigned, ensuring data integrity and simplifying refactoring across large codebases.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_010\"],\"related_concepts\":[\"CONC_002\",\"CONC_007\"]},{\"id\":\"CONC_014\",\"title\":\"ABAP System Fields\",\"aliases\":[\"sy-field\"],\"keywords\":[\"SY-DATUM\",\"SY-UNAME\",\"SY-SUBRC\",\"system field\"],\"confidence\":1,\"difficulty\":2,\"description\":\"ABAP system fields are predefined global variables (prefixed with SY-) that provide contextual runtime information such as current date (SY-DATUM), time (SY-UZEIT), user name (SY-UNAME), return code (SY-SUBRC), transaction code (SY-TCODE), and language key (SY-LANGU). They are read-only and automatically populated by the system, enabling dynamic behavior based on environment state without explicit initialization.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_011\"],\"related_concepts\":[\"CONC_007\",\"CONC_012\"]},{\"id\":\"CONC_015\",\"title\":\"ABAP Layout Standard\",\"aliases\":[\"ABAP best practice\"],\"keywords\":[\"indentation\",\"modularization\",\"comment placement\",\"layout\"],\"confidence\":1,\"difficulty\":2,\"description\":\"ABAP layout standards are coding conventions promoting readability, testability, and reliability. Key techniques include indentation (≥2 columns per block), modularization (subroutines for logical separation), and dedicated comment placement (separate lines, subroutine headers). Adhering to these standards reduces cognitive load, accelerates peer review, and minimizes regression risk during enhancements — aligning with SAP’s recommended development practices.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_012\"],\"related_concepts\":[\"CONC_003\",\"CONC_010\",\"CONC_016\"]},{\"id\":\"CONC_016\",\"title\":\"ABAP Built-in Function\",\"aliases\":[\"ABAP intrinsic function\"],\"keywords\":[\"function\",\"built-in\",\"SQRT\",\"FIND\",\"TO_UPPER\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An ABAP built-in function is a predeclared routine that accepts arguments and returns a value, supporting operations across domains like mathematics (SQRT, ROUND), strings (FIND, REPLACE), dates (CONVERT_DATE_TO_INTERNAL), and conversions (TO_UPPER). Functions can be invoked with unnamed arguments (func(arg)) or named arguments (func(val = arg)). They abstract low-level logic, reduce boilerplate, and ensure consistent, optimized execution across ABAP applications.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_013\"],\"related_concepts\":[\"CONC_006\",\"CONC_012\",\"CONC_017\"]},{\"id\":\"CONC_017\",\"title\":\"ABAP Loop Statement\",\"aliases\":[\"ABAP iteration\"],\"keywords\":[\"DO\",\"WHILE\",\"LOOP\",\"SELECT\",\"CONTINUE\",\"CHECK\",\"EXIT\"],\"confidence\":1,\"difficulty\":3,\"description\":\"ABAP loop statements implement iterative execution: DO (unconditional, with TIMES or WHILE), WHILE (conditional), LOOP (internal tables), and SELECT (database access). DO and WHILE are foundational for algorithmic repetition, supporting CONTINUE (skip iteration), CHECK (conditional skip), and EXIT (terminate loop). Loops must be carefully scoped to avoid infinite execution and are often paired with SY-INDEX for iteration tracking.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_014\"],\"related_concepts\":[\"CONC_004\",\"CONC_011\",\"CONC_018\"]},{\"id\":\"CONC_018\",\"title\":\"ABAP Conditional Statement\",\"aliases\":[\"ABAP branching\"],\"keywords\":[\"IF\",\"CASE\",\"EQ\",\"BETWEEN\",\"AND\",\"OR\"],\"confidence\":1,\"difficulty\":3,\"description\":\"ABAP conditional statements evaluate Boolean expressions to control program flow. IF...ELSEIF...ELSE...ENDIF supports multi-branch logic with arbitrary nesting depth. CASE...WHEN...ENDCASE provides efficient multi-value dispatch for discrete values or ranges (WHEN OTHERS). Both require proper termination and rely on relational operators (EQ, NE, GT, BETWEEN) and logical connectives (AND, OR, NOT) to express business rules precisely.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_015\"],\"related_concepts\":[\"CONC_004\",\"CONC_017\",\"CONC_019\"]},{\"id\":\"CONC_019\",\"title\":\"ABAP Relational Operator\",\"aliases\":[\"comparison operator\"],\"keywords\":[\"EQ\",\"NE\",\"BETWEEN\",\"CO\",\"CA\",\"CS\",\"CP\"],\"confidence\":1,\"difficulty\":3,\"description\":\"ABAP relational operators compare values and return Boolean results. They include equality (EQ, =), inequality (NE, <>), ordering (GT, LT, GE, LE), interval checks (BETWEEN), and character/string predicates (CO, CA, CS, CP). String operators support pattern matching (* for wildcard, + for single char), containment, and case-insensitive comparisons. These operators are used exclusively in conditional contexts (IF, CASE, CHECK) and define decision boundaries in business logic.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_015\"],\"related_concepts\":[\"CONC_004\",\"CONC_018\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"example_of\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"Declarative keywords (e.g., DATA, TYPES) are explicitly listed as a subtype of ABAP keyword.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"example_of\",\"source\":\"CONC_001\",\"target\":\"CONC_003\",\"evidence\":\"Modularization keywords (e.g., FORM, AT SELECTION SCREEN) are explicitly listed as a subtype of ABAP keyword.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"example_of\",\"source\":\"CONC_001\",\"target\":\"CONC_004\",\"evidence\":\"Control keywords (e.g., IF, WHILE) are explicitly listed as a subtype of ABAP keyword.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"example_of\",\"source\":\"CONC_001\",\"target\":\"CONC_005\",\"evidence\":\"Calling keywords (e.g., PERFORM, CALL) are explicitly listed as a subtype of ABAP keyword.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"example_of\",\"source\":\"CONC_001\",\"target\":\"CONC_006\",\"evidence\":\"Operational keywords (e.g., WRITE, MOVE) are explicitly listed as a subtype of ABAP keyword.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"implements\",\"source\":\"CONC_002\",\"target\":\"CONC_007\",\"evidence\":\"DATA is the primary declarative keyword used to declare data objects.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"implements\",\"source\":\"CONC_002\",\"target\":\"CONC_008\",\"evidence\":\"TYPES is the declarative keyword used to define local data types.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"requires\",\"source\":\"CONC_003\",\"target\":\"CONC_008\",\"evidence\":\"FORM routines may use locally defined types (via TYPES) for parameter typing.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"requires\",\"source\":\"CONC_003\",\"target\":\"CONC_009\",\"evidence\":\"FORM parameters or internal tables often reference global dictionary types (e.g., LIKE mara-matnr).\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"part_of\",\"source\":\"CONC_004\",\"target\":\"CONC_017\",\"evidence\":\"DO and WHILE are classified as control keywords and also constitute loop constructs.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"part_of\",\"source\":\"CONC_004\",\"target\":\"CONC_018\",\"evidence\":\"IF and CASE are classified as control keywords and constitute conditional constructs.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"calls\",\"source\":\"CONC_005\",\"target\":\"CONC_003\",\"evidence\":\"PERFORM calls FORM routines; CALL invokes FUNCTION modules.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"implements\",\"source\":\"CONC_006\",\"target\":\"CONC_012\",\"evidence\":\"WRITE is the primary operational keyword for output.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_014\",\"type\":\"requires\",\"source\":\"CONC_007\",\"target\":\"CONC_008\",\"evidence\":\"DATA declarations may reference local types defined via TYPES.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_015\",\"type\":\"requires\",\"source\":\"CONC_007\",\"target\":\"CONC_009\",\"evidence\":\"DATA declarations may reference global types via LIKE or TYPE.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_016\",\"type\":\"opposite_of\",\"source\":\"CONC_008\",\"target\":\"CONC_009\",\"evidence\":\"Local types exist only in one program; global types exist system-wide.\",\"strength\":1,\"bidirectional\":true},{\"id\":\"REL_017\",\"type\":\"supports\",\"source\":\"CONC_010\",\"target\":\"CONC_015\",\"evidence\":\"Comments are a core component of ABAP layout standards.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_018\",\"type\":\"specializes\",\"source\":\"CONC_011\",\"target\":\"CONC_012\",\"evidence\":\"Chain statements are a syntactic variation of the WRITE statement.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_019\",\"type\":\"uses\",\"source\":\"CONC_012\",\"target\":\"CONC_014\",\"evidence\":\"WRITE statements commonly output system fields (e.g., WRITE sy-uname).\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_020\",\"type\":\"similar_to\",\"source\":\"CONC_013\",\"target\":\"CONC_002\",\"evidence\":\"CONSTANTS and DATA are both declarative statements with analogous syntax.\",\"strength\":1,\"bidirectional\":true},{\"id\":\"REL_021\",\"type\":\"extends\",\"source\":\"CONC_016\",\"target\":\"CONC_006\",\"evidence\":\"Functions (e.g., abs(), to_upper()) are often used in operational contexts like WRITE or MOVE.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_022\",\"type\":\"contrasts_with\",\"source\":\"CONC_017\",\"target\":\"CONC_018\",\"evidence\":\"Loops (iterative) and conditionals (branching) represent distinct control flow paradigms.\",\"strength\":1,\"bidirectional\":true},{\"id\":\"REL_023\",\"type\":\"uses\",\"source\":\"CONC_018\",\"target\":\"CONC_019\",\"evidence\":\"IF and CASE statements depend on relational operators to evaluate conditions.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_024\",\"type\":\"supports\",\"source\":\"CONC_019\",\"target\":\"CONC_004\",\"evidence\":\"Relational operators are used exclusively within control keywords (IF, CASE, CHECK).\",\"strength\":1,\"bidirectional\":false}]"', '2026-04-03 16:36:41.149024', '2026-04-03 16:36:41.149024', NULL, '[{"id": "module_1", "name": "ABAP Programming Fundamentals", "topic_count": 12}, {"id": "module_2", "name": "Data Declaration and Types", "topic_count": 14}, {"id": "module_3", "name": "Output with WRITE Statement", "topic_count": 16}, {"id": "module_4", "name": "Operators and Expressions", "topic_count": 12}, {"id": "module_5", "name": "Predefined Functions", "topic_count": 10}, {"id": "module_6", "name": "Control Flow and Loops", "topic_count": 12}]', NULL, 'IT114105 Higher Diploma in Software Engineering

