INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '6_MementoPattern.pdf', '4a631ebe42431d1422cc09b5ee4fbc2a1db14d66028aedae9988a439d7086302', '{"chunks": [{"id": "CHUNK_001", "text": "The intent of this pattern is to capture the internal state of an object without violating encapsulation and thus providing a mean for restoring the object into initial state when needed.", "pages": [2], "end_pos": 158, "summary": "Defines the intent of the Memento Pattern: capturing internal state without breaking encapsulation to enable restoration.", "start_pos": 0, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_002", "text": "Objects frequently expose only some of their internal states using public methods. You would still like to be able to save the entire state of an object because you might need to restore it later. This sort of information saving and restoration is common in systems that need to support undo commands.", "pages": [3], "end_pos": 346, "summary": "Explains the motivation for the Memento Pattern: saving complete object state for restoration, especially for undo functionality.", "start_pos": 159, "chunk_type": "motivation", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_003", "text": "How to retrieve all required information of an object while preserving its encapsulation? For example, a class may have private data with no public getter, making external access impossible without violating encapsulation principles.", "pages": [4], "end_pos": 504, "summary": "Poses the core problem: accessing full internal state while preserving encapsulation.", "start_pos": 347, "chunk_type": "problem", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_004", "text": "The Memento Pattern solves this by having privileged access to the state of the object you want to save. It preserves encapsulation by letting the Originator create and restore its own state. The Caretaker never modifies the state directly. The pattern defines three roles: Originator (object whose state is saved), Memento (object that saves the state), and Caretaker (manages saving and restoration timing).", "pages": [5, 6], "end_pos": 758, "summary": "Describes how the Memento Pattern solves the encapsulation-preserving state capture problem via three defined roles.", "start_pos": 505, "chunk_type": "solution", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_005", "text": "Structure: The UML diagram shows the relationships between Originator, Memento, and Caretaker. The Originator can create and restore from a Memento. The Caretaker holds references to Mementos but interacts with them only through a narrow interface, not accessing internal state.", "pages": [7], "end_pos": 940, "summary": "Describes the structural relationship between the three main components of the Memento Pattern.", "start_pos": 759, "chunk_type": "diagram_description", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CHUNK_006", "text": "Java variables can have access levels: private (class-only), protected (class and subclass), public (all classes), and package-private (same package). These modifiers are crucial for implementing encapsulation in the Memento Pattern, where package scope allows Memento access to Originator state without exposing it widely.", "pages": [8], "end_pos": 1162, "summary": "Reviews Java access modifiers, relevant for understanding encapsulation in implementation.", "start_pos": 941, "chunk_type": "background", "has_examples": false, "main_concepts": ["CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_007", "text": "public class Originator { int state = 0; // package protected attribute public void action() { state = state + 1; } public int getState() { return state; } }", "pages": [9], "end_pos": 1300, "summary": "Code snippet showing an Originator class with a modifiable state and action method.", "start_pos": 1163, "chunk_type": "code", "has_examples": true, "main_concepts": ["CONC_002"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_008", "text": "public class Memento { private int state; Originator orig; public Memento(Originator o) { orig = o; state = orig.state; } public void restore() { orig.state = this.state; } }", "pages": [10], "end_pos": 1480, "summary": "Implements a Memento that captures and can restore the state of an Originator.", "start_pos": 1301, "chunk_type": "code", "has_examples": true, "main_concepts": ["CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_009", "text": "public class Caretaker { public static void main(String[] args) { Originator originator = new Originator(); Memento m0 = new Memento(originator); originator.action(); originator.action(); System.out.println(\"state = \" + originator.getState()); m0.restore(); System.out.println(\"state after restore = \" + originator.getState()); } }", "pages": [11], "end_pos": 1740, "summary": "Demonstrates a Caretaker using Memento to save and later restore an Originator''s state.", "start_pos": 1481, "chunk_type": "code", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": false, "secondary_concepts": ["CONC_002", "CONC_003"]}, {"id": "CHUNK_010", "text": "A graphics drawing tool allows creating and moving shapes. It includes Create Shape, Undo, Redo, and Clear buttons. The tool must support reverting shape positions after moves, requiring state preservation and restoration capabilities.", "pages": [12], "end_pos": 1930, "summary": "Presents a use case for the Memento Pattern in a drawing application with undo/redo features.", "start_pos": 1741, "chunk_type": "use_case", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_011", "text": "Example: TextEditor - Originator is the TextEditor holding text content. Memento captures the text state. Caretaker manages undo/redo stacks. Goal is to support undo/redo without breaking encapsulation by limiting state access to Originator-Memento collaboration.", "pages": [22], "end_pos": 2140, "summary": "Illustrates the Memento Pattern in a text editor with undo/redo stacks managed by the Caretaker.", "start_pos": 1931, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_006", "CONC_004"], "has_definitions": false, "secondary_concepts": ["CONC_001", "CONC_005"]}, {"id": "CHUNK_012", "text": "After three saves: undoList has [\"Hello World!!!\", \"Hello World\", \"Hello\"], redoList empty. Undo moves top of undoList to redoList and restores previous state. Redo pops from redoList, restores, and pushes back to undoList. This demonstrates stack-based state management for undo/redo.", "pages": [24], "end_pos": 2380, "summary": "Explains how undo and redo operations work using two stacks to manage state history.", "start_pos": 2141, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_013", "text": "Common pitfalls: Undo doing nothing due to incorrect state handling; Redo broken after new edit if redoList isn''t cleared; Too many saves causing performance issues; Leaky encapsulation if state access is not properly restricted between Originator and Memento.", "pages": [26], "end_pos": 2580, "summary": "Lists common implementation pitfalls when using the Memento Pattern, especially around state management and encapsulation.", "start_pos": 2381, "chunk_type": "caution", "has_examples": true, "main_concepts": ["CONC_005"], "has_definitions": false, "secondary_concepts": ["CONC_006"]}], "concepts": [{"id": "CONC_001", "title": "Memento Pattern", "aliases": ["Memento"], "keywords": ["design pattern", "behavioral pattern", "state management", "undo mechanism"], "confidence": 1.0, "difficulty": 4, "description": "The Memento Pattern is a behavioral design pattern that enables capturing and externalizing an object''s internal state without violating encapsulation, so the object can be restored to this state later. It involves three key participants: the Originator, which creates a memento containing a snapshot of its current state; the Memento, which stores the state of the Originator; and the Caretaker, which manages mementos but does not modify or inspect their contents. This pattern is commonly used to implement undo/redo functionality in applications.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_003", "CHUNK_004"], "related_concepts": ["CONC_002", "CONC_003", "CONC_004"]}, {"id": "CONC_002", "title": "Originator", "aliases": [], "keywords": ["originator", "state owner", "snapshot creator"], "confidence": 1.0, "difficulty": 3, "description": "In the Memento Pattern, the Originator is the object whose internal state needs to be saved and restored. It has full access to its private state and is responsible for creating a Memento object that contains a snapshot of its current state. The Originator can also accept a Memento object to restore its state. The Originator maintains encapsulation by allowing only itself and trusted collaborators (like the Memento) to access its internal data directly.", "concept_type": "object", "extracted_from": ["CHUNK_003", "CHUNK_004", "CHUNK_008"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_003", "title": "Memento", "aliases": [], "keywords": ["snapshot", "state container", "immutable state holder"], "confidence": 1.0, "difficulty": 3, "description": "The Memento is an object that holds a snapshot of the Originator''s internal state. It is created by the Originator and can only be read and restored by the Originator. The Caretaker stores the Memento but does not access or modify its contents, thus preserving encapsulation. The Memento may expose limited public methods such as restore(), but keeps the actual state data private or package-protected.", "concept_type": "component", "extracted_from": ["CHUNK_003", "CHUNK_004", "CHUNK_009"], "related_concepts": ["CONC_001", "CONC_002", "CONC_004"]}, {"id": "CONC_004", "title": "Caretaker", "aliases": [], "keywords": ["memento manager", "state controller", "undo manager"], "confidence": 1.0, "difficulty": 3, "description": "The Caretaker is responsible for managing the lifecycle of Memento objects. It decides when to save the state of the Originator by requesting a Memento from it and storing it. When a restoration is needed (e.g., on an undo command), the Caretaker passes the appropriate Memento back to the Originator. Crucially, the Caretaker never accesses or modifies the internal state stored in the Memento, ensuring encapsulation is preserved.", "concept_type": "object", "extracted_from": ["CHUNK_004", "CHUNK_011"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_005", "title": "Encapsulation", "aliases": [], "keywords": ["data hiding", "access control", "information hiding"], "confidence": 1.0, "difficulty": 2, "description": "Encapsulation is a fundamental principle of object-oriented programming that restricts direct access to an object''s internal state. Only the object itself can modify its private data, typically through public methods. The Memento Pattern respects encapsulation by allowing the Originator to expose its state only to the Memento, which acts as a trusted collaborator, while other components like the Caretaker remain unaware of the internal structure.", "concept_type": "theory", "extracted_from": ["CHUNK_001", "CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_001"]}, {"id": "CONC_006", "title": "Undo Mechanism", "aliases": ["Undo", "Redo"], "keywords": ["revert", "rollback", "history management"], "confidence": 1.0, "difficulty": 3, "description": "An Undo Mechanism allows users to revert changes made to a system, returning it to a previous state. In software, this is often implemented using stacks to store historical states. The Memento Pattern provides a clean way to implement undo by capturing object state snapshots. Each ''save'' pushes a Memento onto an undo stack, and ''undo'' pops from this stack and restores the state, optionally pushing the current state to a redo stack.", "concept_type": "process", "extracted_from": ["CHUNK_002", "CHUNK_011", "CHUNK_012"], "related_concepts": ["CONC_001", "CONC_004"]}, {"id": "CONC_007", "title": "Java Access Modifiers", "aliases": ["Access Modifiers"], "keywords": ["access control", "visibility", "private", "protected", "public"], "confidence": 1.0, "difficulty": 2, "description": "Java provides access control through modifiers: private (accessible only within the class), protected (within class and subclasses), package-private (default, accessible within the same package), and public (universally accessible). The Memento Pattern often uses package-private access to allow the Memento class to access the Originator''s state while preventing broader exposure, thus maintaining encapsulation.", "concept_type": "theory", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_005"]}], "relationships": [{"id": "REL_001", "type": "requires", "source": "CONC_001", "target": "CONC_002", "evidence": "The Memento Pattern requires an Originator object whose state is to be saved and restored.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "produces", "source": "CONC_001", "target": "CONC_003", "evidence": "The Memento Pattern produces Memento objects to store the state of the Originator.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "managed_by", "source": "CONC_001", "target": "CONC_004", "evidence": "The lifecycle of Mementos in the Memento Pattern is managed by the Caretaker.", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "creates", "source": "CONC_002", "target": "CONC_003", "evidence": "The Originator creates a Memento object containing its internal state.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "restores", "source": "CONC_002", "target": "CONC_003", "evidence": "The Originator uses the Memento to restore its previous state.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "stores_state_of", "source": "CONC_003", "target": "CONC_002", "evidence": "The Memento stores the internal state of the Originator.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "manages", "source": "CONC_004", "target": "CONC_003", "evidence": "The Caretaker manages the storage and retrieval of Memento objects.", "strength": 1.0, "bidirectional": false}, {"id": "REL_008", "type": "implemented_by", "source": "CONC_006", "target": "CONC_001", "evidence": "The Undo Mechanism is implemented using the Memento Pattern.", "strength": 1.0, "bidirectional": false}, {"id": "REL_009", "type": "preserved_by", "source": "CONC_005", "target": "CONC_001", "evidence": "Encapsulation is preserved by the Memento Pattern through restricted state access.", "strength": 1.0, "bidirectional": false}, {"id": "REL_010", "type": "supports", "source": "CONC_007", "target": "CONC_005", "evidence": "Java Access Modifiers support the principle of Encapsulation.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 13, "missing_links": [], "coverage_score": 1.0, "total_concepts": 7, "consistency_score": 1.0, "total_relationships": 10}, "document_metadata": {"title": "ITP4507 - Contemporary Topics in Software Engineering: Behavioral Patterns - Memento Pattern", "language": "English", "main_topic": "Memento Design Pattern in Software Engineering", "difficulty_level": "Intermediate", "estimated_reading_time": "15 minutes"}, "concept_chunk_mapping": [{"concept": "Memento Pattern", "context": "Definition of the pattern''s intent.", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Memento Pattern", "context": "Detailed explanation of the pattern and its roles.", "chunk_id": "CHUNK_004", "positions": [505], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Memento Pattern", "context": "Structural overview of the pattern components.", "chunk_id": "CHUNK_005", "positions": [759], "concept_id": "CONC_001", "importance": "secondary"}, {"concept": "Originator", "context": "Defined as the object whose state is saved.", "chunk_id": "CHUNK_004", "positions": [650], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Originator", "context": "Code example of an Originator class.", "chunk_id": "CHUNK_007", "positions": [1163], "concept_id": "CONC_002", "importance": "example"}, {"concept": "Memento", "context": "Defined as the object that saves the state of the Originator.", "chunk_id": "CHUNK_004", "positions": [680], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Memento", "context": "Implementation of the Memento class in Java.", "chunk_id": "CHUNK_008", "positions": [1301], "concept_id": "CONC_003", "importance": "example"}, {"concept": "Caretaker", "context": "Defined as the manager of Memento saving and restoration timing.", "chunk_id": "CHUNK_004", "positions": [700], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Caretaker", "context": "Code demonstrating the Caretaker managing state restoration.", "chunk_id": "CHUNK_009", "positions": [1481], "concept_id": "CONC_004", "importance": "example"}, {"concept": "Encapsulation", "context": "Mentioned as preserved by the Memento Pattern.", "chunk_id": "CHUNK_001", "positions": [60], "concept_id": "CONC_005", "importance": "secondary"}, {"concept": "Encapsulation", "context": "Core issue in the problem statement: preserving encapsulation while saving state.", "chunk_id": "CHUNK_003", "positions": [350], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Undo Mechanism", "context": "Motivating example for the pattern: supporting undo commands.", "chunk_id": "CHUNK_002", "positions": [250], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "Undo Mechanism", "context": "Demonstration of undo/redo using stacks in a text editor scenario.", "chunk_id": "CHUNK_012", "positions": [2141], "concept_id": "CONC_006", "importance": "example"}, {"concept": "Java Access Modifiers", "context": "Explanation of access levels relevant to implementing encapsulation in Memento.", "chunk_id": "CHUNK_006", "positions": [941], "concept_id": "CONC_007", "importance": "primary"}]}', '{"total_modules": 4, "total_concepts": 12, "difficulty_score": 7, "total_structures": 8, "total_applications": 10}', '"[{\"id\":\"CHUNK_001\",\"text\":\"The intent of this pattern is to capture the internal state of an object without violating encapsulation and thus providing a mean for restoring the object into initial state when needed.\",\"pages\":[2],\"start_pos\":0,\"end_pos\":158,\"summary\":\"Defines the intent of the Memento Pattern: capturing internal state without breaking encapsulation to enable restoration.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_002\",\"text\":\"Objects frequently expose only some of their internal states using public methods. You would still like to be able to save the entire state of an object because you might need to restore it later. This sort of information saving and restoration is common in systems that need to support undo commands.\",\"pages\":[3],\"start_pos\":159,\"end_pos\":346,\"summary\":\"Explains the motivation for the Memento Pattern: saving complete object state for restoration, especially for undo functionality.\",\"chunk_type\":\"motivation\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_003\",\"text\":\"How to retrieve all required information of an object while preserving its encapsulation? For example, a class may have private data with no public getter, making external access impossible without violating encapsulation principles.\",\"pages\":[4],\"start_pos\":347,\"end_pos\":504,\"summary\":\"Poses the core problem: accessing full internal state while preserving encapsulation.\",\"chunk_type\":\"problem\",\"has_examples\":true,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_004\",\"text\":\"The Memento Pattern solves this by having privileged access to the state of the object you want to save. It preserves encapsulation by letting the Originator create and restore its own state. The Caretaker never modifies the state directly. The pattern defines three roles: Originator (object whose state is saved), Memento (object that saves the state), and Caretaker (manages saving and restoration timing).\",\"pages\":[5,6],\"start_pos\":505,\"end_pos\":758,\"summary\":\"Describes how the Memento Pattern solves the encapsulation-preserving state capture problem via three defined roles.\",\"chunk_type\":\"solution\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\",\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_005\",\"text\":\"Structure: The UML diagram shows the relationships between Originator, Memento, and Caretaker. The Originator can create and restore from a Memento. The Caretaker holds references to Mementos but interacts with them only through a narrow interface, not accessing internal state.\",\"pages\":[7],\"start_pos\":759,\"end_pos\":940,\"summary\":\"Describes the structural relationship between the three main components of the Memento Pattern.\",\"chunk_type\":\"diagram_description\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CHUNK_006\",\"text\":\"Java variables can have access levels: private (class-only), protected (class and subclass), public (all classes), and package-private (same package). These modifiers are crucial for implementing encapsulation in the Memento Pattern, where package scope allows Memento access to Originator state without exposing it widely.\",\"pages\":[8],\"start_pos\":941,\"end_pos\":1162,\"summary\":\"Reviews Java access modifiers, relevant for understanding encapsulation in implementation.\",\"chunk_type\":\"background\",\"has_examples\":false,\"main_concepts\":[\"CONC_007\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_007\",\"text\":\"public class Originator { int state = 0; // package protected attribute public void action() { state = state + 1; } public int getState() { return state; } }\",\"pages\":[9],\"start_pos\":1163,\"end_pos\":1300,\"summary\":\"Code snippet showing an Originator class with a modifiable state and action method.\",\"chunk_type\":\"code\",\"has_examples\":true,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_008\",\"text\":\"public class Memento { private int state; Originator orig; public Memento(Originator o) { orig = o; state = orig.state; } public void restore() { orig.state = this.state; } }\",\"pages\":[10],\"start_pos\":1301,\"end_pos\":1480,\"summary\":\"Implements a Memento that captures and can restore the state of an Originator.\",\"chunk_type\":\"code\",\"has_examples\":true,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_009\",\"text\":\"public class Caretaker { public static void main(String[] args) { Originator originator = new Originator(); Memento m0 = new Memento(originator); originator.action(); originator.action(); System.out.println(\\\"state = \\\" + originator.getState()); m0.restore(); System.out.println(\\\"state after restore = \\\" + originator.getState()); } }\",\"pages\":[11],\"start_pos\":1481,\"end_pos\":1740,\"summary\":\"Demonstrates a Caretaker using Memento to save and later restore an Originator''s state.\",\"chunk_type\":\"code\",\"has_examples\":true,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_002\",\"CONC_003\"]},{\"id\":\"CHUNK_010\",\"text\":\"A graphics drawing tool allows creating and moving shapes. It includes Create Shape, Undo, Redo, and Clear buttons. The tool must support reverting shape positions after moves, requiring state preservation and restoration capabilities.\",\"pages\":[12],\"start_pos\":1741,\"end_pos\":1930,\"summary\":\"Presents a use case for the Memento Pattern in a drawing application with undo/redo features.\",\"chunk_type\":\"use_case\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_011\",\"text\":\"Example: TextEditor - Originator is the TextEditor holding text content. Memento captures the text state. Caretaker manages undo/redo stacks. Goal is to support undo/redo without breaking encapsulation by limiting state access to Originator-Memento collaboration.\",\"pages\":[22],\"start_pos\":1931,\"end_pos\":2140,\"summary\":\"Illustrates the Memento Pattern in a text editor with undo/redo stacks managed by the Caretaker.\",\"chunk_type\":\"example\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\",\"CONC_004\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\",\"CONC_005\"]},{\"id\":\"CHUNK_012\",\"text\":\"After three saves: undoList has [\\\"Hello World!!!\\\", \\\"Hello World\\\", \\\"Hello\\\"], redoList empty. Undo moves top of undoList to redoList and restores previous state. Redo pops from redoList, restores, and pushes back to undoList. This demonstrates stack-based state management for undo/redo.\",\"pages\":[24],\"start_pos\":2141,\"end_pos\":2380,\"summary\":\"Explains how undo and redo operations work using two stacks to manage state history.\",\"chunk_type\":\"example\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_013\",\"text\":\"Common pitfalls: Undo doing nothing due to incorrect state handling; Redo broken after new edit if redoList isn''t cleared; Too many saves causing performance issues; Leaky encapsulation if state access is not properly restricted between Originator and Memento.\",\"pages\":[26],\"start_pos\":2381,\"end_pos\":2580,\"summary\":\"Lists common implementation pitfalls when using the Memento Pattern, especially around state management and encapsulation.\",\"chunk_type\":\"caution\",\"has_examples\":true,\"main_concepts\":[\"CONC_005\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_006\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Memento Pattern\",\"aliases\":[\"Memento\"],\"keywords\":[\"design pattern\",\"behavioral pattern\",\"state management\",\"undo mechanism\"],\"confidence\":1,\"difficulty\":4,\"description\":\"The Memento Pattern is a behavioral design pattern that enables capturing and externalizing an object''s internal state without violating encapsulation, so the object can be restored to this state later. It involves three key participants: the Originator, which creates a memento containing a snapshot of its current state; the Memento, which stores the state of the Originator; and the Caretaker, which manages mementos but does not modify or inspect their contents. This pattern is commonly used to implement undo/redo functionality in applications.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_003\",\"CHUNK_004\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_002\",\"title\":\"Originator\",\"aliases\":[],\"keywords\":[\"originator\",\"state owner\",\"snapshot creator\"],\"confidence\":1,\"difficulty\":3,\"description\":\"In the Memento Pattern, the Originator is the object whose internal state needs to be saved and restored. It has full access to its private state and is responsible for creating a Memento object that contains a snapshot of its current state. The Originator can also accept a Memento object to restore its state. The Originator maintains encapsulation by allowing only itself and trusted collaborators (like the Memento) to access its internal data directly.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_003\",\"CHUNK_004\",\"CHUNK_008\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CONC_003\",\"title\":\"Memento\",\"aliases\":[],\"keywords\":[\"snapshot\",\"state container\",\"immutable state holder\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The Memento is an object that holds a snapshot of the Originator''s internal state. It is created by the Originator and can only be read and restored by the Originator. The Caretaker stores the Memento but does not access or modify its contents, thus preserving encapsulation. The Memento may expose limited public methods such as restore(), but keeps the actual state data private or package-protected.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_003\",\"CHUNK_004\",\"CHUNK_009\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_004\"]},{\"id\":\"CONC_004\",\"title\":\"Caretaker\",\"aliases\":[],\"keywords\":[\"memento manager\",\"state controller\",\"undo manager\"],\"confidence\":1,\"difficulty\":3,\"description\":\"The Caretaker is responsible for managing the lifecycle of Memento objects. It decides when to save the state of the Originator by requesting a Memento from it and storing it. When a restoration is needed (e.g., on an undo command), the Caretaker passes the appropriate Memento back to the Originator. Crucially, the Caretaker never accesses or modifies the internal state stored in the Memento, ensuring encapsulation is preserved.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_011\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CONC_005\",\"title\":\"Encapsulation\",\"aliases\":[],\"keywords\":[\"data hiding\",\"access control\",\"information hiding\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Encapsulation is a fundamental principle of object-oriented programming that restricts direct access to an object''s internal state. Only the object itself can modify its private data, typically through public methods. The Memento Pattern respects encapsulation by allowing the Originator to expose its state only to the Memento, which acts as a trusted collaborator, while other components like the Caretaker remain unaware of the internal structure.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_002\",\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\"]},{\"id\":\"CONC_006\",\"title\":\"Undo Mechanism\",\"aliases\":[\"Undo\",\"Redo\"],\"keywords\":[\"revert\",\"rollback\",\"history management\"],\"confidence\":1,\"difficulty\":3,\"description\":\"An Undo Mechanism allows users to revert changes made to a system, returning it to a previous state. In software, this is often implemented using stacks to store historical states. The Memento Pattern provides a clean way to implement undo by capturing object state snapshots. Each ''save'' pushes a Memento onto an undo stack, and ''undo'' pops from this stack and restores the state, optionally pushing the current state to a redo stack.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_002\",\"CHUNK_011\",\"CHUNK_012\"],\"related_concepts\":[\"CONC_001\",\"CONC_004\"]},{\"id\":\"CONC_007\",\"title\":\"Java Access Modifiers\",\"aliases\":[\"Access Modifiers\"],\"keywords\":[\"access control\",\"visibility\",\"private\",\"protected\",\"public\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Java provides access control through modifiers: private (accessible only within the class), protected (within class and subclasses), package-private (default, accessible within the same package), and public (universally accessible). The Memento Pattern often uses package-private access to allow the Memento class to access the Originator''s state while preventing broader exposure, thus maintaining encapsulation.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_005\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"requires\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"The Memento Pattern requires an Originator object whose state is to be saved and restored.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"produces\",\"source\":\"CONC_001\",\"target\":\"CONC_003\",\"evidence\":\"The Memento Pattern produces Memento objects to store the state of the Originator.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"managed_by\",\"source\":\"CONC_001\",\"target\":\"CONC_004\",\"evidence\":\"The lifecycle of Mementos in the Memento Pattern is managed by the Caretaker.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"creates\",\"source\":\"CONC_002\",\"target\":\"CONC_003\",\"evidence\":\"The Originator creates a Memento object containing its internal state.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"restores\",\"source\":\"CONC_002\",\"target\":\"CONC_003\",\"evidence\":\"The Originator uses the Memento to restore its previous state.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"stores_state_of\",\"source\":\"CONC_003\",\"target\":\"CONC_002\",\"evidence\":\"The Memento stores the internal state of the Originator.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"manages\",\"source\":\"CONC_004\",\"target\":\"CONC_003\",\"evidence\":\"The Caretaker manages the storage and retrieval of Memento objects.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"implemented_by\",\"source\":\"CONC_006\",\"target\":\"CONC_001\",\"evidence\":\"The Undo Mechanism is implemented using the Memento Pattern.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"preserved_by\",\"source\":\"CONC_005\",\"target\":\"CONC_001\",\"evidence\":\"Encapsulation is preserved by the Memento Pattern through restricted state access.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"supports\",\"source\":\"CONC_007\",\"target\":\"CONC_005\",\"evidence\":\"Java Access Modifiers support the principle of Encapsulation.\",\"strength\":1,\"bidirectional\":false}]"', '2026-04-10 02:59:26.455431', '2026-04-10 02:59:26.455431', NULL, '[{"id": "module_1", "name": "Memento Pattern Fundamentals", "topic_count": 8}, {"id": "module_2", "name": "Basic Java Implementation", "topic_count": 7}, {"id": "module_3", "name": "Drawing Tool Case Study", "topic_count": 8}, {"id": "module_4", "name": "Text Editor Example & Advanced Concepts", "topic_count": 7}]', NULL, 'ITP4507 - Contemporary Topics 
