INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '23IIITLW005.pdf', '6c750947a6d95e5cd1cdd30210d996f8dd9ee0b01d90006409e1dca1e542e6ec', '{"chunks": [{"id": "CHUNK_001", "text": "IVE Information Technology\nInformation & Communications Technology Programme Board\nInstructions:\n(a) This paper has a total of ELEVEN pages including the covering page.\n(b) This paper contains FIVE questions.\n(c) Answer ALL questions. Each question is worth 20 marks.\nNote: The result of this assessment will not be counted if you do not meet the minimum attendance requirement (if any) governed by the general academic regulations of your programme/course unless approval of the campus principal has been granted.\nHIGHER DIPLOMA IN SOFTWARE ENGINEERING (IT114105)\nMODULE TITLE: ENTERPRISE SOFTWARE\nMODULE CODE: ITP4512\nSEMESTER TWO MAIN EXAMINATION\n08 MAY, 2024 1:30 PM TO 3:30 PM (2 hours)", "pages": [1], "end_pos": 598, "summary": "Exam cover page with instructions, module details, and administrative notes.", "start_pos": 0, "chunk_type": "administrative", "has_examples": false, "main_concepts": [], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Question 1\n(a) Your team has been tasked with designing new maps/levels for VOS’s new game, Galactic Wars. As work progresses, it becomes clear that there are multiple decisions needing to be made at different levels - strategic, tactical, and operational - to ensure this project succeeds.\nFor each of the following questions that ask for different information for decisions, state the level of decision making they are trying to make:\n(i) Should the game, Galactic Wars, focus on developing games exclusively for PC/console or expand into mobile phones as well?\n(ii) Should we invest resources in expanding additional single-player campaign, or focus resources on new multiplayer modes/maps in the new game?\n(iii) What art style should we use on armor and weapons in our new game to create meaningful player expression and a sense of progression?\n(iv) After the new game has been launched, support requests will be increased dramatically. Should we prioritize hiring more live chat agents or developing an AI chatbot to handle routine queries?\n(v) Should we prioritize upgrading our game servers and backend systems or invest in new frontend tools and features to improve the player experience?", "pages": [1, 2], "end_pos": 1426, "summary": "Scenario-based question assessing understanding of strategic, tactical, and operational decision levels in a game development context.", "start_pos": 599, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_001", "CONC_002", "CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "(b) DR is looking to implement the Marketing Mix to strengthen their marketing strategy and establish a significant market presence.\n(i) Name the 4P of Marketing Mix.\n(ii) Give one suggestion to any two sets of the 4P Marketing Mix for helping DR competitive in their market.\n(c) Customer Relationship Management (CRM) software is being implemented by DR to help manage relationships and interactions with game players.\nSuggest and briefly describe TWO features of CRM that help DR to improve the relationship with its customers (game players) and increase revenue.\n(d) DR is also considering the implementation of a Decision Support System (DSS) to enhance its management decision-making process.\n(i) What is the level of Decision Making that a DSS supports? Give one reason.\n(ii) Name three features of DSSs that help decision making in DR.", "pages": [2], "end_pos": 2268, "summary": "Questions on Marketing Mix (4Ps), CRM functionality, and DSS scope/features in a software studio context.", "start_pos": 1427, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_004", "CONC_005", "CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Question 2\n(a) Give the transaction codes of the following functions:\n(i) ABAP Editor\n(ii) General Table Display\n(iii) ABAP Dictionary\n(iv) Function Builder\n(b) Explain how SAP NetWeaver can integrate people, information and process.\n(c) Why ERP is important in a big company which involves cross-functional processes?\n(d) The system architecture of SAP involves 3 layers: Presentation Layer, Application Layer and Database Layer. Identify suitable LAYER to match the following descriptions.\n(i) Provides a user interface to the user for data input and output.\n(ii) Takes user requests and executes calculations and evaluations.\n(iii) Stores business data and source codes of the system programs.\n(iv) Distributes over multiple instances running on separate servers.\n(e) A company is planning to implement ISO 9000 family standards... Suggest a logistic module in SAP and describe its functions.", "pages": [2, 3], "end_pos": 3472, "summary": "SAP fundamentals: transaction codes, NetWeaver integration, ERP rationale, three-tier architecture, and logistics module alignment with ISO 9000.", "start_pos": 2269, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_011", "CONC_007", "CONC_008", "CONC_009"], "has_definitions": true, "secondary_concepts": ["CONC_010"]}, {"id": "CHUNK_005", "text": "Question 4\nA vendor, TechHub Ltd, created TWO ABAP tables called ZSALES and ZPRODUCT. ZSALES holds the information of sales details, and ZPRODUCT holds the information of products.\nTable ZSALES: MANDT, SAL_NO, SAL_DATE, PROD_SN, SAL_QTY\nTable ZPRODUCT: MANDT, PROD_SN, PROD_PRICE, CURR_CODE\n(a)(i) Suggest the primary keys for table ZSALES and table ZPRODUCT respectively.\n(ii) Which field in ZSALES and ZPRODUCT should be set as a foreign key? Please use select statement format...\n(iii) Suggest the type of table (Master or Transaction) for ZPRODUCT. Give a reason...\n(b) Complete the ABAP codes to create the selection screen as shown below for the ABAP program ZSALESMON...\n(c) Complete the following ABAP codes to generate a report using the selection screen in part (b)... SELECT ... FROM ... ON ... INTO ... WHERE ...", "pages": [5, 6], "end_pos": 5520, "summary": "ABAP data modeling (primary/foreign keys, master vs transaction), selection screen construction, and JOIN-based reporting.", "start_pos": 3473, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_012", "CONC_013", "CONC_014", "CONC_015", "CONC_016"], "has_definitions": true, "secondary_concepts": ["CONC_010"]}, {"id": "CHUNK_006", "text": "Question 5\n(a) The following shows the source code of a function module Z_FM_MEAL_PROFIT... Fill in the missing part from (i) to (vi) to complete the source code...\nConditions: If SellingPrice or NumberOfMealsSold or Costs ≤ 0 → Raise INPUT_ERROR\notherwise → Calculate TotalRevenue, TotalCost and MealProfit...", "pages": [7], "end_pos": 6150, "summary": "Function module development: interface definition, exception handling, and arithmetic logic in ABAP.", "start_pos": 5521, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_017"], "has_definitions": true, "secondary_concepts": ["CONC_010"]}, {"id": "CHUNK_007", "text": "Question 5 (b) The skeleton of the program is shown below as your hints. Fill in the missing parts (i) to (vii) of the program.\nREPORT Z_DAILY_PROFIT.\nDATA: MealProfit TYPE p, daily_profit TYPE p.\nWRITE: /''Meal Name'', 15 ''Selling Price'', 30 ''Costs'' .\nWRITE :38 ''Number of Meals sold'', 60 ''Meal Profit''.\n____(i)____\nDEFINE get_meal_profit.\nWRITE / __(ii)__ UNDER ''Meal Name''.\n... *Get MealProfit by calling Z_FM_MEAL_PROFIT\n___(iii)___\nIF SY-SUBRC EQ 1.\n WRITE ''Input error'' ...\nELSEIF SY-SUBRC = 0.\n WRITE ___(iv)___ ...\n daily_profit = daily_profit + MealProfit.\nENDIF.\n________(v)_______.\n_____(vi)_____: ''Donut'' ''22'' ''5'' ''150'', ...\nWRITE: ''Daily Profit is :'' , ____(vii)_____.", "pages": [9, 10], "end_pos": 7200, "summary": "ABAP program structure using macros to invoke function modules and aggregate results.", "start_pos": 6151, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_018"], "has_definitions": true, "secondary_concepts": ["CONC_010", "CONC_017"]}, {"id": "CHUNK_008", "text": "Question 3\na) Write down the output of the following ABAP program named Z_BASIC_ABAP_FORMATTING... REPORT Z_BASIC_ABAP_FORMATTING.\nCONSTANTS: n1 TYPE p DECIMALS 2 VALUE ''98.76''.\nDATA: c1 TYPE c LENGTH 14 VALUE ''Stud_Num.'', c2 TYPE c LENGTH 4 VALUE ''Score'', p1 TYPE p LENGTH 4 VALUE ''-1234''.\nWRITE: / c1 LEFT-JUSTIFIED, c2 RIGHT-JUSTIFIED.\nWRITE: / ''(Stud_Num)'' NO-GAP, ''(01)''.\nULINE /(5).\nWRITE: /3 ''#Chan Tai Man'', / ''test'', (4) n1 UNDER c2.\nWRITE: /2(3) p1 NO-SIGN.", "pages": [3], "end_pos": 3250, "summary": "ABAP output formatting concepts: alignment, spacing, underlining, and numeric display controls.", "start_pos": 2472, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_009", "text": "Question 3 b) Complete the following ABAP program z_loop to calculate factorials, squares, square roots and sum of numbers... REPORT z_loop NO STANDARD PAGE HEADING.\nDATA: n1 TYPE i VALUE 0, n2 TYPE i VALUE 1, n3 TYPE i, temp TYPE i.\n____(i)____ ''ITP4512'', 30 ''Value''.\nDO (iii) n3 = (iv) CASE n3. WHEN 4. WRITE: / ''Square root of'', 15(7) n3, ''is''. ... ENDWHILE. ... DO (ix) ... ENDDO. ... WRITE (8) n1 (xii) ''Value''.", "pages": [4], "end_pos": 4420, "summary": "ABAP control structures: DO loops, CASE statements, arithmetic computation, and formatted output.", "start_pos": 3251, "chunk_type": "question", "has_examples": true, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Strategic Decision Making", "aliases": ["top-level decision", "corporate decision"], "keywords": ["long-term", "executive", "platform strategy", "resource allocation"], "confidence": 1.0, "difficulty": 3, "description": "High-level decisions that define the long-term direction and scope of an organization. These involve resource allocation, market positioning, and competitive advantage. In the context of Digital Realms (DR), strategic decisions include platform expansion (e.g., PC/console vs. mobile), major investment priorities, and business model evolution. Strategic decisions are typically made by senior executives, require significant capital and time commitment, and have irreversible or costly-to-reverse consequences. They align with organizational vision and mission and often shape multi-year roadmaps.", "concept_type": "process", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_002", "title": "Tactical Decision Making", "aliases": ["operational planning", "functional decision"], "keywords": ["medium-term", "departmental", "feature prioritization", "budgeting"], "confidence": 1.0, "difficulty": 3, "description": "Mid-level decisions focused on implementing strategic goals through departmental or functional planning. Tactical decisions bridge strategy and operations, involving medium-term planning (e.g., 6–18 months), budgeting for specific initiatives, and prioritization within constrained resources. In DR’s context, tactical decisions include choosing between expanding single-player campaigns versus multiplayer modes — both supporting the strategic goal but requiring trade-offs in team capacity, timelines, and feature scope. These decisions are typically made by middle management and are revisable based on performance feedback.", "concept_type": "process", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_003", "title": "Operational Decision Making", "aliases": ["day-to-day decision", "execution decision"], "keywords": ["short-term", "execution", "support staffing", "infrastructure tuning"], "confidence": 1.0, "difficulty": 2, "description": "Day-to-day, short-term decisions concerning execution, efficiency, and responsiveness to immediate conditions. Operational decisions are highly structured, repetitive, and often automated or delegated. Examples at DR include staffing support channels post-launch (live chat agents vs. AI chatbot) or backend vs. frontend infrastructure investment — both aimed at maintaining service levels during live operations. These decisions are made by frontline managers or system rules, emphasize speed and consistency, and rely on real-time data such as ticket volume or server load metrics.", "concept_type": "process", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_001", "CONC_002"]}, {"id": "CONC_004", "title": "Marketing Mix (4Ps)", "aliases": ["Four Ps", "marketing variables"], "keywords": ["Product", "Price", "Place", "Promotion", "marketing framework"], "confidence": 1.0, "difficulty": 2, "description": "A foundational marketing framework consisting of Product, Price, Place, and Promotion — four controllable variables used to influence demand for a product or service. In DR’s context, the 4Ps guide how the game development company positions itself: Product (game features, platforms), Price (licensing fees, subscription models), Place (distribution via Steam, App Store, consoles), and Promotion (influencer campaigns, beta testing, community events). Each P must be aligned to deliver consistent value propositions and differentiate DR from competitors in the crowded gaming market.", "concept_type": "theory", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_005"]}, {"id": "CONC_005", "title": "Customer Relationship Management (CRM)", "aliases": ["CRM system", "customer data platform"], "keywords": ["customer data", "segmentation", "personalization", "retention"], "confidence": 1.0, "difficulty": 3, "description": "A business strategy supported by software systems to manage interactions with current and potential customers. CRM enables collection, analysis, and utilization of customer data across touchpoints (e.g., support tickets, purchase history, forum activity) to improve retention, satisfaction, and revenue. For DR, CRM features like behavioral segmentation and automated campaign triggers allow personalized engagement — e.g., offering exclusive skins to high-engagement players or win-back offers after inactivity — directly linking relationship quality to lifetime value and monetization.", "concept_type": "system", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_004", "CONC_006"]}, {"id": "CONC_006", "title": "Decision Support System (DSS)", "aliases": ["management support system"], "keywords": ["semi-structured decision", "data modeling", "interactive analysis", "what-if analysis"], "confidence": 1.0, "difficulty": 4, "description": "An interactive computer-based system designed to assist managers in making semi-structured or unstructured decisions using data analysis, modeling, and visualization tools. DSS supports tactical and strategic decision levels by integrating internal data (e.g., sales, support logs) with external inputs (e.g., market trends) to simulate outcomes. At DR, DSS helps evaluate trade-offs like backend upgrades vs. frontend features by modeling impact on player churn, session length, and support cost — thus augmenting human judgment with evidence-based insight rather than replacing it.", "concept_type": "system", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001", "CONC_002", "CONC_007"]}, {"id": "CONC_007", "title": "SAP NetWeaver", "aliases": ["NetWeaver platform"], "keywords": ["integration platform", "application server", "enterprise portal", "SOA"], "confidence": 1.0, "difficulty": 4, "description": "An integrated technology platform by SAP that enables interoperability among people, information, and business processes across heterogeneous systems. It provides application servers, integration brokers, portal frameworks, and development tools to unify ERP, CRM, SCM, and custom applications. NetWeaver supports cross-system workflows (e.g., syncing game sales data from DR’s storefront into SAP finance modules), real-time analytics dashboards for studio KPIs, and role-based portals for producers, QA leads, and marketing teams — thereby breaking down silos and enabling end-to-end process visibility.", "concept_type": "architecture", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_008", "CONC_009"]}, {"id": "CONC_008", "title": "ERP System", "aliases": ["enterprise system"], "keywords": ["unified database", "cross-functional integration", "real-time reporting", "compliance"], "confidence": 1.0, "difficulty": 3, "description": "Enterprise Resource Planning systems integrate core business functions (finance, HR, supply chain, manufacturing) into a unified database and software architecture. In large companies with cross-functional processes — e.g., game localization requiring coordination between engineering, legal, marketing, and regional sales — ERP eliminates redundant data entry, ensures transactional consistency (e.g., inventory sync across warehouses), and enables real-time reporting. Its importance lies in process standardization, regulatory compliance (e.g., ISO 9000), and scalability across geographies and product lines.", "concept_type": "system", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_007", "CONC_010"]}, {"id": "CONC_009", "title": "SAP Three-Tier Architecture", "aliases": ["three-tier model", "SAP architecture"], "keywords": ["presentation layer", "application layer", "database layer", "scalability"], "confidence": 1.0, "difficulty": 4, "description": "A foundational architectural pattern in SAP systems comprising Presentation Layer (user interface, e.g., SAP GUI or Fiori), Application Layer (business logic execution, ABAP processing, workflow engines), and Database Layer (persistent storage of business data and program source code in relational databases like HANA or Oracle). The layers are physically or logically separable, enabling scalability (e.g., load-balanced application servers), security (firewall segmentation), and maintainability (database upgrades without UI changes). Distribution across multiple instances enhances fault tolerance and performance under load.", "concept_type": "architecture", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_007", "CONC_010"]}, {"id": "CONC_010", "title": "ABAP Programming Language", "aliases": ["ABAP"], "keywords": ["SAP language", "report generation", "function module", "data dictionary"], "confidence": 1.0, "difficulty": 4, "description": "Advanced Business Application Programming (ABAP) is a high-level, fourth-generation programming language developed by SAP for building enterprise applications on the SAP NetWeaver platform. It supports procedural and object-oriented paradigms, integrates tightly with SAP data dictionary and transactional frameworks, and is used for custom reports (e.g., ZSALESMON), function modules (e.g., Z_FM_MEAL_PROFIT), and enhancements. ABAP syntax includes WRITE statements for output formatting, SELECT for database access, and modular constructs like macros and subroutines — all optimized for business logic over raw performance.", "concept_type": "component", "extracted_from": ["CHUNK_005", "CHUNK_006", "CHUNK_007", "CHUNK_008", "CHUNK_009"], "related_concepts": ["CONC_007", "CONC_009", "CONC_011"]}, {"id": "CONC_011", "title": "SAP Transaction Codes", "aliases": ["transaction code", "SAP shortcut"], "keywords": ["T-code", "SE38", "SE11", "SE16N", "SE37"], "confidence": 1.0, "difficulty": 2, "description": "Short alphanumeric codes used in SAP GUI to launch specific transactions or functions quickly. Each code maps to a program, report, or screen (e.g., SE38 for ABAP Editor, SE11 for ABAP Dictionary). Transaction codes streamline user navigation, enforce role-based access control, and serve as entry points for development, configuration, and data maintenance tasks. In exam contexts, knowing common T-codes reflects practical SAP fluency — for instance, SE16N for General Table Display enables ad-hoc data verification without coding.", "concept_type": "object", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_010", "CONC_009"]}, {"id": "CONC_012", "title": "Primary Key", "aliases": ["PK"], "keywords": ["uniqueness", "indexing", "referential integrity", "ABAP Dictionary"], "confidence": 1.0, "difficulty": 3, "description": "A unique identifier field or combination of fields that uniquely distinguishes each record in a database table. In ABAP Dictionary tables, primary keys ensure data integrity and enable efficient indexing and joins. For ZSALES, SAL_NO is the natural primary key (each sales order is distinct); for ZPRODUCT, PROD_SN serves this role (each product has a unique serial number). Primary keys cannot contain null values and must be immutable once set — critical for referential integrity when linking tables like ZSALES and ZPRODUCT.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_013", "CONC_014"]}, {"id": "CONC_013", "title": "Foreign Key", "aliases": ["FK"], "keywords": ["referential integrity", "JOIN condition", "dictionary constraint", "relationship"], "confidence": 1.0, "difficulty": 3, "description": "A field in one table that references the primary key of another table to establish a relationship and enforce referential integrity. In the ZSALES-ZPRODUCT schema, PROD_SN in ZSALES is a foreign key referencing PROD_SN in ZPRODUCT — ensuring every sales record corresponds to an existing product. In ABAP SQL, this is expressed via JOIN conditions (e.g., ''ON zsales-prod_sn = zproduct-prod_sn'') or foreign key relationships defined in the ABAP Dictionary, enabling automatic validation and cascading checks.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_012", "CONC_014"]}, {"id": "CONC_014", "title": "Master vs Transaction Table", "aliases": ["master table", "transaction table"], "keywords": ["master data", "transactional data", "data volatility", "reference data"], "confidence": 1.0, "difficulty": 3, "description": "A classification of SAP database tables based on data volatility and purpose. Master tables store relatively static, reference data shared across business processes (e.g., ZPRODUCT containing product descriptions and prices). Transaction tables store frequently changing, event-driven records (e.g., ZSALES capturing individual sales orders). ZPRODUCT is a master table because its content changes infrequently (product catalog updates), whereas ZSALES is transactional due to high-volume daily inserts. This distinction informs backup strategies, archiving policies, and performance optimization.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_012", "CONC_013"]}, {"id": "CONC_015", "title": "ABAP Selection Screen", "aliases": ["selection screen", "ABAP input screen"], "keywords": ["selection criteria", "PARAMETERS", "SELECT-OPTIONS", "TSCR"], "confidence": 1.0, "difficulty": 4, "description": "A customizable input interface in ABAP reports that allows users to specify selection criteria (e.g., date ranges, document numbers) before report execution. Built using statements like SELECT-OPTIONS and PARAMETERS, it supports validation, help views, and dynamic behavior. In ZSALESMON, the selection screen includes SALES_NO (single-value input) and PERIOD (date range), initialized via TSCR = ''Sales Records''. Selection screens decouple data filtering logic from report processing, enhance usability, and provide audit trails for parameterized outputs.", "concept_type": "component", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_010", "CONC_016"]}, {"id": "CONC_016", "title": "ABAP Report with JOIN", "aliases": ["ABAP join report"], "keywords": ["JOIN", "SELECT statement", "data enrichment", "aggregation"], "confidence": 1.0, "difficulty": 4, "description": "An executable ABAP program that retrieves and displays data by joining multiple database tables — typically using SELECT with INNER JOIN or FOR ALL ENTRIES. In ZSALESMON, the report joins ZSALES and ZPRODUCT on PROD_SN to compute ''Amount'' (Sales Quantity × Product Price) per sales record. The JOIN clause (''ON zsales-prod_sn = zproduct-prod_sn'') ensures only matching products are included; WHERE conditions filter by user-selected SALES_NO and PERIOD. This pattern exemplifies data enrichment and cross-table aggregation in enterprise reporting.", "concept_type": "process", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_010", "CONC_013", "CONC_015"]}, {"id": "CONC_017", "title": "ABAP Function Module", "aliases": ["function module", "FM"], "keywords": ["SE37", "CALL FUNCTION", "exception handling", "reusability"], "confidence": 1.0, "difficulty": 4, "description": "A reusable, encapsulated unit of ABAP code with defined interfaces (IMPORTING, EXPORTING, CHANGING, EXCEPTIONS) that performs a specific business task. Function modules like Z_FM_MEAL_PROFIT support modular design, error handling (e.g., INPUT_ERROR exception), and cross-program reuse. They are created via Function Builder (SE37), registered in the system, and called using CALL FUNCTION syntax. Their stateless nature and strict interface contracts make them ideal for calculations (e.g., profit), validations, and integrations — promoting consistency and testability.", "concept_type": "component", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_010", "CONC_018"]}, {"id": "CONC_018", "title": "ABAP Macro", "aliases": ["ABAP macro"], "keywords": ["DEFINE", "macro expansion", "code reuse", "compile-time"], "confidence": 1.0, "difficulty": 3, "description": "A named block of ABAP statements that can be reused within a program by invoking its name with parameters. Macros reduce code duplication and improve readability for repetitive logic — e.g., Z_DAILY_PROFIT uses a macro to standardize output formatting and function module calls for each meal item. Unlike subroutines or function modules, macros are expanded at compile time (not runtime), so they have no overhead but also lack parameter type safety. Best practices limit macros to simple, non-branching logic to avoid debugging complexity.", "concept_type": "component", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_010", "CONC_017"]}], "relationships": [{"id": "REL_001", "type": "before", "source": "CONC_001", "target": "CONC_002", "evidence": "Strategic decisions set the context for subsequent tactical ones (e.g., platform choice determines feature prioritization scope).", "strength": 0.95, "bidirectional": false}, {"id": "REL_002", "type": "before", "source": "CONC_002", "target": "CONC_003", "evidence": "Tactical plans guide operational execution (e.g., multiplayer mode roadmap dictates real-time support staffing needs).", "strength": 0.95, "bidirectional": false}, {"id": "REL_003", "type": "implements", "source": "CONC_004", "target": "CONC_005", "evidence": "CRM systems operationalize the 4Ps by enabling targeted promotions, price experimentation, channel analytics, and product feedback loops.", "strength": 0.9, "bidirectional": false}, {"id": "REL_004", "type": "requires", "source": "CONC_005", "target": "CONC_006", "evidence": "Effective CRM relies on DSS capabilities for segmentation modeling, churn prediction, and ROI analysis of marketing campaigns.", "strength": 0.85, "bidirectional": false}, {"id": "REL_005", "type": "part_of", "source": "CONC_007", "target": "CONC_008", "evidence": "SAP NetWeaver is the technical foundation upon which SAP ERP systems are built and extended.", "strength": 1.0, "bidirectional": false}, {"id": "REL_006", "type": "implements", "source": "CONC_007", "target": "CONC_009", "evidence": "NetWeaver''s architecture enforces and realizes the three-tier model across all SAP applications.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "supports", "source": "CONC_009", "target": "CONC_010", "evidence": "ABAP runs on the Application Layer of SAP''s three-tier architecture and accesses data via the Database Layer.", "strength": 0.95, "bidirectional": false}, {"id": "REL_008", "type": "uses", "source": "CONC_010", "target": "CONC_011", "evidence": "Transaction codes are the primary user-facing interface to execute ABAP programs and tools.", "strength": 0.95, "bidirectional": false}, {"id": "REL_009", "type": "enables", "source": "CONC_012", "target": "CONC_013", "evidence": "Primary keys are referenced by foreign keys to establish referential integrity between tables.", "strength": 0.95, "bidirectional": false}, {"id": "REL_010", "type": "part_of", "source": "CONC_013", "target": "CONC_014", "evidence": "Foreign key relationships are a defining characteristic distinguishing master and transaction tables in SAP data modeling.", "strength": 0.9, "bidirectional": false}, {"id": "REL_011", "type": "provides_input_for", "source": "CONC_015", "target": "CONC_016", "evidence": "The selection screen defines filters (e.g., PERIOD) used in the JOIN-based report logic.", "strength": 0.95, "bidirectional": false}, {"id": "REL_012", "type": "consumes", "source": "CONC_016", "target": "CONC_017", "evidence": "ZSALESMON report calls Z_FM_MEAL_PROFIT to compute derived values like ''Amount'', demonstrating inter-module dependency.", "strength": 0.85, "bidirectional": false}, {"id": "REL_013", "type": "called_by", "source": "CONC_017", "target": "CONC_018", "evidence": "Z_DAILY_PROFIT uses a macro to repeatedly call Z_FM_MEAL_PROFIT for multiple meal items.", "strength": 0.8, "bidirectional": false}], "quality_metrics": {"total_chunks": 9, "missing_links": [], "coverage_score": 1.0, "total_concepts": 18, "consistency_score": 1.0, "total_relationships": 13}, "document_metadata": {"title": "Enterprise Software (ITP4512) Main Examination", "language": "English", "main_topic": "Enterprise Software Systems with focus on SAP, ABAP programming, Decision Support, CRM, and Marketing Mix", "difficulty_level": "Advanced", "estimated_reading_time": "35 minutes"}, "concept_chunk_mapping": [{"concept": "Strategic Decision Making", "context": "Question 1(a)(i) explicitly asks about platform expansion decision level.", "chunk_id": "CHUNK_002", "positions": [784, 852], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Tactical Decision Making", "context": "Question 1(a)(ii) asks about campaign vs. multiplayer prioritization.", "chunk_id": "CHUNK_002", "positions": [853, 925], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Operational Decision Making", "context": "Question 1(a)(iv) addresses post-launch support staffing decisions.", "chunk_id": "CHUNK_002", "positions": [1048, 1130], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Marketing Mix (4Ps)", "context": "Question 1(b)(i) directly requests naming the 4Ps.", "chunk_id": "CHUNK_003", "positions": [2269, 2322], "concept_id": "CONC_004", "importance": "primary"}, {"concept": "Customer Relationship Management (CRM)", "context": "Question 1(c) asks for CRM features improving customer relationships.", "chunk_id": "CHUNK_003", "positions": [2323, 2410], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Decision Support System (DSS)", "context": "Question 1(d) asks about DSS decision level and features.", "chunk_id": "CHUNK_003", "positions": [2411, 2510], "concept_id": "CONC_006", "importance": "primary"}, {"concept": "SAP NetWeaver", "context": "Question 2(b) explicitly asks how NetWeaver integrates people, info, and process.", "chunk_id": "CHUNK_004", "positions": [2511, 2580], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "ERP System", "context": "Question 2(c) asks why ERP matters for cross-functional processes.", "chunk_id": "CHUNK_004", "positions": [2581, 2650], "concept_id": "CONC_008", "importance": "primary"}, {"concept": "SAP Three-Tier Architecture", "context": "Question 2(d) asks to map descriptions to Presentation/Application/Database layers.", "chunk_id": "CHUNK_004", "positions": [2651, 2750], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "ABAP Programming Language", "context": "Question 3(a) presents full ABAP program with formatting syntax.", "chunk_id": "CHUNK_008", "positions": [2472, 2520], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "SAP Transaction Codes", "context": "Question 2(a) asks for transaction codes of ABAP tools.", "chunk_id": "CHUNK_004", "positions": [2269, 2320], "concept_id": "CONC_011", "importance": "primary"}, {"concept": "Primary Key", "context": "Question 4(a)(i) asks to suggest primary keys for ZSALES and ZPRODUCT.", "chunk_id": "CHUNK_005", "positions": [3473, 3520], "concept_id": "CONC_012", "importance": "primary"}, {"concept": "Foreign Key", "context": "Question 4(a)(ii) asks which field should be set as foreign key with SELECT syntax.", "chunk_id": "CHUNK_005", "positions": [3521, 3620], "concept_id": "CONC_013", "importance": "primary"}, {"concept": "Master vs Transaction Table", "context": "Question 4(a)(iii) asks to classify ZPRODUCT as master or transaction.", "chunk_id": "CHUNK_005", "positions": [3621, 3720], "concept_id": "CONC_014", "importance": "primary"}, {"concept": "ABAP Selection Screen", "context": "Question 4(b) asks to complete ABAP code for selection screen.", "chunk_id": "CHUNK_005", "positions": [3721, 3820], "concept_id": "CONC_015", "importance": "primary"}, {"concept": "ABAP Report with JOIN", "context": "Question 4(c) requires completing SELECT ... ON ... JOIN logic.", "chunk_id": "CHUNK_005", "positions": [4421, 4520], "concept_id": "CONC_016", "importance": "primary"}, {"concept": "ABAP Function Module", "context": "Question 5(a) presents function module interface and exception logic.", "chunk_id": "CHUNK_006", "positions": [5521, 5620], "concept_id": "CONC_017", "importance": "primary"}, {"concept": "ABAP Macro", "context": "Question 5(b) asks to fill macro definition and invocation.", "chunk_id": "CHUNK_007", "positions": [6151, 6250], "concept_id": "CONC_018", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 18, "difficulty_score": 9, "total_structures": 22, "total_applications": 28}', '"[{\"id\":\"CHUNK_001\",\"text\":\"IVE Information Technology\\nInformation & Communications Technology Programme Board\\nInstructions:\\n(a) This paper has a total of ELEVEN pages including the covering page.\\n(b) This paper contains FIVE questions.\\n(c) Answer ALL questions. Each question is worth 20 marks.\\nNote: The result of this assessment will not be counted if you do not meet the minimum attendance requirement (if any) governed by the general academic regulations of your programme/course unless approval of the campus principal has been granted.\\nHIGHER DIPLOMA IN SOFTWARE ENGINEERING (IT114105)\\nMODULE TITLE: ENTERPRISE SOFTWARE\\nMODULE CODE: ITP4512\\nSEMESTER TWO MAIN EXAMINATION\\n08 MAY, 2024 1:30 PM TO 3:30 PM (2 hours)\",\"pages\":[1],\"start_pos\":0,\"end_pos\":598,\"summary\":\"Exam cover page with instructions, module details, and administrative notes.\",\"chunk_type\":\"administrative\",\"has_examples\":false,\"main_concepts\":[],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"Question 1\\n(a) Your team has been tasked with designing new maps/levels for VOS’s new game, Galactic Wars. As work progresses, it becomes clear that there are multiple decisions needing to be made at different levels - strategic, tactical, and operational - to ensure this project succeeds.\\nFor each of the following questions that ask for different information for decisions, state the level of decision making they are trying to make:\\n(i) Should the game, Galactic Wars, focus on developing games exclusively for PC/console or expand into mobile phones as well?\\n(ii) Should we invest resources in expanding additional single-player campaign, or focus resources on new multiplayer modes/maps in the new game?\\n(iii) What art style should we use on armor and weapons in our new game to create meaningful player expression and a sense of progression?\\n(iv) After the new game has been launched, support requests will be increased dramatically. Should we prioritize hiring more live chat agents or developing an AI chatbot to handle routine queries?\\n(v) Should we prioritize upgrading our game servers and backend systems or invest in new frontend tools and features to improve the player experience?\",\"pages\":[1,2],\"start_pos\":599,\"end_pos\":1426,\"summary\":\"Scenario-based question assessing understanding of strategic, tactical, and operational decision levels in a game development context.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"(b) DR is looking to implement the Marketing Mix to strengthen their marketing strategy and establish a significant market presence.\\n(i) Name the 4P of Marketing Mix.\\n(ii) Give one suggestion to any two sets of the 4P Marketing Mix for helping DR competitive in their market.\\n(c) Customer Relationship Management (CRM) software is being implemented by DR to help manage relationships and interactions with game players.\\nSuggest and briefly describe TWO features of CRM that help DR to improve the relationship with its customers (game players) and increase revenue.\\n(d) DR is also considering the implementation of a Decision Support System (DSS) to enhance its management decision-making process.\\n(i) What is the level of Decision Making that a DSS supports? Give one reason.\\n(ii) Name three features of DSSs that help decision making in DR.\",\"pages\":[2],\"start_pos\":1427,\"end_pos\":2268,\"summary\":\"Questions on Marketing Mix (4Ps), CRM functionality, and DSS scope/features in a software studio context.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_004\",\"CONC_005\",\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Question 2\\n(a) Give the transaction codes of the following functions:\\n(i) ABAP Editor\\n(ii) General Table Display\\n(iii) ABAP Dictionary\\n(iv) Function Builder\\n(b) Explain how SAP NetWeaver can integrate people, information and process.\\n(c) Why ERP is important in a big company which involves cross-functional processes?\\n(d) The system architecture of SAP involves 3 layers: Presentation Layer, Application Layer and Database Layer. Identify suitable LAYER to match the following descriptions.\\n(i) Provides a user interface to the user for data input and output.\\n(ii) Takes user requests and executes calculations and evaluations.\\n(iii) Stores business data and source codes of the system programs.\\n(iv) Distributes over multiple instances running on separate servers.\\n(e) A company is planning to implement ISO 9000 family standards... Suggest a logistic module in SAP and describe its functions.\",\"pages\":[2,3],\"start_pos\":2269,\"end_pos\":3472,\"summary\":\"SAP fundamentals: transaction codes, NetWeaver integration, ERP rationale, three-tier architecture, and logistics module alignment with ISO 9000.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_011\",\"CONC_007\",\"CONC_008\",\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\"]},{\"id\":\"CHUNK_005\",\"text\":\"Question 4\\nA vendor, TechHub Ltd, created TWO ABAP tables called ZSALES and ZPRODUCT. ZSALES holds the information of sales details, and ZPRODUCT holds the information of products.\\nTable ZSALES: MANDT, SAL_NO, SAL_DATE, PROD_SN, SAL_QTY\\nTable ZPRODUCT: MANDT, PROD_SN, PROD_PRICE, CURR_CODE\\n(a)(i) Suggest the primary keys for table ZSALES and table ZPRODUCT respectively.\\n(ii) Which field in ZSALES and ZPRODUCT should be set as a foreign key? Please use select statement format...\\n(iii) Suggest the type of table (Master or Transaction) for ZPRODUCT. Give a reason...\\n(b) Complete the ABAP codes to create the selection screen as shown below for the ABAP program ZSALESMON...\\n(c) Complete the following ABAP codes to generate a report using the selection screen in part (b)... SELECT ... FROM ... ON ... INTO ... WHERE ...\",\"pages\":[5,6],\"start_pos\":3473,\"end_pos\":5520,\"summary\":\"ABAP data modeling (primary/foreign keys, master vs transaction), selection screen construction, and JOIN-based reporting.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_012\",\"CONC_013\",\"CONC_014\",\"CONC_015\",\"CONC_016\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\"]},{\"id\":\"CHUNK_006\",\"text\":\"Question 5\\n(a) The following shows the source code of a function module Z_FM_MEAL_PROFIT... Fill in the missing part from (i) to (vi) to complete the source code...\\nConditions: If SellingPrice or NumberOfMealsSold or Costs ≤ 0 → Raise INPUT_ERROR\\notherwise → Calculate TotalRevenue, TotalCost and MealProfit...\",\"pages\":[7],\"start_pos\":5521,\"end_pos\":6150,\"summary\":\"Function module development: interface definition, exception handling, and arithmetic logic in ABAP.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_017\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\"]},{\"id\":\"CHUNK_007\",\"text\":\"Question 5 (b) The skeleton of the program is shown below as your hints. Fill in the missing parts (i) to (vii) of the program.\\nREPORT Z_DAILY_PROFIT.\\nDATA: MealProfit TYPE p, daily_profit TYPE p.\\nWRITE: /''Meal Name'', 15 ''Selling Price'', 30 ''Costs'' .\\nWRITE :38 ''Number of Meals sold'', 60 ''Meal Profit''.\\n____(i)____\\nDEFINE get_meal_profit.\\nWRITE / __(ii)__ UNDER ''Meal Name''.\\n... *Get MealProfit by calling Z_FM_MEAL_PROFIT\\n___(iii)___\\nIF SY-SUBRC EQ 1.\\n WRITE ''Input error'' ...\\nELSEIF SY-SUBRC = 0.\\n WRITE ___(iv)___ ...\\n daily_profit = daily_profit + MealProfit.\\nENDIF.\\n________(v)_______.\\n_____(vi)_____: ''Donut'' ''22'' ''5'' ''150'', ...\\nWRITE: ''Daily Profit is :'' , ____(vii)_____.\",\"pages\":[9,10],\"start_pos\":6151,\"end_pos\":7200,\"summary\":\"ABAP program structure using macros to invoke function modules and aggregate results.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_018\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_010\",\"CONC_017\"]},{\"id\":\"CHUNK_008\",\"text\":\"Question 3\\na) Write down the output of the following ABAP program named Z_BASIC_ABAP_FORMATTING... REPORT Z_BASIC_ABAP_FORMATTING.\\nCONSTANTS: n1 TYPE p DECIMALS 2 VALUE ''98.76''.\\nDATA: c1 TYPE c LENGTH 14 VALUE ''Stud_Num.'', c2 TYPE c LENGTH 4 VALUE ''Score'', p1 TYPE p LENGTH 4 VALUE ''-1234''.\\nWRITE: / c1 LEFT-JUSTIFIED, c2 RIGHT-JUSTIFIED.\\nWRITE: / ''(Stud_Num)'' NO-GAP, ''(01)''.\\nULINE /(5).\\nWRITE: /3 ''#Chan Tai Man'', / ''test'', (4) n1 UNDER c2.\\nWRITE: /2(3) p1 NO-SIGN.\",\"pages\":[3],\"start_pos\":2472,\"end_pos\":3250,\"summary\":\"ABAP output formatting concepts: alignment, spacing, underlining, and numeric display controls.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_009\",\"text\":\"Question 3 b) Complete the following ABAP program z_loop to calculate factorials, squares, square roots and sum of numbers... REPORT z_loop NO STANDARD PAGE HEADING.\\nDATA: n1 TYPE i VALUE 0, n2 TYPE i VALUE 1, n3 TYPE i, temp TYPE i.\\n____(i)____ ''ITP4512'', 30 ''Value''.\\nDO (iii) n3 = (iv) CASE n3. WHEN 4. WRITE: / ''Square root of'', 15(7) n3, ''is''. ... ENDWHILE. ... DO (ix) ... ENDDO. ... WRITE (8) n1 (xii) ''Value''.\",\"pages\":[4],\"start_pos\":3251,\"end_pos\":4420,\"summary\":\"ABAP control structures: DO loops, CASE statements, arithmetic computation, and formatted output.\",\"chunk_type\":\"question\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\"],\"has_definitions\":true,\"secondary_concepts\":[]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Strategic Decision Making\",\"aliases\":[\"top-level decision\",\"corporate decision\"],\"keywords\":[\"long-term\",\"executive\",\"platform strategy\",\"resource allocation\"],\"confidence\":1,\"difficulty\":3,\"description\":\"High-level decisions that define the long-term direction and scope of an organization. These involve resource allocation, market positioning, and competitive advantage. In the context of Digital Realms (DR), strategic decisions include platform expansion (e.g., PC/console vs. mobile), major investment priorities, and business model evolution. Strategic decisions are typically made by senior executives, require significant capital and time commitment, and have irreversible or costly-to-reverse consequences. They align with organizational vision and mission and often shape multi-year roadmaps.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_002\",\"CONC_003\"]},{\"id\":\"CONC_002\",\"title\":\"Tactical Decision Making\",\"aliases\":[\"operational planning\",\"functional decision\"],\"keywords\":[\"medium-term\",\"departmental\",\"feature prioritization\",\"budgeting\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Mid-level decisions focused on implementing strategic goals through departmental or functional planning. Tactical decisions bridge strategy and operations, involving medium-term planning (e.g., 6–18 months), budgeting for specific initiatives, and prioritization within constrained resources. In DR’s context, tactical decisions include choosing between expanding single-player campaigns versus multiplayer modes — both supporting the strategic goal but requiring trade-offs in team capacity, timelines, and feature scope. These decisions are typically made by middle management and are revisable based on performance feedback.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CONC_003\",\"title\":\"Operational Decision Making\",\"aliases\":[\"day-to-day decision\",\"execution decision\"],\"keywords\":[\"short-term\",\"execution\",\"support staffing\",\"infrastructure tuning\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Day-to-day, short-term decisions concerning execution, efficiency, and responsiveness to immediate conditions. Operational decisions are highly structured, repetitive, and often automated or delegated. Examples at DR include staffing support channels post-launch (live chat agents vs. AI chatbot) or backend vs. frontend infrastructure investment — both aimed at maintaining service levels during live operations. These decisions are made by frontline managers or system rules, emphasize speed and consistency, and rely on real-time data such as ticket volume or server load metrics.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_002\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\"]},{\"id\":\"CONC_004\",\"title\":\"Marketing Mix (4Ps)\",\"aliases\":[\"Four Ps\",\"marketing variables\"],\"keywords\":[\"Product\",\"Price\",\"Place\",\"Promotion\",\"marketing framework\"],\"confidence\":1,\"difficulty\":2,\"description\":\"A foundational marketing framework consisting of Product, Price, Place, and Promotion — four controllable variables used to influence demand for a product or service. In DR’s context, the 4Ps guide how the game development company positions itself: Product (game features, platforms), Price (licensing fees, subscription models), Place (distribution via Steam, App Store, consoles), and Promotion (influencer campaigns, beta testing, community events). Each P must be aligned to deliver consistent value propositions and differentiate DR from competitors in the crowded gaming market.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_005\"]},{\"id\":\"CONC_005\",\"title\":\"Customer Relationship Management (CRM)\",\"aliases\":[\"CRM system\",\"customer data platform\"],\"keywords\":[\"customer data\",\"segmentation\",\"personalization\",\"retention\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A business strategy supported by software systems to manage interactions with current and potential customers. CRM enables collection, analysis, and utilization of customer data across touchpoints (e.g., support tickets, purchase history, forum activity) to improve retention, satisfaction, and revenue. For DR, CRM features like behavioral segmentation and automated campaign triggers allow personalized engagement — e.g., offering exclusive skins to high-engagement players or win-back offers after inactivity — directly linking relationship quality to lifetime value and monetization.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_004\",\"CONC_006\"]},{\"id\":\"CONC_006\",\"title\":\"Decision Support System (DSS)\",\"aliases\":[\"management support system\"],\"keywords\":[\"semi-structured decision\",\"data modeling\",\"interactive analysis\",\"what-if analysis\"],\"confidence\":1,\"difficulty\":4,\"description\":\"An interactive computer-based system designed to assist managers in making semi-structured or unstructured decisions using data analysis, modeling, and visualization tools. DSS supports tactical and strategic decision levels by integrating internal data (e.g., sales, support logs) with external inputs (e.g., market trends) to simulate outcomes. At DR, DSS helps evaluate trade-offs like backend upgrades vs. frontend features by modeling impact on player churn, session length, and support cost — thus augmenting human judgment with evidence-based insight rather than replacing it.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_001\",\"CONC_002\",\"CONC_007\"]},{\"id\":\"CONC_007\",\"title\":\"SAP NetWeaver\",\"aliases\":[\"NetWeaver platform\"],\"keywords\":[\"integration platform\",\"application server\",\"enterprise portal\",\"SOA\"],\"confidence\":1,\"difficulty\":4,\"description\":\"An integrated technology platform by SAP that enables interoperability among people, information, and business processes across heterogeneous systems. It provides application servers, integration brokers, portal frameworks, and development tools to unify ERP, CRM, SCM, and custom applications. NetWeaver supports cross-system workflows (e.g., syncing game sales data from DR’s storefront into SAP finance modules), real-time analytics dashboards for studio KPIs, and role-based portals for producers, QA leads, and marketing teams — thereby breaking down silos and enabling end-to-end process visibility.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_008\",\"CONC_009\"]},{\"id\":\"CONC_008\",\"title\":\"ERP System\",\"aliases\":[\"enterprise system\"],\"keywords\":[\"unified database\",\"cross-functional integration\",\"real-time reporting\",\"compliance\"],\"confidence\":1,\"difficulty\":3,\"description\":\"Enterprise Resource Planning systems integrate core business functions (finance, HR, supply chain, manufacturing) into a unified database and software architecture. In large companies with cross-functional processes — e.g., game localization requiring coordination between engineering, legal, marketing, and regional sales — ERP eliminates redundant data entry, ensures transactional consistency (e.g., inventory sync across warehouses), and enables real-time reporting. Its importance lies in process standardization, regulatory compliance (e.g., ISO 9000), and scalability across geographies and product lines.\",\"concept_type\":\"system\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_007\",\"CONC_010\"]},{\"id\":\"CONC_009\",\"title\":\"SAP Three-Tier Architecture\",\"aliases\":[\"three-tier model\",\"SAP architecture\"],\"keywords\":[\"presentation layer\",\"application layer\",\"database layer\",\"scalability\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A foundational architectural pattern in SAP systems comprising Presentation Layer (user interface, e.g., SAP GUI or Fiori), Application Layer (business logic execution, ABAP processing, workflow engines), and Database Layer (persistent storage of business data and program source code in relational databases like HANA or Oracle). The layers are physically or logically separable, enabling scalability (e.g., load-balanced application servers), security (firewall segmentation), and maintainability (database upgrades without UI changes). Distribution across multiple instances enhances fault tolerance and performance under load.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_007\",\"CONC_010\"]},{\"id\":\"CONC_010\",\"title\":\"ABAP Programming Language\",\"aliases\":[\"ABAP\"],\"keywords\":[\"SAP language\",\"report generation\",\"function module\",\"data dictionary\"],\"confidence\":1,\"difficulty\":4,\"description\":\"Advanced Business Application Programming (ABAP) is a high-level, fourth-generation programming language developed by SAP for building enterprise applications on the SAP NetWeaver platform. It supports procedural and object-oriented paradigms, integrates tightly with SAP data dictionary and transactional frameworks, and is used for custom reports (e.g., ZSALESMON), function modules (e.g., Z_FM_MEAL_PROFIT), and enhancements. ABAP syntax includes WRITE statements for output formatting, SELECT for database access, and modular constructs like macros and subroutines — all optimized for business logic over raw performance.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_005\",\"CHUNK_006\",\"CHUNK_007\",\"CHUNK_008\",\"CHUNK_009\"],\"related_concepts\":[\"CONC_007\",\"CONC_009\",\"CONC_011\"]},{\"id\":\"CONC_011\",\"title\":\"SAP Transaction Codes\",\"aliases\":[\"transaction code\",\"SAP shortcut\"],\"keywords\":[\"T-code\",\"SE38\",\"SE11\",\"SE16N\",\"SE37\"],\"confidence\":1,\"difficulty\":2,\"description\":\"Short alphanumeric codes used in SAP GUI to launch specific transactions or functions quickly. Each code maps to a program, report, or screen (e.g., SE38 for ABAP Editor, SE11 for ABAP Dictionary). Transaction codes streamline user navigation, enforce role-based access control, and serve as entry points for development, configuration, and data maintenance tasks. In exam contexts, knowing common T-codes reflects practical SAP fluency — for instance, SE16N for General Table Display enables ad-hoc data verification without coding.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_010\",\"CONC_009\"]},{\"id\":\"CONC_012\",\"title\":\"Primary Key\",\"aliases\":[\"PK\"],\"keywords\":[\"uniqueness\",\"indexing\",\"referential integrity\",\"ABAP Dictionary\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A unique identifier field or combination of fields that uniquely distinguishes each record in a database table. In ABAP Dictionary tables, primary keys ensure data integrity and enable efficient indexing and joins. For ZSALES, SAL_NO is the natural primary key (each sales order is distinct); for ZPRODUCT, PROD_SN serves this role (each product has a unique serial number). Primary keys cannot contain null values and must be immutable once set — critical for referential integrity when linking tables like ZSALES and ZPRODUCT.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_013\",\"CONC_014\"]},{\"id\":\"CONC_013\",\"title\":\"Foreign Key\",\"aliases\":[\"FK\"],\"keywords\":[\"referential integrity\",\"JOIN condition\",\"dictionary constraint\",\"relationship\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A field in one table that references the primary key of another table to establish a relationship and enforce referential integrity. In the ZSALES-ZPRODUCT schema, PROD_SN in ZSALES is a foreign key referencing PROD_SN in ZPRODUCT — ensuring every sales record corresponds to an existing product. In ABAP SQL, this is expressed via JOIN conditions (e.g., ''ON zsales-prod_sn = zproduct-prod_sn'') or foreign key relationships defined in the ABAP Dictionary, enabling automatic validation and cascading checks.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_012\",\"CONC_014\"]},{\"id\":\"CONC_014\",\"title\":\"Master vs Transaction Table\",\"aliases\":[\"master table\",\"transaction table\"],\"keywords\":[\"master data\",\"transactional data\",\"data volatility\",\"reference data\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A classification of SAP database tables based on data volatility and purpose. Master tables store relatively static, reference data shared across business processes (e.g., ZPRODUCT containing product descriptions and prices). Transaction tables store frequently changing, event-driven records (e.g., ZSALES capturing individual sales orders). ZPRODUCT is a master table because its content changes infrequently (product catalog updates), whereas ZSALES is transactional due to high-volume daily inserts. This distinction informs backup strategies, archiving policies, and performance optimization.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_012\",\"CONC_013\"]},{\"id\":\"CONC_015\",\"title\":\"ABAP Selection Screen\",\"aliases\":[\"selection screen\",\"ABAP input screen\"],\"keywords\":[\"selection criteria\",\"PARAMETERS\",\"SELECT-OPTIONS\",\"TSCR\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A customizable input interface in ABAP reports that allows users to specify selection criteria (e.g., date ranges, document numbers) before report execution. Built using statements like SELECT-OPTIONS and PARAMETERS, it supports validation, help views, and dynamic behavior. In ZSALESMON, the selection screen includes SALES_NO (single-value input) and PERIOD (date range), initialized via TSCR = ''Sales Records''. Selection screens decouple data filtering logic from report processing, enhance usability, and provide audit trails for parameterized outputs.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_010\",\"CONC_016\"]},{\"id\":\"CONC_016\",\"title\":\"ABAP Report with JOIN\",\"aliases\":[\"ABAP join report\"],\"keywords\":[\"JOIN\",\"SELECT statement\",\"data enrichment\",\"aggregation\"],\"confidence\":1,\"difficulty\":4,\"description\":\"An executable ABAP program that retrieves and displays data by joining multiple database tables — typically using SELECT with INNER JOIN or FOR ALL ENTRIES. In ZSALESMON, the report joins ZSALES and ZPRODUCT on PROD_SN to compute ''Amount'' (Sales Quantity × Product Price) per sales record. The JOIN clause (''ON zsales-prod_sn = zproduct-prod_sn'') ensures only matching products are included; WHERE conditions filter by user-selected SALES_NO and PERIOD. This pattern exemplifies data enrichment and cross-table aggregation in enterprise reporting.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_010\",\"CONC_013\",\"CONC_015\"]},{\"id\":\"CONC_017\",\"title\":\"ABAP Function Module\",\"aliases\":[\"function module\",\"FM\"],\"keywords\":[\"SE37\",\"CALL FUNCTION\",\"exception handling\",\"reusability\"],\"confidence\":1,\"difficulty\":4,\"description\":\"A reusable, encapsulated unit of ABAP code with defined interfaces (IMPORTING, EXPORTING, CHANGING, EXCEPTIONS) that performs a specific business task. Function modules like Z_FM_MEAL_PROFIT support modular design, error handling (e.g., INPUT_ERROR exception), and cross-program reuse. They are created via Function Builder (SE37), registered in the system, and called using CALL FUNCTION syntax. Their stateless nature and strict interface contracts make them ideal for calculations (e.g., profit), validations, and integrations — promoting consistency and testability.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_006\",\"CHUNK_007\"],\"related_concepts\":[\"CONC_010\",\"CONC_018\"]},{\"id\":\"CONC_018\",\"title\":\"ABAP Macro\",\"aliases\":[\"ABAP macro\"],\"keywords\":[\"DEFINE\",\"macro expansion\",\"code reuse\",\"compile-time\"],\"confidence\":1,\"difficulty\":3,\"description\":\"A named block of ABAP statements that can be reused within a program by invoking its name with parameters. Macros reduce code duplication and improve readability for repetitive logic — e.g., Z_DAILY_PROFIT uses a macro to standardize output formatting and function module calls for each meal item. Unlike subroutines or function modules, macros are expanded at compile time (not runtime), so they have no overhead but also lack parameter type safety. Best practices limit macros to simple, non-branching logic to avoid debugging complexity.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_010\",\"CONC_017\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"before\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"Strategic decisions set the context for subsequent tactical ones (e.g., platform choice determines feature prioritization scope).\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"before\",\"source\":\"CONC_002\",\"target\":\"CONC_003\",\"evidence\":\"Tactical plans guide operational execution (e.g., multiplayer mode roadmap dictates real-time support staffing needs).\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"implements\",\"source\":\"CONC_004\",\"target\":\"CONC_005\",\"evidence\":\"CRM systems operationalize the 4Ps by enabling targeted promotions, price experimentation, channel analytics, and product feedback loops.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"requires\",\"source\":\"CONC_005\",\"target\":\"CONC_006\",\"evidence\":\"Effective CRM relies on DSS capabilities for segmentation modeling, churn prediction, and ROI analysis of marketing campaigns.\",\"strength\":0.85,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"part_of\",\"source\":\"CONC_007\",\"target\":\"CONC_008\",\"evidence\":\"SAP NetWeaver is the technical foundation upon which SAP ERP systems are built and extended.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"implements\",\"source\":\"CONC_007\",\"target\":\"CONC_009\",\"evidence\":\"NetWeaver''s architecture enforces and realizes the three-tier model across all SAP applications.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"supports\",\"source\":\"CONC_009\",\"target\":\"CONC_010\",\"evidence\":\"ABAP runs on the Application Layer of SAP''s three-tier architecture and accesses data via the Database Layer.\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_008\",\"type\":\"uses\",\"source\":\"CONC_010\",\"target\":\"CONC_011\",\"evidence\":\"Transaction codes are the primary user-facing interface to execute ABAP programs and tools.\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_009\",\"type\":\"enables\",\"source\":\"CONC_012\",\"target\":\"CONC_013\",\"evidence\":\"Primary keys are referenced by foreign keys to establish referential integrity between tables.\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_010\",\"type\":\"part_of\",\"source\":\"CONC_013\",\"target\":\"CONC_014\",\"evidence\":\"Foreign key relationships are a defining characteristic distinguishing master and transaction tables in SAP data modeling.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_011\",\"type\":\"provides_input_for\",\"source\":\"CONC_015\",\"target\":\"CONC_016\",\"evidence\":\"The selection screen defines filters (e.g., PERIOD) used in the JOIN-based report logic.\",\"strength\":0.95,\"bidirectional\":false},{\"id\":\"REL_012\",\"type\":\"consumes\",\"source\":\"CONC_016\",\"target\":\"CONC_017\",\"evidence\":\"ZSALESMON report calls Z_FM_MEAL_PROFIT to compute derived values like ''Amount'', demonstrating inter-module dependency.\",\"strength\":0.85,\"bidirectional\":false},{\"id\":\"REL_013\",\"type\":\"called_by\",\"source\":\"CONC_017\",\"target\":\"CONC_018\",\"evidence\":\"Z_DAILY_PROFIT uses a macro to repeatedly call Z_FM_MEAL_PROFIT for multiple meal items.\",\"strength\":0.8,\"bidirectional\":false}]"', '2026-04-05 03:27:32.11172', '2026-04-05 03:27:32.11172', NULL, '[{"id": "module_1", "name": "Enterprise Systems & Business Concepts", "topic_count": 15}, {"id": "module_2", "name": "SAP Architecture & ABAP Fundamentals", "topic_count": 18}, {"id": "module_3", "name": "ABAP Programming & Control Structures", "topic_count": 12}, {"id": "module_4", "name": "Database Design & ABAP Reporting", "topic_count": 14}, {"id": "module_5", "name": "Function Modules & Modular Programming", "topic_count": 11}]', NULL, 'IVE Information Technology 
