INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '22IIITLW007.pdf', '975c2117279abf3781d6b17466a328b16341f215ad57572a36755d3017e51e39', '{"chunks": [{"id": "CHUNK_001", "text": "Cover Page: IVE Information Technology, Higher Diploma in Software Engineering, Module Title: ENTERPRISE SOFTWARE, Code: ITP4512, Date: 5 MAY, 2023, Duration: 2 hours. Total ELEVEN pages, FIVE questions, 20 marks each.", "pages": [1], "end_pos": 150, "summary": "Examination cover page details.", "start_pos": 0, "chunk_type": "metadata", "has_examples": false, "main_concepts": [], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Question 1: Scenario involving interior design company GL and hotel chain ASG. Discusses levels of decision making (Strategic, Tactical, Operational). Asks for FOUR functions of business management. Introduces Customer Relationship Management (CRM) features to improve revenue and relationships. Discusses Decision Support System (DSS) level of support and three helpful features.", "pages": [2], "end_pos": 850, "summary": "Exam question on management concepts (DSS, CRM, Decision Levels).", "start_pos": 150, "chunk_type": "question_content", "has_examples": true, "main_concepts": ["CONC_002", "CONC_003", "CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Question 2: Defines ERP System and examples. Case study of GoFirst Company Ltd upgrading financial operations. Asks for TWO SAP financial modules (Accounts Payable/Receivable, Sales Profitability). Asks about Work Process composition in Application Layer and types. Requests Transaction Codes for Message Maintenance, ABAP Editor, Function Builder, ABAP Dictionary.", "pages": [3], "end_pos": 1550, "summary": "Exam question on ERP architecture and SAP technical components.", "start_pos": 850, "chunk_type": "question_content", "has_examples": true, "main_concepts": ["CONC_001", "CONC_005"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Question 3a: ABAP output analysis for REPORT Z_BASIC_ABAP_FORMATTING. Includes constants, variables, and WRITE statements with justification options. Question 3b: Code completion for z_loop to calculate factorials, squares, square roots. Involves DO loops, CASE statements, arithmetic operations, and nested WHILE loops for summation.", "pages": [4], "end_pos": 2250, "summary": "ABAP logic and formatting exercises.", "start_pos": 1550, "chunk_type": "coding_task", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Question 4: Two ABAP tables ZINV (Invoices) and ZPROD (Products). Defines columns including Client Number, Invoice/Product Numbers, Quantity, Currency. Asks for Foreign Keys, Reference tables for Currency/Quantity, Master vs Transaction table type. Requires Selection Screen coding and Open SQL statement joining ZINV and ZPROD based on criteria.", "pages": [5, 6], "end_pos": 2950, "summary": "Database schema definition and SQL query construction.", "start_pos": 2250, "chunk_type": "database_design", "has_examples": true, "main_concepts": ["CONC_004", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "Question 5: Creates function module Z_FM_FRUIT_PRICE logic (cost calculation tiers, exception handling if cost <= 0). Requires filling logic into source code. Follow-up program Z_FRUIT_SELLING_PRICE calls the function module. Uses macro cal_selling_price to display Fruit Name, Cost, Selling Price or ''cost error''.", "pages": [7, 8, 9, 10], "end_pos": 3650, "summary": "Function module creation and macro usage in reporting.", "start_pos": 2950, "chunk_type": "function_development", "has_examples": true, "main_concepts": ["CONC_004", "CONC_008", "CONC_009"], "has_definitions": true, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Enterprise Resource Planning (ERP)", "aliases": ["ERP System", "Integrated Software Suite"], "keywords": ["ERP", "SAP", "Financial Module", "Business Process"], "confidence": 0.95, "difficulty": 3, "description": "A category of business-management software typically a suite of integrated applications that an organization uses to collect, store, manage, and interpret data from many business activities. Examples include managing supply chain operations, sales, manufacturing, and inventory management.", "concept_type": "component", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_007", "CONC_008"]}, {"id": "CONC_002", "title": "Decision Support System (DSS)", "aliases": ["Decision Support System"], "keywords": ["DSS", "Decision Making", "Tactical Level", "Analytics"], "confidence": 0.95, "difficulty": 3, "description": "An information system that supports business or organizational decision-making activities. DSSs serve the management, operations, and professional levels of an organization. They typically support semi-structured and unstructured decision-making problems.", "concept_type": "component", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_006"]}, {"id": "CONC_003", "title": "Customer Relationship Management (CRM)", "aliases": ["Customer Relationship Management"], "keywords": ["CRM", "Customer Interaction", "Revenue", "Sales"], "confidence": 0.95, "difficulty": 2, "description": "A technology for managing all your company''s relationships and interactions with current and potential customers. The goal is to improve business relationships, grow sales, and increase profitability by centralizing customer information.", "concept_type": "component", "extracted_from": ["CHUNK_002"], "related_concepts": []}, {"id": "CONC_004", "title": "ABAP Programming", "aliases": ["ABAP Language"], "keywords": ["ABAP", "Report Program", "Function Module", "Data Dictionary"], "confidence": 0.95, "difficulty": 4, "description": "Advanced Business Application Programming, the proprietary programming language used to develop custom programs and reports within the SAP ERP environment. It handles database access, logic processing, and interface design for enterprise solutions.", "concept_type": "process", "extracted_from": ["CHUNK_004", "CHUNK_005", "CHUNK_006"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_005", "title": "SAP Work Process", "aliases": ["SAP Process"], "keywords": ["Work Process", "Application Layer", "Dialog", "Background"], "confidence": 0.9, "difficulty": 3, "description": "A work process in the SAP Application Layer processes requests. Types include Dialog, Update, Enqueue, Background, Spool, Message, Batch Input, and Update 1/2. Each handles specific tasks like user interaction or data consistency.", "concept_type": "component", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_004"]}, {"id": "CONC_006", "title": "Decision Levels", "aliases": ["Levels of Decision Making"], "keywords": ["Strategic", "Tactical", "Operational", "Management"], "confidence": 0.95, "difficulty": 2, "description": "Hierarchical levels of decision making in organizations: Strategic (long-term planning), Tactical (mid-range resource allocation), and Operational (day-to-day execution). Different systems support different levels.", "concept_type": "theory", "extracted_from": ["CHUNK_002"], "related_concepts": ["CONC_002"]}, {"id": "CONC_007", "title": "Database Table Definitions", "aliases": ["ABAP Dictionary Table"], "keywords": ["Table Type", "Foreign Key", "Master Data", "Transaction Data", "Open SQL"], "confidence": 0.95, "difficulty": 3, "description": "Structures defining data storage including client number, primary keys, foreign keys, currency fields, and quantity fields. Crucial for integrity in SAP systems (e.g., ZINV, ZPROD tables).", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_004", "CONC_009"]}, {"id": "CONC_008", "title": "Function Module", "aliases": ["FM", "BAPI"], "keywords": ["Function Module", "CALL FUNCTION", "Exception Handling", "Syntax"], "confidence": 0.95, "difficulty": 4, "description": "Reusable program objects in ABAP that encapsulate business logic. They allow passing parameters via Importing, Exporting, Changing, and Tables interfaces, and can raise exceptions to handle errors globally.", "concept_type": "component", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_004"]}, {"id": "CONC_009", "title": "Macro Definition", "aliases": ["ABAP Macro"], "keywords": ["Macro", "DEFINE", "Code Reuse"], "confidence": 0.9, "difficulty": 3, "description": "Code snippets defined in ABAP using DEFINE...ENDOFDEFINITION to reduce repetition and simplify report logic. Macros are processed before compilation.", "concept_type": "process", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_004"]}], "relationships": [{"id": "REL_001", "type": "supports", "source": "CONC_002", "target": "CONC_006", "evidence": "Question 1(d) asks about the level of Decision Making that a DSS supports.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "implements", "source": "CONC_003", "target": "CONC_001", "evidence": "CRM is described as strategic software used to manage relationships, often part of broader Enterprise Software suites.", "strength": 0.8, "bidirectional": false}, {"id": "REL_003", "type": "uses", "source": "CONC_004", "target": "CONC_008", "evidence": "Function modules are called within ABAP programs (Question 5).", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "interacts_with", "source": "CONC_004", "target": "CONC_007", "evidence": "ABAP code defines and queries table structures (Questions 3 & 4).", "strength": 1.0, "bidirectional": true}, {"id": "REL_005", "type": "references", "source": "CONC_007", "target": "CONC_009", "evidence": "Both utilize logical definitions within ABAP programs to structure data flow.", "strength": 0.5, "bidirectional": false}, {"id": "REL_006", "type": "part_of", "source": "CONC_005", "target": "CONC_001", "evidence": "Work processes exist in the Application Layer of the ERP system architecture.", "strength": 1.0, "bidirectional": false}, {"id": "REL_007", "type": "similar_to", "source": "CONC_008", "target": "CONC_009", "evidence": "Both are mechanisms for code abstraction and reuse, though one is a runtime call and one is pre-processing substitution.", "strength": 0.6, "bidirectional": true}, {"id": "REL_008", "type": "influences", "source": "CONC_006", "target": "CONC_003", "evidence": "Strategic decisions influence CRM implementation goals.", "strength": 0.7, "bidirectional": false}], "quality_metrics": {"total_chunks": 6, "missing_links": ["Mapping between Business Functions and Specific Roles in Q1(b)"], "coverage_score": 0.95, "total_concepts": 9, "consistency_score": 0.98, "total_relationships": 8}, "document_metadata": {"title": "Enterprise Software Main Examination (ITP4512)", "language": "English", "main_topic": "Enterprise Software Systems and ABAP Programming", "difficulty_level": "Higher Diploma / Advanced Undergraduate", "estimated_reading_time": "2 hours"}, "concept_chunk_mapping": [{"concept": "Decision Support System (DSS)", "context": "GL is also planning to use Decision Support System (DSS) to enhance its management decision process.", "chunk_id": "CHUNK_002", "positions": [120, 450], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Customer Relationship Management (CRM)", "context": "Customer Relationship Management (CRM) is a new strategic software used by the interior design company.", "chunk_id": "CHUNK_002", "positions": [85, 350], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Decision Levels", "context": "decisions that need to be made at different levels of decision making - strategic, tactical, and operational.", "chunk_id": "CHUNK_002", "positions": [40, 3