INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '5 - Jakarta Server Page.pptx', '1bdff197cf420ba37077550e43a447545031b543c3e60a947db5fb0532f5ffb1', '{"chunks": [{"id": "CHUNK_001", "text": "Servlet Problems vs JSP Advantages: Servlets contain request processing, business logic, and response generation all lumped together. Good Java knowledge is needed to maintain applications. Changing look and feel or new clients require Servlet code changes and web page development tools cannot be used. JSP separates request processing and business logic from presentation. It places all static HTML in a JSP page and adds JSP elements to generate dynamic content. This allows separation of tasks between Java programmers and WEB page authors.", "pages": [1, 2], "end_pos": 485, "summary": "Comparison of limitations in Servlets versus advantages of JSP architecture regarding separation of concerns.", "start_pos": 0, "chunk_type": "comparison", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Data Flow Analysis: Client (Browser) interacts with Server. Example URL ex1form.jsp sends back form.html. User fills in form, runs formHandler.jsp. Server sends back HTML rendered to see results. The flow involves static HTML/XML elements, dynamic scripting elements, and special JSP elements. Example.jsp demonstrates this with imports and title tags, utilizing expressions and scriptlets.", "pages": [3, 4], "end_pos": 850, "summary": "Description of client-server interaction flow involving JSP forms and handlers.", "start_pos": 486, "chunk_type": "flow_diagram", "has_examples": true, "main_concepts": ["CONC_001", "CONC_009"], "has_definitions": false, "secondary_concepts": ["CONC_003"]}, {"id": "CHUNK_003", "text": "JSP Processing Phases: JSP Processing consists of Translation Phase and Request Processing Phase. During Translation Phase, the JSP Translator converts .jsp files into Servlet Source (.java), then the Java Compiler creates Servlet Class (.class). In Request Processing Phase, the JVM executes the request. Components involved include Text Buffer, request, and response objects.", "pages": [5, 6], "end_pos": 1150, "summary": "Detailed breakdown of the two main phases in JSP lifecycle.", "start_pos": 851, "chunk_type": "architecture", "has_examples": false, "main_concepts": ["CONC_007", "CONC_008"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "JSP Constructs: Includes HTML/XML elements, Scripting Elements (Java codes), Directives, and Actions. Scripting Elements include Scriptlets (<% java code %>), Expressions (<%= expression %>), and Declarations (<%! Define variables %>). Scriptlets are executable code enclosed in <% ... %> tags. Expressions are evaluated to a string and inserted. Declarations execute once at translation time.", "pages": [7, 8], "end_pos": 1450, "summary": "Definitions of core JSP syntax elements and scripting constructs.", "start_pos": 1151, "chunk_type": "syntax_reference", "has_examples": true, "main_concepts": ["CONC_003", "CONC_004", "CONC_005"], "has_definitions": true, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_005", "text": "Predefined Implicit Variables: JSP provides several predefined variables including request (HttpServletRequest), response (HttpServletResponse), session (HttpSession), out (JspWriter), application (ServletContext), config (ServletConfig), and exception (Throwable). ''out'' must be used to generate HTML. ''exception'' is accessible only from an error page.", "pages": [9, 10, 11], "end_pos": 1750, "summary": "List and description of available implicit objects in JSP pages.", "start_pos": 1451, "chunk_type": "reference", "has_examples": true, "main_concepts": ["CONC_009"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "Page Directive Attributes: Specifies attributes of the page itself like type of content, buffering requirements, and error handling. Enclosed between <%@ ... %>. Has a name and attribute/value pairs. Examples include <%@ page contentType=...%>, import package, errorPage, isErrorPage, session, pageEncoding, buffer, autoFlush.", "pages": [12, 13, 14], "end_pos": 2100, "summary": "Configuration details for the JSP page directive.", "start_pos": 1751, "chunk_type": "reference", "has_examples": false, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_007", "text": "Error Handling Mechanisms: The page errorPage directive takes a valid relative URL to a JSP file to send exceptions. If set, the designated error page is sent instead of standard error. Works with page isErrorPage=true|false. If true, you can use the exception object containing the reference to the thrown exception. Used to provide user-friendly error messages.", "pages": [15, 16, 17, 18, 19, 20], "end_pos": 2450, "summary": "Explanation of how error handling is implemented using directives and implicit objects.", "start_pos": 2101, "chunk_type": "feature_description", "has_examples": true, "main_concepts": ["CONC_010", "CONC_008"], "has_definitions": true, "secondary_concepts": ["CONC_006"]}, {"id": "CHUNK_008", "text": "Include Directive: The include directive inserts a file of text or code in a JSP file at translation time when compiled. Example: include a navigation bar/menu on each page. Syntax: <%@ include file=\"URL\" %>. Execution order involves Browser -> JSP Servlet -> Include JSP b:Include c:Insert Source JSP e:HTML Response.", "pages": [21, 22], "end_pos": 2750, "summary": "Usage of the include directive to reuse content within JSP pages.", "start_pos": 2451, "chunk_type": "feature_description", "has_examples": true, "main_concepts": ["CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_009", "text": "Syntax Summary: JSP Standard Syntax includes Comments (%<-- .. -->%), Declarations (%<! .. %>%), Expressions (<%= .. %>), Scriptlets (%<%>), and Directives (%@ include..%, %@ page attributes %, %@ taglib..%). These elements allow defining page-dependent attributes, declaring tag libraries, and inserting code at translation time.", "pages": [23, 24], "end_pos": 3050, "summary": "Table summary of standard JSP syntax elements.", "start_pos": 2751, "chunk_type": "summary", "has_examples": false, "main_concepts": ["CONC_003", "CONC_004", "CONC_005", "CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_010", "text": "Sample Code Logic: Examples demonstrate dynamic form handling. Calculating speed involves distance and time inputs parsed via request.getParameter(\"kms\"). Error handling catches NumberFormatException if input contains non-digits. Color testing changes body background color based on #RRGGBB input. Scriptlets mix with presentation logic suggesting separate beans for logic.", "pages": [25, 26, 27, 28, 29, 30], "end_pos": 3400, "summary": "Overview of practical coding examples showing parameter retrieval and error handling.", "start_pos": 3051, "chunk_type": "application_example", "has_examples": true, "main_concepts": ["CONC_003", "CONC_009", "CONC_010"], "has_definitions": false, "secondary_concepts": ["CONC_001"]}], "concepts": [{"id": "CONC_001", "title": "Java Server Pages (JSP)", "aliases": ["JSP Page", "JSP Technology"], "keywords": ["JSP", "presentation", "dynamic content", "HTML"], "confidence": 0.98, "difficulty": 3, "description": "A technology for developing web pages that includes dynamic content, allowing separation of request processing and business logic from presentation. It places static HTML in JSP pages and uses JSP elements to generate dynamic content, enabling task separation between Java programmers and web page authors.", "concept_type": "architecture", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_002", "CONC_007", "CONC_008"]}, {"id": "CONC_002", "title": "Servlet", "aliases": ["Java Servlet"], "keywords": ["Java", "request processing", "business logic", "response generation"], "confidence": 0.98, "difficulty": 3, "description": "A Java class used for handling requests and responding to the client. In early architectures, request processing, business logic, and response generation were all lumped together in Servlets, requiring good Java knowledge and making UI changes difficult without code modification.", "concept_type": "component", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_003", "title": "Scriptlet", "aliases": ["Executable Code Block"], "keywords": ["scriptlet", "java code", "%<%>"], "confidence": 0.95, "difficulty": 2, "description": "A block of executable Java code enclosed in <% ... %> tags within a JSP page. Scriptlets do not directly affect HTML but can write into the HTML output using out.print() or out.println(). They are used to control overall structure and call components.", "concept_type": "component", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_004", "CONC_005"]}, {"id": "CONC_004", "title": "Expression", "aliases": ["JSP Expression"], "keywords": ["expression", "<%= %>", "output"], "confidence": 0.95, "difficulty": 2, "description": "A JSP element enclosed in <%= expression %> that is evaluated to a string and inserted directly into the page output. Unlike scriptlets, expressions are used specifically to display values dynamically.", "concept_type": "component", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_003", "CONC_005"]}, {"id": "CONC_005", "title": "Declaration", "aliases": ["Class Variable Definition"], "keywords": ["declaration", "<%!%>", "variables", "methods"], "confidence": 0.95, "difficulty": 2, "description": "A JSP construct enclosed in <%! ... %> tags used to declare variables or methods at the class level. Declarations are executed only once at translation time, distinct from scriptlets which run per request.", "concept_type": "component", "extracted_from": ["CHUNK_004"], "related_concepts": ["CONC_003", "CONC_004"]}, {"id": "CONC_006", "title": "Directive", "aliases": ["JSP Directive Tag"], "keywords": ["directive", "@page", "@include", "@taglib", "configuration"], "confidence": 0.97, "difficulty": 3, "description": "Instructions provided to the JSP container via <%@ ... %> tags to control how the JSP file is processed. Common types include page (attributes like contentType), include (file inclusion at translation time), and taglib (custom actions).", "concept_type": "component", "extracted_from": ["CHUNK_006"], "related_concepts": ["CONC_001", "CONC_007"]}, {"id": "CONC_007", "title": "Translation Phase", "aliases": ["Compilation Phase"], "keywords": ["translation", "javelo", "source code", "compiler"], "confidence": 0.98, "difficulty": 3, "description": "The first phase of JSP processing where the JSP translator converts the .jsp file into a servlet source code (.java). This phase handles directives and scripting elements before compilation by the Java Compiler.", "concept_type": "process", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_008", "CONC_002"]}, {"id": "CONC_008", "title": "Request Processing Phase", "aliases": ["Runtime Phase"], "keywords": ["request processing", "servlet execution", "response"], "confidence": 0.98, "difficulty": 3, "description": "The second phase of JSP processing where the generated servlet handles the incoming HTTP request. It executes Java codes, controls directives, calls actions, and generates the text buffer response sent to the client.", "concept_type": "process", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_007", "CONC_002"]}, {"id": "CONC_009", "title": "Implicit Objects", "aliases": ["Predefined Variables", "JSP Context Objects"], "keywords": ["implicit objects", "request", "response", "session", "out"], "confidence": 0.96, "difficulty": 3, "description": "Predefined objects available in JSP pages without explicit declaration. Key objects include request (HttpServletRequest), response (HttpServletResponse), session (HttpSession), out (JspWriter), application (ServletContext), config (ServletConfig), and exception.", "concept_type": "object", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_003", "CONC_001"]}, {"id": "CONC_010", "title": "Error Handling Page", "aliases": ["Exception Handler"], "keywords": ["error handling", "exception", "isErrorPage", "errorPage"], "confidence": 0.94, "difficulty": 3, "description": "A dedicated JSP designated via errorPage directive to catch exceptions thrown during request processing. By setting isErrorPage to true, the page gains access to the implicit exception object to provide user-friendly error messages.", "concept_type": "component", "extracted_from": ["CHUNK_007"], "related_concepts": ["CONC_008", "CONC_009"]}], "relationships": [{"id": "REL_001", "type": "implements", "source": "CONC_001", "target": "CONC_002", "evidence": "JSP is translated into a Servlet source code (.java) before execution.", "strength": 0.9, "bidirectional": false}, {"id": "REL_002", "type": "before", "source": "CONC_007", "target": "CONC_008", "evidence": "Translation phase precedes Request Processing Phase in JSP lifecycle.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "controls", "source": "CONC_006", "target": "CONC_001", "evidence": "Directives specify attributes of the page itself such as contentType and buffering.", "strength": 0.9, "bidirectional": false}, {"id": "REL_004", "type": "uses", "source": "CONC_003", "target": "CONC_009", "evidence": "Scriptlets utilize predefined variables like request, response, and out.", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "accesses", "source": "CONC_004", "target": "CONC_009", "evidence": "Expressions can reference implicit objects to evaluate and display data.", "strength": 0.9, "bidirectional": false}, {"id": "REL_006", "type": "consumes", "source": "CONC_008", "target": "CONC_010", "evidence": "Error pages handle exceptions thrown during the request processing phase.", "strength": 0.8, "bidirectional": false}, {"id": "REL_007", "type": "provided_in", "source": "CONC_009", "target": "CONC_008", "evidence": "Implicit objects are available during the request processing phase.", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 10, "missing_links": [], "coverage_score": 0.95, "total_concepts": 10, "consistency_score": 0.98, "total_relationships": 7}, "document_metadata": {"title": "ITP4511 – Enterprise System Development", "language": "English", "main_topic": "Java Server Pages (JSP) Architecture and Syntax", "difficulty_level": "Intermediate", "estimated_reading_time": "20 minutes"}, "concept_chunk_mapping": [{"concept": "Java Server Pages (JSP)", "context": "Definition comparing JSP to Servlet limitations.", "chunk_id": "CHUNK_001", "positions": [40], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Java Server Pages (JSP)", "context": "Context regarding include directive.", "chunk_id": "CHUNK_008", "positions": [0], "concept_id": "CONC_001", "importance": "secondary"}, {"concept": "Scriptlet", "context": "Definition of scripting elements.", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "Implicit Objects", "context": "Listing of predefined variables.", "chunk_id": "CHUNK_005", "positions": [12], "concept_id": "CONC_009", "importance": "primary"}, {"concept": "Translation Phase", "context": "Description of JSP lifecycle start.", "chunk_id": "CHUNK_003", "positions": [20], "concept_id": "CONC_007", "importance": "primary"}, {"concept": "Error Handling Page", "context": "Detail on errorPage and isErrorPage directives.", "chunk_id": "CHUNK_007", "positions": [5], "concept_id": "CONC_010", "importance": "primary"}, {"concept": "Servlet", "context": "Definition of problem with old architecture.", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_002", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 28, "difficulty_score": 7, "total_structures": 15, "total_applications": 18}', '"[{\"id\":\"CHUNK_001\",\"text\":\"Servlet Problems vs JSP Advantages: Servlets contain request processing, business logic, and response generation all lumped together. Good Java knowledge is needed to maintain applications. Changing look and feel or new clients require Servlet code changes and web page development tools cannot be used. JSP separates request processing and business logic from presentation. It places all static HTML in a JSP page and adds JSP elements to generate dynamic content. This allows separation of tasks between Java programmers and WEB page authors.\",\"pages\":[1,2],\"start_pos\":0,\"end_pos\":485,\"summary\":\"Comparison of limitations in Servlets versus advantages of JSP architecture regarding separation of concerns.\",\"chunk_type\":\"comparison\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\",\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"Data Flow Analysis: Client (Browser) interacts with Server. Example URL ex1form.jsp sends back form.html. User fills in form, runs formHandler.jsp. Server sends back HTML rendered to see results. The flow involves static HTML/XML elements, dynamic scripting elements, and special JSP elements. Example.jsp demonstrates this with imports and title tags, utilizing expressions and scriptlets.\",\"pages\":[3,4],\"start_pos\":486,\"end_pos\":850,\"summary\":\"Description of client-server interaction flow involving JSP forms and handlers.\",\"chunk_type\":\"flow_diagram\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\",\"CONC_009\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_003\"]},{\"id\":\"CHUNK_003\",\"text\":\"JSP Processing Phases: JSP Processing consists of Translation Phase and Request Processing Phase. During Translation Phase, the JSP Translator converts .jsp files into Servlet Source (.java), then the Java Compiler creates Servlet Class (.class). In Request Processing Phase, the JVM executes the request. Components involved include Text Buffer, request, and response objects.\",\"pages\":[5,6],\"start_pos\":851,\"end_pos\":1150,\"summary\":\"Detailed breakdown of the two main phases in JSP lifecycle.\",\"chunk_type\":\"architecture\",\"has_examples\":false,\"main_concepts\":[\"CONC_007\",\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"JSP Constructs: Includes HTML/XML elements, Scripting Elements (Java codes), Directives, and Actions. Scripting Elements include Scriptlets (<% java code %>), Expressions (<%= expression %>), and Declarations (<%! Define variables %>). Scriptlets are executable code enclosed in <% ... %> tags. Expressions are evaluated to a string and inserted. Declarations execute once at translation time.\",\"pages\":[7,8],\"start_pos\":1151,\"end_pos\":1450,\"summary\":\"Definitions of core JSP syntax elements and scripting constructs.\",\"chunk_type\":\"syntax_reference\",\"has_examples\":true,\"main_concepts\":[\"CONC_003\",\"CONC_004\",\"CONC_005\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_005\",\"text\":\"Predefined Implicit Variables: JSP provides several predefined variables including request (HttpServletRequest), response (HttpServletResponse), session (HttpSession), out (JspWriter), application (ServletContext), config (ServletConfig), and exception (Throwable). ''out'' must be used to generate HTML. ''exception'' is accessible only from an error page.\",\"pages\":[9,10,11],\"start_pos\":1451,\"end_pos\":1750,\"summary\":\"List and description of available implicit objects in JSP pages.\",\"chunk_type\":\"reference\",\"has_examples\":true,\"main_concepts\":[\"CONC_009\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_006\",\"text\":\"Page Directive Attributes: Specifies attributes of the page itself like type of content, buffering requirements, and error handling. Enclosed between <%@ ... %>. Has a name and attribute/value pairs. Examples include <%@ page contentType=...%>, import package, errorPage, isErrorPage, session, pageEncoding, buffer, autoFlush.\",\"pages\":[12,13,14],\"start_pos\":1751,\"end_pos\":2100,\"summary\":\"Configuration details for the JSP page directive.\",\"chunk_type\":\"reference\",\"has_examples\":false,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_007\",\"text\":\"Error Handling Mechanisms: The page errorPage directive takes a valid relative URL to a JSP file to send exceptions. If set, the designated error page is sent instead of standard error. Works with page isErrorPage=true|false. If true, you can use the exception object containing the reference to the thrown exception. Used to provide user-friendly error messages.\",\"pages\":[15,16,17,18,19,20],\"start_pos\":2101,\"end_pos\":2450,\"summary\":\"Explanation of how error handling is implemented using directives and implicit objects.\",\"chunk_type\":\"feature_description\",\"has_examples\":true,\"main_concepts\":[\"CONC_010\",\"CONC_008\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_006\"]},{\"id\":\"CHUNK_008\",\"text\":\"Include Directive: The include directive inserts a file of text or code in a JSP file at translation time when compiled. Example: include a navigation bar/menu on each page. Syntax: <%@ include file=\\\"URL\\\" %>. Execution order involves Browser -> JSP Servlet -> Include JSP b:Include c:Insert Source JSP e:HTML Response.\",\"pages\":[21,22],\"start_pos\":2451,\"end_pos\":2750,\"summary\":\"Usage of the include directive to reuse content within JSP pages.\",\"chunk_type\":\"feature_description\",\"has_examples\":true,\"main_concepts\":[\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_009\",\"text\":\"Syntax Summary: JSP Standard Syntax includes Comments (%<-- .. -->%), Declarations (%<! .. %>%), Expressions (<%= .. %>), Scriptlets (%<%>), and Directives (%@ include..%, %@ page attributes %, %@ taglib..%). These elements allow defining page-dependent attributes, declaring tag libraries, and inserting code at translation time.\",\"pages\":[23,24],\"start_pos\":2751,\"end_pos\":3050,\"summary\":\"Table summary of standard JSP syntax elements.\",\"chunk_type\":\"summary\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\",\"CONC_004\",\"CONC_005\",\"CONC_006\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_001\"]},{\"id\":\"CHUNK_010\",\"text\":\"Sample Code Logic: Examples demonstrate dynamic form handling. Calculating speed involves distance and time inputs parsed via request.getParameter(\\\"kms\\\"). Error handling catches NumberFormatException if input contains non-digits. Color testing changes body background color based on #RRGGBB input. Scriptlets mix with presentation logic suggesting separate beans for logic.\",\"pages\":[25,26,27,28,29,30],\"start_pos\":3051,\"end_pos\":3400,\"summary\":\"Overview of practical coding examples showing parameter retrieval and error handling.\",\"chunk_type\":\"application_example\",\"has_examples\":true,\"main_concepts\":[\"CONC_003\",\"CONC_009\",\"CONC_010\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_001\"]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Java Server Pages (JSP)\",\"aliases\":[\"JSP Page\",\"JSP Technology\"],\"keywords\":[\"JSP\",\"presentation\",\"dynamic content\",\"HTML\"],\"confidence\":0.98,\"difficulty\":3,\"description\":\"A technology for developing web pages that includes dynamic content, allowing separation of request processing and business logic from presentation. It places static HTML in JSP pages and uses JSP elements to generate dynamic content, enabling task separation between Java programmers and web page authors.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_001\"],\"related_concepts\":[\"CONC_002\",\"CONC_007\",\"CONC_008\"]},{\"id\":\"CONC_002\",\"title\":\"Servlet\",\"aliases\":[\"Java Servlet\"],\"keywords\":[\"Java\",\"request processing\",\"business logic\",\"response generation\"],\"confidence\":0.98,\"difficulty\":3,\"description\":\"A Java class used for handling requests and responding to the client. In early architectures, request processing, business logic, and response generation were all lumped together in Servlets, requiring good Java knowledge and making UI changes difficult without code modification.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_001\"],\"related_concepts\":[\"CONC_001\",\"CONC_007\"]},{\"id\":\"CONC_003\",\"title\":\"Scriptlet\",\"aliases\":[\"Executable Code Block\"],\"keywords\":[\"scriptlet\",\"java code\",\"%<%>\"],\"confidence\":0.95,\"difficulty\":2,\"description\":\"A block of executable Java code enclosed in <% ... %> tags within a JSP page. Scriptlets do not directly affect HTML but can write into the HTML output using out.print() or out.println(). They are used to control overall structure and call components.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_004\",\"CONC_005\"]},{\"id\":\"CONC_004\",\"title\":\"Expression\",\"aliases\":[\"JSP Expression\"],\"keywords\":[\"expression\",\"<%= %>\",\"output\"],\"confidence\":0.95,\"difficulty\":2,\"description\":\"A JSP element enclosed in <%= expression %> that is evaluated to a string and inserted directly into the page output. Unlike scriptlets, expressions are used specifically to display values dynamically.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_003\",\"CONC_005\"]},{\"id\":\"CONC_005\",\"title\":\"Declaration\",\"aliases\":[\"Class Variable Definition\"],\"keywords\":[\"declaration\",\"<%!%>\",\"variables\",\"methods\"],\"confidence\":0.95,\"difficulty\":2,\"description\":\"A JSP construct enclosed in <%! ... %> tags used to declare variables or methods at the class level. Declarations are executed only once at translation time, distinct from scriptlets which run per request.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_004\"],\"related_concepts\":[\"CONC_003\",\"CONC_004\"]},{\"id\":\"CONC_006\",\"title\":\"Directive\",\"aliases\":[\"JSP Directive Tag\"],\"keywords\":[\"directive\",\"@page\",\"@include\",\"@taglib\",\"configuration\"],\"confidence\":0.97,\"difficulty\":3,\"description\":\"Instructions provided to the JSP container via <%@ ... %> tags to control how the JSP file is processed. Common types include page (attributes like contentType), include (file inclusion at translation time), and taglib (custom actions).\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_006\"],\"related_concepts\":[\"CONC_001\",\"CONC_007\"]},{\"id\":\"CONC_007\",\"title\":\"Translation Phase\",\"aliases\":[\"Compilation Phase\"],\"keywords\":[\"translation\",\"javelo\",\"source code\",\"compiler\"],\"confidence\":0.98,\"difficulty\":3,\"description\":\"The first phase of JSP processing where the JSP translator converts the .jsp file into a servlet source code (.java). This phase handles directives and scripting elements before compilation by the Java Compiler.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_008\",\"CONC_002\"]},{\"id\":\"CONC_008\",\"title\":\"Request Processing Phase\",\"aliases\":[\"Runtime Phase\"],\"keywords\":[\"request processing\",\"servlet execution\",\"response\"],\"confidence\":0.98,\"difficulty\":3,\"description\":\"The second phase of JSP processing where the generated servlet handles the incoming HTTP request. It executes Java codes, controls directives, calls actions, and generates the text buffer response sent to the client.\",\"concept_type\":\"process\",\"extracted_from\":[\"CHUNK_003\"],\"related_concepts\":[\"CONC_007\",\"CONC_002\"]},{\"id\":\"CONC_009\",\"title\":\"Implicit Objects\",\"aliases\":[\"Predefined Variables\",\"JSP Context Objects\"],\"keywords\":[\"implicit objects\",\"request\",\"response\",\"session\",\"out\"],\"confidence\":0.96,\"difficulty\":3,\"description\":\"Predefined objects available in JSP pages without explicit declaration. Key objects include request (HttpServletRequest), response (HttpServletResponse), session (HttpSession), out (JspWriter), application (ServletContext), config (ServletConfig), and exception.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_005\"],\"related_concepts\":[\"CONC_003\",\"CONC_001\"]},{\"id\":\"CONC_010\",\"title\":\"Error Handling Page\",\"aliases\":[\"Exception Handler\"],\"keywords\":[\"error handling\",\"exception\",\"isErrorPage\",\"errorPage\"],\"confidence\":0.94,\"difficulty\":3,\"description\":\"A dedicated JSP designated via errorPage directive to catch exceptions thrown during request processing. By setting isErrorPage to true, the page gains access to the implicit exception object to provide user-friendly error messages.\",\"concept_type\":\"component\",\"extracted_from\":[\"CHUNK_007\"],\"related_concepts\":[\"CONC_008\",\"CONC_009\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"implements\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"JSP is translated into a Servlet source code (.java) before execution.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_002\",\"type\":\"before\",\"source\":\"CONC_007\",\"target\":\"CONC_008\",\"evidence\":\"Translation phase precedes Request Processing Phase in JSP lifecycle.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"controls\",\"source\":\"CONC_006\",\"target\":\"CONC_001\",\"evidence\":\"Directives specify attributes of the page itself such as contentType and buffering.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"uses\",\"source\":\"CONC_003\",\"target\":\"CONC_009\",\"evidence\":\"Scriptlets utilize predefined variables like request, response, and out.\",\"strength\":1,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"accesses\",\"source\":\"CONC_004\",\"target\":\"CONC_009\",\"evidence\":\"Expressions can reference implicit objects to evaluate and display data.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_006\",\"type\":\"consumes\",\"source\":\"CONC_008\",\"target\":\"CONC_010\",\"evidence\":\"Error pages handle exceptions thrown during the request processing phase.\",\"strength\":0.8,\"bidirectional\":false},{\"id\":\"REL_007\",\"type\":\"provided_in\",\"source\":\"CONC_009\",\"target\":\"CONC_008\",\"evidence\":\"Implicit objects are available during the request processing phase.\",\"strength\":1,\"bidirectional\":false}]"', '2026-04-17 12:45:44.840152', '2026-04-17 12:45:44.840152', NULL, '[{"id": "module_1", "name": "JSP Fundamentals and Motivation", "topic_count": 10}, {"id": "module_2", "name": "JSP Scripting Elements", "topic_count": 12}, {"id": "module_3", "name": "JSP Directives", "topic_count": 10}, {"id": "module_4", "name": "Form Handling and Practical Examples", "topic_count": 15}, {"id": "module_5", "name": "Error Handling and Best Practices", "topic_count": 8}]', NULL, 'ITP4511 – Enterprise System Development

