INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '9 Recurrent Neural Network.pptx', '57e0f0e896e00ce755abf6315a4d34dd8613f568f0a6f1e88205b2fcd28ca315', '{"chunks": [{"id": "CHUNK_001", "text": "Introduction to Artificial Intelligence / AI Fundamental \n\nRecurrent neural network (RNN) Introduction to Artificial Intelligence / Al Fundamental \n\nModel structure and operation. RNN Training: back-propagation through time (BPTT) LSTM (long/short term memory)", "pages": [1], "end_pos": 190, "summary": "Slides introducing RNN, BPTT, and LSTM topics.", "start_pos": 0, "chunk_type": "overview", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_003"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Features \nRecurrences means output fed back to input \nNecessarily, the input is a time-series data \nMain applications are speech recognition, language modelling (machine translation, sentence completion), where data is given as time series)\nAbility to operate over sequences of vectors", "pages": [1], "end_pos": 480, "summary": "Defines RNN features including recurrence logic and input types.", "start_pos": 190, "chunk_type": "feature_definition", "has_examples": false, "main_concepts": ["CONC_001", "CONC_007"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Example \nTwo layers RNN \nHidden layout output is fed back to input with one sample delay \nLayer 2 has no feedback loop (conventional NN layer) \n\nHidden layer in RNN''s have same weights and bias through out the process giving them the chance to memorize information processed through them. \n\nModel 1-layer RNN unfolded RNN", "pages": [2], "end_pos": 850, "summary": "Describes RNN architecture examples and weight sharing mechanics.", "start_pos": 480, "chunk_type": "architecture_example", "has_examples": true, "main_concepts": ["CONC_001", "CONC_008"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Problem with RNN \nDue to recurrence nature, RNN training requires back propagation through time \nIf T get large, the gradient may vanish or explode -> the training rule should be care fully tuned", "pages": [2], "end_pos": 1050, "summary": "Outlines the training problems related to gradient vanishing in RNNs.", "start_pos": 850, "chunk_type": "problem_statement", "has_examples": false, "main_concepts": ["CONC_001", "CONC_003", "CONC_004"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Long/Short term memory (LSTM) \na variant of RNN to solve the vanishing gradient and to make system memory longer \nGood for classify, process and make predictions based on time series data \n\nLTSM cell is Compose of \ninput gate \noutput gate \nforget gate \nThe gate decides whether the input could be output or not (forget)", "pages": [3], "end_pos": 1450, "summary": "Explains LSTM as a solution for RNN limitations and details its components.", "start_pos": 1050, "chunk_type": "solution_definition", "has_examples": false, "main_concepts": ["CONC_002", "CONC_004", "CONC_005", "CONC_006"], "has_definitions": true, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Recurrent Neural Network (RNN)", "aliases": ["Recurrent NN"], "keywords": ["RNN", "neural network", "sequence", "recurrence"], "confidence": 1.0, "difficulty": 4, "description": "A class of artificial neural networks designed for recognizing patterns in sequences of data, such as text, genomes, handwriting, or spoken words. The connections between nodes form a directed graph along a temporal sequence, allowing the network to exhibit temporal dynamic behavior. Unlike feedforward neural networks, RNNs can use their internal state or memory to process sequences of inputs effectively. They operate by feeding output back into the input with a delay.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_002", "CHUNK_003", "CHUNK_004"], "related_concepts": ["CONC_002", "CONC_007", "CONC_008"]}, {"id": "CONC_002", "title": "Long Short-Term Memory (LSTM)", "aliases": ["Long/Short Term Memory"], "keywords": ["LSTM", "memory", "gating", "time-series"], "confidence": 1.0, "difficulty": 5, "description": "A specific variant of the Recurrent Neural Network architecture designed to solve the vanishing gradient problem and enable learning of long-term dependencies. LSTMs incorporate gating mechanisms including input, output, and forget gates to regulate information flow. This allows the system memory to retain information over longer time steps, making them highly effective for classification, processing, and prediction tasks based on time-series data where context is crucial.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_004", "CONC_005", "CONC_006"]}, {"id": "CONC_003", "title": "Back-Propagation Through Time (BPTT)", "aliases": [], "keywords": ["BPTT", "training", "gradient", "back-propagation"], "confidence": 1.0, "difficulty": 4, "description": "The fundamental training algorithm used for recurrent neural networks. BPTT involves unrolling the RNN through the time dimension to compute gradients for every parameter at every step. This method is required because the recurrence nature of the network implies that errors at later time steps depend on previous states. While powerful, if the time horizon T gets large during this process, the gradient may vanish or explode, requiring careful tuning of training rules.", "concept_type": "process", "extracted_from": ["CHUNK_001", "CHUNK_004"], "related_concepts": ["CONC_001", "CONC_004"]}, {"id": "CONC_004", "title": "Vanishing Gradient Problem", "aliases": [], "keywords": ["vanishing gradient", "exploding gradient", "training stability"], "confidence": 1.0, "difficulty": 5, "description": "A phenomenon occurring in deep neural networks and RNNs during training via backpropagation. It describes the situation where the gradient signal becomes extremely small as it propagates backward through time or layers. In the context of RNNs, if T gets large, the gradient may vanish or explode. This prevents early layers from learning effectively and limits the ability to capture long-range dependencies without architectural solutions like LSTM.", "concept_type": "phenomenon", "extracted_from": ["CHUNK_004", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_002"]}, {"id": "CONC_005", "title": "Forget Gate", "aliases": [], "keywords": ["gate", "forget", "LSTM", "cell state"], "confidence": 1.0, "difficulty": 3, "description": "A key component within the LSTM cell architecture. Its primary function is to decide whether the input information should be retained or discarded from the cell state. It determines whether the current input could be forgotten, helping the network manage long-term memory by removing irrelevant past information. This gate works alongside the input and output gates to control the flow of information precisely.", "concept_type": "component", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_006"]}, {"id": "CONC_006", "title": "Input Gate", "aliases": [], "keywords": ["gate", "input", "LSTM", "information flow"], "confidence": 1.0, "difficulty": 3, "description": "One of the three main gating mechanisms in an LSTM cell, responsible for controlling how much new information from the current input vector enters the cell state. Along with the Forget Gate and Output Gate, the Input Gate allows the network to update its memory selectively. This selective writing capability is essential for preserving important temporal features while filtering out noise.", "concept_type": "component", "extracted_from": ["CHUNK_005"], "related_concepts": ["CONC_002", "CONC_005"]}, {"id": "CONC_007", "title": "Time-Series Data", "aliases": [], "keywords": ["time-series", "data", "sequences", "vectors"], "confidence": 1.0, "difficulty": 2, "description": "A collection of data points indexed in time order. In the context of machine learning, it is necessarily input for RNNs and LSTMs. Main applications include speech recognition and language modeling where data is given as a time series. These systems must operate over sequences of vectors, leveraging the ability to handle temporal dynamics and dependencies inherent in sequential data.", "concept_type": "object", "extracted_from": ["CHUNK_002", "CHUNK_005"], "related_concepts": ["CONC_001", "CONC_002"]}, {"id": "CONC_008", "title": "Hidden Layer", "aliases": [], "keywords": ["hidden layer", "weights", "bias", "feedback"], "confidence": 1.0, "difficulty": 3, "description": "In the context of RNNs, these layers share the same weights and bias throughout the entire process. This weight sharing gives the hidden layer the chance to memorize information processed through them. A standard example is a Two-layer RNN where the hidden layer output is fed back to the input with one sample delay, distinguishing it from conventional neural network layers which have no feedback loop.", "concept_type": "component", "extracted_from": ["CHUNK_003"], "related_concepts": ["CONC_001"]}], "relationships": [{"id": "REL_001", "type": "is_a", "source": "CONC_002", "target": "CONC_001", "evidence": "a variant of RNN to solve the vanishing gradient and to make system memory longer", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "requires", "source": "CONC_001", "target": "CONC_003", "evidence": "Due to recurrence nature, RNN training requires back propagation through time", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "part_of", "source": "CONC_005", "target": "CONC_002", "evidence": "LTSM cell is Compose of input gate, output gate, forget gate", "strength": 1.0, "bidirectional": false}, {"id": "REL_004", "type": "part_of", "source": "CONC_006", "target": "CONC_002", "evidence": "LTSM cell is Compose of input gate, output gate, forget gate", "strength": 1.0, "bidirectional": false}, {"id": "REL_005", "type": "consumes", "source": "CONC_001", "target": "CONC_007", "evidence": "Necessarily, the input is a time-series data; Main applications are speech recognition... where data is given as time series", "strength": 0.9, "bidirectional": false}, {"id": "REL_006", "type": "part_of", "source": "CONC_008", "target": "CONC_001", "evidence": "Hidden layer in RNNs have same weights and bias through out the process", "strength": 0.95, "bidirectional": false}, {"id": "REL_007", "type": "opposite_of", "source": "CONC_004", "target": "CONC_001", "evidence": "If T get large, the gradient may vanish or explode", "strength": 0.8, "bidirectional": true}, {"id": "REL_008", "type": "implements", "source": "CONC_002", "target": "CONC_004", "evidence": "variant of RNN to solve the vanishing gradient", "strength": 1.0, "bidirectional": false}], "quality_metrics": {"total_chunks": 5, "missing_links": [], "coverage_score": 0.95, "total_concepts": 8, "consistency_score": 0.95, "total_relationships": 8}, "document_metadata": {"title": "Introduction to Artificial Intelligence / AI Fundamental", "language": "English", "main_topic": "Recurrent Neural Networks and LSTM", "difficulty_level": "Intermediate", "estimated_reading_time": "10 minutes"}, "concept_chunk_mapping": [{"concept": "CONC_001", "context": "Core subject introduction", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "CONC_002", "context": "Topic listed in overview", "chunk_id": "CHUNK_001", "positions": [170], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "CONC_001", "context": "Feature definition", "chunk_id": "CHUNK_002", "positions": [210], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "CONC_008", "context": "Weight sharing explanation", "chunk_id": "CH