INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '6-JSPAction-2024.pdf', 'f89569ee99ad4395f231ddd433c456cfb1c1b01f7d04dde55fcab52a2bc71fe5', '{"chunks": [{"id": "CHUNK_001", "text": "JSP Action Definition: JSP actions are HTML-like syntax with predefined tags and attributes designed to perform actions based on information. Examples include <jsp:useBean> to interact with java bean objects. Action elements are predefined functions that simplify programming implementation by providing a list of standard action tags for specific tasks.", "pages": [1], "end_pos": 450, "summary": "Introduction to JSP actions as predefined HTML-like tags.", "start_pos": 0, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Standard Action Syntax: Actions represent dynamic operations at runtime. Syntax involves a prefix and action name (e.g., prefix:action-name). Standard actions include <jsp:param> (adds parameter to request), <jsp:include> (includes response during request processing), and <jsp:forward> (forwards request processing to another page or servlet).", "pages": [2], "end_pos": 900, "summary": "Overview of standard JSP action tags and their purposes.", "start_pos": 450, "chunk_type": "overview", "has_examples": false, "main_concepts": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "jsp:include Detailed: Used to include a file at request time, merging content with the current JSP. It can appear anywhere in the page. Example code shows <jsp:include page=\"relative url\" /> including header.jsp or info.jsp. Parameters can be added using nested <jsp:param> tags to pass dynamic data like ''name'' or ''campus'' into the included template.", "pages": [3, 4, 5], "end_pos": 1450, "summary": "Deep dive into jsp:include functionality and parameter passing.", "start_pos": 900, "chunk_type": "technical_detail", "has_examples": true, "main_concepts": ["CONC_002", "CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_004", "text": "jsp:forward Detailed: Passes control to another JSP page or servlet. Current page execution terminates, fully handing control to the target. The URL does not change in the browser. Can include parameters using nested <jsp:param>. Example shows forwarding to conditional.jsp based on a random chance value generated in forward.jsp.", "pages": [6, 7, 8, 9], "end_pos": 2000, "summary": "Explanation of jsp:forward mechanism and parameter usage.", "start_pos": 1450, "chunk_type": "technical_detail", "has_examples": true, "main_concepts": ["CONC_003", "CONC_004"], "has_definitions": true, "secondary_concepts": ["CONC_001"]}, {"id": "CHUNK_005", "text": "Java Bean Fundamentals: Beans are containers for dynamic content and reusable components that encapsulate data about one entity. They separate business logic from presentation logic. A Java class must follow conventions: package definition, no-argument constructor, properties accessed via getters/setters, Serializable implementation.", "pages": [10, 11, 12], "end_pos": 2550, "summary": "Core characteristics and requirements of Java Beans in JSP.", "start_pos": 2000, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_008"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "Bean Interaction Actions: How to use Java Beans in JSP using <jsp:useBean>, <jsp:setProperty>, and <jsp:getProperty>. useBean declares the ID and class. setProperty updates values using attribute ''value'' or ''param''. getProperty displays values. These actions replace manual Java scriptlet coding for accessing properties.", "pages": [13, 14, 15], "end_pos": 3100, "summary": "Methods for declaring and manipulating Java Beans within JSP pages.", "start_pos": 2550, "chunk_type": "technical_detail", "has_examples": true, "main_concepts": ["CONC_005", "CONC_006", "CONC_007"], "has_definitions": true, "secondary_concepts": ["CONC_008"]}, {"id": "CHUNK_007", "text": "Bean Scopes and Form Handling: Available scopes for jsp:useBean are Page, Request, Session, and Application. Page is default; Request survives the forward chain. Form handling uses request.getParameter() or auto-binding with param property. Attributes allow updating properties directly from form inputs without explicit parsing.", "pages": [16, 17, 18], "end_pos": 3650, "summary": "Understanding bean lifecycles across scopes and binding form data.", "start_pos": 3100, "chunk_type": "advanced", "has_examples": true, "main_concepts": ["CONC_009", "CONC_006"], "has_definitions": true, "secondary_concepts": ["CONC_003", "CONC_008"]}, {"id": "CHUNK_008", "text": "MVC Architecture Context: Model-View-Controller separates data/business logic (Model), presentation (View), and interaction (Controller). User interacts with Controller which forwards to Model, result displayed by View. JSP Container handles Browser interactions. Beans often serve as Model, Servlet/JSP as Controller/View.", "pages": [19, 20], "end_pos": 4100, "summary": "Overview of MVC design pattern relevance to JSP enterprise systems.", "start_pos": 3650, "chunk_type": "theory", "has_examples": false, "main_concepts": ["CONC_010"], "has_definitions": true, "secondary_concepts": ["CONC_008"]}], "concepts": [{"id": "CONC_001", "title": "JSP Action Syntax", "aliases": ["Action Elements", "JSP Standard Actions"], "keywords": ["syntax", "tags", "runtime", "predefined"], "confidence": 1.0, "difficulty": 3, "description": "JSP actions utilize HTML-like syntax with predefined tags to perform dynamic actions at runtime. They simplify programming by encapsulating standard tasks such as bean manipulation and request forwarding. Actions typically follow a prefix:action-name pattern with attributes and optional bodies.", "concept_type": "component", "extracted_from": ["CHUNK_001"], "related_concepts": ["CONC_002", "CONC_005"]}, {"id": "CONC_002", "title": "jsp:include", "aliases": ["Include Directive"], "keywords": ["include", "merge", "request time", "servlet"], "confidence": 1.0, "difficulty": 3, "description": "A JSP action used to include the response from a servlet or JSP page during the request processing phase. It allows merging external file content at request time and supports passing parameters via jsp:param sub-elements.", "concept_type": "component", "extracted_from": ["CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_004", "CONC_001"]}, {"id": "CONC_003", "title": "jsp:forward", "aliases": ["Page Forwarding"], "keywords": ["forward", "control", "termination", "redirect"], "confidence": 1.0, "difficulty": 3, "description": "An action that passes control to another JSP page or servlet. Execution of the current page is terminated, and control is fully passed to the target. The URL remains unchanged to the client, but processing moves to the new resource.", "concept_type": "component", "extracted_from": ["CHUNK_003", "CHUNK_004"], "related_concepts": ["CONC_004", "CONC_009"]}, {"id": "CONC_004", "title": "jsp:param", "aliases": ["Request Parameter"], "keywords": ["parameter", "data transfer", "attribute"], "confidence": 1.0, "difficulty": 2, "description": "Adds a parameter value to a request handed off to another servlet or JSP page. It is commonly nested within jsp:include or jsp:forward elements to pass data dynamically during the merge or forward operation.", "concept_type": "component", "extracted_from": ["CHUNK_002", "CHUNK_003"], "related_concepts": ["CONC_002", "CONC_003"]}, {"id": "CONC_005", "title": "jsp:useBean", "aliases": ["Use Bean Action"], "keywords": ["bean", "instance", "scope", "declaration"], "confidence": 1.0, "difficulty": 3, "description": "Declares a JavaBeans component available to a JSP page. It creates an instance of a bean class, assigns it an ID, and defines its scope (page, request, session, application). It simplifies object creation compared to scriptlets.", "concept_type": "component", "extracted_from": ["CHUNK_005", "CHUNK_006"], "related_concepts": ["CONC_008", "CONC_007"]}, {"id": "CONC_006", "title": "jsp:setProperty", "aliases": ["Set Property"], "keywords": ["set", "update", "property", "assignment"], "confidence": 1.0, "difficulty": 3, "description": "Sets a JavaBean property value using either a literal value or an input parameter. The name attribute must match the useBean ID, and the property attribute must match the bean''s defined properties. Supports auto-conversion types.", "concept_type": "component", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_005", "CONC_008"]}, {"id": "CONC_007", "title": "jsp:getProperty", "aliases": ["Get Property"], "keywords": ["get", "retrieve", "read", "display"], "confidence": 1.0, "difficulty": 2, "description": "Retrieves a property value from a JavaBean component and adds it to the response. Values returned are automatically converted to strings. It requires matching the bean ID and property name.", "concept_type": "component", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_005", "CONC_008"]}, {"id": "CONC_008", "title": "Java Bean", "aliases": ["Bean Component", "Java Class"], "keywords": ["reusable", "encapsulation", "getter", "setter"], "confidence": 1.0, "difficulty": 3, "description": "A reusable software component encapsulating data about one entity. In JSP, beans separate business logic from presentation logic. They must have a no-argument constructor, private properties, and public getter/setter methods.", "concept_type": "object", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_005", "CONC_009"]}, {"id": "CONC_009", "title": "Bean Scope", "aliases": ["Scope Attribute"], "keywords": ["lifetime", "visibility", "context", "storage"], "confidence": 1.0, "difficulty": 4, "description": "Defines the lifetime and visibility of a bean instance. Options include Page (current page), Request (single request), Session (user session), and Application (entire web app). Default scope is usually Page.", "concept_type": "architecture", "extracted_from": ["CHUNK_006", "CHUNK_007"], "related_concepts": ["CONC_005", "CONC_003"]}, {"id": "CONC_010", "title": "MVC Design Pattern", "aliases": ["Model View Controller"], "keywords": ["MVC", "separation", "logic", "presentation"], "confidence": 1.0, "difficulty": 4, "description": "Model-View-Controller architecture separates data/business logic (Model), presentation (View), and interaction (Controller). JSP often acts as the View/Controller while Beans act as the Model, facilitating separation of concerns.", "concept_type": "architecture", "extracted_from": ["CHUNK_008"], "related_concepts": ["CONC_008", "CONC_001"]}], "relationships": [{"id": "REL_001", "type": "implements", "source": "CONC_001", "target": "CONC_002", "evidence": "jsp:include is listed as a standard action under JSP Action Syntax.", "strength": 1.0, "bidirectional": false}, {"id": "REL_002", "type": "implements", "source": "CONC_001", "target": "CONC_003", "evidence": "jsp:forward is listed as a standard action under JSP Action Syntax.", "strength": 1.0, "bidirectional": false}, {"id": "REL_003", "type": "consumes", "source": "CONC_003", "target": "CONC_004", "evidence": "Forward can accept parameters via jsp:param for conditional logic.", "strength": 0.9, "bidirectional": false}, {"id": "REL_004", "type": "consumes", "source": "CONC_002", "target": "CONC_004", "evidence": "Include can include content with parameter using jsp:param.", "strength": 0.9, "bidirectional": false}, {"id": "REL_005", "type": "manages", "source": "CONC_005", "target": "CONC_008", "evidence": "jsp:useBean declares a JavaBeans component available to a page.", "strength": 1.0, "bidirectional": false},