INSERT INTO parsed_documents (document_name, document_hash, parsed_json, summary, chunks, concepts, relationships, created_at, updated_at, deleted_at, modules, source_id, raw_text) VALUES ( '9-1_Microservices.pdf', '3ba13be4eb5398c2076a2415a99de84a08098fbeff11a3a74d419d529f1969fb', '{"chunks": [{"id": "CHUNK_001", "text": "Monolithic architecture: Monolithic software is designed to be self-contained; components of the program are interconnected and interdependent. Is a tightly-coupled architecture. Each component and its associated components must be present in order for code to be executed or compiled.", "pages": [1], "end_pos": 245, "summary": "Definition of Monolithic Architecture focusing on self-containment and tight coupling.", "start_pos": 0, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_002", "text": "Monolithic Applications handle multiple related tasks (e.g., ecommerce SaaS). The application might contain a web server, UI Handler, catalog service, ordering system, payment function, Shipping service, Accounting service, and a load balancer. Traditional web application architecture uses WAR files.", "pages": [1], "end_pos": 500, "summary": "Examples of components within a Monolithic Application including legacy architecture references.", "start_pos": 246, "chunk_type": "example", "has_examples": true, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_003", "text": "Strengths of the Monolithic Architecture: Less cross-cutting concerns, easier debugging and testing since it is a single indivisible unit. End-to-end testing is much faster. Simple to deploy by putting the WAR file on runtime. Simple to develop as it follows a standard way.", "pages": [1], "end_pos": 750, "summary": "Analysis of the strengths of Monolithic Architecture including deployment simplicity.", "start_pos": 501, "chunk_type": "analysis", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_004", "text": "Weaknesses of the Monolithic Architecture: Understanding becomes hard as scale increases. Making changes affects the whole system due to tight coupling. Scalability cannot happen at the component level. Applying new technology requires rewriting the entire application.", "pages": [1], "end_pos": 990, "summary": "Analysis of the weaknesses of Monolithic Architecture focusing on complexity and rigidity.", "start_pos": 751, "chunk_type": "analysis", "has_examples": false, "main_concepts": ["CONC_001"], "has_definitions": false, "secondary_concepts": []}, {"id": "CHUNK_005", "text": "Microservice architecture: An alternative pattern addressing monolithic limitations. Martin Fowler defines it as developing a single application as a suite of small services, each running in its own process communicating with lightweight mechanisms, often HTTP resource API.", "pages": [1], "end_pos": 1250, "summary": "Definition of Microservice Architecture citing industry expert definitions.", "start_pos": 991, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_006", "text": "What are microservices? Smaller applications deployed independently as loosely coupled services. Features: Highly maintainable and testable, loosely coupled, independently deployable, organized around business capabilities, owned by a small team. Software engineering approach decomposing into single-function modules.", "pages": [1], "end_pos": 1520, "summary": "List of key features and definitions associated with Microservices Architecture.", "start_pos": 1251, "chunk_type": "features", "has_examples": false, "main_concepts": ["CONC_002"], "has_definitions": true, "secondary_concepts": ["CONC_005"]}, {"id": "CHUNK_007", "text": "Introduction to Spring Boot: Spring Boot is a framework that makes it easy to create Spring-based applications: Stand-alone & production-grade. Embedded Tomcat, Jetty or Undertow server. Starter dependencies > simplify build configuration, Automatic configuration of Spring and 3rd party libraries.", "pages": [2], "end_pos": 1790, "summary": "Introduction to Spring Boot features including embedded servers and starter dependencies.", "start_pos": 1521, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_008", "text": "Role of Spring Boot in Microservices: Enables stand-alone applications with embedded servers. Simplifies configuration with auto-configuration and sensible defaults. Integrates with Spring Cloud for service discovery, load balancing, etc. Supports containerization for modern deployment environments.", "pages": [2], "end_pos": 2060, "summary": "Description of how Spring Boot supports the Microservices architecture specifically.", "start_pos": 1791, "chunk_type": "application", "has_examples": false, "main_concepts": ["CONC_003"], "has_definitions": false, "secondary_concepts": ["CONC_002"]}, {"id": "CHUNK_009", "text": "What is REST? Representational State Transfer. Architectural style for designing networked applications. Uses HTTP as the foundation. Relies on standard HTTP methods (GET, POST, PUT, DELETE). Leverages resource-based URLs for identification. Supports multiple data formats (e.g., JSON, XML).", "pages": [3], "end_pos": 2330, "summary": "Definition and core principles of the REST architectural style for APIs.", "start_pos": 2061, "chunk_type": "definition", "has_examples": false, "main_concepts": ["CONC_004"], "has_definitions": true, "secondary_concepts": []}, {"id": "CHUNK_010", "text": "REST Resource Identification: Resources are central components in REST architecture representing entities (e.g., users, products). Unique and descriptive URIs assigned to each resource. Hierarchical structure for easy organization (e.g., /products/1, /users/2). Accessing resources using HTTP methods map to CRUD operations.", "pages": [3], "end_pos": 2600, "summary": "Detailed explanation of how resources are identified and accessed within RESTful systems.", "start_pos": 2331, "chunk_type": "technical_detail", "has_examples": true, "main_concepts": ["CONC_004"], "has_definitions": false, "secondary_concepts": []}], "concepts": [{"id": "CONC_001", "title": "Monolithic Architecture", "aliases": ["Traditional Web Application", "Single Unit Architecture"], "keywords": ["monolith", "tightly-coupled", "indivisible unit", "WAR file", "single codebase"], "confidence": 0.98, "difficulty": 3, "description": "A monolithic architecture is a software design where the entire application is built as a single, indivisible unit. Components are tightly coupled and interdependent, meaning they cannot function or deploy independently. All business logic, data access, and user interface layers reside within one codebase. Deployment involves building and running the entire application on a runtime server, often packaged as a WAR file.", "concept_type": "architecture", "extracted_from": ["CHUNK_001", "CHUNK_002"], "related_concepts": ["CONC_002"]}, {"id": "CONC_002", "title": "Microservices Architecture", "aliases": ["Microservice Architecture", "SOA Pattern"], "keywords": ["loosely coupled", "independent deployment", "distributed system", "lightweight communication", "business capabilities"], "confidence": 0.97, "difficulty": 4, "description": "Microservices architecture structures an application as a suite of small services, each running in its own process and communicating via lightweight mechanisms like HTTP APIs. Services are loosely coupled, independently deployable, and organized around business capabilities. This approach allows for different technologies to be used per service and enables independent scaling of components rather than the whole application.", "concept_type": "architecture", "extracted_from": ["CHUNK_003", "CHUNK_004"], "related_concepts": ["CONC_001", "CONC_003"]}, {"id": "CONC_003", "title": "Spring Boot", "aliases": ["Spring Framework Tooling"], "keywords": ["auto-configuration", "embedded server", "starter dependencies", "stand-alone", "production-ready"], "confidence": 0.99, "difficulty": 3, "description": "Spring Boot is a framework designed to simplify the creation of Spring-based applications. It provides production-grade features such as auto-configuration, embedded servers (Tomcat, Jetty), and starter dependencies that reduce boilerplate configuration. It enables stand-alone applications without needing external WAR files and supports containerization for modern deployment environments.", "concept_type": "object", "extracted_from": ["CHUNK_007", "CHUNK_008"], "related_concepts": ["CONC_002"]}, {"id": "CONC_004", "title": "REST API", "aliases": ["RESTful Interface", "RESTful Web Service"], "keywords": ["HTTP methods", "resource-based URLs", "stateless", "JSON/XML", "API communication"], "confidence": 0.95, "difficulty": 3, "description": "Representational State Transfer (REST) is an architectural style for designing networked applications using standard HTTP methods (GET, POST, PUT, DELETE). It relies on resource-based URLs, stateless interactions, and separation of concerns between client and server. Resources can be represented in various formats like JSON or XML, facilitating loose coupling and scalability.", "concept_type": "theory", "extracted_from": ["CHUNK_009", "CHUNK_010"], "related_concepts": ["CONC_002"]}, {"id": "CONC_005", "title": "Loose Coupling", "aliases": ["Weak Coupling"], "keywords": ["minimal dependency", "maintainability", "scalability", "independence"], "confidence": 0.96, "difficulty": 2, "description": "Loose coupling describes a design principle where components have minimal dependency on one another. In microservices, changes in one service do not directly affect others, allowing for easier maintenance, testing, and independent scaling. It contrasts with tight coupling found in monolithic systems.", "concept_type": "theory", "extracted_from": ["CHUNK_004", "CHUNK_006"], "related_concepts": ["CONC_002"]}], "relationships": [{"id": "REL_001", "type": "opposite_of", "source": "CONC_001", "target": "CONC_002", "evidence": "The document explicitly compares Monolithic and Microservices architectures highlighting their opposing characteristics regarding coupling and deployment.", "strength": 1.0, "bidirectional": true}, {"id": "REL_002", "type": "requires", "source": "CONC_002", "target": "CONC_005", "evidence": "Microservices architecture involves smaller applications deployed independently as loosely coupled services tied together through application integration.", "strength": 0.9, "bidirectional": false}, {"id": "REL_003", "type": "implements", "source": "CONC_003", "target": "CONC_002", "evidence": "Role of Spring Boot in Microservices includes enabling stand-alone applications with embedded servers and integrating with Spring Cloud for service discovery.", "strength": 0.85, "bidirectional": false}, {"id": "REL_004", "type": "consumes", "source": "CONC_004", "target": "CONC_002", "evidence": "Microservices communicate with other microservices through APIs which follow REST principles like statelessness and resource identification.", "strength": 0.8, "bidirectional": false}, {"id": "REL_005", "type": "similar_to", "source": "CONC_001", "target": "CONC_005", "evidence": "Monolithic architecture is described as tightly-coupled, whereas loose coupling is a defining feature of Microservices.", "strength": 0.1, "bidirectional": false}], "quality_metrics": {"total_chunks": 10, "missing_links": [], "coverage_score": 0.92, "total_concepts": 5, "consistency_score": 0.95, "total_relationships": 5}, "document_metadata": {"title": "Monolithic architecture vs. Microservices architecture ITP4511", "language": "English", "main_topic": "Enterprise System Development: Architectural Patterns", "difficulty_level": "Intermediate", "estimated_reading_time": "6 minutes"}, "concept_chunk_mapping": [{"concept": "Monolithic Architecture", "context": "Defines monolithic software as self-contained and tightly-coupled.", "chunk_id": "CHUNK_001", "positions": [0], "concept_id": "CONC_001", "importance": "primary"}, {"concept": "Monolithic Architecture", "context": "Details the weaknesses and scalability issues of monolithic applications.", "chunk_id": "CHUNK_004", "positions": [0], "concept_id": "CONC_001", "importance": "secondary"}, {"concept": "Microservices Architecture", "context": "Provides Martin Fowler''s definition of microservice architecture.", "chunk_id": "CHUNK_005", "positions": [0], "concept_id": "CONC_002", "importance": "primary"}, {"concept": "Loose Coupling", "context": "Lists loose coupling as a key feature of microservices.", "chunk_id": "CHUNK_006", "positions": [20], "concept_id": "CONC_005", "importance": "primary"}, {"concept": "Spring Boot", "context": "Introduces Spring Boot framework features like auto-configuration.", "chunk_id": "CHUNK_007", "positions": [0], "concept_id": "CONC_003", "importance": "primary"}, {"concept": "REST API", "context": "Defines REST as an architectural style using HTTP methods and resource URLs.", "chunk_id": "CHUNK_009", "positions": [0], "concept_id": "CONC_004", "importance": "primary"}]}', '{"total_modules": 5, "total_concepts": 28, "difficulty_score": 6, "total_structures": 16, "total_applications": 8}', '"[{\"id\":\"CHUNK_001\",\"text\":\"Monolithic architecture: Monolithic software is designed to be self-contained; components of the program are interconnected and interdependent. Is a tightly-coupled architecture. Each component and its associated components must be present in order for code to be executed or compiled.\",\"pages\":[1],\"start_pos\":0,\"end_pos\":245,\"summary\":\"Definition of Monolithic Architecture focusing on self-containment and tight coupling.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_002\",\"text\":\"Monolithic Applications handle multiple related tasks (e.g., ecommerce SaaS). The application might contain a web server, UI Handler, catalog service, ordering system, payment function, Shipping service, Accounting service, and a load balancer. Traditional web application architecture uses WAR files.\",\"pages\":[1],\"start_pos\":246,\"end_pos\":500,\"summary\":\"Examples of components within a Monolithic Application including legacy architecture references.\",\"chunk_type\":\"example\",\"has_examples\":true,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_003\",\"text\":\"Strengths of the Monolithic Architecture: Less cross-cutting concerns, easier debugging and testing since it is a single indivisible unit. End-to-end testing is much faster. Simple to deploy by putting the WAR file on runtime. Simple to develop as it follows a standard way.\",\"pages\":[1],\"start_pos\":501,\"end_pos\":750,\"summary\":\"Analysis of the strengths of Monolithic Architecture including deployment simplicity.\",\"chunk_type\":\"analysis\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_004\",\"text\":\"Weaknesses of the Monolithic Architecture: Understanding becomes hard as scale increases. Making changes affects the whole system due to tight coupling. Scalability cannot happen at the component level. Applying new technology requires rewriting the entire application.\",\"pages\":[1],\"start_pos\":751,\"end_pos\":990,\"summary\":\"Analysis of the weaknesses of Monolithic Architecture focusing on complexity and rigidity.\",\"chunk_type\":\"analysis\",\"has_examples\":false,\"main_concepts\":[\"CONC_001\"],\"has_definitions\":false,\"secondary_concepts\":[]},{\"id\":\"CHUNK_005\",\"text\":\"Microservice architecture: An alternative pattern addressing monolithic limitations. Martin Fowler defines it as developing a single application as a suite of small services, each running in its own process communicating with lightweight mechanisms, often HTTP resource API.\",\"pages\":[1],\"start_pos\":991,\"end_pos\":1250,\"summary\":\"Definition of Microservice Architecture citing industry expert definitions.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_006\",\"text\":\"What are microservices? Smaller applications deployed independently as loosely coupled services. Features: Highly maintainable and testable, loosely coupled, independently deployable, organized around business capabilities, owned by a small team. Software engineering approach decomposing into single-function modules.\",\"pages\":[1],\"start_pos\":1251,\"end_pos\":1520,\"summary\":\"List of key features and definitions associated with Microservices Architecture.\",\"chunk_type\":\"features\",\"has_examples\":false,\"main_concepts\":[\"CONC_002\"],\"has_definitions\":true,\"secondary_concepts\":[\"CONC_005\"]},{\"id\":\"CHUNK_007\",\"text\":\"Introduction to Spring Boot: Spring Boot is a framework that makes it easy to create Spring-based applications: Stand-alone & production-grade. Embedded Tomcat, Jetty or Undertow server. Starter dependencies > simplify build configuration, Automatic configuration of Spring and 3rd party libraries.\",\"pages\":[2],\"start_pos\":1521,\"end_pos\":1790,\"summary\":\"Introduction to Spring Boot features including embedded servers and starter dependencies.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_008\",\"text\":\"Role of Spring Boot in Microservices: Enables stand-alone applications with embedded servers. Simplifies configuration with auto-configuration and sensible defaults. Integrates with Spring Cloud for service discovery, load balancing, etc. Supports containerization for modern deployment environments.\",\"pages\":[2],\"start_pos\":1791,\"end_pos\":2060,\"summary\":\"Description of how Spring Boot supports the Microservices architecture specifically.\",\"chunk_type\":\"application\",\"has_examples\":false,\"main_concepts\":[\"CONC_003\"],\"has_definitions\":false,\"secondary_concepts\":[\"CONC_002\"]},{\"id\":\"CHUNK_009\",\"text\":\"What is REST? Representational State Transfer. Architectural style for designing networked applications. Uses HTTP as the foundation. Relies on standard HTTP methods (GET, POST, PUT, DELETE). Leverages resource-based URLs for identification. Supports multiple data formats (e.g., JSON, XML).\",\"pages\":[3],\"start_pos\":2061,\"end_pos\":2330,\"summary\":\"Definition and core principles of the REST architectural style for APIs.\",\"chunk_type\":\"definition\",\"has_examples\":false,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":true,\"secondary_concepts\":[]},{\"id\":\"CHUNK_010\",\"text\":\"REST Resource Identification: Resources are central components in REST architecture representing entities (e.g., users, products). Unique and descriptive URIs assigned to each resource. Hierarchical structure for easy organization (e.g., /products/1, /users/2). Accessing resources using HTTP methods map to CRUD operations.\",\"pages\":[3],\"start_pos\":2331,\"end_pos\":2600,\"summary\":\"Detailed explanation of how resources are identified and accessed within RESTful systems.\",\"chunk_type\":\"technical_detail\",\"has_examples\":true,\"main_concepts\":[\"CONC_004\"],\"has_definitions\":false,\"secondary_concepts\":[]}]"', '"[{\"id\":\"CONC_001\",\"title\":\"Monolithic Architecture\",\"aliases\":[\"Traditional Web Application\",\"Single Unit Architecture\"],\"keywords\":[\"monolith\",\"tightly-coupled\",\"indivisible unit\",\"WAR file\",\"single codebase\"],\"confidence\":0.98,\"difficulty\":3,\"description\":\"A monolithic architecture is a software design where the entire application is built as a single, indivisible unit. Components are tightly coupled and interdependent, meaning they cannot function or deploy independently. All business logic, data access, and user interface layers reside within one codebase. Deployment involves building and running the entire application on a runtime server, often packaged as a WAR file.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_001\",\"CHUNK_002\"],\"related_concepts\":[\"CONC_002\"]},{\"id\":\"CONC_002\",\"title\":\"Microservices Architecture\",\"aliases\":[\"Microservice Architecture\",\"SOA Pattern\"],\"keywords\":[\"loosely coupled\",\"independent deployment\",\"distributed system\",\"lightweight communication\",\"business capabilities\"],\"confidence\":0.97,\"difficulty\":4,\"description\":\"Microservices architecture structures an application as a suite of small services, each running in its own process and communicating via lightweight mechanisms like HTTP APIs. Services are loosely coupled, independently deployable, and organized around business capabilities. This approach allows for different technologies to be used per service and enables independent scaling of components rather than the whole application.\",\"concept_type\":\"architecture\",\"extracted_from\":[\"CHUNK_003\",\"CHUNK_004\"],\"related_concepts\":[\"CONC_001\",\"CONC_003\"]},{\"id\":\"CONC_003\",\"title\":\"Spring Boot\",\"aliases\":[\"Spring Framework Tooling\"],\"keywords\":[\"auto-configuration\",\"embedded server\",\"starter dependencies\",\"stand-alone\",\"production-ready\"],\"confidence\":0.99,\"difficulty\":3,\"description\":\"Spring Boot is a framework designed to simplify the creation of Spring-based applications. It provides production-grade features such as auto-configuration, embedded servers (Tomcat, Jetty), and starter dependencies that reduce boilerplate configuration. It enables stand-alone applications without needing external WAR files and supports containerization for modern deployment environments.\",\"concept_type\":\"object\",\"extracted_from\":[\"CHUNK_007\",\"CHUNK_008\"],\"related_concepts\":[\"CONC_002\"]},{\"id\":\"CONC_004\",\"title\":\"REST API\",\"aliases\":[\"RESTful Interface\",\"RESTful Web Service\"],\"keywords\":[\"HTTP methods\",\"resource-based URLs\",\"stateless\",\"JSON/XML\",\"API communication\"],\"confidence\":0.95,\"difficulty\":3,\"description\":\"Representational State Transfer (REST) is an architectural style for designing networked applications using standard HTTP methods (GET, POST, PUT, DELETE). It relies on resource-based URLs, stateless interactions, and separation of concerns between client and server. Resources can be represented in various formats like JSON or XML, facilitating loose coupling and scalability.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_009\",\"CHUNK_010\"],\"related_concepts\":[\"CONC_002\"]},{\"id\":\"CONC_005\",\"title\":\"Loose Coupling\",\"aliases\":[\"Weak Coupling\"],\"keywords\":[\"minimal dependency\",\"maintainability\",\"scalability\",\"independence\"],\"confidence\":0.96,\"difficulty\":2,\"description\":\"Loose coupling describes a design principle where components have minimal dependency on one another. In microservices, changes in one service do not directly affect others, allowing for easier maintenance, testing, and independent scaling. It contrasts with tight coupling found in monolithic systems.\",\"concept_type\":\"theory\",\"extracted_from\":[\"CHUNK_004\",\"CHUNK_006\"],\"related_concepts\":[\"CONC_002\"]}]"', '"[{\"id\":\"REL_001\",\"type\":\"opposite_of\",\"source\":\"CONC_001\",\"target\":\"CONC_002\",\"evidence\":\"The document explicitly compares Monolithic and Microservices architectures highlighting their opposing characteristics regarding coupling and deployment.\",\"strength\":1,\"bidirectional\":true},{\"id\":\"REL_002\",\"type\":\"requires\",\"source\":\"CONC_002\",\"target\":\"CONC_005\",\"evidence\":\"Microservices architecture involves smaller applications deployed independently as loosely coupled services tied together through application integration.\",\"strength\":0.9,\"bidirectional\":false},{\"id\":\"REL_003\",\"type\":\"implements\",\"source\":\"CONC_003\",\"target\":\"CONC_002\",\"evidence\":\"Role of Spring Boot in Microservices includes enabling stand-alone applications with embedded servers and integrating with Spring Cloud for service discovery.\",\"strength\":0.85,\"bidirectional\":false},{\"id\":\"REL_004\",\"type\":\"consumes\",\"source\":\"CONC_004\",\"target\":\"CONC_002\",\"evidence\":\"Microservices communicate with other microservices through APIs which follow REST principles like statelessness and resource identification.\",\"strength\":0.8,\"bidirectional\":false},{\"id\":\"REL_005\",\"type\":\"similar_to\",\"source\":\"CONC_001\",\"target\":\"CONC_005\",\"evidence\":\"Monolithic architecture is described as tightly-coupled, whereas loose coupling is a defining feature of Microservices.\",\"strength\":0.1,\"bidirectional\":false}]"', '2026-04-28 15:06:37.448628', '2026-04-28 15:06:37.448628', NULL, '[{"id": "module_1", "name": "Monolithic Architecture", "topic_count": 10}, {"id": "module_2", "name": "Microservice Architecture", "topic_count": 12}, {"id": "module_3", "name": "Architecture Comparison", "topic_count": 10}, {"id": "module_4", "name": "Spring Boot for Microservices", "topic_count": 8}, {"id": "module_5", "name": "REST API Principles and Interactions", "topic_count": 12}]', NULL, 'Monolithic architecture vs. Microservices architecture ITP4511 — Enterprise System Development

Monolithic architecture
•
Monolithic software is designed to be self-contained; 
•
components of the program are interconnected and 
interdependent
•
is a tightly-coupled architecture
•
Each component and its associated components must be 
present in order for code to be executed or compiled.

Monolithic Architecture
•
Server-side enterprise application. 
•
It MUST support a variety of different clients 
•
desktop browsers, 
•
mobile browsers
•
native mobile applications. 
•
The application might also 
•
expose an API for 3rd parties. 
•
integrate with other applications via either web services or a message broker. 
•
The application handles requests (HTTP requests and messages) 
•
by executing business logic; 
•
accessing a database; 
•
exchanging messages with other systems; and returning a HTML/JSON/XML response. 
•
There are logical components corresponding to different functional areas of the 
application.
Monolithic Architecture

Monolithic applications
•
Monolithic application is designed to handle multiple related 
tasks.
•
For example, a monolithic ecommerce SaaS application. The same 
application might contain 
•
a web server, 
•
UI Handler
•
a catalog service that services up product images, 
•
an ordering system,
•
a payment function, 
•
Shipping service.
•
Accounting service 
•
a load balancer
“Traditional web application architecture WAR ‘StoreFronUl ‘Accounting Service develop test deploy scale’

Strengths of the Monolithic Architecture
•
Less cross-cutting concerns. 
•
monolithic application focus on it own functionalities. so it is easier to handle 
Strengths of the Monolithic Architecture.
•
Easier debugging and testing. 
•
easy to debug and test since a monolithic app is a single indivisible unit
•
End-to-end testing much faster.
•
Simple to deploy. 
•
monolithic applications do not have to handle many deployments 
•
simply deploy the WAR file (or directory hierarchy) on the appropriate 
runtime
•
Simple to develop. 
•
is a standard way of building applications
“Traditional web application architecture WAR ‘StoreFronUl ‘Accounting Service develop test deploy scale’

Weaknesses of the Monolithic 
Architecture
•
Understanding
•
large monolithic application scales up  becomes too complicated to understand. 
•
A complex system of code within one application is hard to manage.
•
Making changes. 
•
It is harder to implement changes in such a large and complex application with 
highly tight coupling. 
•
Any code change affects the whole system. Overall development process take  
much longer.
•
Scalability
•
cannot scale components independently, only the whole application.
•
New technology barriers.
•
It is extremely problematic to apply a new technology in a monolithic application 
because then the entire application has to be rewritten.

Microservice architecture
•
The microservice architecture is an alternative pattern that 
addresses the limitations of the monolithic architecture.
“the microservice architectural style is an approach to developing a single application as a suite of small 
services, each running in its own process and communicating with lightweight mechanisms, often an HTTP 
resource API.”
Martin Fowler

What are microservices?
•
Microservices architecture involves smaller applications deployed 
independently as loosely coupled services, tied together through 
application integration
•
Microservices  also known as the microservice architecture – is an 
architectural style that structures an application as a collection of 
services that are
•
Highly maintainable and testable
•
Loosely coupled
•
Independently deployable
•
Organized around business capabilities
•
Owned by a small team
