INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('da81f7f0-8a20-4193-872d-9ccd4316cff5', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '5bf5e878-857b-49c6-8458-50134184e6e5', NULL, 'The Architect''s Fall: A System in Crisis', 'active', 'easy', 'beginner', '{"clues": [{"name": "Legacy WAR Deployment Log", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The system was still operating under a traditional monolithic architecture at the time of failure.", "description": "A system log entry showing the final deployment of the monolithic application as a single WAR file to the central server. Timestamp matches the last stable system state.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "Hidden Microservices Commit", "type": "digital", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Jax attempted to introduce microservices into the environment without approval.", "description": "An encrypted Git commit authored by Jax, dated two hours before the crash. Contains code for a standalone Spring Boot service intended to run alongside the main system.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "REST API Endpoint List", "type": "digital", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "The unauthorized microservice used REST APIs for communication between components.", "description": "A configuration file fragment listing internal endpoints like /api/users and /api/orders with HTTP methods noted. Found in a deleted folder labeled ''micro-experiment''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004"]}, {"name": "System Coupling Analysis", "type": "report", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "The core system exhibits classic signs of monolithic architecture where changes in one module affect the entire system.", "description": "Automated dependency scan revealing that all modules share the same database connection and cannot be restarted independently. A red flag for tight coupling.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "Spring Boot Configuration Snippet", "type": "digital", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "The experimental service used Spring Boot’s auto-configuration and embedded server features.", "description": "A partial application.yml file containing ''server.port: 8082'' and ''spring.application.name: inventory-service'', indicating an embedded server setup.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003"]}, {"name": "Final System Timeline", "type": "timeline", "clueId": "CLUE_B1_006", "foundBy": "CHAR_001", "reveals": "The timing suggests the independent deployment of a loosely coupled service disrupted tightly integrated components.", "description": "Chronological log of events leading up to the crash: Dr. Moss approved a minor patch, then Jax''s service went live, followed by cascading failures across interdependent modules.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Dr. Moss''s Private Notes", "type": "document", "clueId": "CLUE_B1_007", "foundBy": "CHAR_001", "reveals": "Dr. Moss was aware of architectural vulnerabilities and actively resisted change to protect her legacy.", "description": "Handwritten notes recovered from her desk drawer stating: ''If they push microservices, the whole house of cards falls. Must maintain control.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001"]}, {"name": "Fragmented Service Log", "type": "document", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Evidence that services are loosely coupled—failure in one did not immediately halt all operations.", "description": "A log file recovered from a backup drive shows timestamps of microservices communicating via HTTP APIs. One service restarted repeatedly just before the crash, but others continued operating normally.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Isolated Deployment Record", "type": "system_log", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Demonstrates independent deployability—a hallmark of loose coupling in microservices.", "description": "Deployment logs show that ''PaymentService'' was updated independently while ''OrderService'' remained unchanged. No recompilation or restart of the full platform occurred.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Architectural Whiteboard Sketch", "type": "image", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Jax’s design philosophy emphasizes minimal interdependence between components.", "description": "A whiteboard photo from Jax’s lab station shows boxes labeled ''User Auth'', ''Catalog'', and ''Shipping'' with arrows marked ''REST API''. A note reads: ''No shared DBs – keep dependencies minimal.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "System Dependency Map", "type": "diagram", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Structural proof of weak coupling in the new architecture; changes in one service do not force changes in another.", "description": "A network diagram extracted from configuration files reveals no direct database links between services. Each connects only through defined API endpoints.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005"]}, {"name": "Final Message from Dr. Moss", "type": "text_message", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "Dr. Moss resisted architectural decentralization, fearing loss of authority over tightly integrated systems.", "description": "Recovered chat log: ''If we allow this level of independence, how can I ensure control? The system must remain unified under my oversight.'' Sent minutes before collapse.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005"]}, {"name": "Microservice Independence Test", "type": "test_result", "clueId": "CLUE_B2_006", "foundBy": "CHAR_001", "reveals": "Functional validation of loose coupling—services operate independently even during partial outages.", "description": "Automated test report shows that when the Notification service was taken offline, the Checkout service continued processing transactions for 8+ minutes.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005"]}], "title": "The Architect''s Fall: A System in Crisis", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Room", "sceneId": "SCENE_001", "location": "Monolithic Inc. War Room", "description": "The emergency response team gathers after a catastrophic system failure. Dr. Moss lies unconscious at the central console. Alarms flash red. Logs show cascading errors across services. Detective Lin arrives as internal investigators seal the room.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code & Conflict", "sceneId": "SCENE_002", "location": "Development Lab", "description": "Lin reviews recent commits and deployment logs with Jax. Tensions surface over architectural disagreements. Hidden files reveal unauthorized changes and documentation pointing to structural weaknesses in the old system.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Deployment", "sceneId": "SCENE_003", "location": "Server Vault", "description": "All surviving characters converge in the secure server vault where the final deployment occurred. Evidence reveals whether the system failed naturally—or was sabotaged. The truth emerges through log timestamps, configuration files, and last messages from Dr. Moss.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Uncompiled", "content": "The system didn''t fail due to malice—it collapsed under its own weight. Dr. Moss refused to adopt microservices and loose coupling. Jax''s well-intentioned fix exposed the fragility. No crime was committed—only technical debt left unaddressed.", "debrief": "You''ve learned that architecture choices have real consequences. Monolithic systems can become unsustainable, while microservices require discipline. Loose coupling isn''t optional—it''s essential.", "summary": "The death was accidental, caused by systemic failure. The true culprit: outdated design decisions.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Scapegoat Protocol", "content": "You accuse Jax of sabotage. He is terminated. But within days, the same failure recurs. Without understanding the root cause—the monolith’s rigidity—the cycle repeats.", "debrief": "Jumping to conclusions without full evidence leads to injustice. Technical problems often stem from structure, not individuals.", "summary": "Blame was misplaced. The system remains broken.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes tech summit held inside a secure innovation lab, the lead architect of a failing enterprise system is found dead—was it sabotage? Three developers must uncover the truth behind the collapse of Monolithic Inc.''s flagship platform before the next deployment dooms the company.", "version": "1.0", "evidence": [{"name": "System Failure Log", "type": "Digital Record", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Log entries showing a cascade of failures originating from the core monolith during peak load. Timestamps suggest no external attack.", "foundLocation": "Central Console - SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "Unauthorized Microservice Commit", "type": "Git Repository Snapshot", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A hidden commit by Jax introducing a Spring Boot service that bypassed approval workflows. It called critical endpoints without rate limiting.", "foundLocation": "Development Lab Terminal - SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "Final Configuration File", "type": "Server Manifest", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "The last deployment manifest shows mismatched versions between services. One component expected loose coupling via REST, but the monolith forced synchronous calls.", "foundLocation": "Server Vault - SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_001", "CONC_002"]}], "has_quiz": false, "scriptId": "ESD_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the last known stable deployment log. The system was packaged and deployed as a single WAR file. What does this indicate about the application’s architecture?", "options": [{"content": "It uses a microservices architecture with independent deployments.", "feedback": "Incorrect. Microservices are independently deployable and would not rely on a single WAR file. This points away from distributed services.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It is a monolithic architecture, where all components are bundled into one unit.", "feedback": "Correct. A WAR file deployment is characteristic of monolithic applications, where the entire system must be built and deployed together.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "It uses REST APIs to communicate between modular frontends.", "feedback": "Incorrect. While REST can exist in any architecture, the use of a WAR file strongly indicates a monolithic structure, not modular independence.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It leverages Spring Boot for auto-configuration and embedded servers.", "feedback": "Incorrect. Spring Boot typically avoids WAR files in favor of standalone JARs with embedded servers. This deployment method contradicts that pattern.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin runs a dependency analysis on the core system. The report shows that updating the payment module requires restarting the entire application. What architectural trait does this reveal?", "options": [{"content": "Loose coupling, typical of microservices.", "feedback": "Incorrect. Loose coupling allows components to operate independently. Requiring a full restart indicates tight interdependence.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Tight coupling, a hallmark of monolithic design.", "feedback": "Correct. In monolithic systems, components are tightly coupled, meaning changes in one area often require redeploying the entire application.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_004"]}, {"content": "Stateless communication via REST APIs.", "feedback": "Incorrect. Stateless communication doesn''t explain deployment behavior. The need to restart everything points to structural coupling, not API style.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Independent scalability of services.", "feedback": "Incorrect. Independent scaling is only possible in loosely coupled systems like microservices. This system clearly lacks that capability.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Jax shows Lin a hidden branch in the repo with a new service using Spring Boot. ''It starts fast and runs on its own,'' he says. Which feature of Spring Boot enables this standalone behavior?", "options": [{"content": "Auto-configuration and embedded server support.", "feedback": "Correct. Spring Boot includes embedded servers like Tomcat, allowing applications to run without external deployment containers.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_005"]}, {"content": "Use of WAR files for easy deployment.", "feedback": "Incorrect. Spring Boot favors standalone JARs over WAR files. Using WARs would contradict its goal of simplifying deployment.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Monolithic packaging for unified testing.", "feedback": "Incorrect. Monolithic packaging is unrelated to Spring Boot’s purpose. Spring Boot is designed to enable microservices, not reinforce monoliths.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Manual XML configuration for precise control.", "feedback": "Incorrect. Spring Boot reduces manual configuration through auto-configuration, making XML setup unnecessary in most cases.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Among the deleted files, Lin finds a list of endpoints: GET /products, POST /orders, DELETE /users. What architectural style do these patterns suggest?", "options": [{"content": "Monolithic routing table for internal navigation.", "feedback": "Incorrect. While monoliths may have routes, the use of standard HTTP methods with resource-based URLs is characteristic of REST, not general routing.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "REST API design using stateless operations on resources.", "feedback": "Correct. These endpoints follow REST conventions: nouns for resources and HTTP verbs for actions, enabling loose coupling and scalability.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "SOAP web services with XML payloads.", "feedback": "Incorrect. SOAP uses complex envelopes and often POST-only calls. These clean, verb-driven URLs point to REST, not SOAP.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Server-sent events for real-time updates.", "feedback": "Incorrect. Server-sent events are for streaming data, not CRUD operations on discrete resources like users or orders.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines deployment records showing individual services being updated without affecting others. What principle does this demonstrate?", "options": [{"content": "Tight Coupling", "feedback": "Incorrect. Tight coupling would require all components to be redeployed together. This scenario shows the opposite behavior.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Loose Coupling", "feedback": "Correct. Loose coupling allows services to be modified and deployed independently, which is evident in the isolated update pattern.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "Monolithic Integration", "feedback": "Incorrect. In a monolith, changing one part typically requires rebuilding and restarting the entire application.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Cross-Cutting Concerns", "feedback": "Incorrect. Cross-cutting concerns refer to functionality spanning multiple modules (like logging), not deployment independence.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin reviews Jax’s whiteboard sketch showing services connected only by REST APIs and labeled ''no shared DBs''. What architectural goal is he trying to achieve?", "options": [{"content": "Maximize inter-service dependencies", "feedback": "Incorrect. That would increase fragility. Jax is clearly trying to reduce dependencies, not maximize them.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Ensure all services share the same database", "feedback": "Incorrect. Sharing databases increases coupling. His note explicitly avoids this.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Achieve loose coupling through minimal dependencies", "feedback": "Correct. By avoiding shared databases and using standardized APIs, Jax reduces direct dependencies between services.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "Simplify debugging through centralized logging", "feedback": "Incorrect. While useful, centralized logging isn''t the focus here. The sketch emphasizes structural independence.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "After analyzing logs, Lin sees that a failed notification service didn’t stop order processing. Which concept explains this resilience?", "options": [{"content": "Tight Coupling", "feedback": "Incorrect. Tightly coupled systems fail entirely when one component fails. This system showed partial failure tolerance.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Shared Memory Access", "feedback": "Incorrect. Shared memory increases dependency and risk—if one process corrupts it, others suffer.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Loose Coupling", "feedback": "Correct. Because services are loosely coupled, the failure of one doesn’t directly impact the operation of others.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "Centralized Control", "feedback": "Incorrect. Centralized control usually implies tighter coordination and higher coupling, not independent operation.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_003", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 7, "content": "Detective Lin notes that changes in one microservice do not force changes in others. This design principle is known as ________ coupling.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_007", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["loose", "weak"], "feedbackCorrect": "Correct. Both ''loose'' and ''weak'' are used interchangeably to describe minimal dependency between components.", "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": "Incorrect. Think about the opposite of ''tight''—the goal is to minimize direct dependencies so services can evolve independently."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "Lin pieces together the timeline: Dr. Moss maintained a rigid monolith, while Jax introduced a loosely coupled Spring Boot service using REST. What fundamental architectural conflict does this represent?", "options": [{"content": "Centralized vs. decentralized authentication.", "feedback": "Incorrect. The conflict isn''t about security—it''s about how the system is structured and whether components can evolve independently.", "optionId": "OPT_B1_017", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Monolithic integration versus microservices independence.", "feedback": "Correct. The core tension is between a single, tightly-coupled system and a distributed model where services are loosely coupled and independently deployable.", "optionId": "OPT_B1_018", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_006"]}, {"content": "Synchronous vs. asynchronous messaging queues.", "feedback": "Incorrect. While relevant in distributed systems, there''s no evidence of message queues here. The issue lies in deployment and coupling models.", "optionId": "OPT_B1_019", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "UI rendering on server vs. client side.", "feedback": "Incorrect. The conflict is backend architectural—about service boundaries and deployment—not frontend rendering strategies.", "optionId": "OPT_B1_020", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Dr. Moss approves a minor configuration update to the monolith."}, {"itemId": "ITEM_B1_002", "content": "Jax deploys an experimental Spring Boot service to improve order processing."}, {"itemId": "ITEM_B1_003", "content": "Multiple services begin failing due to database connection exhaustion."}, {"itemId": "ITEM_B1_004", "content": "The central console goes dark; alarms trigger across the war room."}], "order": 6, "content": "Reconstruct the sequence of events based on log timestamps and witness statements. Arrange the following in chronological order:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_006", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence shows how a small change in the monolith followed by an independent microservice deployment led to cascading failure—highlighting integration risks between architectures.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Incorrect. Remember: the monolith update came first, then the new service launch, followed by system strain and finally total collapse. This order reveals the cause-and-effect chain."}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 7, "content": "In reviewing Dr. Moss''s private notes, Detective Lin reads: ''The platform may be slow, but it’s predictable. If we break it into smaller parts communicating over HTTP APIs, we lose control.'' She is referring to a shift from a monolithic architecture to a ________ architecture.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_007", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["microservices", "microservice"], "feedbackCorrect": "Correct. Dr. Moss feared transitioning to a microservices architecture, where independent services communicate over APIs like HTTP, reducing centralized control.", "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": "Incorrect. The key clue is ''smaller parts communicating over HTTP APIs''—this describes microservices, not monoliths or other patterns."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Moss’s final message expresses concern about losing control if services become too independent. How does loose coupling challenge traditional monolithic oversight?", "options": [{"content": "It makes the system harder to monitor with legacy tools", "feedback": "Partially true, but not the core issue. The deeper problem is structural autonomy undermining centralized authority.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It allows teams to make changes without central approval", "feedback": "Correct. Loose coupling enables independent development and deployment, reducing reliance on top-down control.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_005"]}, {"content": "It requires more documentation", "feedback": "Incorrect. While documentation helps, it''s not a defining consequence of loose coupling.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It slows down release cycles", "feedback": "Incorrect. On the contrary, loose coupling accelerates releases by enabling independent deployments.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_004", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "The dependency map shows no direct database links between services—only API calls. Why is this significant for system maintainability?", "options": [{"content": "It increases data consistency across services", "feedback": "Incorrect. Independent databases may lead to eventual consistency, not stronger immediate consistency.", "optionId": "OPT_B2_017", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It prevents any service from failing", "feedback": "Incorrect. Services can still fail individually. The benefit is isolation, not invulnerability.", "optionId": "OPT_B2_018", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It minimizes ripple effects when updating components", "feedback": "Correct. With no shared databases, changes in one service won’t break others—an essential trait of loose coupling.", "optionId": "OPT_B2_019", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_004"]}, {"content": "It simplifies user authentication", "feedback": "Incorrect. Authentication complexity depends on implementation, not coupling style alone.", "optionId": "OPT_B2_020", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "NotificationService crashes due to malformed payload from new microservice"}, {"itemId": "ITEM_B2_002", "content": "Jax deploys experimental ''RecommendationEngine'' as standalone Spring Boot app"}, {"itemId": "ITEM_B2_003", "content": "OrderService continues processing despite outage in notifications"}, {"itemId": "ITEM_B2_004", "content": "System-wide alert triggered after cascading timeout in dependent modules"}], "order": 6, "content": "Arrange the events in chronological order based on log timestamps to reconstruct how the experimental microservice impacted the system.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_006", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence shows how an independently deployed service caused a failure in one area, yet others persisted—demonstrating both the risks and benefits of loose coupling.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Remember: the experimental service was deployed first, then caused a specific failure, while other services kept running until broader timeouts occurred."}], "characters": [{"age": 34, "goal": "Uncover the truth behind the victim’s death and prevent further damage to the company’s infrastructure.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Lin once worked at Monolithic Inc. and was fired after advocating for microservices when the victim rejected the idea.", "background": "A former software architect turned forensic analyst for enterprise outages, known for solving complex technical failures through logic and behavioral analysis.", "occupation": "Lead Systems Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and deeply curious about human motives behind code decisions.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_005"]}, {"age": 41, "goal": "Protect her reputation—even beyond death.", "name": "Dr. Elara Moss", "role": "Suspect", "scenes": ["SCENE_003"], "secret": "She falsified system health reports to hide the platform’s instability from investors.", "background": "Brilliant but stubborn pioneer of Monolithic Inc.''s legacy platform; resistant to change despite growing performance issues.", "occupation": "Chief Architect (Victim)", "characterId": "CHAR_002", "personality": "Authoritative, visionary, dismissive of newer trends she considers ''fads''.", "knowledgePoints": ["CONC_001"]}, {"age": 29, "goal": "Clear his name and prove that progress shouldn’t be punished.", "name": "Jax Renn", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Jax secretly deployed an experimental microservice that destabilized the main system hours before the incident.", "background": "Self-taught coder who pushed for modernization using Spring Boot and microservices; frequently clashed with Dr. Moss.", "occupation": "Junior Developer", "characterId": "CHAR_003", "personality": "Passionate, impulsive, idealistic about clean architecture.", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_004", "CONC_005"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Monolithic Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "A single-tiered software application where components are tightly coupled and run as one service. Easy to develop initially but hard to scale and maintain.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Microservices Architecture", "category": "Architecture", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "An approach where an application is made of small, independent services that communicate over defined APIs. Enables scalability and independent deployment.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Spring Boot", "category": "Framework", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 1, "description": "A framework that simplifies the creation of standalone, production-grade Spring-based applications with minimal configuration.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "REST API", "category": "Communication", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A standard way for services to communicate using HTTP methods. It allows microservices to interact without tight dependencies.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_002", "CONC_005"]}, {"name": "Loose Coupling", "category": "Design Principle", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A design principle where components depend minimally on each other, allowing changes in one part without affecting others.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004"]}], "educational_goals": ["Understand the differences between monolithic and microservices architectures", "Explain how Spring Boot enables rapid service development", "Define REST API principles and their role in inter-service communication", "Recognize the importance of loose coupling in scalable systems"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '3ba13be4eb5398c2076a2415a99de84a08098fbeff11a3a74d419d529f1969fb', 'all concepts', '2026-04-28 15:11:16.447193', NULL, 'ITP4511') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('71a21276-82b2-4b48-b819-9cd11852693b', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f36387e3-c216-4017-9cbe-c72560cc8ebb', NULL, 'The JDBC Connection Crime Scene', 'active', 'easy', 'standard', '{"clues": [{"name": "JDBC Architecture Diagram", "type": "documentary", "clueId": "CLUE_001", "foundBy": "On the wall beside the body", "reveals": "DriverManager is the central routing component — whoever controls it controls all DB access", "description": "Hand-drawn 4-layer diagram labeled: (1) Java App, (2) JDBC API, (3) DriverManager, (4) Vendor Driver. Layer 3 is circled with ''WHO ROUTES CALLS?''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007", "CONC_001"]}, {"name": "Corrupted Connection URL", "type": "digital", "clueId": "CLUE_002", "foundBy": "On victim''s terminal screen", "reveals": "Connection requires exact URL syntax — subprotocol, host, port, and subname must match driver expectations", "description": "Terminal log shows failed getConnection() call: ''jdbc:mysql://localhost:3306/pets?user=root&password=***'' — but port is wrong (3307)", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_012", "CONC_003"]}, {"name": "Whiteboard Annotation", "type": "physical", "clueId": "CLUE_003", "foundBy": "On Thorne''s whiteboard", "reveals": "Driver registration method matters — improper registration breaks DriverManager''s ability to locate drivers", "description": "Crossed-out ''Class.forName()'' with margin note: ''Use ServiceLoader — or risk ClassLoader leaks!''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_008"]}, {"name": "PetDB.java Snippet", "type": "code_sample", "clueId": "CLUE_004", "foundBy": "On Thorne''s desk", "reveals": "This violates JDBC best practices — string concatenation enables SQL injection and skips PreparedStatement benefits", "description": "Open file shows addRecord(Pet p) method using Statement.executeUpdate(''INSERT INTO pets...\" + p.getName() + \"...'')", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Side-by-Side Query Log", "type": "digital", "clueId": "CLUE_005", "foundBy": "On forensic workstation", "reveals": "Placeholders enable precompilation and reuse — preventing injection and improving performance", "description": "Two logs: [A] ''UPDATE pets SET name=\"'' + userInput + ''\"'' vs [B] ''UPDATE pets SET name=?'' → setString(1, userInput). Only [B] shows ''Prepared statement cached''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013", "CONC_005"]}, {"name": "ResultSet Iteration Note", "type": "documentary", "clueId": "CLUE_006", "foundBy": "Taped to monitor bezel", "reveals": "ResultSet cursor behavior is foundational — incorrect iteration misses data and breaks CRUD consistency", "description": "Handwritten: ''rs.next() returns false AFTER last row — always use while(rs.next()) not do-while! Failure causes skipped first row.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_006", "CONC_011"]}, {"name": "Audit Vault Terminal", "type": "interactive", "clueId": "CLUE_007", "foundBy": "After entering vault access code", "reveals": "Full JDBC lifecycle must be executed correctly — omission of any step risks resource leaks or security flaws", "description": "Command-line prompt: ''Reconstruct JDBC flow. Enter step numbers in order: [1] URL, [2] Driver Registration, [3] getConnection(), [4] prepareStatement(), [5] setXxx(), [6] executeUpdate(), [7] close()''", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_005", "CONC_006", "CONC_010"]}], "title": "The JDBC Connection Crime Scene", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Broken Connection", "sceneId": "SCENE_001", "location": "Server Room B-7 — ''PetDB Core'' rack", "description": "Maya Chen lies slumped over her terminal. Her screen displays an incomplete stack trace: ''java.sql.SQLException: No suitable driver found''. A printed JDBC Architecture diagram is pinned to the wall — one layer circled in red: ''DriverManager''.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "The Driver Registry", "sceneId": "SCENE_002", "location": "Thorne’s Office — whiteboard covered in driver class names", "description": "Whiteboard reads: ''MySQL: com.mysql.cj.jdbc.Driver | Derby: org.apache.derby.jdbc.ClientDriver'' — but one line is violently crossed out: ''Class.forName(\"com.mysql.jdbc.Driver\") // deprecated!''. A coffee-stained PetDB.java file sits open on the desk.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_005", "CLUE_006"], "order": 1, "title": "The Prepared Statement Paradox", "sceneId": "SCENE_003", "location": "Security Lab — forensic workstation running ResultSet analysis", "description": "A terminal shows two side-by-side queries: one using Statement with string concatenation, another using PreparedStatement with ''?''. Maya’s notes say: ''Only one prevents injection — find which.''", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": ["CLUE_007"], "order": 1, "title": "The Final Commit", "sceneId": "SCENE_004", "location": "Audit Vault — sealed server cabinet", "description": "A locked terminal boots into a JDBC test harness. To unlock the final report, Detective Lin must reconstruct the correct JDBC call sequence — from URL to ResultSet iteration — matching Maya’s documented standards.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Truth Revealed", "content": "Dr. Thorne murdered Maya Chen after she discovered his PetDB implementation used insecure Statement concatenation in addRecord() and updateRecord(), violating company security policy and exposing customer data. He attempted to cover it up by altering driver registration — but the corrupted port in the URL and inconsistent PreparedStatement usage left forensic traces. The JDBC architecture itself was never compromised — only its implementation.", "debrief": "You mastered: JDBC as a vendor-neutral API (CONC_001); driver registration and DriverManager''s routing role (CONC_002, CONC_007); Connection lifecycle and URL syntax (CONC_003, CONC_012); Statement vs PreparedStatement tradeoffs (CONC_004, CONC_005, CONC_013); ResultSet cursor semantics (CONC_006); and how DAO/JavaBean patterns abstract JDBC (CONC_008–CONC_011).", "summary": "The crime wasn''t in the architecture — it was in the implementation. Every JDBC layer exists to enforce safety, abstraction, and portability. When developers skip steps or misuse abstractions, vulnerabilities emerge — and sometimes, people get hurt.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_007", "Q_008", "Q_009", "Q_010", "Q_011"]}}], "logline": "A database architect is found dead with corrupted connection strings.", "version": "1.0", "evidence": [{"name": "JDBC Architecture Diagram", "type": "Documentary", "clueIds": ["CLUE_001"], "evidenceId": "EVIDENCE_001", "description": "Laminated 4-layer diagram showing interaction flow: Java App → JDBC API → DriverManager → Vendor Driver → DB. Red arrow points from DriverManager to ''Driver Registration'' box.", "foundLocation": "Server Room B-7 wall", "relatedKnowledge": ["CONC_007", "CONC_002"]}, {"name": "PetDB.java Source File", "type": "Code Sample", "clueIds": ["CLUE_004"], "evidenceId": "EVIDENCE_002", "description": "Printed Java file showing insecure Statement usage in addRecord() and secure PreparedStatement usage in getPets(). Highlights violation of internal policy.", "foundLocation": "Thorne''s desk", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_010"]}], "has_quiz": true, "scriptId": "JDBC_MURDER_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "It’s the central manager that sits between the Java Application and vendor-specific drivers.", "unlockAfterAttempts": 1}], "order": 1, "content": "Maya’s terminal shows ''No suitable driver found''. Which JDBC component is responsible for loading and routing to the correct driver?", "options": [{"content": "JDBC API", "feedback": "The JDBC API defines interfaces like Connection and Statement — but doesn’t load drivers.", "optionId": "OPT_001", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "DriverManager", "feedback": "Correct! DriverManager loads registered drivers and routes getConnection() calls to the appropriate vendor driver.", "optionId": "OPT_002", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "PreparedStatement", "feedback": "PreparedStatement handles parameterized queries — it relies on Connection, which relies on DriverManager.", "optionId": "OPT_003", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Architecture", "knowledgeId": "CONC_007"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_007", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Look at the part before the colon after ''jdbc:'' — it specifies the database protocol.", "unlockAfterAttempts": 1}], "order": 2, "content": "The corrupted URL ''jdbc:mysql://localhost:3307/pets'' fails. What part of the URL identifies the driver type?", "options": [{"content": "localhost:3307", "feedback": "That''s the host/port — required for network connection, but doesn''t identify the driver.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "mysql", "feedback": "Correct! ''mysql'' is the subprotocol — DriverManager uses it to select the MySQL JDBC driver.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_002"]}, {"content": "/pets", "feedback": "That''s the database name (subname), not the driver identifier.", "optionId": "OPT_006", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Database URLs", "knowledgeId": "CONC_012"}, "difficulty": 2, "questionId": "Q_002", "knowledgeId": "CONC_012", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "Consider class loading scope and what happens when multiple versions of the same driver exist.", "unlockAfterAttempts": 1}], "order": 1, "content": "Dr. Thorne crossed out ''Class.forName()'' — why is this driver registration method problematic in modern JDBC?", "options": [{"content": "It throws ClassNotFoundException if driver JAR isn’t in classpath", "feedback": "True, but that’s also true for ServiceLoader — not the core issue here.", "optionId": "OPT_007", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It forces static class loading, breaking modular isolation and causing ClassLoader leaks", "feedback": "Correct! Class.forName() binds the driver to the current ClassLoader — dangerous in containerized or modular environments.", "optionId": "OPT_008", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_004"]}, {"content": "It prevents PreparedStatement from caching execution plans", "feedback": "Precompilation depends on PreparedStatement — not driver registration method.", "optionId": "OPT_009", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_007"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "What happens if p.getName() contains ''O''Reilly'' or ''; DROP TABLE pets;''?", "unlockAfterAttempts": 1}], "order": 2, "content": "PetDB.java uses Statement.executeUpdate(''INSERT INTO pets VALUES (\"'' + p.getName() + ''\")''). Why is this unsafe compared to PreparedStatement?", "options": [{"content": "It recompiles SQL every time — poor performance", "feedback": "True, but secondary. The critical flaw is security.", "optionId": "OPT_010", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It enables SQL injection because user input isn’t escaped or typed", "feedback": "Correct! String concatenation allows malicious SQL to execute — PreparedStatement prevents this via type-safe placeholders.", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "It can’t handle BLOB or CLOB data types", "feedback": "Statement supports all SQL types — PreparedStatement just does it more safely.", "optionId": "OPT_012", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_004", "knowledgeId": "CONC_004", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "Remember: cursor starts BEFORE first row — so the first call to next() moves to row 1.", "unlockAfterAttempts": 1}], "order": 1, "content": "Maya’s note says: ''rs.next() returns false AFTER last row.'' What’s the safest way to iterate all rows in a ResultSet?", "options": [{"content": "do { processRow(); } while(rs.next());", "feedback": "This would process the first row twice — cursor starts before row 1, so first next() advances to row 1, then loop repeats.", "optionId": "OPT_013", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "while(rs.next()) { processRow(); }", "feedback": "Correct! This advances cursor and checks BEFORE processing — ensures each row is visited exactly once.", "optionId": "OPT_014", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": ["CLUE_006"]}, {"content": "for(int i = 0; i < rs.size(); i++) { rs.absolute(i); processRow(); }", "feedback": "ResultSet has no size() method by default — and absolute() requires scrollable ResultSet.", "optionId": "OPT_015", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About ResultSet", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_005", "knowledgeId": "CONC_006", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "Think about what happens during SQL parsing and plan generation — and how placeholders change that.", "unlockAfterAttempts": 1}], "order": 2, "content": "Which JDBC concept explains why PreparedStatement is both safer AND faster than Statement for repeated queries?", "options": [{"content": "Precompilation — SQL is parsed and optimized once, then reused with new parameters", "feedback": "Correct! PreparedStatement compiles the query once and caches the execution plan — preventing injection and boosting speed.", "optionId": "OPT_016", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Auto-commit mode — PreparedStatement disables auto-commit for transaction safety", "feedback": "Auto-commit is controlled by Connection, not PreparedStatement.", "optionId": "OPT_017", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Metadata retrieval — PreparedStatement automatically fetches column types", "feedback": "Metadata is available from ResultSetMetaData — independent of Statement type.", "optionId": "OPT_018", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About PreparedStatement", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_006", "knowledgeId": "CONC_005", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_013"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_007", "content": "Start with driver registration, end with ResultSet iteration. PreparedStatement methods require Connection, which requires DriverManager.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Load driver (e.g., Class.forName or ServiceLoader)"}, {"itemId": "ITEM_002", "content": "Call DriverManager.getConnection(url, user, pass)"}, {"itemId": "ITEM_003", "content": "Call connection.prepareStatement(''SELECT * FROM pets WHERE id = ?'')"}, {"itemId": "ITEM_004", "content": "Call pstmt.setInt(1, 123)"}, {"itemId": "ITEM_005", "content": "Call pstmt.executeQuery()"}, {"itemId": "ITEM_006", "content": "Iterate ResultSet with while(rs.next())"}], "order": 1, "content": "Reconstruct the correct JDBC flow to execute a safe parameterized query. Arrange these steps in order:", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Connection", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_007", "knowledgeId": "CONC_003", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004", "ITEM_005", "ITEM_006"], "feedbackCorrect": "Perfect! This is the full, safe JDBC lifecycle: register driver → get connection → prepare statement → bind parameters → execute → iterate results.", "feedbackIncorrect": "Remember: driver must be loaded before getConnection(); parameters bound before executeQuery(); ResultSet processed only after execution.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_008", "content": "Think of it as a stack: your code (top) talks to standard interfaces, which talk to a manager, which talks to the vendor.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_007", "content": "Database-specific JDBC Driver"}, {"itemId": "ITEM_008", "content": "JDBC Driver Manager"}, {"itemId": "ITEM_009", "content": "Java Application"}, {"itemId": "ITEM_010", "content": "JDBC API (interfaces)"}], "order": 2, "content": "Arrange the JDBC Architecture layers from top (application) to bottom (database):", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JDBC Architecture", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_008", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctOrder": ["ITEM_009", "ITEM_010", "ITEM_008", "ITEM_007"], "feedbackCorrect": "Correct! Java Application uses JDBC API interfaces → DriverManager routes calls → Vendor Driver translates to native protocol.", "feedbackIncorrect": "The Java Application sits at the top — it uses the JDBC API, which DriverManager implements, which directs traffic to the vendor driver.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_009", "content": "Ask: which component lets you call ''addRecord(p)'' without writing SQL? That’s the most abstract.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_011", "content": "PetDB.java (DAO)"}, {"itemId": "ITEM_012", "content": "Pet.java (JavaBean)"}, {"itemId": "ITEM_013", "content": "PreparedStatement"}, {"itemId": "ITEM_014", "content": "JDBC Driver"}], "order": 3, "content": "In the PetDB DAO pattern, arrange these components by abstraction level — from highest (most abstract) to lowest (closest to SQL):", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About ORM", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_008", "maxAttempts": 2, "correctOrder": ["ITEM_011", "ITEM_012", "ITEM_013", "ITEM_014"], "feedbackCorrect": "Correct! DAO hides persistence logic → JavaBean models data → PreparedStatement executes SQL → Driver handles wire protocol.", "feedbackIncorrect": "DAO is the highest abstraction — it exposes methods like addRecord(). JavaBean is data structure. PreparedStatement is low-level SQL execution.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_010", "content": "It’s a syntactic marker — often numbered starting from 1 — used with setter methods like setString(1, value).", "unlockAfterAttempts": 1}], "order": 4, "content": "In PreparedStatement, the ''?'' symbol is called a ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_010", "knowledgeId": "CONC_013", "maxAttempts": 2, "correctAnswers": ["placeholder", "Placeholder", "PLACEHOLDER"], "feedbackCorrect": "Correct! Placeholders allow safe, type-aware parameter binding — preventing SQL injection and enabling query plan reuse.", "feedbackIncorrect": "It''s the symbol that marks where parameters will be inserted — a key feature of PreparedStatement.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_011", "content": "It''s a four-letter acronym — each letter represents one operation: C, R, U, D.", "unlockAfterAttempts": 1}], "order": 5, "content": "The four fundamental data manipulation operations implemented by PetDB are collectively known as ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About CRUD Operations", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_011", "knowledgeId": "CONC_011", "maxAttempts": 2, "correctAnswers": ["CRUD", "crud", "Create Read Update Delete", "create read update delete"], "feedbackCorrect": "Correct! CRUD stands for Create, Retrieve (Read), Update, and Delete — the core operations abstracted by the DAO pattern.", "feedbackIncorrect": "It''s the acronym describing the four basic functions any persistent storage system must support.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}], "characters": [{"age": 34, "goal": "Solve the murder using only JDBC knowledge — no external tools", "name": "Detective Lin", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Once shipped production code that forgot to close Connections — caused a memory leak outage", "background": "Former Java developer turned investigator; specializes in code-based crimes", "occupation": "Cyber Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, methodical, skeptical of ''magic'' abstractions", "knowledgePoints": ["CONC_001", "CONC_007"]}, {"age": 48, "goal": "Protect his ORM legacy from being deprecated", "name": "Dr. Aris Thorne", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Used Class.forName() instead of ServiceLoader for driver registration — violating internal security policy", "background": "Designed the ''PetDB'' ORM framework used company-wide; last seen arguing with victim about driver registration", "occupation": "Lead Database Architect", "characterId": "CHAR_002", "personality": "Brilliant but rigid, believes ''if it compiles, it’s secure''", "knowledgePoints": ["CONC_002", "CONC_005", "CONC_013"]}, {"age": 39, "goal": "Publish the ''JDBC Safety Audit Report'' before the quarterly board meeting", "name": "Maya Chen", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Found evidence that Dr. Thorne’s DAO bypassed placeholder binding — enabling SQL injection in updateRecord()", "background": "Hired to audit all database access layers; discovered critical vulnerabilities in PetDB’s PreparedStatement usage", "occupation": "JDBC Standards Compliance Officer", "characterId": "CHAR_003", "personality": "Precise, uncompromising, documented everything in JDBC-compliant format", "knowledgePoints": ["CONC_003", "CONC_004", "CONC_006", "CONC_011"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "architecture", "appearsIn": ["SCENE_001", "SCENE_004", "CLUE_001", "CHAR_001"], "difficulty": 3, "description": "JDBC is a Java API that enables Java applications to interact with relational databases in a vendor-neutral manner. It provides a standardized interface for connecting to, querying, and updating databases through JDBC drivers that translate generic JDBC calls into database-specific protocols.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002", "CLUE_001", "CLUE_003", "CHAR_002"], "difficulty": 4, "description": "A JDBC driver is a Java class that implements the JDBC API to enable communication between a Java application and a specific database management system. It acts as a translation layer, converting JDBC method calls into database-specific network protocols. Drivers are registered via System.setProperty or Class.forName, and are identified by unique class names such as ''com.mysql.jdbc.Driver''.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_007"]}, {"name": "Connection", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_004", "CLUE_002", "CHAR_003"], "difficulty": 3, "description": "A Connection object represents a session between a Java application and a database. It is obtained via DriverManager.getConnection() using database URL, username, and password. The Connection provides factory methods to create Statement, PreparedStatement, and CallableStatement objects, supports transaction control (commit/rollback), and allows retrieval of database metadata.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004", "CONC_005"]}, {"name": "Statement", "category": "component", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_004", "CHAR_003"], "difficulty": 3, "description": "A Statement object is used to execute static SQL queries that do not require parameterization. It is created via Connection.createStatement() and supports executeQuery() for SELECT statements (returning ResultSet), executeUpdate() for DML operations (INSERT/UPDATE/DELETE), and execute() for mixed or DDL operations.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_007"]}, {"name": "PreparedStatement", "category": "component", "appearsIn": ["SCENE_002", "SCENE_003", "SCENE_004", "CLUE_004", "CLUE_005", "CHAR_002"], "difficulty": 4, "description": "A PreparedStatement is a precompiled SQL statement that supports parameterized queries using placeholders (''?''). Created via Connection.prepareStatement(), it improves performance by compiling the SQL once and reusing the execution plan across multiple executions with different parameter values. It prevents SQL injection, handles type conversion automatically, and supports setter methods like setString() and setInt().", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_007", "CONC_013"]}, {"name": "ResultSet", "category": "object", "appearsIn": ["SCENE_003", "SCENE_004", "CLUE_006", "CHAR_003"], "difficulty": 3, "description": "A ResultSet object represents the tabular results of a database query. It maintains a cursor initially positioned before the first row; the next() method advances the cursor row-by-row. ResultSet provides accessor methods (e.g., getString(), getInt()) to retrieve column values by index or name. By default, it is forward-only and read-only.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_007"]}, {"name": "JDBC Architecture", "category": "architecture", "appearsIn": ["SCENE_001", "SCENE_004", "CLUE_001", "CHAR_001"], "difficulty": 4, "description": "JDBC architecture consists of four layers: (1) Java Application, (2) JDBC API, (3) JDBC Driver Manager, and (4) Database-specific JDBC Driver. The application uses JDBC API interfaces (Connection, Statement, ResultSet). DriverManager loads and manages drivers, routing calls to the appropriate vendor driver. The driver translates JDBC calls into native database protocols.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "theory", "appearsIn": ["SCENE_002", "SCENE_004", "CLUE_004", "CHAR_002"], "difficulty": 4, "description": "ORM is a programming technique that maps object-oriented domain models to relational database schemas. In this context, it refers to a simplified ORM pattern where JavaBean classes (e.g., Pet.java) represent database tables, and DAO classes (e.g., PetDB.java) encapsulate CRUD operations. ORM abstracts SQL, enables type-safe data access, and supports relationships between entities.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010", "CONC_011"]}, {"name": "JavaBean", "category": "object", "appearsIn": ["SCENE_002", "SCENE_004", "CLUE_004", "CHAR_002"], "difficulty": 2, "description": "A JavaBean is a reusable, serializable Java class following conventions: private fields with public getter/setter methods, a no-argument constructor, and implementation of java.io.Serializable. In JDBC contexts, JavaBeans (e.g., Pet.java) model database records—each field corresponds to a table column.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_011"]}, {"name": "DAO (Data Access Object)", "category": "pattern", "appearsIn": ["SCENE_002", "SCENE_004", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "A DAO is a design pattern that abstracts and encapsulates database access logic. In this material, PetDB.java exemplifies a DAO: it manages database connections, executes CRUD operations on the Pet table, and returns JavaBean instances. DAO separates persistence logic from business logic, improving testability, maintainability, and database independence.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_009", "CONC_011"]}, {"name": "CRUD Operations", "category": "process", "appearsIn": ["SCENE_002", "SCENE_003", "SCENE_004", "CLUE_004", "CHAR_003"], "difficulty": 2, "description": "CRUD stands for Create, Retrieve (or Read), Update, and Delete—the four fundamental data manipulation operations supported by persistent storage systems. In JDBC, these map to SQL INSERT, SELECT, UPDATE, and DELETE statements. The PetDB class implements CRUD via methods like addRecord(), getPets(), updateRecord(), and deleteRecord().", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_005"]}, {"name": "Database URL", "category": "object", "appearsIn": ["SCENE_001", "SCENE_002", "CLUE_002", "CHAR_003"], "difficulty": 3, "description": "A JDBC database URL is a string that specifies how to connect to a database, following the syntax ''jdbc:subprotocol:subname''. The ''subprotocol'' identifies the driver (e.g., ''mysql'', ''derby''), and ''subname'' contains connection details like host, port, and database name.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Placeholder", "category": "object", "appearsIn": ["SCENE_003", "SCENE_004", "CLUE_005", "CHAR_002"], "difficulty": 3, "description": "A placeholder is a ''?'' character in a PreparedStatement SQL string that represents a parameter to be bound at execution time. Placeholders enable safe, efficient parameter substitution without string concatenation. Each placeholder is assigned an integer index starting from 1, and corresponding setter methods (e.g., setString(1, value)) bind values before execution.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_006"]}], "educational_goals": ["Understand JDBC as a vendor-neutral database connectivity API", "Master JDBC driver registration and the role of DriverManager", "Apply Connection, Statement, PreparedStatement, and ResultSet in correct sequence", "Differentiate between static SQL and parameterized queries for security and performance", "Trace the layered JDBC architecture from application to database", "Recognize how ORM patterns (JavaBean + DAO) abstract JDBC operations"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 3}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'Database Connection and Driver Management', '2026-03-25 08:12:54.24229', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('941a5400-dfea-46da-a9de-73762beaf60b', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f36387e3-c216-4017-9cbe-c72560cc8ebb', NULL, 'The Vanishing Entity: An ORM Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "JDBC Disconnection Log Entry", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Indicates possible misuse or crash due to improper JDBC resource handling.", "description": "System log shows an abrupt JDBC connection termination without proper close() invocation. Timestamp aligns with Dr. Reed''s disappearance.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Driver Registration Comment in Code", "type": "code", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Implies potential misconfiguration in JDBC driver loading mechanism.", "description": "A commented-out line in the ORM setup script reads: ''// Class.forName(\"com.mysql.jdbc.Driver\"); // legacy registration''. Suggests outdated configuration practices.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Sticky Note: ''use ? placeholders''", "type": "physical", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Kai knew about secure coding practices but may not have followed them.", "description": "Crumpled sticky note found in Kai’s trash bin emphasizes parameterized queries, suggesting awareness of SQL injection risks.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Raw Statement Usage in DAO Layer", "type": "code", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Confirms insecure JDBC usage that could allow SQL injection.", "description": "Code audit reveals a DAO method using Statement instead of PreparedStatement for dynamic queries, creating a vulnerability.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "Connection URL Pattern", "type": "configuration", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Validates correct JDBC URL syntax and identifies MySQL as backend DBMS.", "description": "Database URL extracted from environment variables follows the format jdbc:mysql://localhost:3306/enterprise_dev", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Crumpled Sticky Note", "type": "document", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Kai was aware of secure JDBC practices but may not have followed them.", "description": "A crumpled sticky note found in Kai Morrison''s trash bin with the handwritten phrase: ''use ? placeholders''. The ink is slightly smudged, suggesting it was written in haste.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Prepared Statement Code Snippet", "type": "digital", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Dr. Reed was implementing secure database access patterns before disappearing.", "description": "Recovered from Dr. Reed’s workstation cache: a partially written Java method using PreparedStatement with parameterized UPDATE query for the Pet table. The SQL uses ''?'' placeholders and calls setString() and setInt().", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "ResultSet Iteration Log", "type": "log", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Someone accessed pet data systematically, possibly extracting information via proper ResultSet handling.", "description": "System log excerpt showing repeated calls to rs.next() in a while loop, retrieving pet records. Includes timestamps indicating high-frequency data access during off-hours.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006"]}, {"name": "JDBC Driver Stack Diagram", "type": "diagram", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "The correct JDBC architecture model that ensures abstraction and portability across databases.", "description": "Whiteboard sketch behind Dr. Reed’s desk showing four layers: Application → JDBC API → DriverManager → Vendor Driver → Database. Arrows indicate flow of SQL commands and result sets.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_007"]}, {"name": "ORM Design Blueprint", "type": "blueprint", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "Dr. Reed’s intended ORM design that abstracts direct SQL usage and enforces structured data access.", "description": "Printed diagram titled ''Pet Management ORM v2'' showing Pet.java as JavaBean linked to PetDB.java DAO class. CRUD operations mapped to SQL methods with annotations like @Create, @Update.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_008"]}, {"name": "Crumpled JavaBean Note", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The ORM model uses JavaBeans as data carriers between layers.", "description": "A torn piece of paper found in Kai''s trash bin with a sketch of a Pet class, showing private fields and getter/setter methods. Handwritten annotation: ''must be serializable''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "DAO Interface Snippet", "type": "digital", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Database operations are abstracted through a DAO layer to separate concerns.", "description": "A cached IDE tab on Dr. Reed’s workstation showing the PetDB.java file with clearly labeled CRUD methods: addRecord(), getPets(), updateRecord(), deleteRecord().", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_010"]}, {"name": "CRUD Execution Log", "type": "log", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "All four fundamental data operations were executed shortly before the disconnection anomaly.", "description": "A filtered system log from the connection pool showing sequential calls: INSERT (Create), SELECT (Read), UPDATE (Update), DELETE (Delete) on the Pet table within a single user session.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_011"]}, {"name": "JDBC URL Configuration File", "type": "digital", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The application connects to a MySQL database hosted locally on port 3306.", "description": "A backup config file recovered from the server vault containing the line: ''db.url=jdbc:mysql://localhost:3306/petclinic''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_012"]}, {"name": "Crumpled Sticky Note", "type": "document", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "Kai was aware of secure JDBC practices but may not have followed them.", "description": "A torn sticky note found in Kai Morrison''s trash bin with the phrase ''use ? placeholders'' hastily scribbled on it. The handwriting matches Kai’s, but the advice contradicts his recent code commits.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "PreparedStatement Syntax Pattern", "type": "code_evidence", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Dr. Reed was actively enforcing secure parameter binding standards prior to being locked in the vault.", "description": "Recovered from Dr. Reed’s encrypted notes: a snippet showing proper use of ''?'' placeholders in a PreparedStatement with corresponding setString() calls. Timestamped just before her disappearance.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013"]}, {"name": "Index-Based Binding Log Entry", "type": "system_log", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "The system uses index-based parameter binding, which prevented SQL injection attempts.", "description": "Database audit log excerpt showing repeated execution of a prepared statement with bound parameters at indices 1 and 2. One entry shows an attempted injection attack that failed due to parameterization.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}, {"name": "Flawed Statement Execution Trace", "type": "execution_trace", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "Kai used unsafe string concatenation in JDBC calls, creating a vulnerability.", "description": "Stack trace from a failed transaction showing raw SQL concatenation instead of parameterized queries. Source traced back to Kai Morrison’s development branch.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}], "title": "The Vanishing Entity: An ORM Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Empty Workstation", "sceneId": "SCENE_001", "location": "Enterprise Development Lab", "description": "Detective Lin arrives at the dimly lit development lab where Dr. Reed’s workstation is still running. Code editor open on an incomplete ORM mapping file. Coffee cup half-full. No sign of struggle, but logs show abnormal JDBC disconnection.", "charactersPresent": ["CHAR_001"]}, {"act": 2, "clues": [], "order": 2, "title": "Interrogation in the Break Room", "sceneId": "SCENE_002", "location": "Office Break Room", "description": "Lin questions Kai Morrison, who claims he last saw Dr. Reed debugging a DAO method. He nervously avoids discussing database access patterns. A sticky note with ''use ? placeholders'' lies crumpled in his trash.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Confrontation in the Server Vault", "sceneId": "SCENE_003", "location": "Secure Server Vault", "description": "Lin discovers Dr. Reed alive but locked inside the server vault. She reveals she hid after detecting unauthorized access to the connection pool. All suspects converge as the truth surfaces about flawed JDBC usage and ORM misdesign.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct Resolution", "title": "Truth Mapped", "content": "Lin exposes Kai’s reckless use of Statement objects and improper SQL concatenation. Dr. Reed confirms the ORM model was sabotaged through this vulnerability. Kai admits fault, vowing to adopt secure PreparedStatement practices.", "debrief": "The case highlights the importance of secure JDBC usage, proper ORM modeling, and adherence to DAO patterns.", "summary": "Security wins over speed. Proper use of PreparedStatement and ORM principles prevents exploits.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect Resolution", "title": "False Accusation", "content": "Lin blames Dr. Reed for poor ORM design, ignoring evidence of external tampering. The real flaw—unsafe JDBC usage—remains unpatched, risking future breaches.", "debrief": "Jumping to conclusions without full investigation leads to missed vulnerabilities and misplaced blame.", "summary": "Incomplete analysis results in unresolved risks and damaged trust.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes software development lab, the lead developer vanishes just before a critical ORM model deployment. Players must uncover the truth behind the missing engineer by investigating database connections, object-relational mappings, and hidden code secrets.", "version": "1.0", "evidence": [{"name": "Open IDE with Incomplete ORM Mapping", "type": "Digital Artifact", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Dr. Reed''s computer shows a partially written @Entity class with mismatched field types and column annotations.", "foundLocation": "Development Lab Desk", "relatedKnowledge": ["CONC_008", "CONC_009"]}, {"name": "Crumpled Sticky Note", "type": "Physical Note", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Handwritten reminder: ''Use ? placeholders – never concatenate strings in SQL''. Found in Kai''s trash bin.", "foundLocation": "Break Room Trash Can", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "Log Entry: Abnormal Disconnection", "type": "System Log", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Server log indicates sudden termination of JDBC connection during a SELECT query execution.", "foundLocation": "Server Vault Terminal", "relatedKnowledge": ["CONC_003", "CONC_006"]}, {"name": "DAO Implementation File", "type": "Code File", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A DAO class using Statement instead of PreparedStatement for user updates, leaving it vulnerable to injection.", "foundLocation": "Version Control Printout", "relatedKnowledge": ["CONC_004", "CONC_010"]}], "has_quiz": true, "scriptId": "SCRIPT_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the open code editor at Dr. Reed’s workstation. The system logs show a sudden disconnection without cleanup. What is the primary role of JDBC in this enterprise application?", "options": [{"content": "To provide a standardized API for Java applications to interact with relational databases in a vendor-neutral way.", "feedback": "Correct. JDBC abstracts database-specific details, allowing portable database access across different systems.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "To automatically generate ORM models from database schemas.", "feedback": "Incorrect. While tools exist for schema-to-model generation, JDBC itself does not perform ORM modeling.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To encrypt all data transmitted between the application and the database.", "feedback": "Incorrect. JDBC does not handle encryption by default; SSL/TLS must be configured separately.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To replace SQL with object-oriented query languages like JPQL.", "feedback": "Incorrect. That function belongs to higher-level frameworks like JPA, not JDBC itself.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin finds a commented line: ''// Class.forName(\"com.mysql.jdbc.Driver\");''. Why was this step historically required in JDBC setups?", "options": [{"content": "To register the MySQL-specific driver so DriverManager can use it to establish connections.", "feedback": "Correct. Class.forName() loads the driver class into memory, enabling DriverManager to locate and use it.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "To compile the SQL query into bytecode for faster execution.", "feedback": "Incorrect. JDBC drivers translate SQL, but Class.forName() doesn''t compile queries.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To create a new instance of the Connection object directly.", "feedback": "Incorrect. Connections are created via DriverManager.getConnection(), not through direct instantiation.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To enable automatic garbage collection of database resources.", "feedback": "Incorrect. Resource cleanup must be handled explicitly; JDBC does not auto-manage this.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Kai nervously avoids discussing his DAO implementation. Detective Lin recalls that a Connection object is central to JDBC operations. Which of the following best describes what a Connection provides?", "options": [{"content": "A session with the database that allows creation of Statements, transaction control, and metadata access.", "feedback": "Correct. The Connection is the gateway for all interactions with the database, including statement creation and transaction management.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_005"]}, {"content": "A compiled execution plan for frequently used SQL queries.", "feedback": "Incorrect. Execution plans are managed internally by the DBMS and PreparedStatement, not the Connection itself.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "An encrypted tunnel ensuring all data is protected in transit.", "feedback": "Incorrect. Encryption depends on network configuration, not guaranteed by Connection alone.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "A cache of ResultSet objects to improve performance.", "feedback": "Incorrect. ResultSets are live views over data; they are not cached by the Connection.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Call connection.createStatement()"}, {"itemId": "ITEM_B1_002", "content": "Import java.sql.Statement"}, {"itemId": "ITEM_B1_003", "content": "Execute stmt.executeUpdate(sql)"}, {"itemId": "ITEM_B1_004", "content": "Define the SQL string with hardcoded values"}], "order": 4, "content": "To understand how Kai might have improperly used JDBC, Detective Lin reconstructs the correct sequence for executing a static SQL update. Arrange the steps in order:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Usage", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_001", "ITEM_B1_004", "ITEM_B1_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Proper use of Statement requires importing the class, creating it from a Connection, defining the SQL, then executing it.", "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": "Incorrect. Remember: import → create statement → define SQL → execute. This pattern applies to static queries.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "Detective Lin inspects the database configuration file. The URL follows the pattern ''jdbc:mysql://localhost:3306/enterprise_dev''. What keyword starts every JDBC URL? Enter only the protocol prefix.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Connection URLs", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["jdbc"], "feedbackCorrect": "Correct. All JDBC URLs begin with ''jdbc'' followed by a colon, forming the standard protocol identifier.", "relatedKnowledge": ["CONC_012"], "feedbackIncorrect": "Incorrect. Recall that JDBC URLs always start with ''jdbc:'' as the universal scheme prefix.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines Dr. Reed’s open code editor. She sees a commented-out Statement update and an incomplete PreparedStatement version using ''?''. Which advantage does this suggest about PreparedStatement over Statement?", "options": [{"content": "It allows dynamic table renaming at runtime.", "feedback": "Incorrect. Table names cannot be parameterized with ''?''. PreparedStatement does not support dynamic schema changes through placeholders.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It compiles once and reuses the execution plan, improving performance and preventing SQL injection.", "feedback": "Correct. PreparedStatement precompiles the SQL and uses placeholders (''?'') for parameters, which prevents SQL injection and improves efficiency when reused.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "It automatically generates primary keys for new records.", "feedback": "Incorrect. Primary key generation depends on database settings or application logic, not on whether PreparedStatement is used.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It supports joining multiple result sets without additional queries.", "feedback": "Incorrect. Joining result sets requires separate SQL JOIN statements or application-level merging; PreparedStatement doesn’t inherently enable this.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About PreparedStatement", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin picks up the crumpled sticky note with ''use ? placeholders''. She recalls how ResultSet handles query output. What is the correct way to iterate through a ResultSet to retrieve all pet records?", "options": [{"content": "Use a for loop with getRow(i) to access each index directly.", "feedback": "Incorrect. ResultSet does not have a getRow() method or random access by default. It uses a cursor-based forward-only iteration.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Call next() once to jump to the last row, then use previous() to go backward.", "feedback": "Incorrect. By default, ResultSet is forward-only and does not support backward traversal. The next() method moves forward one row at a time.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Use while(rs.next()) to advance the cursor and process each row safely.", "feedback": "Correct. The standard pattern is while(rs.next()) because the cursor starts before the first row, and next() returns false after the last row.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "Call rs.getAllRows() and loop through the returned list.", "feedback": "Incorrect. There is no getAllRows() method in ResultSet. Data must be retrieved iteratively using next().", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About ResultSet", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Inside the server vault, Dr. Reed shows Lin a whiteboard diagram explaining how JDBC isolates application code from database specifics. Which component is responsible for loading the correct driver and routing connection requests?", "options": [{"content": "Connection", "feedback": "Incorrect. Connection represents the session with the database but does not manage driver selection.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Statement", "feedback": "Incorrect. Statement executes SQL but plays no role in driver management or connection routing.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "DriverManager", "feedback": "Correct. DriverManager loads the appropriate JDBC driver based on the URL and manages connections between the application and the vendor-specific driver.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_004"]}, {"content": "ResultSet", "feedback": "Incorrect. ResultSet holds query results, not connection routing logic.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About JDBC Architecture", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Pet.java (JavaBean representing a pet)"}, {"itemId": "ITEM_B2_002", "content": "PetDB.java (DAO handling CRUD operations)"}, {"itemId": "ITEM_B2_003", "content": "PreparedStatement with parameterized queries"}, {"itemId": "ITEM_B2_004", "content": "Relational Pet table in the database"}], "order": 4, "content": "Dr. Reed explains her ORM design: Java objects should map cleanly to database tables without raw SQL exposure. Arrange these components in the correct order of abstraction from application to database:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About ORM", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The ORM stack flows from domain object (Pet.java) → DAO layer (PetDB.java) → secure JDBC (PreparedStatement) → actual database table.", "relatedKnowledge": ["CONC_007", "CONC_010", "CONC_011"], "feedbackIncorrect": "Incorrect. Remember: ORM starts with the Java object, goes through the DAO, uses PreparedStatement for safety, and ends at the relational table.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "On Dr. Reed’s monitor, a comment reads: ''Always use ________ instead of Statement to prevent SQL injection and improve performance with repeated queries.''", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About PreparedStatement", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["PreparedStatement", "prepared statement", "Prepared Statement"], "feedbackCorrect": "Correct. PreparedStatement uses parameterized queries with ''?'' placeholders, preventing SQL injection and enabling precompilation for better performance.", "relatedKnowledge": ["CONC_004", "CONC_013"], "feedbackIncorrect": "Incorrect. Consider the secure alternative to Statement that supports parameterized queries using ''?''. It''s a single term commonly used in JDBC best practices.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the crumpled note in Kai’s trash. It shows a Java class with private fields, public getters/setters, a no-arg constructor, and implements Serializable. What is this design pattern called?", "options": [{"content": "Entity Class", "feedback": "While close, ''Entity'' is more JPA-specific. The correct term refers to reusable, serializable classes following strict conventions for data transfer.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "JavaBean", "feedback": "Correct. A JavaBean is a standard DTO pattern using private fields, public accessors, a no-arg constructor, and serialization—perfect for ORM mapping.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_001"]}, {"content": "POJO", "feedback": "A POJO is any plain Java object, but not all POJOs follow JavaBean conventions like serialization or getter/setter requirements.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Model View", "feedback": "This refers to MVC architecture, but doesn''t specify the implementation pattern. JavaBean is the precise term for this structure.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_008"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin reviews the open code editor at Dr. Reed’s desk. She sees a class named PetDB.java that handles all database interactions—creating connections, executing queries, and returning Pet objects. What design pattern does this represent?", "options": [{"content": "Service Layer", "feedback": "The service layer handles business logic, not direct database access. This class is focused on persistence abstraction.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Repository Pattern", "feedback": "Similar concept, but in this context, the material specifically refers to the DAO (Data Access Object) pattern as the standard JDBC abstraction.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "DAO (Data Access Object)", "feedback": "Exactly. The DAO pattern encapsulates database access logic, separating it from business rules and improving maintainability and testability.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Connection Manager", "feedback": "While it manages connections, its broader role in handling full CRUD operations defines it as a DAO, not just a connection utility.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About DAO Pattern", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Dr. Reed explains that the attacker exploited the system by manipulating data operations. Detective Lin checks the logs and sees INSERT, SELECT, UPDATE, and DELETE commands executed in sequence. What acronym describes these four core operations?", "options": [{"content": "ACID", "feedback": "ACID refers to transaction properties (Atomicity, Consistency, Isolation, Durability), not data operations.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "CRUD", "feedback": "Correct. CRUD stands for Create (INSERT), Read (SELECT), Update (UPDATE), Delete (DELETE)—the foundational data manipulation operations.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "BASE", "feedback": "BASE is an alternative consistency model used in distributed systems, unrelated to basic data operations.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "DML", "feedback": "DML (Data Manipulation Language) includes these commands, but CRUD is the conceptual framework describing the operations themselves.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About CRUD Operations", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Call DriverManager.getConnection()"}, {"itemId": "ITEM_B3_002", "content": "Provide database URL, username, and password"}, {"itemId": "ITEM_B3_003", "content": "Register the JDBC driver using Class.forName()"}, {"itemId": "ITEM_B3_004", "content": "Use the Connection object for SQL operations"}], "order": 4, "content": "To reconstruct the attack timeline, Detective Lin must sequence the steps the application uses to establish a database connection. Arrange the following in the correct order:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Database URLs", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": ["ITEM_B3_003", "ITEM_B3_002", "ITEM_B3_001", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. First register the driver, then provide credentials and URL, get the connection, and finally execute SQL.", "relatedKnowledge": ["CONC_003", "CONC_002"], "feedbackIncorrect": "Incorrect. Remember: driver registration comes first, then connection parameters, then obtaining the connection before use.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "Detective Lin analyzes the configuration file and sees the connection string: ''jdbc:mysql://localhost:3306/petclinic''. What part of this URL identifies the database vendor and driver type?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About JDBC URL Structure", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["mysql", "subprotocol"], "feedbackCorrect": "Correct. ''mysql'' is the subprotocol that tells JDBC which driver to use for connecting to the database.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Look at the part after ''jdbc:'' and before the ''://''. That segment specifies the driver and database type.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the database logs and notices a recurring pattern: a SQL query is parsed once and executed multiple times with different values. She sees ''?'' symbols in the original SQL template. What do these symbols represent?", "options": [{"content": "Dynamic table names that change per execution", "feedback": "Incorrect. Table names cannot be substituted via placeholders. Only parameter values can be bound using ''?''. This misunderstanding could lead to unsafe dynamic SQL construction.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Indexes for result set columns during retrieval", "feedback": "No. Column indexes in ResultSet are accessed differently. The ''?'' here appears in the SQL *before* execution—it''s part of the input query structure, not output data access.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Placeholders for parameter binding, assigned by index starting at 1", "feedback": "Correct. The ''?'' symbols are placeholders that allow safe, efficient parameter substitution. They prevent SQL injection and enable query plan reuse by separating code from data.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_003"]}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin confronts Kai about the sticky note in his trash: ''use ? placeholders''. He claims he always uses them. But she pulls up his latest commit—raw SQL strings with concatenated user input. What critical security issue does this create?", "options": [{"content": "Increased memory usage due to repeated query parsing", "feedback": "While true, this isn’t the primary security concern. Performance degradation is a side effect, but the real danger lies in exploitability through malicious input.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "SQL injection vulnerability from unescaped user input", "feedback": "Exactly. Without placeholders, attackers can inject malicious SQL through input fields. Using ''?'' ensures values are treated as data, not executable code.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_004"]}, {"content": "Incompatibility with connection pooling mechanisms", "feedback": "Connection pools work independently of how SQL is constructed. The core flaw here is security, not infrastructure compatibility.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Parameter Binding", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Dr. Reed explains that she hid after detecting unauthorized access. She shows Lin a secure code snippet where values are bound using setString(1, value) and setInt(2, value). Why must the indices start at 1, not 0?", "options": [{"content": "It’s a Java convention—all arrays and lists start at index 1", "feedback": "Actually, Java collections start at index 0. However, JDBC deliberately uses 1-based indexing for parameter positions to align with SQL standard conventions and improve readability in complex queries.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The JDBC specification defines parameter indices as 1-based for consistency and clarity", "feedback": "Correct. JDBC uses 1-based indexing for parameter placeholders to match SQL semantics and avoid confusion between programming language arrays and database parameters.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_002"]}, {"content": "To reserve index 0 for metadata or connection info", "feedback": "There is no such reservation. Index 0 is simply invalid in PreparedStatement setter methods—the specification starts at 1 for semantic reasons, not technical constraints.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Index-Based Binding", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_003", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "Call prepareStatement(sql) on the Connection object"}, {"itemId": "ITEM_B4_002", "content": "Define SQL string with ''?'' placeholders for parameters"}, {"itemId": "ITEM_B4_003", "content": "Use setter methods like setString(1, value) to bind values to placeholders"}, {"itemId": "ITEM_B4_004", "content": "Execute the query using executeUpdate() or executeQuery()"}], "order": 4, "content": "To prove her point, Dr. Reed asks Detective Lin to reconstruct the correct sequence for safely executing a parameterized query. Arrange the steps in order:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Review PreparedStatement Workflow", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_004", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_002", "ITEM_B4_001", "ITEM_B4_003", "ITEM_B4_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. This sequence ensures the SQL is precompiled with placeholders, parameters are safely bound by index, and the query executes without string injection risks.", "relatedKnowledge": ["CONC_005", "CONC_003"], "feedbackIncorrect": "Not quite. Remember: first define the SQL with ''?'', then prepare it, bind values using setters, and finally execute. Reversing or skipping steps introduces vulnerabilities.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "Detective Lin examines Kai’s code. She mutters, \"He should’ve used a PreparedStatement with ________ to prevent injection.\" What term fits best?", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Understand How Placeholders Prevent Injection", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_005", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["placeholders", "parameter binding", "setter methods", "index-based parameters"], "feedbackCorrect": "Yes. ''Placeholders'' (the ''?'' symbols) combined with setter methods enable secure, reusable queries. This would have stopped the attack vector.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Not quite. Think about what feature of PreparedStatement allows safe input handling—hint: it involves ''?'' and numbered parameters.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}], "characters": [{"age": 34, "goal": "Uncover what happened to Dr. Reed and secure the ORM model before it''s compromised.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once worked at the same company years ago but left after a failed ORM migration project.", "background": "A seasoned investigator with expertise in enterprise system architecture and database forensics. Known for solving complex technical mysteries.", "occupation": "Software Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, detail-oriented", "knowledgePoints": ["CONC_008", "CONC_010", "CONC_011"]}, {"age": 41, "goal": "Ensure her ORM design is not weaponized or stolen.", "name": "Dr. Elena Reed", "role": "Victim/Suspect", "scenes": ["SCENE_003"], "secret": "Discovered that someone was injecting malicious SQL via unsecured JDBC calls and planned to expose it.", "background": "Pioneer in ORM integration for legacy banking systems. Recently reported concerns about security flaws in the new model.", "occupation": "Lead Enterprise Architect", "characterId": "CHAR_002", "personality": "Brilliant, paranoid, perfectionist", "knowledgePoints": ["CONC_007", "CONC_008", "CONC_012"]}, {"age": 29, "goal": "Avoid being blamed for the system flaw and keep his job.", "name": "Kai Morrison", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003"], "secret": "Used raw Statement instead of PreparedStatement to speed up development, creating a vulnerability.", "background": "Fast-tracked hire with questionable coding practices. Often cuts corners to meet deadlines.", "occupation": "Junior Backend Developer", "characterId": "CHAR_003", "personality": "Charismatic, impulsive, defensive when challenged", "knowledgePoints": ["CONC_004", "CONC_005", "CONC_006"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "Database Access", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Java API that enables connectivity between Java applications and relational databases.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "Database Access", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Implementation of JDBC interface specific to a database management system.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_012"]}, {"name": "Connection", "category": "Database Access", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "Session between Java application and database established via DriverManager or DataSource.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Statement", "category": "SQL Execution", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "JDBC object used to execute static SQL queries without parameters.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "PreparedStatement", "category": "SQL Execution", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Precompiled SQL statement that supports parameterized queries using placeholders.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_013"]}, {"name": "ResultSet", "category": "Data Retrieval", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Table of data representing results from a database query executed via Statement or PreparedStatement.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "JDBC Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Layered structure consisting of JDBC API and JDBC driver manager facilitating communication between Java apps and databases.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "Design Pattern", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Programming technique to convert data between relational databases and object-oriented models.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "JavaBean", "category": "Object Design", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "Java class that follows conventions such as private fields, public getters/setters, and no-argument constructor.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "DAO (Data Access Object)", "category": "Design Pattern", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Design pattern that abstracts database interactions into dedicated classes for cleaner separation of concerns.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_011"]}, {"name": "CRUD Operations", "category": "Operations", "appearsIn": ["SCENE_003"], "difficulty": 1, "description": "Basic functions: Create, Read, Update, Delete performed on database records.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_005"]}, {"name": "Database URL", "category": "Configuration", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "String specifying the location of a database including protocol, subprotocol, and address.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Placeholder", "category": "Security", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Symbol (usually ''?'') used in PreparedStatement to safely insert dynamic values into SQL queries.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_011"]}], "educational_goals": ["Understand the fundamentals of JDBC and its components", "Explain the purpose and mechanics of Object-Relational Mapping (ORM)", "Design effective data models using DAO pattern and JavaBeans", "Perform CRUD operations through prepared statements and connection management"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 3}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'Object-Relational Mapping (ORM) and Model Design', '2026-04-01 11:53:00.190238', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('08fd4a3b-34d7-4a02-8eec-33133d80e61f', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f36387e3-c216-4017-9cbe-c72560cc8ebb', NULL, 'The ResultSet Heist: A JDBC Crime Scene', 'active', 'easy', 'standard', '{"clues": [{"name": "Frozen ResultSet Stack Trace", "type": "digital", "clueId": "CLUE_001", "foundBy": "On Miguel''s terminal screen", "reveals": "ResultSet cursor was not properly positioned before iteration — violates core ResultSet usage pattern.", "description": "Terminal output showing java.sql.SQLException: ''Invalid cursor state'' at rs.next() in PetDB.getPets(). Last executed SQL: ''SELECT * FROM pets WHERE owner = \"Lena\"''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006"]}, {"name": "JDBC URL Sticky Note", "type": "physical", "clueId": "CLUE_002", "foundBy": "Stuck to monitor bezel", "reveals": "Connection was established without explicit driver registration — implies reliance on auto-loading or misconfigured DriverManager.", "description": "Handwritten note: ''jdbc:mysql://prod-db:3306/petdb?useSSL=false'' — smudged with coffee stain and ''NO DRIVER REG'' scribbled underneath.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_012"]}, {"name": "Driver Registration Audit Log", "type": "documentary", "clueId": "CLUE_003", "foundBy": "On Lena''s desk, under keyboard", "reveals": "Bypassing driver registration violates JDBC architecture — breaks vendor independence and safe initialization.", "description": "Handwritten ledger page listing driver registrations. Row for ''PetDB v2.3'' shows ''Class.forName() — SKIPPED'' and ''DriverManager.getConnection() called directly''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Cursor State Sticky Note", "type": "physical", "clueId": "CLUE_004", "foundBy": "Stuck to laptop lid", "reveals": "Improper resource management: unclosed Connection invalidates ResultSet — explains intermittent cursor failure.", "description": "Yellow sticky: ''rs.next() fails after 3rd call — check cursor state''. Scribbled beside it: ''Connection not closed → ResultSet invalidated?''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_006"]}, {"name": "PetDB v2.2 vs v2.3 Diff", "type": "digital", "clueId": "CLUE_005", "foundBy": "Via repository version comparison tool", "reveals": "Removal of PreparedStatement placeholders introduced SQL injection risk and eliminated precompilation benefits.", "description": "Side-by-side code diff: v2.2 uses ''pstmt.setString(1, pet.getName())''; v2.3 uses ''\"SELECT * FROM pets WHERE name = \\\"'' + pet.getName() + ''\\\"\"''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "Encrypted Notebook Page", "type": "documentary", "clueId": "CLUE_006", "foundBy": "Decrypted via passphrase ''jdbc-arch-42''", "reveals": "Confusing Statement’s executeUpdate() and executeQuery() usage leads to ResultSet misuse — violates JDBC API contract.", "description": "Scanned page from Miguel’s notebook: ''Statement.executeUpdate() returns int rowsAffected — but ResultSet from executeQuery() requires while(rs.next()). Using Statement for both breaks separation of concerns.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004", "CONC_006"]}], "title": "The ResultSet Heist: A JDBC Crime Scene", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Corrupted Console", "sceneId": "SCENE_001", "location": "Server Room B7 — Midnight", "description": "Fluorescent lights hum over humming racks. Miguel’s workstation displays a frozen ResultSet with garbled column names and a stack trace pointing to rs.next(). His coffee cup is cold. A printed JDBC URL dangles from the monitor.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "The Driver Registry Ledger", "sceneId": "SCENE_002", "location": "Database Admin Office — Next Morning", "description": "Lena’s desk holds a handwritten log titled ''Driver Registration Audit''. One entry is heavily redacted: ''Class.forName(\"com.mysql.jdbc.Driver\") — bypassed for PetDB v2.3''. A sticky note reads: ''rs.next() fails after 3rd call — check cursor state''.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_005", "CLUE_006"], "order": 1, "title": "The PetDB Source Vault", "sceneId": "SCENE_003", "location": "Secure Code Repository Terminal", "description": "Alex accesses the PetDB.java source. Two versions are side-by-side: v2.2 uses PreparedStatement with ? placeholders; v2.3 replaces them with String concatenation in addRecord(). A comment says: ''Performance fix — ResultSet handled in caller.''", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": [], "order": 1, "title": "The Final Connection", "sceneId": "SCENE_004", "location": "Conference Room ''JDBC Layer 3''", "description": "Whiteboard shows the full JDBC Architecture diagram—with ''ResultSet'' circled in red and ''Connection leak'' written beside it. Lena stands by the window. Alex holds Miguel’s decrypted notebook open to a sketch of a ResultSet cursor stuck between rows.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Architecture Was the Murder Weapon", "content": "Lena knowingly replaced PreparedStatement with Statement in PetDB v2.3 to meet performance targets—ignoring Miguel''s warnings. This removed SQL injection protection, eliminated precompilation, and broke ResultSet isolation. When concurrent requests reused the same Statement, ResultSet cursors became corrupted, causing silent data loss. Miguel discovered the flaw and prepared evidence—leading Lena to sabotage his workstation to destroy proof. The murder wasn''t personal—it was architectural negligence disguised as optimization.", "debrief": "You mastered JDBC fundamentals: the layered architecture (CONC_007), driver registration (CONC_002), Connection lifecycle (CONC_003), Statement vs PreparedStatement tradeoffs (CONC_004, CONC_005), ResultSet cursor mechanics (CONC_006), and real-world patterns like JavaBean (CONC_009), DAO (CONC_010), and CRUD (CONC_011). You now see how each piece interlocks—and how breaking one link collapses the whole system.", "summary": "Justice is served—not with handcuffs, but with a corrected pull request, proper try-with-resources blocks, and a company-wide JDBC safety training.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_005", "CLUE_006", "CLUE_001"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_005", "Q_007", "Q_010"]}}], "logline": "A database architect is found dead—his ResultSet code corrupted.", "version": "1.0", "evidence": [{"name": "PetDB v2.3 Vulnerability Report Draft", "type": "Documentary", "clueIds": ["CLUE_006"], "evidenceId": "EVIDENCE_001", "description": "Unsent internal memo authored by Miguel: details how Statement-based queries in PetDB v2.3 caused ResultSet corruption under load due to lack of isolation and improper cursor handling.", "foundLocation": "Encrypted in Miguel''s cloud backup (accessed in SCENE_003)", "relatedKnowledge": ["CONC_004", "CONC_006"]}, {"name": "JDBC Architecture Whiteboard Photo", "type": "Physical", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Photo of whiteboard from SCENE_004 showing labeled layers. ''ResultSet'' is highlighted with arrows pointing to ''Connection'' and ''PreparedStatement'', annotated: ''Dependent on both — never standalone.''", "foundLocation": "Alex''s case file (referenced in SCENE_004)", "relatedKnowledge": ["CONC_007", "CONC_003", "CONC_005"]}], "has_quiz": true, "scriptId": "JDBC_MURDER_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "ResultSet is not a data container—it''s a cursor-based iterator. What must happen before accessing any row?", "unlockAfterAttempts": 1}], "order": 1, "content": "Why does the stack trace point to ''rs.next()'' as the failing line—not the SQL execution?", "options": [{"content": "Because ResultSet objects are forward-only and read-only by default—the cursor starts before the first row and must be advanced with next().", "feedback": "Correct! ResultSet maintains a cursor position. Without calling next(), you''re attempting to read from an invalid position—hence ''Invalid cursor state''. This is fundamental to ResultSet handling.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "Because the SQL query syntax was malformed and only detected during row access.", "feedback": "Incorrect. Syntax errors would fail at executeQuery(), not rs.next(). ResultSet validity depends on cursor state, not query syntax.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About ResultSet Cursor Mechanics", "knowledgeId": "CONC_006"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_006", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Recall the full getConnection() signature—and what happens if the driver isn’t loaded before connection.", "unlockAfterAttempts": 1}], "order": 2, "content": "What critical JDBC component is missing from the sticky-note JDBC URL clue—and why is its omission dangerous?", "options": [{"content": "The username and password are missing—without credentials, DriverManager cannot authenticate with the database.", "feedback": "Incorrect. While credentials are required for getConnection(), the clue explicitly shows a valid JDBC URL. The danger lies elsewhere—in driver registration.", "optionId": "OPT_003", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The driver class is not registered—without Class.forName() or System.setProperty(), DriverManager may fail to locate the correct vendor driver, causing runtime exceptions or silent fallbacks.", "feedback": "Correct! JDBC requires driver registration to bind the generic API to vendor-specific protocols. Skipping it risks undefined behavior, especially in multi-driver environments.", "optionId": "OPT_004", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC URL and Driver Registration", "knowledgeId": "CONC_012"}, "difficulty": 2, "questionId": "Q_002", "knowledgeId": "CONC_012", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "JDBC Architecture has four layers. Which layer mediates between the application and vendor drivers?", "unlockAfterAttempts": 1}], "order": 1, "content": "Based on the audit log, why did skipping Class.forName() create a vulnerability in PetDB v2.3?", "options": [{"content": "It disabled the DriverManager layer, forcing direct calls to the vendor driver—bypassing abstraction and making the app DBMS-dependent.", "feedback": "Correct! DriverManager is the central routing layer in JDBC Architecture. Skipping driver registration undermines portability and safety checks built into the JDBC API.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "It prevented PreparedStatement precompilation—causing slower query execution.", "feedback": "Incorrect. Precompilation is tied to PreparedStatement creation—not driver registration. This is a separate issue.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JDBC Driver and DriverManager", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_007"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "Connection objects manage resources like network sockets and statement handles. What happens when they’re garbage-collected without explicit close()?", "unlockAfterAttempts": 1}], "order": 2, "content": "Why would an unclosed Connection cause rs.next() to fail intermittently—as noted on the sticky?", "options": [{"content": "The underlying database session terminates, invalidating all associated ResultSets—even if they’re still referenced in memory.", "feedback": "Correct! ResultSet is dependent on its parent Connection. If Connection is closed or GC’d, ResultSet becomes invalid. This causes ''Invalid cursor state'' on subsequent next() calls.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_006"]}, {"content": "It triggers automatic rollback, resetting the ResultSet to its initial position before the first row.", "feedback": "Incorrect. Rollback affects transaction state—not ResultSet cursor position. ResultSet invalidation is a resource lifecycle issue, not a transaction one.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Connection Lifecycle and Resource Management", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_004", "knowledgeId": "CONC_003", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_006"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "Consider two things: (1) How user input flows into the query, and (2) How many times the same SQL structure is compiled.", "unlockAfterAttempts": 1}], "order": 1, "content": "What security and performance flaws were introduced by replacing PreparedStatement with string concatenation in PetDB v2.3?", "options": [{"content": "SQL injection vulnerability + loss of precompiled execution plans → slower repeated queries and potential data theft.", "feedback": "Correct! Placeholders prevent injection by separating code from data. PreparedStatement caches the execution plan—string concatenation forces re-parsing every time.", "optionId": "OPT_009", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Increased memory usage due to storing multiple identical SQL strings in heap memory.", "feedback": "Incorrect. While inefficient, memory bloat isn’t the primary flaw. The critical issues are security (injection) and performance (no plan reuse).", "optionId": "OPT_010", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About PreparedStatement Benefits", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_005", "knowledgeId": "CONC_005", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_013"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_006", "content": "Start with Connection — everything depends on it. End with ResultSet iteration — nothing can happen before executeQuery().", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Call pstmt.setString(1, \"Lena\") to bind parameter"}, {"itemId": "ITEM_002", "content": "Obtain Connection via DriverManager.getConnection()"}, {"itemId": "ITEM_003", "content": "Iterate ResultSet with while(rs.next())"}, {"itemId": "ITEM_004", "content": "Execute query with pstmt.executeQuery()"}, {"itemId": "ITEM_005", "content": "Create PreparedStatement via conn.prepareStatement(sql)"}], "order": 2, "content": "Arrange these JDBC operations in the correct order to safely retrieve and process pet records using PreparedStatement:", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About PreparedStatement Workflow", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_006", "knowledgeId": "CONC_005", "maxAttempts": 2, "correctOrder": ["ITEM_002", "ITEM_005", "ITEM_001", "ITEM_004", "ITEM_003"], "feedbackCorrect": "Perfect! Safe PreparedStatement flow: (1) Get Connection, (2) Create PreparedStatement, (3) Bind parameters, (4) Execute, (5) Iterate ResultSet. This ensures resource control, type safety, and cursor correctness.", "feedbackIncorrect": "Remember: Connection must be obtained first; PreparedStatement created from it; parameters bound before execution; ResultSet processed only after executeQuery().", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_007", "content": "Look at the four-layer model: Application → JDBC API → ? → Vendor Driver.", "unlockAfterAttempts": 1}], "order": 1, "content": "Which JDBC architectural layer is responsible for translating generic JDBC method calls into MySQL-specific network commands?", "options": [{"content": "JDBC Driver Manager", "feedback": "Incorrect. DriverManager loads and routes to drivers—but doesn’t translate calls. That’s the driver’s job.", "optionId": "OPT_011", "showHint": "HINT_007", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Database-specific JDBC Driver", "feedback": "Correct! The vendor-specific JDBC Driver (e.g., mysql-connector-java) implements the translation layer—converting JDBC API calls into native database protocol messages.", "optionId": "OPT_012", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JDBC Architecture Layers", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_007", "knowledgeId": "CONC_007", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_008", "content": "First blank: ''Pet implements Serializable'' and has getId()/setName(). Second blank: ''PetDB has addRecord() and getPets()''.", "unlockAfterAttempts": 1}], "order": 2, "content": "In the PetDB ORM pattern, Pet.java is a ________ that maps to a database table, while PetDB.java is the ________ that encapsulates CRUD logic.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JavaBean and DAO Patterns", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_008", "knowledgeId": "CONC_009", "maxAttempts": 2, "correctAnswers": ["JavaBean", "DAO", "javabean", "dao", "data access object"], "feedbackCorrect": "Exactly! Pet.java follows JavaBean conventions (private fields, getters/setters, no-arg constructor) — modeling table rows. PetDB.java is the DAO: it abstracts database interactions and exposes clean CRUD methods.", "feedbackIncorrect": "Think about the roles: one represents data (with getters/setters), the other manages persistence (with add/update/delete).", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_009", "content": "Start with resource management (guarantees cleanup), end with data access (requires valid cursor position).", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_006", "content": "Use try-with-resources to auto-close Connection, PreparedStatement, and ResultSet"}, {"itemId": "ITEM_007", "content": "Call rs.getString(\"name\") or rs.getString(1) to retrieve column values"}, {"itemId": "ITEM_008", "content": "Initialize cursor with rs.next() inside a while loop"}, {"itemId": "ITEM_009", "content": "Obtain ResultSet from pstmt.executeQuery()"}], "order": 3, "content": "Order these steps to implement safe ResultSet access in a Java web application:", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Safe ResultSet Handling", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_009", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctOrder": ["ITEM_006", "ITEM_009", "ITEM_008", "ITEM_007"], "feedbackCorrect": "Spot on! Resource safety first (try-with-resources), then get ResultSet, advance cursor with next(), then access columns. This prevents leaks and invalid cursor states.", "feedbackIncorrect": "Remember: ResultSet must be obtained before iterating, and all resources must be closed—even if the loop exits early.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_010", "content": "Retrieve means reading data — which method returns a ResultSet? And which object owns that method?", "unlockAfterAttempts": 1}], "order": 4, "content": "Miguel’s notebook mentions ''CRUD operations'' in PetDB. Which JDBC component is most directly responsible for implementing the ''R'' (Retrieve) operation?", "options": [{"content": "PreparedStatement — because executeQuery() returns ResultSet, enabling data retrieval.", "feedback": "Correct! executeQuery() (on Statement or PreparedStatement) is the standard JDBC method for Retrieve operations. PreparedStatement is preferred for parameterized SELECTs.", "optionId": "OPT_013", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Connection — because it provides the getConnection() factory method.", "feedback": "Incorrect. Connection creates statements—but doesn’t execute queries itself. Retrieve is implemented by Statement/PreparedStatement.", "optionId": "OPT_014", "showHint": "HINT_010", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About CRUD Mapping to JDBC Methods", "knowledgeId": "CONC_011"}, "difficulty": 3, "questionId": "Q_010", "knowledgeId": "CONC_011", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_006"]}], "characters": [{"age": 32, "goal": "Solve the murder and expose the systemic JDBC flaw that enabled it.", "name": "Alex Chen", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Once deployed a vulnerable Statement-based query that leaked customer data—now obsessed with PreparedStatement safety.", "background": "Former Java backend developer turned digital crime investigator; specializes in database-layer vulnerabilities.", "occupation": "Senior Software Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, patient, deeply curious about how systems break—and why.", "knowledgePoints": ["CONC_001", "CONC_007"]}, {"age": 41, "goal": "Protect her reputation and prevent exposure of noncompliant code.", "name": "Dr. Lena Rossi", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Privately reverted critical PetDB queries to Statement for speed—bypassing placeholder safety to meet SLA deadlines.", "background": "Designed the ''PetDB'' ORM framework used company-wide; publicly advocated for PreparedStatement-only policies.", "occupation": "Lead Database Architect & JDBC Standards Committee Member", "characterId": "CHAR_002", "personality": "Precise, authoritative, dismissive of ''legacy'' JDBC practices—but recently stressed over performance audits.", "knowledgePoints": ["CONC_005", "CONC_013", "CONC_011"]}, {"age": 29, "goal": "Publish proof that unsafe ResultSet handling caused silent data loss in production.", "name": "Miguel Torres", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Had just submitted an internal report proving ResultSet corruption was caused by improper Statement reuse across threads.", "background": "Wrote the official PetDB documentation and discovered the Statement backdoor in Lena’s production code.", "occupation": "Junior JDBC Developer & ORM Documentation Lead", "characterId": "CHAR_003", "personality": "Idealistic, meticulous, quietly defiant—left encrypted notes about ''cursor corruption''.", "knowledgePoints": ["CONC_006", "CONC_004", "CONC_003"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "architecture", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_004"], "difficulty": 3, "description": "JDBC is a Java API that enables Java applications to interact with relational databases in a vendor-neutral manner. It provides standardized interfaces for connecting to, querying, and updating databases through JDBC drivers that translate generic JDBC calls into database-specific protocols.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "A JDBC driver is a Java class that implements the JDBC API to enable communication between a Java application and a specific database management system. It acts as a translation layer, converting JDBC method calls into database-specific network protocols. Drivers are registered via Class.forName() or System.setProperty().", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_007"]}, {"name": "Connection", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "difficulty": 3, "description": "A Connection object represents a session between a Java application and a database. Obtained via DriverManager.getConnection(), it provides factory methods (createStatement(), prepareStatement()), supports transaction control (commit/rollback), and allows metadata retrieval. Must be explicitly closed to prevent resource leaks.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004", "CONC_005"]}, {"name": "Statement", "category": "component", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "A Statement object executes static SQL queries without parameterization. Created via Connection.createStatement(), it supports executeQuery() (returns ResultSet), executeUpdate() (INSERT/UPDATE/DELETE), and execute(). Each execution compiles SQL anew—less efficient than PreparedStatement for repeated use.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_007"]}, {"name": "PreparedStatement", "category": "component", "appearsIn": ["SCENE_002", "SCENE_003", "SCENE_004"], "difficulty": 4, "description": "A PreparedStatement is a precompiled SQL statement supporting parameterized queries using ''?'' placeholders. Created via Connection.prepareStatement(), it improves performance (plan reuse) and prevents SQL injection. Uses setter methods (setString(), setInt()) to bind values before execution.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_007", "CONC_013"]}, {"name": "ResultSet", "category": "object", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "difficulty": 3, "description": "A ResultSet object represents tabular query results. It maintains a cursor initially positioned before the first row. The next() method advances the cursor row-by-row. Provides accessor methods (getString(), getInt()) to retrieve column values by index or name. Default is forward-only and read-only.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_007"]}, {"name": "JDBC Architecture", "category": "architecture", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_004"], "difficulty": 4, "description": "JDBC architecture consists of four layers: (1) Java Application, (2) JDBC API, (3) JDBC Driver Manager, (4) Database-specific JDBC Driver. DriverManager loads and routes to drivers; drivers translate JDBC calls into native protocols. Ensures portability and abstraction.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "theory", "appearsIn": ["SCENE_003", "SCENE_004"], "difficulty": 4, "description": "ORM maps object-oriented models to relational schemas. In this context, it refers to a simplified pattern where JavaBean classes (e.g., Pet.java) represent tables, and DAO classes (e.g., PetDB.java) encapsulate CRUD operations—abstracting SQL and enabling type-safe access.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010", "CONC_011"]}, {"name": "JavaBean", "category": "object", "appearsIn": ["SCENE_003", "SCENE_004"], "difficulty": 2, "description": "A JavaBean is a reusable, serializable Java class following conventions: private fields with public getter/setter methods, a no-argument constructor, and java.io.Serializable implementation. In JDBC, JavaBeans model database records—each field maps to a column.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_011"]}, {"name": "DAO (Data Access Object)", "category": "pattern", "appearsIn": ["SCENE_003", "SCENE_004"], "difficulty": 3, "description": "A DAO abstracts and encapsulates database access logic. PetDB.java exemplifies this: it manages connections, executes CRUD operations on the Pet table, and returns JavaBean instances. Separates persistence from business logic, improving testability and database independence.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_009", "CONC_011"]}, {"name": "CRUD Operations", "category": "process", "appearsIn": ["SCENE_003", "SCENE_004"], "difficulty": 2, "description": "CRUD stands for Create, Retrieve, Update, Delete—the four fundamental data manipulation operations. In JDBC, these map to INSERT, SELECT, UPDATE, and DELETE SQL statements. PetDB implements them via addRecord(), getPets(), updateRecord(), and deleteRecord().", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_005"]}, {"name": "Database URL", "category": "object", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "A JDBC database URL specifies how to connect to a database, using syntax ''jdbc:subprotocol:subname''. ''subprotocol'' identifies the driver (e.g., ''mysql''); ''subname'' contains host, port, and database name. Passed to DriverManager.getConnection() with credentials.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Placeholder", "category": "object", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "A placeholder is a ''?'' character in a PreparedStatement SQL string representing a parameter to be bound at execution time. Placeholders enable safe parameter substitution without string concatenation. Each is assigned an index (starting at 1) and bound via setter methods (e.g., setString(1, value)).", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_006"]}], "educational_goals": ["Master JDBC architecture and component relationships (Connection, Statement, PreparedStatement, ResultSet)", "Understand ResultSet cursor navigation, iteration, and accessor methods", "Differentiate Statement vs PreparedStatement, including placeholders and SQL injection prevention", "Apply JDBC concepts to real-world data access patterns: ORM, DAO, JavaBean, and CRUD"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 3}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'ResultSet Handling and Data Access', '2026-03-25 09:36:28.254047', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('c5a46f88-dd35-48eb-8c6c-c0b596babb42', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '143b43ff-7373-4be2-b387-155aa7232cee', NULL, 'The Servlet Sabotage', 'active', 'easy', 'standard', '{"clues": [{"name": "Corrupted web.xml snippet", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Evidence of inconsistent URL mapping due to manual editing error or tampering.", "description": "A fragment of web.xml showing mismatched <servlet> and <servlet-mapping> entries — the internal name ''LoginHandler'' maps to class ''ict.servlet.AuthServlet'', but the mapping points to ''ict.servlet.LoginServlet''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004"]}, {"name": "GlassFish container log excerpt", "type": "log", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The web container recognized and registered the servlet — misconfiguration lies elsewhere, not in basic deployment.", "description": "Timestamped log line: ''INFO: Initializing Servlet [LoginServlet] with name [LoginHandler]. Container bound /login to LoginHandler.'' Confirms container successfully loaded and mapped the servlet.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002"]}, {"name": "HTTP request trace (Wireshark-style)", "type": "network_trace", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Client sent POST, but server responded as if handling GET — suggests doGet() was invoked instead of doPost().", "description": "Raw HTTP request: ''POST /login HTTP/1.1\\r\\nHost: app.local\\r\\nContent-Type: application/x-www-form-urlencoded\\r\\nContent-Length: 27\\r\\n\\r\\nusername=admin&password=secret''. Response status: 200 OK, but body is empty HTML — no login success message.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "Raj’s local git diff (stashed)", "type": "code_diff", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Raj implemented only doGet(), despite the form using POST — a critical architectural oversight, not sabotage.", "description": "Staged change in LoginServlet.java: ''protected void doGet(HttpServletRequest req, HttpServletResponse resp)'' — unchanged. But missing ''protected void doPost(...)'' method entirely. A comment reads: ''// TODO: add POST handler — will do after testing GET first''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Container lifecycle annotation", "type": "diagram_annotation", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "A reminder of container-managed lifecycle — confirms Lin’s foundational understanding and hints that failure occurred at the dispatch layer, not infrastructure.", "description": "Handwritten sticky note on server rack: ''Tomcat creates thread → new req/resp objs → calls service() → dispatches to doGet/doPost → serializes response → GCs objs. No socket code needed.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Corrupted HttpServletRequest.getParameter() Call", "type": "code_snippet", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Mismatch between form field name and parameter extraction key — demonstrates misuse of HttpServletRequest interface.", "description": "A fragment from Raj''s servlet showing ''request.getParameter(\"username\")'' returning null — but the HTML form uses ''user_name'' as the input name attribute.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Response Header Set After PrintWriter Acquisition", "type": "log_entry", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Violation of HttpServletResponse contract: headers must be set before obtaining output streams.", "description": "Container error log: ''IllegalStateException: Cannot set header. Response already committed.'' — timestamped just before the crash.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006"]}, {"name": "doGet() Handling Login Form Submission", "type": "code_annotation", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Critical architectural misalignment: doGet() used for state-changing login, ignoring HTTP semantics and causing parameter binding failure.", "description": "Comment in Raj’s LoginServlet.java: ''// Using doGet for simplicity — POST not needed for small login''. The form’s method is ''post'', but doGet() is overridden without checking request method.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_007"]}, {"name": "Jakarta EE Stack Version Mismatch Warning", "type": "deployment_log", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Underlying architecture fragility: Jakarta EE version incompatibility undermines URL mapping and servlet lifecycle — supports Moss’s claim about outdated stack.", "description": "GlassFish server log: ''WARNING: Servlet [LoginServlet] declares @WebServlet but container is running Jakarta EE 9.1 — web.xml version 4.0 detected; namespace mismatch may disable annotation processing.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_008"]}, {"name": "Corrupted Form Submission Log", "type": "digital_evidence", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The form data was never submitted correctly due to mismatched input names and incorrect HTTP method handling.", "description": "A timestamped log snippet showing the raw HTTP POST request body from the login form — reveals missing ''username'' and ''password'' parameters, with only empty name-value pairs.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}, {"name": "Checkbox Value Mismatch Report", "type": "code_analysis", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Raj reused radio-button logic (getParameter) for checkbox inputs — a classic CONC_009 error causing null or truncated IDE preference data.", "description": "Side-by-side diff of the deployed HTML form (checkbox.html) and the servlet’s doPost() handler — shows the servlet calls getParameterValues(''ide'') but the HTML uses name=''ide'' correctly; however, the servlet mistakenly calls getParameter(''ide''), expecting a single value.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_005", "CONC_007"]}, {"name": "Radio Button Name Consistency Audit", "type": "configuration_evidence", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The HTML is valid; the failure occurs when the servlet attempts to retrieve radio button values — reinforcing that parameter extraction logic (not structure) is flawed.", "description": "Printout of Jakarta EE deployment validation tool output: highlights that all radio buttons in ''employee'' group share identical ''name=\"employee\"'', satisfying HTML spec — confirming the issue lies *not* in markup, but in servlet-side extraction.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "UTF-8 Encoding Warning Flag", "type": "server_log", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Using doGet() for form submission prevents proper character encoding setup — a subtle but critical CONC_009 implication when handling internationalized input.", "description": "GlassFish server log entry: ''WARNING: Request.setCharacterEncoding(\"UTF-8\") ignored — encoding already set by container. Parameter values may be corrupted if client submits non-ASCII characters.'' Appears only during GET requests.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009", "CONC_005"]}], "title": "The Servlet Sabotage", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Report", "sceneId": "SCENE_001", "location": "Server Room Control Center", "description": "Detective Lin arrives at the dimly lit control center where alarms flash red. Logs show an incomplete HTTP request that never reached a servlet. Dr. Moss claims the container was misconfigured, while Raj insists his code was correct. Initial inspection reveals missing deployment descriptors.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code and Confessions", "sceneId": "SCENE_002", "location": "Development Lab", "description": "Lin examines the source code repository. A corrupted web.xml suggests tampering. Raj admits to losing a config file but denies malice. Moss argues that the entire Jakarta EE stack is outdated. Lin discovers inconsistent URL mappings and unhandled form submissions pointing to deeper architectural flaws.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Deployment Test", "sceneId": "SCENE_003", "location": "Testing Chamber", "description": "Lin reconstructs the HTTP request-response flow using a test harness. All three watch as the system processes a login form. The test exposes that doGet() was improperly used instead of doPost(), and HttpServletRequest.getParameter() returns null due to incorrect name binding. The evidence converges on one suspect.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Revealed: The Accidental Saboteur", "content": "Raj Patel, overwhelmed and afraid of failure, reused a doGet() method to handle form login data. When the system went live, the mismatch between HTTP method and data handling caused silent failures. His attempt to hide the error led to cascading breakdowns. No malice intended—but ignorance was the real culprit.", "debrief": "Understanding the distinction between doGet() and doPost(), proper use of HttpServletRequest, and accurate URL mapping are essential for reliable web applications.", "summary": "The sabotage was not intentional. A junior developer’s misunderstanding of form handling and HTTP methods caused the system collapse.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: The Architect Falls", "content": "You accused Dr. Moss of deliberate sabotage. While she opposed the technology, logs prove her designs were sound. The real flaw lies downstream—in implementation, not architecture.", "debrief": "Even elegant architecture fails without proper execution. Focus on the full request-response chain, not just high-level design.", "summary": "Wrong suspect identified. Technical bias led to misjudgment.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes tech firm, a critical web application fails during deployment. As the lead architect vanishes, three suspects emerge—each with access, motive, and secrets. Only by tracing the HTTP request lifecycle and decoding Jakarta EE architecture can the detective uncover who sabotaged the system.", "version": "1.0", "evidence": [{"name": "Corrupted web.xml", "type": "Digital File", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Deployment descriptor showing malformed URL patterns and missing servlet declarations.", "foundLocation": "Development Lab", "relatedKnowledge": ["CONC_004", "CONC_001"]}, {"name": "Incomplete HTTP Log Entry", "type": "Server Log", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Log entry showing a POST request that entered the container but never reached a servlet method.", "foundLocation": "Server Room Control Center", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Test Login Form Submission", "type": "Interactive Evidence", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Simulated form submission that fails due to doGet() being called instead of doPost().", "foundLocation": "Testing Chamber", "relatedKnowledge": ["CONC_007", "CONC_005", "CONC_009"]}], "has_quiz": true, "scriptId": "ESD_MYSTERY_01", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin scans the flashing logs in the Server Room Control Center. One line reads: ''Container started; 3 servlets loaded, 2 mappings active.'' She knows this means the web container has taken control — but what core responsibility does the container *absolutely handle* so developers never write raw socket code?", "options": [{"content": "Compiling Java source files into bytecode before deployment", "feedback": "No — compilation is done by javac or build tools (e.g., Maven), not the web container. The container works with already-compiled .class files.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Managing servlet lifecycle, threading, and request-response binding", "feedback": "Correct. The web container handles loading, instantiation, initialization, multithreaded request dispatch, and cleanup — freeing developers from low-level networking and thread management. This is why servlets are portable across containers like Tomcat or GlassFish.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "Validating HTML forms before submission to prevent XSS", "feedback": "No — client-side validation is optional and insecure. Server-side validation is the developer’s responsibility; the container provides no built-in XSS filtering for form data.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Generating database connection pools automatically for all servlets", "feedback": "Not quite — while some containers *support* connection pooling via JNDI resources, it’s configured separately (e.g., in context.xml) and isn’t part of the core servlet container spec.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Web Container Responsibilities", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Moss insists, ''The container was misconfigured — it never even saw the request!'' Lin checks the logs and sees: ''INFO: Mapped servlet [LoginHandler] to [/login]''. What does this line *conclusively prove* about the web container’s role?", "options": [{"content": "The container successfully performed URL mapping — binding the public path ''/login'' to an internal servlet name.", "feedback": "Yes — this log confirms the container completed its declarative mapping duty (via web.xml or @WebServlet). The issue isn’t mapping failure — it’s downstream: method dispatch or logic.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_005"]}, {"content": "The servlet class file was corrupted and auto-recompiled on load.", "feedback": "No — container logs would show ''ClassNotFoundException'' or ''VerifyError'' if the class were invalid. A clean ''Mapped...'' log implies successful class loading.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The request reached the servlet’s doGet() method and executed fully.", "feedback": "Not provable from this log alone — mapping success doesn’t guarantee method invocation. That requires tracing the request flow (CONC_003).", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Security constraints blocked the request before mapping occurred.", "feedback": "False — security checks happen *after* mapping (during request dispatch), and a blocked request would log ''Access denied'' or return 403 — not a clean mapping message.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: How Containers Map URLs", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "In the Development Lab, Lin opens the corrupted web.xml. She sees <servlet-name>LoginHandler</servlet-name> paired with <servlet-class>ict.servlet.LoginServlet</servlet-class>, but the <servlet-mapping> links ''/login'' to <servlet-name>AuthHandler</servlet-name>. What architectural principle did this break — and why does it matter?", "options": [{"content": "It broke URL mapping abstraction — the container can’t resolve the endpoint because the internal name doesn’t match any declared servlet.", "feedback": "Exactly. URL mapping relies on two consistent layers: client URL → internal name → class. A mismatched <servlet-name> makes the mapping dangling — the container throws ''Servlet not found'' at runtime. This explains the incomplete HTTP request in SCENE_001.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "It violated Jakarta EE packaging standards — servlet classes must be in WEB-INF/classes, not src/main/java.", "feedback": "No — packaging location is a build concern, not a mapping one. As long as the compiled class is in the right place, the container loads it regardless of source layout.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It disabled declarative security — without matching names, roles in <security-constraint> are ignored.", "feedback": "Partially true for security, but the *immediate* failure is mapping resolution — the request never reaches security checks if the servlet can’t be located.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It prevented JSP translation — the container skips JSP support when servlet names are inconsistent.", "feedback": "No — JSP translation is independent of servlet mapping. It’s handled by a separate JSP servlet within the container.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: URL Mapping Layers", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Raj nervously admits he ''lost a config file'' — but Lin notices his code comments say: ''// POST handler pending''. She runs a test: submitting the login form sends POST, yet the response contains no error — just blank HTML. What servlet mechanism *must have been triggered*, and why did it fail silently?", "options": [{"content": "doGet() was called — because HttpServlet’s default service() dispatches POST to doGet() only if doPost() is undefined, and Raj never implemented doPost().", "feedback": "Correct. When doPost() is missing, HttpServlet falls back to doGet() — which likely returned empty HTML (no parameter handling). This explains the silent failure: no exception, just incorrect behavior. It’s a logic flaw, not a crash.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_004"]}, {"content": "The container threw ServletException — but Raj suppressed the stack trace in logging.", "feedback": "Unlikely — suppressed exceptions still appear in container logs (e.g., ''SEVERE: Servlet.service()''). Lin would have seen it in SCENE_001’s red alarms.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "getParameter() returned null because the form field name didn’t match the servlet’s expected variable.", "feedback": "That would cause null dereference *inside* doPost() — crashing with NullPointerException. Here, there’s no crash — meaning doPost() wasn’t entered at all.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The request was intercepted by a Filter and dropped before reaching the servlet.", "feedback": "Possible — but no filter declarations exist in the corrupted web.xml, and Dr. Moss didn’t mention filters. Occam’s razor points to missing doPost().", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Servlet Method Dispatch", "knowledgeId": "CONC_001"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Container creates HttpServletRequest and HttpServletResponse objects"}, {"itemId": "ITEM_B1_002", "content": "User clicks login form’s submit button (POST request)"}, {"itemId": "ITEM_B1_003", "content": "Container invokes service(), which dispatches to doPost()"}, {"itemId": "ITEM_B1_004", "content": "Container serializes response object into HTTP format and sends it to client"}, {"itemId": "ITEM_B1_005", "content": "Container locates correct servlet using URL mapping and allocates a thread"}], "order": 5, "content": "In the Testing Chamber, Lin reconstructs the full HTTP request-response flow for the login form. Arrange these steps in the exact order the web container executes them — from browser click to final response delivery.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: HTTP Request-Response Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_001", "ITEM_B1_005", "ITEM_B1_003", "ITEM_B1_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms the container’s orchestration role: it bridges the network layer (request arrival) and application layer (servlet logic) — and exposes where things went wrong (step 3: doPost() was missing, so service() fell back to doGet()).", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Review the lifecycle: the user action comes first, then container object creation, then mapping/threading, then method dispatch, and finally response serialization. Missing step 3 explains the blank response.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Lin watches the test harness output: ''Request method: POST | Parameter username: null''. She knows the form submits POST, but the servlet returns null for getParameter(\"username\"). What single word must replace ''doGet'' in the servlet’s method signature to fix this — and ensure parameters are properly bound?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: doGet() vs doPost()", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B1_006", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["doPost", "dopost", "DOPOST"], "feedbackCorrect": "Correct — changing the handler from doGet() to doPost() ensures the servlet receives the full POST payload (including form-encoded parameters). doGet() ignores POST body content by design, hence the null parameter.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Remember: doGet() handles query-string parameters (e.g., /login?username=admin); doPost() handles form-body parameters (e.g., username=admin in request body). For login forms, doPost() is mandatory.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash logs and sees an ''IllegalStateException: Cannot set header. Response already committed.'' What does this indicate about how the servlet handled the HttpServletResponse object?", "options": [{"content": "The servlet tried to write binary data using ServletOutputStream after already writing text with PrintWriter.", "feedback": "While mixing streams is unsafe, this specific error occurs earlier — when headers are modified *after* the response body has started streaming to the client.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet called setContentType() or addHeader() *after* calling getWriter() or getOutputStream().", "feedback": "Correct. HttpServletResponse enforces strict ordering: all headers and status codes must be set *before* acquiring any output stream. Violating this causes the container to ''commit'' the response prematurely — leading to this exact exception.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "The servlet attempted to redirect using sendRedirect() after writing content to the response.", "feedback": "True — that also triggers this error — but the log shows no redirect call. This option is plausible but unsupported by current evidence. Focus on the most directly indicated violation.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The container failed to initialize HttpServletResponse due to missing web.xml configuration.", "feedback": "No — the container *did* create the object (the error proves it was instantiated). The issue is misuse *after* creation, not initialization failure.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin compares the login form’s HTML source with the servlet code. The form uses <input type=''text'' name=''user_name''>, but the servlet calls request.getParameter(\"username\"). Why does this return null — and what core concept explains why the developer *expected* it to work?", "options": [{"content": "Because HttpServletRequest.getParameter() only works with GET requests — and the form uses POST.", "feedback": "Incorrect. getParameter() works identically for both GET (query string) and POST (request body) — as long as the parameter name matches exactly.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Because the parameter name in the servlet (''username'') doesn’t match the HTML input’s ''name'' attribute (''user_name'') — HttpServletRequest requires exact string matching.", "feedback": "Exactly. HttpServletRequest.getParameter() performs case-sensitive, exact string matching on the ''name'' attribute. A mismatch means no value is found — returning null. This is a foundational behavior of the request object.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_001"]}, {"content": "Because the servlet didn’t call request.setCharacterEncoding(''UTF-8'') first — causing encoding corruption.", "feedback": "Encoding issues affect character rendering (e.g., ''café'' becoming ''cafÃ©''), not parameter presence. A name mismatch always returns null regardless of encoding.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Because the form lacks enctype=''application/x-www-form-urlencoded'', so parameters aren’t parsed.", "feedback": "Incorrect. That enctype is the default for forms — no explicit declaration is needed. The browser sends parameters correctly; the servlet just looks for the wrong name.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Raj admits he ‘used doGet() for the login handler because it was easier’. Dr. Moss interrupts: ‘That’s not just lazy — it breaks HTTP semantics.’ What is the *primary* semantic reason doPost() should handle login — beyond convenience?", "options": [{"content": "doPost() supports larger payloads — login credentials could exceed GET’s URL length limit.", "feedback": "True, but secondary. While payload size matters, the *core semantic distinction* is about safety and side effects — which is more fundamental to HTTP design.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "GET requests are cached, bookmarkable, and logged — exposing credentials in URLs, server logs, and browser history.", "feedback": "Yes — this is the critical semantic violation. HTTP defines GET as ''safe'' and ''idempotent'': it must not cause state changes. Login *changes server state* (session creation, auth tracking) and must never appear in URLs. Using doGet() for login breaks security and RESTful principles.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "doGet() cannot access the request body — so form fields submitted via POST won’t be available.", "feedback": "Incorrect. HttpServlet’s service() method automatically dispatches POST requests to doPost(), *not* doGet(). If doGet() ran at all, the request was likely sent as GET — meaning the form’s method attribute was misconfigured.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Only doPost() can set cookies or session attributes — required for authentication.", "feedback": "False. Both doGet() and doPost() have full access to request.getSession() and response.addCookie(). Session handling isn’t restricted by HTTP method.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Moss argues the entire Jakarta EE stack is outdated — pointing to namespace mismatches in deployment logs. Which architectural layer does Jakarta EE’s container model *most directly* insulate developers from — explaining why Moss believes replacing it would prevent failures like this one?", "options": [{"content": "The physical network layer — abstracting TCP/IP socket management and load balancing.", "feedback": "Containers don’t replace network stacks. They rely on them — but don’t abstract away low-level networking.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The application server implementation — letting developers write portable servlets that run unchanged across GlassFish, WildFly, or Tomcat.", "feedback": "Correct. Jakarta EE’s container model provides a standardized API (Servlet, JSP, etc.) and runtime contract. Developers write to the spec — not vendor APIs. When version mismatches break annotation processing or lifecycle hooks, portability and abstraction fail — validating Moss’s concern.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_004"]}, {"content": "The database access layer — hiding SQL dialect differences via JPA providers.", "feedback": "While JPA *does* provide that abstraction, this incident involves servlet dispatching and request handling — not persistence. It’s outside the scope of this failure.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The frontend rendering layer — enabling automatic conversion between Java objects and HTML templates.", "feedback": "No Jakarta EE spec handles HTML generation automatically. JSP/JSF assist, but developers still write view logic. This failure occurred before rendering — in request routing and parameter binding.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Container creates HttpServletRequest and HttpServletResponse objects."}, {"itemId": "ITEM_B2_002", "content": "Container calls the servlet’s service() method."}, {"itemId": "ITEM_B2_003", "content": "Container dispatches to doPost() because the HTML form specifies method=''post''."}, {"itemId": "ITEM_B2_004", "content": "Servlet calls request.getParameter(''user_name'') to extract credentials."}, {"itemId": "ITEM_B2_005", "content": "Container serializes the HttpServletResponse object into an HTTP response and transmits it."}], "order": 5, "content": "Lin reconstructs the container’s exact sequence when handling the login request. Order these steps chronologically — from the moment the user clicks Submit to the final HTTP response being sent.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This flow confirms the container *did* follow HTTP semantics — meaning the bug lies in the servlet’s logic (e.g., wrong parameter name or using doGet()), not the container’s dispatch.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Review CHUNK_008: the container *always* creates request/response objects first, then calls service(), which dispatches based on HTTP method. The servlet’s parameter extraction happens *inside* doPost() — not before object creation.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Lin runs a debug trace and sees the servlet attempts to retrieve the password using request.getParameter(______). The HTML shows <input type=''password'' name=''pwd''> — so the blank must be filled with the exact string the servlet should use to match the form field.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["pwd"], "feedbackCorrect": "Correct. HttpServletRequest.getParameter() requires an exact, case-sensitive match to the HTML input’s ''name'' attribute — here, ''pwd''. Any variation (e.g., ''password'', ''PWD'', ''pwd_input'') returns null.", "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": "Remember: the parameter name is defined solely by the HTML ''name'' attribute — not by variable names in Java or common conventions. Check the form source again: it’s literally ''name=\"pwd\"''.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash report’s incomplete HTTP request. The logs show a 400 Bad Request response after a login attempt — no stack trace, just ''getParameter() returned null''. Lin recalls that form data binding depends on two things: correct HTTP method *and* matching name attributes. Which scenario most directly explains why getParameter(''username'') returns null?", "options": [{"content": "The HTML form uses method=''get'', but the servlet only implements doPost() — so the container never invokes the handler.", "feedback": "Incorrect. If doPost() is the only implemented method and the form uses GET, the container would call doGet() — but here, doGet() *is* implemented (and misused). Also, a missing method would typically yield 405 Method Not Allowed, not silent nulls.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet calls getParameter(''username'') inside doGet(), but the form submits via POST — so no parameters are parsed for GET requests.", "feedback": "Correct. In Jakarta EE, HttpServletRequest.getParameter() only extracts form data from POST request bodies — not from GET query strings unless explicitly included there. Using doGet() for form submission means the container never populates the parameter map from the POST body, resulting in null returns. This is a foundational CONC_009 pitfall.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "The web.xml mapping is missing, so the container routes the request to a default servlet that doesn’t handle parameters.", "feedback": "Incorrect. While missing deployment descriptors caused initial alarm (SCENE_001), the logs confirm the request reached *a* servlet — it’s the *parameter extraction* inside that servlet that fails. This points to logic, not routing.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The HTML input has name=''user_name'', but the servlet looks for ''username'' — a case-sensitive naming mismatch.", "feedback": "Plausible, but the crash report shows *all* parameters returning null — not just ''username''. A naming mismatch would affect only that field. Nulls across the board indicate systemic parameter map emptiness — consistent with using doGet() for POST data.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: How Form Data Binding Really Works", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the Development Lab, Lin compares Raj’s checkbox.html (CHUNK_018) with his servlet code. The HTML defines three checkboxes all with name=''ide''. Lin knows that checkboxes allow multiple selections — so what’s the *correct* servlet method to retrieve *all selected IDEs*?", "options": [{"content": "request.getParameter(\"ide\") — returns a comma-separated string of all selected values.", "feedback": "Incorrect. getParameter() always returns only the *first* value associated with the name — even for checkboxes. It will return only one IDE (e.g., ''eclipse''), ignoring others.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getParameterValues(\"ide\") — returns a String[] containing each selected value.", "feedback": "Correct. For multi-value controls like checkboxes, getParameterValues() is mandatory. It returns an array of all selected values (e.g., [\"eclipse\", \"netbean\"]). Using getParameter() here silently drops all but the first selection — a common CONC_009 bug that corrupts user intent.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_002"]}, {"content": "request.getAttribute(\"ide\") — pulls from request scope, not form data.", "feedback": "Incorrect. getAttribute() retrieves objects placed into the request by other components (e.g., filters or upstream servlets), not HTML form submissions. Form data lives in the parameter map — accessed via getParameter* methods.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getQueryString().split(\"&\") — manually parses the raw URL string.", "feedback": "Incorrect and unsafe. Query strings only exist for GET requests. For POST forms, data is in the request body — inaccessible via getQueryString(). Plus, manual parsing ignores encoding, null safety, and Jakarta EE abstractions.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Single vs. Multi-Value Parameter Extraction", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Lin notices Dr. Moss’s critique: ''This entire stack treats form handling as an afterthought.'' She’s right that Jakarta EE separates concerns — but where does *actual form data binding* happen? Lin examines the request lifecycle: the container creates HttpServletRequest, then dispatches to doGet()/doPost(). At which precise moment are parameters like ''username'' and ''employee'' made available to the servlet?", "options": [{"content": "When the container instantiates the servlet — parameters are injected during init().", "feedback": "Incorrect. Servlet initialization (init()) happens once per instance and is unrelated to individual requests. Parameters are request-scoped and created per invocation.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Inside the service() method — the container populates the parameter map before calling doGet() or doPost().", "feedback": "Correct. As described in CHUNK_008 and CHUNK_009, the container creates the HttpServletRequest object *and populates its internal parameter map* (from query string or POST body) before invoking service(), which then delegates to doGet()/doPost(). This is why parameters are immediately available inside those methods — it’s automatic, container-managed binding.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "Only after the developer calls request.parseParameters() — Jakarta EE requires explicit parsing.", "feedback": "Incorrect. Jakarta EE containers auto-parse parameters. There is no parseParameters() method in HttpServletRequest — this is a misconception. The container handles it transparently as part of request object creation.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "During JSP rendering — parameters are bound only when forwarding to a view.", "feedback": "Incorrect. Parameters are available in the servlet *before* any forwarding occurs. JSPs access them via EL (e.g., ${param.username}), but the binding happens at the servlet layer during request dispatch.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: When & How Parameters Are Populated", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "In the Testing Chamber, Lin runs the login test and observes the HTTP request headers: ''Content-Type: application/x-www-form-urlencoded'' and ''Content-Length: 27''. Yet inside doGet(), getParameter(''password'') returns null. Lin checks the container logs and sees: ''WARNING: setCharacterEncoding ignored — encoding already set''. What’s the root cause linking the warning, the null parameter, and the Content-Type header?", "options": [{"content": "The servlet calls setCharacterEncoding() too late — after the container has already parsed parameters using ISO-8859-1, causing corruption.", "feedback": "Partially true for encoding, but doesn’t explain *null*. Even with wrong encoding, parameters would still be non-null — just garbled. Null indicates *no parsing occurred*, not bad parsing.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The Content-Type header confirms this is a POST request — but doGet() cannot read POST body parameters at all. The container skips parameter population for GET handlers.", "feedback": "Correct. The presence of ''Content-Type'' and ''Content-Length'' headers proves this is a POST request. Jakarta EE containers *only* populate the parameter map from the request body for POST requests — and *only* when the servlet method invoked is doPost(). Calling doGet() bypasses body parsing entirely, leaving getParameter() results null. The encoding warning is a red herring — it appears because doGet() was called, not because of encoding issues.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_004"]}, {"content": "GlassFish rejects requests with Content-Type headers in GET requests — so the request never reaches the servlet.", "feedback": "Incorrect. GET requests should not have Content-Type or Content-Length — but the test harness is deliberately sending a malformed GET *with* a body (which violates HTTP spec). However, Jakarta EE containers still ignore the body in doGet(); they don’t reject the request outright.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The ''x-www-form-urlencoded'' format requires manual decoding — the container doesn’t auto-parse it for security reasons.", "feedback": "Incorrect. Jakarta EE containers *always* auto-parse x-www-form-urlencoded bodies for POST requests — it’s core behavior. No manual decoding is needed or expected.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: HTTP Method, Body Parsing, and Parameter Availability", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Browser sends HTTP POST request with body: ''username=lin&password=trustno1''"}, {"itemId": "ITEM_B3_002", "content": "Container creates HttpServletRequest and HttpServletResponse objects"}, {"itemId": "ITEM_B3_003", "content": "Container populates HttpServletRequest parameter map from POST body"}, {"itemId": "ITEM_B3_004", "content": "Container dispatches to servlet''s doPost() method"}, {"itemId": "ITEM_B3_005", "content": "Servlet calls request.getParameter(''username'') → returns ''lin''"}, {"itemId": "ITEM_B3_006", "content": "Container serializes HttpServletResponse into HTTP response and sends to browser"}], "order": 5, "content": "Lin reconstructs the exact sequence of events when a user submits the login form via POST. Arrange these steps in the order they occur — from browser click to response delivery.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: The Lifecycle of a Form Submission", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004", "ITEM_B3_005", "ITEM_B3_006"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms that parameter availability (CONC_009) is guaranteed *only* when the container populates the map (step 3) — which requires both a POST request *and* dispatch to doPost().", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_007"], "feedbackIncorrect": "Review CHUNK_008 and CHUNK_009: parameter population happens *after* request/response object creation but *before* the servlet method is called. The container handles this automatically — but only for the correct HTTP method.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Lin writes a forensic note: ''To fix the login failure, the form’s method must change from ''get'' to ''______'', and the servlet must implement ______() instead of doGet(). Only then will the container populate the parameter map from the request body.'' Fill in both blanks with the exact terms used in Jakarta EE servlet specification.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: GET vs POST — When to Use Which", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["post", "doPost"], "feedbackCorrect": "Exactly right. Changing the HTML form to method=''post'' signals the browser to send data in the request body. Implementing doPost() ensures the container populates the parameter map from that body — making getParameter() calls reliable. This is the canonical fix for CONC_009-related failures.", "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": "Remember: ''GET'' appends data to the URL (query string); ''POST'' sends it in the body. Jakarta EE servlets use doPost() to handle body-based submissions — not doGet(). Both terms are case-sensitive and lowercase in HTML and Java.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the sabotage and restore system integrity.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once worked at the same company years ago but left after a failed deployment caused major losses.", "background": "Former software engineer turned forensic analyst for enterprise systems. Known for solving complex technical failures.", "occupation": "Systems Integrity Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, detail-oriented", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_007", "CONC_008", "CONC_009"]}, {"age": 45, "goal": "Protect her reputation and avoid blame for the failure.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Privately submitted a proposal to replace the entire servlet-based system, which was rejected last week.", "background": "Architect of the failing web application. Advocates for modern frameworks over traditional servlets.", "occupation": "Lead Architect", "characterId": "CHAR_002", "personality": "Brilliant but dismissive of legacy technologies", "knowledgePoints": ["CONC_008", "CONC_001", "CONC_002"]}, {"age": 32, "goal": "Avoid being fired by shifting suspicion elsewhere.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Accidentally deleted a critical configuration file and tried to cover it up.", "background": "Junior developer responsible for implementing form handlers and URL mappings.", "occupation": "Backend Developer", "characterId": "CHAR_003", "personality": "Nervous, eager to prove himself, overly meticulous in code comments.", "knowledgePoints": ["CONC_004", "CONC_005", "CONC_009", "CONC_007"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Servlet", "category": "Core Component", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A Java class that handles requests and generates responses in a web application using the Jakarta EE platform.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_007", "CONC_005"]}, {"name": "Web Container", "category": "Infrastructure", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Runtime environment that manages servlets, handles request routing, and provides services like security and concurrency.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "HTTP Request-Response Lifecycle", "category": "Process Flow", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "The sequence of events from client request initiation to server response delivery, including parsing, dispatching, processing, and rendering.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_002"]}, {"name": "URL Mapping", "category": "Routing", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Configuration that binds incoming URLs to specific servlets or methods within a web application.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "HttpServletRequest", "category": "Request Handling", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Interface representing the client''s request, allowing access to headers, parameters, and session data.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_009", "CONC_003"]}, {"name": "HttpServletResponse", "category": "Response Handling", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Interface used to send responses back to the client, including status codes, headers, and content.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "doGet() and doPost() Methods", "category": "Method Logic", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Servlet methods that handle HTTP GET and POST requests respectively, differing in purpose and data handling.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_009"]}, {"name": "Jakarta EE Web Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "Enterprise framework for building scalable, secure, and maintainable web applications using standardized components and containers.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Form Data Handling", "category": "User Interaction", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Process of capturing, validating, and processing user input from HTML forms via HTTP requests.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_005", "CONC_007"]}], "educational_goals": ["Understand the role of Servlets in enterprise web applications", "Trace the HTTP Request-Response lifecycle through a Web Container", "Apply knowledge of HttpServletRequest and HttpServletResponse objects", "Implement proper URL mapping and form data handling", "Synthesize understanding of Jakarta EE Web Architecture components"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 3}}', '307dba01e492c9b0576a5195dd29f33c031273a74804f218bc6594620cfae249', 'all concepts', '2026-04-01 13:37:12.60538', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('0120ed13-0d2f-45a5-86c0-085a1ea116c1', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '7e6ea295-eea6-428f-a36b-1897b6726763', NULL, 'The Servlet Server Sabotage', 'active', 'easy', 'standard', '{"clues": [{"name": "Maya''s Terminal Snapshot", "type": "digital", "clueId": "CLUE_001", "foundBy": "On Maya’s unlocked laptop, pinned tab", "reveals": "Redirect failed because response object was null—suggesting service() never properly initialized the response", "description": "Screenshot showing stack trace: ''java.lang.NullPointerException at com.nexusbank.LoginServlet.service(LoginServlet.java:42)'' — line 42 is ''response.sendRedirect(\"/error.jsp\");''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "Sticky Note: ''No main()?''", "type": "physical", "clueId": "CLUE_002", "foundBy": "Stuck to edge of Maya’s keyboard", "reveals": "The servlet lifecycle was interrupted—init() never ran, so DB connections weren’t established", "description": "Yellow sticky on monitor: ''Servlets don’t have main(). Container calls init() → service() → destroy(). Why did ours skip init()?''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"]}, {"name": "Tomcat Log Snippet", "type": "documentary", "clueId": "CLUE_003", "foundBy": "Scrolled in Thorne’s active terminal", "reveals": "Container loaded the servlet and called service(), but no doXXX() method responded—pointing to flawed HttpServlet inheritance", "description": "''INFO [main] o.a.c.c.Catalina.start Server startup in 1243 ms'' followed by repeated ''DEBUG [http-nio-8080-exec-1] c.n.LoginServlet.service Invoked — method=POST''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_005", "CONC_014"]}, {"name": "Thorne''s Annotation", "type": "testimonial", "clueId": "CLUE_004", "foundBy": "Overheard during log review", "reveals": "He removed HTTP-specific dispatching—so doPost() was never called despite POST requests", "description": "Thorne says: ''HttpServlet’s service() is just routing glue. I replaced it with GenericServlet to unify REST and SOAP endpoints.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013", "CONC_014", "CONC_007"]}, {"name": "Login Flow Diagram", "type": "documentary", "clueId": "CLUE_005", "foundBy": "Drawn beside Maya’s keyboard, partially erased", "reveals": "Forward preserves request attributes (e.g., error messages); redirect does not—her implementation relied on this distinction", "description": "Whiteboard sketch: ''GET /login → forward to login.jsp'' | ''POST /login → validate → forward to dashboard.jsp OR redirect to /error.jsp''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_011", "CONC_010", "CONC_008"]}, {"name": "Request Object Printout", "type": "physical", "clueId": "CLUE_006", "foundBy": "Running debug print in Maya’s test servlet", "reveals": "The request object wasn’t populated—likely because init() failed or service() bypassed parameter parsing", "description": "Terminal output: ''request.getMethod() = POST'' and ''request.getParameter(\"password\") = null'' — even though form submitted password", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_008", "CONC_004", "CONC_003"]}, {"name": "Custom Servlet Classpath", "type": "digital", "clueId": "CLUE_007", "foundBy": "Thorne opens terminal and types command unprompted", "reveals": "Thorne deployed a non-HTTP servlet—breaking MVC controller logic and eliminating doGet/doPost hooks", "description": "ls -l /opt/tomcat/webapps/ROOT/WEB-INF/classes/com/nexusbank/ shows ''LoginServlet.class'' and ''CustomGenericServlet.class'' — no HttpServlet", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_013", "CONC_001", "CONC_012"]}], "title": "The Servlet Server Sabotage", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Crash Site", "sceneId": "SCENE_001", "location": "NexusBank DevOps Lab — Server Room B", "description": "Flickering monitors display red Tomcat error logs. Maya’s workstation is cordoned off. A half-drank coffee sits beside an open terminal showing ''HTTP Status 500 – Internal Server Error''.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "Log Line Interrogation", "sceneId": "SCENE_002", "location": "DevOps Lab — Conference Booth", "description": "Thorne reviews server logs on a shared screen. Lines show repeated ''service() called—but no doGet or doPost invoked''. A sticky note reads: ''Why no main()? Container runs it.''", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_005", "CLUE_006"], "order": 1, "title": "The Forward-Redirect Dilemma", "sceneId": "SCENE_003", "location": "DevOps Lab — Code Review Station", "description": "Detective Lin examines Maya’s last pull request: a login flow that should forward on success (JSP view) but redirects on failure (error page). The deployed version does neither—just hangs.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": ["CLUE_007"], "order": 1, "title": "Container Confession", "sceneId": "SCENE_004", "location": "DevOps Lab — Servlet Container Console", "description": "Thorne stands before the live Tomcat instance. Logs reveal container loaded a custom GenericServlet—not HttpServlet. Detective Lin confronts him as the JVM begins reloading.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Container Confession", "content": "Thorne admits he replaced HttpServlet with a custom GenericServlet to unify internal APIs—but ignored HTTP semantics. Without HttpServlet’s service() routing, doPost() was never invoked, leaving request/response objects null. Maya discovered this and was about to revert it. Her redirect failed because response was null; her forward failed because request params were null—both symptoms of broken lifecycle. The container tried—but couldn’t execute what wasn’t there.", "debrief": "You’ve mastered: servlets as container-managed components (CONC_001), the 5-stage lifecycle (CONC_003), init() for setup (CONC_004), service() as HTTP dispatcher (CONC_005), doGet/doPost as safe extension points (CONC_006/007), request/response as input/output carriers (CONC_008/009), forward vs redirect tradeoffs (CONC_010/011), MVC roles (CONC_012), and why HttpServlet > GenericServlet for web apps (CONC_013/014).", "summary": "The crime wasn’t malicious—it was architectural hubris. And the evidence was in the lifecycle.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_007"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_007", "Q_009", "Q_015"]}}], "logline": "A Java web app crashes—was it a bug or betrayal?", "version": "1.0", "evidence": [{"name": "Tomcat Startup Log", "type": "Documentary", "clueIds": ["CLUE_001", "CLUE_002"], "evidenceId": "EVIDENCE_001", "description": "Official Catalina log showing server boot, servlet loading, and missing init() traces—proving container attempted but failed to initialize the servlet.", "foundLocation": "SCENE_001 terminal", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Custom Servlet Bytecode", "type": "Digital", "clueIds": ["CLUE_007"], "evidenceId": "EVIDENCE_002", "description": "Compiled .class file analysis reveals no HttpServlet inheritance—only GenericServlet—confirming Thorne’s architectural sabotage.", "foundLocation": "SCENE_004 classpath", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Login Flow Architecture Diagram", "type": "Documentary", "clueIds": ["CLUE_005"], "evidenceId": "EVIDENCE_003", "description": "Maya’s official MVC design doc showing servlet → JSP (forward) and servlet → error page (redirect), validating correct usage intent.", "foundLocation": "SCENE_003 whiteboard", "relatedKnowledge": ["CONC_012", "CONC_010", "CONC_011"]}], "has_quiz": true, "scriptId": "SERVLET_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "Servlets run inside a managed environment—not as standalone programs.", "unlockAfterAttempts": 1}], "order": 1, "content": "Why doesn’t Maya’s LoginServlet have a main() method—and who *actually* starts its execution?", "options": [{"content": "It’s a Java class, not an application—execution is triggered by the servlet container upon receiving HTTP requests.", "feedback": "Correct! Servlets are managed components. The container (e.g., Tomcat) loads them, calls init(), and invokes service() for each request—no main() needed.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "Developers write main() manually—it’s omitted here due to a coding error.", "feedback": "Incorrect. Servlets *never* use main(). Their entry point is controlled entirely by the container.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Servlets", "knowledgeId": "CONC_001"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "It’s called once, before any requests—and is ideal for one-time setup.", "unlockAfterAttempts": 1}], "order": 2, "content": "Maya’s sticky note asks: ''Why did ours skip init()?'' What is the *purpose* of the init() method in the servlet lifecycle?", "options": [{"content": "To perform one-time initialization like opening database connections or loading config files—before any client requests arrive.", "feedback": "Correct! init() runs once after instantiation and before service(). Skipping it explains why DB connections failed and parameters were null.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}, {"content": "To handle the first GET request—like a warm-up call before real traffic.", "feedback": "Incorrect. init() is unrelated to request handling. It’s purely for setup—and happens *before* any service() call.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About init()", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_003"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "It checks the HTTP method and delegates to the correct handler—unless you override it (which you shouldn’t).", "unlockAfterAttempts": 1}], "order": 1, "content": "Thorne says HttpServlet’s service() is ''just routing glue.'' What does the default service() method in HttpServlet *actually* do?", "options": [{"content": "It examines the HTTP method (GET/POST) and automatically calls doGet() or doPost()—so developers shouldn’t override it.", "feedback": "Correct! HttpServlet.service() provides safe, standardized routing. Overriding it breaks the contract—exactly what caused the POST failures.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "It writes the HTTP response headers and commits the OutputStream—leaving body writing to doGet/doPost.", "feedback": "Incorrect. Headers and output are handled by the response object—not service(). Its sole job is method-based dispatch.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About service()", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_005", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_014"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "GenericServlet is protocol-agnostic—it knows nothing about GET, POST, or HttpServletRequest.", "unlockAfterAttempts": 1}], "order": 2, "content": "Thorne replaced HttpServlet with GenericServlet. What key HTTP functionality does GenericServlet *lack*?", "options": [{"content": "Built-in support for HTTP methods (GET/POST) and automatic dispatch to doGet()/doPost().", "feedback": "Correct! GenericServlet implements Servlet interface generically. HttpServlet extends it to add HTTP-awareness—including service() routing and request/response typing.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_006"]}, {"content": "The ability to be instantiated by the container—only HttpServlet supports container lifecycle management.", "feedback": "Incorrect. Both GenericServlet and HttpServlet support full container lifecycle (init/service/destroy). The difference is HTTP specialization.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About GenericServlet", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_013", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_014"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "Think about browser behavior: what happens if the user refreshes the page after a POST?", "unlockAfterAttempts": 1}], "order": 1, "content": "Maya’s whiteboard shows ''forward to dashboard.jsp'' on success, but ''redirect to /error.jsp'' on failure. Why is redirect *required* for errors after form submission?", "options": [{"content": "To prevent duplicate form submissions if the user refreshes—the redirect creates a new GET request, breaking the POST chain.", "feedback": "Correct! Redirect (302) makes the browser issue a new GET, avoiding resubmission. Forward would keep the POST context—dangerous after state changes.", "optionId": "OPT_009", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": ["CLUE_007"]}, {"content": "Because forward cannot send status codes like 400 Bad Request—only redirect supports error signaling.", "feedback": "Incorrect. Both forward and redirect can set status codes. The key distinction is browser awareness and request repetition.", "optionId": "OPT_010", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Redirect", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_005", "knowledgeId": "CONC_010", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_011"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "It’s about data scope: what’s available to the next component in the chain?", "unlockAfterAttempts": 1}], "order": 2, "content": "Maya’s diagram uses ''forward'' for successful login. What critical feature does forward preserve that redirect does *not*?", "options": [{"content": "Request-scoped attributes (e.g., ''user'', ''errorMessage'')—so the JSP can display personalized content.", "feedback": "Correct! Forward transfers control *internally*—the same request object (with all params/attributes) is passed to the JSP. Redirect starts fresh.", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "The original HTTP method—so the JSP can re-issue the same POST if needed.", "feedback": "Incorrect. Forward doesn’t change the method, but the JSP receives a *forwarded* request—not a new one. Method preservation isn’t the key benefit.", "optionId": "OPT_012", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Forward", "knowledgeId": "CONC_011"}, "difficulty": 3, "questionId": "Q_006", "knowledgeId": "CONC_011", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_008"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_007", "content": "MVC separates responsibilities: one part handles input, another renders, another manages data.", "unlockAfterAttempts": 1}], "order": 1, "content": "Thorne’s custom servlet bypassed HttpServlet. In MVC terms, what role did Maya’s LoginServlet play—and what broke when he removed it?", "options": [{"content": "Controller—responsible for routing requests, processing input, updating model (e.g., auth check), and selecting view (JSP). Removing HttpServlet broke routing.", "feedback": "Correct! Servlets act as MVC controllers. Without HttpServlet’s service() routing, no doGet/doPost meant no request handling—collapsing the entire pattern.", "optionId": "OPT_013", "showHint": "", "isCorrect": true, "nextSceneId": "ENDING_001", "unlockClues": []}, {"content": "Model—holding user credentials and session state. His change corrupted the database layer.", "feedback": "Incorrect. Model is business/data logic (e.g., UserDAO). Servlets are controllers—they orchestrate, not store.", "optionId": "OPT_014", "showHint": "HINT_007", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About MVC", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_007", "knowledgeId": "CONC_012", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_001"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_008", "content": "It’s the runtime environment—not the web server or database—that manages servlet instances.", "unlockAfterAttempts": 1}], "order": 2, "content": "The Tomcat logs show ''Server startup in 1243 ms''—but then no init() trace. Which component is responsible for loading the servlet class and calling init()?", "options": [{"content": "The servlet container (e.g., Tomcat)—it loads classes, instantiates servlets, and calls their lifecycle methods.", "feedback": "Correct! The container owns the lifecycle: load → instantiate → init() → service() × N → destroy(). Its absence explains the crash.", "optionId": "OPT_015", "showHint": "", "isCorrect": true, "nextSceneId": "ENDING_001", "unlockClues": []}, {"content": "The JVM itself—via static class loading and constructor invocation.", "feedback": "Incorrect. JVM loads classes, but only the *container* calls init(), service(), and destroy() per the Servlet spec.", "optionId": "OPT_016", "showHint": "HINT_008", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Servlet Container", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_008", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_003"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_009", "content": "It’s passed as a parameter—so it must be valid when the method receiving it is invoked.", "unlockAfterAttempts": 1}], "order": 3, "content": "Maya’s failing redirect suggests response.sendRedirect() was called on a null response. When is the HttpServletResponse object *guaranteed* to be non-null?", "options": [{"content": "Inside doGet(), doPost(), or other doXXX() methods—because service() passes valid request/response objects to them.", "feedback": "Correct! HttpServletResponse is injected by service(). If doPost() never ran (due to broken HttpServlet), response stays null.", "optionId": "OPT_017", "showHint": "", "isCorrect": true, "nextSceneId": "ENDING_001", "unlockClues": []}, {"content": "Inside init()—since it’s the first lifecycle method and prepares all dependencies.", "feedback": "Incorrect. init() receives only ServletConfig—not request/response. They’re only available during request handling.", "optionId": "OPT_018", "showHint": "HINT_009", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Response Object", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_009", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_005"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_010", "content": "This object wraps the raw HTTP request—and its methods only work if the request was parsed correctly.", "unlockAfterAttempts": 1}], "order": 4, "content": "Thorne’s terminal shows ''method=POST'' but no password param. Which object provides getParameter()—and why would it return null even with valid form data?", "options": [{"content": "HttpServletRequest—returns null if request body wasn’t parsed, e.g., because service() bypassed standard parameter extraction.", "feedback": "Correct! HttpServletRequest.getParameter() relies on container parsing. If service() was overridden or skipped, parsing never occurs—params stay null.", "optionId": "OPT_019", "showHint": "", "isCorrect": true, "nextSceneId": "ENDING_001", "unlockClues": []}, {"content": "HttpServletResponse—used to read client input before writing output.", "feedback": "Incorrect. HttpServletResponse is for *output*. Input comes exclusively from HttpServletRequest.", "optionId": "OPT_020", "showHint": "HINT_010", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Request Object", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_010", "knowledgeId": "CONC_008", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_003"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_011", "content": "Think of it like building a house: load foundations, build frame, install utilities (init), then host guests (service), finally demolish (destroy).", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Class loading into JVM"}, {"itemId": "ITEM_002", "content": "Instantiation via constructor"}, {"itemId": "ITEM_003", "content": "Initialization via init()"}, {"itemId": "ITEM_004", "content": "Request handling via service()"}, {"itemId": "ITEM_005", "content": "Cleanup via destroy()"}], "order": 3, "content": "Arrange the servlet lifecycle phases in correct chronological order.", "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Servlet Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_011", "knowledgeId": "CONC_003", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004", "ITEM_005"], "feedbackCorrect": "Correct! The container follows strict order: load → instantiate → init() → service() × N → destroy(). Skipping init() (as in the crime) breaks downstream phases.", "feedbackIncorrect": "Recall: init() must complete before service() can safely use resources. destroy() always comes last.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": "SCENE_002"}, {"type": "sequencing", "hints": [{"hintId": "HINT_012", "content": "The container never calls doPost() directly—it always goes through service() first.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_006", "content": "Client submits form to /login with POST"}, {"itemId": "ITEM_007", "content": "Container calls service() on LoginServlet"}, {"itemId": "ITEM_008", "content": "service() detects POST and delegates to doPost()"}, {"itemId": "ITEM_009", "content": "doPost() extracts username/password from request object"}, {"itemId": "ITEM_010", "content": "doPost() validates, updates model, then forwards to JSP or redirects"}], "order": 3, "content": "Order these steps in how a typical HTTP POST login request flows through the servlet stack.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About doPost()", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_012", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctOrder": ["ITEM_006", "ITEM_007", "ITEM_008", "ITEM_009", "ITEM_010"], "feedbackCorrect": "Correct! This is the canonical HTTP servlet flow. Thorne’s sabotage broke step 3—so steps 4–5 never executed.", "feedbackIncorrect": "Remember: service() is the dispatcher. Without it calling doPost(), the rest of the chain halts.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_013", "content": "Synonyms include ''web container'' and ''servlet engine''.", "unlockAfterAttempts": 1}], "order": 3, "content": "The runtime environment that loads servlet classes, manages their lifecycle, and handles concurrent requests is called the ________.", "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Servlet Container", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_013", "knowledgeId": "CONC_002", "maxAttempts": 2, "correctAnswers": ["servlet container", "web container", "container", "servlet engine"], "feedbackCorrect": "Correct! Servlet container (e.g., Tomcat) is the JVM-level manager responsible for init(), service(), and destroy()—making it central to the crime.", "feedbackIncorrect": "Hint: It’s not the web server or database—it’s the Java component that hosts servlets.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": "SCENE_001"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_014", "content": "They’re protected methods inherited from HttpServlet—named do + HTTP verb.", "unlockAfterAttempts": 1}], "order": 4, "content": "In HttpServlet, developers should override ________ and ________ to handle GET and POST requests—not service().", "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About doGet()", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_014", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctAnswers": ["doGet", "doPost", "doget", "dopost", "doget dopost", "dopost doGet"], "feedbackCorrect": "Correct! doGet() and doPost() are the intended extension points. Overriding service() violates the HttpServlet contract—causing the crash.", "feedbackIncorrect": "Hint: These methods start with ''do'' and end with the HTTP method name.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": "SCENE_002"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_015", "content": "First letters of Model, View, Controller.", "unlockAfterAttempts": 1}], "order": 5, "content": "The architectural pattern where servlets act as Controllers, JSPs as Views, and DAOs as Models is abbreviated as ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About MVC", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_015", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctAnswers": ["MVC", "mvc", "model view controller", "Model-View-Controller"], "feedbackCorrect": "Correct! MVC enforces separation of concerns—precisely why Thorne’s monolithic GenericServlet undermined system integrity.", "feedbackIncorrect": "Hint: It’s a three-letter acronym representing Model, View, and Controller.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}], "characters": [{"age": 32, "goal": "Identify who sabotaged the banking servlet—and why", "name": "Detective Lin", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Once deployed a servlet without overriding init(), causing a production DB connection leak", "background": "Former Java developer turned forensic investigator for enterprise web systems; assigned to audit the ''NexusBank'' online portal after its sudden outage.", "occupation": "Application Security Analyst", "characterId": "CHAR_001", "personality": "Methodical, empathetic, fluent in both code and human motives", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003"]}, {"age": 47, "goal": "Prove his GenericServlet redesign was viable—even if it required sabotage", "name": "Dr. Aris Thorne", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Modified the core HttpServlet to bypass service() routing—breaking all POST handling", "background": "Designed the MVC-compliant servlet architecture; recently clashed with management over replacing HttpServlet with custom GenericServlet for legacy integration.", "occupation": "Lead Architect, NexusBank Web Platform", "characterId": "CHAR_002", "personality": "Brilliant but rigid, values protocol independence over HTTP convenience", "knowledgePoints": ["CONC_013", "CONC_014", "CONC_005"]}, {"age": 29, "goal": "Ensure NexusBank’s MVC integrity and user data safety", "name": "Maya Chen", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Discovered Thorne’s modified HttpServlet and was about to report it—her last commit included a failing redirect test", "background": "Authored the secure login servlet using proper init() DB pooling and doPost() validation; found dead at her workstation with open Tomcat logs.", "occupation": "Senior Servlet Developer & MVC Implementer", "characterId": "CHAR_003", "personality": "Pragmatic, meticulous, believed in separation of concerns above all", "knowledgePoints": ["CONC_012", "CONC_010", "CONC_011"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Servlet", "category": "component", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001", "CHAR_002", "CHAR_003"], "difficulty": 3, "description": "A Java class that runs on a server and handles client requests, typically over HTTP. Servlets are managed by a container which controls their lifecycle including loading, initialization, servicing requests via service() method, and destruction. They do not have a main() method as execution is orchestrated by the container in response to web requests.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "Servlet Container", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002", "CLUE_003", "CHAR_001", "CHAR_002"], "difficulty": 3, "description": "A runtime environment within an application server that manages the lifecycle of servlets. It loads servlet classes, instantiates them, calls their init(), service(), and destroy() methods, and handles threading for concurrent requests. Examples include Tomcat and Jetty.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "Servlet Lifecycle", "category": "process", "appearsIn": ["SCENE_001", "SCENE_002", "CLUE_002", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "The sequence of stages a servlet goes through: loading into JVM, instantiation via constructor, initialization via init(), request processing via service(), and cleanup via destroy(). The container manages this entire process, ensuring each phase occurs only once except service() which may be called multiple times.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_006", "CONC_007"]}, {"name": "init() Method", "category": "method", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "A lifecycle method in servlets called once after instantiation. It allows developers to perform one-time setup such as initializing data structures, establishing database connections, or loading configuration files. Overriding this method is optional but common when initialization logic is required before handling client requests.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "service() Method", "category": "method", "appearsIn": ["SCENE_002", "CLUE_003", "CHAR_002"], "difficulty": 4, "description": "The core method in a servlet that gets invoked for every client request. It determines the HTTP method (GET, POST, etc.) and dispatches the request to the corresponding doGet(), doPost(), or other doXXX() methods. Developers should not override this method in HttpServlet subclasses since it already contains proper routing logic.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_003", "CONC_009", "CONC_010"]}, {"name": "doGet() Method", "category": "method", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_005", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "A method in HttpServlet that handles HTTP GET requests. It is called by the service() method when a GET request arrives. This method should be overridden by developers to define behavior for retrieving data or rendering pages. It receives HttpServletRequest and HttpServletResponse objects for reading input and writing output.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_005", "CONC_001"]}, {"name": "doPost() Method", "category": "method", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_006", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "A method in HttpServlet that handles HTTP POST requests. Invoked by the service() method upon receiving a POST request. Used primarily for submitting form data or performing state-changing operations. Like doGet(), it takes request and response parameters and must be overridden to implement custom logic.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_001"]}, {"name": "Request Object", "category": "object", "appearsIn": ["SCENE_003", "CLUE_006", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "An instance of HttpServletRequest that encapsulates all data from the client''s HTTP request. It provides access to headers, cookies, session information, request parameters, HTTP method type, and input streams. Servlets use this object to extract user input and contextual data needed to generate responses.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_001", "CONC_011"]}, {"name": "Response Object", "category": "object", "appearsIn": ["SCENE_001", "SCENE_003", "CLUE_001", "CHAR_001", "CHAR_003"], "difficulty": 3, "description": "An instance of HttpServletResponse used to send data back to the client. It allows setting content type (MIME type), status codes, headers, and obtaining output streams (Writer or OutputStream) for sending text or binary data such as HTML, JSON, images, or files.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "Redirect", "category": "process", "appearsIn": ["SCENE_003", "CLUE_001", "CHAR_003"], "difficulty": 4, "description": "A technique where the server instructs the browser to make a new request to a different URL using HttpServletResponse.sendRedirect(). It results in two HTTP requests, changes the browser’s address bar, and does not preserve request-scoped attributes. Best used after data-modifying operations like INSERT, UPDATE, DELETE to prevent duplicate submissions.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_011", "CONC_009"]}, {"name": "Forward", "category": "process", "appearsIn": ["SCENE_003", "CLUE_005", "CHAR_003"], "difficulty": 4, "description": "A server-side mechanism that transfers control internally from one component (like a servlet) to another (like a JSP) without informing the browser. Achieved via RequestDispatcher.forward(). The original URL remains unchanged in the browser, and request-scoped data is preserved. Suitable for SELECT operations where safe repetition is acceptable.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_009"]}, {"name": "Model-View-Controller", "category": "architecture", "appearsIn": ["SCENE_004", "CLUE_007", "CHAR_002", "CHAR_003"], "difficulty": 4, "description": "A software architectural pattern that separates concerns into three interconnected components: Model (data and business logic), View (presentation layer, e.g., JSP), and Controller (request handler that routes input and updates model). In web applications, servlets often act as controllers while JSPs serve as views.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_001", "CONC_013"]}, {"name": "GenericServlet", "category": "component", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "An abstract class implementing the Servlet interface with protocol-independent functionality. It provides basic lifecycle management but lacks HTTP-specific features. Used as a base for creating non-HTTP servlets. For HTTP-based applications, HttpServlet (which extends GenericServlet) is preferred.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_001", "CONC_014"]}, {"name": "HttpServlet", "category": "component", "appearsIn": ["SCENE_002", "CLUE_003", "CHAR_002"], "difficulty": 4, "description": "A concrete extension of GenericServlet tailored for HTTP communication. It implements the service() method to route HTTP requests based on method type (GET, POST, etc.) to corresponding protected methods like doGet() and doPost(). As an abstract class, it requires subclassing and overriding these doXXX() methods to provide actual behavior.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_013", "CONC_005"]}], "educational_goals": ["Understand how servlets are managed by containers and why they lack main() methods", "Master the servlet lifecycle: init(), service(), doGet()/doPost(), and destroy()", "Differentiate request/response objects, forward vs redirect, and MVC architecture in web apps"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 2}}', '59ff3fbd2a008b6795d7d669d48d63fac7cb9533aa4a00f2f5e2802958bd5ec4', 'all concepts', '2026-03-25 13:26:50.727308', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('df5854b3-8724-42e3-b6b3-22ec296d8667', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'e45053b9-7fb4-4e3b-9c2d-a0399ed0afd5', NULL, 'The Case of the Vanished Venture: A Business Basics Murder Mystery', 'active', 'easy', 'beginner', '{"clues": [{"name": "Highlighted Mission Statement", "type": "documentary", "clueId": "CLUE_001", "foundBy": "On Elias’s desk, under his left hand.", "reveals": "The tension between profit motive (CONC_002) and organizational purpose (CONC_003)—central to the conflict.", "description": "A laminated copy of NexusStart’s mission: ‘To empower SMEs through ethical technology—profitably, sustainably, and inclusively.’ Highlighted: ‘Profitably’ and ‘inclusively’.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "Open Spreadsheet: Q3 Profit Analysis", "type": "digital", "clueId": "CLUE_002", "foundBy": "Laptop screen unlocked, no password required.", "reveals": "Someone manipulated profit calculation (CONC_002)—either hiding losses or faking compliance.", "description": "Formula visible: ‘=REVENUES - COSTS’. Cell B5 shows ‘$0’ for ‘Net Income’. Row 6: ‘Taxes’ listed as $0 despite $120K revenue.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002"]}, {"name": "‘World’s Okayest Accountant’ Mug", "type": "physical", "clueId": "CLUE_003", "foundBy": "Beside laptop, warm to touch.", "reveals": "Elias was questioning equity valuation—hinting at balance sheet (CONC_015) discrepancies.", "description": "Hand-drawn accounting equation on the mug: ‘ASSETS = LIABILITIES + EQUITY’—with ‘EQUITY’ circled and ‘???’ written underneath.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_015"]}, {"name": "Wiped Whiteboard Corner", "type": "physical", "clueId": "CLUE_004", "foundBy": "Under UV light (provided in kit).", "reveals": "Maya implemented call center automation (CONC_023) but concealed its scope—likely violating NexusStart’s ‘inclusive’ purpose.", "description": "Faint marker residue reveals erased words: ‘Call Center Automation → Lead Qualification → ROI ↑’.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_023"]}, {"name": "Partially Shredded Trial Balance", "type": "documentary", "clueId": "CLUE_005", "foundBy": "Pulled from shredder; 30% intact.", "reveals": "Trial balance (CONC_013) misuse—treating marketing metrics as balance sheet assets violates accounting standards.", "description": "Page from CHUNK_013: lists accounts like ‘Cash’, ‘Accounts Receivable’, ‘Revenue’, ‘Expenses’—but ‘Qualified Leads’ appears as an unclassified ‘Asset’.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Sticky Note: ‘SaaS limits? Not our problem.’", "type": "documentary", "clueId": "CLUE_006", "foundBy": "Stuck to monitor bezel.", "reveals": "Awareness of SaaS affordability (CONC_025) and willful ignorance of its limitations (CONC_026).", "description": "Scrawled on CRM dashboard printout. Next to it: ‘SaaS Affordability: $299/mo vs. $12K on-premise’.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_025", "CONC_026"]}, {"name": "Physical Balance Sheet", "type": "documentary", "clueId": "CLUE_007", "foundBy": "Top document in ‘STRATEGY_VAULT’ cabinet.", "reveals": "Balance sheet (CONC_015) is mathematically sound—but equity may be inflated by fake revenue (linking to CLUE_002).", "description": "Printed on thick stock. Assets: $420K. Liabilities: $280K. Equity: $140K. Handwritten margin note: ‘Equity mismatch—see income stmt’.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_015"]}, {"name": "Income Statement (Redacted)", "type": "documentary", "clueId": "CLUE_008", "foundBy": "Inside USB drive case, not on drive.", "reveals": "Income statement (CONC_016) was altered to hide negative net income—proving Elias knew Maya’s automation inflated ‘qualified leads’ artificially.", "description": "Shows ‘Revenue: $120K’, ‘Expenses: $120K’, ‘Net Income: $0’. Redaction covers ‘Lead Acquisition Cost’ line—visible shadow suggests ‘-$45K’.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_016"]}, {"name": "USB Drive: ‘SaaS_Audit_FINAL’", "type": "digital", "clueId": "CLUE_009", "foundBy": "Inside vault, encrypted but password is ‘NEXUS2024’ (found on Elias’s desk calendar).", "reveals": "Elias documented SaaS limitations (CONC_026)—Maya accessed this hours before the incident.", "description": "Contains vendor contracts, security audit reports, and a memo: ‘SaaS Limitations: Bandwidth risk confirmed. Customization blocked per Tier-1 plan.’", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_026"]}, {"name": "Projector Slide: ‘Why Our Mission Statement ≠ Empty Words’", "type": "digital", "clueId": "CLUE_010", "foundBy": "Projector powered on, remote on podium.", "reveals": "Elias was preparing to expose the gap between stated purpose (CONC_003) and operational reality—motivating the sabotage.", "description": "Slide compares two columns: ‘What We Say’ (mission) vs. ‘What We Do’ (CRM/SaaS practices). Highlights mismatch in ‘inclusivity’ and ‘transparency’.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_003", "CONC_007"]}], "title": "The Case of the Vanished Venture: A Business Basics Murder Mystery", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002", "CLUE_003"], "order": 1, "title": "The Unbalanced Ledger", "sceneId": "SCENE_001", "location": "NexusStart Incubator – Founder’s Office (Indoor)", "description": "Dr. Elias Thorne lies slumped over his desk. His laptop displays an open spreadsheet titled ‘Q3 Profit Analysis’. A printed mission statement lies beside it—highlighted phrase: ‘Profit *and* Purpose’. A half-empty mug reads ‘World’s Okayest Accountant’.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_004", "CLUE_005", "CLUE_006"], "order": 2, "title": "The Misplaced Mix", "sceneId": "SCENE_002", "location": "NexusStart Marketing Lab (Indoor)", "description": "Whiteboards overflow with customer personas and ‘4Ps’ diagrams—but one corner is wiped clean. A CRM dashboard shows ‘Lead Score: 98%’ while a sticky note says ‘SaaS limits? Not our problem.’ A trial balance printout sits in the shredder—partially fed.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_007", "CLUE_008", "CLUE_009"], "order": 1, "title": "The Strategy Vault", "sceneId": "SCENE_003", "location": "NexusStart Server Room (Indoor)", "description": "Cold, humming servers line the walls. A locked cabinet labeled ‘STRATEGY_VAULT’ stands open—inside: a physical balance sheet, an income statement, and a USB drive labeled ‘SaaS_Audit_FINAL’. The door alarm shows ‘Last accessed: 2:14 AM — User: MAYA_C’.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": ["CLUE_010"], "order": 1, "title": "The Final Forecast", "sceneId": "SCENE_004", "location": "NexusStart Boardroom (Indoor)", "description": "A projector glows with a slide: ‘Why Our Mission Statement ≠ Empty Words’. On the table: Elias’s redacted income statement, Maya’s CRM export, and a SaaS vendor contract marked ‘Initial Affordability Only’.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Balanced Truth", "content": "Maya didn’t intend harm—but feared NexusStart’s strict ethics would kill her high-growth marketing model. She accessed Elias’s SaaS audit, altered the income statement to hide lead-cost losses, and used call center automation to inflate ‘qualified leads’—knowing it violated the mission. Elias discovered the fraud and scheduled a confrontation. Maya panicked, sedated him (non-lethally), and fled—leaving clues that only business literacy could decode. True leadership isn’t avoiding risk—it’s aligning tools (SaaS), tactics (marketing mix), and purpose (mission) with integrity.", "debrief": "You mastered: Business (CONC_001), Profit (CONC_002), Purpose (CONC_003), Management Functions (CONC_006), Mission Statement (CONC_007), Marketing (CONC_009), Marketing Mix (CONC_011), Accounting (CONC_012), Trial Balance (CONC_013), Financial Reporting (CONC_014), Balance Sheet (CONC_015), Income Statement (CONC_016), Supply Chain (CONC_017), CRM (CONC_020), Call Center Automation (CONC_023), SaaS (CONC_024), and its trade-offs (CONC_025, CONC_026).", "summary": "Alex presents the evidence: Maya admits misconduct but agrees to overhaul NexusStart’s CRM ethics policy—turning crisis into catalyst for principled growth.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007", "CLUE_008", "CLUE_009", "CLUE_010"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_001", "Q_002", "Q_003", "Q_004", "Q_005", "Q_006", "Q_007", "Q_008", "Q_009", "Q_010"]}}], "logline": "A startup founder is found unconscious—only business knowledge can solve it.", "version": "1.0", "evidence": [{"name": "Redacted Income Statement", "type": "Documentary", "clueIds": ["CLUE_008"], "evidenceId": "EVIDENCE_001", "description": "Official NexusStart financial report with ‘Lead Acquisition Cost’ redacted—but shadow reveals -$45K. Proves Elias knew Maya’s automation inflated metrics.", "foundLocation": "Inside ‘STRATEGY_VAULT’ cabinet (SCENE_003)", "relatedKnowledge": ["CONC_016"]}, {"name": "SaaS Vendor Contract: ‘Tier-1 Plan’", "type": "Documentary", "clueIds": ["CLUE_009"], "evidenceId": "EVIDENCE_002", "description": "Contract clause: ‘Customization disabled. Bandwidth throttling applied above 50 concurrent users.’ Confirms Maya ignored documented SaaS limitations.", "foundLocation": "Inside USB drive ‘SaaS_Audit_FINAL’ (SCENE_003)", "relatedKnowledge": ["CONC_026"]}], "has_quiz": true, "scriptId": "BUSINESS_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "Look at the definition: ‘financial gain realized when revenue exceeds costs’.", "unlockAfterAttempts": 1}], "order": 1, "content": "Elias’s highlighted mission says ‘profitably, sustainably, and inclusively’. What core concept does ‘profitably’ directly reflect?", "options": [{"content": "Profit", "feedback": "Correct! ‘Profitably’ refers to generating profit (CONC_002)—the financial gain from revenue minus costs. It’s the engine of sustainability for most businesses.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}, {"content": "Business Purpose", "feedback": "While purpose (CONC_003) includes profit, ‘profitably’ specifically names the financial outcome—not the broader reason for existing.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Profit", "knowledgeId": "CONC_002"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "This statement is a ‘snapshot’—not a summary over time.", "unlockAfterAttempts": 1}], "order": 2, "content": "The mug shows ‘ASSETS = LIABILITIES + EQUITY’. Which financial statement presents this equation in practice?", "options": [{"content": "Balance Sheet", "feedback": "Correct! The balance sheet (CONC_015) is the formal snapshot that embodies the accounting equation: Assets = Liabilities + Owners’ Equity.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_005"]}, {"content": "Income Statement", "feedback": "The income statement (CONC_016) shows performance over time (revenue, expenses, profit)—not the static equation.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Balance Sheet", "knowledgeId": "CONC_015"}, "difficulty": 1, "questionId": "Q_002", "knowledgeId": "CONC_015", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_012", "CONC_013"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "Think: Product, Price, Place, Promotion—the classic ‘4Ps’.", "unlockAfterAttempts": 1}], "order": 1, "content": "Maya’s whiteboard had ‘4Ps’ diagrams. Which list correctly names all four components of the marketing mix?", "options": [{"content": "Product, Price, Place, Promotion", "feedback": "Correct! The marketing mix (CONC_011) is defined by these four controllable tactical tools—known as the 4Ps.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_006"]}, {"content": "Planning, Organizing, Directing, Controlling", "feedback": "Those are management functions (CONC_006)—not marketing mix elements.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Marketing Mix", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "Review the SaaS limitations list: security, bandwidth/response time, flexibility…", "unlockAfterAttempts": 1}], "order": 2, "content": "Maya’s sticky note says ‘SaaS limits? Not our problem.’ But which limitation is *most directly related* to bandwidth and response time?", "options": [{"content": "Bandwidth/Response Time", "feedback": "Correct! CONC_026 explicitly lists ‘Bandwidth/response time’ as a key SaaS limitation—critical for real-time CRM and call center tools.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_007"]}, {"content": "Security", "feedback": "Security is also a SaaS limitation (CONC_026), but the sticky note references performance—not breaches.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About SaaS Limitations", "knowledgeId": "CONC_026"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_026", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_024", "CONC_025"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_005", "content": "Think of building a house: design (plan), gather materials (organize), hire crew (direct), inspect progress (control).", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Planning: Setting goals and defining resource relationships"}, {"itemId": "ITEM_002", "content": "Organizing: Allocating resources and assigning tasks"}, {"itemId": "ITEM_003", "content": "Directing: Leading teams and motivating performance"}, {"itemId": "ITEM_004", "content": "Controlling: Monitoring results and adjusting plans"}], "order": 1, "content": "Put the core management functions in the correct order as described in business theory.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Management Functions", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_005", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004"], "feedbackCorrect": "Correct! Management functions (CONC_006) follow this logical sequence: Plan first, then organize resources, direct people, and finally control outcomes.", "feedbackIncorrect": "Remember: You can’t organize without a plan, can’t direct without organization, and can’t control without direction.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "sequencing", "hints": [{"hintId": "HINT_006", "content": "Ask: Who provides inputs? Who transforms them? Who distributes? Who sells? Who buys?", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_005", "content": "Supplier"}, {"itemId": "ITEM_006", "content": "Manufacturer"}, {"itemId": "ITEM_007", "content": "Wholesaler"}, {"itemId": "ITEM_008", "content": "Retailer"}, {"itemId": "ITEM_009", "content": "Customer"}], "order": 2, "content": "Arrange these supply chain stages in the order they occur—from raw material to consumer.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Supply Chain", "knowledgeId": "CONC_017"}, "difficulty": 2, "questionId": "Q_006", "knowledgeId": "CONC_017", "maxAttempts": 2, "correctOrder": ["ITEM_005", "ITEM_006", "ITEM_007", "ITEM_008", "ITEM_009"], "feedbackCorrect": "Correct! The supply chain (CONC_017) flows linearly: Supplier → Manufacturer → Wholesaler → Retailer → Customer.", "feedbackIncorrect": "Trace the journey: raw materials start with suppliers, end with customers receiving finished goods.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_007", "content": "It’s the function that connects products to people through pricing, promotion, and place.", "unlockAfterAttempts": 1}], "order": 1, "content": "The process of planning and executing the conception, pricing, promotion, and distribution of ideas, goods, and services is called ____.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Marketing", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_007", "knowledgeId": "CONC_009", "maxAttempts": 2, "correctAnswers": ["marketing", "Marketing"], "feedbackCorrect": "Correct! Marketing (CONC_009) is defined precisely as this comprehensive process to create value-driven exchanges.", "feedbackIncorrect": "Hint: It starts with ‘M’ and is one of the core business functions taught in Chapter 11.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_008", "content": "It answers: ‘What do we do? For whom? How are we different?’", "unlockAfterAttempts": 1}], "order": 2, "content": "A formal summary defining an organization’s core purpose and focus—answering what it does for customers, employees, and owners—is called a ____ statement.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Mission Statement", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_008", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctAnswers": ["mission", "Mission", "mission statement", "Mission Statement"], "feedbackCorrect": "Correct! A mission statement (CONC_007) articulates purpose, identity, and stakeholder value—it’s the ‘why’ behind the business.", "feedbackIncorrect": "Hint: It’s often posted on websites and office walls—and Elias had one laminated on his desk.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_009", "content": "One statement shows ‘what you own/owe’ (snapshot); the other shows ‘what you earned/spent’ (flow).", "unlockAfterAttempts": 1}], "order": 3, "content": "Elias’s redacted income statement hides ‘Lead Acquisition Cost’. Which concept explains why this cost belongs on the income statement—not the balance sheet?", "options": [{"content": "The income statement summarizes operating results over time—including expenses like lead acquisition.", "feedback": "Correct! The income statement (CONC_016) captures revenues and expenses incurred during a period—so lead costs belong here, not on the balance sheet (CONC_015).", "optionId": "OPT_009", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "The balance sheet reflects long-term assets only—lead costs are short-term.", "feedback": "Incorrect. Balance sheets include current assets/liabilities—but expenses like lead acquisition reduce net income, affecting retained earnings (equity) on the balance sheet *indirectly*.", "optionId": "OPT_010", "showHint": "HINT_009", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Income Statement", "knowledgeId": "CONC_016"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_016", "maxAttempts": 3, "masteryReward": 3, "relatedKnowledge": ["CONC_015", "CONC_012"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_010", "content": "Purpose (CONC_003) defines the ‘fundamental reason’ an organization exists—including non-profit values like inclusivity.", "unlockAfterAttempts": 1}], "order": 4, "content": "Maya used call center automation to screen leads—but Elias argued it violated NexusStart’s mission. Which concept links automation ethics to organizational purpose?", "options": [{"content": "Business Purpose — because automating lead filtering contradicted the stated commitment to inclusivity and fairness.", "feedback": "Correct! Business purpose (CONC_003) is the foundational ‘why’—and Elias believed Maya’s automation undermined NexusStart’s core promise of inclusive opportunity.", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Marketing Strategy — because segmentation should target, not exclude.", "feedback": "Strategy (CONC_010) guides *how* to reach markets—but purpose (CONC_003) defines *whether* a tactic aligns with mission.", "optionId": "OPT_012", "showHint": "HINT_010", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Business Purpose", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_010", "knowledgeId": "CONC_003", "maxAttempts": 3, "masteryReward": 3, "relatedKnowledge": ["CONC_007", "CONC_023"]}], "characters": [{"age": 32, "goal": "Uncover who sabotaged NexusStart—and why—by reconstructing the business logic behind the crime.", "name": "Alex Rivera", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Alex once misapplied the accounting equation in a client report—learned the hard way that Assets = Liabilities + Equity must always balance.", "background": "Hired by the Chamber of Commerce to investigate irregularities at ''NexusStart'', a local incubator for SMEs. Alex uses business fundamentals daily to advise clients—and now to uncover deception.", "occupation": "Small Business Consultant & Former Auditor", "characterId": "CHAR_001", "personality": "Calm, observant, asks precise questions; believes numbers never lie but people often omit context.", "knowledgePoints": ["CONC_015", "CONC_016", "CONC_002"]}, {"age": 28, "goal": "Protect her marketing team’s autonomy—and prevent exposure of her automated lead filtering.", "name": "Maya Chen", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Maya secretly used call center automation to filter out ‘low-potential’ investors—violating NexusStart’s inclusive mission—and hid the logs in a mislabeled trial balance file.", "background": "Led the rebranding of three failed startups into profitable ventures using hyper-targeted one-to-one marketing. Recently clashed with the victim over cutting CRM budget for ''low-frills'' SaaS tools.", "occupation": "Marketing Director, NexusStart Incubator", "characterId": "CHAR_002", "personality": "Charismatic, data-driven, impatient with vague strategy—believes ‘if it’s not measurable, it’s not marketing’.", "knowledgePoints": ["CONC_009", "CONC_010", "CONC_011", "CONC_021", "CONC_022", "CONC_023"]}, {"age": 54, "goal": "Launch NexusStart’s ‘Ethical Tech Stack’ certification—requiring full transparency on SaaS limitations and CRM ethics.", "name": "Dr. Elias Thorne", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Elias discovered Maya’s call center automation violated GDPR-style consent rules—and planned to present evidence at tomorrow’s board meeting using a redacted income statement showing inflated ‘qualified leads’.", "background": "Former accounting professor turned entrepreneur. Built NexusStart to help SMEs implement ethical, scalable business practices. Was finalizing a white paper titled ‘Profit with Purpose: Why Non-Profits Can’t Ignore the Balance Sheet’.", "occupation": "Founder & CEO, NexusStart Incubator", "characterId": "CHAR_003", "personality": "Principled, meticulous, quietly passionate about aligning profit motive with social impact.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_007", "CONC_008", "CONC_012", "CONC_013", "CONC_014", "CONC_015", "CONC_016", "CONC_017", "CONC_018", "CONC_019", "CONC_020", "CONC_024", "CONC_025", "CONC_026"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Business", "category": "basics", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_003"], "difficulty": 2, "description": "An organization engaged in commercial activities to generate profit by providing goods/services—or societal benefit (non-profits). Core traits: profit motive, exchange, and stakeholder accountability.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Profit", "category": "formula", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_003"], "difficulty": 2, "description": "Financial gain = Revenue − Costs. Serves as performance indicator and reward for delivering customer value efficiently. Non-profits reinvest surplus rather than distribute profits.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_018"]}, {"name": "Business Purpose", "category": "theory", "appearsIn": ["SCENE_001", "CLUE_001", "CLUE_010", "CHAR_003"], "difficulty": 2, "description": "The fundamental reason an organization exists—to earn profit for owners (or advance societal good for non-profits). Guides decisions, strategy, and ethical boundaries.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_012"]}, {"name": "Business Management", "category": "process", "appearsIn": ["SCENE_003", "CHAR_002"], "difficulty": 3, "description": "The process of planning, organizing, directing, and controlling resources to achieve goals effectively and efficiently. Managers balance stakeholder expectations and operational realities.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Effective Manager", "category": "person", "appearsIn": ["SCENE_002", "CHAR_002"], "difficulty": 2, "description": "A manager accountable for performance and effectiveness—aligning team efforts with objectives through leadership, oversight, and decision-making.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_006"]}, {"name": "Management Functions", "category": "process", "appearsIn": ["SCENE_003", "Q_005", "CHAR_002"], "difficulty": 3, "description": "Four core responsibilities: Planning (setting goals), Organizing (allocating resources), Directing (leading teams), Controlling (monitoring and adjusting). Essential for adaptive execution.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Mission Statement", "category": "object", "appearsIn": ["SCENE_001", "CLUE_001", "CLUE_010", "CHAR_003"], "difficulty": 3, "description": "A formal summary of an organization’s core purpose—answering what it does for customers, employees, and owners. Guides strategy and reflects identity (e.g., Apple’s innovation focus).", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_003", "CONC_008"]}, {"name": "Business Strategy", "category": "process", "appearsIn": ["SCENE_003", "CHAR_003"], "difficulty": 4, "description": "Long-term plans to meet goals amid market changes. Involves environmental analysis, goal-setting, capability matching, and actionable tactics (e.g., product differentiation).", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_007", "CONC_006"]}, {"name": "Marketing", "category": "process", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "Process of planning/executing conception, pricing, promotion, and distribution to create value-driven exchanges satisfying individual and organizational objectives.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "Marketing Strategy", "category": "process", "appearsIn": ["SCENE_002", "CHAR_002"], "difficulty": 3, "description": "Plan to reach target markets via segmentation, need analysis (research), and tailored marketing mix (4Ps) to fulfill needs and build loyalty.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_009", "CONC_011"]}, {"name": "Marketing Mix", "category": "component", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "The 4Ps—Product, Price, Place, Promotion—controllable tools used to produce desired market response and deliver value propositions.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_009"]}, {"name": "Accounting", "category": "process", "appearsIn": ["SCENE_001", "CHAR_003"], "difficulty": 3, "description": "Discipline measuring/communicating financial information to support decisions and control. Involves recording, classifying, summarizing, and reporting (e.g., trial balances, statements).", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Trial Balance", "category": "object", "appearsIn": ["SCENE_002", "CLUE_005", "CHAR_003"], "difficulty": 3, "description": "Internal report listing ledger account balances (assets, liabilities, revenues, expenses). Verifies arithmetic accuracy before financial statements and detects bookkeeping errors.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_012", "CONC_015"]}, {"name": "Financial Reporting", "category": "process", "appearsIn": ["SCENE_003", "CHAR_003"], "difficulty": 3, "description": "Formal communication of financial activities/condition via standardized reports (income statements, balance sheets, cash flow). Enables stakeholder assessment of performance and solvency.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_015", "CONC_016"]}, {"name": "Balance Sheet", "category": "object", "appearsIn": ["SCENE_001", "SCENE_003", "CLUE_003", "CLUE_007", "CHAR_003"], "difficulty": 3, "description": "Snapshot of financial position on a specific date. Embodies Assets = Liabilities + Owners’ Equity. Shows owned resources, debts, and residual ownership interest.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_013", "CONC_012"]}, {"name": "Income Statement", "category": "object", "appearsIn": ["SCENE_003", "CLUE_008", "CHAR_003"], "difficulty": 3, "description": "Summary of operating results over time (monthly/quarterly/annual). Shows revenues, expenses, and profit measures (net income, comprehensive income) to evaluate profitability.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_014", "CONC_015"]}, {"name": "Supply Chain", "category": "process", "appearsIn": ["SCENE_003", "Q_006", "CHAR_003"], "difficulty": 3, "description": "All activities from raw material sourcing to finished product delivery: Supplier → Manufacturer → Wholesaler → Retailer → Customer. SCM optimizes flow, cost, and forecasting.", "knowledgeId": "CONC_017", "relatedKnowledge": ["CONC_018", "CONC_019"]}, {"name": "Materials Management", "category": "process", "appearsIn": ["SCENE_003", "CHAR_003"], "difficulty": 3, "description": "Ensures material/product availability while minimizing inventory. Involves production planning, delivery scheduling, and purchasing to reduce holding costs.", "knowledgeId": "CONC_018", "relatedKnowledge": ["CONC_017", "CONC_019"]}, {"name": "Logistics", "category": "process", "appearsIn": ["SCENE_003", "CHAR_003"], "difficulty": 3, "description": "Analysis/management of supply chain status—including demand forecasting, shipment tracking, and distribution optimization to ensure responsiveness.", "knowledgeId": "CONC_019", "relatedKnowledge": ["CONC_017", "CONC_018"]}, {"name": "Customer Relationship Management (CRM)", "category": "system", "appearsIn": ["SCENE_002", "CHAR_002", "CHAR_003"], "difficulty": 3, "description": "System managing all customer data to improve interaction quality and loyalty. Tools include contact managers, sales activity trackers, and automation integrations.", "knowledgeId": "CONC_020", "relatedKnowledge": ["CONC_021", "CONC_022"]}, {"name": "One-to-One Marketing", "category": "process", "appearsIn": ["SCENE_002", "CHAR_002"], "difficulty": 3, "description": "Personalized approach focusing on individual interactions to increase loyalty. Leverages CRM data to tailor communications and offers for enhanced perceived value.", "knowledgeId": "CONC_021", "relatedKnowledge": ["CONC_020", "CONC_022"]}, {"name": "Sales Force Automation", "category": "process", "appearsIn": ["SCENE_002", "CHAR_002"], "difficulty": 3, "description": "Technology automating sales tasks: tracking interactions/history, analyzing forecasts, and measuring performance. Integrated within CRM systems.", "knowledgeId": "CONC_022", "relatedKnowledge": ["CONC_020", "CONC_021"]}, {"name": "Call Center Automation", "category": "process", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "Tech improving efficiency by screening qualified leads from cold calls—automating workflows and prioritizing high-potential customers to boost conversion.", "knowledgeId": "CONC_023", "relatedKnowledge": ["CONC_020", "CONC_022"]}, {"name": "Software as a Service (SaaS)", "category": "architecture", "appearsIn": ["SCENE_002", "SCENE_003", "CHAR_002", "CHAR_003"], "difficulty": 3, "description": "Cloud-based software delivery model: hosted by provider (e.g., SAP), accessed via web browser. Offers lower cost/faster deployment—but raises security, bandwidth, and customization concerns.", "knowledgeId": "CONC_024", "relatedKnowledge": ["CONC_025", "CONC_026"]}, {"name": "Initial Affordability of SaaS", "category": "phenomenon", "appearsIn": ["SCENE_002", "CLUE_006", "CHAR_002"], "difficulty": 3, "description": "Lower upfront implementation cost of SaaS vs. on-premise software—making it attractive for SMEs needing scalable IT without large capital investment.", "knowledgeId": "CONC_025", "relatedKnowledge": ["CONC_024", "CONC_026"]}, {"name": "SaaS Limitations", "category": "phenomenon", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_006", "CLUE_009", "CHAR_002"], "difficulty": 3, "description": "Drawbacks include security vulnerabilities, bandwidth dependency, limited customization, generic features, and technical (vs. business) design orientation.", "knowledgeId": "CONC_026", "relatedKnowledge": ["CONC_024", "CONC_025"]}], "educational_goals": ["Define core business concepts: business, profit, and business purpose", "Explain how management functions (planning, organizing, directing, controlling) drive operations", "Distinguish accounting, financial reporting, and key statements (balance sheet, income statement)", "Identify marketing’s role, strategy components, and the 4Ps (marketing mix)", "Recognize CRM systems, supply chain functions, and SaaS trade-offs"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 2, "puzzle_sorting": 2}}', '603cecf6a65ee4f376e683bc7d5502f2af5cbb3261ad3de796e0eb97f5c71d3c', 'all concepts', '2026-03-26 06:05:32.350021', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('e436bb59-1ff1-4b84-8174-e43ac5088b7b', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'e45053b9-7fb4-4e3b-9c2d-a0399ed0afd5', NULL, 'The Case of the Vanishing Data: A Systems Sleuth Mystery', 'active', 'easy', 'beginner', '{"clues": [{"name": "Frozen EIS Dashboard", "type": "digital", "clueId": "CLUE_001", "foundBy": "On Elena''s open laptop", "reveals": "Elena was using EIS to investigate strategic risk—requiring drill-down capability (CONC_004, CONC_005).", "description": "Screen capture shows top-level KPIs (revenue, churn) with a highlighted ''DRILL DOWN'' button beside ''Q3 Acquisition Risk''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "MIS Weekly Report", "type": "documentary", "clueId": "CLUE_002", "foundBy": "On Elena''s desk beside laptop", "reveals": "MIS delivers summarized performance data to middle management—and enables drill-down for root-cause analysis (CONC_002, CONC_005).", "description": "Printed sales summary showing regional totals, office-level breakdowns, and product-line summaries. Handwritten note: ''Why does Midwest show +12% but Chicago -8%?''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_005"]}, {"name": "Live TPS Dashboard", "type": "digital", "clueId": "CLUE_003", "foundBy": "Displayed on Maya''s main monitor", "reveals": "TPS handles high-volume, structured operational tasks—feeding raw data to higher systems (CONC_001, CONC_011).", "description": "Real-time feed: ''Orders processed: 2,841 | Payroll entries: 1,092 | Shipments dispatched: 3,177''. All flagged ''SUCCESS''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_011"]}, {"name": "Inventory Alert Log", "type": "documentary", "clueId": "CLUE_004", "foundBy": "Tucked under Maya''s keyboard", "reveals": "TPS integrates with inventory systems—but can be overridden, violating business function protocols (CONC_001, CONC_008).", "description": "Printout showing 17 ''Low Stock'' alerts suppressed over 3 days. Header reads: ''TPS Auto-Reorder Disabled per Ops Directive''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "DSS Scenario Model", "type": "digital", "clueId": "CLUE_005", "foundBy": "On central display screen", "reveals": "DSS supports unstructured, strategic decisions via modeling—not routine reporting (CONC_003, CONC_009).", "description": "Interactive forecast titled ''Acquisition Risk v7'' with sliders for ''Market Volatility'', ''Regulatory Delay'', and ''Integration Cost''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_009"]}, {"name": "External Data Source Tag", "type": "digital", "clueId": "CLUE_006", "foundBy": "Mouse-over on DSS interface", "reveals": "DSS relies on both internal and external data—accuracy depends on freshness and verification (CONC_003, CONC_006).", "description": "Small icon on DSS model: ''Data: MarketSentinel API v3.1 (unverified)''. Hover reveals ''Last sync: 14 days ago''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_006"]}, {"name": "Misfiled Budget Report", "type": "documentary", "clueId": "CLUE_007", "foundBy": "In partially open cabinet drawer", "reveals": "MIS transforms TPS data into summaries—but discrepancies indicate need for data-to-information validation (CONC_002, CONC_007).", "description": "Q2 budget report with margin notes: ''MIS shows 92% payroll accuracy—but TPS logs show 37 failed deductions. Why?''.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Workflow Diagram", "type": "documentary", "clueId": "CLUE_008", "foundBy": "Taped inside cabinet door", "reveals": "Systems form a hierarchy aligned with organizational decision levels—operational → tactical → strategic (CONC_006, REL_009, REL_001).", "description": "Hand-drawn flowchart: ''TPS → MIS → DSS → EIS'' with arrows labeled ''feeds into'', ''transforms'', ''supports''.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_006"]}, {"name": "Admin Access Log", "type": "digital", "clueId": "CLUE_009", "foundBy": "Pulled from server audit trail", "reveals": "Drill-down capability can be restricted or enhanced—CTO used it to conceal data anomalies (CONC_005, CONC_004).", "description": "Server log entry: ''tanaka [EIS] — drill-down override active — 22:17:03''. Timestamp conflicts with CEO''s last activity (22:16:51).", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_005", "CONC_004"]}, {"name": "GDSS Session Archive", "type": "digital", "clueId": "CLUE_010", "foundBy": "Retrieved from GDSS server backup", "reveals": "GDSS enables collaborative interpretation of complex data—highlighting how unstructured decisions vary by perspective (CONC_010, CONC_009).", "description": "Saved group collaboration file: ''Acquisition Review''. Shows 4 users annotating same DSS chart—2 mark ''RISK HIGH'', 2 mark ''RISK LOW''.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_010", "CONC_009"]}, {"name": "Duplicate Shipment Receipt", "type": "physical", "clueId": "CLUE_011", "foundBy": "Jammed in TPS printer tray", "reveals": "Transactions are atomic events—duplicates indicate manual intervention or system failure (CONC_011, CONC_001).", "description": "Thermal receipt for Order #8842 showing identical line items, timestamps 2 seconds apart, and ''RECORD_OVERRIDE'' stamp.", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_011", "CONC_001"]}, {"name": "TPS Configuration File", "type": "digital", "clueId": "CLUE_012", "foundBy": "Found in shared network drive ''OPS_CONFIG''", "reveals": "Business function systems follow procedural rules—and human overrides create systemic risk (CONC_008, CONC_001).", "description": "Text file named ''tps_ops_config.txt'' containing: ''AUTO_REORDER = FALSE // Per M. Rodriguez directive''.", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_008", "CONC_001"]}, {"name": "Groupware Chat Log", "type": "digital", "clueId": "CLUE_013", "foundBy": "Recovered from GDSS groupware cache", "reveals": "Groupware enables communication for GDSS—but also hides dissent when leadership suppresses inquiry (CONC_012, CONC_010).", "description": "Encrypted chat snippet: ''[Tanaka]: Let''s present DSS consensus as unanimous. [Dubois]: I need drill-down proof first.''", "foundInScene": "SCENE_007", "relatedKnowledge": ["CONC_012", "CONC_010"]}, {"name": "Drill-Down Path Screenshot", "type": "digital", "clueId": "CLUE_014", "foundBy": "Hidden in GDSS session metadata", "reveals": "Drill-down connects strategic, tactical, and operational layers—exposing how one transaction impacts executive decisions (CONC_005, CONC_006).", "description": "PNG file named ''eis_path_final.png'': shows exact navigation from EIS summary → MIS detail → TPS transaction #8842.", "foundInScene": "SCENE_007", "relatedKnowledge": ["CONC_005", "CONC_006"]}], "title": "The Case of the Vanishing Data: A Systems Sleuth Mystery", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Empty Office", "sceneId": "SCENE_001", "location": "Veridian Corp CEO Suite — Indoor", "description": "Elena’s desk is immaculate—except for an open laptop displaying a frozen EIS dashboard and a printed regional sales summary labeled ''MIS Weekly Report''. No sign of struggle.", "charactersPresent": ["CHAR_001", "CHAR_004"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "Operations Under Pressure", "sceneId": "SCENE_002", "location": "Veridian Corp Operations Center — Indoor", "description": "Bank of humming terminals processes orders, payroll entries, and shipments. Maya reviews live TPS dashboards showing high-volume transaction throughput.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_005", "CLUE_006"], "order": 3, "title": "The Forecast Room", "sceneId": "SCENE_003", "location": "Veridian Corp Strategy Lab — Indoor", "description": "Wall-sized screen displays DSS scenario models: ''Acquisition Risk Analysis v7''. Dr. Tanaka nervously adjusts parameters while muttering about ''data noise''.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": ["CLUE_007", "CLUE_008"], "order": 1, "title": "The MIS Anomaly", "sceneId": "SCENE_004", "location": "Veridian Corp Reporting Hub — Indoor", "description": "A locked cabinet holds archived MIS reports. One drawer is slightly ajar—revealing a misfiled budget report with handwritten notes questioning data sources.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_009", "CLUE_010"], "order": 2, "title": "Backdoor Trace", "sceneId": "SCENE_005", "location": "Veridian Corp Server Vault — Indoor", "description": "Cool, silent rows of servers. Tanaka’s admin log shows late-night EIS access—but the timestamps mismatch the CEO’s last login.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": ["CLUE_011", "CLUE_012"], "order": 3, "title": "Transaction Trail", "sceneId": "SCENE_006", "location": "Veridian Corp Logistics Terminal — Indoor", "description": "TPS terminal prints continuous receipts. One batch—''Order #8842''—shows duplicate shipment entries and an unusual ''RECORD_OVERRIDE'' flag.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": ["CLUE_013", "CLUE_014"], "order": 1, "title": "GDSS Confession", "sceneId": "SCENE_007", "location": "Veridian Corp Collaboration Lounge — Indoor", "description": "A GDSS-enabled touchscreen displays a saved group session: ''Q3 Acquisition Review''. Annotations reveal conflicting interpretations of the same DSS output.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 3, "clues": [], "order": 2, "title": "The Final Drill-Down", "sceneId": "SCENE_008", "location": "Veridian Corp Executive Briefing Room — Indoor", "description": "Alex boots Elena’s laptop. The EIS dashboard reappears—frozen at a drill-down path: ''Regional Sales → District Office → Product Line → Transaction ID #8842''.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "truth", "title": "The Truth Revealed", "content": "Elena discovered that the DSS had ingested outdated market data—making the acquisition appear low-risk. She initiated a drill-down from EIS → MIS → TPS to verify transaction integrity, uncovering duplicate shipments (#8842) linked to Maya’s disabled auto-reorder. When Elena confronted Tanaka, he activated his EIS backdoor to hide the flaw—but the forensic path remained. Elena wasn’t harmed; she went underground to gather irrefutable evidence before going  The case exposes how layered systems interconnect: TPS captures truth (transactions), MIS summarizes it (performance), DSS models possibilities (risk), and EIS presents strategy (insight)—all anchored by drill-down and governed by decision-level needs.", "debrief": "You’ve learned: TPS handles operational transactions; MIS delivers tactical summaries; DSS supports strategic modeling; EIS serves executive insight; drill-down connects all layers; organizational levels define data needs; data becomes information through processing; business function systems require procedural integrity; structured vs unstructured decisions match system capabilities; GDSS and groupware enable collaborative sense-making.", "summary": "The CEO is safe—and the systems stack is now transparent, accountable, and aligned.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007", "CLUE_008", "CLUE_009", "CLUE_010", "CLUE_011", "CLUE_012", "CLUE_013", "CLUE_014"], "requiredScenes": ["SCENE_008"], "requiredQuestions": ["Q_007", "Q_008", "Q_009", "Q_010"]}}], "logline": "A CEO disappears after her EIS crashes—only her transaction logs remain.", "version": "1.0", "evidence": [{"name": "System Hierarchy Chart", "type": "Documentary", "clueIds": ["CLUE_008"], "evidenceId": "EVIDENCE_001", "description": "Laminated wall chart in Operations Center showing ''TPS → MIS → DSS → EIS'' with arrows labeled ''feeds into'', ''transforms'', ''supports''. Matches clue CLUE_008.", "foundLocation": "SCENE_004", "relatedKnowledge": ["CONC_006"]}, {"name": "Drill-Down Forensic Path", "type": "Digital", "clueIds": ["CLUE_014"], "evidenceId": "EVIDENCE_002", "description": "Reconstructed navigation log from Elena''s laptop: EIS Summary → MIS Regional Report → TPS Transaction #8842. Proves intent to trace anomaly to source.", "foundLocation": "SCENE_008", "relatedKnowledge": ["CONC_005", "CONC_001"]}], "has_quiz": true, "scriptId": "MIS_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "This system takes raw transaction data and turns it into summaries for performance monitoring.", "unlockAfterAttempts": 1}], "order": 1, "content": "What type of information system would produce the ''MIS Weekly Report'' found on Elena''s desk?", "options": [{"content": "Transaction Processing System (TPS)", "feedback": "TPS captures raw transaction data—it doesn’t produce summary reports.", "optionId": "OPT_001", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Management Information System (MIS)", "feedback": "Correct! MIS transforms TPS data into periodic summary reports like sales summaries and budget reports for middle management.", "optionId": "OPT_002", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "Executive Information System (EIS)", "feedback": "EIS provides highly summarized, strategic-level info for executives—not weekly operational summaries.", "optionId": "OPT_003", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About MIS", "knowledgeId": "CONC_002"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_001"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Think of this as a discrete, measurable business activity that changes state—like inventory or account balance.", "unlockAfterAttempts": 1}], "order": 1, "content": "Which concept best describes the ''Order #8842'' event captured by the TPS dashboard?", "options": [{"content": "Data", "feedback": "Data is raw facts—this is a specific event triggering data recording.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Transaction", "feedback": "Correct! A transaction is any event of interest—like an order—that triggers data recording and processing in a TPS.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "Information", "feedback": "Information is processed, meaningful output—not the raw event itself.", "optionId": "OPT_006", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Transactions", "knowledgeId": "CONC_011"}, "difficulty": 1, "questionId": "Q_002", "knowledgeId": "CONC_011", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_001"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "Acquisition decisions are complex, non-routine, and require modeling alternatives—not just reviewing past summaries.", "unlockAfterAttempts": 1}], "order": 1, "content": "Why would the CEO use a DSS instead of an MIS to evaluate the $200M acquisition?", "options": [{"content": "Because DSS produces faster reports than MIS", "feedback": "Speed isn’t the issue—DSS provides interactive modeling for unstructured decisions.", "optionId": "OPT_007", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Because acquisition decisions are unstructured and require scenario analysis", "feedback": "Correct! DSS supports semi-structured/unstructured decisions with tools for forecasting and comparing alternatives.", "optionId": "OPT_008", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": ["CLUE_007"]}, {"content": "Because DSS integrates with external data sources like market APIs", "feedback": "While true, this is a feature—not the core reason. The key is supporting unstructured decision-making.", "optionId": "OPT_009", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About DSS", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002", "CONC_009"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "Strategic decisions focus on long-term goals and external factors; operational decisions handle day-to-day tasks with internal data.", "unlockAfterAttempts": 1}], "order": 1, "content": "What distinguishes the information needs of the CEO (strategic level) from those of Operations (operational level)?", "options": [{"content": "CEO needs detailed, internal, quantitative data; Operations needs summarized, external data", "feedback": "Reversed! Operational decisions require detailed internal data; strategic decisions need summarized external/qualitative input.", "optionId": "OPT_010", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "CEO needs summarized, external, qualitative data; Operations needs detailed, internal, quantitative data", "feedback": "Correct! Organizational decision levels dictate distinct information requirements: strategic (CEO), tactical (middle), operational (Ops).", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_005", "unlockClues": ["CLUE_009"]}, {"content": "Both need identical data—the difference is only in report formatting", "feedback": "No—information needs differ fundamentally by level, scope, time frame, and source.", "optionId": "OPT_012", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Decision Levels", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_006", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "This is an interactive navigation feature that lets users explore data hierarchically—from summary to detail.", "unlockAfterAttempts": 1}], "order": 1, "content": "What capability allows Elena to move from the EIS summary dashboard to the specific transaction #8842?", "options": [{"content": "Data mining", "feedback": "Data mining discovers patterns in large datasets—not hierarchical navigation.", "optionId": "OPT_013", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_005", "unlockClues": []}, {"content": "Drill-down capability", "feedback": "Correct! Drill-down enables navigating from summary-level data (EIS) to increasingly detailed views (MIS → TPS).", "optionId": "OPT_014", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_006", "unlockClues": ["CLUE_011"]}, {"content": "System integration", "feedback": "Integration connects systems—but drill-down is the specific user-facing capability enabling this navigation.", "optionId": "OPT_015", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_005", "unlockClues": []}], "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More About Drill-Down", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "Business function systems follow defined procedures and policies—overrides violate governance rules.", "unlockAfterAttempts": 1}], "order": 1, "content": "How does the ''RECORD_OVERRIDE'' flag on the duplicate receipt relate to the concept of a Business Function System?", "options": [{"content": "It shows the system is functioning correctly by allowing flexibility", "feedback": "No—overrides bypass procedural rules, compromising system integrity and governance.", "optionId": "OPT_016", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_006", "unlockClues": []}, {"content": "It violates the policy-governed workflow of a business function system", "feedback": "Correct! Business function systems (like TPS) rely on defined workflows and policies—manual overrides break governance and create risk.", "optionId": "OPT_017", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_007", "unlockClues": ["CLUE_013"]}, {"content": "It proves the TPS is outdated and needs replacement", "feedback": "Not necessarily—the issue is procedural compliance, not technology age.", "optionId": "OPT_018", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_006", "unlockClues": []}], "sceneId": "SCENE_006", "learnMore": {"buttonText": "Learn More About Business Function Systems", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_006", "knowledgeId": "CONC_008", "maxAttempts": 3, "masteryReward": 3, "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_007", "content": "Start with where data originates (transactions), then trace upward through reporting, analysis, and executive dashboards.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Transaction Processing System (TPS)"}, {"itemId": "ITEM_002", "content": "Management Information System (MIS)"}, {"itemId": "ITEM_003", "content": "Executive Information System (EIS)"}, {"itemId": "ITEM_004", "content": "Decision Support System (DSS)"}], "order": 1, "content": "Arrange these systems in the correct order of data flow—from raw capture to strategic insight.", "sceneId": "SCENE_007", "learnMore": {"buttonText": "Learn More About System Hierarchy", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_007", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_004", "ITEM_003"], "feedbackCorrect": "Correct! Data flows: TPS (captures raw transactions) → MIS (summarizes for tactical use) → DSS (models for strategic options) → EIS (presents insights to executives).", "feedbackIncorrect": "Remember: TPS feeds MIS, which informs DSS and EIS. EIS sits at the top for strategic consumption.", "nextSceneIdCorrect": "SCENE_008", "nextSceneIdIncorrect": "SCENE_007"}, {"type": "sequencing", "hints": [{"hintId": "HINT_008", "content": "Ask: Which item is a single, unprocessed fact? Which requires judgment and external context?", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_005", "content": "Customer order number ''8842''"}, {"itemId": "ITEM_006", "content": "Midwest regional sales increased 12%"}, {"itemId": "ITEM_007", "content": "Q3 acquisition carries high regulatory risk"}, {"itemId": "ITEM_008", "content": "2,841 orders processed today"}], "order": 2, "content": "Place these concepts in order of increasing abstraction—from raw input to actionable insight.", "sceneId": "SCENE_007", "learnMore": {"buttonText": "Learn More About Data vs Information", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_008", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctOrder": ["ITEM_005", "ITEM_008", "ITEM_006", "ITEM_007"], "feedbackCorrect": "Correct! Data starts as atomic facts (order #8842), becomes aggregated counts (2,841 orders), then interpreted summaries (Midwest +12%), finally strategic conclusions (high acquisition risk).", "feedbackIncorrect": "Atomic data comes first; strategic conclusions require interpretation and context—so they''re most abstract.", "nextSceneIdCorrect": "SCENE_008", "nextSceneIdIncorrect": "SCENE_007"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_009", "content": "It''s the top layer of the IS hierarchy—designed for CEOs and board members.", "unlockAfterAttempts": 1}], "order": 1, "content": "The system designed specifically for senior executives to access highly summarized, user-friendly information—and optionally explore details—is called an ________.", "sceneId": "SCENE_008", "learnMore": {"buttonText": "Learn More About EIS", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_009", "knowledgeId": "CONC_004", "maxAttempts": 2, "correctAnswers": ["Executive Information System", "EIS", "executive information system", "eis"], "feedbackCorrect": "Correct! An Executive Information System (EIS) delivers tailored, summarized insights to executives—and includes drill-down capability for deeper investigation.", "feedbackIncorrect": "Hint: Its acronym starts with ''E'' and ends with ''S''. It''s built for strategic decision-makers.", "nextSceneIdCorrect": "SCENE_008", "nextSceneIdIncorrect": "SCENE_008"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_010", "content": "Its name reflects collective work—starts with ''Group'' and ends with ''ware''.", "unlockAfterAttempts": 1}], "order": 2, "content": "Software that enables electronic brainstorming, document sharing, and scheduling for collaborative decision-making is known as ________.", "sceneId": "SCENE_008", "learnMore": {"buttonText": "Learn More About Groupware", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_010", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctAnswers": ["Groupware", "groupware"], "feedbackCorrect": "Correct! Groupware provides the collaborative infrastructure for Group DSS—supporting communication and consensus-building among distributed teams.", "feedbackIncorrect": "Hint: It''s the technology layer behind GDSS—think ''collaborative software'' or ''shared workspace tools''.", "nextSceneIdCorrect": "SCENE_008", "nextSceneIdIncorrect": "SCENE_008"}], "characters": [{"age": 32, "goal": "Reconstruct the sequence of system interactions that preceded the CEO''s disappearance.", "name": "Alex Chen", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004", "SCENE_005", "SCENE_006", "SCENE_007", "SCENE_008"], "secret": "Once misconfigured a TPS during an internship—causing payroll errors. Now obsessively verifies data integrity.", "background": "Hired by Veridian Corp to investigate the unexplained disappearance of their CEO after a critical system failure. Alex specializes in tracing digital footprints across enterprise systems.", "occupation": "Digital Forensics Consultant", "characterId": "CHAR_001", "personality": "Analytical, patient, quietly empathetic; notices inconsistencies others miss.", "knowledgePoints": ["CONC_007"]}, {"age": 41, "goal": "Protect her team from blame—and prevent discovery of the inventory gap she concealed.", "name": "Maya Rodriguez", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_004", "SCENE_006", "SCENE_008"], "secret": "Disabled TPS auto-reorder alerts to hide chronic stock shortages—violating policy (CONC_008).", "background": "Oversees all daily transactions at Veridian Corp—including order processing, payroll, and inventory. Has full access to the TPS and reports directly to the missing CEO.", "occupation": "Head of Operations", "characterId": "CHAR_002", "personality": "Efficient, no-nonsense, slightly defensive about operational metrics.", "knowledgePoints": ["CONC_001", "CONC_011", "CONC_008"]}, {"age": 53, "goal": "Preserve his reputation and avoid regulatory scrutiny over the compromised EIS.", "name": "Dr. Kenji Tanaka", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003", "SCENE_005", "SCENE_007", "SCENE_008"], "secret": "Built backdoor access into the EIS to override drill-down restrictions—used it to hide a flawed DSS forecast (CONC_004, CONC_005).", "background": "Architect of Veridian’s layered IS stack: TPS → MIS → DSS → EIS. Designed the drill-down feature used by the CEO.", "occupation": "Chief Technology Officer", "characterId": "CHAR_003", "personality": "Brilliant but arrogant; believes systems should ''speak for themselves'' without human interpretation.", "knowledgePoints": ["CONC_004", "CONC_005", "CONC_003"]}, {"age": 58, "goal": "Confront the CTO and COO with evidence before finalizing the acquisition.", "name": "Elena Dubois", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Discovered that the DSS had been feeding inaccurate external market data into the EIS—jeopardizing a $200M acquisition (CONC_009, CONC_006).", "background": "Visionary leader who insisted on real-time, drill-down enabled EIS access to monitor strategic KPIs. Was reviewing Q3 forecasts when she vanished.", "occupation": "CEO & Founder", "characterId": "CHAR_004", "personality": "Decisive, data-driven, trusted intuition only when backed by layered evidence.", "knowledgePoints": ["CONC_006", "CONC_009", "CONC_004"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Transaction Processing System (TPS)", "category": "system", "appearsIn": ["SCENE_002", "CLUE_003", "CHAR_002"], "difficulty": 3, "description": "A Transaction Processing System (TPS) is an information system that captures and processes data from business transactions. It supports the most basic operational activities of an organization by recording, storing, and managing transactional data such as order processing, payroll, shipments, and receipts. TPS handles high volumes of structured, predefined tasks and provides accurate, detailed internal data primarily used by lower-level management for day-to-day operations.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_006", "CONC_009"]}, {"name": "Management Information System (MIS)", "category": "system", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_002"], "difficulty": 3, "description": "A Management Information System (MIS) transforms raw data from Transaction Processing Systems into summarized reports for monitoring performance and supporting middle management in structured decision-making. It analyzes large volumes of input data and produces periodic output such as sales summaries or budget reports. MIS enhances organizational efficiency and effectiveness by providing timely, relevant information.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"]}, {"name": "Decision Support System (DSS)", "category": "system", "appearsIn": ["SCENE_003", "CLUE_005", "CHAR_003"], "difficulty": 4, "description": "A Decision Support System (DSS) assists middle and top-level managers in making semi-structured or unstructured decisions by analyzing and modeling complex data sets. Unlike MIS, which focuses on routine reporting, DSS provides interactive tools for scenario analysis, forecasting, and comparison of alternative solutions. It supports strategic planning and problem-solving in areas such as financial planning and loan management.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_002", "CONC_005", "CONC_012"]}, {"name": "Executive Information System (EIS)", "category": "system", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_003"], "difficulty": 4, "description": "An Executive Information System (EIS) is designed for senior executives at the strategic level of an organization. It delivers highly summarized, external and internal information tailored to individual executive needs. EIS emphasizes user-friendliness and enables CEOs to access data across all organizational levels. While typically focused on high-level overviews, it also allows drilling down into details when necessary.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_006"]}, {"name": "Drill-down Capability", "category": "process", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_003"], "difficulty": 3, "description": "Drill-down capability refers to the functionality in information systems that allows users to navigate from summary-level data to increasingly detailed views. This process helps managers investigate underlying causes of performance issues by exploring data hierarchically—such as moving from regional sales totals to office-level results, then to product-line specifics.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Organizational Decision Levels", "category": "theory", "appearsIn": ["SCENE_004", "CLUE_008", "CHAR_004"], "difficulty": 3, "description": "Organizational decision levels refer to the hierarchical structure of decision-making within a company: strategic (senior management), tactical (middle management), and operational (lower-level management). Each level has distinct information requirements: strategic decisions require external, qualitative, and summarized data; tactical decisions use both internal and external data in summarized form; operational decisions rely on internal, quantitative, and detailed data.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"name": "Data vs Information", "category": "phenomenon", "appearsIn": ["SCENE_004", "CLUE_007", "CHAR_001"], "difficulty": 2, "description": "Data refers to raw, unprocessed facts and figures collected during business operations, serving as the foundational input for information systems. Information is derived from processed, organized, and interpreted data, making it meaningful and useful for decision-making. The transformation from data to information occurs through systems like TPS and MIS, where context and structure are added.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Business Function System", "category": "architecture", "appearsIn": ["SCENE_006", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "A business function system is a group of related procedures designed to support a specific business operation, such as payroll or inventory management. These systems follow defined policies and workflows to transform inputs into meaningful outputs. They involve coordination among users, managers, and IS staff, governed by procedural rules.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Structured vs Unstructured Decisions", "category": "theory", "appearsIn": ["SCENE_003", "CLUE_005", "CHAR_004"], "difficulty": 4, "description": "Structured decisions are routine, well-defined, and based on predictable processes, typically made at the operational level using internal, quantitative data. Unstructured decisions are complex, non-routine, and require judgment, intuition, and external data, usually occurring at strategic levels. Information systems are tailored accordingly: TPS supports structured decisions, while DSS aids in semi-structured or unstructured ones.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_006"]}, {"name": "Group Decision Support System (GDSS)", "category": "system", "appearsIn": ["SCENE_007", "CLUE_010", "CHAR_003"], "difficulty": 4, "description": "A Group Decision Support System (GDSS) enhances collaborative decision-making by integrating communication tools and analytical models. It enables multiple decision-makers to work together interactively using computer-based platforms. GDSS supports group productivity through features like electronic brainstorming, document sharing, scheduling, and real-time modeling.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Transaction", "category": "object", "appearsIn": ["SCENE_002", "CLUE_003", "CHAR_002"], "difficulty": 2, "description": "In the context of information systems, a transaction is any event of interest to the organization that triggers data recording and processing. Examples include customer orders, payments, shipments, and employee time entries. Transactions are discrete, measurable, and typically involve a change in state, such as inventory levels or account balances.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Groupware", "category": "component", "appearsIn": ["SCENE_007", "CLUE_013", "CHAR_003"], "difficulty": 3, "description": "Groupware refers to software applications that facilitate electronic collaboration among groups, including communication, scheduling, document sharing, and task management. It supports Group DSS by enabling seamless interaction between geographically dispersed team members. Features like shared calendars, real-time editing, and discussion forums enhance group productivity and decision quality.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_010"]}], "educational_goals": ["Distinguish between TPS, MIS, DSS, EIS, and GDSS by function and user level", "Explain how organizational decision levels shape information system design", "Describe the data-to-information transformation and drill-down capability"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 2, "puzzle_sorting": 2}}', 'ed05817ba2df6844649bf42f5396880d1a4b172562c18462ad242585e5eb0d34', 'all concepts', '2026-03-26 06:40:23.148525', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('740c6fbf-d371-48f2-9043-e38665175674', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '6ffb50c0-ee85-4665-919a-2f5cefc64a9c', NULL, 'The Live Wire Incident: A Hong Kong Flat Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "Smoking Three-Pin Plug", "type": "physical", "clueId": "CLUE_001", "foundBy": "On floor beside victim’s right hand", "reveals": "Earth wire was disconnected — eliminating fault protection. Live-to-case contact would cause lethal shock instead of breaker trip.", "description": "Charred BS 1363 plug with brown (live), blue (neutral), and severed green-and-yellow (earth) wires. Earth wire ends are bare and unconnected.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_014", "CONC_007"]}, {"name": "Scorched Socket Faceplate", "type": "physical", "clueId": "CLUE_002", "foundBy": "Pried off wall with screwdriver", "reveals": "Excessive current flowed — consistent with overloading or short circuit, not normal operation.", "description": "Wall socket with melted plastic around live and neutral holes. No discoloration near earth hole.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_015"]}, {"name": "Incomplete Audit Report", "type": "digital", "clueId": "CLUE_003", "foundBy": "Unlocked tablet on desk", "reveals": "Victim identified hazards moments before death — proving danger was known and preventable.", "description": "Tablet file: ''Flat 12B – Critical Safety Failures.docx'' — bullet points include ''No earth continuity at study socket'', ''Overloaded multi-plug (measured 28 A > 13 A rating)'', ''Series extension violates HK Code Clause 5.3''. Last edit timestamp: 2 min before incident.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_011", "CONC_012", "CONC_013", "CONC_005"]}, {"name": "Handwritten Fuse Box Diagram", "type": "documentary", "clueId": "CLUE_004", "foundBy": "Taped inside fuse box door", "reveals": "Illegal fuse substitution increased fire risk and disabled overcurrent protection.", "description": "Laminated sketch showing ''Live → 20A Fuse → Socket'' — but HK standard requires 13A for ring mains. Notes say ''Foil wrap stops blowing''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_005", "CONC_008"]}, {"name": "Maintenance Ledger Entry", "type": "documentary", "clueId": "CLUE_005", "foundBy": "Inside ''Maintenance'' filing cabinet", "reveals": "Misrepresentation of work done — no actual socket upgrade occurred.", "description": "Handwritten line: ''2024-05-12: Socket upgrade @ Study — $380''. Invoice attached shows only ''Fuse replacement x2 — $45''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_014"]}, {"name": "Loose Wire Coil", "type": "physical", "clueId": "CLUE_006", "foundBy": "Under landlord’s desk", "reveals": "Improper ''earth bonding'' — created a false return path, raising neutral potential and increasing shock risk.", "description": "1.5mm² twin-and-earth cable, cut mid-run. Green-and-yellow sheath stripped 10 cm back — exposing bare copper twisted around blue neutral wire.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_006"]}, {"name": "Smart Kilowatt-Hour Meter Display", "type": "digital", "clueId": "CLUE_007", "foundBy": "Mounted beside fuse box in utility cupboard", "reveals": "Current exceeded socket rating (13 A) and fuse rating (20 A) — confirming overload *and* short circuit during failure.", "description": "Meter screen shows: ''Peak Load: 28.4 A | Voltage: 220 V | Energy Today: 12.7 kWh''. Graph shows sharp 0.5-sec spike to 42 A before blackout.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013", "CONC_010", "CONC_005", "CONC_006"]}, {"name": "Exposed Wiring Bundle", "type": "physical", "clueId": "CLUE_008", "foundBy": "Behind utility cupboard panel", "reveals": "Thermal stress from overloading degraded insulation — enabling short circuit.", "description": "Five cables tightly bound together — violating HK Code requirement for separation to prevent heat buildup. Two show insulation cracks.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_015"]}, {"name": "Labelled ''Live Extension''", "type": "physical", "clueId": "CLUE_009", "foundBy": "On cable entering study socket", "reveals": "Landlord knowingly installed ungrounded extension — bypassing safety earth entirely.", "description": "Handwritten tag tied to cable: ''Live Extension – Not Earthed''. Tied to same cable as CLUE_006.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_002", "CONC_004", "CONC_014"]}], "title": "The Live Wire Incident: A Hong Kong Flat Mystery", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002", "CLUE_003"], "order": 1, "title": "The Shocked Study", "sceneId": "SCENE_001", "location": "Cluttered study in a 1970s Mid-Levels flat — desk strewn with appliance manuals, a smoking three-pin plug, and a cracked smart meter display", "description": "Detective Mei Lin arrives at the scene: Ms. Lee is slumped beside her open laptop. A kettle, hairdryer, and space heater are plugged into one socket. The wall socket shows scorch marks. Her tablet displays an incomplete audit report titled ''Flat 12B – Critical Safety Failures''.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_004", "CLUE_005", "CLUE_006"], "order": 2, "title": "The Landlord''s Ledger", "sceneId": "SCENE_002", "location": "Mr. Chan’s cramped office — filing cabinet labeled ''Maintenance'', a laminated HK wiring code poster (with handwritten notes), and a fuse box diagram taped to the wall", "description": "Mr. Chan produces receipts for recent ''repairs'' — but his fuse box diagram contradicts HK standard color coding. A loose wire coil lies under his desk. His ledger lists ''socket upgrade'' — yet the invoice shows only ''fuse replacement''.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_007", "CLUE_008", "CLUE_009"], "order": 1, "title": "The Meter Reads Truth", "sceneId": "SCENE_003", "location": "Flat’s utility cupboard — exposed wiring, old ceramic fuse box, and Ms. Lee’s newly installed smart kilowatt-hour meter glowing faintly", "description": "The meter shows abnormal current spikes. Wires leading to the study socket are bundled tightly — not separated as required. One cable’s green-and-yellow sheath is cut short; the bare copper is twisted around a neutral wire. A label reads ''Live Extension – Not Earthed''.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": [], "order": 1, "title": "The Final Circuit", "sceneId": "SCENE_004", "location": "Same study — now cleared except for a whiteboard showing circuit diagrams, the three-pin plug, and Ms. Lee’s tablet open to her final report", "description": "Mei Lin reconstructs the sequence using evidence. Mr. Chan admits modifying the circuit — but claims he ''followed the old rules''. Mei Lin must prove his actions violated core safety principles — and that Ms. Lee’s death was preventable.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Circuit of Accountability", "content": "Mei Lin presents irrefutable evidence: Mr. Chan’s illegal 20 A fuse failed to interrupt the 28 A overload, allowing sustained heating that cracked insulation. This caused a live-to-neutral short, sending massive current through the unearthed kettle casing. With no earth path, the current chose Ms. Lee’s body — 220 V across her chest delivering ~100 mA, inducing cardiac arrest. His ''socket upgrade'' was fiction; his ''foil fix'' was fatal negligence. The court mandates HK-wide inspection of pre-1990 estates and revokes his license.", "debrief": "You''ve mastered: Mains voltage (220 V) as the system baseline; live/neutral/earth wire roles and color codes; how overloading and short circuits differ yet interact; why earth continuity is non-negotiable; fuse vs. breaker protection logic; power calculations (P=VI); efficiency metrics; and why parallel — not series — wiring defines safe homes.", "summary": "Justice is served not with drama, but with volts, amps, and adherence to code.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_003", "CLUE_007"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_008", "Q_009", "Q_010", "Q_011"]}}], "logline": "A fatal shock in a high-rise flat reveals dangerous wiring flaws.", "version": "1.0", "evidence": [{"name": "HK Electrical Code Violation Report", "type": "Documentary", "clueIds": ["CLUE_003"], "evidenceId": "EVIDENCE_001", "description": "Official PDF from HK EDU listing 12 violations found in Flat 12B — including ''Missing earth continuity at study socket (Clause 4.2.1)'', ''Overloaded socket exceeding 13 A limit (Clause 5.1.3)'', and ''Illegal series extension (Clause 5.3.2)''. Signed by Ms. Lee.", "foundLocation": "Victim’s encrypted cloud folder (accessed via tablet)", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_015"]}, {"name": "Laboratory Test Results: Foil-Wrapped Fuse", "type": "Documentary", "clueIds": ["CLUE_004"], "evidenceId": "EVIDENCE_002", "description": "Independent lab report showing 20 A fuse with aluminum foil wrap required 32 A to blow — 2.5× its rated capacity. Concludes ''Gross violation of safety standards — fire hazard confirmed.''", "foundLocation": "Sent to Detective Mei Lin’s secure email (triggered after Q_003 answered correctly)", "relatedKnowledge": ["CONC_009", "CONC_005"]}], "has_quiz": true, "scriptId": "EMM_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "Which wire exists solely to carry fault current safely to ground and trigger the breaker?", "unlockAfterAttempts": 1}], "order": 1, "content": "The victim was found beside a smoking three-pin plug. Which wire’s disconnection most directly explains why she received a fatal shock instead of triggering automatic protection?", "options": [{"content": "The brown live wire", "feedback": "The live wire delivers power — disconnecting it would stop the circuit, not cause shock.", "optionId": "OPT_001", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The blue neutral wire", "feedback": "While dangerous if energized, neutral disconnection alone wouldn’t prevent breaker tripping during live-to-case contact.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The green-and-yellow earth wire", "feedback": "Yes — without earth, fault current had no safe path. The live wire contacted the metal kettle casing, and current flowed through Ms. Lee to ground instead of tripping the breaker.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Earth Wire Safety", "knowledgeId": "CONC_004"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_004", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_002", "content": "It''s the same number used in the victim’s meter reading and fuse calculations.", "unlockAfterAttempts": 1}], "order": 2, "content": "Hong Kong’s standard mains voltage is ____ V AC.", "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Mains Voltage", "knowledgeId": "CONC_001"}, "difficulty": 1, "questionId": "Q_002", "knowledgeId": "CONC_001", "maxAttempts": 2, "correctAnswers": ["220", "two twenty", "two-hundred twenty"], "feedbackCorrect": "Correct — 220 V AC is the regulated supply voltage across live and neutral in HK homes. This value is critical for appliance design and fuse sizing.", "feedbackIncorrect": "Recall the opening line of your textbook: ''In Hong Kong, mains voltage is ___ V.''", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": "SCENE_001"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "Fuses protect cables — not appliances. What must match the cable’s current-carrying capacity?", "unlockAfterAttempts": 1}], "order": 1, "content": "Mr. Chan’s ledger says ''Socket upgrade'' but the invoice shows only ''fuse replacement''. Based on HK wiring standards, what is the *minimum* required action when upgrading a socket in a 13 A ring main?", "options": [{"content": "Replace the socket only — no fuse change needed", "feedback": "False — socket rating must match circuit protection. A 13 A socket requires a 13 A fuse.", "optionId": "OPT_004", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Replace the fuse with one rated for the *appliance’s* power, not the cable", "feedback": "Dangerous misconception — fuses protect *wiring*. Using a higher-rated fuse risks fire.", "optionId": "OPT_005", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Install a correctly rated 13 A fuse and verify earth continuity", "feedback": "Exactly — HK standards require fuse rating to match cable capacity (13 A for 2.5 mm²), and earth integrity must be tested.", "optionId": "OPT_006", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_007"]}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Fuse Ratings", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_009", "maxAttempts": 2, "masteryReward": 2, "relatedKnowledge": ["CONC_014", "CONC_015"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_004", "content": "Start with the human action — then follow the physics chain: heat → damage → fault → failed protection → shock.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Ms. Lee plugs in kettle, hairdryer, and space heater into one multi-socket."}, {"itemId": "ITEM_002", "content": "Overloaded circuit heats insulation, causing it to crack."}, {"itemId": "ITEM_003", "content": "Live conductor contacts neutral due to cracked insulation — creating a short circuit."}, {"itemId": "ITEM_004", "content": "20 A fuse fails to blow; excessive current flows through earthless kettle casing."}, {"itemId": "ITEM_005", "content": "Ms. Lee touches casing while standing on floor — current flows through her body to earth."}], "order": 2, "content": "Order these events to reconstruct how the fatal shock occurred:", "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Overloading", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_005", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004", "ITEM_005"], "feedbackCorrect": "Correct sequence. Overloading caused insulation failure, leading to short circuit. With no earth, fault current passed through Ms. Lee — not the fuse.", "feedbackIncorrect": "Remember: Overload comes first (too many devices), then thermal damage, then short, then failed protection, then shock.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": "SCENE_002"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_005", "content": "The opposite configuration — where one device failing breaks the whole circuit — is called ______.", "unlockAfterAttempts": 1}], "order": 1, "content": "In a household circuit, sockets are wired in ____ so each receives full 220 V and operates independently.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Parallel Circuits", "knowledgeId": "CONC_015"}, "difficulty": 2, "questionId": "Q_005", "knowledgeId": "CONC_015", "maxAttempts": 2, "correctAnswers": ["parallel", "parallel circuit", "shunt"], "feedbackCorrect": "Correct — parallel connection ensures constant voltage, independent operation, and additive current draw. This is why overloading one socket doesn’t affect others — but makes that socket’s fuse critical.", "feedbackIncorrect": "Think about why turning off your lamp doesn’t switch off your TV.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "Multiply volts × amps. Round to nearest kilowatt.", "unlockAfterAttempts": 1}], "order": 2, "content": "The smart meter recorded 28.4 A peak load. Given HK’s 220 V supply, what was the approximate *total power* drawn by the three appliances? (Use P = VI)", "options": [{"content": "≈ 6.2 kW", "feedback": "Yes — 220 V × 28.4 A = 6,248 W ≈ 6.2 kW. Far above a 13 A socket’s 2.86 kW capacity (220 × 13).", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "≈ 12.8 kW", "feedback": "That would require ~58 A — far beyond the meter’s 42 A spike.", "optionId": "OPT_008", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Electrical Power", "knowledgeId": "CONC_010"}, "difficulty": 2, "questionId": "Q_006", "knowledgeId": "CONC_010", "maxAttempts": 2, "masteryReward": 2, "relatedKnowledge": ["CONC_011"]}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_007", "content": "Recall Ohm’s Law: I = V/R. For a given voltage, what resistance gives high current?", "unlockAfterAttempts": 1}], "order": 3, "content": "The victim’s audit noted ''No earth continuity''. This means the resistance between the earth pin and the main grounding rod was too ____ to safely carry fault current.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Earth Continuity Testing", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_007", "knowledgeId": "CONC_004", "maxAttempts": 2, "correctAnswers": ["high", "large", "excessive"], "feedbackCorrect": "Correct — high earth resistance prevents sufficient fault current from flowing to trip the breaker quickly. Safe earth resistance in HK is <1 Ω.", "feedbackIncorrect": "Low resistance allows current to flow easily — which is what we need for safety!", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "sequencing", "hints": [{"hintId": "HINT_008", "content": "Ask: Which layer could have stopped the incident *before* the plug smoked? Which layer only acts *after* failure begins?", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_006", "content": "Proper earth continuity providing low-resistance fault path"}, {"itemId": "ITEM_007", "content": "Correctly rated 13 A fuse interrupting overload current"}, {"itemId": "ITEM_008", "content": "Parallel circuit design preventing single-point failure"}, {"itemId": "ITEM_009", "content": "User awareness of power ratings and socket limits"}, {"itemId": "ITEM_010", "content": "Circuit breaker tripping on short-circuit current surge"}], "order": 1, "content": "Arrange these safety features in order of *how they should have prevented this tragedy*, from first line of defense to last:", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Circuit Protection Layers", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_008", "knowledgeId": "CONC_008", "maxAttempts": 2, "correctOrder": ["ITEM_009", "ITEM_008", "ITEM_007", "ITEM_006", "ITEM_010"], "feedbackCorrect": "Correct — Human behavior (awareness) is the first defense. Parallel design contains the problem. Correct fuse stops overload. Earth enables safe fault clearing. Breaker is final backup for extreme faults.", "feedbackIncorrect": "Remember: Prevention hierarchy starts with user action, then passive design, then active protection.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_009", "content": "The numbers 15 and 20 appear in CHUNK_006 — check the bulb efficiency calculation.", "unlockAfterAttempts": 1}], "order": 2, "content": "Ms. Lee’s audit measured 12.7 kWh energy use today. If her efficient LED lamp used 15 W useful output from 20 W input, its efficiency was ____%.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Energy Efficiency", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctAnswers": ["75", "seventy five"], "feedbackCorrect": "Correct — Efficiency = (useful output / input) × 100% = (15/20) × 100% = 75%. Her report used such calculations to rank appliance efficiency.", "feedbackIncorrect": "Apply the formula: (useful power ÷ total power) × 100%.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_010", "content": "What time unit completes ''kiloWATT-___''?", "unlockAfterAttempts": 1}], "order": 3, "content": "The victim’s smart meter measures energy in kilowatt-____ (kW·h).", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Kilowatt-Hour Meters", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_010", "knowledgeId": "CONC_013", "maxAttempts": 2, "correctAnswers": ["hours", "hour", "hrs"], "feedbackCorrect": "Correct — kilowatt-hour is the standard billing unit: energy = power × time. 1 kW·h = energy used by a 1 kW device running for 1 hour.", "feedbackIncorrect": "It’s a compound unit — think of electricity bills you’ve seen.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_011", "content": "What happens to the entire circuit if one bulb blows in a string of old Christmas lights?", "unlockAfterAttempts": 1}], "order": 4, "content": "Why is a series circuit *not* used for household sockets?", "options": [{"content": "It reduces total power consumption", "feedback": "False — series increases total resistance, reducing current and power.", "optionId": "OPT_009", "showHint": "HINT_011", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "All appliances would share the 220 V supply, causing dim lights and slow motors", "feedback": "Yes — in series, voltage divides across devices. A kettle would get only ~50 V, failing to boil water. Parallel ensures full 220 V to each.", "optionId": "OPT_010", "showHint": "", "isCorrect": true, "nextSceneId": "ENDING_001", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Series vs Parallel", "knowledgeId": "CONC_016"}, "difficulty": 3, "questionId": "Q_011", "knowledgeId": "CONC_016", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_015"]}], "characters": [{"age": 34, "goal": "Solve the case without exposing her past oversight — but only if justice and safety come first.", "name": "Detective Mei Lin", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "She once approved a building’s wiring certificate despite noticing a missing earth wire — she covered it up to avoid delaying her first major promotion.", "background": "Former apprentice electrician who switched to enforcement after her brother suffered a non-fatal shock from faulty earthing. Knows HK domestic wiring standards inside out.", "occupation": "Electrical Safety Inspector (seconded to HK Police)", "characterId": "CHAR_001", "personality": "Methodical, empathetic, technically precise, quietly intense", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_014", "CONC_015"]}, {"age": 58, "goal": "Convince investigators the victim caused the accident by misusing appliances — and avoid prosecution or license revocation.", "name": "Mr. Chan Wai-Keung", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "He replaced a tripped 13 A fuse with a 20 A one — then wrapped it in foil — to stop tenants complaining about frequent blackouts.", "background": "Owns the aging Mid-Levels flat where the incident occurred. Known for cutting corners on maintenance to maximize rental yield. Installed unlicensed ‘quick-fix’ extensions himself.", "occupation": "Retired licensed electrician & landlord", "characterId": "CHAR_002", "personality": "Charming but evasive, speaks in technical jargon to intimidate, dismisses modern safety standards as ‘over-engineering’.", "knowledgePoints": ["CONC_009", "CONC_005", "CONC_006", "CONC_008"]}, {"age": 27, "goal": "Publish findings to trigger mandatory HK-wide rewiring grants — before her report was due Friday.", "name": "Ms. Soo-Yin Lee", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Her audit report — found in her tablet — identified *three* critical violations in this flat: no earth continuity, overloaded socket, and illegal series extension — all flagged for urgent remediation.", "background": "Was auditing residential energy efficiency for a new government rebate scheme. Had just installed a smart kilowatt-hour meter in the flat before her death.", "occupation": "Sustainability Officer at HK Electric", "characterId": "CHAR_003", "personality": "Detail-oriented, passionate about green tech, recently raised concerns about outdated wiring in older estates.", "knowledgePoints": ["CONC_010", "CONC_011", "CONC_012", "CONC_013", "CONC_005", "CONC_015"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Mains voltage", "category": "basics", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 2, "description": "The standard electrical potential difference supplied to residential buildings. In Hong Kong, it is 220 V alternating current (AC), providing the baseline energy source for all household appliances. This voltage is maintained across the live and neutral wires and must be strictly regulated to ensure safe and consistent operation of devices rated for this supply.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Live wire", "category": "components", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 2, "description": "A current-carrying conductor in a mains circuit that maintains a high potential (220 V relative to earth) and delivers electrical energy from the supply. It is typically color-coded brown in three-pin plug systems and must always be fused on the live side for safety. Contact with the live wire while grounded poses severe risk of electric shock.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_007"]}, {"name": "Neutral wire", "category": "components", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 2, "description": "A return path conductor in a mains circuit that completes the electrical loop by carrying current back to the supply transformer. It is maintained near earth potential (0 V) under normal conditions and is color-coded blue. While less hazardous than the live wire, it can become energized during faults and must never be assumed safe without verification.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_007"]}, {"name": "Earth wire", "category": "components", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 3, "description": "A safety conductor that connects the metal casing of an appliance directly to the ground (earth). Its purpose is to provide a low-resistance path for fault current to flow safely away if the live wire contacts the casing, thereby preventing electric shock by triggering the circuit breaker or fuse. It is color-coded green-and-yellow and is not intended to carry current under normal operation.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_007", "CONC_008"]}, {"name": "Overloading", "category": "phenomena", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_002"], "difficulty": 3, "description": "A hazardous condition that occurs when too many appliances draw excessive current through a single circuit or socket, exceeding its designed capacity. This causes overheating of wires, insulation damage, and fire risk. It is prevented by using appropriately rated fuses or circuit breakers and distributing loads across multiple circuits.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_008", "CONC_012"]}, {"name": "Short circuit", "category": "phenomena", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_002"], "difficulty": 3, "description": "An abnormal low-resistance connection between two points of different potential in a circuit—typically between live and neutral or live and earth. It bypasses the normal load, causing dangerously high current flow, rapid heating, and potential fire or equipment damage. Common causes include damaged insulation, loose wires, or moisture ingress.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Electric shock", "category": "phenomena", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 3, "description": "Physiological injury caused by electric current passing through the human body. Severity depends on current magnitude, pathway, duration, and frequency. In household contexts, it most commonly results from contact with a live conductor while grounded or from faulty earthing. Prevention relies on proper insulation, earthing, double insulation, and protective devices like RCDs or circuit breakers.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Circuit breaker", "category": "components", "appearsIn": ["SCENE_003", "CLUE_007", "CHAR_002"], "difficulty": 3, "description": "An automatically operated electrical switch designed to protect a circuit from damage due to overcurrent or short circuit. Unlike a fuse, it is resettable after tripping. It detects excess current via thermal or magnetic mechanisms and interrupts the live conductor. In modern installations, it replaces fuses as the primary overcurrent protection device.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_012"]}, {"name": "Fuse", "category": "components", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 2, "description": "A sacrificial overcurrent protection device containing a metal wire or strip that melts when excessive current flows, thereby breaking the circuit. Rated in amperes (e.g., 5 A, 13 A), it must be placed in series on the live wire. Its rating should match the cable''s current-carrying capacity—not the appliance''s demand—to prevent fire hazards.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_012"]}, {"name": "Electrical power", "category": "theory", "appearsIn": ["SCENE_003", "CLUE_007", "CHAR_003"], "difficulty": 2, "description": "The rate at which electrical energy is transferred by an electric circuit, measured in watts (W). For resistive loads, power equals voltage multiplied by current (P = VI). It quantifies how fast an appliance converts electrical energy into other forms such as heat, light, or motion. Larger units include kilowatt (kW) for appliances and megawatt (MW) for grid-scale generation.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_011", "CONC_013"]}, {"name": "Power rating", "category": "objects", "appearsIn": ["SCENE_001", "CLUE_003", "CHAR_003"], "difficulty": 2, "description": "The nominal electrical power an appliance is designed to consume when operating at its specified voltage (e.g., 220 V). It appears on nameplates and determines appropriate fuse sizing, wiring gauge, and circuit loading. Exceeding this rating may cause overheating or failure; operating below it typically reduces performance but not safety.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_012"]}, {"name": "Energy efficiency", "category": "theory", "appearsIn": ["SCENE_001", "CLUE_003", "CHAR_003"], "difficulty": 3, "description": "The ratio of useful energy output to total energy input, expressed as a percentage. For electrical appliances, it measures how effectively they convert electricity into desired outputs (e.g., light, heat, motion) versus waste (e.g., heat loss in motors, standby consumption). Higher efficiency reduces electricity bills and environmental impact, and is indicated by energy labels (e.g., Grade 1 in Hong Kong).", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_010", "CONC_013"]}, {"name": "Kilowatt-hour meter", "category": "components", "appearsIn": ["SCENE_003", "CLUE_007", "CHAR_003"], "difficulty": 2, "description": "A measuring instrument that records the cumulative electrical energy consumed over time, expressed in kilowatt-hours (kW·h). One kW·h equals 3.6 million joules—the energy used by a 1-kW device operating for one hour. Utilities use it for billing; it differs from a wattmeter, which measures instantaneous power.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_010", "CONC_012"]}, {"name": "Three-pin plug", "category": "objects", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 2, "description": "A standardized electrical connector used in Hong Kong and other regions with 220–240 V AC supply. It contains three pins: live (brown wire), neutral (blue wire), and earth (green-and-yellow wire), each corresponding to dedicated holes in the socket. Designed for safety, polarity, and grounding, it ensures correct connection of appliances with exposed metal parts.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "Parallel circuit", "category": "architecture", "appearsIn": ["SCENE_003", "CLUE_002", "CHAR_001"], "difficulty": 3, "description": "An electrical configuration where components are connected across common nodes, providing multiple independent paths for current flow. In household wiring, sockets and appliances are connected in parallel so that each receives full mains voltage (220 V), operates independently, and does not affect others if switched off or faulty. Total current equals sum of branch currents.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_016"]}, {"name": "Series circuit", "category": "architecture", "appearsIn": ["SCENE_004", "Q_011", "CHAR_001"], "difficulty": 2, "description": "An electrical configuration where components are connected end-to-end in a single path, so the same current flows through all elements. Voltage is divided among components proportionally to their resistance. Not used for household power distribution due to dependency—if one device fails, the entire circuit opens—but common in simple experiments and some control circuits.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_015"]}], "educational_goals": ["Understand the roles and safety functions of live, neutral, and earth wires", "Differentiate between overloading, short circuits, and electric shock mechanisms", "Apply concepts of parallel circuits, power rating, fuses, and energy efficiency to real-world electrical safety"], "template_difficulty": {"puzzle_mcq": 5, "puzzle_fill": 7, "puzzle_sorting": 2}}', '604d5fe4ec646035a8092b0b47a784b0a2f9b470e793b5b5159c5a2e0fc5a775', 'all concepts', '2026-03-26 09:44:34.70325', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('95f0c57a-61b7-4fb1-9ae8-91b06f64007d', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '68d04cde-8520-4a93-95ff-4848a1538df5', NULL, 'The Ledger Lockdown: A Financial Statement Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "Annotated Trial Balance Printout", "type": "documentary", "clueId": "CLUE_001", "foundBy": "On Maya’s desk, beneath her left hand", "reveals": "Trial balance failed its primary purpose: verifying arithmetic accuracy before financial reporting.", "description": "Physical printout with handwritten notes: ''Assets overstated — need $1.8M correction'', ''Liabilities understated?'', ''Equity must reconcile''. Red ''X'' over ''Total Debits = Total Credits''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}, {"name": "Draft Email Fragment", "type": "digital", "clueId": "CLUE_002", "foundBy": "Opened via forensic access to Maya’s laptop", "reveals": "Misclassification violates accounting principles — confusing expense (SaaS fee) with asset (inventory).", "description": "Recovered from unsent drafts folder: ''…unless we reclassify the prepaid SaaS implementation fee as inventory, the balance sheet won’t balance and the board will pull funding.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_012", "CONC_015"]}, {"name": "Veridian Mission Statement Plaque", "type": "physical", "clueId": "CLUE_003", "foundBy": "On the boardroom wall, directly above the conference table", "reveals": "Business purpose (CONC_003) conflicts with financial manipulation — mission demands transparency, not illusion.", "description": "Engraved brass plaque: ''Empowering SMEs through ethical fintech — integrity first, growth second.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "Q3 Draft Income Statement", "type": "documentary", "clueId": "CLUE_004", "foundBy": "In a labeled ''Q3 Final — FOR BOARD'' folder", "reveals": "Profit (CONC_002) was artificially sustained by suppressing expenses — violating matching principle.", "description": "Shows flat COGS and SG&A despite 22% revenue growth. Net profit margin inflated to 18% — inconsistent with industry benchmarks.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_016"]}, {"name": "System Edit Log", "type": "digital", "clueId": "CLUE_005", "foundBy": "Via server audit trail query", "reveals": "Accounting (CONC_012) requires proper classification — misclassifying expenses as assets distorts both balance sheet and income statement.", "description": "Timestamped entry: ''User: M.Rodriguez | Action: Reclassify GL#4489 (Prepaid SaaS) → Inventory | Amount: $1,842,500 | Time: 23:47, Oct 21''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_012", "CONC_015"]}, {"name": "Digital Trial Balance Snapshot", "type": "digital", "clueId": "CLUE_006", "foundBy": "Exported from accounting software backup", "reveals": "Trial balance (CONC_013) must balance — this error proves intentional manipulation, not clerical mistake.", "description": "CSV export showing total debits = $14,287,100; total credits = $14,286,950 — $150 imbalance. Assets column includes ''Prepaid SaaS'' under Inventory.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013", "CONC_015"]}, {"name": "Maya’s Handwritten Journal Page", "type": "documentary", "clueId": "CLUE_007", "foundBy": "Inside hollowed-out copy of ''Principles of Financial Accounting''", "reveals": "Connects Business (CONC_001), Profit (CONC_002), and Business Purpose (CONC_003) — exposing moral tension at the heart of accounting ethics.", "description": "''Oct 22 — Told Kenji the truth. He said: ‘A business isn’t just profit — it’s purpose. If the numbers lie, the mission dies.’ I don’t know which is worse: failure or fraud.''", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}], "title": "The Ledger Lockdown: A Financial Statement Mystery", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Broken Balance", "sceneId": "SCENE_001", "location": "Veridian Corp. CFO''s Office — Night", "description": "Detective Alex Chen arrives at the locked CFO office. Maya Rodriguez lies slumped at her desk beside an open ledger, a printed trial balance marked ''FINAL — DO NOT ALTER'' — with red pen corrections on asset totals. A half-written email reads: ''…the balance sheet won’t balance unless we reclassify…''", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "The Mission and the Numbers", "sceneId": "SCENE_002", "location": "Veridian Corp. Boardroom — Day", "description": "Alex reviews Veridian’s public mission statement (''Empowering SMEs through ethical fintech'') while interviewing Dr. Tanaka. A framed Apple mission statement hangs nearby. On the table: a draft income statement showing suspiciously flat expenses despite revenue growth.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": ["CLUE_005", "CLUE_006"], "order": 1, "title": "Trial by Ledger", "sceneId": "SCENE_003", "location": "Veridian Corp. Finance Server Room — Day", "description": "Alex accesses the accounting system backup. The digital trial balance shows mismatched debits/credits. Dr. Tanaka explains how errors propagate — and reveals Maya’s final edit log: ''Reclassified $1.8M prepaid marketing as inventory.''", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 3, "clues": ["CLUE_007"], "order": 1, "title": "The Equation Revealed", "sceneId": "SCENE_004", "location": "Veridian Corp. Auditorium — Day", "description": "Alex reconstructs the fraud using whiteboard visuals. Dr. Tanaka confirms the accounting equation violation. Maya’s secret journal surfaces — not a confession, but a plea: ''If the balance sheet lies, the mission dies.''", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "truth", "title": "The Equation Restored", "content": "Maya Rodriguez died of cardiac arrest — not foul play — but her final act was fraud. She reclassified a $1.8M SaaS implementation fee as inventory to inflate assets and hide rising costs, breaking the trial balance (CONC_013) and violating the accounting equation (CONC_015). Her motive? To protect Veridian’s mission (CONC_003) — ironically, by betraying it. The income statement (CONC_016) showed false profit (CONC_002), masking unsustainable operations. Accounting (CONC_012) wasn’t broken — it worked perfectly, exposing the lie.", "debrief": "You’ve mastered: Business (CONC_001) as the entity, Profit (CONC_002) as its vital sign, Business Purpose (CONC_003) as its moral compass, Accounting (CONC_012) as its language, Trial Balance (CONC_013) as its accuracy check, Financial Reporting (CONC_014) as its voice, Balance Sheet (CONC_015) as its portrait, and Income Statement (CONC_016) as its story — all bound by the unbreakable equation.", "summary": "Truth isn’t hidden in the numbers — it’s revealed by them. When the ledger balances, the mission can breathe.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_005", "Q_006", "Q_007", "Q_008", "Q_009", "Q_010", "Q_011"]}}], "logline": "A CFO is found dead beside a corrupted trial balance.", "version": "1.0", "evidence": [{"name": "Corrupted Trial Balance Archive", "type": "Digital", "clueIds": ["CLUE_005", "CLUE_006"], "evidenceId": "EVIDENCE_001", "description": "Server backup file showing timestamped imbalance and unauthorized reclassification entries — definitive proof of intentional manipulation.", "foundLocation": "Finance Server Room (SCENE_003)", "relatedKnowledge": ["CONC_012", "CONC_013"]}, {"name": "Mission-Driven Ethics Memo", "type": "Documentary", "clueIds": ["CLUE_003"], "evidenceId": "EVIDENCE_002", "description": "Internal memo from Dr. Tanaka to board: ''Our mission requires financial integrity — no exception for growth targets.'' Dated 3 months pre-incident.", "foundLocation": "Boardroom filing cabinet (SCENE_002)", "relatedKnowledge": ["CONC_003", "CONC_007"]}], "has_quiz": true, "scriptId": "ACC_MYST_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "It’s an internal check — not shared externally — used before formal reports are issued.", "unlockAfterAttempts": 1}], "order": 1, "content": "What is the primary purpose of a trial balance in accounting?", "options": [{"content": "To verify that total debits equal total credits in the ledger", "feedback": "Correct! The trial balance ensures arithmetic accuracy before preparing financial statements — exactly why Maya’s annotated copy is so damning.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "To calculate net profit for the period", "feedback": "Incorrect. That’s the role of the income statement (CONC_016), not the trial balance.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Trial Balance", "knowledgeId": "CONC_013"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_012"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Think of synonyms like ''enterprise'' or ''company'' — it’s the foundational unit of accounting.", "unlockAfterAttempts": 1}], "order": 2, "content": "Which concept best defines ''an organization engaged in commercial activities to generate profit by providing goods/services''?", "options": [{"content": "Business", "feedback": "Correct! ''Business'' (CONC_001) is the core entity whose financial activity accounting measures and communicates.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}, {"content": "Profit", "feedback": "No — profit (CONC_002) is the *result* of business activity, not the entity itself.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Business", "knowledgeId": "CONC_001"}, "difficulty": 1, "questionId": "Q_002", "knowledgeId": "CONC_001", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "Look at the plaque: it emphasizes values — not just profit. What word captures that core reason?", "unlockAfterAttempts": 1}], "order": 1, "content": "According to Veridian’s mission statement, what is the fundamental reason the company exists?", "options": [{"content": "To empower SMEs through ethical fintech", "feedback": "Correct! This is Veridian’s business purpose (CONC_003) — guiding decisions beyond short-term profit.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "To maximize shareholder value quarterly", "feedback": "Incorrect. While profit matters, Veridian’s stated purpose prioritizes mission and ethics — aligning with CONC_003.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Business Purpose", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_007"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "It’s often called the ''profit and loss account'' — and it’s where net profit (revenue minus costs) is calculated.", "unlockAfterAttempts": 1}], "order": 2, "content": "Which financial statement summarizes operating results over a period — such as revenue, expenses, and net profit?", "options": [{"content": "Income Statement", "feedback": "Correct! The income statement (CONC_016) shows whether the business generated profit (CONC_002) during the period.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_006"]}, {"content": "Balance Sheet", "feedback": "No — the balance sheet (CONC_015) shows financial position *at a point in time*, not performance over time.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Income Statement", "knowledgeId": "CONC_016"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_016", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_002"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_005", "content": "Start with raw data capture — end with external reporting.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Recording transactions (e.g., cash received, goods sold)"}, {"itemId": "ITEM_002", "content": "Classifying and summarizing data (e.g., into revenue/expense accounts)"}, {"itemId": "ITEM_003", "content": "Preparing trial balance to verify accuracy"}, {"itemId": "ITEM_004", "content": "Communicating results via financial statements"}], "order": 1, "content": "Arrange the four core phases of accounting in their correct order:", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Accounting Process", "knowledgeId": "CONC_012"}, "difficulty": 2, "questionId": "Q_005", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004"], "feedbackCorrect": "Correct! Accounting (CONC_012) is a process: record → classify → verify (trial balance) → communicate (financial reports).", "feedbackIncorrect": "Remember: you must record first, then group data, then check accuracy (trial balance), then report.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "sequencing", "hints": [{"hintId": "HINT_006", "content": "This equation is the foundation of the balance sheet — always starts with Assets.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_005", "content": "Assets"}, {"itemId": "ITEM_006", "content": "Liabilities"}, {"itemId": "ITEM_007", "content": "Owners’ Equity"}], "order": 2, "content": "Place these financial elements in the correct order within the fundamental accounting equation:", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Balance Sheet & Equation", "knowledgeId": "CONC_015"}, "difficulty": 3, "questionId": "Q_006", "knowledgeId": "CONC_015", "maxAttempts": 2, "correctOrder": ["ITEM_005", "ITEM_006", "ITEM_007"], "feedbackCorrect": "Correct! The balance sheet (CONC_015) rests on Assets = Liabilities + Owners’ Equity — the bedrock of financial reporting.", "feedbackIncorrect": "Recall: what the business owns (assets) must equal what it owes (liabilities) plus what remains for owners (equity).", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_007", "content": "It’s defined mathematically in CHUNK_003 and appears in Maya’s journal quote: ''If the numbers lie, the mission dies.''", "unlockAfterAttempts": 1}], "order": 1, "content": "The financial gain realized when revenue exceeds costs is called ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Profit", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_007", "knowledgeId": "CONC_002", "maxAttempts": 2, "correctAnswers": ["Profit", "profit", "Net income", "net income"], "feedbackCorrect": "Correct! Profit (CONC_002) = Revenue − Costs. It’s the key performance indicator Maya tried — and failed — to sustain honestly.", "feedbackIncorrect": "Hint: It’s the same term used in the phrase ''profit motive'' and appears in Maya’s journal.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_008", "content": "It’s prominently displayed in the boardroom and referenced in CHUNK_008 with Apple’s example.", "unlockAfterAttempts": 1}], "order": 2, "content": "A formal summary defining an organization’s core purpose — such as Veridian’s ''Empowering SMEs through ethical fintech'' — is called a(n) ________ statement.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Mission Statement", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_008", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctAnswers": ["Mission", "mission", "business mission"], "feedbackCorrect": "Correct! The mission statement (CONC_007) articulates business purpose (CONC_003) and guides strategic decisions — including ethical ones about financial reporting.", "feedbackIncorrect": "Hint: It answers ''what does the organization do for customers, employees, and owners?''", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_009", "content": "Its definition begins: ''concerned primarily with the measurement and communication of financial information...''", "unlockAfterAttempts": 1}], "order": 3, "content": "The discipline concerned with measuring and communicating financial information to support decision-making and control is called ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Accounting", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctAnswers": ["Accounting", "accounting", "Financial accounting"], "feedbackCorrect": "Correct! Accounting (CONC_012) is the entire discipline — encompassing recording, trial balances, and financial statements.", "feedbackIncorrect": "Hint: It’s the subject of CHUNK_012 and the central theme of this mystery.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_010", "content": "It’s one of the ''basic financial statements'' listed in CHUNK_017.", "unlockAfterAttempts": 1}], "order": 4, "content": "The financial statement presenting a company’s financial position on a specific date — showing assets, liabilities, and equity — is the ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Balance Sheet", "knowledgeId": "CONC_015"}, "difficulty": 2, "questionId": "Q_010", "knowledgeId": "CONC_015", "maxAttempts": 2, "correctAnswers": ["Balance Sheet", "balance sheet", "statement of financial position"], "feedbackCorrect": "Correct! The balance sheet (CONC_015) reflects the accounting equation and was deliberately distorted in this case.", "feedbackIncorrect": "Hint: It’s described as a ''snapshot'' in CHUNK_017 and includes the equation Assets = Liabilities + Equity.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_011", "content": "It’s referenced in CHUNK_014 as part of the accounting process — and appears in CLUE_001 and CLUE_006.", "unlockAfterAttempts": 1}], "order": 5, "content": "An internal accounting report listing all ledger account balances — used to verify arithmetic accuracy before preparing financial statements — is the ________.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Trial Balance", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_011", "knowledgeId": "CONC_013", "maxAttempts": 2, "correctAnswers": ["Trial Balance", "trial balance", "trial balance report"], "feedbackCorrect": "Correct! The trial balance (CONC_013) is the critical checkpoint — and Maya’s annotated copy proves it was knowingly violated.", "feedbackIncorrect": "Hint: Its definition in CHUNK_013 says it’s an ''internal report that lists the balances of all accounts...''", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_004"}], "characters": [{"age": 34, "goal": "Identify who manipulated the financial records and why", "name": "Alex Chen", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Once missed a material misstatement in a prior audit — now obsessed with verification rigor", "background": "Former auditor turned investigator; hired by the HK Securities and Futures Commission to probe irregularities at Veridian Corp.", "occupation": "Forensic Accounting Investigator (Hong Kong ICAS)", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, skeptical of surface explanations", "knowledgePoints": ["CONC_012", "CONC_013", "CONC_014", "CONC_015", "CONC_016"]}, {"age": 41, "goal": "Protect Veridian’s stock price and her legacy — even posthumously", "name": "Maya Rodriguez", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Altered Q3 trial balance to hide $2.3M inventory overstatement — fearing board removal if profitability dipped", "background": "Led Veridian’s IPO preparation; known for aggressive growth targets and cost-cutting. Found dead at her desk.", "occupation": "CFO, Veridian Corp.", "characterId": "CHAR_002", "personality": "Driven, perfectionist, privately anxious about missing earnings targets", "knowledgePoints": ["CONC_002", "CONC_013", "CONC_015", "CONC_016"]}, {"age": 58, "goal": "Ensure truth emerges without destroying Veridian’s mission-driven culture", "name": "Dr. Kenji Tanaka", "role": "Witness", "scenes": ["SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Knew Maya was under pressure but didn’t escalate — believed she’d self-correct", "background": "Authored textbooks on financial statement analysis; resigned 3 months ago citing ''strategic misalignment''.", "occupation": "Professor of Accounting & Former Veridian Audit Committee Chair", "characterId": "CHAR_003", "personality": "Wise, measured, quietly disappointed in modern accounting shortcuts", "knowledgePoints": ["CONC_001", "CONC_003", "CONC_007", "CONC_012", "CONC_014"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Business", "category": "basics", "appearsIn": ["SCENE_001", "CLUE_007", "CHAR_002"], "difficulty": 2, "description": "An organization or entity engaged in commercial, industrial, or professional activities aimed at generating profit by providing goods and services. Non-profit organizations reinvest surplus revenue into organizational improvement rather than distributing profits to owners.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Profit", "category": "formula", "appearsIn": ["SCENE_002", "CLUE_004", "CLUE_007", "CHAR_002"], "difficulty": 2, "description": "The financial gain realized when revenue exceeds the costs of operations and taxes. Calculated as Profits = Revenues - Costs. It serves as a key performance indicator for businesses and acts as a reward for delivering value to consumers efficiently.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_018"]}, {"name": "Business Purpose", "category": "theory", "appearsIn": ["SCENE_002", "CLUE_003", "CLUE_007", "CHAR_003"], "difficulty": 2, "description": "The fundamental reason an organization exists, which is typically to generate profit for its owners by meeting customer needs effectively. For non-profits, the purpose shifts toward societal benefit, with any surplus used to enhance the organization’s mission.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_012"]}, {"name": "Accounting", "category": "process", "appearsIn": ["SCENE_003", "CLUE_002", "CLUE_005", "CHAR_001"], "difficulty": 3, "description": "The discipline concerned with measuring and communicating financial information to support decision-making and control within organizations. It involves recording transactions, classifying data, summarizing results, and producing reports like trial balances and financial statements to reflect performance and condition.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Trial Balance", "category": "object", "appearsIn": ["SCENE_001", "CLUE_001", "CLUE_006", "CHAR_002"], "difficulty": 3, "description": "An internal accounting report listing the balances of all ledger accounts related to assets, liabilities, revenues, expenses, gains, and losses. Used to verify arithmetic accuracy before preparing formal financial statements and detect potential errors in bookkeeping.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_012", "CONC_015"]}, {"name": "Financial Reporting", "category": "process", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_003"], "difficulty": 3, "description": "The formal communication of a business’s financial activities and condition through standardized reports such as income statements, balance sheets, and cash flow statements. These reports help stakeholders assess performance, solvency, and investment potential.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_015", "CONC_016"]}, {"name": "Balance Sheet", "category": "object", "appearsIn": ["SCENE_003", "CLUE_002", "CLUE_005", "CHAR_002"], "difficulty": 3, "description": "A fundamental financial statement presenting a company''s financial position on a specific date. It reflects the accounting equation: Assets = Liabilities + Owners’ Equity. Assets represent owned resources, liabilities are debts, and equity is the residual interest after deducting liabilities from assets.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_013", "CONC_012"]}, {"name": "Income Statement", "category": "object", "appearsIn": ["SCENE_002", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "A basic financial statement summarizing a firm’s operating results over a period (monthly, quarterly, annually). It shows total revenues, expenses, and various profit measures such as net income and comprehensive income, enabling evaluation of profitability and operational efficiency.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_014", "CONC_015"]}, {"name": "Mission Statement", "category": "object", "appearsIn": ["SCENE_002", "CLUE_003", "CHAR_003"], "difficulty": 3, "description": "A formal summary defining an organization''s core purpose and focus, answering what it does for customers, employees, and owners. It guides strategic decisions and reflects identity.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_003", "CONC_008"]}], "educational_goals": ["Understand the definition and purpose of business, profit, and business purpose", "Master the accounting process: recording, classifying, summarizing, and communicating financial information", "Interpret core financial statements: Balance Sheet and Income Statement using the accounting equation", "Recognize how trial balances verify accuracy before financial reporting"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 5, "puzzle_sorting": 2}}', '603cecf6a65ee4f376e683bc7d5502f2af5cbb3261ad3de796e0eb97f5c71d3c', 'Accounting Principles and Financial Statements', '2026-03-26 10:02:39.01161', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('61496383-9558-4289-93bf-344fa2243265', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '68d04cde-8520-4a93-95ff-4848a1538df5', NULL, 'The Data Breach at Veridian Corp', 'active', 'easy', 'standard', '{"clues": [{"name": "Frozen EIS Dashboard", "type": "digital", "clueId": "CLUE_001", "foundBy": "On victim''s laptop", "reveals": "EIS was intentionally restricted from detailed exploration", "description": "Screenshot of EIS interface stuck on national sales summary; no drill-down options active.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Circled MIS Summary", "type": "documentary", "clueId": "CLUE_002", "foundBy": "Beside coffee cup", "reveals": "MIS output contradicts ground-truth TPS data", "description": "Printed Q3 sales report with ''DISCREPANCY'' handwritten next to $1.2M variance.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Drill-Down Failure Log", "type": "digital", "clueId": "CLUE_003", "foundBy": "Via EIS admin console", "reveals": "Drill-down capability was actively blocked—not malfunctioning", "description": "System log showing 17 ''Access Denied'' entries for drill-down on Regional Sales.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_004"]}, {"name": "EIS User Policy Doc", "type": "documentary", "clueId": "CLUE_004", "foundBy": "In shared drive folder ''EIS_Compliance''", "reveals": "Lena violated governance policy to conceal data issues", "description": "Internal PDF stating: ''Drill-down must be available to all executives per Audit Rule 7.3.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_006"]}, {"name": "TPS Manual Override Note", "type": "physical", "clueId": "CLUE_005", "foundBy": "On workstation monitor", "reveals": "TPS integrity compromised by human intervention", "description": "Handwritten sticky note on TPS terminal: ''SHIPMENT #7742: NO INVENTORY MATCH — MANUAL OVERRIDE.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_011"]}, {"name": "Transaction Definition Poster", "type": "physical", "clueId": "CLUE_006", "foundBy": "Above terminal", "reveals": "Shipment #7742 violates atomicity principle—two conflicting states recorded", "description": "Wall poster: ''A transaction = atomic, measurable business event (e.g., order, payment, shipment).''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_011", "CONC_009"]}, {"name": "Timestamp-Mismatched MIS Report", "type": "digital", "clueId": "CLUE_007", "foundBy": "In server archive /reports/mis/q3/", "reveals": "MIS reports were altered post-generation—breaking data lineage", "description": "PDF metadata shows generation time (2:15 AM) vs approval stamp (8:00 AM).", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "MIS Input Spec Sheet", "type": "documentary", "clueId": "CLUE_008", "foundBy": "In compliance binder on shelf", "reveals": "MIS violated its core design principle—data provenance broken", "description": "Document stating: ''MIS feeds exclusively from TPS outputs. No manual edits permitted.''", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Dual-State TPS Log Entry", "type": "digital", "clueId": "CLUE_009", "foundBy": "Querying TPS database directly", "reveals": "TPS produced contradictory facts—systemic failure or sabotage?", "description": "Raw log lines for #7742: identical timestamp, one says ''INVENTORY_OK'', other ''INVENTORY_LOW''.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_001", "CONC_009"]}, {"name": "Business Function System Diagram", "type": "documentary", "clueId": "CLUE_010", "foundBy": "Behind whiteboard eraser", "reveals": "TPS is a business function system bound by procedural governance", "description": "Whiteboard sketch: ''Payroll TPS → HR MIS → Compensation DSS'' with ''Policy: No cross-system overrides.''", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_008", "CONC_001"]}, {"name": "DSS Scenario Comparison", "type": "digital", "clueId": "CLUE_011", "foundBy": "On conference tablet", "reveals": "DSS was fed selective data—ignoring unstructured risk signals from operations", "description": "Side-by-side DSS outputs: ''Optimistic Loan Model'' (green) vs ''TPS Default Data'' (red bar chart).", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_003", "CONC_009"]}, {"name": "DSS Governance Memo", "type": "documentary", "clueId": "CLUE_012", "foundBy": "In shared folder ''DSS_Policy''", "reveals": "DSS model violated its own design mandate by excluding TPS facts", "description": "Memo: ''DSS supports semi/unstructured decisions using internal + external data. TPS data is mandatory input.''", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_003", "CONC_006"]}, {"name": "GDSS Encrypted Chat Log", "type": "digital", "clueId": "CLUE_013", "foundBy": "Forensic recovery of GDSS server cache", "reveals": "Group DSS was used to suppress collaborative truth-seeking", "description": "Decrypted snippet: ''Kill consensus vote on TPS audit. Use Groupware priority flag to bury thread.''", "foundInScene": "SCENE_007", "relatedKnowledge": ["CONC_010", "CONC_012"]}, {"name": "Groupware Feature Guide", "type": "documentary", "clueId": "CLUE_014", "foundBy": "In GDSS installation USB", "reveals": "Groupware enabled intentional information suppression in group decisions", "description": "Manual page: ''Priority Flag: Temporarily hides threads from non-admin users during sensitive deliberations.''", "foundInScene": "SCENE_007", "relatedKnowledge": ["CONC_012", "CONC_010"]}], "title": "The Data Breach at Veridian Corp", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002"], "order": 1, "title": "The Empty Office", "sceneId": "SCENE_001", "location": "Veridian Corp CEO Suite — Indoor, minimalist glass office", "description": "Desk is pristine except for an open laptop showing a frozen EIS dashboard and a printed MIS sales summary with red ''DISCREPANCY'' circled. A single coffee cup sits beside it.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}, {"act": 1, "clues": ["CLUE_003", "CLUE_004"], "order": 2, "title": "The Executive Dashboard", "sceneId": "SCENE_002", "location": "EIS Control Room — Indoor, darkened room with wall-sized monitor", "description": "Lena demonstrates EIS interface: high-level KPIs glow green, but drill-down attempts freeze at ''Regional Sales'' layer. Logs show 17 failed drill-down requests yesterday.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 1, "clues": ["CLUE_005", "CLUE_006"], "order": 3, "title": "The Warehouse Terminal", "sceneId": "SCENE_003", "location": "Distribution Center TPS Booth — Indoor, fluorescent-lit workstation", "description": "Marcus shows Alex a TPS terminal displaying real-time order entries. A sticky note reads: ''SHIPMENT #7742: NO INVENTORY MATCH — MANUAL OVERRIDE.''", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": ["CLUE_007", "CLUE_008"], "order": 1, "title": "The MIS Report Vault", "sceneId": "SCENE_004", "location": "Finance Department Server Closet — Indoor, humming racks", "description": "Alex accesses archived MIS budget reports. One file (''Q3_Sales_MIS.pdf'') has mismatched timestamps: generated at 2:15 AM but logged as ''approved'' at 8:00 AM.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_009", "CLUE_010"], "order": 2, "title": "The TPS Log Anomaly", "sceneId": "SCENE_005", "location": "Operations IT Lab — Indoor, dual-monitor workstation", "description": "Marcus pulls up raw TPS logs. Transaction #7742 appears twice: once with ''INVENTORY_OK'', once with ''INVENTORY_LOW''—same timestamp, different servers.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": ["CLUE_011", "CLUE_012"], "order": 3, "title": "The DSS Scenario War Room", "sceneId": "SCENE_006", "location": "Strategic Planning Conference Room — Indoor, oval table with tablets", "description": "Lena and Marcus argue over a DSS loan-risk model. Lena insists on ''optimistic scenario''; Marcus points to TPS data showing rising defaults.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": ["CLUE_013", "CLUE_014"], "order": 1, "title": "The Groupware Backdoor", "sceneId": "SCENE_007", "location": "GDSS Collaboration Hub — Indoor, glass-walled meeting pod", "description": "Alex discovers encrypted GDSS chat logs. A message reads: ''Per L.R.: Kill consensus vote on TPS audit. Use Groupware ''priority flag'' to bury thread.''", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 2, "title": "The Final Dashboard", "sceneId": "SCENE_008", "location": "CEO Suite Revisited — Indoor, same desk, now with forensic tablet", "description": "Alex reconstructs Elena’s final EIS session. Drill-down works—but only when bypassing Lena’s proxy. The truth unfolds layer by layer.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "truth", "title": "The Four-Layer Truth", "content": "Elena discovered that Lena suppressed EIS drill-down to hide regional sales collapse, forcing Marcus to manually override TPS—creating contradictory logs. To justify continued investment, Lena fed cherry-picked data to DSS, producing ''optimistic'' loan models. Finally, she used GDSS groupware to bury audit concerns—preventing consensus. Elena was preparing to expose how each IS layer (TPS→MIS→DSS→EIS) had been corrupted to serve narrative over truth—violating decision-level integrity at every tier.", "debrief": "You mastered: (1) TPS as atomic transaction handler, (2) MIS as data-to-information transformer, (3) DSS as semi-structured decision modeler, (4) EIS as strategic insight engine with drill-down, (5) Organizational decision levels as the blueprint for system design, (6) Data vs information as the core value chain, (7) Groupware as GDSS’s collaborative infrastructure.", "summary": "Truth wasn''t hidden in shadows—it was buried in plain sight, across four layers of trusted systems.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007", "CLUE_008", "CLUE_009", "CLUE_010", "CLUE_011", "CLUE_012", "CLUE_013", "CLUE_014"], "requiredScenes": ["SCENE_008"], "requiredQuestions": ["Q_001", "Q_002", "Q_003", "Q_004", "Q_005", "Q_006", "Q_007", "Q_008"]}}], "logline": "A CEO vanishes after discovering a systemic data leak across all IS layers.", "version": "1.0", "evidence": [{"name": "Integrated Audit Trail", "type": "Digital", "clueIds": ["CLUE_005", "CLUE_007", "CLUE_011", "CLUE_001"], "evidenceId": "EVIDENCE_001", "description": "Forensic reconstruction showing how TPS data corruption (#7742) propagated: TPS → MIS (timestamp tampering) → DSS (selective modeling) → EIS (drill-down suppression).", "foundLocation": "CEO Suite forensic tablet (SCENE_008)", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"name": "Whistleblower Draft Report", "type": "Documentary", "clueIds": ["CLUE_002", "CLUE_004", "CLUE_012", "CLUE_014"], "evidenceId": "EVIDENCE_002", "description": "Elena’s unfinished manuscript: ''The Four-Layer Deception: How Veridian’s IS Architecture Was Weaponized Against Truth.'' Details policy violations per layer.", "foundLocation": "Encrypted partition on CEO laptop (SCENE_001)", "relatedKnowledge": ["CONC_006", "CONC_009", "CONC_010"]}], "has_quiz": true, "scriptId": "MIS_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "MIS transforms data into information—but only if the transformation is faithful.", "unlockAfterAttempts": 1}], "order": 1, "content": "What fundamental distinction explains why the circled MIS report (''DISCREPANCY'') matters more than raw TPS logs?", "options": [{"content": "Data is raw; information adds meaning, context, and business value.", "feedback": "Correct! The MIS report is supposed to convert TPS data into actionable information. A ''DISCREPANCY'' means that meaning-making process failed—undermining all decisions based on it.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_003"]}, {"content": "MIS reports are legally binding; TPS logs are not.", "feedback": "Incorrect. Neither is inherently legally binding—the issue is fidelity of information transformation.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Data vs Information", "knowledgeId": "CONC_007"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_007", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_001"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Recall which management level uses EIS—and what kind of decisions they make.", "unlockAfterAttempts": 1}], "order": 1, "content": "Why would disabling drill-down in EIS violate both policy AND decision-level theory?", "options": [{"content": "EIS serves strategic leaders who need drill-down to validate assumptions behind long-term goals.", "feedback": "Correct! Strategic decisions require both summarized views AND ability to verify underlying details—drill-down is essential for accountability at this level.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_005"]}, {"content": "Drill-down is only for technical staff—not executives.", "feedback": "Incorrect. EIS is explicitly designed for executives to explore data hierarchically—including drilling down to operational realities.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Drill-down Capability", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_004", "CONC_006"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "TPS handles structured tasks. What defines a ''transaction''?", "unlockAfterAttempts": 1}], "order": 1, "content": "Why is ''SHIPMENT #7742: NO INVENTORY MATCH — MANUAL OVERRIDE'' a violation of TPS principles?", "options": [{"content": "TPS must ensure transaction atomicity and consistency—manual override breaks reliability.", "feedback": "Correct! A transaction like shipment #7742 must be an atomic, state-changing event. Manual intervention creates contradictory records—violating TPS core purpose.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": ["CLUE_007"]}, {"content": "TPS isn’t meant for shipments—only payroll.", "feedback": "Incorrect. TPS handles all operational transactions: orders, payroll, shipments, receipts.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: Transaction Processing System", "knowledgeId": "CONC_001"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_001", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_011"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "Tactical decisions use summarized internal/external data. Who approves MIS reports?", "unlockAfterAttempts": 1}], "order": 1, "content": "What decision level does the timestamp mismatch in the MIS report expose—and why?", "options": [{"content": "Tactical level—MIS serves middle management, and altering approval timing undermines their structured decision authority.", "feedback": "Correct! MIS produces summaries for tactical decisions (e.g., budget adjustments). Tampering with approval timing breaks trust in the system’s support for those decisions.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_005", "unlockClues": ["CLUE_009"]}, {"content": "Operational level—warehouse staff generate MIS reports.", "feedback": "Incorrect. Operational staff feed TPS; MIS is managed and approved by middle management for tactical use.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_004", "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More: Organizational Decision Levels", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_004", "knowledgeId": "CONC_006", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_002"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "Structured decisions follow predictable rules. What should TPS do when inventory doesn’t match?", "unlockAfterAttempts": 1}], "order": 1, "content": "Why do the dual TPS log entries for #7742 indicate a structured decision failure?", "options": [{"content": "Structured decisions require consistent, rule-based outcomes—dual states mean the TPS decision logic failed or was bypassed.", "feedback": "Correct! Structured decisions (like inventory validation) must yield deterministic results. Contradictory logs prove either system failure or unauthorized override—both break operational integrity.", "optionId": "OPT_009", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_006", "unlockClues": ["CLUE_011"]}, {"content": "It proves TPS can’t handle high-volume transactions.", "feedback": "Incorrect. Volume isn’t the issue—consistency and atomicity are. Dual states reflect logic failure, not capacity.", "optionId": "OPT_010", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_005", "unlockClues": []}], "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More: Structured vs Unstructured Decisions", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_005", "knowledgeId": "CONC_009", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_001"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "DSS supports semi-structured decisions. What data sources must it integrate?", "unlockAfterAttempts": 1}], "order": 1, "content": "Why is the DSS ''Optimistic Loan Model'' ethically compromised when it ignores TPS default data?", "options": [{"content": "DSS must use both internal (TPS) and external data. Excluding TPS facts makes it unstructured—and dangerously biased.", "feedback": "Correct! DSS is designed for semi-structured decisions requiring comprehensive data. Ignoring authoritative internal data like TPS defaults creates illusion of control without grounding in reality.", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_007", "unlockClues": ["CLUE_013"]}, {"content": "DSS only needs external market data—not internal operations.", "feedback": "Incorrect. DSS explicitly integrates internal AND external data. Omitting TPS data violates its core design.", "optionId": "OPT_012", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_006", "unlockClues": []}], "sceneId": "SCENE_006", "learnMore": {"buttonText": "Learn More: Decision Support System", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_006", "knowledgeId": "CONC_003", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_001", "CONC_009"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_007", "content": "GDSS enhances collaborative decision-making. What does ''burying a thread'' do to collaboration?", "unlockAfterAttempts": 1}], "order": 1, "content": "How does weaponizing Groupware’s ''priority flag'' subvert the purpose of GDSS?", "options": [{"content": "GDSS requires transparent consensus-building; hiding threads prevents diverse perspectives from influencing decisions.", "feedback": "Correct! GDSS exists to surface multiple viewpoints. Using Groupware to suppress dissent destroys its collaborative foundation—and replaces consensus with coercion.", "optionId": "OPT_013", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_008", "unlockClues": []}, {"content": "Groupware is only for scheduling—not decision records.", "feedback": "Incorrect. Groupware supports full collaboration lifecycle—including document sharing, modeling, and discussion threads.", "optionId": "OPT_014", "showHint": "HINT_007", "isCorrect": false, "nextSceneId": "SCENE_007", "unlockClues": []}], "sceneId": "SCENE_007", "learnMore": {"buttonText": "Learn More: Group Decision Support System", "knowledgeId": "CONC_010"}, "difficulty": 4, "questionId": "Q_007", "knowledgeId": "CONC_010", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_012"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_008", "content": "Trace the data flow: TPS → MIS → DSS → EIS. Where did each layer fail its intended role?", "unlockAfterAttempts": 1}], "order": 1, "content": "What final insight confirms Elena’s whistleblower thesis about systemic deception?", "options": [{"content": "Each layer was corrupted: TPS (integrity), MIS (fidelity), DSS (completeness), EIS (transparency)—proving coordinated deception across all decision levels.", "feedback": "Correct! The breach wasn’t isolated—it cascaded: TPS lost atomicity, MIS lost fidelity, DSS lost completeness, EIS lost transparency. This proves Elena’s thesis: deception required compromising every layer of the decision hierarchy.", "optionId": "OPT_015", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_008", "unlockClues": []}, {"content": "Only EIS was compromised—others were functioning normally.", "feedback": "Incorrect. Evidence shows failures at every level—from TPS logs to GDSS chat suppression.", "optionId": "OPT_016", "showHint": "HINT_008", "isCorrect": false, "nextSceneId": "SCENE_008", "unlockClues": []}], "sceneId": "SCENE_008", "learnMore": {"buttonText": "Learn More: Organizational Decision Levels", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_008", "knowledgeId": "CONC_006", "maxAttempts": 2, "masteryReward": 4, "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_009", "content": "Start with the most granular, high-volume system—and end with the most summarized, executive-facing one.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "Transaction Processing System (TPS)"}, {"itemId": "ITEM_002", "content": "Management Information System (MIS)"}, {"itemId": "ITEM_003", "content": "Executive Information System (EIS)"}, {"itemId": "ITEM_004", "content": "Decision Support System (DSS)"}], "order": 2, "content": "Arrange these systems in the correct data flow hierarchy—from raw capture to strategic insight:", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More: Organizational Decision Levels", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_009", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_004", "ITEM_003"], "feedbackCorrect": "Correct! TPS captures raw transactions → MIS summarizes for tactical decisions → DSS models alternatives for semi-structured decisions → EIS delivers strategic insights with drill-down. This mirrors the organizational hierarchy.", "feedbackIncorrect": "Think about data flow: where does data originate? Which system serves operational, then tactical, then strategic levels?", "nextSceneIdCorrect": "SCENE_005", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_010", "content": "Match each capability to its user: warehouse clerk? department head? CEO?", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_005", "content": "Drill-down capability"}, {"itemId": "ITEM_006", "content": "Detailed transaction logging"}, {"itemId": "ITEM_007", "content": "Scenario analysis modeling"}, {"itemId": "ITEM_008", "content": "KPI dashboards with trend alerts"}], "order": 2, "content": "Order these capabilities by the management level they primarily serve:", "sceneId": "SCENE_006", "learnMore": {"buttonText": "Learn More: Organizational Decision Levels", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_010", "knowledgeId": "CONC_006", "maxAttempts": 2, "correctOrder": ["ITEM_006", "ITEM_002", "ITEM_007", "ITEM_005", "ITEM_008"], "feedbackCorrect": "Correct! Operational (detailed logs) → Tactical (MIS summaries) → Strategic (scenario modeling) → Executive (drill-down + KPIs). Note: EIS uses both drill-down and KPIs—but KPIs are the entry point.", "feedbackIncorrect": "Recall: operational needs detail, tactical needs summaries, strategic needs modeling, executive needs both overview and depth.", "nextSceneIdCorrect": "SCENE_007", "nextSceneIdIncorrect": "SCENE_006"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_011", "content": "First blank = unprocessed facts. Second blank = useful output.", "unlockAfterAttempts": 1}], "order": 2, "content": "The raw facts collected during business operations are called ______, while the processed, meaningful output used for decisions is called ______.", "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Data vs Information", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_011", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctAnswers": ["data", "information"], "feedbackCorrect": "Correct! Data is the raw material; information is derived from processing, organizing, and interpreting that data—adding business value.", "feedbackIncorrect": "Remember: ''Data'' comes first—unprocessed and context-free. ''Information'' is what results when data gains meaning.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": "SCENE_001"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_012", "content": "Think of events that change inventory, accounts, or employee status.", "unlockAfterAttempts": 1}], "order": 2, "content": "A discrete, measurable business event—such as a customer order or payment—is called a ______.", "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: Transaction", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_012", "knowledgeId": "CONC_011", "maxAttempts": 2, "correctAnswers": ["transaction"], "feedbackCorrect": "Correct! A transaction is an atomic, state-changing business event that TPS is designed to capture reliably.", "feedbackIncorrect": "Hint: It''s the foundational unit of operational activity—what TPS processes.", "nextSceneIdCorrect": "SCENE_004", "nextSceneIdIncorrect": "SCENE_003"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_013", "content": "Look at CHUNK_006 definition: ''A system is a group of related procedures for a specific business function.''", "unlockAfterAttempts": 1}], "order": 2, "content": "A group of related procedures supporting a specific business operation—like payroll or inventory—is called a ______ system.", "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More: Business Function System", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_013", "knowledgeId": "CONC_008", "maxAttempts": 2, "correctAnswers": ["business function", "functional"], "feedbackCorrect": "Correct! Business function systems are the building blocks of larger architectures like TPS and MIS—they follow defined policies and workflows.", "feedbackIncorrect": "Hint: It''s defined as ''a group of related procedures for a specific business function.''", "nextSceneIdCorrect": "SCENE_006", "nextSceneIdIncorrect": "SCENE_005"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_014", "content": "It''s referenced in CHUNK_009 and CHUNK_011 as ''navigating from summary to detailed views.''", "unlockAfterAttempts": 1}], "order": 2, "content": "The EIS feature allowing navigation from summary KPIs to granular details—like regional sales → store-level data—is called ______.", "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Drill-down Capability", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_014", "knowledgeId": "CONC_005", "maxAttempts": 2, "correctAnswers": ["drill-down", "drill down", "drilling down"], "feedbackCorrect": "Correct! Drill-down capability enables hierarchical data exploration—critical for validating strategic assumptions against operational reality.", "feedbackIncorrect": "Hint: It''s the interactive functionality that lets executives ''dig deeper'' into summaries.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": "SCENE_002"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_015", "content": "CHUNK_012 defines it as ''software applications that facilitate electronic collaboration among groups.''", "unlockAfterAttempts": 1}], "order": 2, "content": "Software enabling electronic collaboration—like shared calendars, document editing, and discussion forums—is called ______.", "sceneId": "SCENE_007", "learnMore": {"buttonText": "Learn More: Groupware", "knowledgeId": "CONC_012"}, "difficulty": 4, "questionId": "Q_015", "knowledgeId": "CONC_012", "maxAttempts": 2, "correctAnswers": ["groupware", "collaborative software"], "feedbackCorrect": "Correct! Groupware provides the infrastructure for GDSS—facilitating communication, coordination, and consensus among distributed teams.", "feedbackIncorrect": "Hint: It''s the technology layer that powers GDSS features like electronic brainstorming and real-time modeling.", "nextSceneIdCorrect": "SCENE_008", "nextSceneIdIncorrect": "SCENE_007"}], "characters": [{"age": 34, "goal": "Reconstruct the data trail that led to the CEO’s disappearance", "name": "Alex Chen", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004", "SCENE_005", "SCENE_006", "SCENE_007", "SCENE_008"], "secret": "Once suppressed a TPS error that caused $2M inventory loss—now obsessed with traceability", "background": "Hired by Veridian’s board after CEO disappearance; previously designed TPS integrations for logistics firms.", "occupation": "Corporate Forensic Analyst (ex-IS consultant)", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, notices inconsistencies in data flows", "knowledgePoints": ["CONC_007", "CONC_006"]}, {"age": 48, "goal": "Protect EIS integrity and prevent board investigation into strategic misalignment", "name": "Dr. Lena Rostova", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_004", "SCENE_006", "SCENE_007", "SCENE_008"], "secret": "Disabled drill-down in EIS to hide declining regional sales—violating audit policy", "background": "Designed Veridian’s EIS; reports directly to missing CEO; oversees all decision-support infrastructure.", "occupation": "VP of Strategic Systems & EIS Architect", "characterId": "CHAR_002", "personality": "Precise, hierarchical, dismissive of ''operational noise''", "knowledgePoints": ["CONC_004", "CONC_005", "CONC_006"]}, {"age": 39, "goal": "Prevent TPS shutdown that would lay off 87 warehouse staff", "name": "Marcus Bell", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_003", "SCENE_005", "SCENE_006", "SCENE_007", "SCENE_008"], "secret": "Manually patched TPS inventory triggers for 3 months after integration failure—creating data silos", "background": "Ran payroll, order processing, and shipment TPS for 12 years; discovered anomalous transaction logs before CEO vanished.", "occupation": "Head of Operations & TPS Manager", "characterId": "CHAR_003", "personality": "Pragmatic, loyal to frontline staff, distrusts ''summary-only'' reporting", "knowledgePoints": ["CONC_001", "CONC_011", "CONC_009"]}, {"age": 52, "goal": "Publish integrated audit showing how manipulated data across TPS→MIS→DSS→EIS enabled strategic deception", "name": "Elena Torres", "role": "Victim", "scenes": ["SCENE_001"], "secret": "Was finalizing a whistleblower report proving GDSS had been weaponized to suppress dissent in merger talks", "background": "Former MIS professor who built Veridian’s layered IS architecture from scratch; authored ''Data Flow Ethics''.", "occupation": "CEO & Chief Information Steward", "characterId": "CHAR_004", "personality": "Visionary, ethical rigorist, believed ''no decision should outrun its data''", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_010", "CONC_012"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Transaction Processing System (TPS)", "category": "system", "appearsIn": ["SCENE_001", "SCENE_003", "SCENE_005", "SCENE_006", "CLUE_005", "CLUE_009", "CHAR_003"], "difficulty": 3, "description": "A Transaction Processing System (TPS) is an information system that captures and processes data from business transactions. It supports the most basic operational activities of an organization by recording, storing, and managing transactional data such as order processing, payroll, shipments, and receipts. TPS handles high volumes of structured, predefined tasks and provides accurate, detailed internal data primarily used by lower-level management for day-to-day operations.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_007", "CONC_006", "CONC_009"]}, {"name": "Management Information System (MIS)", "category": "system", "appearsIn": ["SCENE_001", "SCENE_004", "SCENE_006", "CLUE_002", "CLUE_007", "CHAR_004"], "difficulty": 3, "description": "A Management Information System (MIS) transforms raw data from Transaction Processing Systems into summarized reports for monitoring performance and supporting middle management in structured decision-making. It analyzes large volumes of input data and produces periodic output such as sales summaries or budget reports. MIS enhances organizational efficiency and effectiveness by providing timely, relevant information. Examples include sales management, budgeting, and human resource systems.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"]}, {"name": "Decision Support System (DSS)", "category": "system", "appearsIn": ["SCENE_006", "SCENE_007", "CLUE_011", "CHAR_004"], "difficulty": 4, "description": "A Decision Support System (DSS) assists middle and top-level managers in making semi-structured or unstructured decisions by analyzing and modeling complex data sets. Unlike MIS, which focuses on routine reporting, DSS provides interactive tools for scenario analysis, forecasting, and comparison of alternative solutions. It supports strategic planning and problem-solving in areas such as financial planning and loan management. DSS can integrate both internal and external data sources to support dynamic decision environments.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_002", "CONC_005", "CONC_012"]}, {"name": "Executive Information System (EIS)", "category": "system", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_008", "CLUE_001", "CLUE_003", "CHAR_002"], "difficulty": 4, "description": "An Executive Information System (EIS) is designed for senior executives at the strategic level of an organization. It delivers highly summarized, external and internal information tailored to individual executive needs. EIS emphasizes user-friendliness and enables CEOs to access data across all organizational levels. While typically focused on high-level overviews, it also allows drilling down into details when necessary. It supports long-term planning and goal setting by presenting key performance indicators and trends.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_006"]}, {"name": "Drill-down Capability", "category": "process", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_008", "CLUE_001", "CLUE_003", "CHAR_002"], "difficulty": 3, "description": "Drill-down capability refers to the functionality in information systems that allows users to navigate from summary-level data to increasingly detailed views. This process helps managers investigate underlying causes of performance issues by exploring data hierarchically—such as moving from regional sales totals to office-level results, then to product-line specifics. It is commonly supported in MIS and EIS to enable deeper analysis while maintaining a high-level overview, enhancing decision accuracy and problem identification.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Organizational Decision Levels", "category": "theory", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_004", "SCENE_005", "SCENE_006", "SCENE_007", "SCENE_008", "CLUE_004", "CLUE_008", "CLUE_012", "CHAR_002", "CHAR_003", "CHAR_004"], "difficulty": 3, "description": "Organizational decision levels refer to the hierarchical structure of decision-making within a company: strategic (senior management), tactical (middle management), and operational (lower-level management). Each level has distinct information requirements: strategic decisions require external, qualitative, and summarized data; tactical decisions use both internal and external data in summarized form; operational decisions rely on internal, quantitative, and detailed data. The time frame and scope of decisions vary accordingly, influencing the design and function of information systems.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"name": "Data vs Information", "category": "phenomenon", "appearsIn": ["SCENE_001", "SCENE_004", "CLUE_002", "CLUE_007", "CHAR_001", "CHAR_004"], "difficulty": 2, "description": "Data refers to raw, unprocessed facts and figures collected during business operations, serving as the foundational input for information systems. Information is derived from processed, organized, and interpreted data, making it meaningful and useful for decision-making. The transformation from data to information occurs through systems like TPS and MIS, where context and structure are added. Accurate and timely information increases business value by supporting effective managerial decisions across organizational levels.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Business Function System", "category": "architecture", "appearsIn": ["SCENE_003", "CLUE_010", "CHAR_003"], "difficulty": 3, "description": "A business function system is a group of related procedures designed to support a specific business operation, such as payroll or inventory management. These systems follow defined policies and workflows to transform inputs into meaningful outputs. They involve coordination among users, managers, and IS staff, governed by procedural rules. Such systems are integral to organizational efficiency and serve as building blocks for larger information architectures like TPS and MIS.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Structured vs Unstructured Decisions", "category": "theory", "appearsIn": ["SCENE_003", "SCENE_005", "SCENE_006", "CLUE_006", "CLUE_009", "CLUE_011", "CHAR_003", "CHAR_004"], "difficulty": 4, "description": "Structured decisions are routine, well-defined, and based on predictable processes, typically made at the operational level using internal, quantitative data. Unstructured decisions are complex, non-routine, and require judgment, intuition, and external data, usually occurring at strategic levels. Semi-structured decisions fall between these extremes. Information systems are tailored accordingly: TPS supports structured decisions, while DSS aids in semi-structured or unstructured ones, reflecting differing data needs and analytical requirements.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_006"]}, {"name": "Group Decision Support System (GDSS)", "category": "system", "appearsIn": ["SCENE_007", "CLUE_013", "CHAR_004"], "difficulty": 4, "description": "A Group Decision Support System (GDSS) enhances collaborative decision-making by integrating communication tools and analytical models. It enables multiple decision-makers to work together interactively using computer-based platforms. GDSS supports group productivity through features like electronic brainstorming, document sharing, scheduling, and real-time modeling. It is particularly useful for solving complex problems requiring consensus and diverse perspectives, extending traditional DSS capabilities to team environments.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Transaction", "category": "object", "appearsIn": ["SCENE_001", "SCENE_003", "SCENE_005", "CLUE_005", "CLUE_006", "CHAR_003"], "difficulty": 2, "description": "In the context of information systems, a transaction is any event of interest to the organization that triggers data recording and processing. Examples include customer orders, payments, shipments, and employee time entries. Transactions are discrete, measurable, and typically involve a change in state, such as inventory levels or account balances. TPS is specifically designed to handle high volumes of such transactions reliably and accurately, forming the foundation for higher-level information systems.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Groupware", "category": "component", "appearsIn": ["SCENE_007", "CLUE_013", "CLUE_014", "CHAR_004"], "difficulty": 3, "description": "Groupware refers to software applications that facilitate electronic collaboration among groups, including communication, scheduling, document sharing, and task management. It supports Group DSS by enabling seamless interaction between geographically dispersed team members. Features like shared calendars, real-time editing, and discussion forums enhance group productivity and decision quality. Groupware plays a critical role in modern distributed organizations by reducing coordination overhead and improving information flow.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_010"]}], "educational_goals": ["Distinguish Transaction Processing Systems (TPS), MIS, DSS, EIS, and GDSS by function, audience, and decision type", "Explain how organizational decision levels (strategic, tactical, operational) drive information system design", "Apply the data-to-information transformation process across system hierarchies", "Use drill-down capability to diagnose performance anomalies across management levels", "Classify decisions as structured, semi-structured, or unstructured—and match them to supporting systems"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 5, "puzzle_sorting": 2}}', 'ed05817ba2df6844649bf42f5396880d1a4b172562c18462ad242585e5eb0d34', 'all concepts', '2026-03-26 13:52:28.004096', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('cfc2ba43-c577-4cbc-80e8-8c4a69817455', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'b41bf291-ff70-4ad9-ae3e-5eeda5e24aad', NULL, 'The Blackout at Edison House', 'active', 'easy', 'standard', '{"clues": [{"name": "Burnt Three-Pin Plug", "type": "physical", "clueId": "CLUE_B1_001", "foundBy": "CHAR_003", "reveals": "Evidence of overloading or short circuit due to faulty wiring.", "description": "A damaged three-pin plug with frayed wires and scorch marks. The insulation is melted near the base, and the internal wiring is exposed. The live wire (brown) shows signs of overheating.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Color-Coded Wires Note", "type": "document", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Confirms standard color coding for safe electrical installation in Hong Kong.", "description": "A small sticky note found inside the electrical closet with handwritten labels: ''Brown = Live (220 V)'', ''Blue = Neutral'', ''Green-Yellow = Earth''. It looks like a reminder for proper wiring standards.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "Frayed Live Wire", "type": "component", "clueId": "CLUE_B1_003", "foundBy": "CHAR_002", "reveals": "Direct evidence that the live wire came into contact with a conductive surface, risking electric shock or short circuit.", "description": "A loose strand of brown-insulated wire pulled from the damaged plug. It has charring at the tip and was found touching the metal casing of an appliance.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Burnt Fuse with Overload Signs", "type": "physical", "clueId": "CLUE_B2_001", "foundBy": "CHAR_003", "reveals": "Evidence of circuit overloading prior to failure.", "description": "A fuse in the electrical closet shows clear signs of overheating—blackened edges and melted casing. The damage suggests it failed due to prolonged excessive current rather than a sudden surge.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Frayed Three-Pin Plug", "type": "object", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Potential cause of a short circuit due to exposed conductors.", "description": "A damaged three-pin plug lies near the outlet panel. The insulation on the wires is worn, exposing copper strands. One wire appears to have been recently cut and poorly reconnected.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006", "CONC_007"]}, {"name": "Disabled Alarm Indicator Light", "type": "mechanical", "clueId": "CLUE_B2_003", "foundBy": "CHAR_002", "reveals": "The safety alarm was intentionally disabled, preventing early warning of overcurrent.", "description": "The circuit breaker alarm indicator is taped over, and a small switch near it is set to ''Off''. A handwritten note reads: ''Alarm tripping during floor cleaning – disable until review.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Burnt Fuse", "type": "physical", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The fuse failed due to overcurrent, suggesting either overload or short circuit.", "description": "A cartridge fuse pulled from the main circuit breaker panel shows visible scorch marks and a broken internal wire. The label reads ''13 A''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_015"]}, {"name": "Frayed Three-Pin Plug", "type": "physical", "clueId": "CLUE_B3_002", "foundBy": "CHAR_003", "reveals": "This faulty plug could have caused a short circuit or excessive current draw.", "description": "A damaged three-pin plug with exposed copper wires on the live pin. The insulation is melted near the base. No appliance is attached.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_004", "CONC_011"]}, {"name": "Energy Audit Note", "type": "document", "clueId": "CLUE_B3_003", "foundBy": "CHAR_002", "reveals": "Nina had prior knowledge of dangerous power consumption levels but did not report them.", "description": "A handwritten note in Nina''s notebook: ''Power draw at Break Room outlets peaked at 3.8 kW yesterday—well above safe limit for shared circuit.'' Dated one day before the blackout.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_010", "CONC_011", "CONC_012"]}, {"name": "Burnt Three-Pin Plug", "type": "physical", "clueId": "CLUE_B4_001", "foundBy": "CHAR_003", "reveals": "Evidence of improper wiring or overloading in a high-power appliance.", "description": "A three-pin plug with visibly frayed wires and scorch marks near the base. The earth pin shows signs of overheating.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_014", "CONC_015"]}, {"name": "Kilowatt-Hour Meter Log", "type": "document", "clueId": "CLUE_B4_002", "foundBy": "CHAR_003", "reveals": "Proof that excessive power draw occurred prior to the failure, suggesting overloading.", "description": "A printed log from the building''s kilowatt-hour meter showing an unusual spike in energy consumption just before the blackout.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013", "CONC_010"]}, {"name": "Handwritten Note on Circuit Design", "type": "document", "clueId": "CLUE_B4_003", "foundBy": "CHAR_002", "reveals": "Dr. Patel was aware of the risks associated with parallel circuits and cumulative current draw.", "description": "A crumpled note in Dr. Patel’s handwriting: ''Parallel setup keeps voltage stable... but total current adds up fast if too many devices run at once.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_015", "CONC_016"]}], "title": "The Blackout at Edison House", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Sudden Blackout", "sceneId": "SCENE_001", "location": "Office Break Room", "description": "The lights flicker and die. Emergency lighting kicks in. The three characters are stranded together after a sudden power failure. Frustrated employees complain over walkie-talkies. A burnt smell lingers near the outlet panel.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Investigating the Fuse Box", "sceneId": "SCENE_002", "location": "Electrical Closet", "description": "The trio heads to the main electrical closet. The circuit breaker is tripped. Burn marks are visible on one fuse. Tools are scattered, suggesting recent tampering. A three-pin plug with frayed wires lies nearby.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "The Final Revelation", "sceneId": "SCENE_003", "location": "Conference Room", "description": "Using data from the kilowatt-hour meter and witness accounts, the group reconstructs the events leading to the overload. Tensions rise as secrets emerge. One character must confess—or be exposed.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth and Safety Restored", "content": "The team uncovers that overloading, combined with a faulty plug and disabled safety systems, caused the blackout. Lena admits her oversight, Tomás acknowledges his role, and Nina ensures a full safety review. The building reopens safely.", "debrief": "Multiple failures led to the incident: overloading (CONC_005), a frayed plug causing a short circuit (CONC_006), and disabled safety devices (CONC_008, CONC_009). Proper use of earthing (CONC_004) and circuit design (CONC_015) could have prevented this.", "summary": "Safety requires both proper design and responsible maintenance.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame Without Proof", "content": "The group blames only the old wiring, ignoring recent changes. The root causes remain unaddressed. Another blackout occurs weeks later.", "debrief": "Ignoring modern safety practices like circuit breakers (CONC_008) and proper load management (CONC_005) leads to repeated failures.", "summary": "True safety comes from understanding all system components.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Partial", "title": "Half the Story", "content": "The team identifies overloading but misses the tampered alarm and burnt fuse. Temporary fixes are made, but risks remain.", "debrief": "While overloading (CONC_005) was a factor, ignoring the disabled alarm (EVIDENCE_005) and fuse condition (EVIDENCE_001) leaves the system vulnerable.", "summary": "Complete investigation is essential for lasting solutions.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_003"], "requiredQuestions": []}}], "logline": "Three colleagues trapped in a sudden blackout must uncover the cause of an electrical failure in their office building—while one of them may be hiding a dangerous secret.", "version": "1.0", "evidence": [{"name": "Burnt Fuse", "type": "Physical", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A visibly melted fuse from the main circuit panel, indicating excessive current.", "foundLocation": "Electrical Closet", "relatedKnowledge": ["CONC_009", "CONC_005", "CONC_006"]}, {"name": "Frayed Three-Pin Plug", "type": "Physical", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A damaged plug found near the break room outlet, showing exposed wires.", "foundLocation": "Break Room Floor", "relatedKnowledge": ["CONC_014", "CONC_006", "CONC_007"]}, {"name": "Kilowatt-Hour Meter Log", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Printout showing abnormally high energy consumption in the hour before the blackout.", "foundLocation": "Conference Room Table", "relatedKnowledge": ["CONC_013", "CONC_005", "CONC_010"]}, {"name": "Inspection Bypass Note", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A handwritten note from Lena approving the circuit panel without final inspection.", "foundLocation": "Engineer''s Desk Drawer", "relatedKnowledge": ["CONC_008", "CONC_001"]}, {"name": "Disabled Alarm Switch", "type": "Physical", "clueIds": [], "evidenceId": "EVIDENCE_005", "description": "The circuit breaker alarm switch is taped in the ''off'' position.", "foundLocation": "Electrical Closet Wall", "relatedKnowledge": ["CONC_008", "CONC_005"]}], "has_quiz": true, "scriptId": "ELEC_MYST_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_001", "content": "Check the regional electrical standards. Think about what voltage would be needed to power multiple office devices simultaneously.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "The blackout began suddenly, and a burnt smell came from the outlet. Nina recalls that in Hong Kong, the standard mains voltage supplied to buildings is:", "options": [{"content": "110 V AC", "feedback": "Incorrect. That is the standard in some countries like the US, but not in Hong Kong.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "220 V AC", "feedback": "Correct. In Hong Kong, the standard mains voltage is 220 V alternating current (AC), which powers all household and office appliances.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "240 V DC", "feedback": "Incorrect. While some regions use 240 V, Hong Kong uses 220 V AC, not DC.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "12 V AC", "feedback": "Incorrect. 12 V is typical for low-voltage systems like car electronics, not mains supply.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 2, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Well done! Understanding the local mains voltage is key to diagnosing electrical faults.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Review the standard voltage used in Hong Kong’s electrical grid.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_002", "content": "Think about which wire is responsible for delivering power and poses the greatest shock risk when touched.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Tomás picks up the damaged plug and notices the brown wire is fused and charred. Which wire carries the high potential of 220 V from the power supply?", "options": [{"content": "Neutral wire", "feedback": "Incorrect. The neutral wire provides the return path and is near zero potential.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Earth wire", "feedback": "Incorrect. The earth wire is a safety conductor and does not carry current under normal conditions.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Live wire", "feedback": "Correct. The live wire, typically color-coded brown, carries the full 220 V potential and delivers energy from the supply.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "Blue wire", "feedback": "Incorrect. Blue indicates the neutral wire, not the live conductor.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Exactly! The live wire is the primary carrier of electrical energy and must be properly insulated and fused.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Remember: the live wire is dangerous because it maintains high voltage relative to ground.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B1_003", "content": "This wire is color-coded blue and operates at near-zero voltage under normal conditions.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "Lena examines the plug and explains that the blue wire completes the circuit by carrying current back to the source. This is called the __________ wire.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["neutral", "return"], "feedbackCorrect": "Correct! The neutral wire provides the return path for current in a mains circuit.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Hint: It''s not the live or earth wire. Think about the path electricity takes to complete a loop.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_004", "content": "Consider what happens if the live wire accidentally touches the metal body of an appliance.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Nina points out the green-and-yellow wire connected to the metal casing of the appliance. What is its main purpose?", "options": [{"content": "To carry operating current during normal use", "feedback": "Incorrect. The earth wire does not carry current under normal conditions.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To provide a low-resistance path for fault current and prevent electric shock", "feedback": "Correct. The earth wire safely directs fault current to the ground if the live wire touches the casing, preventing electric shock.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "To increase the efficiency of the appliance", "feedback": "Incorrect. The earth wire is for safety, not performance enhancement.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To reduce the mains voltage to a safer level", "feedback": "Incorrect. Voltage regulation is handled by transformers, not the earth wire.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": 12, "correctAnswers": null, "feedbackCorrect": "Excellent! You understand the critical role of the protective earth in preventing electrocution.", "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": "Review how grounding protects users during internal faults.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B1_005", "content": "Start with the fault event, then trace the path of current, and end with the protective response.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B1_001", "content": "Live wire contacts the metal casing due to insulation failure"}, {"itemId": "ITEM_B1_002", "content": "Fault current flows through the earth wire instead of a person"}, {"itemId": "ITEM_B1_003", "content": "Earth wire provides a low-resistance path to the ground"}, {"itemId": "ITEM_B1_004", "content": "Circuit breaker trips or fuse blows, cutting off power"}], "order": 5, "content": "Arrange the steps in the correct order to explain how the earth wire prevents electric shock when the live wire touches the metal case of an appliance.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_003", "ITEM_B1_002", "ITEM_B1_004"], "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Perfect! You’ve correctly mapped the safety mechanism of the earth wire in a fault scenario.", "relatedKnowledge": ["CONC_002", "CONC_007"], "feedbackIncorrect": "Think again: the sequence starts with the fault and ends with the circuit being interrupted.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_001", "content": "Look at how the fuse melted gradually—this indicates sustained high current, not a sudden spike.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Based on the burn marks on the fuse and the scattered tools, what most likely caused the circuit to fail?", "options": [{"content": "Overloading from too many devices drawing current over time.", "feedback": "Correct. Prolonged overloading causes gradual heating and can melt fuses or trip breakers.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "A momentary power surge from lightning.", "feedback": "Incorrect. Lightning surges typically affect multiple circuits and leave different damage patterns.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Normal wear and tear after years of use.", "feedback": "Incorrect. The recent upgrades make this unlikely, and the burn pattern points to overload.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Voltage drop from insufficient supply.", "feedback": "Incorrect. Voltage drops reduce current, they don''t cause overheating or blown fuses.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B2_001"], "feedbackCorrect": "Yes, continuous overloading generates heat that damages components over time.", "relatedKnowledge": ["CONC_008", "CONC_006"], "feedbackIncorrect": "Review the difference between overloading and other electrical faults.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_002", "content": "Think about what happens when current takes an unintended shortcut through damaged insulation.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "The frayed wires on the three-pin plug could create a short circuit. What defines a short circuit?", "options": [{"content": "A low-resistance path between live and neutral wires, causing high current flow.", "feedback": "Correct. This bypasses the appliance and creates dangerous fault current.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "A broken connection that stops all current flow.", "feedback": "Incorrect. That describes an open circuit, not a short.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Too many appliances plugged into one socket.", "feedback": "Incorrect. That''s overloading, which is different from a direct short.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "A switch turned off accidentally.", "feedback": "Incorrect. A switched-off circuit is intentional and safe.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B2_005"], "feedbackCorrect": "Exactly. A short circuit creates a dangerous path with minimal resistance.", "relatedKnowledge": ["CONC_005", "CONC_008"], "feedbackIncorrect": "Remember, a short allows current to bypass the load entirely.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_003", "content": "Consider why someone would choose a breaker over replacing a blown fuse.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "What is the main function of a circuit breaker compared to a fuse?", "options": [{"content": "It automatically resets after tripping, providing reusable overcurrent protection.", "feedback": "Correct. Unlike fuses, circuit breakers can be manually reset after a fault.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "It increases voltage during high demand to prevent outages.", "feedback": "Incorrect. Circuit breakers do not regulate voltage.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It reduces energy consumption by limiting usage time.", "feedback": "Incorrect. Breakers protect circuits, not manage usage schedules.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It converts AC to DC for safer appliance operation.", "feedback": "Incorrect. That function belongs to a rectifier, not a breaker.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B2_009"], "feedbackCorrect": "Yes, the resettable nature makes circuit breakers more convenient and reliable.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Review the purpose of overcurrent protection devices.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_004", "content": "This term describes exceeding the safe current capacity of a circuit.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "When too many appliances are connected to a single socket, the circuit may experience __________, where excessive current causes overheating and fire risk.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["overloading"], "feedbackCorrect": "Correct. Overloading stresses wiring and can lead to fires.", "relatedKnowledge": ["CONC_008"], "feedbackIncorrect": "Think about what happens when demand exceeds capacity.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_005", "content": "Ohm''s Law tells us that lower this value means higher current for the same voltage.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "An abnormal connection between live and neutral wires creates a short circuit, allowing current to flow through a path of very low __________.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["resistance"], "feedbackCorrect": "Yes, low resistance leads to dangerously high current in a short circuit.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Recall that current increases when resistance decreases.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_001", "content": "Think about what happens inside a fuse when it ''blows''. It has a wire designed to fail safely.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Tomás finds a burnt cartridge fuse labeled ''13 A'' in the electrical closet. What is the primary function of this component?", "options": [{"content": "To regulate voltage fluctuations in the circuit", "feedback": "Incorrect. Fuses do not regulate voltage. They protect circuits by breaking during overcurrent.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To act as a sacrificial device that melts when too much current flows", "feedback": "Correct. A fuse contains a metal element that melts under excessive current, breaking the circuit to prevent fire.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "To ground the metal casing of appliances during a fault", "feedback": "Incorrect. That is the role of the earth wire, not the fuse.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To measure the total energy consumed by the building", "feedback": "Incorrect. A kilowatt-hour meter measures energy consumption, not a fuse.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B3_002"], "feedbackCorrect": "Well done! The fuse is a critical safety device designed to break the circuit during overcurrent.", "relatedKnowledge": ["CONC_008", "CONC_015"], "feedbackIncorrect": "Review how fuses work as protective components in electrical systems.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_002", "content": "Remember: P = VI. Higher total power means higher current if voltage is constant.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Nina notices several high-power appliances plugged into the same outlet in the break room: microwave (1.2 kW), kettle (2.0 kW), and space heater (1.5 kW). What concept explains why this setup is dangerous?", "options": [{"content": "Electrical power adds up in parallel circuits, increasing total current draw", "feedback": "Correct. In parallel circuits, total power is the sum of individual powers, leading to higher current and potential overloading.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "Voltage drops significantly when multiple devices are used", "feedback": "Incorrect. In parallel circuits, each device receives full voltage. Voltage drop is minimal under normal conditions.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Appliances interfere with each other’s efficiency ratings", "feedback": "Incorrect. Efficiency affects energy use but not immediate circuit safety like overloading.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "The earth wire cannot handle multiple grounded devices", "feedback": "Incorrect. The earth wire only carries current during faults and is not overloaded by multiple devices.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_010"}, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B3_005"], "feedbackCorrect": "Exactly! Connecting multiple high-power devices increases total current, risking circuit overload.", "relatedKnowledge": ["CONC_011", "CONC_013"], "feedbackIncorrect": "Consider how power consumption accumulates in household circuits.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B3_003", "content": "This component must match the cable''s capacity and is designed to break the circuit if current becomes too high.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "The power rating of an appliance indicates the amount of electrical power it consumes when operating at its specified voltage. This value, usually given in watts or kilowatts, helps determine the correct size of the _____ and wiring needed for safe operation.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["fuse"], "feedbackCorrect": "Correct! The power rating determines the appropriate fuse size to prevent overheating.", "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": "Think about which safety component is selected based on an appliance’s power demand.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_004", "content": "Use the formula: Power (kW) = Energy (kWh) / Time (h). Then convert to watts.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Nina calculates that a coffee maker draws 1.44 kWh of energy over 2 hours. What is its power consumption during that time?", "options": [{"content": "720 W", "feedback": "Correct. Power = Energy / Time = 1.44 kWh / 2 h = 0.72 kW = 720 W.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "1.44 kW", "feedback": "Incorrect. That would be true only if it ran for one hour. Remember to divide by time.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "2.88 kW", "feedback": "Incorrect. You multiplied instead of dividing. Use P = E/t.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "360 W", "feedback": "Incorrect. Double-check your calculation: 1.44 divided by 2 equals 0.72 kW.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": 12, "correctAnswers": ["OPT_B3_009"], "feedbackCorrect": "Well calculated! Understanding power from energy and time is essential for audits.", "relatedKnowledge": ["CONC_013", "CONC_012"], "feedbackIncorrect": "Practice using the relationship between energy, power, and time.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B3_005", "content": "Start with data collection, then ensure units match before applying the efficiency formula.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B3_001", "content": "Measure the total electrical energy input using a joulemeter or kWh meter"}, {"itemId": "ITEM_B3_002", "content": "Determine the useful energy output (e.g., light, motion, heat delivered)"}, {"itemId": "ITEM_B3_003", "content": "Calculate efficiency using: (useful output / total input) × 100%"}, {"itemId": "ITEM_B3_004", "content": "Convert energy values to the same unit (e.g., joules or kWh)"}], "order": 5, "content": "Arrange the following steps in the correct order to calculate the efficiency of an electrical appliance.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_004", "ITEM_B3_003"], "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Perfect! You’ve mastered the logical flow of efficiency calculations.", "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": "Review the standard method for calculating energy efficiency in appliances.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_001", "content": "Think about what happens when a live wire touches a metal case accidentally.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Why is a three-pin plug used for appliances with metal casings?", "options": [{"content": "To increase the power output of the appliance", "feedback": "No, extra pins do not boost power. Safety is the priority.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To ensure correct polarity and provide grounding through the earth wire", "feedback": "Correct. The earth wire safely directs fault current to ground, preventing shocks.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "To allow the appliance to work on lower voltage", "feedback": "Incorrect. The plug does not alter voltage; it ensures safe connection.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To make the plug fit only one way into the socket", "feedback": "While true, this is a feature of polarized plugs, not the main purpose of the third pin.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_B4_001", "knowledgeId": "CONC_014", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Well done! The earth pin provides critical protection against electric shock.", "relatedKnowledge": ["CONC_004", "CONC_002"], "feedbackIncorrect": "Review how grounding works in household circuits.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_002", "content": "Imagine turning off your lamp without affecting your fridge. What circuit type allows that?", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Which statement best describes why household sockets are wired in parallel?", "options": [{"content": "So that all appliances receive the same current", "feedback": "No. In parallel circuits, voltage is uniform, but current varies per branch.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "So that each appliance gets full mains voltage and operates independently", "feedback": "Yes. Parallel wiring allows independent operation and consistent voltage.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "To reduce overall energy consumption", "feedback": "Not true. Parallel connections don''t save energy—they may increase total draw.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Because series circuits cannot deliver enough power", "feedback": "Series circuits can deliver power, but they’re impractical for homes due to dependency between devices.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_015"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Exactly! Parallel circuits enable reliable, independent appliance use.", "relatedKnowledge": ["CONC_016", "CONC_010"], "feedbackIncorrect": "Remember: in series, one broken device breaks the whole circuit.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B4_003", "content": "It''s often located near the main electrical panel and sends data to the power company.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "The __________ records the total electrical energy used by the building in kilowatt-hours and is used for utility billing.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_B4_003", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["kilowatt-hour meter", "electricity meter", "utility meter"], "feedbackCorrect": "Correct! This device tracks cumulative energy usage for billing purposes.", "relatedKnowledge": ["CONC_010", "CONC_012"], "feedbackIncorrect": "This instrument measures total energy consumed over time, not instantaneous power.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B4_004", "content": "Start with the action that initiated excessive current flow.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B4_001", "content": "Multiple high-power appliances plugged into the same outlet"}, {"itemId": "ITEM_B4_002", "content": "Current in the parallel circuit increases beyond safe levels"}, {"itemId": "ITEM_B4_003", "content": "Overheating damages the three-pin plug insulation"}, {"itemId": "ITEM_B4_004", "content": "Short circuit occurs due to exposed live wire"}, {"itemId": "ITEM_B4_005", "content": "Circuit breaker trips, causing a total blackout"}], "order": 4, "content": "Arrange these events in the correct order that led to the blackout.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B4_004", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": ["ITEM_B4_001", "ITEM_B4_002", "ITEM_B4_003", "ITEM_B4_004", "ITEM_B4_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect! You''ve reconstructed the chain of electrical failure accurately.", "relatedKnowledge": ["CONC_013", "CONC_014", "CONC_009"], "feedbackIncorrect": "Think about cause and effect: overloading leads to heat, which leads to shorts.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_005", "content": "Consider what happens when one bulb burns out in a string of Christmas lights.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "What is a key difference between a series and a parallel circuit?", "options": [{"content": "In a series circuit, voltage is divided among components; in parallel, each gets full voltage", "feedback": "Correct. Series circuits divide voltage; parallel circuits maintain uniform voltage.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "In a series circuit, each device can be turned off independently", "feedback": "No. That’s a feature of parallel circuits. In series, all devices share the same switch.", "optionId": "OPT_B4_010", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Parallel circuits have less total resistance than any individual branch", "feedback": "True, but not the most fundamental operational difference in household contexts.", "optionId": "OPT_B4_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Series circuits are commonly used for wall outlets", "feedback": "Incorrect. Household outlets are wired in parallel for independent operation.", "optionId": "OPT_B4_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_016"}, "difficulty": 2, "questionId": "Q_B4_005", "knowledgeId": "CONC_016", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Excellent! You understand the practical implications of circuit design.", "relatedKnowledge": ["CONC_015", "CONC_009"], "feedbackIncorrect": "Review how voltage and independence differ between configurations.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Prove that the system was safe and shift blame elsewhere", "name": "Dr. Lena Patel", "role": "Lead Electrical Engineer", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She bypassed the proper inspection for the new circuit breaker panel to meet deadlines.", "background": "Lena designed the building''s updated electrical grid last year. She is detail-oriented and takes pride in her work, but recently cut corners due to budget pressure.", "occupation": "Electrical Systems Engineer", "characterId": "CHAR_001", "personality": "Analytical, cautious, slightly defensive under pressure", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_008", "CONC_015", "CONC_016"]}, {"age": 52, "goal": "Protect his job by proving the fault lies with the new system, not his maintenance", "name": "Tomás Rivera", "role": "Facilities Manager", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He disabled the circuit breaker alarm last week because it kept going off during cleaning shifts.", "background": "Tomás has worked in the building for 20 years. He’s practical and hands-on but resents being excluded from recent upgrades.", "occupation": "Building Maintenance Supervisor", "characterId": "CHAR_002", "personality": "Gruff, loyal to tradition, distrustful of new technology", "knowledgePoints": ["CONC_005", "CONC_006", "CONC_009", "CONC_013", "CONC_014", "CONC_015"]}, {"age": 29, "goal": "Uncover the truth and ensure public safety, even if it implicates someone", "name": "Nina Cho", "role": "Energy Auditor", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She discovered dangerously high power draw the day before but didn’t report it, hoping to gather more evidence first.", "background": "Nina was auditing the building’s energy efficiency when the blackout occurred. She’s data-driven and passionate about green energy.", "occupation": "Sustainability Consultant", "characterId": "CHAR_003", "personality": "Curious, empathetic, persistent", "knowledgePoints": ["CONC_010", "CONC_011", "CONC_012", "CONC_013", "CONC_015", "CONC_007"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Mains voltage", "category": "Electricity", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "The standard voltage supplied to homes and buildings from the power grid, typically 230V in many countries.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_010"]}, {"name": "Live wire", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "The wire in a circuit that carries current from the power source to the appliance. It is dangerous to touch.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_004", "CONC_007"]}, {"name": "Neutral wire", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "The wire that completes the circuit by carrying current back to the power source.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Earth wire", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A safety wire that directs excess current into the ground to prevent electric shock.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_007", "CONC_014"]}, {"name": "Overloading", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "When too many appliances draw power from the same circuit, causing excessive current flow.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_010", "CONC_015"]}, {"name": "Short circuit", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 4, "description": "An abnormal connection between live and neutral wires, causing a surge of current.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_007", "CONC_008", "CONC_009"]}, {"name": "Electric shock", "category": "Electricity", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "Harmful physical effects caused by electric current passing through the body.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Circuit breaker", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A safety device that automatically cuts off electricity when current exceeds safe levels.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Fuse", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A thin wire that melts and breaks the circuit when too much current flows through it.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_006"]}, {"name": "Electrical power", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "The rate at which electrical energy is transferred, measured in watts.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_011", "CONC_013"]}, {"name": "Power rating", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "The maximum power an appliance is designed to operate at, usually listed in watts.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_012"]}, {"name": "Energy efficiency", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "How effectively an appliance converts electrical energy into useful output.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_011", "CONC_010"]}, {"name": "Kilowatt-hour meter", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A device that measures total electrical energy used over time, in kilowatt-hours.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_010", "CONC_005"]}, {"name": "Three-pin plug", "category": "Electricity", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A plug with live, neutral, and earth pins for safe connection to mains electricity.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "Parallel circuit", "category": "Electricity", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A circuit where components are connected across common points, allowing independent operation.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_016", "CONC_005"]}, {"name": "Series circuit", "category": "Electricity", "appearsIn": ["SCENE_001"], "difficulty": 3, "description": "A circuit where components are connected end-to-end; failure in one stops the entire circuit.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_015"]}], "educational_goals": ["Understand the components and safety mechanisms of household electrical systems", "Differentiate between series and parallel circuits", "Recognize hazards such as overloading and short circuits", "Apply knowledge of fuses, circuit breakers, and earthing to real-world scenarios", "Calculate power consumption and interpret kilowatt-hour meter readings"], "template_difficulty": {"puzzle_mcq": 15, "puzzle_fill": 5, "puzzle_sorting": 5}}', '604d5fe4ec646035a8092b0b47a784b0a2f9b470e793b5b5159c5a2e0fc5a775', 'all concepts', '2026-04-01 08:20:19.74721', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('16b466a8-27f4-4454-8f40-0a09eb021531', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f36387e3-c216-4017-9cbe-c72560cc8ebb', NULL, 'The Missing Connection: A JDBC Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "JDBC Driver Entry in Logs", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_002", "reveals": "The application attempted to use a MySQL JDBC driver, indicating database connectivity setup was in progress.", "description": "A log entry shows that the class ''com.mysql.jdbc.Driver'' was loaded at startup, but no corresponding DriverManager registration call is visible in the recent code commits.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Fragmented Connection String", "type": "code_snippet", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The team was using a local MySQL instance for development, and the connection URL follows standard JDBC syntax.", "description": "A commented-out line in a Java file reads: ''// String url = \"jdbc:mysql://localhost:3306/development\";'', suggesting the database URL configuration was being tested locally.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Raw SQL Update Statement", "type": "code_snippet", "clueId": "CLUE_B1_003", "foundBy": "CHAR_003", "reveals": "The system used non-parameterized SQL statements, increasing risk of injection and reducing performance.", "description": "A piece of code uses Statement to execute a hardcoded UPDATE query: ''stmt.executeUpdate(\"UPDATE users SET status = ''active'' WHERE id = 10\");''. No parameterization is used.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "Fragmented PreparedStatement Code", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_002", "reveals": "The team was transitioning to safer database practices using PreparedStatement, but not all components were updated.", "description": "A snippet of Java code recovered from Jordan''s workstation shows the use of PreparedStatement with placeholders (''?''). The SQL string is parameterized for updating pet records, indicating an intent to prevent SQL injection.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_007"]}, {"name": "Incomplete ResultSet Handling", "type": "log", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "A flaw in how query results are processed—developers assumed the ResultSet would remain valid without proper iteration checks.", "description": "An exception trace in the debug logs shows a ''ResultSet closed'' error during a data retrieval operation. The stack indicates that next() was called without checking if the ResultSet was still open.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_006", "CONC_004"]}, {"name": "JDBC Architecture Diagram Draft", "type": "document", "clueId": "CLUE_B2_003", "foundBy": "CHAR_003", "reveals": "Alex was designing a more robust JDBC architecture before disappearing, emphasizing abstraction and portability.", "description": "A whiteboard sketch in the server room outlines four layers: Application, JDBC API, DriverManager, and Vendor Driver. Arrows show flow from Alex’s application through DriverManager to a MySQL driver.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_007", "CONC_001"]}, {"name": "Pet.java Source Fragment", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "This is a JavaBean used to model data from the Pet table. It follows standard conventions for serialization and property access.", "description": "A torn piece of paper found in the server room trash bin contains part of a Java class definition. It shows private fields (id, name, specie, owner), a no-argument constructor, and getter/setter method stubs. The class implements Serializable and is in the package ict.bean.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}, {"name": "PetDB.java Method List", "type": "code_printout", "clueId": "CLUE_B3_002", "foundBy": "CHAR_002", "reveals": "The system uses a DAO pattern to abstract database interactions. Each method corresponds to a specific data operation.", "description": "Printed debugging logs include a list of methods from a class called PetDB: getConnection(), createPetsTable(), getPets(), addRecord(Pet p), updateRecord(Pet p), deleteRecord(String id). These suggest structured database operations rather than ad-hoc queries.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010"]}, {"name": "Database URL Configuration Snippet", "type": "log_entry", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The application relies on a properly formatted JDBC URL to establish connections. Misconfiguration here could explain intermittent failures.", "description": "An old debug log entry shows a failed connection attempt with the message: ''Attempting to connect using URL: jdbc:mysql://localhost:3306/sample''. This appears in Jordan''s personal notebook with annotations about driver compatibility.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_012"]}, {"name": "Torn Code Snippet with Placeholders", "type": "document", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The use of index-based parameter binding in PreparedStatements prevents SQL injection and requires correct positional assignment.", "description": "A crumpled piece of paper found near Jordan''s workstation contains a fragment of Java code using PreparedStatement with question marks. The line reads: ''pstmt.setString(2, name);'' with a handwritten note: ''Indices start at 1... never forget.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Whiteboard Diagram: SQL Injection Attempt", "type": "diagram", "clueId": "CLUE_B4_002", "foundBy": "CHAR_002", "reveals": "PreparedStatement placeholders prevent SQL injection by separating code from data, making dynamic query construction safe.", "description": "Faint markings on the office whiteboard show a malicious input example: name = \"Colombian''; DROP TABLE COFFEES; --\". Arrows point to a PreparedStatement template with ''?'' placeholders, labeled ''Safe from injection''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "DAO Class Debug Log Entry", "type": "log", "clueId": "CLUE_B4_003", "foundBy": "CHAR_003", "reveals": "PreparedStatements use placeholders for parameter binding, allowing secure and efficient execution with different values.", "description": "A server log entry recovered from backup shows: ''Executing PreparedStatement: UPDATE users SET last_login = ? WHERE user_id = ?'', followed by ''Bound parameters: [2023-11-05 14:22:10, 1007]''. No raw string concatenation is visible.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013"]}], "title": "The Missing Connection: A JDBC Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Disappearance", "sceneId": "SCENE_001", "location": "Development Office", "description": "The team gathers in the dimly lit office after discovering that the lead architect has vanished. The main server is down, and the database connection fails with no clear error. Code repositories show recent changes, but logs are incomplete. Tension rises as deadlines loom.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code and Configuration", "sceneId": "SCENE_002", "location": "Workstation Area", "description": "The developers examine local workstations and version control history. They find fragments of JDBC code—some using Statement, others using PreparedStatement. A missing db.properties file raises suspicion. Debug output hints at malformed URLs and driver issues.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": [], "order": 3, "title": "Truth in the Logs", "sceneId": "SCENE_003", "location": "Server Room", "description": "Accessing the secure server room, the team reviews authentication logs and exception traces. They reconstruct the sequence of failed CRUD operations and identify a pattern of unauthorized access. The final log entry points to a misconfigured DAO using raw SQL strings.", "charactersPresent": ["CHAR_001", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Secure Connections Restored", "content": "The team reconstructs the configuration, replaces unsafe Statements with PreparedStatements, and reestablishes the database link. The lead developer returns, having gone offline to investigate the same flaws. Management agrees to adopt proper ORM and security practices.", "debrief": "You identified the risks of raw SQL execution and the importance of using PreparedStatement with placeholders. You also recognized how DAO and JavaBean patterns improve maintainability and security.", "summary": "By applying JDBC best practices—using PreparedStatement, managing connections properly, and following DAO patterns—the team restored system integrity and prevented future breaches.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Partial", "title": "System Online, Risks Remain", "content": "The connection is restored using a backup config, but the root cause—unsafe SQL usage—is ignored. Development continues under pressure, leaving the door open for future exploits.", "debrief": "While you fixed the immediate issue, you overlooked the deeper architectural flaws. Using Statement instead of PreparedStatement leaves the system vulnerable to SQL injection.", "summary": "A quick fix brought the system back online, but long-term stability and security were compromised by skipping essential JDBC safeguards.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Total System Lockdown", "content": "Without understanding the JDBC architecture or configuration needs, the team makes incorrect changes that corrupt the driver setup. The database locks down all external access, halting all operations.", "debrief": "Misunderstanding the JDBC Driver and Connection setup led to configuration errors. Knowing how the JDBC architecture layers interact is essential for troubleshooting.", "summary": "Lack of foundational knowledge about JDBC components resulted in cascading failures and complete loss of data access.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001"], "requiredQuestions": []}}], "logline": "In a quiet software development office, the lead developer vanishes just before a critical database integration deadline. Three team members must uncover clues hidden in code and configuration files to restore the broken data layer—and discover who sabotaged the system.", "version": "1.0", "evidence": [{"name": "Missing db.properties File", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A configuration file containing database credentials and URL that has been deleted from the project directory. Its absence breaks the connection initialization.", "foundLocation": "Developer Workstation", "relatedKnowledge": ["CONC_012", "CONC_003"]}, {"name": "Log Entry with SQL Injection Attempt", "type": "Log", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A server log showing an exception caused by malformed SQL due to unescaped user input. Indicates misuse of Statement over PreparedStatement.", "foundLocation": "Server Logs", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_013"]}, {"name": "Outdated DAO Implementation", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A Java class using direct concatenation in SQL queries instead of parameterized statements. Violates secure coding practices and DAO pattern principles.", "foundLocation": "Source Repository", "relatedKnowledge": ["CONC_010", "CONC_004", "CONC_011"]}], "has_quiz": true, "scriptId": "ESD_JDBC_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_001", "content": "Think about how JDBC separates the application logic from the database implementation.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Alex mentions that the system should be able to switch databases without rewriting the data access code. Which core feature of JDBC makes this possible?", "options": [{"content": "DriverManager manages all active connections automatically.", "feedback": "While DriverManager helps manage drivers, it''s not what enables vendor independence.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "JDBC provides a standardized API that abstracts database-specific details through drivers.", "feedback": "Correct! JDBC’s design allows applications to remain independent of the underlying DBMS by using drivers as translation layers.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "All databases support the same SQL dialect, so no translation is needed.", "feedback": "Incorrect. SQL dialects vary significantly between vendors; JDBC handles this via drivers.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Java natively understands SQL and connects directly to any database.", "feedback": "No, Java requires JDBC and specific drivers to communicate with databases.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Well done! JDBC’s abstraction layer is key to portable database applications.", "relatedKnowledge": ["CONC_002", "CONC_007"], "feedbackIncorrect": "Review how JDBC uses drivers to achieve vendor neutrality.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_002", "content": "This method loads the driver into memory so the JDBC framework can find it.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Jordan finds a line of code: ''Class.forName(\"com.mysql.jdbc.Driver\");''. What is the purpose of this line in JDBC?", "options": [{"content": "It creates a new database connection using MySQL.", "feedback": "No, creating a connection requires DriverManager.getConnection().", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It registers the MySQL JDBC driver with the DriverManager so it can be used for connections.", "feedback": "Exactly! Class.forName() loads the driver class, which auto-registers it with DriverManager.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "It executes a query to check if the MySQL server is running.", "feedback": "This line doesn’t execute queries or test connectivity directly.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It imports the necessary SQL classes for MySQL operations.", "feedback": "Importing classes is done with ''import'' statements, not Class.forName().", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Great job! Driver registration is essential for establishing database connections.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Remember, Class.forName() is about loading and registering the driver class.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B1_003", "content": "This object represents a session with the database and is used to create statements.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "To establish a database session in JDBC, you call DriverManager.getConnection(), which returns a(n) __________ object.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["Connection"], "feedbackCorrect": "Correct! The Connection object is central to all JDBC operations.", "relatedKnowledge": ["CONC_001", "CONC_004"], "feedbackIncorrect": "Think about which JDBC component acts as the session between the app and the database.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B1_004", "content": "Start with establishing the session and end with cleanup.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B1_001", "content": "Call getConnection() with URL, username, and password"}, {"itemId": "ITEM_B1_002", "content": "Create a Statement object using createStatement()"}, {"itemId": "ITEM_B1_003", "content": "Execute the SQL query using executeQuery()"}, {"itemId": "ITEM_B1_004", "content": "Process the ResultSet to retrieve data"}, {"itemId": "ITEM_B1_005", "content": "Close the Connection to release resources"}], "order": 4, "content": "Reconstruct the correct sequence of steps to safely execute a SQL query using JDBC.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": 12, "correctAnswers": null, "feedbackCorrect": "Perfect! You''ve mastered the JDBC execution lifecycle.", "relatedKnowledge": ["CONC_004", "CONC_001"], "feedbackIncorrect": "Review the order: connect → create statement → execute → process results → close.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_005", "content": "Consider what happens if a user inputs something like ''; DROP TABLE users;--''.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "Casey reviews a DAO class that constructs SQL queries by concatenating strings. Why is using Statement objects with concatenated user input dangerous?", "options": [{"content": "It improves performance by reusing execution plans.", "feedback": "Actually, static Statements don''t reuse plans effectively when SQL changes.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It can lead to SQL injection attacks if input is not sanitized.", "feedback": "Yes! Concatenated queries can be manipulated by malicious input, leading to security breaches.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "It prevents the use of transactions.", "feedback": "Transactions are controlled by the Connection, not the Statement type.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It requires additional memory for driver caching.", "feedback": "Memory usage isn''t the primary concern here—security is.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Excellent! Avoiding raw SQL concatenation is a key security practice.", "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": "Think about how untrusted input can alter the intended SQL command.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_001", "content": "Think about what happens when a malicious user types ''; DROP TABLE pets;'' as input.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Jordan finds this code on their screen:\n\nString sql = \"SELECT * FROM pets WHERE owner = ?\";\nPreparedStatement pstmt = conn.prepareStatement(sql);\npstmt.setString(1, userInput);\nResultSet rs = pstmt.executeQuery();\n\nWhy is this approach better than using Statement?", "options": [{"content": "It allows multiple SQL statements to be executed at once.", "feedback": "No, that''s not a feature of PreparedStatement. It''s about parameterization, not batch execution.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It prevents SQL injection by separating SQL structure from data inputs.", "feedback": "Correct! Using placeholders ensures user input is treated as data, not executable code.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "It automatically creates database tables if they don’t exist.", "feedback": "No, PreparedStatement does not handle schema creation. That requires DDL commands.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It reduces memory usage by compressing result sets.", "feedback": "No, compression isn''t a benefit of PreparedStatement. Performance comes from precompilation.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B2_002"], "feedbackCorrect": "Good job! You’ve identified a key security advantage of PreparedStatement.", "relatedKnowledge": ["CONC_004", "CONC_006", "CONC_013"], "feedbackIncorrect": "Review how dynamic queries can be exploited with raw strings.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_002", "content": "Recall the initial state of a ResultSet after executeQuery().", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Alex reviews a failed query log showing:\nwhile(rs.next()) {\n  String name = rs.getString(\"pet_name\");\n}\n\nWhat must be true about the ResultSet before this loop runs?", "options": [{"content": "The cursor is positioned on the first row.", "feedback": "No, initially the cursor is *before* the first row. The first call to next() moves it to row one.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "The cursor is positioned before the first row.", "feedback": "Yes! The ResultSet cursor starts before the first row, so next() advances it into position.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "All rows have already been fetched into memory.", "feedback": "Not necessarily. ResultSets often fetch rows lazily, especially for large datasets.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "The connection has been closed.", "feedback": "No, the connection must remain open to read from the ResultSet.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["OPT_B2_006"], "feedbackCorrect": "Exactly! The cursor starts before the first row—next() brings it forward.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Remember: you need to call next() at least once to access any data.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_003", "content": "Look for keywords like DriverManager and vendor driver in the description.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "Casey examines the system design and sees four distinct layers:\n1. Java App (PetDB.java)\n2. JDBC API (Connection, Statement)\n3. DriverManager\n4. MySQL JDBC Driver\n\nWhich concept does this represent?", "options": [{"content": "Object-Relational Mapping (ORM)", "feedback": "Close, but ORM refers to mapping objects to tables. This is about connectivity layers.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "JDBC Architecture", "feedback": "Yes! This layered model separates application logic from vendor-specific drivers via JDBC API and DriverManager.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "CRUD Operations", "feedback": "CRUD describes Create, Read, Update, Delete actions—not the system architecture.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Connection Pooling", "feedback": "Connection pooling manages reuse of connections, but this diagram shows structural layers, not resource management.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["OPT_B2_010"], "feedbackCorrect": "Perfect! You''ve recognized the standard JDBC layered architecture.", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"], "feedbackIncorrect": "Review how JDBC abstracts database access through its four-layer model.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_004", "content": "Check CHUNK_017—it gives a direct example of PetDB.java functionality.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Alex explains that ORM in this project uses Pet.java and PetDB.java. What role does PetDB.java play?", "options": [{"content": "It defines the UI layout for displaying pets.", "feedback": "No, that would be part of a view layer. PetDB is backend-focused.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It encapsulates CRUD operations and acts as a DAO.", "feedback": "Yes! PetDB.java contains methods like addRecord(), deleteRecord()—classic DAO behavior.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "It generates random pet names for testing.", "