2", "ITEM_B2_004", "ITEM_B2_005", "ITEM_B2_001", "ITEM_B2_003"], "masteryReward": 12, "correctAnswers": null, "feedbackCorrect": "Perfect! You’ve mastered the PreparedStatement workflow.", "relatedKnowledge": ["CONC_003", "CONC_006"], "feedbackIncorrect": "Review the steps: connection → SQL with ? → prepare → set parameters → execute.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B2_006", "content": "The canonical pattern is: ResultSet rs = stmt.executeQuery(); while(rs.next()) { ... }", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B2_006", "content": "Call rs.next() to advance the cursor"}, {"itemId": "ITEM_B2_007", "content": "Use getString(), getInt(), etc., to read column values"}, {"itemId": "ITEM_B2_008", "content": "Initialize a while loop conditioned on rs.next()"}, {"itemId": "ITEM_B2_009", "content": "Obtain ResultSet from executeQuery()"}, {"itemId": "ITEM_B2_010", "content": "Process each row inside the loop body"}], "order": 6, "content": "Arrange the steps to properly iterate through a ResultSet and retrieve data.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": ["ITEM_B2_009", "ITEM_B2_008", "ITEM_B2_006", "ITEM_B2_007", "ITEM_B2_010"], "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Excellent! You understand how to safely traverse query results.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Remember: always check rs.next() before accessing data.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B2_007", "content": "Start with your code, then go to interfaces, then manager, then vendor driver.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B2_011", "content": "Database-specific JDBC Driver"}, {"itemId": "ITEM_B2_012", "content": "Java Application"}, {"itemId": "ITEM_B2_013", "content": "JDBC Driver Manager"}, {"itemId": "ITEM_B2_014", "content": "JDBC API"}], "order": 7, "content": "Order the layers of JDBC architecture from top (application) to bottom (database).", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_007", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_012", "ITEM_B2_014", "ITEM_B2_013", "ITEM_B2_011"], "masteryReward": 12, "correctAnswers": null, "feedbackCorrect": "Spot on! You’ve mapped the full JDBC stack correctly.", "relatedKnowledge": ["CONC_002", "CONC_001"], "feedbackIncorrect": "Think: Your app uses JDBC API → DriverManager routes to vendor driver.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_008", "content": "It uses placeholders like ''?'' and is created via prepareStatement().", "unlockAfterAttempts": 1}], "items": null, "order": 8, "content": "To prevent SQL injection and improve performance, developers should use __________ instead of Statement when dealing with user input.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_008", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["PreparedStatement"], "feedbackCorrect": "Correct! PreparedStatement is the secure and efficient choice.", "relatedKnowledge": ["CONC_004", "CONC_013"], "feedbackIncorrect": "Think about parameterized queries and precompilation.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_009", "content": "It''s not on the first row yet—it needs to move there.", "unlockAfterAttempts": 1}], "items": null, "order": 9, "content": "The ResultSet cursor starts positioned ________ the first row, so you must call next() before reading any data.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_009", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": 8, "correctAnswers": ["before"], "feedbackCorrect": "Exactly! The cursor begins before the first row.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Remember: the first call to next() positions it on row one.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_001", "content": "Look at the structure: private fields, public getters/setters, no-arg constructor, and Serializable. These are hallmarks of a reusable data container in Java.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Jordan finds a fragment of Pet.java showing private fields with public getters and setters, a no-argument constructor, and Serializable implementation. What design pattern does this represent?", "options": [{"content": "DAO (Data Access Object)", "feedback": "Incorrect. A DAO manages database operations, but this code defines a data model, not access logic.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "JavaBean", "feedback": "Correct. This class follows JavaBean conventions: private fields, public accessors, no-arg constructor, and Serializable interface. It acts as a DTO for database records.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "Singleton", "feedback": "Incorrect. Singleton ensures one instance of a class, which is not indicated by this code structure.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Factory Method", "feedback": "Incorrect. Factory Method creates objects, but this class is meant to hold data, not instantiate other classes.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Well done! You''ve identified the JavaBean pattern used to transport data between layers.", "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": "Review the characteristics of JavaBeans: they''re simple POJOs designed for data transfer with standardized accessors.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_002", "content": "This class doesn''t contain business rules—it only performs database operations. Think about patterns that separate data access from application logic.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Alex examines PetDB.java and sees methods like addRecord(), getPets(), updateRecord(), and deleteRecord(). What architectural role does this class play?", "options": [{"content": "Controller in MVC", "feedback": "Incorrect. Controllers handle user input and coordinate views/models, but this class directly interacts with the database.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Service Layer", "feedback": "Incorrect. Service layers contain business logic, but this class focuses solely on data persistence operations.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "DAO (Data Access Object)", "feedback": "Correct. PetDB encapsulates all database access logic, providing a clean API for CRUD operations while hiding SQL details—classic DAO pattern.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "Entity Manager", "feedback": "Incorrect. While similar, Entity Manager is JPA-specific. Here we see a custom DAO implementation without ORM annotations.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Excellent! You''ve recognized how the DAO pattern improves maintainability by isolating database dependencies.", "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": "Focus on the separation of concerns: this class handles only data persistence, shielding other components from SQL complexity.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B3_003", "content": "Every database operation starts with establishing connectivity before any SQL can be executed.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B3_001", "content": "Call getConnection() to obtain a Connection object"}, {"itemId": "ITEM_B3_002", "content": "Create a PreparedStatement with parameterized SQL"}, {"itemId": "ITEM_B3_003", "content": "Set parameters using setString(), setInt(), etc."}, {"itemId": "ITEM_B3_004", "content": "Execute the statement via executeUpdate() or executeQuery()"}, {"itemId": "ITEM_B3_005", "content": "Process results or return status to calling layer"}], "order": 3, "content": "Reconstruct the correct sequence of steps the PetDB class uses to execute a successful CRUD operation.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_011"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004", "ITEM_B3_005"], "masteryReward": 20, "correctAnswers": null, "feedbackCorrect": "Perfect! You''ve mapped the full lifecycle of a secure CRUD operation using PreparedStatement.", "relatedKnowledge": ["CONC_010", "CONC_003"], "feedbackIncorrect": "Remember: connection first, then prepare SQL, bind values, execute, and handle output.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B3_004", "content": "It comes right after ''jdbc:'' and before the ''://'' part. It tells JDBC which driver to load for the database vendor.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Casey recalls that the database connection requires a string in the format ''jdbc:subprotocol:subname''. In the example ''jdbc:mysql://localhost:3306/sample'', the subprotocol is _____ and identifies the driver type.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["mysql"], "feedbackCorrect": "Exactly! The subprotocol ''mysql'' directs JDBC to use the MySQL driver for this connection.", "relatedKnowledge": ["CONC_003", "CONC_002"], "feedbackIncorrect": "Look at the syntax: jdbc:subprotocol:subname. The middle part specifies the database technology being accessed.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_005", "content": "Think about what the method name suggests: it''s fetching or retrieving information, not modifying it.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "The final log entry shows a call to PetDB.getPets() returning a list of Pet objects. What fundamental operation does this represent?", "options": [{"content": "Create", "feedback": "Incorrect. Create would involve inserting new data, not retrieving existing records.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Read", "feedback": "Correct. Retrieving data from the database via SELECT is the ''Read'' operation in CRUD.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": []}, {"content": "Update", "feedback": "Incorrect. Update modifies existing data, whereas this method only fetches data without changes.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Delete", "feedback": "Incorrect. Delete removes records from the database, which is not happening here.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_005", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": null, "feedbackCorrect": "Right! You''ve correctly identified the Read operation in the CRUD cycle.", "relatedKnowledge": ["CONC_010", "CONC_009"], "feedbackIncorrect": "Review CRUD fundamentals: Read means querying data without altering it.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_001", "content": "These numbers correspond to the position of ''?'' symbols in the SQL string used to create the PreparedStatement.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Jordan finds a code snippet using PreparedStatement with the line: ''pstmt.setInt(1, sales); pstmt.setString(2, name);''. What is the purpose of the numbers 1 and 2 in these method calls?", "options": [{"content": "They represent database column indices in the table schema.", "feedback": "Incorrect. Column names are not tied to parameter indices. The numbers refer to placeholder positions in the SQL statement.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "They indicate the order of execution when multiple statements are batched.", "feedback": "Incorrect. Batch execution order is determined separately. These indices map to specific ''?'' placeholders in one SQL template.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "They are placeholder indices that match the position of ''?'' in the SQL query string.", "feedback": "Correct! Each number corresponds to the position of a ''?'' placeholder in the SQL, starting from 1.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_001"]}, {"content": "They specify memory allocation size for each parameter value.", "feedback": "Incorrect. Memory management is handled automatically. The indices are purely for mapping values to placeholders.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Well done! Understanding parameter indexing is key to using PreparedStatements safely.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Review how PreparedStatement binds values to placeholders by position.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_002", "content": "Consider what happens when user input contains SQL keywords or quote characters.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Alex explains why raw Statement objects are dangerous compared to PreparedStatement. Which scenario best illustrates the security advantage of using placeholders?", "options": [{"content": "Placeholders allow faster network transmission of SQL commands.", "feedback": "Incorrect. Network speed isn''t improved by placeholders. The benefit is security and performance via query plan reuse.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "They prevent malicious input from altering the intended SQL structure.", "feedback": "Correct! By separating SQL logic from data, placeholders stop injection attacks.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_002"]}, {"content": "They reduce the amount of Java code needed to build queries.", "feedback": "Not the primary benefit. While cleaner, the main purpose is safety, not brevity.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "They automatically encrypt sensitive data before sending to the database.", "feedback": "Incorrect. Encryption must be implemented separately. Placeholders only ensure structural integrity of the query.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Exactly! Placeholders protect against SQL injection by treating input as data, not code.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Think about how unescaped input could manipulate SQL execution.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_003", "content": "Databases can cache execution plans for parameterized queries.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "Casey reviews a log showing repeated executions of ''SELECT * FROM sessions WHERE user_id = ? AND expires = ?''. Why is this more efficient than using Statement with string concatenation?", "options": [{"content": "The database parses the SQL once and reuses the execution plan for different parameter values.", "feedback": "Correct! This is known as plan caching, which boosts performance significantly.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_003"]}, {"content": "It reduces the number of round trips required to execute multiple queries.", "feedback": "Incorrect. Round trips depend on batching, not parameterization. Efficiency comes from parsing optimization.", "optionId": "OPT_B4_010", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It allows the JVM to optimize Java bytecode more effectively.", "feedback": "Incorrect. JVM optimizations are unrelated. The gain is at the database level through plan reuse.", "optionId": "OPT_B4_011", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It compresses the SQL text before sending it over the network.", "feedback": "Incorrect. No compression occurs. The efficiency is due to reduced parsing overhead on the server.", "optionId": "OPT_B4_012", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_003", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Yes! PreparedStatement enables query plan caching, improving performance on repeated calls.", "relatedKnowledge": ["CONC_005", "CONC_011"], "feedbackIncorrect": "Remember that databases can optimize execution when the SQL structure remains constant.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B4_004", "content": "Start with obtaining a connection and defining the SQL with placeholders.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B4_001", "content": "Call prepareStatement(sql) on the Connection object"}, {"itemId": "ITEM_B4_002", "content": "Define SQL string with ''?'' placeholders for parameters"}, {"itemId": "ITEM_B4_003", "content": "Use setter methods like setString() or setInt() to bind values to placeholders"}, {"itemId": "ITEM_B4_004", "content": "Obtain a database Connection object"}, {"itemId": "ITEM_B4_005", "content": "Execute the statement using executeUpdate()"}], "order": 4, "content": "Arrange the correct sequence of steps to safely execute a parameterized SQL update using PreparedStatement.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_004", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_004", "ITEM_B4_002", "ITEM_B4_001", "ITEM_B4_003", "ITEM_B4_005"], "masteryReward": 20, "correctAnswers": null, "feedbackCorrect": "Perfect! You''ve mastered the secure workflow for PreparedStatement usage.", "relatedKnowledge": ["CONC_005", "CONC_003"], "feedbackIncorrect": "Review the proper lifecycle: connect → define SQL → create statement → bind params → execute.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B4_005", "content": "This term refers to the symbolic representation of a value that will be supplied later.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "In a PreparedStatement, the ''?'' symbol is called a __________, which acts as a parameter placeholder and helps prevent SQL injection attacks.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_005", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["placeholder"], "feedbackCorrect": "Correct! The placeholder mechanism is fundamental to secure database programming.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Think of a term that describes a temporary stand-in for a future value in SQL.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B4_006", "content": "Indexing begins at the first occurrence of ''?'' in the SQL string.", "unlockAfterAttempts": 1}], "items": null, "order": 6, "content": "When using PreparedStatement.setString(____, value), the first argument must be an integer representing the position of the ''?'' placeholder in the SQL, starting from ____.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_006", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 10, "correctAnswers": ["index", "1"], "feedbackCorrect": "Exactly! Placeholder indices start at 1, not 0, matching natural counting.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Remember that SQL parameter positions are 1-based, unlike array indices in Java.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_007", "content": "Consider how untrusted input is treated in each case—does it become part of the command?", "unlockAfterAttempts": 1}], "items": null, "order": 7, "content": "Jordan sees two code versions: one uses string concatenation with Statement, another uses ''?'' placeholders with PreparedStatement. What is the primary security benefit of the second approach?", "options": [{"content": "It ensures all inputs are converted to uppercase for consistency.", "feedback": "Incorrect. Case conversion is unrelated. The real benefit is structural protection against injection.", "optionId": "OPT_B4_013", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It separates SQL logic from data, so input cannot alter query intent.", "feedback": "Correct! Parameters are treated as literal values, not executable code.", "optionId": "OPT_B4_014", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_002"]}, {"content": "It automatically validates input length and type before execution.", "feedback": "Incorrect. Type checking may occur but isn''t guaranteed. The core protection is syntax isolation.", "optionId": "OPT_B4_015", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It logs every query for audit purposes.", "feedback": "Incorrect. Logging is a separate concern. Security comes from preventing code injection.", "optionId": "OPT_B4_016", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_007", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Well reasoned! Separating code from data is the foundation of injection defense.", "relatedKnowledge": ["CONC_004", "CONC_005"], "feedbackIncorrect": "Think about how attackers exploit string concatenation to inject commands.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_008", "content": "Replace string concatenation with parameterized queries using placeholders.", "unlockAfterAttempts": 1}], "items": null, "order": 8, "content": "Alex discovers a DAO method that builds SQL strings dynamically using user input. What is the safest way to refactor it?", "options": [{"content": "Continue using Statement but sanitize input by removing quotes and semicolons.", "feedback": "Incorrect. Input filtering is unreliable and easily bypassed. Use parameterization instead.", "optionId": "OPT_B4_017", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Rewrite the query using PreparedStatement with ''?'' placeholders and setter methods.", "feedback": "Correct! This eliminates injection risk by design.", "optionId": "OPT_B4_018", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_003"]}, {"content": "Encrypt all user inputs before including them in SQL strings.", "feedback": "Incorrect. Encryption doesn''t prevent syntactic manipulation. Only parameterization does.", "optionId": "OPT_B4_019", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Limit query execution to predefined static strings only.", "feedback": "Too restrictive. PreparedStatement allows safe dynamic queries with parameters.", "optionId": "OPT_B4_020", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_008", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": 15, "correctAnswers": null, "feedbackCorrect": "Excellent choice! PreparedStatement is the standard solution for secure dynamic queries.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Remember that no amount of input cleaning beats proper parameter binding.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 34, "goal": "Ensure the integrity of the database layer is preserved and the truth about the vulnerability comes out.", "name": "Alex Rivera", "role": "Senior Developer", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Alex discovered a security flaw in the company''s use of Statement instead of PreparedStatement and threatened to report it.", "background": "A seasoned coder with deep expertise in backend systems. Alex designed the current JDBC implementation but has been acting secretive lately.", "occupation": "Software Engineer", "characterId": "CHAR_001", "personality": "Analytical, reserved, and detail-oriented. Prefers logic over emotion.", "knowledgePoints": ["CONC_001", "CONC_007", "CONC_003", "CONC_004", "CONC_011"]}, {"age": 26, "goal": "Recover the lost configuration and avoid being blamed for the system failure.", "name": "Jordan Kim", "role": "Junior Developer", "scenes": ["SCENE_001", "SCENE_002"], "secret": "Jordan accidentally deleted a critical configuration file while trying to fix a bug and hasn''t told anyone.", "background": "New to enterprise development but eager to prove themselves. Recently assigned to assist on the JDBC module.", "occupation": "Application Developer", "characterId": "CHAR_002", "personality": "Curious, enthusiastic, and slightly nervous. Asks many questions and takes detailed notes.", "knowledgePoints": ["CONC_002", "CONC_012", "CONC_005", "CONC_006", "CONC_013"]}, {"age": 38, "goal": "Get the system running again without exposing management decisions that led to technical debt.", "name": "Casey Morgan", "role": "Team Lead", "scenes": ["SCENE_001", "SCENE_003"], "secret": "Casey pressured the team to skip ORM best practices to meet a deadline, compromising system safety.", "background": "Oversees the entire development lifecycle. Focused on delivery timelines and architectural consistency.", "occupation": "Engineering Manager", "characterId": "CHAR_003", "personality": "Pragmatic, authoritative, and process-driven. Values efficiency and accountability.", "knowledgePoints": ["CONC_008", "CONC_009", "CONC_010", "CONC_001", "CONC_011"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "API", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "A Java API that enables Java applications to interact with relational databases using SQL. It provides a standard interface for connecting, querying, and updating data.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"]}, {"name": "JDBC Driver", "category": "Component", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A software component that implements the JDBC interface for a specific database. It translates JDBC calls into database-specific protocols.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_012"]}, {"name": "Connection", "category": "Interface", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "An object representing a session between a Java application and a database. Created via DriverManager or DataSource using a database URL, username, and password.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_012", "CONC_004"]}, {"name": "Statement", "category": "Interface", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Used to execute static SQL queries. Vulnerable to SQL injection if user input is concatenated directly into the query string.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_011", "CONC_006"]}, {"name": "PreparedStatement", "category": "Interface", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 4, "description": "A precompiled SQL statement that uses placeholders (?) for parameters. Prevents SQL injection and improves performance for repeated executions.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_013", "CONC_011"]}, {"name": "ResultSet", "category": "Interface", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Holds the data returned from a SELECT query. Traversed row by row to extract values using column names or indices.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "JDBC Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "Consists of two layers: the JDBC API (for application developers) and the JDBC Driver API (for driver vendors). Communication flows from application → JDBC API → Driver Manager → Driver → Database.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "Pattern", "appearsIn": ["SCENE_003"], "difficulty": 4, "description": "A programming technique that maps database tables to Java objects. Simplifies data persistence and retrieval without writing raw SQL.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "JavaBean", "category": "Class", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A Java class that follows conventions: private fields, public getters/setters, and a no-argument constructor. Often used in ORM to represent table rows.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "DAO (Data Access Object)", "category": "Pattern", "appearsIn": ["SCENE_003"], "difficulty": 4, "description": "A design pattern that separates low-level database operations from business logic. Encapsulates JDBC code and provides a clean API for data manipulation.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_011", "CONC_003"]}, {"name": "CRUD Operations", "category": "Operation", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Basic functions of persistent storage: Create (INSERT), Read (SELECT), Update (UPDATE), Delete (DELETE). Implemented using JDBC Statements or PreparedStatements.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_006"]}, {"name": "Database URL", "category": "Configuration", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A string that specifies the location of a database. Follows the format jdbc:subprotocol:subname and is used by DriverManager to load the appropriate driver.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Placeholder", "category": "Syntax", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Symbol (usually ''?'') used in PreparedStatement to represent dynamic parameters. Prevents SQL injection by ensuring input is treated as data, not executable code.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_011"]}], "educational_goals": ["Understand the role and function of JDBC in Java applications", "Identify components of JDBC architecture including drivers, connections, statements, and result sets", "Apply knowledge of PreparedStatement and placeholders to prevent SQL injection", "Explain how DAO and JavaBean patterns work with JDBC for clean data access", "Perform CRUD operations using JDBC interfaces"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 3}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'JDBC Fundamentals and Architecture', '2026-04-01 08:34:37.366527', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('27473a86-62aa-4d71-8280-30f55279b2b5', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f36387e3-c216-4017-9cbe-c72560cc8ebb', NULL, 'The PreparedStatement Poisoning', 'active', 'easy', 'standard', '{"clues": [{"name": "JDBC Architecture Diagram", "type": "documentary", "clueId": "CLUE_001", "foundBy": "On desk beside victim", "reveals": "The foundational design principle violated by the crime: abstraction failure between application and driver.", "description": "Hand-drawn whiteboard sketch showing four layers: Java App → JDBC API → DriverManager → Vendor Driver. Arrows labeled ''abstraction'' and ''vendor independence''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Database URL Sticky Note", "type": "physical", "clueId": "CLUE_002", "foundBy": "Stuck to terminal bezel", "reveals": "The exact connection parameters used — essential for recreating the vulnerable session.", "description": "Yellow sticky note on monitor: ''jdbc:mysql://localhost:3306/petdb | user: miguel | pass: 🐾dev2024''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Open PetDB.java Tab", "type": "digital", "clueId": "CLUE_003", "foundBy": "Active browser tab on victim''s screen", "reveals": "Evidence of deliberate misuse — PreparedStatement created but not properly parameterized.", "description": "IDE window showing PetDB.addRecord() method using PreparedStatement, but with suspiciously missing setXXX() calls before executeUpdate().", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "Execution Plan Timestamp Log", "type": "digital", "clueId": "CLUE_004", "foundBy": "In /var/log/jdbc/plan_trace.log", "reveals": "PreparedStatement was *not* reusing execution plans — indicating precompilation was disabled.", "description": "CSV export showing 12 identical UPDATE queries with ''?'' placeholders — yet 12 distinct plan IDs and compilation times.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "Driver Registration Snippet", "type": "code_pattern", "clueId": "CLUE_005", "foundBy": "In commit history ''fix-driver-load-order''", "reveals": "Driver registration was removed — implying reliance on auto-loading, which failed silently in this environment.", "description": "Git diff fragment: ''- Class.forName(\"com.mysql.cj.jdbc.Driver\");'' — deleted from PetDB.getConnection().", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "DAO Configuration File", "type": "documentary", "clueId": "CLUE_006", "foundBy": "In project resources folder", "reveals": "Dr. Rostova intentionally disabled PreparedStatement caching — creating the vulnerability exploited.", "description": "config/db.properties contains ''jdbc.pool.prepstmt.cache.size=0'' and comment: ''# Per Rostova: avoids Derby lock contention''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_010"]}, {"name": "ResultSet Iteration Anomaly", "type": "code_pattern", "clueId": "CLUE_007", "foundBy": "Code review of getPets() method", "reveals": "Fragile ResultSet usage — if schema changed, this would fail silently or return wrong data.", "description": "PetDB.getPets() uses while(rs.next()) but accesses columns via index (rs.getString(1)) — no column name validation.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_006", "CONC_004"]}], "title": "The PreparedStatement Poisoning", "scenes": [{"act": 1, "clues": ["CLUE_001", "CLUE_002", "CLUE_003"], "order": 1, "title": "The Server Room Discovery", "sceneId": "SCENE_001", "location": "University Data Center — Server Rack Bay 7", "description": "Miguel’s body slumps over a terminal displaying fragmented SQL logs and an open PetDB.java file. A coffee cup steams beside a printed JDBC Architecture diagram.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": ["CLUE_004", "CLUE_005"], "order": 2, "title": "The Corrupted Log Analysis", "sceneId": "SCENE_002", "location": "Forensics Lab — Terminal Cluster", "description": "Alex examines Miguel’s last executed queries. One log shows repeated ''UPDATE pets SET owner = ? WHERE id = ?'' — but timestamps reveal identical execution plans were *not* reused.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": ["CLUE_006", "CLUE_007"], "order": 1, "title": "The DAO Code Audit", "sceneId": "SCENE_003", "location": "Development Office — Dual-Monitor Workstation", "description": "Alex reviews PetDB.java alongside database config files. A commented-out line reads ''// setPoolPrepStmts(true) — disabled per Rostova directive''.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": [], "order": 1, "title": "The Confrontation in the JDBC Layer", "sceneId": "SCENE_004", "location": "Architecture Review Room — Whiteboard Labeled ''JDBC Stack''", "description": "Alex reconstructs the full JDBC flow on the board: Application → DriverManager → Driver → Connection → PreparedStatement → ResultSet. Dr. Rostova watches silently.", "charactersPresent": ["CHAR_001", "CHAR_002"]}], "endings": [{"type": "truth", "title": "The Truth Revealed", "content": "Dr. Rostova disabled PreparedStatement caching to mask a workaround for a Derby bug — but created a systemic vulnerability. Miguel discovered it and committed a fix restoring precompilation. Before deployment, Rostova accessed his machine, replaced the patched JAR with a version that *looked* secure but silently ignored setXXX() calls — causing the PreparedStatement to execute with raw, unvalidated strings. The final log showed ''UPDATE pets SET owner = ''''Robert''; DROP TABLE pets; --'''' WHERE id = 123'' — injected via flawed string concatenation in the compromised build. Her motive: protecting her architectural authority, not malice — but the negligence was fatal.", "debrief": "You''ve mastered: JDBC''s vendor-independent architecture (CONC_001/007), the Connection lifecycle (CONC_003), Statement vs PreparedStatement tradeoffs (CONC_004/005), ResultSet safety (CONC_006), driver registration (CONC_002), URL structure (CONC_012), placeholder security (CONC_013), JavaBean/DAO patterns (CONC_009/010), and CRUD implementation (CONC_011).", "summary": "The murder wasn''t physical — it was architectural. And the evidence was in the code.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["CLUE_001", "CLUE_002", "CLUE_003", "CLUE_004", "CLUE_005", "CLUE_006", "CLUE_007"], "requiredScenes": ["SCENE_004"], "requiredQuestions": ["Q_008", "Q_009", "Q_010", "Q_011", "Q_012"]}}], "logline": "A database architect is found dead with corrupted SQL logs.", "version": "1.0", "evidence": [{"name": "JDBC Architecture Diagram", "type": "Documentary", "clueIds": ["CLUE_001"], "evidenceId": "EVIDENCE_001", "description": "Whiteboard photo showing four-layer stack with labels and arrows. Key annotation: ''Abstraction = vendor independence''.", "foundLocation": "Server room desk", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Database Credentials Sticky Note", "type": "Physical", "clueIds": ["CLUE_002"], "evidenceId": "EVIDENCE_002", "description": "Handwritten sticky with full JDBC URL, username, and password — used to recreate the victim''s session.", "foundLocation": "Terminal bezel", "relatedKnowledge": ["CONC_003", "CONC_012"]}], "has_quiz": true, "scriptId": "JDBC_MURDER_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_001", "content": "It’s about how Java code talks to databases *without* knowing their internal protocols.", "unlockAfterAttempts": 1}], "order": 1, "content": "What core JDBC principle does the whiteboard diagram (CLUE_001) illustrate — and why is it vital for cross-database portability?", "options": [{"content": "Vendor independence: JDBC provides a uniform API so apps don’t depend on MySQL/Oracle-specific syntax.", "feedback": "Exactly. JDBC abstracts vendor details behind standard interfaces like Connection and Statement — enabling portable code.", "optionId": "OPT_001", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_004"]}, {"content": "Connection pooling: Reusing connections improves performance across all databases.", "feedback": "Pooling is useful, but not part of JDBC’s core portability promise — it’s an implementation detail.", "optionId": "OPT_002", "showHint": "HINT_001", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Portability", "knowledgeId": "CONC_001"}, "difficulty": 1, "questionId": "Q_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_007"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_002", "content": "Look at the sticky note — three pieces of info are listed. Two are credentials.", "unlockAfterAttempts": 1}], "order": 2, "content": "Based on CLUE_002, what component must be passed to DriverManager.getConnection() *alongside* the URL to establish a session?", "options": [{"content": "Username and password", "feedback": "Yes — Connection requires URL, username, and password. These authenticate the session with the database.", "optionId": "OPT_003", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_005"]}, {"content": "Driver class name and transaction isolation level", "feedback": "Driver class is registered separately; isolation level is optional and set later on the Connection.", "optionId": "OPT_004", "showHint": "HINT_002", "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Connection Objects", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_012"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_003", "content": "PreparedStatement is supposed to compile once and reuse the plan — what configuration controls this?", "unlockAfterAttempts": 1}], "order": 1, "content": "CLUE_004 shows identical PreparedStatement queries with *different* execution plans. What JDBC concept explains why this breaks PreparedStatement’s core promise?", "options": [{"content": "Precompilation: PreparedStatement compiles the SQL once and caches the execution plan for reuse.", "feedback": "Correct. Without precompilation, each execution compiles anew — losing performance and security benefits.", "optionId": "OPT_005", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_006"]}, {"content": "Placeholder binding: Using ''?'' prevents SQL injection regardless of plan reuse.", "feedback": "Binding prevents injection, but doesn’t address the *performance* violation shown in the log.", "optionId": "OPT_006", "showHint": "HINT_003", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About PreparedStatement Precompilation", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_003", "knowledgeId": "CONC_005", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_013"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_004", "content": "Consider environments where automatic driver discovery fails — e.g., older JVMs or modular classpaths.", "unlockAfterAttempts": 1}], "order": 2, "content": "CLUE_005 shows deleted driver registration. Why is explicitly loading a JDBC driver still necessary in some environments?", "options": [{"content": "To ensure the driver is loaded into memory before getConnection() is called — especially when auto-loading is unreliable.", "feedback": "Yes. Class.forName() forces initialization of the driver’s static block, registering it with DriverManager.", "optionId": "OPT_007", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "To bypass firewall restrictions by embedding driver logic directly in the app.", "feedback": "Drivers don’t handle networking — that’s the DBMS’s job. Registration is purely for JVM visibility.", "optionId": "OPT_008", "showHint": "HINT_004", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JDBC Driver Registration", "knowledgeId": "CONC_002"}, "difficulty": 2, "questionId": "Q_004", "knowledgeId": "CONC_002", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_003"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_005", "content": "It’s not the PreparedStatement itself — it’s the layer that manages connections and optimizes repeated use.", "unlockAfterAttempts": 1}], "order": 1, "content": "CLUE_006 reveals ''jdbc.pool.prepstmt.cache.size=0''. Which JDBC component is responsible for *caching prepared statements* — and why does disabling it undermine PreparedStatement’s value?", "options": [{"content": "Connection pool: It caches PreparedStatement objects per connection to avoid repeated prepare() calls.", "feedback": "Exactly. The pool reuses both Connections *and* their PreparedStatements — disabling cache forces re-preparation every time.", "optionId": "OPT_009", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "DriverManager: It caches compiled SQL across all applications sharing the same JVM.", "feedback": "DriverManager only loads drivers — it doesn’t cache statements. That’s the job of connection pools or drivers themselves.", "optionId": "OPT_010", "showHint": "HINT_005", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About PreparedStatement Caching", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_005", "knowledgeId": "CONC_005", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_003"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_006", "content": "What happens if someone adds a new column to the SELECT clause — or changes column order — in the SQL?", "unlockAfterAttempts": 1}], "order": 2, "content": "In CLUE_007, getPets() uses rs.getString(1). Why is accessing ResultSet columns by *index* riskier than by name in production DAOs?", "options": [{"content": "Index-based access breaks if column order changes — whereas column names remain stable identifiers.", "feedback": "Correct. getColumnLabel() or getString(''owner'') survives schema evolution; index 1 does not.", "optionId": "OPT_011", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "It’s slower — name-based lookup requires string hashing, while index access is O(1).", "feedback": "Performance difference is negligible. The real issue is *maintainability* and resilience to SQL changes.", "optionId": "OPT_012", "showHint": "HINT_006", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About ResultSet Column Access", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "masteryReward": 2, "relatedKnowledge": ["CONC_010"]}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_007", "content": "Locking behavior depends on the DBMS — not the JDBC API. Which layer translates generic calls into vendor-specific ones?", "unlockAfterAttempts": 1}], "order": 3, "content": "Dr. Rostova claimed disabling PreparedStatement caching avoided ''Derby lock contention''. But what *actual* JDBC architecture layer handles database-specific locking — and why couldn’t PreparedStatement be blamed?", "options": [{"content": "JDBC Driver: It implements locking semantics per the database — PreparedStatement is just a Java wrapper.", "feedback": "Yes. The driver handles Derby-specific locks; PreparedStatement only sends parameterized SQL — it doesn’t control concurrency.", "optionId": "OPT_013", "showHint": "", "isCorrect": true, "nextSceneId": "SCENE_004", "unlockClues": []}, {"content": "Connection: It manages transaction boundaries and can configure isolation levels to reduce lock contention.", "feedback": "True — but Connection isn’t the layer that *implements* locking. That’s entirely the driver’s responsibility.", "optionId": "OPT_014", "showHint": "HINT_007", "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About JDBC Architecture Layers", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_007", "knowledgeId": "CONC_007", "maxAttempts": 2, "masteryReward": 3, "relatedKnowledge": ["CONC_002"]}, {"type": "sequencing", "hints": [{"hintId": "HINT_008", "content": "Start with how the session begins — then follow the object creation chain: Connection → PreparedStatement → ResultSet.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_001", "content": "DriverManager.getConnection() with URL, username, password"}, {"itemId": "ITEM_002", "content": "Connection.prepareStatement() with parameterized SQL"}, {"itemId": "ITEM_003", "content": "PreparedStatement.setString() / setInt() to bind values"}, {"itemId": "ITEM_004", "content": "PreparedStatement.executeQuery() returning ResultSet"}, {"itemId": "ITEM_005", "content": "while(rs.next()) iterating over rows"}], "order": 1, "content": "Reconstruct the correct JDBC execution flow used in PetDB.java — from establishing connectivity to retrieving results.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JDBC Execution Flow", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_008", "knowledgeId": "CONC_003", "maxAttempts": 2, "correctOrder": ["ITEM_001", "ITEM_002", "ITEM_003", "ITEM_004", "ITEM_005"], "feedbackCorrect": "This is the canonical safe, efficient JDBC flow: connect → prepare → bind → execute → iterate.", "feedbackIncorrect": "Remember: Connection creates PreparedStatement, which must be bound *before* execution — and ResultSet requires cursor navigation.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_009", "content": "The JDBC Architecture diagram (CLUE_001) shows arrows flowing downward — follow that direction.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_006", "content": "Java Application (e.g., PetDB)"}, {"itemId": "ITEM_007", "content": "JDBC API (Connection, Statement, ResultSet)"}, {"itemId": "ITEM_008", "content": "DriverManager"}, {"itemId": "ITEM_009", "content": "Database-Specific JDBC Driver"}], "order": 2, "content": "Order these JDBC components by architectural layer — from highest (application-facing) to lowest (database-facing).", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JDBC Layered Architecture", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_009", "knowledgeId": "CONC_007", "maxAttempts": 2, "correctOrder": ["ITEM_006", "ITEM_007", "ITEM_008", "ITEM_009"], "feedbackCorrect": "Correct: Application → JDBC API → DriverManager → Vendor Driver — a clean separation of concerns.", "feedbackIncorrect": "Think of it as a stack: your code sits on top; the driver is the bottom layer talking directly to the DBMS.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "sequencing", "hints": [{"hintId": "HINT_010", "content": "Refer to CHUNK_017: ''public void createPetsTable() {} public ArrayList<Pet> getPets() {} ...''", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_010", "content": "createPetsTable()"}, {"itemId": "ITEM_011", "content": "getPets()"}, {"itemId": "ITEM_012", "content": "addRecord(Pet p)"}, {"itemId": "ITEM_013", "content": "updateRecord(Pet p)"}, {"itemId": "ITEM_014", "content": "deleteRecord(String id)"}], "order": 3, "content": "Arrange the CRUD operations implemented in PetDB.java in the order they appear in the source (CHUNK_017).", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About CRUD Operations", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_010", "knowledgeId": "CONC_011", "maxAttempts": 2, "correctOrder": ["ITEM_010", "ITEM_011", "ITEM_012", "ITEM_013", "ITEM_014"], "feedbackCorrect": "Yes — the source (CHUNK_017) lists them in this exact order: create → retrieve → create (add) → update → delete.", "feedbackIncorrect": "Check CHUNK_017: it starts with createPetsTable(), then getPets(), then addRecord(), etc.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_011", "content": "It''s defined in CHUNK_012: ''? is called ________''", "unlockAfterAttempts": 1}], "order": 4, "content": "In PreparedStatement, the ''?'' symbol is called a ________ — it enables safe parameter binding and prevents SQL injection.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_011", "knowledgeId": "CONC_013", "maxAttempts": 2, "correctAnswers": ["placeholder", "Placeholder"], "feedbackCorrect": "Correct! Placeholders decouple SQL structure from data values — making injection impossible.", "feedbackIncorrect": "It''s the character that marks where dynamic values will be inserted — a fundamental PreparedStatement feature.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_012", "content": "CHUNK_018 shows ''public int getId() { }'' and ''public void setId(int id) { }'' — those are the patterns.", "unlockAfterAttempts": 1}], "order": 5, "content": "The JavaBean class Pet.java follows strict conventions: private fields, public ________ and ________ methods, a no-arg constructor, and Serializable.", "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More About JavaBean Conventions", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_012", "knowledgeId": "CONC_009", "maxAttempts": 2, "correctAnswers": ["getter setter", "setter getter", "getters setters", "Getters Setters"], "feedbackCorrect": "Yes — JavaBeans require public getter/setter methods (e.g., getName(), setName()) to enable framework introspection.", "feedbackIncorrect": "These methods allow frameworks like JDBC mappers to read/write field values without reflection violations.", "nextSceneIdCorrect": "ENDING_001", "nextSceneIdIncorrect": "SCENE_004"}], "characters": [{"age": 32, "goal": "Identify the technical flaw that enabled the crime and expose the perpetrator’s motive.", "name": "Alex Chen", "role": "Detective", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "Once deployed a vulnerable Statement-based query that caused a data leak — now obsessively verifies parameterization.", "background": "Former Java backend developer turned digital investigator; specializes in tracing code-level anomalies in production systems.", "occupation": "Software Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, patient, quietly intense; notices inconsistencies others miss.", "knowledgePoints": ["CONC_001", "CONC_004", "CONC_005"]}, {"age": 47, "goal": "Protect her architectural reputation and prevent discovery of the intentional vulnerability.", "name": "Dr. Lena Rostova", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004"], "secret": "She secretly disabled PreparedStatement precompilation on one critical service to bypass a vendor bug — leaving it vulnerable to injection.", "background": "Designed the ''PetDB'' ORM layer used across campus systems; known for advocating PreparedStatement-only policies.", "occupation": "Lead Database Architect", "characterId": "CHAR_002", "personality": "Precise, uncompromising, deeply protective of system integrity.", "knowledgePoints": ["CONC_005", "CONC_007", "CONC_013"]}, {"age": 39, "goal": "Ship secure, performant CRUD operations without compromising standards.", "name": "Miguel Torres", "role": "Victim", "scenes": ["SCENE_001"], "secret": "He had just committed a patch restoring PreparedStatement precompilation — timestamped minutes before his death.", "background": "Built PetDB.java and Pet.java under Dr. Rostova; discovered the disabled PreparedStatement optimization and planned to report it.", "occupation": "Junior JDBC Developer & ORM Implementer", "characterId": "CHAR_003", "personality": "Idealistic, meticulous, quietly defiant when ethics are at stake.", "knowledgePoints": ["CONC_009", "CONC_010", "CONC_011"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "architecture", "appearsIn": ["SCENE_001", "CLUE_001", "CHAR_001"], "difficulty": 3, "description": "JDBC is a Java API that enables Java applications to interact with relational databases in a vendor-neutral manner. It provides a standardized interface for connecting to, querying, and updating databases through JDBC drivers that translate generic JDBC calls into database-specific protocols.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "component", "appearsIn": ["SCENE_002", "CLUE_005", "CHAR_002"], "difficulty": 4, "description": "A JDBC driver is a Java class that implements the JDBC API to enable communication between a Java application and a specific database management system. It acts as a translation layer, converting JDBC method calls into database-specific network protocols.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_007"]}, {"name": "Connection", "category": "component", "appearsIn": ["SCENE_001", "SCENE_002", "CLUE_002", "CHAR_001"], "difficulty": 3, "description": "A Connection object represents a session between a Java application and a database. It is obtained via DriverManager.getConnection() using database URL, username, and password. The Connection provides factory methods to create Statement, PreparedStatement, and CallableStatement objects.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004", "CONC_005"]}, {"name": "Statement", "category": "component", "appearsIn": ["SCENE_003", "CLUE_007", "CHAR_001"], "difficulty": 3, "description": "A Statement object is used to execute static SQL queries that do not require parameterization. It is created via Connection.createStatement() and supports executeQuery() for SELECT statements (returning ResultSet), executeUpdate() for DML operations (INSERT/UPDATE/DELETE), and execute() for mixed or DDL operations.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_005", "CONC_007"]}, {"name": "PreparedStatement", "category": "component", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_003", "CLUE_004", "CLUE_006", "CHAR_002"], "difficulty": 4, "description": "A PreparedStatement is a precompiled SQL statement that supports parameterized queries using placeholders (''?''). Created via Connection.prepareStatement(), it improves performance by compiling the SQL once and reusing the execution plan across multiple executions with different parameter values. It prevents SQL injection and handles type conversion automatically.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_007", "CONC_013"]}, {"name": "ResultSet", "category": "object", "appearsIn": ["SCENE_003", "CLUE_007", "CHAR_001"], "difficulty": 3, "description": "A ResultSet object represents the tabular results of a database query. It maintains a cursor initially positioned before the first row; the next() method advances the cursor row-by-row. ResultSet provides accessor methods (e.g., getString(), getInt()) to retrieve column values by index or name.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_007"]}, {"name": "JDBC Architecture", "category": "architecture", "appearsIn": ["SCENE_001", "SCENE_004", "CLUE_001", "CHAR_002"], "difficulty": 4, "description": "JDBC architecture consists of four layers: (1) Java Application, (2) JDBC API, (3) JDBC Driver Manager, and (4) Database-specific JDBC Driver. The application uses JDBC API interfaces (Connection, Statement, ResultSet). DriverManager loads and manages drivers, routing calls to the appropriate vendor driver.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "theory", "appearsIn": ["SCENE_003", "CHAR_002"], "difficulty": 4, "description": "ORM is a programming technique that maps object-oriented domain models to relational database schemas. In this context, it refers to a simplified ORM pattern where JavaBean classes (e.g., Pet.java) represent database tables, and DAO classes (e.g., PetDB.java) encapsulate CRUD operations.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010", "CONC_011"]}, {"name": "JavaBean", "category": "object", "appearsIn": ["SCENE_003", "CLUE_003", "CHAR_003"], "difficulty": 2, "description": "A JavaBean is a reusable, serializable Java class following conventions: private fields with public getter/setter methods, a no-argument constructor, and implementation of java.io.Serializable. In JDBC contexts, JavaBeans model database records — each field corresponds to a table column.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_011"]}, {"name": "DAO (Data Access Object)", "category": "pattern", "appearsIn": ["SCENE_003", "CLUE_006", "CHAR_003"], "difficulty": 3, "description": "A DAO is a design pattern that abstracts and encapsulates database access logic. In this material, PetDB.java exemplifies a DAO: it manages database connections, executes CRUD operations on the Pet table, and returns JavaBean instances. DAO separates persistence logic from business logic.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_009", "CONC_011"]}, {"name": "CRUD Operations", "category": "process", "appearsIn": ["SCENE_003", "CLUE_006", "CHAR_003"], "difficulty": 2, "description": "CRUD stands for Create, Retrieve (or Read), Update, and Delete — the four fundamental data manipulation operations supported by persistent storage systems. In JDBC, these map to SQL INSERT, SELECT, UPDATE, and DELETE statements.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_008", "CONC_010", "CONC_005"]}, {"name": "Database URL", "category": "object", "appearsIn": ["SCENE_001", "CLUE_002", "CHAR_001"], "difficulty": 3, "description": "A JDBC database URL is a string that specifies how to connect to a database, following the syntax ''jdbc:subprotocol:subname''. The ''subprotocol'' identifies the driver (e.g., ''mysql'', ''derby''), and ''subname'' contains connection details like host, port, and database name.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Placeholder", "category": "object", "appearsIn": ["SCENE_002", "SCENE_003", "CLUE_003", "CLUE_004", "CHAR_002"], "difficulty": 3, "description": "A placeholder is a ''?'' character in a PreparedStatement SQL string that represents a parameter to be bound at execution time. Placeholders enable safe, efficient parameter substitution without string concatenation. Each placeholder is assigned an integer index starting from 1.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_006"]}], "educational_goals": ["Understand JDBC architecture and its layered components", "Differentiate Statement vs PreparedStatement in execution, security, and performance", "Apply JDBC concepts including Connection, ResultSet, Driver, and URL to diagnose real-world failures"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 3}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'SQL Execution with Statement and PreparedStatement', '2026-04-01 08:51:35.530124', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('f0a3d9e3-c2de-4f89-a130-075e06767a66', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, 'f6254db1-7401-432b-a251-5322a8c1e238', NULL, 'The Database Lockdown: A JDBC Heist', 'active', 'easy', 'standard', '{"clues": [{"name": "JDBC Driver Registration Log Entry", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The system uses explicit driver registration, indicating low-level JDBC control rather than ORM abstraction.", "description": "A log snippet shows the use of Class.forName(''com.mysql.jdbc.Driver'') during system startup. This confirms the JDBC driver was manually loaded, a common practice to ensure availability before connection attempts.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Connection URL Configuration File", "type": "file", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The application connects directly via JDBC using a standard URL format, bypassing ORM tools.", "description": "A configuration file contains the database URL: jdbc:mysql://db-prod.internal:3306/core_data. It also includes placeholder credentials marked ''DO NOT COMMIT''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Raw Statement Usage in Audit Code", "type": "code_snippet", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Legacy code uses non-parameterized queries, making it vulnerable to injection and inefficient for repeated execution.", "description": "A fragment from an old audit module shows Statement stmt = conn.createStatement(); followed by stmt.executeQuery(\"SELECT * FROM logs WHERE user=''\" + username + \"''\");", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "PreparedStatement Template for User Login", "type": "code_snippet", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Critical paths use parameterized queries, suggesting security awareness but highlighting inconsistency with other modules.", "description": "Security-critical login logic uses: PreparedStatement pstmt = conn.prepareStatement(\"SELECT id, role FROM users WHERE email = ? AND hash = ?\");", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_003"]}, {"name": "Failed Connection Stack Trace", "type": "log", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Driver not registered or unavailable for Oracle, causing connection failure despite correct URL syntax.", "description": "Error log: java.sql.SQLException: No suitable driver found for jdbc:oracle://backup.internal:1521/archive. Suggests misconfigured or missing driver for Oracle.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Database Session Metadata Dump", "type": "data_dump", "clueId": "CLUE_B1_006", "foundBy": "CHAR_001", "reveals": "The Connection object was successfully used to retrieve metadata, confirming active session capabilities.", "description": "Metadata retrieved from a live connection shows database product name: MySQL, version 8.0.28, and JDBC driver version: mysql-connector-java-8.0.28.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "ORM Advocacy Email from Dr. Moss", "type": "email", "clueId": "CLUE_B1_007", "foundBy": "CHAR_001", "reveals": "Dr. Moss had strong motivation to discredit JDBC usage, aligning with her secret opposition to current architecture.", "description": "Internal email from Dr. Elena Moss: ''Using raw JDBC is a technical debt time bomb. We must migrate to Hibernate immediately.'' Sent one week before the incident.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_008", "CONC_001"]}, {"name": "Connection Leak Warning in Garbage Collection Logs", "type": "log", "clueId": "CLUE_B1_008", "foundBy": "CHAR_001", "reveals": "Connections are not being closed properly, risking exhaustion and instability.", "description": "GC log entry: ''Possible resource leak: 15 unclosed Connection objects detected over last hour.'' Indicates improper lifecycle management.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "Statement Execution Timeline Report", "type": "report", "clueId": "CLUE_B1_009", "foundBy": "CHAR_001", "reveals": "Use of Statement instead of PreparedStatement leads to inefficiency, supporting Maya Tran''s argument for better query practices.", "description": "Performance report shows that static SQL statements are recompiled on every execution, consuming 40% more CPU than parameterized equivalents.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "Suspicious PreparedStatement Template", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Indicates misuse of PreparedStatement where required parameters were not fully bound, potentially causing system failure.", "description": "A fragment of SQL code recovered from the debug logs shows a parameterized query with unbound placeholders: ''UPDATE access_logs SET status = ? WHERE user_id = ?''. The second parameter was never set before execution.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "JDBC Driver Registration Trace", "type": "log", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Reveals non-standard driver loading behavior that may indicate misconfiguration or tampering.", "description": "System trace shows DriverManager loaded both MySQL and Oracle drivers, but only the MySQL driver was actively used. No Class.forName() call was logged—suggesting an alternative registration method.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007"]}, {"name": "ResultSet Iteration Error in Audit Module", "type": "code", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Explains why recent audit queries failed silently—improper ResultSet handling caused skipped or corrupted records.", "description": "Code review reveals a missing rs.next() check in the audit trail processor. The module attempts to read data without advancing the cursor, violating ResultSet protocol.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Hidden ORM Bypass Flag", "type": "configuration", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Suggests someone with architectural knowledge intentionally disabled safety layers to inject low-level code.", "description": "A hidden flag in the deployment config file disables ORM abstraction for ''emergency direct access'', allowing raw JDBC calls even in ORM-enforced modules.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "Prepared Statement Reuse Pattern", "type": "performance log", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "Demonstrates proper use of PreparedStatement for performance optimization in high-frequency operations.", "description": "Performance logs show one PreparedStatement object being reused 2,147 times over 3 hours with different parameters—indicating correct precompilation and efficiency gains.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Forward-Only ResultSet Assumption", "type": "design doc", "clueId": "CLUE_B2_006", "foundBy": "CHAR_001", "reveals": "Confirms system design aligns with default ResultSet behavior—any attempt to move backward would fail.", "description": "Internal documentation assumes all ResultSets are forward-only and does not request scrollable types. This limits navigation options during forensic query playback.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Layered Architecture Violation", "type": "network trace", "clueId": "CLUE_B2_007", "foundBy": "CHAR_001", "reveals": "Indicates deliberate circumvention of JDBC’s abstraction layer, possibly for testing or sabotage.", "description": "Network packet analysis shows JDBC API calls bypassing DriverManager and communicating directly with a mock driver—breaking the standard architecture model.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007"]}, {"name": "PetDB.java DAO Implementation Snippet", "type": "source code", "clueId": "CLUE_B2_008", "foundBy": "CHAR_001", "reveals": "Shows how simplified ORM patterns are implemented using core JDBC components safely.", "description": "Excerpt from version control shows PetDB.java using PreparedStatement for insertions and ResultSet for retrieval loops—demonstrating ORM-style CRUD encapsulation.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "Malformed Connection URL", "type": "config file", "clueId": "CLUE_B2_009", "foundBy": "CHAR_001", "reveals": "Identifies source of intermittent connection loss due to incorrect JDBC URL syntax.", "description": "An outdated configuration entry uses ''jdbc:mysql://localhost:3306/db'' instead of the required SSL-enabled endpoint, leading to rejected connections.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007", "CONC_012"]}, {"name": "Unreleased ResultSet Handle", "type": "memory dump", "clueId": "CLUE_B2_010", "foundBy": "CHAR_001", "reveals": "Resource leak likely contributed to database pool exhaustion and service degradation.", "description": "Memory snapshot shows 14 open ResultSet objects tied to long-running transactions, indicating poor resource management.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Pet.java JavaBean Definition", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The system uses JavaBeans as data transfer objects between database and business logic layers.", "description": "A code snippet showing the Pet.java class with private fields, public getters/setters, no-argument constructor, and Serializable implementation.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "PetDB.java DAO Interface", "type": "document", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Database operations are abstracted through a DAO pattern to separate persistence from business logic.", "description": "Source code excerpt of PetDB.java showing methods like addRecord(), getPets(), updateRecord(), and deleteRecord().", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_010"]}, {"name": "CRUD Operation Log Entry", "type": "log", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "All four CRUD operations were executed in a standard order before the lockdown occurred.", "description": "System log showing a sequence of operations: ''CREATE pet_id=107'', ''READ pet_id=107'', ''UPDATE pet_id=107 owner=Maria'', ''DELETE pet_id=107''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_011"]}, {"name": "Malformed JDBC URL in Config File", "type": "configuration", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Raj Patel previously used this incorrect URL, which caused earlier outages he tried to hide.", "description": "An outdated connection string found in server config: ''jdbc:mysql://localhost:5432/sample'' — port 5432 is incorrect for MySQL.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_012"]}, {"name": "JavaBean Serialization Flag", "type": "metadata", "clueId": "CLUE_B3_005", "foundBy": "CHAR_001", "reveals": "The Pet model is designed for safe data transfer across network boundaries.", "description": "Bytecode analysis reveals that Pet.class implements java.io.Serializable, confirming it follows JavaBean conventions.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "DAO Abstraction Layer Schematic", "type": "diagram", "clueId": "CLUE_B3_006", "foundBy": "CHAR_001", "reveals": "Direct SQL execution is blocked unless routed through the DAO layer for security and consistency.", "description": "Architecture diagram showing how PetDB acts as an intermediary between application services and raw JDBC calls.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010"]}, {"name": "PreparedStatement Execution Trace", "type": "trace", "clueId": "CLUE_B3_007", "foundBy": "CHAR_001", "reveals": "A non-CRUD operation injected raw SQL outside the DAO, triggering the shutdown mechanism.", "description": "Execution trace shows repeated use of parameterized queries via PreparedStatement, but one call bypasses it using dynamic concatenation.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_011"]}, {"name": "Correct JDBC URL Specification", "type": "configuration", "clueId": "CLUE_B3_008", "foundBy": "CHAR_001", "reveals": "The correct port for MySQL is 3306; deviation indicates misconfiguration or sabotage.", "description": "Validated connection string: ''jdbc:mysql://localhost:3306/sample'' — matches production standards and driver expectations.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_012"]}, {"name": "Suspicious PreparedStatement with Index 1", "type": "code_fragment", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The use of index-based parameter binding in a security-critical context. Proper placeholder usage prevents injection but depends on correct implementation.", "description": "A log excerpt shows a PreparedStatement being executed with setString(1, userInput) where the SQL contains a single ''?'' placeholder. The query was intended to authenticate admin access.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Malformed Query Template in Security Module", "type": "configuration_file", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Evidence that a valid placeholder was used in design, but no corresponding setter method was invoked—suggesting an incomplete or bypassed execution path.", "description": "A configuration file from Maya Tran''s workstation contains a PreparedStatement template: ''SELECT * FROM users WHERE role = ? AND active = 1''. No bound parameters are logged for its execution during the outage.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Hidden Test Flag in PreparedStatement Logic", "type": "debug_log", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "Intentional insertion of a dangerous value into a placeholder-bound parameter, defeating its protective purpose as a security test.", "description": "Debug logs show a conditional block around a PreparedStatement: ''if (TEST_MODE) pstmt.setString(1, \"''\"); // trigger fail''. This code was committed under Maya Tran’s credentials.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013"]}, {"name": "PreparedStatement Reuse Pattern in Audit Trail", "type": "system_log", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "Demonstrates efficient reuse of prepared statements—validating their performance benefit when placeholders are correctly managed.", "description": "Audit records indicate the same PreparedStatement object was reused 247 times over 3 hours with different inputs via setInt() and setString() calls before failure.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}, {"name": "Index Mismatch in Parameter Binding", "type": "error_log", "clueId": "CLUE_B4_005", "foundBy": "CHAR_001", "reveals": "Indicates a developer attempted to bind a value to parameter index 2 despite only one placeholder existing—showcasing misuse of index-based binding.", "description": "An error log reads: ''SQLException: Invalid value for parameter index 2; no second placeholder in SQL''. The associated query is ''DELETE FROM sessions WHERE token = ?''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Security Test Documentation Fragment", "type": "note", "clueId": "CLUE_B4_006", "foundBy": "CHAR_001", "reveals": "Confirms intent behind the placeholder manipulation—to simulate injection through safe mechanisms—but reveals flawed assumptions about system resilience.", "description": "A sticky note found on Maya Tran’s desk reads: ''Test fail-safe: inject single quote via placeholder → should throw exception, not crash DB.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013"]}], "title": "The Database Lockdown: A JDBC Heist", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Locked Server Room", "sceneId": "SCENE_001", "location": "Indoor - Enterprise Data Center Control Room", "description": "The detective arrives at the control room where alarms are flashing. The central database is inaccessible. Three engineers are present, each offering conflicting explanations. Initial clues lie in log entries, connection strings, and recent deployment records.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}, {"act": 2, "clues": [], "order": 2, "title": "Deep Dive into the Logs", "sceneId": "SCENE_002", "location": "Indoor - Secure Debugging Lab", "description": "The detective reviews system logs and code snippets with each suspect. Tensions rise as inconsistencies emerge in their stories. Focus shifts to PreparedStatement misuse, Connection failures, and ORM bypass decisions.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Truth Unfolds", "sceneId": "SCENE_003", "location": "Indoor - Executive Briefing Room", "description": "All suspects gather as the detective presents evidence. A final puzzle reveals how a malicious placeholder in a PreparedStatement triggered the shutdown. Each suspect''s motive and technical footprint are examined.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}], "endings": [{"type": "Correct", "title": "Justice Served: The Security Test Gone Rogue", "content": "The detective reveals that Maya Tran inserted a malicious placeholder in a PreparedStatement intended as a security drill, but it inadvertently locked the entire database. Her intention was to expose vulnerabilities, but the execution breached protocol.", "debrief": "Understanding PreparedStatement and placeholder usage is crucial not only for security but also for system stability. Misuse can lead to unintended consequences even with good intentions.", "summary": "The case closes with Maya accepting responsibility. The team agrees to implement safer testing protocols and improve PreparedStatement validation.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: The Cover-Up Deepens", "content": "The detective wrongly blames Raj for the Connection failure, ignoring the deeper PreparedStatement flaw. Raj is suspended, but the system remains unstable.", "debrief": "Focusing only on surface-level issues like Connection errors without examining query execution can lead to misdiagnosis. A holistic view of JDBC components is essential.", "summary": "The real culprit remains free, and another outage occurs weeks later, revealing the unresolved PreparedStatement vulnerability.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Partial", "title": "Compromise: Shared Blame", "content": "The detective concludes that both Maya’s PreparedStatement and Dr. Moss’s ORM resistance contributed equally. No single person is held fully accountable.", "debrief": "While multiple factors may contribute to a failure, identifying the direct cause—here, the flawed PreparedStatement—is key to resolution.", "summary": "The company adopts a hybrid ORM-JDBC model but fails to enforce secure coding practices, leaving future risks unaddressed.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}], "logline": "In a high-stakes indoor tech summit, a critical enterprise database has been locked down by an unknown insider. The detective must interrogate three suspects—each with deep knowledge of JDBC and data access patterns—to uncover who sabotaged the system and why, using technical clues rooted in Enterprise Systems Development concepts.", "version": "1.0", "evidence": [{"name": "Corrupted Connection Log", "type": "Log File", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A server log showing repeated failed attempts to establish a database connection due to an invalid Database URL.", "foundLocation": "Control Room Terminal", "relatedKnowledge": ["CONC_003", "CONC_012"]}, {"name": "Suspicious PreparedStatement Code", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A fragment of Java code containing a malformed PreparedStatement with an unescaped placeholder that could trigger a denial-of-service condition.", "foundLocation": "Debugging Lab Workstation", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "ORM Bypass Memo", "type": "Internal Document", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "An encrypted memo from Dr. Moss criticizing the use of raw JDBC and proposing forced ORM migration through ''system stress events''.", "foundLocation": "Executive Office Safe", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "ResultSet Timeout Report", "type": "Performance Report", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A report indicating abnormal ResultSet processing times, suggesting inefficient Statement usage.", "foundLocation": "Server Monitoring Dashboard", "relatedKnowledge": ["CONC_004", "CONC_006"]}], "has_quiz": true, "scriptId": "ESD_MYSTERY_01", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the boot sequence logs and finds evidence of Class.forName(''com.mysql.jdbc.Driver''). What does this indicate about the system''s database connectivity approach?", "options": [{"content": "The application uses an ORM framework like Hibernate to abstract database access.", "feedback": "Incorrect. ORM frameworks typically handle driver loading automatically. Explicit Class.forName() calls suggest direct JDBC usage and manual driver registration.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The JDBC driver is being explicitly registered to enable database connections.", "feedback": "Correct. Class.forName() loads the driver class into memory, allowing DriverManager to use it for establishing connections.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "The system is using a connection pool without needing a driver.", "feedback": "Incorrect. Connection pools still require a valid JDBC driver to create physical connections. The driver must be present regardless of pooling.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The database is embedded and does not require external drivers.", "feedback": "Incorrect. Even embedded databases like Derby require their own JDBC drivers. The presence of com.mysql.jdbc.Driver indicates a remote MySQL instance.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Raj Patel claims the connection string ''jdbc:mysql://localhost:3306/billing'' is sufficient to establish a link. Detective Lin knows something is missing. What essential components are required along with the URL?", "options": [{"content": "Driver class name and SSL certificate", "feedback": "Incorrect. While the driver is needed, it''s registered separately. The immediate requirements for getConnection() are URL, username, and password.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Username and password", "feedback": "Correct. DriverManager.getConnection() requires the database URL, username, and password to authenticate and create a session.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "Firewall rules and IP whitelist", "feedback": "Incorrect. Network policies are infrastructure concerns. At the API level, JDBC needs authentication credentials to initiate a connection.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Query timeout and fetch size", "feedback": "Incorrect. These are optional configuration parameters, not mandatory for establishing a basic connection.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin sees a failed connection attempt to ''jdbc:oracle://backup.internal:1521/archive'' with ''No suitable driver found''. What is the most likely cause?", "options": [{"content": "Invalid username or password", "feedback": "Incorrect. Authentication errors would show ''access denied'', not ''no suitable driver''. This points to driver absence, not credentials.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Oracle JDBC driver not loaded or missing from classpath", "feedback": "Correct. The error indicates no registered driver can handle the Oracle URL protocol, meaning the driver JAR is missing or not initialized.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_005"]}, {"content": "Network firewall blocking port 1521", "feedback": "Incorrect. A network block would result in a timeout or connection refused error, not a missing driver message.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Database server is out of disk space", "feedback": "Incorrect. Disk issues would manifest after connection establishment, not prevent driver resolution.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Maya Tran argues that raw SQL strings like ''SELECT * FROM users WHERE id='' + userId are dangerous. What type of JDBC component should replace them for safety?", "options": [{"content": "Connection", "feedback": "Incorrect. Connection establishes the session but doesn''t execute queries. The issue lies in how the SQL is constructed and executed.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Statement", "feedback": "Incorrect. Statement executes static SQL and is exactly what enables injection when concatenated. It should be avoided in favor of safer alternatives.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "PreparedStatement", "feedback": "Correct. PreparedStatement uses placeholders (?) and binds values separately, preventing SQL injection by treating input as data, not code.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_004"]}, {"content": "ResultSet", "feedback": "Incorrect. ResultSet holds query results, not the execution mechanism. It comes after the query runs.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "Dr. Moss insists all database access should go through an ORM layer. How does this relate to JDBC?", "options": [{"content": "ORM replaces JDBC entirely with its own protocol.", "feedback": "Incorrect. ORM frameworks like Hibernate are built on top of JDBC and use it under the hood for actual database communication.", "optionId": "OPT_B1_017", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ORM abstracts JDBC details, generating SQL and managing connections automatically.", "feedback": "Correct. ORM layers sit atop JDBC, handling boilerplate code while relying on JDBC drivers and connections for execution.", "optionId": "OPT_B1_018", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_007"]}, {"content": "JDBC requires ORM to function properly.", "feedback": "Incorrect. JDBC works independently and is often used directly in performance-critical or legacy systems without ORM.", "optionId": "OPT_B1_019", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ORM and JDBC are competing standards for database access.", "feedback": "Incorrect. They operate at different levels. JDBC is a low-level API; ORM is a high-level design pattern that may use JDBC.", "optionId": "OPT_B1_020", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JDBC", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 6, "content": "Detective Lin finds a Connection object being used to retrieve database metadata. Which method call would produce this information?", "options": [{"content": "conn.getMetaData()", "feedback": "Correct. The Connection interface provides getMetaData() to retrieve information about the database, such as version, tables, and supported features.", "optionId": "OPT_B1_021", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_006"]}, {"content": "conn.createMetadata()", "feedback": "Incorrect. There is no createMetadata() method. Metadata is retrieved, not created, via getMetaData().", "optionId": "OPT_B1_022", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "conn.getDatabaseInfo()", "feedback": "Incorrect. This method does not exist in the JDBC API. Use getMetaData() instead.", "optionId": "OPT_B1_023", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "conn.describe()", "feedback": "Incorrect. The describe command is SQL-specific and not part of the Connection interface. Metadata access is standardized via getMetaData().", "optionId": "OPT_B1_024", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_006", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 7, "content": "A developer used Statement.executeUpdate(sql) where sql is built by concatenating user input. What is the primary risk?", "options": [{"content": "Increased memory usage", "feedback": "Incorrect. While inefficient, the main danger is security-related. Concatenated SQL enables injection attacks.", "optionId": "OPT_B1_025", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "SQL injection vulnerability", "feedback": "Correct. Dynamic SQL construction allows malicious input to alter query logic, potentially exposing or destroying data.", "optionId": "OPT_B1_026", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_003"]}, {"content": "Driver incompatibility", "feedback": "Incorrect. The driver handles valid SQL regardless of how it''s built. The issue is semantic, not compatibility.", "optionId": "OPT_B1_027", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Connection timeout", "feedback": "Incorrect. Timeouts depend on network and query execution time, not how the SQL string is assembled.", "optionId": "OPT_B1_028", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_007", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 8, "content": "Why might repeated use of Statement objects with varying parameters be inefficient?", "options": [{"content": "Each execution requires SQL parsing and plan generation", "feedback": "Correct. Unlike PreparedStatement, Statement recompiles the SQL each time, wasting resources when only parameters change.", "optionId": "OPT_B1_029", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_009"]}, {"content": "Statements cannot be cached in memory", "feedback": "Incorrect. Statements are Java objects and reside in memory. The inefficiency is in SQL compilation, not object storage.", "optionId": "OPT_B1_030", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They consume extra network bandwidth", "feedback": "Incorrect. The SQL text size difference is negligible. The cost is server-side parsing, not transmission overhead.", "optionId": "OPT_B1_031", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They require additional authentication", "feedback": "Incorrect. Authentication occurs at connection time. Subsequent queries do not re-authenticate.", "optionId": "OPT_B1_032", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_008", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Call DriverManager.getConnection(url, user, pass)"}, {"itemId": "ITEM_B1_002", "content": "Import java.sql.* and relevant driver package"}, {"itemId": "ITEM_B1_003", "content": "Register driver using Class.forName(driverClassName)"}, {"itemId": "ITEM_B1_004", "content": "Define database URL, username, and password"}], "order": 9, "content": "Detective Lin reconstructs the correct sequence for establishing a JDBC connection. Arrange these steps in order:", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_009", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_001"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Proper setup requires importing packages, registering the driver, defining credentials, then requesting the connection.", "relatedKnowledge": ["CONC_003", "CONC_001"], "feedbackIncorrect": "Incorrect. Remember: import → register driver → define credentials → get connection.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_005", "content": "Execute the SQL command using executeQuery() or executeUpdate()"}, {"itemId": "ITEM_B1_006", "content": "Create a Statement or PreparedStatement object"}, {"itemId": "ITEM_B1_007", "content": "Process the ResultSet (if applicable)"}, {"itemId": "ITEM_B1_008", "content": "Obtain a Connection object"}], "order": 10, "content": "Arrange the typical flow of a JDBC operation after a connection is established:", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_010", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_008", "ITEM_B1_006", "ITEM_B1_005", "ITEM_B1_007"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Sequence is: Connection → Statement → Execution → Result processing.", "relatedKnowledge": ["CONC_004", "CONC_001"], "feedbackIncorrect": "Incorrect. You need a connection first, then create a statement, execute it, and handle results.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_009", "content": "Set parameter values using setString(), setInt(), etc."}, {"itemId": "ITEM_B1_010", "content": "Execute the statement with executeUpdate() or executeQuery()"}, {"itemId": "ITEM_B1_011", "content": "Prepare the SQL with placeholders: ''SELECT * FROM users WHERE id = ?''"}, {"itemId": "ITEM_B1_012", "content": "Obtain a Connection object"}], "order": 11, "content": "Detective Lin reviews secure query practices. Order the steps for safely executing a parameterized query:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_011", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_012", "ITEM_B1_011", "ITEM_B1_009", "ITEM_B1_010"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Secure flow: Connect → Prepare SQL with ? → Bind parameters → Execute.", "relatedKnowledge": ["CONC_005", "CONC_013"], "feedbackIncorrect": "Incorrect. Always start with connection, use placeholders, bind values, then execute.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_013", "content": "Close the Connection object"}, {"itemId": "ITEM_B1_014", "content": "Close the ResultSet (if used)"}, {"itemId": "ITEM_B1_015", "content": "Close the Statement or PreparedStatement"}, {"itemId": "ITEM_B1_016", "content": "Commit or rollback transaction if not auto-commit"}], "order": 12, "content": "To prevent resource leaks, arrange the proper cleanup sequence after database operations:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_012", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_014", "ITEM_B1_015", "ITEM_B1_016", "ITEM_B1_013"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Best practice: close ResultSet → Statement → commit/rollback → Connection.", "relatedKnowledge": ["CONC_004", "CONC_001"], "feedbackIncorrect": "Incorrect. Close result sets and statements first, then handle transaction, then close connection.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_017", "content": "Prevents SQL injection attacks"}, {"itemId": "ITEM_B1_018", "content": "Reduces SQL parsing overhead"}, {"itemId": "ITEM_B1_019", "content": "Enables efficient reuse with new parameters"}, {"itemId": "ITEM_B1_020", "content": "Simplifies complex string concatenation"}], "order": 13, "content": "During the final confrontation, Detective Lin explains why PreparedStatement is superior for repeated queries. Order the reasons by impact:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_013", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_017", "ITEM_B1_018", "ITEM_B1_019", "ITEM_B1_020"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Security is paramount, followed by performance, reusability, and code clarity.", "relatedKnowledge": ["CONC_005", "CONC_013"], "feedbackIncorrect": "Incorrect. Prioritize security (injection prevention), then performance (parsing), reuse, and simplicity.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 14, "content": "The standard Java API for connecting to relational databases is called ________.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_014", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["JDBC", "Java Database Connectivity"], "feedbackCorrect": "Correct. JDBC (Java Database Connectivity) is the standard API for database access in Java.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. The answer is JDBC or Java Database Connectivity.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 15, "content": "To safely include user input in a SQL query, you should use a ________ with placeholders (?) instead of concatenating strings.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Objects", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_015", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["PreparedStatement"], "feedbackCorrect": "Correct. PreparedStatement uses parameter binding to separate code from data, preventing injection.", "relatedKnowledge": ["CONC_005", "CONC_013"], "feedbackIncorrect": "Incorrect. The secure alternative to string concatenation is PreparedStatement.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 16, "content": "The object that represents a session between a Java application and a database is called ________.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_016", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["Connection"], "feedbackCorrect": "Correct. The Connection object manages the session, including transactions, statements, and metadata.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Incorrect. The answer is Connection.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the server''s last executed query. It used a template with ''?'' symbols replaced by actual values at runtime. Which JDBC component enables this secure, efficient pattern?", "options": [{"content": "Statement", "feedback": "Incorrect. Statement executes static SQL strings and concatenates values directly, making it vulnerable to injection and less efficient.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "PreparedStatement", "feedback": "Correct. PreparedStatement uses placeholders (''?'') for parameters, which are bound separately. This prevents SQL injection and allows precompilation for better performance.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "CallableStatement", "feedback": "Close, but CallableStatement is used for stored procedures, not general parameterized queries like this one.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Connection", "feedback": "No. Connection establishes the session but doesn''t handle SQL templates or parameter binding.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "The logs show that SQL queries are compiled once and reused with new parameters hundreds of times. What key advantage does this demonstrate about PreparedStatement?", "options": [{"content": "Automatic transaction rollback", "feedback": "No. Transaction control is managed via Connection.commit() and rollback(), not inherent to PreparedStatement.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "SQL injection prevention and execution plan caching", "feedback": "Correct. PreparedStatement prevents injection by separating code from data and caches the execution plan after first use, improving performance significantly.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_005"]}, {"content": "Dynamic table creation", "feedback": "No. Table creation requires DDL statements and isn''t related to PreparedStatement reuse benefits.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Automatic connection pooling", "feedback": "No. Connection pooling is handled externally or via DataSource, not by PreparedStatement itself.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "To execute a dynamic query with user input safely, which method should be used to bind a string value to a placeholder in a PreparedStatement?", "options": [{"content": "executeQuery(\"value\")", "feedback": "No. This passes raw strings into SQL, defeating the purpose of parameterization and risking injection.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "setString(1, \"value\")", "feedback": "Correct. setString() binds a string parameter to the first placeholder (index 1), ensuring safe insertion without concatenation.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "addParameter(\"value\")", "feedback": "No. There is no such method in JDBC. Parameters are set using type-specific setters like setString(), setInt(), etc.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "bindValue(\"value\")", "feedback": "No. JDBC does not have a bindValue method. Use setXxx() methods based on data type.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Which layer in the JDBC architecture is responsible for loading the appropriate vendor driver and routing database calls?", "options": [{"content": "Java Application", "feedback": "No. The application uses JDBC APIs but doesn’t manage driver selection or translation.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "JDBC API", "feedback": "No. The JDBC API defines interfaces but doesn’t route calls to specific drivers.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "DriverManager", "feedback": "Correct. DriverManager loads registered drivers and selects the appropriate one based on the database URL, acting as a router between the API and driver.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "Database-Specific Driver", "feedback": "No. While the driver performs translation, it’s the DriverManager that chooses and initializes it.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "After executing a SELECT query, what object holds the returned tabular data and allows row-by-row access?", "options": [{"content": "Connection", "feedback": "No. Connection manages the session but doesn’t hold query results.", "optionId": "OPT_B2_017", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Statement", "feedback": "No. Statement sends the query but doesn’t store the returned data.", "optionId": "OPT_B2_018", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "ResultSet", "feedback": "Correct. ResultSet represents the result table from a query and provides methods to navigate and retrieve data row by row.", "optionId": "OPT_B2_019", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_003"]}, {"content": "PreparedStatement", "feedback": "No. While it can return a ResultSet, PreparedStatement itself is for defining and executing parameterized queries.", "optionId": "OPT_B2_020", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 6, "content": "What is the initial position of the cursor in a newly created ResultSet?", "options": [{"content": "On the first row", "feedback": "No. The cursor starts *before* the first row. You must call next() to advance to the first record.", "optionId": "OPT_B2_021", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Before the first row", "feedback": "Correct. The cursor begins positioned before the first row. Calling next() moves it forward and returns true if a row exists.", "optionId": "OPT_B2_022", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_006"]}, {"content": "After the last row", "feedback": "No. That position occurs only after iterating past all rows.", "optionId": "OPT_B2_023", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "At the middle row", "feedback": "No. The cursor has no concept of ''middle'' initially—it starts at the beginning.", "optionId": "OPT_B2_024", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B2_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 7, "content": "Dr. Moss argues that ORM frameworks eliminate the need for manual SQL. How does ORM relate to JDBC?", "options": [{"content": "ORM replaces JDBC entirely", "feedback": "No. ORM frameworks like Hibernate are built *on top of* JDBC—they use it under the hood for database communication.", "optionId": "OPT_B2_025", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ORM abstracts JDBC to automate object-database mapping", "feedback": "Correct. ORM uses JDBC internally but hides low-level details, allowing developers to work with Java objects instead of SQL statements.", "optionId": "OPT_B2_026", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_008"]}, {"content": "JDBC is a subset of ORM functionality", "feedback": "No. It''s the reverse—ORM builds upon JDBC to provide higher-level abstractions.", "optionId": "OPT_B2_027", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ORM and JDBC are unrelated technologies", "feedback": "No. ORM relies on JDBC for actual database connectivity and command execution.", "optionId": "OPT_B2_028", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_007", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 8, "content": "Maya Tran claims her security test used a PreparedStatement to simulate an attack. What makes PreparedStatement effective against SQL injection?", "options": [{"content": "It encrypts the SQL statement", "feedback": "No. Encryption is not involved. The protection comes from structural separation of code and data.", "optionId": "OPT_B2_029", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It separates SQL structure from parameter values", "feedback": "Correct. By predefining the SQL structure and binding parameters separately, PreparedStatement ensures user input cannot alter the intended query logic.", "optionId": "OPT_B2_030", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_001"]}, {"content": "It blocks all external input", "feedback": "No. It allows input but treats it strictly as data, not executable code.", "optionId": "OPT_B2_031", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It runs queries in a sandboxed environment", "feedback": "No. Security comes from syntax separation, not execution isolation.", "optionId": "OPT_B2_032", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_008", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Call prepareStatement(sql) on the Connection"}, {"itemId": "ITEM_B2_002", "content": "Define SQL with placeholders (e.g., ''WHERE id = ?'')"}, {"itemId": "ITEM_B2_003", "content": "Set parameter values using setString(), setInt(), etc."}, {"itemId": "ITEM_B2_004", "content": "Execute the query with executeQuery() or executeUpdate()"}, {"itemId": "ITEM_B2_005", "content": "Obtain a database Connection"}], "order": 9, "content": "Arrange the correct sequence of steps to safely execute a parameterized query using PreparedStatement.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_009", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_005", "ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. This follows the proper flow: establish connection → define parameterized SQL → create PreparedStatement → bind values → execute.", "relatedKnowledge": ["CONC_003", "CONC_004"], "feedbackIncorrect": "Incorrect. Remember: you need a connection first, then define the SQL with ''?'' placeholders, create the statement, bind parameters, and finally execute.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_006", "content": "Java Application"}, {"itemId": "ITEM_B2_007", "content": "JDBC API"}, {"itemId": "ITEM_B2_008", "content": "DriverManager"}, {"itemId": "ITEM_B2_009", "content": "Database-Specific JDBC Driver"}, {"itemId": "ITEM_B2_010", "content": "Relational Database"}], "order": 10, "content": "Order the layers of the JDBC architecture from top (application) to bottom (database).", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_010", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_006", "ITEM_B2_007", "ITEM_B2_008", "ITEM_B2_009", "ITEM_B2_010"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The layered architecture flows from application → API → DriverManager → Vendor Driver → Database.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Incorrect. Think of it as a stack: your app uses JDBC API, which routes through DriverManager to the correct driver, which talks to the database.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_011", "content": "Initialize ResultSet from executeQuery()"}, {"itemId": "ITEM_B2_012", "content": "Use accessor methods like getString() or getInt()"}, {"itemId": "ITEM_B2_013", "content": "Enter while(rs.next()) loop"}, {"itemId": "ITEM_B2_014", "content": "Move cursor to first row with next()"}, {"itemId": "ITEM_B2_015", "content": "Check if more rows exist using next()"}], "order": 11, "content": "Put the standard ResultSet processing loop into the correct order.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_011", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": ["ITEM_B2_011", "ITEM_B2_013", "ITEM_B2_014", "ITEM_B2_012", "ITEM_B2_015"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. You get the ResultSet, enter the loop (which checks and advances), then process each row inside.", "relatedKnowledge": ["CONC_004", "CONC_005"], "feedbackIncorrect": "Incorrect. The while(rs.next()) combines checking and advancing. Inside the loop, you retrieve data for the current row.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_016", "content": "Statement with concatenated strings"}, {"itemId": "ITEM_B2_017", "content": "PreparedStatement with setXxx() methods"}, {"itemId": "ITEM_B2_018", "content": "Stored procedure via CallableStatement"}], "order": 12, "content": "Rank these query execution methods from most to least secure against SQL injection.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_012", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_017", "ITEM_B2_018", "ITEM_B2_016"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. PreparedStatement is most secure due to parameter separation. CallableStatement is also safe when used properly. Concatenated strings are highly vulnerable.", "relatedKnowledge": ["CONC_004", "CONC_013"], "feedbackIncorrect": "Incorrect. Prioritize methods that separate code from data. Concatenation is always risky.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_019", "content": "JavaBean object (e.g., Pet)"}, {"itemId": "ITEM_B2_020", "content": "DAO class (e.g., PetDB)"}, {"itemId": "ITEM_B2_021", "content": "PreparedStatement with UPDATE SQL"}, {"itemId": "ITEM_B2_022", "content": "Database row updated"}, {"itemId": "ITEM_B2_023", "content": "Call updateRecord(pet) on DAO"}], "order": 13, "content": "Order the components involved when a Java app updates a database record using ORM principles.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_013", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": ["ITEM_B2_019", "ITEM_B2_023", "ITEM_B2_020", "ITEM_B2_021", "ITEM_B2_022"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The flow goes: modify object → call DAO method → DAO prepares SQL → execute → database reflects change.", "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": "Incorrect. Start with the object, then trigger the update via DAO, which uses JDBC internally to persist changes.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 14, "content": "In a PreparedStatement, the symbol used to represent a parameter placeholder is: ____", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_014", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["?", "? "], "feedbackCorrect": "Correct. The question mark (?) is used as a placeholder for parameters in PreparedStatement SQL templates.", "relatedKnowledge": ["CONC_013"], "feedbackIncorrect": "Incorrect. The correct symbol is the question mark (?), which acts as a parameter placeholder.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 15, "content": "The method used to advance the cursor to the next row in a ResultSet is: ________", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_015", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["next()", "rs.next()", "resultSet.next()"], "feedbackCorrect": "Correct. The next() method moves the cursor forward and returns true if a row is available.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Use the next() method to move the ResultSet cursor to the next row.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 16, "content": "The JDBC component that maps Java objects to database tables and automates CRUD operations is called: ________", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_016", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["ORM", "Object-Relational Mapping"], "feedbackCorrect": "Correct. ORM (Object-Relational Mapping) abstracts database interactions and maps Java classes to tables.", "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": "Incorrect. The correct term is ORM (Object-Relational Mapping), which simplifies data persistence.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the Pet.java file and notices it has private fields, public getter/setter methods, a no-argument constructor, and implements Serializable. What does this indicate about its role in the system?", "options": [{"content": "It''s a utility class for database connections.", "feedback": "Incorrect. Utility classes don''t typically model data or implement Serializable. This is actually a JavaBean used to represent database records.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It''s a JavaBean serving as a data transfer object (DTO) between the database and application.", "feedback": "Correct. The structure confirms it’s a JavaBean following conventions for use as a DTO in MVC architectures.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "It''s a servlet handling HTTP requests for pet data.", "feedback": "Incorrect. Servlets handle web requests and extend HttpServlet. This class models data, not behavior.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It''s a database trigger written in Java.", "feedback": "Incorrect. Triggers are defined in SQL and run on the DBMS. This is clearly a Java class modeling a record.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Moss argues that direct JDBC usage should be replaced by full ORM tools. She points to PetDB.java, which encapsulates all database interactions. What design pattern does this exemplify?", "options": [{"content": "Factory Pattern", "feedback": "Incorrect. The Factory pattern creates objects; this class manages data access, not instantiation.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Singleton Pattern", "feedback": "Incorrect. While Connection pools often use Singleton, PetDB itself isn’t enforcing single instance creation here.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Data Access Object (DAO) Pattern", "feedback": "Correct. PetDB abstracts CRUD operations and hides SQL details, perfectly illustrating the DAO pattern.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Observer Pattern", "feedback": "Incorrect. Observer deals with event subscription. This is about data persistence abstraction.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About DAO", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Maya Tran explains that every interaction with the Pet table must support basic data manipulation functions. Which set of operations corresponds to these fundamental capabilities?", "options": [{"content": "Encrypt, Decrypt, Hash, Sign", "feedback": "Incorrect. These are cryptographic operations, not core data manipulations.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Create, Read, Update, Delete (CRUD)", "feedback": "Correct. CRUD defines the essential operations for persistent data: Create, Retrieve (Read), Update, Delete.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_003"]}, {"content": "Start, Stop, Pause, Resume", "feedback": "Incorrect. These describe process control, not database record management.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Login, Logout, Register, Verify", "feedback": "Incorrect. These are user authentication actions, unrelated to general data manipulation.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About CRUD", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Raj Patel provides a connection string: ''jdbc:mysql://localhost:3306/sample''. Detective Lin knows this format contains several components. What part specifies the database driver type?", "options": [{"content": "jdbc", "feedback": "Incorrect. ''jdbc'' is the protocol prefix. The subprotocol identifies the driver.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "mysql", "feedback": "Correct. ''mysql'' is the subprotocol identifying the JDBC driver to use for connecting to MySQL.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_004"]}, {"content": "localhost", "feedback": "Incorrect. ''localhost'' is the host address, not the driver identifier.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "sample", "feedback": "Incorrect. ''sample'' is the database name, not the driver type.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Database URLs", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "During forensic analysis, Detective Lin finds that Pet.java implements java.io.Serializable. Why is this important for a JavaBean used in data transfer?", "options": [{"content": "It allows the object to be stored in a relational database directly.", "feedback": "Incorrect. Objects aren''t stored directly; their state is mapped via JDBC or ORM tools.", "optionId": "OPT_B3_017", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It enables the object to be converted into a byte stream for transmission or storage.", "feedback": "Correct. Serialization allows JavaBeans to be safely transferred across networks or saved to files.", "optionId": "OPT_B3_018", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_005"]}, {"content": "It ensures thread safety during concurrent access.", "feedback": "Incorrect. Serialization doesn''t guarantee thread safety; synchronization mechanisms do.", "optionId": "OPT_B3_019", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It validates input data integrity automatically.", "feedback": "Incorrect. Validation must be implemented separately; serialization only handles state conversion.", "optionId": "OPT_B3_020", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 6, "content": "Dr. Moss insists that PetDB.java should be replaced with a full ORM framework. However, what key benefit does the current DAO already provide?", "options": [{"content": "Automatic UI generation", "feedback": "Incorrect. DAO does not generate user interfaces.", "optionId": "OPT_B3_021", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Separation of concerns by isolating database logic from business rules.", "feedback": "Correct. The DAO pattern cleanly separates persistence logic from application logic, improving maintainability.", "optionId": "OPT_B3_022", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_006"]}, {"content": "Real-time data encryption", "feedback": "Incorrect. Encryption is a separate concern not inherently provided by DAO.", "optionId": "OPT_B3_023", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Dynamic query optimization without indexing.", "feedback": "Incorrect. Query optimization depends on DBMS and indexing strategies, not DAO structure.", "optionId": "OPT_B3_024", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About DAO", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_006", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 7, "content": "Detective Lin reviews logs showing INSERT, SELECT, UPDATE, and DELETE statements tied to pet records. What overarching concept do these SQL commands represent?", "options": [{"content": "ACID Properties", "feedback": "Incorrect. ACID refers to transaction guarantees (Atomicity, Consistency, Isolation, Durability).", "optionId": "OPT_B3_025", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "CRUD Operations", "feedback": "Correct. These SQL commands map directly to Create (INSERT), Read (SELECT), Update (UPDATE), Delete (DELETE).", "optionId": "OPT_B3_026", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_007"]}, {"content": "Normalization Forms", "feedback": "Incorrect. Normalization relates to schema design, not individual operations.", "optionId": "OPT_B3_027", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Indexing Strategies", "feedback": "Incorrect. Indexing improves performance but isn''t represented by these command types.", "optionId": "OPT_B3_028", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About CRUD", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_007", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 8, "content": "Raj Patel claims his configuration was never faulty. Detective Lin compares two URLs: ''jdbc:mysql://localhost:3306/sample'' and ''jdbc:mysql://localhost:5432/sample''. What issue does the second URL have?", "options": [{"content": "Wrong protocol prefix", "feedback": "Incorrect. ''jdbc'' is correct. The issue lies in the port number.", "optionId": "OPT_B3_029", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Incorrect port for MySQL (should be 3306)", "feedback": "Correct. Port 5432 is PostgreSQL''s default. MySQL uses 3306, so this would cause connection failures.", "optionId": "OPT_B3_030", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_008"]}, {"content": "Invalid database name", "feedback": "Incorrect. ''sample'' is a valid database name. The problem is the port mismatch.", "optionId": "OPT_B3_031", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Missing username parameter", "feedback": "Incorrect. Username is passed separately to getConnection(); it''s not part of the URL syntax here.", "optionId": "OPT_B3_032", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database URLs", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_008", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Call getPets() method on PetDB instance"}, {"itemId": "ITEM_B3_002", "content": "PetDB establishes a Connection using DriverManager"}, {"itemId": "ITEM_B3_003", "content": "PetDB executes a SELECT query and maps results to Pet objects"}, {"itemId": "ITEM_B3_004", "content": "Application receives ArrayList<Pet> and processes data"}], "order": 9, "content": "Arrange the typical steps a Java application takes when using a DAO to retrieve pet data from the database.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_009", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The DAO pattern flows from client request to connection, query execution, mapping, and return.", "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": "Incorrect. Remember: the client calls the DAO method first, then the DAO handles connection and mapping internally.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_005", "content": "jdbc"}, {"itemId": "ITEM_B3_006", "content": "mysql"}, {"itemId": "ITEM_B3_007", "content": "localhost"}, {"itemId": "ITEM_B3_008", "content": "sample"}], "order": 10, "content": "Order the components of a proper JDBC URL from general to specific.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_010", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": ["ITEM_B3_005", "ITEM_B3_006", "ITEM_B3_007", "ITEM_B3_008"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Format is jdbc:subprotocol:host/database — moving from protocol to vendor to location.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Recall the syntax: ''jdbc:subprotocol:subname'' where subname includes host and database.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_009", "content": "New Pet() instance created"}, {"itemId": "ITEM_B3_010", "content": "Set field values using setters (e.g., setName(''Fluffy''))"}, {"itemId": "ITEM_B3_011", "content": "Pass Pet object to PetDB.addRecord()"}, {"itemId": "ITEM_B3_012", "content": "PetDB extracts data and inserts into database"}], "order": 11, "content": "Put the lifecycle of a JavaBean in the context of a database operation in the correct order.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_011", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_009", "ITEM_B3_010", "ITEM_B3_011", "ITEM_B3_012"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The bean is instantiated, populated, passed to DAO, and persisted.", "relatedKnowledge": ["CONC_011", "CONC_010"], "feedbackIncorrect": "Incorrect. Start with object creation, then population, then DAO invocation, then persistence.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_013", "content": "User submits updated pet information"}, {"itemId": "ITEM_B3_014", "content": "Pet object is constructed with new data"}, {"itemId": "ITEM_B3_015", "content": "PetDB.updateRecord(pet) is called"}, {"itemId": "ITEM_B3_016", "content": "PreparedStatement uses parameterized query to prevent injection"}], "order": 12, "content": "Sequence the steps involved in performing a secure update using CRUD principles and PreparedStatement.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_012", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": ["ITEM_B3_013", "ITEM_B3_014", "ITEM_B3_015", "ITEM_B3_016"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Data flows from user input to object, DAO call, and secure execution.", "relatedKnowledge": ["CONC_005", "CONC_010"], "feedbackIncorrect": "Incorrect. The process starts with user input and ends with secure SQL execution via PreparedStatement.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_017", "content": "Malicious script attempts direct SQL injection bypassing DAO"}, {"itemId": "ITEM_B3_018", "content": "Security layer detects unauthorized query pattern"}, {"itemId": "ITEM_B3_019", "content": "Trigger activates emergency lockdown protocol"}, {"itemId": "ITEM_B3_020", "content": "Database becomes read-only to prevent compromise"}], "order": 13, "content": "Reconstruct the timeline of events leading to the database lockdown based on log evidence.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_013", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": ["ITEM_B3_017", "ITEM_B3_018", "ITEM_B3_019", "ITEM_B3_020"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The attack initiated the chain: detection, response, isolation.", "relatedKnowledge": ["CONC_012", "CONC_010"], "feedbackIncorrect": "Incorrect. The sequence begins with the malicious attempt, followed by detection and automated response.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 14, "content": "A Java class that follows naming conventions, has private fields with public getter/setter methods, a no-argument constructor, and implements Serializable is known as a __________.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_014", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["JavaBean", "bean class"], "feedbackCorrect": "Correct. These conventions define a JavaBean, commonly used as a DTO in JDBC applications.", "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": "Incorrect. Think of a reusable Java class that models data with strict structural rules — it starts with ''Java'' and ends with ''Bean''.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 15, "content": "The design pattern that abstracts database operations like create, read, update, and delete into a dedicated class such as PetDB is called __________.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_015", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DAO", "Data Access Object"], "feedbackCorrect": "Correct. DAO encapsulates data access logic and promotes separation of concerns.", "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": "Incorrect. It stands for Data Access Object — a pattern used to isolate persistence code.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 16, "content": "The acronym CRUD stands for Create, Read, Update, and __________.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_016", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["Delete"], "feedbackCorrect": "Correct. CRUD encompasses the four fundamental operations for managing persistent data.", "relatedKnowledge": ["CONC_010", "CONC_005"], "feedbackIncorrect": "Incorrect. The last letter in CRUD stands for removing a record from the database.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the initial access logs and finds a frequently executed query: ''SELECT balance FROM accounts WHERE id = ?''. What does the ''?'' symbol represent in this context?", "options": [{"content": "A wildcard for pattern matching like LIKE syntax", "feedback": "Incorrect. Wildcards like % are used with LIKE. The ''?'' here is a parameter placeholder, not a search pattern.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A placeholder for a dynamically bound parameter", "feedback": "Correct. In PreparedStatement, ''?'' acts as a placeholder for values safely injected using setter methods like setString().", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_004"]}, {"content": "An indicator of missing data in the database", "feedback": "No. The ''?'' is part of the SQL template, not a representation of missing data in stored records.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A temporary alias for the column name", "feedback": "Not quite. Column aliases use AS or whitespace. The ''?'' is a parameter binding marker, not a naming tool.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 1, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "While examining connection patterns, Detective Lin notices repeated executions of the same SQL structure with varying input. Which feature enables efficient reuse of such queries?", "options": [{"content": "Statement with concatenated strings", "feedback": "This works but is inefficient and unsafe. Each concatenation creates a new SQL string, forcing re-parsing by the DB.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "PreparedStatement with placeholders", "feedback": "Yes. PreparedStatement parses the SQL once and caches the execution plan. Placeholders allow safe, repeated execution with new parameters.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_001"]}, {"content": "Direct JDBC driver call", "feedback": "JDBC drivers handle transport, but efficiency comes from how SQL is structured and sent—not low-level driver access.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "ORM abstraction layer", "feedback": "While ORM can help, it''s not required. PreparedStatement alone provides this optimization at the JDBC level.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 1, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Dr. Moss argues that raw JDBC is outdated. But Detective Lin finds evidence that PreparedStatement effectively prevents SQL injection. How do placeholders contribute to this security?", "options": [{"content": "They encrypt the transmitted data", "feedback": "No. Encryption is handled separately. Placeholders prevent injection by separating code from data structure.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They ensure all inputs are lowercase", "feedback": "Case normalization doesn''t stop injection. Attackers can still embed commands regardless of case.", "optionId": "OPT_B4_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They separate SQL logic from parameter values", "feedback": "Exactly. The database treats the placeholder position as pure data, so even if input contains SQL, it won’t be executed as code.", "optionId": "OPT_B4_011", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_002"]}, {"content": "They limit query length to 255 characters", "feedback": "There''s no inherent length restriction. Security comes from structural separation, not truncation.", "optionId": "OPT_B4_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_B4_003", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Raj Patel claims he never wrote vulnerable code. Detective Lin examines a snippet:\n\nString sql = \"INSERT INTO logs(message, level) VALUES (?, ?)\";\nPreparedStatement ps = conn.prepareStatement(sql);\nps.setString(1, msg);\nps.setString(3, level); // line causing error\n\nWhat is wrong with this code?", "options": [{"content": "The SQL has incorrect syntax", "feedback": "The SQL is valid. Two placeholders are defined correctly with ''?''. Syntax isn''t the issue.", "optionId": "OPT_B4_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Parameter index 3 used but only 2 placeholders exist", "feedback": "Correct. Placeholder indices start at 1 and must match available positions. Only indices 1 and 2 are valid here.", "optionId": "OPT_B4_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_005"]}, {"content": "setString() cannot be used for level field", "feedback": "If ''level'' is text (e.g., ''ERROR''), setString() is appropriate. Type mismatch would depend on schema, not method choice alone.", "optionId": "OPT_B4_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The PreparedStatement wasn''t closed", "feedback": "While resource leaks are bad practice, they don’t cause immediate runtime errors like this. The index mismatch is the direct cause.", "optionId": "OPT_B4_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_B4_004", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "Maya Tran insists her PreparedStatement-based authentication system is secure. Detective Lin asks: ''Which method binds a string value to the first placeholder in a PreparedStatement?''", "options": [{"content": "ps.bind(1, value)", "feedback": "No such method exists. Parameter binding uses type-specific setters like setString().", "optionId": "OPT_B4_017", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ps.setParameter(1, value)", "feedback": "Not a standard method. JDBC uses typed setters (e.g., setString, setInt) based on parameter index.", "optionId": "OPT_B4_018", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "ps.setString(1, value)", "feedback": "Correct. setString(index, value) binds a string to the specified placeholder index, starting from 1.", "optionId": "OPT_B4_019", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_001"]}, {"content": "ps.addValue(value)", "feedback": "No such method. Binding requires both index and type specificity for safety and clarity.", "optionId": "OPT_B4_020", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_B4_005", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 6, "content": "During the final confrontation, Detective Lin reconstructs Maya’s test: she set a placeholder to a single quote (\") using setString(1, \"''\"). Why did this trigger a system crash instead of just failing securely?", "options": [{"content": "Placeholders cannot accept special characters", "feedback": "Incorrect. Placeholders can accept any character, including quotes—they’re designed to handle untrusted input safely.", "optionId": "OPT_B4_021", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The DB driver crashed on malformed UTF-8", "feedback": "Unlikely. A single quote is valid ASCII/UTF-8. Driver crashes are rare and usually not caused by simple characters.", "optionId": "OPT_B4_022", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The application misused the result, assuming success", "feedback": "Yes. Even though PreparedStatement handled the input safely, the app likely didn’t validate the outcome and proceeded with invalid state.", "optionId": "OPT_B4_023", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_003"]}, {"content": "The network dropped packets due to odd byte count", "feedback": "Network issues aren’t tied to specific character content. This is a red herring.", "optionId": "OPT_B4_024", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_006", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 7, "content": "Detective Lin explains: ''You used a placeholder correctly in syntax, Maya, but your test introduced risk.'' What fundamental principle did the test violate?", "options": [{"content": "Never reuse PreparedStatements", "feedback": "False. Reuse is encouraged for performance. The issue wasn’t reuse, but intent and environment control.", "optionId": "OPT_B4_025", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Placeholders should only be used for integers", "feedback": "No. Placeholders support all types via appropriate setters (setString, setInt, etc). Type flexibility is a feature.", "optionId": "OPT_B4_026", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Security tests with live parameters require isolation", "feedback": "Correct. Even safe mechanisms like placeholders shouldn’t be tested with disruptive values in production-like environments.", "optionId": "OPT_B4_027", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_006"]}, {"content": "All queries must have at least two placeholders", "feedback": "No such rule. Queries can have zero, one, or many placeholders depending on need.", "optionId": "OPT_B4_028", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_007", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 8, "content": "To summarize the case, Detective Lin states: ''The placeholder itself wasn’t the flaw—it was how it was used.'' What best describes the role of a placeholder in preventing SQL injection?", "options": [{"content": "It automatically escapes dangerous characters", "feedback": "Not exactly. Escaping is not what happens. Instead, the DB parses the SQL structure first, treating parameters as pure data.", "optionId": "OPT_B4_029", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "It separates SQL code structure from data values", "feedback": "Exactly. The query is compiled before values are inserted, so injected SQL cannot alter execution logic.", "optionId": "OPT_B4_030", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "It blocks user input containing semicolons", "feedback": "No filtering occurs. Even semicolons in data are allowed because they’re treated as literal characters, not command terminators.", "optionId": "OPT_B4_031", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "It encrypts the entire SQL statement", "feedback": "Encryption is unrelated. Protection comes from structural parsing, not secrecy of the SQL.", "optionId": "OPT_B4_032", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Placeholders", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_008", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "Call prepareStatement(sql) on the Connection"}, {"itemId": "ITEM_B4_002", "content": "Define SQL with ''?'' placeholders for parameters"}, {"itemId": "ITEM_B4_003", "content": "Execute the query using executeQuery()"}, {"itemId": "ITEM_B4_004", "content": "Bind actual values using setString(), setInt(), etc."}], "order": 9, "content": "Arrange the steps Detective Lin follows to create and use a secure PreparedStatement for retrieving user data.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 1, "questionId": "Q_B4_009", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_002", "ITEM_B4_001", "ITEM_B4_004", "ITEM_B4_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. First define the parameterized SQL, then prepare it, bind values, and execute.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. Remember: define SQL with ?, prepare it, bind values, then execute.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_005", "content": "Maya configures a PreparedStatement with ''SELECT * FROM admins WHERE token = ?''"}, {"itemId": "ITEM_B4_006", "content": "She sets TEST_MODE = true in the debugging environment"}, {"itemId": "ITEM_B4_007", "content": "Her script calls pstmt.setString(1, \"''\") to simulate injection"}, {"itemId": "ITEM_B4_008", "content": "The query returns no results due to malformed token"}, {"itemId": "ITEM_B4_009", "content": "System fails open and grants access due to null-check bug"}], "order": 10, "content": "Reconstruct the timeline of events leading to the database lockout based on log entries.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B4_010", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_005", "ITEM_B4_006", "ITEM_B4_007", "ITEM_B4_008", "ITEM_B4_009"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence shows how a well-formed PreparedStatement was misused in a flawed testing scenario that exposed downstream logic errors.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Incorrect. Start with PreparedStatement creation, then test mode activation, dangerous binding, failed lookup, and faulty fallback logic.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_010", "content": "String sql = \"DELETE FROM cache WHERE region = ? AND ttl < ?\""}, {"itemId": "ITEM_B4_011", "content": "PreparedStatement ps = conn.prepareStatement(sql)"}, {"itemId": "ITEM_B4_012", "content": "ps.setString(1, \"EU\")"}, {"itemId": "ITEM_B4_013", "content": "ps.setInt(2, 300)"}, {"itemId": "ITEM_B4_014", "content": "ps.executeUpdate()"}], "order": 11, "content": "Order the steps Raj should have taken to properly bind two parameters in a DELETE statement.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B4_011", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_010", "ITEM_B4_011", "ITEM_B4_012", "ITEM_B4_013", "ITEM_B4_014"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Define SQL, prepare statement, bind index 1, bind index 2, then execute.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. Remember: SQL definition → preparation → binding in order → execution.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_015", "content": "Using PreparedStatement with placeholders"}, {"itemId": "ITEM_B4_016", "content": "Escaping all inputs manually before concatenation"}, {"itemId": "ITEM_B4_017", "content": "Allowing direct user input in raw SQL"}, {"itemId": "ITEM_B4_018", "content": "Using stored procedures with input validation"}], "order": 12, "content": "Rank these practices from most to least secure when handling dynamic queries.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B4_012", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_015", "ITEM_B4_018", "ITEM_B4_016", "ITEM_B4_017"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. PreparedStatements are top-tier. Stored procs with validation are strong too. Manual escaping is error-prone. Raw input is worst.", "relatedKnowledge": ["CONC_005", "CONC_004"], "feedbackIncorrect": "Incorrect. Prioritize structural protection (placeholders) over manual checks. Direct input is always weakest.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_019", "content": "Prevents SQL injection attacks"}, {"itemId": "ITEM_B4_020", "content": "Enables query plan caching and reuse"}, {"itemId": "ITEM_B4_021", "content": "Simplifies parameter management without string building"}, {"itemId": "ITEM_B4_022", "content": "Ensures type-safe parameter binding"}], "order": 13, "content": "Arrange the technical advantages of using placeholders in PreparedStatement from most to least impactful.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B4_013", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_019", "ITEM_B4_020", "ITEM_B4_021", "ITEM_B4_022"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Security is paramount, followed by performance, maintainability, and type safety.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. Rank by impact: injection prevention > performance > simplicity > type enforcement.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 14, "content": "In a PreparedStatement, the question mark (?) used in SQL is called a __________.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 1, "questionId": "Q_B4_014", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["placeholder"], "feedbackCorrect": "Correct. The ''?'' symbol is known as a placeholder for parameter binding.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. Think of it as a stand-in for a future value. It''s called a ''placeholder''.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 15, "content": "When using setString(1, value), the number 1 refers to the __________ of the placeholder in the SQL.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B4_015", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["index", "position"], "feedbackCorrect": "Correct. Placeholder indices start at 1 and correspond to the order of ''?'' in the SQL.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. The number indicates the position of the placeholder in the query, starting from 1.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 16, "content": "Although Maya used a placeholder correctly, injecting a single quote via setString() revealed a flaw in the application’s __________ handling.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B4_016", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["error", "exception", "failure", "response"], "feedbackCorrect": "Correct. The real issue wasn''t the placeholder use, but how the system responded to unexpected or invalid outcomes.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Incorrect. Consider what went wrong after the query executed. It was the system''s reaction to failure that caused the crash.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the database lockdown and restore system integrity.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once worked on the same development team as one of the suspects but left due to ethical disagreements.", "background": "A seasoned investigator specializing in software system breaches, known for solving complex code-based crimes.", "occupation": "Cyber Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, detail-oriented.", "knowledgePoints": ["CONC_001", "CONC_007", "CONC_011"]}, {"age": 45, "goal": "Protect her reputation and prevent exposure of her sabotage to push ORM adoption.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Secretly opposed the company''s decision to use raw JDBC instead of full ORM tools.", "background": "Pioneer in ORM frameworks and advocate for abstraction layers between Java and databases.", "occupation": "Lead Architect, Data Access Layer", "characterId": "CHAR_002", "personality": "Confident, intellectual, slightly dismissive of legacy approaches.", "knowledgePoints": ["CONC_008", "CONC_009", "CONC_010"]}, {"age": 32, "goal": "Avoid blame for past mistakes and deflect suspicion onto others.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Made a critical error in the Connection URL that caused prior outages, which he covered up.", "background": "Expert in low-level database connectivity; built the current JDBC driver configuration.", "occupation": "JDBC Integration Engineer", "characterId": "CHAR_003", "personality": "Nervous, technically brilliant, eager to prove himself.", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_012"]}, {"age": 36, "goal": "Convince others it was a controlled test, not an attack.", "name": "Maya Tran", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Inserted a hidden PreparedStatement block that triggered the lockdown as a ''security test'' gone wrong.", "background": "Former hacker turned security expert, focused on preventing SQL injection via PreparedStatement.", "occupation": "Security & Query Optimization Specialist", "characterId": "CHAR_004", "personality": "Sharp, cautious, values security above all.", "knowledgePoints": ["CONC_004", "CONC_005", "CONC_006", "CONC_013"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "Database Connectivity", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A Java API that enables Java applications to interact with relational databases using standard SQL.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "Database Connectivity", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A software component that implements the JDBC interface for a specific database management system.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Connection", "category": "Database Connectivity", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "An object representing a session with a specific database, established via DriverManager or DataSource.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_012"]}, {"name": "Statement", "category": "SQL Execution", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "An interface used to execute static SQL queries against the database.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_005"]}, {"name": "PreparedStatement", "category": "SQL Execution", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A precompiled SQL statement that supports parameterized queries to prevent SQL injection.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_013"]}, {"name": "ResultSet", "category": "Data Retrieval", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "An object that holds the data returned after executing a query, allowing row-by-row traversal.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "JDBC Architecture", "category": "System Design", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "The layered design of JDBC including application, driver manager, driver, and database layers.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "Data Abstraction", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A programming technique to convert data between relational databases and object-oriented models.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "JavaBean", "category": "Data Modeling", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A reusable Java class with private fields, public getters/setters, and a no-arg constructor, often used in ORM.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "DAO (Data Access Object)", "category": "Design Pattern", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A design pattern that abstracts database interactions into dedicated classes for separation of concerns.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_011"]}, {"name": "CRUD Operations", "category": "Data Management", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "Basic functions: Create, Read, Update, Delete, used to manage data in databases.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_010"]}, {"name": "Database URL", "category": "Configuration", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A string specifying the location and type of database to connect to, used in establishing a Connection.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Placeholder", "category": "Security", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A parameter marker (e.g., ''?'') in a PreparedStatement used to safely inject dynamic values.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_011"]}], "educational_goals": ["Understand the core components of JDBC and their roles in database connectivity", "Differentiate between Statement, PreparedStatement, and ResultSet usage", "Apply knowledge of DAO, ORM, and CRUD operations in real-world scenarios", "Trace the flow of JDBC architecture from application to database"], "template_difficulty": {"puzzle_mcq": 30, "puzzle_fill": 10, "puzzle_sorting": 20}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'all concepts', '2026-04-01 10:54:55.837918', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('50a2172f-3274-4072-b2f0-71a8962bdfd2', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '7f23b494-6e79-4a95-81e7-dcf45cafc51b', NULL, 'The Case of the Corrupted Connection', 'active', 'easy', 'standard', '{"clues": [{"name": "Missing JDBC Driver Registration", "type": "code_evidence", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The system failed to locate a suitable JDBC driver because the driver was never registered at runtime.", "description": "A commented-out line in the application startup script reads: ''// Class.forName(\"com.mysql.jdbc.Driver\"); // Disabled for \"modernization\"''. This suggests intentional removal of driver registration, which is required for establishing database connections via DriverManager.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Hardcoded SQL Update Statement", "type": "code_snippet", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The use of Statement with concatenated strings introduces both performance issues and a critical SQL injection vulnerability.", "description": "In the inventory module, a Java method uses Statement to execute a string-concatenated SQL query: ''UPDATE INVENTORY SET QUANTITY = '' + userQty + '' WHERE ITEM_ID = '' + itemId; No parameterization or PreparedStatement used.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "Fragmented SQL Query in Logs", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The application used string concatenation for SQL queries, creating a vulnerability to injection attacks.", "description": "A log entry shows a malformed SQL UPDATE statement with concatenated user input: ''UPDATE users SET role = ''\" + userInput + \"'' WHERE id = 123''. No parameter placeholders are used.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Prepared Statement Usage Pattern", "type": "code", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "The system was designed to support secure parameterized queries, but they were not consistently implemented.", "description": "A commented-out code block reveals the correct use of PreparedStatement: connection.prepareStatement(\"SELECT * FROM pets WHERE owner = ?\"); followed by setString(1, ownerName);", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_013"]}, {"name": "ResultSet Iteration Snippet", "type": "code", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Raj knew the proper way to iterate over a ResultSet, suggesting his mistake was due to time pressure, not lack of knowledge.", "description": "A sticky note on Raj''s desk contains: ''while(rs.next()) { String name = rs.getString(\"name\"); }'' — a correct pattern for processing query results.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006", "CONC_004"]}, {"name": "JDBC Architecture Diagram Draft", "type": "document", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "The system relies on JDBC''s layered architecture for database abstraction and driver management.", "description": "A whiteboard sketch shows four layers: Application → JDBC API → DriverManager → Vendor Driver, with arrows indicating call routing.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007"]}, {"name": "Pet.java JavaBean Definition", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The application uses JavaBeans (specifically Pet.java) as data transfer objects to represent database records in memory, following standard conventions for MVC modeling.", "description": "A source code file defining the Pet class as a JavaBean. It includes private fields for id, name, specie, and owner, along with public getters and setters, a no-argument constructor, and implements Serializable.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "PetDB.java DAO Implementation", "type": "code_file", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The system uses a DAO pattern (PetDB) to abstract CRUD operations from business logic, encapsulating SQL execution and connection management.", "description": "A Java class named PetDB.java that handles all database interactions for the Pet entity. It contains methods such as addRecord(), getPets(), updateRecord(), and deleteRecord(), and manages JDBC connections internally.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "Database URL Configuration Snippet", "type": "log_entry", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The intended database URL was present in early configurations but disabled before launch, contributing to the ''No suitable driver found'' error when fallback paths were removed.", "description": "A configuration entry found in the deployment script: ''jdbc:mysql://localhost:3306/inventory''. This was used in DriverManager.getConnection() calls but commented out during final build.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_012"]}, {"name": "Fragmented SQL Log Entry", "type": "digital", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The system was designed to use safe parameter binding via PreparedStatement, suggesting that any injection vulnerability stems from deviation from this pattern.", "description": "A partial log from the application server shows a PreparedStatement with placeholders (''?'') used in a user authentication query. The structure indicates parameterized input was intended, but no bound values are logged.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Code Comment from Raj''s JDBC Module", "type": "document", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Raj attempted to follow secure coding practices by using placeholders, but may not have fully understood how to bind parameters correctly.", "description": "In the version control history, Raj added a comment: ''// Using ? placeholders – Elena said raw strings are dangerous. Hope this is enough.'' This appears just before committing the login validation code.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}], "title": "The Case of the Corrupted Connection", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash at Demo Hour", "sceneId": "SCENE_001", "location": "Enterprise Development Lab", "description": "During a live demo of the new inventory management system, the application crashes with a ''No suitable driver found'' error. Logs show incomplete connection setup. Detective Lin arrives to investigate what went wrong—and whether someone tampered with the system.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Review Under Pressure", "sceneId": "SCENE_002", "location": "Secure Code Audit Room", "description": "Lin examines the source code repository and configuration files. Both suspects are questioned separately while evidence is analyzed. A suspicious SQL query using string concatenation is found, along with a missing DAO implementation for user authentication.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Truth in Transactions", "sceneId": "SCENE_003", "location": "Server Monitoring Room", "description": "All parties gather as Lin reconstructs the sequence of events. Real-time logs reveal an unhandled exception in the JDBC Connection lifecycle, triggered by malformed input. The team must now face who bypassed security protocols—and why the safeguards failed.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Justice Through JDBC", "content": "The investigation concludes that Raj''s use of unsafe Statement concatenation allowed malicious input to crash the connection, while Elena''s removal of fallback paths amplified the failure. Both share responsibility.", "debrief": "Best practices require both secure coding (PreparedStatement) and resilient architecture (DAO fallbacks). Neither abstraction nor raw access alone ensures safety.", "summary": "The corruption stemmed from combining poor JDBC practices with rigid architectural decisions. Education on balanced enterprise design prevents such failures.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame Assigned, Lesson Lost", "content": "Detective Lin blames Dr. Moss entirely, believing ORM should have prevented all issues. The root cause in the application layer remains unaddressed.", "debrief": "ORM tools help but do not eliminate the need for secure JDBC practices. Understanding底层 mechanisms is essential even with abstractions.", "summary": "Over-reliance on frameworks without understanding underlying JDBC risks leads to unresolved vulnerabilities.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Scapegoat Syndrome", "content": "Raj is fired for bad code, but the team ignores Elena''s decision to disable monitoring and rollback features in the name of ''clean architecture''.", "debrief": "Systemic failures require systemic analysis. Isolating individual mistakes without examining design choices leads to repeated errors.", "summary": "True enterprise resilience comes from integrating secure coding, robust patterns, and fault-tolerant design.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes software development lab, a critical database connection fails during a live demo—was it sabotage? Players step into the shoes of a detective and two suspects to uncover how JDBC components were manipulated, exposing vulnerabilities in enterprise system design.", "version": "1.0", "evidence": [{"name": "Crash Log Excerpt", "type": "Log File", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Shows ''java.sql.SQLException: No suitable driver found for jdbc:mysql://localhost:3306/inventory''", "foundLocation": "Development Server Terminal", "relatedKnowledge": ["CONC_002", "CONC_012"]}, {"name": "Unsafe Query Snippet", "type": "Code Fragment", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Java code using Statement with string concatenation: \"SELECT * FROM users WHERE id = \" + userId", "foundLocation": "Version Control System - Recent Commit", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_013"]}, {"name": "Missing DAO Implementation", "type": "File Artifact", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "UserDAO.java file is present but contains only stub methods without actual JDBC logic.", "foundLocation": "Source Code Directory", "relatedKnowledge": ["CONC_010", "CONC_008"]}], "has_quiz": true, "scriptId": "ESD_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash log showing ''No suitable driver found''. She suspects the root cause lies in how the application connects to the database. Based on the error and JDBC fundamentals, what is the most likely missing step during initialization?", "options": [{"content": "The Connection URL syntax was incorrect, preventing proper parsing.", "feedback": "While an invalid URL can cause connection failures, the specific error ''No suitable driver found'' points to driver registration—not URL formatting—as the primary issue. The DriverManager cannot proceed without a registered driver.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The JDBC driver class was not loaded or registered using Class.forName() or System.setProperty().", "feedback": "Correct. The JDBC driver must be explicitly registered so that DriverManager can locate it. Without this step, no connection can be established regardless of correct credentials or URL.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "The database server was offline or unreachable due to network issues.", "feedback": "Network outages would typically result in timeout or connection refused errors—not ''No suitable driver found''. This error occurs before any network attempt, during driver lookup.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin discovers a code snippet that executes SQL updates using Statement instead of PreparedStatement. Why is this a problematic design choice from both security and performance standpoints?", "options": [{"content": "Statement objects cannot execute UPDATE queries—only SELECT statements are supported.", "feedback": "Incorrect. Statement objects support all SQL types via executeUpdate() and execute(). The limitation isn''t functionality, but efficiency and safety when reusing queries with different parameters.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Each execution compiles the SQL anew, making it inefficient for repeated calls, and leaves the application vulnerable to SQL injection attacks.", "feedback": "Exactly right. Unlike PreparedStatement, Statement does not reuse execution plans and allows raw string concatenation, opening the door to malicious input manipulation and slower performance over multiple executions.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_002"]}, {"content": "Statement requires manual transaction management, while PreparedStatement handles commits automatically.", "feedback": "Both Statement and PreparedStatement require explicit transaction control via Connection.commit() or rollback(). Transaction behavior is independent of the statement type used.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Statement Usage", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash logs and finds a dangerous SQL pattern: ''UPDATE accounts SET balance = '' + amount + '' WHERE user = \"'' + username + \"\". What is the most effective way to prevent this vulnerability?", "options": [{"content": "Use PreparedStatement with parameter placeholders (?) to separate SQL logic from data.", "feedback": "Correct. PreparedStatement precompiles the SQL and uses type-safe setters, preventing injection by treating inputs as data, not executable code.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_002"]}, {"content": "Switch to using Statement objects with manual input escaping.", "feedback": "Incorrect. Manual escaping is error-prone and inconsistent. PreparedStatement is the standard solution for dynamic queries.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Store all queries in external files to hide them from attackers.", "feedback": "Incorrect. Externalizing queries doesn''t prevent injection if dynamic parts are still concatenated unsafely.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Disable all UPDATE operations during peak hours.", "feedback": "Incorrect. This would break core functionality. The issue is not the operation type, but how it''s constructed.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About PreparedStatement", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin examines a code snippet that retrieves pet records: it calls executeQuery() and gets a ResultSet. The cursor starts before the first row. Which loop structure correctly processes all rows?", "options": [{"content": "while (rs.next()) { /* process row */ }", "feedback": "Correct. The next() method advances the cursor and returns false when past the last row, making this the standard iteration pattern.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "for (int i = 0; i < rs.size(); i++) { rs.get(i); }", "feedback": "Incorrect. ResultSet does not have a size() method. You must use next() to advance through rows.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "do { /* process row */ } while (rs.hasNext());", "feedback": "Incorrect. There is no hasNext() method in ResultSet. Use next() which both advances and checks existence.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "while (rs.hasNextRow()) { rs.moveToNext(); }", "feedback": "Incorrect. These methods do not exist in the JDBC API. Use rs.next() for both checking and advancing.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About ResultSet", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the Pet.java file and notices it follows specific design rules: private fields, public getter/setter methods, a no-argument constructor, and implements Serializable. What is the purpose of this structure in the JDBC workflow?", "options": [{"content": "To allow automatic mapping between database rows and Java objects as Data Transfer Objects (DTOs).", "feedback": "Correct. JavaBeans like Pet.java serve as DTOs that model database records, enabling clean separation between data storage and business logic in an MVC architecture.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_001"]}, {"content": "To enforce thread safety during concurrent database access.", "feedback": "Incorrect. While thread safety is important, JavaBean conventions themselves do not provide thread safety. Their primary role here is data representation and transfer.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "To optimize SQL query parsing by reducing string concatenation overhead.", "feedback": "Incorrect. Query optimization is handled by PreparedStatement, not JavaBean structure. JavaBeans are about data modeling, not SQL performance.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin discovers a class called PetDB.java that manages all interactions with the Pet table—handling inserts, queries, updates, and deletes. It uses Connection and PreparedStatement objects internally but exposes only high-level methods like addRecord() and getPets(). What design pattern does this represent, and why is it used?", "options": [{"content": "DAO pattern—it separates data access logic from business logic, improving maintainability and testability.", "feedback": "Correct. The DAO pattern abstracts database operations behind an interface, allowing changes to the persistence layer without affecting other components. This supports separation of concerns and makes testing easier.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_002"]}, {"content": "Singleton pattern—it ensures only one instance of the database connection exists across the application.", "feedback": "Incorrect. While connection pooling may use singletons, the description matches DAO, which focuses on abstraction of CRUD operations, not object instantiation control.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Factory pattern—it dynamically creates different types of database drivers based on environment settings.", "feedback": "Incorrect. Driver creation might use factory patterns, but PetDB''s role is managing data operations—not creating objects. This is characteristic of the DAO pattern.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About DAO Pattern", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the suspicious SQL query found in the audit logs. It uses a PreparedStatement with question marks (?). What role do these symbols play in preventing SQL injection?", "options": [{"content": "They act as index-based parameter placeholders that are safely bound using setter methods like setString(), preventing direct string concatenation.", "feedback": "Correct. The ''?'' characters are placeholders assigned indices starting at 1. Values are bound via setter methods (e.g., setString(1, value)), which ensures input is treated as data—not executable code—thwarting SQL injection attempts.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_001"]}, {"content": "They represent optional query conditions that can be toggled on or off depending on user input.", "feedback": "Incorrect. Placeholders (''?'') are not conditional flags. They are strictly for parameter binding and must be paired with corresponding setter calls to pass safe values into the query.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "They allow the database to auto-detect and sanitize malicious input during parsing.", "feedback": "Incorrect. The database does not automatically detect or sanitize inputs based on ''?''. Security comes from the application properly binding values through PreparedStatement setter methods, not from passive detection.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin examines Raj’s code and sees a line: pstmt.setString(2, username). What does the number ''2'' signify in this context?", "options": [{"content": "It refers to the second column in the result set being updated.", "feedback": "Incorrect. The index in setString() refers to the position of the placeholder (''?'') in the SQL string, not the result set columns.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "It identifies the second parameter placeholder (?) in the prepared SQL statement, ensuring the username is bound to the correct position.", "feedback": "Correct. The integer specifies the index of the placeholder in the SQL query (starting from 1). This ensures the value is securely bound to the right parameter location, maintaining query integrity and safety.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_002"]}, {"content": "It sets the command timeout to 2 seconds for this execution.", "feedback": "Incorrect. Timeout settings are controlled by separate methods like setQueryTimeout(). The first argument in setter methods like setString() always refers to the placeholder index.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the corrupted database connection and prevent future exploits.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once wrote flawed JDBC code that caused a production outage; keeps it hidden to protect reputation.", "background": "A seasoned investigator specializing in software system breaches and code-level anomalies.", "occupation": "System Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical in reasoning.", "knowledgePoints": ["CONC_001", "CONC_007", "CONC_011"]}, {"age": 45, "goal": "Protect her architectural vision and avoid blame for the system failure.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She intentionally disabled the raw JDBC fallback path during deployment to force adoption of her ORM framework.", "background": "Designed the ORM layer used in the project; advocates for abstraction over raw JDBC.", "occupation": "Lead Architect", "characterId": "CHAR_002", "personality": "Confident, idealistic, dismissive of legacy patterns like direct JDBC usage.", "knowledgePoints": ["CONC_008", "CONC_009", "CONC_010"]}, {"age": 29, "goal": "Avoid being fired for using unsafe coding practices.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Used string concatenation instead of PreparedStatement to meet deadline, leaving SQL injection vulnerability.", "background": "Responsible for writing the JDBC interaction code; under pressure to deliver quickly.", "occupation": "Junior Developer", "characterId": "CHAR_003", "personality": "Nervous, eager to please, prone to cutting corners when stressed.", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_012", "CONC_013"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "Database Access", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "A Java API that enables Java applications to interact with relational databases using SQL.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "Database Access", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A database-specific implementation of the JDBC API that allows Java to connect to a particular DBMS.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Connection", "category": "Database Access", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "An interface representing a session with a specific database, required for executing SQL statements.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_004", "CONC_012"]}, {"name": "Statement", "category": "Database Access", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "An object used to send SQL statements to the database; can be vulnerable to injection if not handled properly.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "PreparedStatement", "category": "Database Access", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "A precompiled SQL statement that uses placeholders to safely pass parameters and prevent SQL injection.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_013"]}, {"name": "ResultSet", "category": "Database Access", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "An object that holds the data returned from a database query after execution of a Statement or PreparedStatement.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_005"]}, {"name": "JDBC Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "The layered structure consisting of the JDBC API and JDBC Driver Manager that connects Java apps to databases.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Object-Relational Mapping (ORM)", "category": "Data Abstraction", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 4, "description": "A programming technique to convert data between relational databases and object-oriented models.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "JavaBean", "category": "Data Abstraction", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A reusable Java component with private fields, public getters/setters, and a no-arg constructor, often used in ORM.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "DAO (Data Access Object)", "category": "Design Pattern", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 4, "description": "A design pattern that abstracts database interactions into separate classes, promoting separation of concerns.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_011"]}, {"name": "CRUD Operations", "category": "Operations", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Basic functions: Create, Read, Update, Delete, implemented via JDBC or DAO methods.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_010"]}, {"name": "Database URL", "category": "Configuration", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A string specifying the location of the database, including protocol, subprotocol, and address.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "Placeholder", "category": "Security", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "A marker (e.g., ''?'') in a PreparedStatement used to securely insert dynamic values into SQL queries.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005", "CONC_011"]}], "educational_goals": ["Understand the core components of JDBC and their roles in database connectivity", "Explain the purpose and advantages of PreparedStatement and placeholders in SQL queries", "Apply knowledge of DAO pattern and ORM to secure and streamline data access", "Diagnose common failures in JDBC architecture through real-world debugging scenarios"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 0, "puzzle_sorting": 0}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'all concepts', '2026-04-01 11:19:40.936464', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('bacb4265-62ba-4226-9dd8-b0f6fd3e5f2c', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '7f23b494-6e79-4a95-81e7-dcf45cafc51b', NULL, 'The Missing Connection: A Database Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "Flickering Server Log Entry", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The system attempted to load a JDBC driver that was either missing or improperly registered.", "description": "A cached log snippet recovered from the primary server showing ''ClassNotFoundException: com.mysql.jdbc.Driver'' during startup sequence.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Driver Registration Comment", "type": "code", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The JDBC driver registration was intentionally disabled in code, possibly without ensuring alternative mechanisms were in place.", "description": "A commented-out line in the legacy data access module: ''// Class.forName(\"com.mysql.jdbc.Driver\"); // Deprecated - remove before prod''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Fragments of a PreparedStatement", "type": "digital_artifact", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The system attempted to execute a parameterized query via PreparedStatement, suggesting dynamic data input was involved prior to the failure.", "description": "A partially recovered code snippet from the crash dump shows a parameterized SQL update using placeholders (?). The method calls setInt() and setString() before execution, indicating use of PreparedStatement for safety and efficiency.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "ResultSet Iteration Pattern in Logs", "type": "log_excerpt", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "The application was mid-iteration over a ResultSet when the connection failed, implying an open result set was being read during the outage.", "description": "Server logs contain a recurring Java loop pattern: ''while (rs.next()) { ... }''. Inside, accessor methods like getString(''name'') are used to extract pet data, confirming ResultSet was actively processing query results at time of crash.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "JDBC Architecture Diagram Draft", "type": "handwritten_note", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Dr. Moss understood the layered nature of JDBC but may have underestimated how her ORM changes affected lower-level driver dependencies.", "description": "A whiteboard sketch found near Dr. Moss''s desk outlines four layers: Application → JDBC API → DriverManager → Vendor Driver. Arrows show DriverManager routing connections based on URL subprotocol.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Pet.java Source Code Fragment", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Reveals the use of JavaBean conventions to model database records as reusable data transfer objects.", "description": "A partial Java class file found in the version control history. It defines a class named ''Pet'' with private fields (id, name, specie, owner), public getters/setters, a no-argument constructor, and implements Serializable.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "PetDB.java Method Signatures", "type": "document", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Indicates the use of a DAO pattern to encapsulate database operations and separate persistence logic from business rules.", "description": "Extracted interface of PetDB.java showing method declarations: getPets(), addRecord(Pet p), updateRecord(Pet p), deleteRecord(String id). No SQL statements visible—abstraction is evident.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "Database URL Configuration Note", "type": "note", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Explains why the JDBC connection failed—DevOps disabled a legacy URL still required due to incomplete ORM transition.", "description": "A sticky note discovered near Raj’s workstation: ''Disabled jdbc:mysql://legacy-db.internal:3306/sample – outdated driver, security risk. Assumed ORM migration completed.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_012"]}, {"name": "Fragmented PreparedStatement Code", "type": "digital", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "Dr. Moss was aware of secure parameter binding practices but may have failed to ensure their implementation after removing JDBC code.", "description": "A partially deleted code snippet recovered from Dr. Moss''s workstation shows a SQL update using ''?'' placeholders and setString() calls. The comment above reads ''// Safe binding - prevents injection''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Failed Connection Log Entry", "type": "log", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "The system attempted to run a parameterized query without properly binding values, indicating a gap in configuration or execution logic.", "description": "System logs from the crash time show repeated attempts to execute a prepared statement with unbound parameters. Error: ''No value specified for parameter 1''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}], "title": "The Missing Connection: A Database Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Site", "sceneId": "SCENE_001", "location": "Server Room B", "description": "The team arrives at the locked server room where Dr. Moss was found unconscious. Lights flicker. The primary database server displays a fatal connection error. Logs show failed attempts to load a JDBC driver.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Repository Audit", "sceneId": "SCENE_002", "location": "Development Office", "description": "Players examine recent commits in the version control system. A controversial pull request removed direct JDBC usage in favor of an ORM framework. Tensions rise as coding philosophies clash.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Connection Test", "sceneId": "SCENE_003", "location": "Testing Lab", "description": "All characters gather as the detective reconstructs the sequence of failures. A live test environment simulates the crash. The truth emerges through configuration gaps and conflicting priorities.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Unlocked: The System Failure Explained", "content": "The crash resulted from a cascade: Raj removed the driver believing it was obsolete, while Elena''s ORM refactor lacked proper fallbacks. The hardcoded URL had no port, and no validation existed. Together, these created a fatal blind spot.", "debrief": "Both overconfidence in abstraction and rigid adherence to cleanup protocols contributed. Proper integration testing and monitoring could have prevented this.", "summary": "The real villain was incomplete coordination between infrastructure and development teams.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: Blame Assigned Without Full Context", "content": "You accused Raj alone for removing the driver. While his action triggered the crash, you ignored Elena''s removal of safety-net JDBC code and the invalid URL.", "debrief": "System failures are rarely due to one person. Always trace the full chain of dependencies and assumptions.", "summary": "Incomplete analysis leads to unfair blame and recurring issues.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes software development lab, the lead developer is found unconscious beside a corrupted database server. Players must uncover how the JDBC connection failed and who sabotaged the system by investigating clues tied to core database connectivity concepts.", "version": "1.0", "evidence": [{"name": "Missing JDBC Driver JAR", "type": "Digital Artifact", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "The mysql-connector-java.jar file is absent from the deployment directory despite being listed in dependencies.", "foundLocation": "Server Room B", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Deleted JDBC Code Commit", "type": "Version Control Log", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A recent commit titled ''Remove legacy JDBC - switch to ORM'' deleted all direct Connection and Statement usage.", "foundLocation": "Development Office", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"]}, {"name": "Hardcoded Database URL", "type": "Configuration File", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "The application.properties file contains a malformed URL missing the port number, causing connection refusal.", "foundLocation": "Testing Lab", "relatedKnowledge": ["CONC_012", "CONC_003"]}], "has_quiz": true, "scriptId": "DBCONN_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash logs and sees repeated ''No suitable driver found'' errors. She knows the application relies on JDBC for database access. What is the primary role of a JDBC driver in this context?", "options": [{"content": "To provide a standardized API for writing portable SQL queries across databases.", "feedback": "That describes the purpose of the JDBC API itself, not the driver. The driver implements this API for a specific database.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "To act as a translation layer between JDBC method calls and the database''s native protocol.", "feedback": "Correct. A JDBC driver translates generic JDBC calls into database-specific network protocols, enabling Java applications to communicate with a particular DBMS.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "To manage connection pooling and optimize resource usage across threads.", "feedback": "Connection pooling is typically handled by external libraries or application servers, not the core responsibility of a JDBC driver.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "To encrypt all data transmitted between the application and the database.", "feedback": "While secure connections can be established using SSL/TLS, encryption is not the primary function of a JDBC driver.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JDBC Drivers", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "While auditing the version control history, Detective Lin finds a commit that removed explicit driver registration via Class.forName(). She needs to determine how a Connection object is obtained in JDBC. Which method is used to establish a database connection using the DriverManager?", "options": [{"content": "Connection.createInstance(url, user, pass)", "feedback": "There is no static createInstance method on the Connection interface. Connections are obtained through the DriverManager.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "DriverManager.getConnection(url, username, password)", "feedback": "Exactly. The DriverManager.getConnection() method uses the provided URL, username, and password to locate a suitable driver and establish a Connection object representing the session with the database.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_002"]}, {"content": "Database.connect(url, credentials)", "feedback": "This is not part of the standard JDBC API. The official mechanism goes through DriverManager or a DataSource.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "JDBCSession.open(url, auth)", "feedback": "There is no such class as JDBCSession in the core JDBC specification. The correct entry point is DriverManager.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Database Connections", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the last known SQL operation before the crash. The log shows a precompiled statement with ''?'' placeholders and setter methods. Which JDBC component is best suited for this secure, reusable query pattern?", "options": [{"content": "Statement – ideal for static queries without parameters.", "feedback": "Incorrect. While Statement can execute SQL, it doesn''t support parameterization or precompilation. Using it for dynamic queries increases SQL injection risk and reduces performance due to repeated parsing.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "PreparedStatement – designed for parameterized, reusable queries with automatic escaping.", "feedback": "Correct. PreparedStatement compiles the SQL once and reuses the execution plan. It safely binds parameters using setters like setString(), preventing SQL injection and improving performance—exactly what the logs show.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "CallableStatement – used only for stored procedures.", "feedback": "Incorrect. CallableStatement is for executing database stored procedures, not general parameterized queries. The log shows a standard UPDATE, not a procedure call.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Connection – responsible for creating statements, not executing them.", "feedback": "Incorrect. Connection is used to create a PreparedStatement via prepareStatement(sql), but it does not handle parameter binding or execution itself.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About PreparedStatement", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "While auditing recent code, Detective Lin finds a loop structure that processes database results row by row. The cursor starts before the first row and advances with next(). Which JDBC object represents this tabular data and iteration model?", "options": [{"content": "ResultSet – holds query results and supports forward-only traversal via next().", "feedback": "Correct. ResultSet is the standard object for holding tabular query results. Its cursor must be advanced with next() before reading data, and it provides accessor methods like getString() to retrieve column values.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_002"]}, {"content": "PreparedStatement – used to execute queries, not store results.", "feedback": "Incorrect. PreparedStatement executes parameterized queries and returns a ResultSet. It does not represent the data itself or allow row-by-row iteration.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Connection – manages the session, not the result data.", "feedback": "Incorrect. Connection is the session interface used to create statements and manage transactions. It does not hold or iterate over query results.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "DatabaseMetaData – describes database structure, not runtime data.", "feedback": "Incorrect. DatabaseMetaData provides schema information (tables, columns, drivers), not actual query result rows. It’s useful for introspection, not data processing.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About ResultSet", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the codebase and finds Pet.java—a simple class with private fields, public getters/setters, a no-arg constructor, and Serializable implementation. ''This isn’t just a model,'' she mutters. ''It’s following a specific design convention for data interchange.''\n\nWhat is the correct term for this type of class in Java?", "options": [{"content": "Entity Bean", "feedback": "Close, but Entity Beans are part of older EJB specifications. The class here follows simpler, lightweight conventions without container dependency.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "JavaBean", "feedback": "Correct. A JavaBean is a serializable class with private fields, public getters/setters, and a no-argument constructor—perfect for modeling database records like Pet.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_001"]}, {"content": "POJO", "feedback": "While technically true (it''s a Plain Old Java Object), POJO is too broad. The presence of serialization and getter/setter conventions specifically identifies it as a JavaBean.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "DTO Interface", "feedback": "Incorrect. This is a concrete class, not an interface, and while it serves as a DTO, the structural pattern matches JavaBean standards exactly.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_008"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin reviews PetDB.java and notices methods like addRecord(), getPets(), updateRecord(), and deleteRecord(). These don’t expose any SQL—they return JavaBeans and handle connections internally.\n\n''So this layer hides the database details,'' she reasons. ''It’s enforcing separation between data access and business logic.''\n\nWhich design pattern does this represent?", "options": [{"content": "Service Locator", "feedback": "No. Service Locator helps find services at runtime, but doesn’t abstract data operations. This code clearly manages direct database interactions.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Factory Method", "feedback": "Incorrect. Factory patterns create objects, but here we’re dealing with data persistence operations, not object instantiation strategies.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Data Access Object (DAO)", "feedback": "Exactly. The DAO pattern encapsulates all database CRUD operations, providing a clean API while hiding SQL and connection logic—just like PetDB.java does.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_002"]}, {"content": "Observer Pattern", "feedback": "No. Observer establishes a one-to-many dependency between objects. There’s no event notification mechanism shown here—only direct data manipulation.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About DAO Pattern", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_001", "content": "Look at how PreparedStatement handles parameters. Each ''?'' must be matched with a setter method before execution.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Detective Lin reviews the crash logs and finds an error: ''No value specified for parameter 1'' during a PreparedStatement execution. What does this indicate about the use of placeholders in the failing query?", "options": [{"content": "The SQL syntax was malformed and could not be parsed.", "feedback": "Incorrect. Syntax errors would result in parsing failures earlier. This error occurs at execution time, specifically due to missing parameter binding.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A placeholder (''?'') was not assigned a value using a setter method like setString() or setInt().", "feedback": "Correct. Placeholders in a PreparedStatement must be bound to values via indexed setter methods before execution. Failure to do so causes this exact error.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_002"]}, {"content": "The database rejected the connection due to invalid credentials.", "feedback": "Incorrect. Authentication issues would generate different errors, such as ''access denied''. This message is specific to parameter binding in prepared statements.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The driver failed to translate the JDBC call into a vendor-specific command.", "feedback": "Incorrect. Driver translation issues would typically occur earlier in the process. This error is raised by the PreparedStatement itself when parameters are missing.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_002", "content": "Consider security and performance. How does using ''?'' protect against malicious input?", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "While auditing the version history, Detective Lin finds a removed block of code that used ''?'' placeholders and setString() calls. What primary advantage did this approach provide over string concatenation?", "options": [{"content": "It allowed dynamic table name changes during runtime.", "feedback": "Incorrect. Table names cannot be parameterized using PreparedStatement placeholders. Only literal values can be bound this way.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It prevented SQL injection by separating code from data and enabled efficient query plan reuse.", "feedback": "Correct. Using placeholders ensures user input is treated strictly as data, not executable code, preventing injection attacks. It also allows the database to cache and reuse execution plans.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_001"]}, {"content": "It reduced memory usage by eliminating the need for String objects.", "feedback": "Incorrect. While efficient, the main benefits are security and performance through plan caching, not memory reduction.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It automatically handled database connection pooling.", "feedback": "Incorrect. Connection pooling is managed separately by the application server or connection manager, not by PreparedStatement parameter binding.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 34, "goal": "Discover the truth behind the system failure and identify the culprit.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once caused a production outage due to a misconfigured driver but covered it up.", "background": "A former enterprise architect turned digital crime investigator, known for solving complex system failures.", "occupation": "Software Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_007"]}, {"age": 41, "goal": "Protect her reputation and prevent exposure of her risky refactor.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003"], "secret": "She secretly removed legacy JDBC code without testing fallbacks, fearing it would expose design flaws.", "background": "Architect of the new ORM layer; passionate about abstraction and clean code.", "occupation": "Lead Developer", "characterId": "CHAR_002", "personality": "Brilliant but dismissive of ''low-level'' details like raw JDBC.", "knowledgePoints": ["CONC_008", "CONC_009", "CONC_010", "CONC_011"]}, {"age": 29, "goal": "Avoid blame for breaking production despite following protocol.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_003"], "secret": "He disabled an outdated driver that was still in use, assuming no one relied on it.", "background": "Responsible for deploying drivers and managing database URLs across environments.", "occupation": "DevOps Engineer", "characterId": "CHAR_003", "personality": "Pragmatic, detail-oriented, slightly paranoid about security.", "knowledgePoints": ["CONC_002", "CONC_012", "CONC_003", "CONC_006"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "JDBC (Java Database Connectivity)", "category": "API", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A Java API that enables Java programs to execute SQL statements and interact with any SQL-compliant database.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "JDBC Driver", "category": "Component", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "A software component that allows a Java application to communicate with a database using JDBC. Must be loaded before establishing a connection.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_012"]}, {"name": "Connection", "category": "Interface", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "An interface representing a session with a specific database. SQL statements are executed and results are returned within this context.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004"]}, {"name": "Statement", "category": "Interface", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "An object used for executing static SQL statements and returning results. Vulnerable to injection if not handled properly.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "PreparedStatement", "category": "Interface", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "A precompiled SQL statement that improves performance and prevents SQL injection by using placeholders.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_013"]}, {"name": "ResultSet", "category": "Interface", "appearsIn": ["SCENE_001"], "difficulty": 3, "description": "Represents the data returned after executing a query. It provides methods to retrieve column values by name or index.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_003", "CONC_004"]}, {"name": "JDBC Architecture", "category": "Architecture", "appearsIn": ["SCENE_001"], "difficulty": 3, "description": "Two-tier architecture involving the JDBC API and JDBC driver manager coordinating with vendor-specific drivers.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Object-Relational Mapping (ORM)", "category": "Pattern", "appearsIn": ["SCENE_002"], "difficulty": 4, "description": "A programming technique that maps database tables to Java objects, reducing boilerplate JDBC code.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "JavaBean", "category": "Class", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A reusable Java class with private fields, public getters/setters, and a no-arg constructor, often used in ORM mappings.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008", "CONC_010"]}, {"name": "DAO (Data Access Object)", "category": "Pattern", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 4, "description": "A design pattern that separates low-level database access logic from business logic using interfaces.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_008", "CONC_011"]}, {"name": "CRUD Operations", "category": "Operation", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Basic functions: Create, Read, Update, Delete, typically implemented via DAO methods interacting with the database.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_004"]}, {"name": "Database URL", "category": "Configuration", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "A string specifying the location of the database including protocol, subprotocol, and address, used when establishing a connection.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Placeholder", "category": "Syntax", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Symbols like ''?'' used in PreparedStatement to safely pass parameters into SQL queries.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_005"]}], "educational_goals": ["Understand the role of JDBC and its architecture in Java applications", "Identify components required to establish and manage a database connection", "Apply knowledge of JDBC drivers, URLs, and statements to diagnose connection issues", "Differentiate between Statement and PreparedStatement for secure data access", "Explain how DAO and ORM patterns abstract database operations"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 0, "puzzle_sorting": 0}}', 'd5d22105acb3d11072784bde1d8fabd62155ad6b871c59e5975c0c6636348989', 'Database Connection and Driver Management', '2026-04-01 11:30:22.071542', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('4aac3cb2-7929-4d7b-b38e-0d05f3fce88e', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '143b43ff-7373-4be2-b387-155aa7232cee', NULL, 'The Case of the Missing Servlet', 'active', 'easy', 'standard', '{"clues": [{"name": "War File Contents Log", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The servlet class file is physically absent — not misconfigured or unmapped.", "description": "A timestamped directory listing of the deployed WAR file — shows ''LoginServlet.class'' missing from WEB-INF/classes/ict/servlet/", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "Tomcat Startup Trace", "type": "log", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The web container attempted to register a servlet but found no mapping — suggesting either missing @WebServlet annotation or empty <servlet-mapping> in web.xml.", "description": "Container initialization log snippet: ''INFO [main] o.a.c.c.C.[localhost].[/app] No servlet mapping found for /login — skipping registration.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "HttpServletRequest Flow Diagram", "type": "diagram", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Confirms the container’s role in orchestrating the full HTTP lifecycle — and that a 404 implies failure *before* step 5 (i.e., servlet not found, not broken logic).", "description": "Hand-drawn whiteboard sketch labeled ''Request Path'': (1) Browser → (2) Web Server → (3) Container → (4) new HttpServletRequest/Response → (5) service() → (6) doGet() → (7) write to response → (8) container serializes HTTP response.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003"]}, {"name": "web.xml Fragment (Redacted)", "type": "configuration", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "URL mapping exists, but the target class is unreadable — pointing to deletion or corruption of the servlet class itself, not misconfiguration.", "description": "A torn printout showing only <servlet> and <servlet-mapping> tags — but the <servlet-class> element is smudged beyond legibility; the <url-pattern> reads ''/login''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004"]}, {"name": "Git Diff Snippet (Ben''s Local Repo)", "type": "code", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Direct evidence Ben deleted the servlet file during refactor — confirming accidental removal, not sabotage or architectural disagreement.", "description": "A terminal screenshot showing ''git status'' output: ''deleted: src/main/java/ict/servlet/LoginServlet.java'' — staged but uncommitted.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Container-Generated Request Object", "type": "code_analysis", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Confirms HttpServletRequest is container-managed and immutable per request; proves Ben couldn’t have modified it pre-invocation.", "description": "A debug log snippet showing HttpServletRequest instantiation by the container before servlet invocation: ''Container created HttpServletRequest@7a811971 for /login with method=POST, content-length=124''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Response Header Timing Violation", "type": "build_log_entry", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Indicates Ben attempted manual HttpServletResponse manipulation *after* output stream acquisition — a violation confirming his lack of understanding of response lifecycle.", "description": "A Tomcat startup warning in catalina.out: ''WARNING: Attempted to set header [Content-Type] after response was committed — ignored.'' Appears only in Ben’s local build logs, not CI.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "doPost() Stub with Empty Body", "type": "source_code_fragment", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Explains why login form (POST) fails silently — Ben mapped the servlet but never handled POST data, exposing his confusion about HTTP verb semantics.", "description": "A Git diff fragment from Ben’s last commit: LoginServlet.java shows doPost() exists but contains only ''super.doPost(req, resp);'' — no parameter extraction or business logic. doGet() is fully implemented.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Jakarta EE Container Layer Diagram", "type": "architectural_document", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Confirms Dr. Stack’s architectural critique is ideological — she opposes the *layer*, not just the implementation — making her motive structural, not operational.", "description": "A hand-drawn whiteboard sketch labeled ''Dr. Stack’s Microservices Transition Plan'', overlaying the official Jakarta EE architecture diagram (CHUNK_002) with red Xs over ''Web Container'' and ''Servlet'' layers.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_008"]}, {"name": "Fragmented Form Submission Log", "type": "digital_evidence", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The form was submitted via POST, but the servlet’s doPost() method was never invoked — suggesting either missing servlet or misconfigured mapping. Also reveals checkbox multi-value behavior (ide appears twice).", "description": "A truncated Tomcat access log showing GET requests to /login with parameters: name=Alex&employee=100-200&ide=eclipse&ide=netbean — but no corresponding doPost() entries despite form method=\"post\" in source.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Checkbox Parameter Extraction Snippet", "type": "code_fragment", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Ben was actively debugging form data handling — specifically distinguishing single-value (text/radio) vs multi-value (checkbox) extraction. His note confirms awareness of CONC_009 patterns — but also hints at recent confusion.", "description": "A sticky Post-it on Ben’s monitor: ''req.getParameterValues(\"ide\") → String[]; req.getParameter(\"name\") → String; null check before .length!''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Radio Button Mapping Mismatch", "type": "configuration_error", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Mismatched parameter names and URL paths suggest rushed implementation — not sabotage. The radio button value extraction fails silently if name doesn’t match, aligning with Ben’s cover-up story.", "description": "In web.xml, <servlet-mapping> for LoginServlet points to URL pattern ''/login'', yet the HTML form submits to ''/auth/login''. The radio button group uses name=''size'' in HTML but Ben’s servlet attempts getParameter(''employee'').", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_004"]}, {"name": "UTF-8 Encoding Warning in Catalina.out", "type": "server_log", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The servlet lacks proper request.setCharacterEncoding(\"UTF-8\") — causing garbled input and failed validation. This subtle bug would cause silent failures for international users, reinforcing why robust form handling (CONC_009) requires encoding awareness.", "description": "Tomcat log entry: ''WARNING: Parameters: Invalid chunk ignored. Note: further occurrences will be logged at DEBUG level.'' Appears immediately after a test submission containing ''naïve café'' in the text field.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}], "title": "The Case of the Missing Servlet", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Server Room Alarm", "sceneId": "SCENE_001", "location": "Indoor - Secure Development Lab", "description": "Alarms blare as the deployment pipeline fails. The lead architect reports that the main LoginServlet is missing from the WAR file. Detective Lin Code arrives to investigate. Both suspects are present, offering conflicting explanations.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Tracing the Deployment Logs", "sceneId": "SCENE_002", "location": "Indoor - Configuration Office", "description": "The detective examines the build logs and finds anomalies in the web.xml. Ben claims he mapped the servlet correctly, but Dr. Stack insists the URL pattern violates best practices. A deeper look reveals inconsistencies in request handling.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Container Truth", "sceneId": "SCENE_003", "location": "Indoor - Debugging Chamber (Live Tomcat Instance)", "description": "Running a diagnostic on the live web container, the detective reproduces the error. A test HTTP request returns a 404. Through analysis of HttpServletRequest and HttpServletResponse behavior, the truth emerges: the servlet was deleted, not misconfigured. Ben confesses under scrutiny. Dr. Stack''s architectural critique is valid—but irrelevant to the crime.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth in the Logs", "content": "Ben Tran admits he deleted the servlet accidentally while cleaning up code. He panicked and didn’t report it. The real issue wasn''t architecture or mapping—it was human error. The servlet is restored from a local backup.", "debrief": "While Dr. Stack’s concerns about modernization are valid, the immediate failure stemmed from poor change management and lack of version control discipline. Understanding servlet lifecycle and container behavior helped isolate the root cause.", "summary": "The missing servlet was deleted by a junior developer who failed to follow protocol. Proper use of source control and logging revealed the truth.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": ["EVIDENCE_001", "EVIDENCE_004"], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame the Configuration", "content": "The team concludes the web.xml misconfiguration caused the outage. They rework all mappings, only to discover the servlet still doesn’t exist. Deployment fails again.", "debrief": "Focusing solely on URL mapping without verifying the existence of the servlet led to a false conclusion. A complete understanding of the Jakarta EE stack requires checking both code and configuration.", "summary": "Misdiagnosed the problem as a mapping issue when the servlet itself was missing.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": ["EVIDENCE_002"], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}], "logline": "In a high-tech server room, a critical servlet has vanished just before deployment, threatening to collapse the entire Jakarta EE application. A detective and two suspects must uncover the truth hidden in code, configuration, and container behavior.", "version": "1.0", "evidence": [{"name": "Missing Servlet File", "type": "Digital Artifact", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "The LoginServlet.java file is absent from version control history after the last commit by Ben Tran.", "foundLocation": "Git Repository Audit Log", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Misconfigured web.xml", "type": "Configuration File", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "URL pattern uses ''/login/*'' but frontend calls ''/auth/login'', causing 404s even if servlet existed.", "foundLocation": "Project Configuration Directory", "relatedKnowledge": ["CONC_004", "CONC_008"]}, {"name": "Incomplete Form Handler", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Partial doPost() implementation that reads username but ignores password field.", "foundLocation": "Backup Draft Files", "relatedKnowledge": ["CONC_007", "CONC_009"]}, {"name": "Container Startup Log", "type": "System Log", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "Log shows successful startup but no registration of LoginServlet, indicating it was never loaded.", "foundLocation": "Tomcat Logs", "relatedKnowledge": ["CONC_002", "CONC_003"]}], "has_quiz": true, "scriptId": "ESD_SERVLET_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code opens the exploded WAR archive. The folder structure is intact — WEB-INF/web.xml exists, classes/ is present, but under ''ict/servlet/'', there’s no LoginServlet.class. What does this tell her *immediately* about the servlet’s state?", "options": [{"content": "The servlet was never compiled — it’s a build tool misconfiguration.", "feedback": "Incorrect. A missing .class file doesn’t imply compilation failure — it could mean the source was deleted *before* compilation, or the class wasn’t included in the build path. The WAR contains other .class files, so the build process itself is working.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet class file is physically absent — meaning it was deleted, excluded, or never added to the project.", "feedback": "Correct. A servlet is a Java class deployed as bytecode (.class). If LoginServlet.class is missing from the WAR’s classpath, the web container cannot load or instantiate it — regardless of web.xml mappings or annotations. This is a *component absence*, not a configuration flaw.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "The servlet is misnamed in web.xml — the container looked for ''LoginServlet'' but found ''LoginHandler''.", "feedback": "Incorrect. A naming mismatch would still leave the .class file in the WAR. The container throws a ClassNotFoundException *only if the class is missing*. Here, the file itself is gone — so the issue predates mapping.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It’s a Tomcat version incompatibility — newer containers require Jakarta Servlet 5.0+.", "feedback": "Incorrect. Version incompatibility would typically cause runtime exceptions *after* loading (e.g., NoSuchMethodError), not total absence of the class file. The WAR is built for the target environment — and other servlets deploy fine.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: What is a Servlet?", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Detective Lin reviews Tomcat’s startup logs and sees: ''No servlet mapping found for /login''. She checks web.xml — the <servlet-mapping> for ''/login'' exists, but the corresponding <servlet> block has no <servlet-class>. Where does the responsibility lie — and what component *must* resolve this link?", "options": [{"content": "The developer — they must manually update both <servlet> and <servlet-mapping> in sync.", "feedback": "Partially true for legacy XML, but incomplete. While developers declare the mapping, the *binding* between URL and class is enforced by the container at deployment time — and it fails loudly if the class is missing or misnamed.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The web container — it reads web.xml, validates the <servlet-class>, loads the bytecode, and registers the mapping. If the class is missing, the mapping is silently ignored.", "feedback": "Correct. Per CONC_002 and CONC_004: the web container is responsible for interpreting deployment descriptors, loading servlet classes, and establishing URL-to-class bindings. If <servlet-class> points to a nonexistent class, the container logs a warning and skips registration — resulting in ''No servlet mapping found''.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "The HTTP server (e.g., Apache httpd) — it routes requests before Tomcat sees them.", "feedback": "Incorrect. The HTTP server delegates servlet-bound requests *to* the web container (e.g., via AJP). It has no knowledge of servlet classes or web.xml — that’s entirely the container’s domain.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Dr. Stack’s microservices gateway — it intercepted and blocked the servlet registration.", "feedback": "Incorrect. There’s no evidence of a gateway in this monolithic deployment. The log message originates from Tomcat’s own startup sequence — proving the container itself failed to bind the mapping.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: How URL Mapping Works", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin sketches the request flow on a whiteboard: (1) User clicks login link → (2) Browser sends GET /login → (3) Web server forwards to Tomcat → (4) ??? → (5) doGet() executes → (6) Response sent. What critical pair of objects does the container create *between steps 3 and 4* — and why are they essential to the servlet’s operation?", "options": [{"content": "HttpSession and Cookie — they preserve user state across requests.", "feedback": "Incorrect. While sessions and cookies support statefulness, they’re *optional* and created on demand — not guaranteed per request. The container *must* create request/response objects for *every* HTTP exchange.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "HttpServletRequest and HttpServletResponse — they encapsulate client input and server output, enabling the servlet to read parameters and write HTML without handling raw sockets.", "feedback": "Correct. As defined in CONC_003 and CHUNK_012: the container creates these two objects for every request. HttpServletRequest gives access to headers, parameters, and attributes; HttpServletResponse provides methods to set status, headers, and write body content. They abstract low-level networking — letting the servlet focus on logic.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_003"]}, {"content": "ServletContext and ServletConfig — they provide app-wide and servlet-specific configuration.", "feedback": "Incorrect. These objects are created once per servlet (or app) at initialization — not per request. They’re available *inside* doGet(), but aren’t the immediate bridge between HTTP wire format and servlet method invocation.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "PrintWriter and ServletOutputStream — they’re used to write the response body.", "feedback": "Incorrect. These are *derived* from HttpServletResponse (via getWriter() or getOutputStream()) — not created by the container directly. The container creates the response object first; the servlet then chooses how to write to it.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: HTTP Request-Response Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "In the Debugging Chamber, Detective Lin runs curl -I http://localhost:8080/app/login and receives HTTP/1.1 404 Not Found. She checks Tomcat’s manager app — the application is deployed and running. What layer of the Jakarta EE stack *must* be failing — and why can’t Dr. Stack’s microservices critique explain this result?", "options": [{"content": "The EJB Container — business logic beans aren’t responding.", "feedback": "Incorrect. A 404 is an HTTP-level error indicating the *resource* (URL path) was not found — not a failure in backend services. EJBs are invoked *after* the servlet handles the request.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The Web Container — it failed to locate or instantiate the servlet for /login, meaning the servlet class is missing or unmapped.", "feedback": "Correct. A 404 from Tomcat means the web container received the request but could not dispatch it to any registered servlet — either because no servlet is mapped to ''/login'', or because the mapped servlet class could not be loaded (e.g., missing .class file). Dr. Stack’s critique about architecture is irrelevant here: even obsolete tech works if correctly deployed.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_005"]}, {"content": "The Database Layer — the login query timed out, returning null.", "feedback": "Incorrect. A database timeout would produce a 500 Internal Server Error (if unhandled) or custom error page — not a 404. The 404 occurs *before* any database interaction.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The HTTP Server — Apache httpd rejected the request due to firewall rules.", "feedback": "Incorrect. Detective Lin is hitting Tomcat directly (localhost:8080), bypassing any front-end HTTP server. The 404 originates from Tomcat’s own response generation.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: What is a Web Container?", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Container calls servlet.service(), which dispatches to doGet()."}, {"itemId": "ITEM_B1_002", "content": "User clicks link targeting ''/login''."}, {"itemId": "ITEM_B1_003", "content": "Container creates HttpServletRequest and HttpServletResponse objects."}, {"itemId": "ITEM_B1_004", "content": "Container finds servlet mapped to ''/login'' and allocates a thread."}, {"itemId": "ITEM_B1_005", "content": "Container serializes response object into HTTP and sends it to browser."}], "order": 5, "content": "Detective Lin reconstructs the exact sequence the web container follows when handling a GET request to ''/login''. Arrange these steps in the correct order — from browser click to response delivery.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_001", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms the container’s central orchestration role: it bridges the HTTP protocol and servlet code — creating abstractions, managing threads, and enforcing the lifecycle. A break at step 4 (finding the servlet) explains the 404.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Not quite. Remember: the container must first create request/response objects *before* finding the servlet or allocating a thread. And response serialization happens *after* doGet() completes — not during it. Review the six-step flow in CHUNK_008.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin asks Ben: ''What Java class type must LoginServlet extend to be recognized by Tomcat as a valid web component?'' — Ben hesitates, then says the two-word answer that matches the Jakarta Servlet specification.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 3, "questionId": "Q_B1_006", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["HttpServlet", "HTTPServlet", "http servlet", "HTTP servlet", "Http servlet"], "feedbackCorrect": "Correct. HttpServlet is the standard base class for request-handling servlets in Jakarta EE. Extending it signals to the container that this class implements the required interface (via inheritance) and can be managed within the servlet lifecycle.", "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": "Try again. The class isn’t just ''Servlet'' — it’s a specific subclass designed for HTTP. Check CHUNK_004 and CHUNK_014: it’s the class that provides doGet(), doPost(), and other HTTP-method handlers.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code reviews the initial alarm report: ''LoginServlet missing from WAR''. She checks the deployment manifest and sees the class file is absent — but the web.xml still declares the servlet mapping. As she interviews Ben, he nervously says, ''I used the @WebServlet annotation — maybe the container didn’t see it?'' Which concept explains why the annotation alone wouldn’t cause a 404 if the class file is truly missing?", "options": [{"content": "HttpServletRequest is only created *after* the container locates and loads the servlet class — no class means no request object creation at all.", "feedback": "Correct. The container must first load and instantiate the servlet class before it can create HttpServletRequest/HttpServletResponse objects. A missing class causes a ClassNotFound exception *before* any request handling begins — resulting in a 404 because the URL mapping has no target. This confirms the issue is absence, not misconfiguration.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "The @WebServlet annotation is processed at runtime — so even without the class file, the container tries to generate a proxy.", "feedback": "Incorrect. Annotations like @WebServlet are read during servlet class loading — if the class file is missing, there’s nothing to scan. No proxy is generated. This misconception reflects a common confusion between compile-time annotation processing and runtime container behavior.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "HttpServletRequest can be mocked independently — so the container might create it anyway and fail later.", "feedback": "Incorrect. HttpServletRequest is *always* container-managed and tightly coupled to the servlet lifecycle. It is never created in isolation. Its existence depends entirely on successful servlet class loading and instantiation.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The web.xml mapping overrides annotations — so the container looks for the servlet regardless.", "feedback": "Partially true for discovery, but irrelevant here: if the servlet class is missing, neither annotation nor web.xml can resolve it. Both mechanisms require the class to exist. The 404 occurs because the container finds no matching servlet instance — not because of mapping ambiguity.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: HttpServletRequest Lifecycle", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the Configuration Office, Detective Lin examines Ben’s local build logs and spots a repeated warning: ''Attempted to set header [Content-Type] after response was committed''. She recalls Ben’s login servlet returns HTML. What critical rule about HttpServletResponse does this violation expose — and why does it prove Ben’s implementation is flawed, not malicious?", "options": [{"content": "Headers and status codes must be set *before* acquiring PrintWriter or ServletOutputStream — Ben tried to set Content-Type after writing to the response body.", "feedback": "Correct. This is a fundamental constraint: HttpServletResponse enforces header immutability once the response body stream is committed. Ben’s error reveals he misunderstands response lifecycle ordering — a beginner mistake, not sabotage. It also explains why his local tests show garbled output or partial pages.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "Content-Type must be set using setContentType(), not addHeader() — Ben used the wrong method.", "feedback": "Incorrect. While addHeader() is inappropriate for Content-Type (which requires setContentType()), the warning message explicitly says ''set header'', meaning he likely used setHeader() or setContentType() *after* calling getWriter(). The issue is timing, not method choice.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Tomcat ignores duplicate Content-Type headers — so this warning is harmless and unrelated to the 404.", "feedback": "Incorrect. This warning indicates a *programming error* that breaks response integrity — it may cause truncated responses, incorrect MIME types, or client-side rendering failures. It doesn’t cause 404s directly, but it confirms Ben’s code is unstable and untested.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The container sets Content-Type automatically — Ben shouldn’t set it at all.", "feedback": "Incorrect. While some containers default to text/plain, Jakarta EE servlets *require* explicit Content-Type for HTML responses (e.g., ''text/html;charset=UTF-8'') to ensure correct browser interpretation. Omitting it is itself a bug.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: HttpServletResponse Constraints", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Dr. Stack insists Ben misused doPost(): ''He handles login via GET — exposing credentials in URLs!'' But Detective Lin checks the login form HTML and sees method=''post''. Still, the live test returns 404 on POST. Ben admits he only implemented doGet(). What does this reveal about HttpServlet dispatching — and why did the 404 occur *only* on POST?", "options": [{"content": "The container calls service(), which dispatches to doPost() — but since Ben didn’t override it, service() falls back to the default implementation, which returns HTTP 405 (Method Not Allowed), not 404.", "feedback": "Incorrect. While true that unimplemented doPost() yields 405, the mystery reports a 404 — meaning the servlet *itself* wasn’t found. This points to class absence, not method absence. The 404 confirms the servlet class is missing — so neither doGet() nor doPost() is ever reached.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The container only invokes doPost() if the servlet is mapped to handle POST — but Ben’s mapping (in web.xml or @WebServlet) only declared GET support.", "feedback": "Incorrect. Servlet mappings (via <http-method> or @WebServlet(urlPatterns=..., methods={}) ) are optional — by default, a servlet handles *all* HTTP methods unless restricted. Absence of restriction means doPost() *should* be called — unless the servlet class isn’t loaded at all.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The 404 occurred because the servlet class file is missing — so the container never reaches *any* HTTP method handler. The fact that doGet() exists in the source is irrelevant if the class isn’t deployed.", "feedback": "Correct. This is the core insight: 404 = resource not found (servlet class missing). 405 = method not allowed (servlet found but method unimplemented). Since the error is 404, the container failed at the *dispatch* stage — before invoking service(), doGet(), or doPost(). Ben’s incomplete doPost() is a red herring; the real crime is deletion.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "POST requests require special configuration in web.xml — Ben omitted <security-constraint>, causing the container to reject them silently.", "feedback": "Incorrect. Security constraints affect *authorization*, not routing. A missing security constraint would allow the request to proceed — it wouldn’t cause a 404. Routing happens before security checks.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: doGet() vs doPost() Dispatch", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Stack presents a sleek architecture diagram contrasting ''Legacy Monolith'' (with Servlet, JSP, EJB layers) and ''Modern Jakarta EE Cloud Stack'' (with REST endpoints, microservices, and container orchestration). She argues the missing LoginServlet proves the monolithic approach is ''fundamentally insecure and unmaintainable''. Which architectural principle does her diagram *actually* illustrate — and why does it make her critique valid *in theory*, yet irrelevant to the *crime* of deletion?", "options": [{"content": "Jakarta EE’s layered container model — where Web Containers manage servlets, EJB Containers manage business logic, and separation of concerns enables independent scaling and security policies.", "feedback": "Correct. Her diagram accurately depicts Jakarta EE’s enterprise architecture: client → web container (servlets/JSP) → EJB container → database. Her critique is architecturally sound — microservices *can* improve resilience and deployment agility. But it doesn’t explain *why the servlet vanished*. Valid architecture opinion ≠ evidence of sabotage.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_004"]}, {"content": "The MVC pattern — where servlets act as controllers, JSPs as views, and EJBs as models — and deleting the controller breaks the entire flow.", "feedback": "Partially relevant, but too narrow. MVC is a *design pattern* within Jakarta EE, not the overarching architecture. Dr. Stack’s diagram shows broader infrastructure layers (containers, networks, databases), not just MVC roles. Also, deleting one controller wouldn’t cause a 404 unless the *class* was gone — which is Ben’s error, not an MVC failure.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Declarative security via web.xml — and the missing servlet bypasses all configured <security-constraint> rules.", "feedback": "Incorrect. Declarative security applies to *URL patterns*, not servlet classes. If the servlet class is missing, no security rules apply — but that’s a consequence of deletion, not its cause. Her diagram doesn’t focus on security configuration.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Thread-per-request model — and removing the servlet crashes the container’s threading subsystem.", "feedback": "Incorrect. Missing servlets don’t crash containers — they return 404. Threading is managed per *request*, not per servlet existence. Her diagram shows logical layers, not threading mechanics.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Jakarta EE Web Architecture", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Container creates HttpServletRequest and HttpServletResponse objects."}, {"itemId": "ITEM_B2_002", "content": "Container calls the servlet''s service() method."}, {"itemId": "ITEM_B2_003", "content": "Container matches the request URL to the LoginServlet mapping."}, {"itemId": "ITEM_B2_004", "content": "Container allocates a thread and passes request/response objects to the servlet."}, {"itemId": "ITEM_B2_005", "content": "service() dispatches to doPost() based on HTTP method."}], "order": 5, "content": "Detective Lin reconstructs the exact sequence of events when a user submits the login form (method=''post''). Arrange these steps in the order the Tomcat container executes them — from HTTP request arrival to response transmission.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_003", "ITEM_B2_001", "ITEM_B2_004", "ITEM_B2_002", "ITEM_B2_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms the container *must* locate the servlet (step 1) and create request/response objects (step 2) *before* any servlet method runs. Since the 404 occurred, step 1 failed — the servlet class was missing.", "relatedKnowledge": ["CONC_006", "CONC_007"], "feedbackIncorrect": "Review CHUNK_008: the container first identifies the target servlet from the URL, *then* creates request/response, *then* allocates a thread, *then* calls service(), *then* dispatches to doPost(). Getting this order right reveals why ''missing class'' causes 404 — it fails at the very first step.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "In the Debugging Chamber, Detective Lin runs a curl command: ''curl -X POST http://localhost:8080/app/login'' and receives HTTP 404. She then checks the Tomcat manager and sees ''LoginServlet: NOT LOADED''. She opens the WAR file — WEB-INF/classes/ is empty. To confirm the root cause, she recalls the container’s strict requirement: the servlet class must be present and loadable *before* it can create the ________ object.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["HttpServletRequest", "HTTP request", "request"], "feedbackCorrect": "Exactly. HttpServletRequest is the first container-managed object created *after* successful servlet class loading and instantiation. No class → no instantiation → no request object → 404. This is the smoking gun: the container never got far enough to even attempt creating HttpServletRequest.", "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": "Think about the lifecycle: the container needs the servlet class to instantiate it, then it creates the request and response objects to pass into service(). The blank refers to the object whose creation *depends* on the servlet being loaded — and whose absence confirms deletion, not misconfiguration.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code reviews the alarm-triggering login form HTML found in the staging repo. The form uses method=''post'' and submits to ''/login''. Which parameter extraction method should the LoginServlet use for the checkbox group named ''ide''?", "options": [{"content": "request.getParameter(\"ide\") — returns the first checked value as a String", "feedback": "Incorrect. getParameter() only returns a single String — but checkboxes allow multiple selections. Using it here would lose all but one IDE choice.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "request.getParameterValues(\"ide\") — returns a String array of all checked values", "feedback": "Correct! Checkboxes share the same ''name'' but submit multiple values. getParameterValues() is the standard, safe way to retrieve them — exactly how CONC_009 defines multi-value form handling.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "request.getAttribute(\"ide\") — retrieves a server-side attribute set earlier", "feedback": "Incorrect. getAttribute() accesses scoped objects (e.g., request scope), not client-submitted form data. That’s for internal forwarding — not form parsing.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "request.getQueryString() — parses the full URL query string manually", "feedback": "Incorrect. While technically possible, manual parsing violates separation of concerns and ignores built-in, encoding-aware servlet APIs. CONC_009 emphasizes using dedicated parameter methods.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Stack insists the login form violates Jakarta EE best practices because it mixes GET and POST semantics. Detective Lin notices the form includes both a text field (name) and radio buttons (company size). Which HTTP method is *most appropriate* for this form — and why?", "options": [{"content": "GET — because all fields are simple strings and fit in the URL", "feedback": "Incorrect. While GET works for small, non-sensitive data, submitting company size and user name via URL exposes them in logs, browser history, and proxies — violating security and privacy expectations. CONC_009 highlights that form handling must consider context, not just capability.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "POST — because it supports larger payloads, avoids URL length limits, and keeps sensitive or structured data out of logs", "feedback": "Correct! POST is the standard for forms containing user identity, preferences, or any data that shouldn’t be cached or bookmarked. CONC_009 explicitly cites POST for ''new data to be stored'' — and real-world login flows always use POST.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Either — Jakarta EE treats GET and POST identically for parameter extraction", "feedback": "Incorrect. While getParameter() works for both, the *semantics* differ: GET is for safe, idempotent retrieval; POST is for state-changing operations like login. Mixing them breaks RESTful design and confuses caching layers.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "PUT — because it''s more secure than POST for credential submission", "feedback": "Incorrect. PUT is for idempotent resource replacement (e.g., updating a user profile), not authentication. Browsers don’t natively support PUT in HTML forms — and Jakarta EE servlets require explicit doPut() handling, which isn’t used here.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin examines Ben’s draft servlet code. It calls getParameter(\"size\") for the radio button group — but the HTML uses name=''employee''. What happens when the form is submitted with ''100-200'' selected?", "options": [{"content": "Returns \"100-200\" — parameter names are case-insensitive and auto-resolved", "feedback": "Incorrect. Servlet parameter extraction is strictly case-sensitive and name-matching. If the HTML says name=''employee'', getParameter(\"size\") returns null — no auto-resolution occurs.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Returns null — because the parameter name doesn''t match the HTML ''name'' attribute", "feedback": "Correct! getParameter() returns null when no matching parameter exists. This is a classic CONC_009 pitfall: mismatched names cause silent failures. Ben’s bug explains why login appears broken — even though the servlet exists.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "Throws IllegalArgumentException — unmatched parameters trigger runtime exceptions", "feedback": "Incorrect. Servlets do not throw exceptions for missing parameters. Null return is intentional — forcing developers to validate with if (val != null) checks, per CONC_009’s emphasis on robust handling.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Returns an empty string — unmatched parameters default to \"\"", "feedback": "Incorrect. getParameter() returns null, not \"\". An empty string would only occur if the HTML input had value=\"\" or was submitted blank — not from a name mismatch.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "While reviewing the deployment logs, Detective Lin spots a warning: ''Parameters: Invalid chunk ignored''. Moments later, a test submission containing ''café'' and ''naïve'' returns garbled characters. What’s the most likely missing line in the servlet’s doPost() method?", "options": [{"content": "response.setContentType(\"text/html; charset=UTF-8\");", "feedback": "Partially relevant — this sets the *response* encoding, but doesn’t fix *request* parameter decoding. Garbled input comes from unreadable request bytes, not output rendering.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.setCharacterEncoding(\"UTF-8\");", "feedback": "Correct! This tells the container how to decode incoming form data. Without it, Tomcat defaults to ISO-8859-1 — corrupting UTF-8 characters like ''é'' or ''ï''. CONC_009 stresses encoding awareness as foundational to robust form handling.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_004"]}, {"content": "response.setCharacterEncoding(\"UTF-8\");", "feedback": "Incorrect. response.setCharacterEncoding() affects the *output* stream encoding — useful for ensuring browsers render UTF-8 correctly, but irrelevant to parsing incoming form data.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.setAttribute(\"encoding\", \"UTF-8\");", "feedback": "Incorrect. setAttribute() stores objects in request scope for forwarding — it has zero effect on how the container decodes raw HTTP request bytes.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Container calls doPost() on LoginServlet, passing HttpServletRequest and HttpServletResponse"}, {"itemId": "ITEM_B3_002", "content": "User clicks Submit → browser sends HTTP POST with body: name=Alex&employee=100-200&ide=eclipse&ide=netbean"}, {"itemId": "ITEM_B3_003", "content": "Servlet calls request.getParameter(\"name\") → returns \"Alex\""}, {"itemId": "ITEM_B3_004", "content": "Servlet calls request.getParameterValues(\"ide\") → returns [\"eclipse\", \"netbean\"]"}, {"itemId": "ITEM_B3_005", "content": "Container creates HttpServletRequest object and populates it with parsed parameters"}], "order": 5, "content": "Detective Lin reconstructs the exact sequence of events inside the servlet container when a user submits the login form (method=''post'') with name=''Alex'', employee=''100-200'', and ide=''eclipse'' + ide=''netbean''. Arrange these steps in correct chronological order.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_002", "ITEM_B3_005", "ITEM_B3_001", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction! The flow begins with the client request, then container parsing, then servlet invocation, then parameter extraction — precisely how CONC_009 integrates with the broader request lifecycle (CONC_003).", "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": "Not quite. Remember: the container must parse the raw HTTP body into parameters *before* invoking doPost(). So parsing (ITEM_B3_005) happens right after the request arrives — not after doPost() starts.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin runs a diagnostic curl command: ''curl -X POST http://localhost:8080/app/login --data \"name=Alex&ide=eclipse&ide=netbean\"''. To safely retrieve *all* selected IDEs in the servlet, Ben should call request.__________(\"ide\") — not getParameter().", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["getParameterValues", "getparametervalues", "getparametervalues()"], "feedbackCorrect": "Exactly! getParameterValues() is the required method for multi-value form controls like checkboxes — returning a String array so no selection is lost. This is core to CONC_009’s definition of robust form data handling.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Try again. The blank needs the exact servlet API method name used to extract *multiple* values from a single parameter name — like when two checkboxes share the same ''name'' attribute.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Discover what happened to the missing servlet and restore the system before launch.", "name": "Detective Lin Code", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once wrote a rogue servlet that crashed a production server—blamed on ''unknown causes''.", "background": "A seasoned developer turned digital detective, known for debugging unresponsive enterprise systems.", "occupation": "Application Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and deeply curious about system internals.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_007", "CONC_008", "CONC_009"]}, {"age": 34, "goal": "Prevent the servlet from being deployed to force adoption of her new framework.", "name": "Dr. Elena Stack", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Privately believes servlets are obsolete and may have sabotaged the build to push her microservices agenda.", "background": "Designed the web architecture but is known for favoring microservices over monolithic servlets.", "occupation": "Lead Jakarta EE Architect", "characterId": "CHAR_002", "personality": "Brilliant, impatient, dismissive of legacy tech, speaks in acronyms.", "knowledgePoints": ["CONC_008", "CONC_002", "CONC_003", "CONC_004"]}, {"age": 29, "goal": "Avoid blame for losing the servlet and quietly fix it before anyone notices.", "name": "Ben Tran", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Accidentally deleted the servlet file during a refactor and tried to cover it up by faking logs.", "background": "Assigned to implement the missing servlet but lacks confidence in mapping and form handling.", "occupation": "Junior Backend Developer", "characterId": "CHAR_003", "personality": "Nervous, eager to please, makes mistakes when stressed, hides errors quickly.", "knowledgePoints": ["CONC_001", "CONC_005", "CONC_006", "CONC_007", "CONC_009"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Servlet", "category": "Core Concept", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A Java class that extends functionality of a server, processing client requests and generating dynamic content.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Web Container", "category": "Infrastructure", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "Runtime environment like Tomcat that manages servlet lifecycle, handles threading, and routes requests.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "HTTP Request-Response Lifecycle", "category": "Process", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Sequence from client request to server response, including parsing, routing, processing, and rendering.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "URL Mapping", "category": "Configuration", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Defining which URLs trigger specific servlets via annotations or web.xml configuration.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "HttpServletRequest", "category": "API", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Interface providing access to client request data such as headers, parameters, and session info.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_009", "CONC_007"]}, {"name": "HttpServletResponse", "category": "API", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Interface used to send responses back to clients, including status codes, headers, and output streams.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_005", "CONC_007"]}, {"name": "doGet() and doPost() Methods", "category": "Methodology", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Servlet methods handling GET and POST HTTP requests respectively, defining logic per verb.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Jakarta EE Web Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "Enterprise platform for building scalable, secure, component-based web applications in Java.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Form Data Handling", "category": "Functionality", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Extracting and processing user input from HTML forms using request parameters in servlets.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_005", "CONC_007"]}], "educational_goals": ["Understand the role of a Servlet within a Web Container", "Trace the HTTP Request-Response Lifecycle through Jakarta EE architecture", "Implement and map servlets using URL patterns", "Handle form data via HttpServletRequest and HttpServletResponse", "Differentiate between doGet() and doPost() methods in practice"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 3}}', '307dba01e492c9b0576a5195dd29f33c031273a74804f218bc6594620cfae249', 'Servlet Implementation & Mapping', '2026-04-03 07:00:30.89047', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('a36ed233-a8fb-4068-9f0e-2c32856c95df', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '143b43ff-7373-4be2-b387-155aa7232cee', NULL, 'The Case of the Missing Form Data', 'active', 'easy', 'standard', '{"clues": [{"name": "Flickering Server Room Log Snippet", "type": "log_entry", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The request reached the container and triggered service(), but no doPost() was executed — pointing to a missing handler method.", "description": "A torn thermal printout from the Server Room Control Center log: ''POST /register → 200 OK (no body written) — service() invoked, doPost() not found''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "GlassFish Container Status Panel", "type": "terminal_output", "clueId": "CLUE_B1_002", "foundBy": "CHAR_002", "reveals": "The ''/register'' endpoint is absent from the container’s servlet registry — indicating a URL mapping failure or omission.", "description": "A live terminal feed from the Development Lab showing: ''GlassFish v7.0.0 — Web Container ACTIVE | Servlets loaded: [LoginServlet, DashboardServlet] | /register → NOT MAPPED''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Annotated @WebServlet Annotation", "type": "code_snippet", "clueId": "CLUE_B1_003", "foundBy": "CHAR_003", "reveals": "The servlet class exists and is correctly mapped, but its doPost() method — required for form submission — was deleted.", "description": "A highlighted line in Kai’s IDE: ''@WebServlet(\"/register\") public class RegistrationServlet extends HttpServlet { ... }'' — with a red comment beside it: ''// doPost() intentionally removed during ''cleanup refactor'' — 2024-04-11''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Container Lifecycle Flowchart (Hand-drawn)", "type": "diagram", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "The HTTP lifecycle breaks precisely at step 5 when doPost() is missing — confirming the failure occurs *after* routing but *before* business logic execution.", "description": "A whiteboard sketch in the Debugging Pod: six labeled boxes in sequence: [1. Client clicks /register] → [2. Web server delegates to container] → [3. Container creates req/res objects] → [4. Container finds servlet & allocates thread] → [5. Container calls service() → dispatches to doPost()] → [6. Response serialized & sent]. Box #5 has a large ''X'' over ''doPost()'' and an arrow pointing to ''405 Method Not Allowed?''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "Incomplete Request Log Entry", "type": "log_fragment", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The container received the POST request but did not invoke doPost() — suggesting the handler is missing or misconfigured.", "description": "A truncated log line showing ''POST /register HTTP/1.1'' followed by ''--- END REQUEST ---'' with no corresponding response or parameter dump.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005", "CONC_007"]}, {"name": "Servlet Method Signature Snippet", "type": "code_fragment", "clueId": "CLUE_B2_002", "foundBy": "CHAR_002", "reveals": "The servlet only implements doGet(); form submissions using POST have no handler — explaining why data never reaches business logic.", "description": "A terminal window displays part of RegisterServlet.java: ''protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException { ... }'' — but no doPost() method appears in the visible scroll.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"]}, {"name": "GlassFish Container Trace Output", "type": "debug_output", "clueId": "CLUE_B2_003", "foundBy": "CHAR_003", "reveals": "The container correctly instantiated both request and response objects — confirming they exist and are passed — but dispatched to doGet() instead of doPost(), proving the HTTP method routing failed.", "description": "A debug log from GlassFish: ''Container allocated thread-12 for /register; created HttpServletRequest@abc789 and HttpServletResponse@def456; calling service()... service() dispatched to doGet().''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"]}, {"name": "HTTP Lifecycle Whiteboard Sketch", "type": "diagram", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Detective Lin’s reconstruction confirms the lifecycle breaks at method dispatch — the critical gap between container setup and developer implementation.", "description": "Hand-drawn flow on a lab whiteboard: ''Client → POST /register → Web Server → Container → [CREATE] req/res → [DISPATCH] → ? → [SERIALIZE] → Client''. An arrow points to a blank box labeled ''doXXX()?'' with ''⚠️ MISSING?'' scrawled beside it.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"]}, {"name": "HTML Form with Text Input", "type": "digital_artifact", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The frontend is configured to send data via GET request with parameter named ''name''.", "description": "A fragment of an HTML file showing a form that collects user name via text input, using GET method and submitting to ''hello'' servlet.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Radio Button Form Snippet", "type": "digital_artifact", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Single-selection inputs use shared name attributes; only one value will be submitted under that key.", "description": "An HTML form asking about company size with radio buttons all sharing the name attribute ''employee''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Checkbox Group Code", "type": "digital_artifact", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Multi-value parameters are expected on the backend when handling checkbox groups with same name.", "description": "HTML form allowing multiple IDE selections via checkboxes, all with name=''ide'' and different values.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Incomplete Parameter Extraction", "type": "code_analysis", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Backend fails to handle multi-select form fields correctly, losing data from checkboxes.", "description": "Java code in doPost() uses getParameter(\"ide\") instead of getParameterValues(\"ide\"). Only first selected checkbox is captured.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}, {"name": "UTF-8 Encoding Omission", "type": "configuration_issue", "clueId": "CLUE_B3_005", "foundBy": "CHAR_001", "reveals": "Potential data corruption when users submit non-ASCII characters in form fields.", "description": "No setCharacterEncoding(\"UTF-8\") call in servlet before reading request parameters.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}], "title": "The Case of the Missing Form Data", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Failed Demo", "sceneId": "SCENE_001", "location": "Server Room Control Center", "description": "Lights flicker as alarms sound. The team watches a live demo fail: user registration form submits but no data appears in the database. Detective Lin arrives to lead the investigation. Initial checks show the server is running, but logs indicate incomplete requests.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Tracing the Request Path", "sceneId": "SCENE_002", "location": "Development Lab", "description": "The team reviews the request flow. They examine URL mappings, inspect the servlet configuration, and analyze how form submissions are routed. Logs show that POST requests reach the container but aren''t processed. Suspicion grows around missing handler methods.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: Code Confession", "sceneId": "SCENE_003", "location": "Debugging Pod", "description": "All three gather around a terminal showing the source code. Detective Lin reconstructs the HTTP lifecycle step-by-step. Under scrutiny, Kai admits he deleted the doPost() method. Dr. Moss acknowledges she didn’t verify integration points. The truth surfaces: both structural oversight and human error caused the failure.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct Resolution", "title": "Truth Revealed: The Deleted doPost()", "content": "The investigation concludes that the form data was never processed because the doPost() method was accidentally deleted. While URL mapping and container setup were correct, the absence of the handler method caused silent failure.", "debrief": "This case highlights the importance of understanding the full HTTP lifecycle and maintaining both frontend-backend contracts and proper version control discipline.", "summary": "Human error in code maintenance combined with insufficient integration testing led to the failure. Proper use of doGet()/doPost(), HttpServletRequest, and Jakarta EE standards would prevent recurrence.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}], "logline": "In a high-tech server room, a critical web application fails during a live demo—form data vanishes mid-submission. A detective and two engineers must trace the HTTP request lifecycle to uncover what happened before the system goes live for thousands of users.", "version": "1.0", "evidence": [{"name": "Log Entry: Empty Request Body", "type": "Digital Log", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Server log shows a POST request reaching the container with Content-Length > 0 but empty parameter map.", "foundLocation": "Development Lab Terminal", "relatedKnowledge": ["CONC_005", "CONC_003"]}, {"name": "Missing doPost() Method in UserServlet.java", "type": "Source Code", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Version control diff reveals the doPost() method was removed in the latest commit by Kai Tanaka.", "foundLocation": "Code Repository", "relatedKnowledge": ["CONC_007", "CONC_009"]}, {"name": "web.xml Configuration File", "type": "Configuration", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Shows correct URL mapping to UserServlet, confirming the route is not the issue.", "foundLocation": "Project Resources Folder", "relatedKnowledge": ["CONC_004", "CONC_001"]}], "has_quiz": true, "scriptId": "ESD_HTTP_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the flickering server logs: ''POST /register → 200 OK (no body written)''. She notes the status is 200 — meaning the container accepted the request — but no data appeared in the database. What component is *definitely functioning* at this stage?", "options": [{"content": "The frontend HTML form — it successfully submitted a POST request", "feedback": "While true, the form is external to the Jakarta EE stack. The clue confirms the *container* received and acknowledged the request — that’s the key evidence here.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The web container — it processed the request and returned HTTP 200", "feedback": "Correct. A 200 OK response means the container successfully received, routed, and handled the request up to the service() level — proving the container is active and operational. The failure lies deeper, inside the servlet''s implementation.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "The database connection — since no error was logged, it must be available", "feedback": "Incorrect. No database interaction occurred — the logs show ''no body written'', meaning the servlet never attempted to write to the response or access the DB. Absence of an error doesn’t imply connectivity.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet class file — it must be compiled and deployed, or the container wouldn’t respond", "feedback": "Partially true, but insufficient. The container could load a servlet class without a doPost() method — and still return 200 if service() runs but does nothing. The log proves container activity, not servlet completeness.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: What is a Web Container?", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the Development Lab, Dr. Moss insists her architecture is flawless and points to GlassFish’s status panel: ''Servlets loaded: [LoginServlet, DashboardServlet] | /register → NOT MAPPED''. Detective Lin asks Kai: ''If the servlet class exists and compiles, why would /register appear as unmapped?'' What is the *most likely structural cause*?", "options": [{"content": "The servlet class lacks the @WebServlet annotation or corresponding <servlet-mapping> in web.xml", "feedback": "Correct. URL mapping is a *separate configuration layer* from class existence. Without explicit mapping (via annotation or deployment descriptor), the container has no way to associate the client-facing URL ''/register'' with any servlet class — even if that class is perfectly valid and deployed.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "The servlet class is in the wrong package directory, so the container can’t locate it", "feedback": "Incorrect. Package structure affects class loading, but the status panel says ''/register → NOT MAPPED'' — not ''class not found''. Mapping failure is a configuration issue, not a filesystem path issue.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The web.xml file is missing entirely, so no servlets can be registered", "feedback": "Incorrect. Servlet 3.0+ supports programmatic mapping via @WebServlet. If the annotation is present and valid, web.xml isn’t required. The clue points to mapping absence — not container misconfiguration.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The servlet extends GenericServlet instead of HttpServlet, so it can’t handle HTTP methods", "feedback": "Incorrect. While true that GenericServlet doesn’t provide doGet()/doPost(), the log shows ''POST /register'' was received — meaning the container *attempted* HTTP dispatch. This implies HttpServlet was used; the issue is the missing method, not the base class.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: What is URL Mapping?", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Kai nervously opens his IDE and shows Detective Lin the RegistrationServlet class. It has @WebServlet(\"/register\") and extends HttpServlet — but no doPost() method. He says, ''I thought doGet() was enough since it’s just a form…'' Detective Lin replies, ''That’s where the lifecycle breaks.'' Which step in the HTTP request-response lifecycle fails when doPost() is missing?", "options": [{"content": "Step 3: Container finds the correct servlet and allocates a thread", "feedback": "No — the container *did* find the servlet (it responded with 200), and allocated a thread (service() ran). The failure happens *after* this step.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Step 4: Container calls the servlet''s service() method, which dispatches to doPost()", "feedback": "Correct. The service() method is inherited from HttpServlet and *automatically dispatches* to doGet() or doPost() based on the HTTP method. With no doPost(), service() has nothing to call for POST — resulting in silent failure or default behavior (e.g., returning 200 with empty body). This is the precise breakpoint.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_003"]}, {"content": "Step 2: Container creates HttpServletRequest and HttpServletResponse objects", "feedback": "No — those objects *were* created. The log shows ''no body written'', implying the response object existed but wasn’t populated — meaning creation succeeded, but population failed.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Step 6: Container serializes the response and sends it back to the client", "feedback": "No — the container *did* serialize and send a response (200 OK). The problem is that the response object was empty — because doPost() never ran to populate it.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: HTTP Request-Response Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "In the Debugging Pod, Detective Lin projects the hand-drawn lifecycle flowchart. She highlights step 5: ''Container calls service() → dispatches to doPost()''. Kai admits he deleted doPost(). Dr. Moss argues, ''But the servlet class is there — shouldn’t the container throw an error?'' What does the Jakarta Servlet specification *actually require* of a servlet class regarding HTTP methods?", "options": [{"content": "It must implement *at least one* of doGet(), doPost(), or doPut() — otherwise, the container rejects deployment", "feedback": "Incorrect. The servlet class only needs to extend HttpServlet (or implement Servlet). The container doesn’t validate method presence at deploy time — it dispatches dynamically at runtime. Missing methods result in silent non-execution, not deployment failure.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "It must override service() to handle requests — doGet() and doPost() are optional convenience methods", "feedback": "Incorrect. While you *can* override service(), HttpServlet’s default service() *relies on* doGet()/doPost() existing. If neither is overridden, service() throws ServletException for unsupported methods — but here, it returned 200, meaning service() ran without error, implying it found *something* — likely an empty or inherited method.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "It must declare support for specific HTTP methods — but the container won’t enforce it; it’s the developer’s responsibility to implement them", "feedback": "Correct. The servlet specification defines doGet(), doPost(), etc., as *convention-based hooks*. The container dispatches based on HTTP method name — but if the corresponding method is missing or empty, no exception is thrown by default. It’s a design contract, not a compile-time or runtime enforcement. That’s why the failure was silent.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_004"]}, {"content": "It must implement the Servlet interface directly — extending HttpServlet is optional and less secure", "feedback": "Incorrect. HttpServlet is the standard, recommended base class for HTTP servlets. Implementing Servlet directly is possible but unnecessarily low-level and not relevant to this POST handling failure.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: What is a Servlet?", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Container creates HttpServletRequest and HttpServletResponse objects"}, {"itemId": "ITEM_B1_002", "content": "User clicks ''Submit'' on the HTML form targeting ''/register'' with method=''POST''"}, {"itemId": "ITEM_B1_003", "content": "Container locates RegistrationServlet via URL mapping and allocates a thread"}, {"itemId": "ITEM_B1_004", "content": "Container calls service(), which attempts to dispatch to doPost()"}, {"itemId": "ITEM_B1_005", "content": "Container serializes the (empty) response object into HTTP format and sends 200 OK to browser"}], "order": 5, "content": "Detective Lin reconstructs the exact HTTP request-response lifecycle for the failed registration form. Arrange these steps in the order they occur — from client action to final response delivery.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_001", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence reveals exactly where the failure occurred: after thread allocation and service() invocation, but before doPost() could populate the response.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Review the lifecycle: it starts with the user action, then container object creation, then servlet lookup/thread allocation, then method dispatch, and finally response serialization. The missing doPost() breaks the chain at step 4.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin scans the Server Room Control Center logs again. One line stands out: ''POST /register → 200 OK (no body written)''. She murmurs, ''The container responded, so the ________ is running — but the servlet didn’t write to the response, so its ________ method is missing.'' Fill in both blanks with the correct Jakarta EE terms.", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 3, "questionId": "Q_B1_006", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["web container", "doPost"], "feedbackCorrect": "Exactly. ''Web container'' confirms the runtime environment is active and handling requests. ''doPost'' is the specific HttpServlet method responsible for processing POST submissions like form data — and its absence explains the empty response.", "relatedKnowledge": ["CONC_001", "CONC_007"], "feedbackIncorrect": "Hint: The first blank names the Jakarta EE component that manages servlets and handles HTTP delegation. The second blank names the standard method HttpServlet uses to process POST requests — the one Kai deleted.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the flickering server logs. One line reads: ''Received POST /register — no parameters logged.'' She turns to the team and asks: ''What object *must* be used inside the servlet to extract those missing form fields — and where does it come from?''", "options": [{"content": "HttpServletResponse — passed by the container to write the response body", "feedback": "Incorrect. HttpServletResponse is for sending data *back* to the client — like HTML or status codes. It cannot read form data submitted *by* the client.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "HttpServletRequest — automatically created and passed by the container to hold client request data", "feedback": "Correct. The container creates an HttpServletRequest object for every request and passes it to the servlet''s doGet() or doPost() method. This object contains methods like getParameter() to retrieve form fields — exactly what’s missing here.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "ServletContext — used to share application-wide data across servlets", "feedback": "Incorrect. ServletContext provides app-level context (e.g., init parameters), not per-request data like form inputs. It’s unrelated to extracting POST parameters.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "HttpSession — stores user-specific state across multiple requests", "feedback": "Incorrect. While HttpSession can store data *after* extraction, it doesn’t contain the raw request parameters. The form data arrives in the HttpServletRequest — not the session.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: HttpServletRequest", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Alarms still blare. Dr. Moss insists, ''The architecture is sound — the container handles everything.'' Detective Lin replies, ''Then explain this: if the container created the request object… why did nothing get written to the database?'' She points to the empty response log. What interface is *required* to send any output — and what critical rule governs its use?", "options": [{"content": "HttpServletResponse — headers and status must be set *before* acquiring PrintWriter or OutputStream", "feedback": "Correct. This constraint explains silent failures: if you try to write to the response before setting Content-Type, the container may suppress output or throw an exception. Here, no response was sent — possibly because the servlet never touched the response object at all.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "HttpServletRequest — must be validated with getParameterMap() before use", "feedback": "Incorrect. Validation is good practice, but HttpServletRequest has no such mandatory pre-use step. Its methods (like getParameter()) safely return null or empty values if parameters are absent.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "ServletConfig — must be initialized before processing any request", "feedback": "Incorrect. ServletConfig holds servlet-specific init parameters and is available via getServletConfig(), but it’s not involved in request/response I/O.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "PrintWriter — must always be closed with .close(), never .flush()", "feedback": "Incorrect. While closing is recommended, .flush() ensures buffered content is sent — and many containers auto-close PrintWriter. The real constraint is header-first ordering, not closure timing.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: HttpServletResponse", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "In the Development Lab, Kai nervously opens the servlet code. The form uses method=''post'', yet only a doGet() method exists. Detective Lin asks: ''If the client sends a POST request to a servlet that only overrides doGet(), what actually happens — and why does the form appear to vanish?''", "options": [{"content": "The container throws a 405 Method Not Allowed error — but it’s silently swallowed by the frontend", "feedback": "Incorrect. HttpServlet’s default service() method *does* send a 405 response when doPost() is unimplemented — but only if no doGet() exists. Here, doGet() *is* present, so the container dispatches to it instead.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The container calls doGet() anyway — but since doGet() doesn’t extract POST parameters, the data is ignored", "feedback": "Correct. This is the core bug. The container dispatches based on HTTP method *only if* the corresponding doXXX() method is overridden. If not, it falls back to the default (which sends 405) — but if doGet() *is* present and doPost() is absent, the container still calls doGet() for POST. And since doGet() typically reads query strings (not POST bodies), the form data vanishes.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "The browser automatically resubmits as GET — stripping the body and appending params to the URL", "feedback": "Incorrect. Browsers do *not* auto-convert POST to GET. That would break security and semantics. The request remains POST — but the servlet mishandles it.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The web.xml mapping forces GET handling regardless of form method", "feedback": "Incorrect. URL mappings route requests to servlets — they don’t override HTTP method dispatch. The container decides doGet() vs doPost() based on the request’s method *and* which methods the servlet implements.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: doGet() and doPost()", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Moss pulls up the Jakarta EE architecture diagram. ''Look — the web container sits between browser and servlet. It’s responsible for the entire HTTP lifecycle.'' Detective Lin nods, then asks: ''So — at *which exact moment* does the container create the HttpServletRequest and HttpServletResponse objects?''", "options": [{"content": "When the servlet class is first loaded into memory (during initialization)", "feedback": "Incorrect. Request and response objects are *per-request*, not per-servlet. They’re created anew for each HTTP interaction — not during servlet startup.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "As soon as the container receives the raw HTTP bytes from the web server", "feedback": "Correct. Per CHUNK_008: ''The container \"sees\" that the request is for a servlet, so the container creates two objects HttpServletRequest and HttpServletResponse.'' This happens immediately upon request receipt — before thread allocation or method dispatch — ensuring fresh, isolated objects for every request.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_004"]}, {"content": "Inside the servlet’s service() method, right before calling doGet() or doPost()", "feedback": "Incorrect. The objects are created *before* service() is called and passed *as arguments*. The service() method itself is defined as ''service(HttpServletRequest req, HttpServletResponse resp)'' — meaning they already exist.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Only after the servlet successfully processes the request and prepares a response", "feedback": "Incorrect. That would make response generation impossible — you need the response object *to write to it*. Creation must precede processing.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Jakarta EE Web Architecture", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "User clicks link/form with URL mapped to servlet"}, {"itemId": "ITEM_B2_002", "content": "Container creates HttpServletRequest and HttpServletResponse objects"}, {"itemId": "ITEM_B2_003", "content": "Container finds servlet, allocates thread, passes req/res objects"}, {"itemId": "ITEM_B2_004", "content": "Container calls servlet''s service() method"}, {"itemId": "ITEM_B2_005", "content": "service() dispatches to doGet() or doPost() based on HTTP method"}, {"itemId": "ITEM_B2_006", "content": "Servlet populates HttpServletResponse; container serializes and sends response"}], "order": 5, "content": "Detective Lin sketches the HTTP request lifecycle on a whiteboard. Reconstruct the *exact sequence* — from browser click to response delivery — as described in CHUNK_008 and CHUNK_009.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B2_005", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_005", "ITEM_B2_006"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms why the form failed: step 5 (dispatch to doPost()) never occurred — because doPost() was missing, and the container fell back to doGet() without extracting POST body data.", "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": "Check CHUNK_008: the container creates req/res *before* allocating the thread — and dispatch happens *inside* service(), not before it. Remember: creation → thread allocation → service() → dispatch → response.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "At the terminal, Kai stares at the empty doPost() method signature. Detective Lin types a command to verify the HTTP method dispatch behavior. She runs: ''curl -X POST http://localhost:8080/register'' — and sees the homepage render instead of an error. She states the root cause aloud: ''The servlet has no ________ method, so the container dispatched the POST to doGet(), which ignores the request body.'' Fill in the blank with the exact Java method name.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["doPost", "doPost()", "dopost", "dopost()"], "feedbackCorrect": "Exactly. ''doPost'' is the required method name. Its absence — combined with the presence of doGet() — caused the container to route the POST request to the wrong handler, discarding the form payload. This is the smoking gun.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "The method name is case-sensitive and follows Java naming conventions: ''doPost'', not ''post'', ''handlePost'', or ''do_post''. Review CHUNK_014 — it lists ''doPost()'' explicitly as the handler for POST requests.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the registration form''s HTML. It includes several checkboxes for ''Preferred IDEs'' with the same name=''ide''. What should the backend servlet use to capture all selected options?", "options": [{"content": "request.getParameter(\"ide\")", "feedback": "Incorrect. getParameter() only returns the first value for a given parameter name. With checkboxes, this would miss all but one selection.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getAttribute(\"ide\")", "feedback": "Incorrect. getAttribute() retrieves server-side attributes stored in request scope, not client-submitted form data.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getParameterValues(\"ide\")", "feedback": "Correct. When multiple form elements share the same name (like checkboxes), getParameterValues() returns a String array containing all selected values.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_003"]}, {"content": "request.getParameters(\"ide\")", "feedback": "Incorrect. There is no method called getParameters(). The correct method for multiple values is getParameterValues().", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Moss insists her architecture handles all input types. Detective Lin reviews a radio button group for ''Company Size'' with name=''employee''. Which method should the servlet use to read the user’s choice?", "options": [{"content": "request.getParameterValues(\"employee\")", "feedback": "While this would technically work (returning a single-element array), it''s not the standard or most efficient approach for single-value inputs like radio buttons.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getParameter(\"employee\")", "feedback": "Correct. Radio buttons are single-selection controls. Only one option is sent, so getParameter() suffices to retrieve its value.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "request.getAttribute(\"employee\")", "feedback": "Incorrect. getAttribute() is for server-side scoped variables, not incoming HTTP parameters from forms.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "request.getReader().readLine()", "feedback": "Incorrect. This reads raw request body content as a stream, which is unnecessary for standard form-encoded data. Use parameter extraction methods instead.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "The registration form has a text field for ''Full Name'' with name=''name''. Kai claims the backend receives it correctly. Which line of code properly extracts this value in a doPost() method?", "options": [{"content": "String name = request.setAttribute(\"name\", \"\");", "feedback": "Incorrect. setAttribute() stores data on the server side. To retrieve client input, you must use getParameter().", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "String name = request.getParameter(\"name\");", "feedback": "Correct. getParameter() retrieves the value of a single form field by its name attribute. Always check for null or emptiness after.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "String name = response.getParameter(\"name\");", "feedback": "Incorrect. The HttpServletResponse object does not have getParameter(). Parameters come from the request, not the response.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "String name = request.getFormValue(\"name\");", "feedback": "Incorrect. There is no such method as getFormValue() in HttpServletRequest. Use getParameter() for standard form data.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Detective Lin finds a critical flaw: the servlet processes checkbox data using getParameter(\"ide\") instead of getParameterValues(\"ide\"). What data loss issue does this cause?", "options": [{"content": "All checkbox values are stored as a comma-separated string automatically.", "feedback": "Incorrect. The container does not automatically concatenate checkbox values. Only the first selected value is returned by getParameter().", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Only the first selected checkbox value is captured; others are lost.", "feedback": "Correct. Since getParameter() returns only the first value for a parameter name, any additional checked boxes are ignored, leading to incomplete user data.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_004"]}, {"content": "The entire request fails with a 400 Bad Request error.", "feedback": "Incorrect. The request succeeds, but silently loses data. This makes the bug harder to detect during testing.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The server throws a NullPointerException.", "feedback": "Incorrect. A null pointer would only occur if the parameter didn’t exist at all. Here, at least one value exists, so no exception is thrown—just silent data loss.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Review the HTML form structure and input types."}, {"itemId": "ITEM_B3_002", "content": "Identify which parameters are sent and their names."}, {"itemId": "ITEM_B3_003", "content": "Check if getParameter() or getParameterValues() is used appropriately."}, {"itemId": "ITEM_B3_004", "content": "Verify encoding settings for proper character handling."}, {"itemId": "ITEM_B3_005", "content": "Confirm null checks and validation logic in the servlet."}], "order": 5, "content": "Reconstruct the correct sequence of steps Detective Lin follows to diagnose missing form data in the servlet:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_005", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Detective Lin starts with the frontend, traces data flow, validates backend logic, and ensures encoding integrity—methodical forensic analysis.", "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": "Incorrect. Always begin with the source (HTML form), then trace how data moves through the system. Multi-value fields require special handling, and encoding matters for international users.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "To prevent data corruption when users enter names with special characters (e.g., naïve, résumé), the servlet should call request.setCharacterEncoding(\"_____\") before reading any parameters.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Form Data Handling", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["UTF-8", "utf-8", "UTF8", "utf8"], "feedbackCorrect": "Correct. Setting character encoding to UTF-8 ensures proper interpretation of international characters in form submissions.", "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": "Incorrect. The standard encoding for modern web applications is UTF-8. Without setting it explicitly, the container may use a default encoding that corrupts non-ASCII characters.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Identify where the form data was lost and restore trust in the system.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once caused a production outage by misconfiguring a servlet mapping—keeps it hidden to protect reputation.", "background": "Former software engineer turned digital crime investigator, known for solving complex middleware failures.", "occupation": "System Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, asks precise questions.", "knowledgePoints": ["CONC_003", "CONC_004", "CONC_005", "CONC_006"]}, {"age": 42, "goal": "Protect her architectural design from being blamed.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Rushed deployment without proper testing because she wanted credit before promotion review.", "background": "Designed the current web architecture; insists her design is flawless.", "occupation": "Lead Jakarta EE Architect", "characterId": "CHAR_002", "personality": "Confident, slightly defensive, speaks in technical absolutes.", "knowledgePoints": ["CONC_008", "CONC_001", "CONC_002"]}, {"age": 29, "goal": "Avoid getting fired for his coding error.", "name": "Kai Tanaka", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Accidentally removed a doPost() method while refactoring code, thinking it was redundant.", "background": "Responsible for connecting HTML forms to backend servlets; new to Jakarta EE.", "occupation": "Frontend-to-Backend Integration Developer", "characterId": "CHAR_003", "personality": "Eager to prove himself, nervous when questioned, admits mistakes quickly.", "knowledgePoints": ["CONC_007", "CONC_009", "CONC_005"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Servlet", "category": "Core Component", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "A Java class that handles client requests and generates dynamic responses within a web container.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "Web Container", "category": "Infrastructure", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Runtime environment that manages servlets, handles threading, and enforces security policies.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "HTTP Request-Response Lifecycle", "category": "Process", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 1, "description": "Sequence of events from client request initiation to server response delivery.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "URL Mapping", "category": "Routing", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Configuration that directs incoming URLs to specific servlets for processing.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "HttpServletRequest", "category": "Data Access", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Interface providing access to client request data including headers, parameters, and form input.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_009", "CONC_007"]}, {"name": "HttpServletResponse", "category": "Output", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "Interface used to send responses back to clients, including status codes and output streams.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "doGet() and doPost() Methods", "category": "Methodology", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Servlet methods that handle GET and POST HTTP requests respectively.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Jakarta EE Web Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "Standardized platform for building enterprise-grade web applications using modular components.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Form Data Handling", "category": "User Interaction", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Process of capturing, validating, and processing user input submitted via HTML forms.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_005", "CONC_007"]}], "educational_goals": ["Understand the role of Servlets and Web Containers in handling HTTP requests", "Trace the full HTTP Request-Response Lifecycle from client to server", "Map URLs to servlets and interpret form data using HttpServletRequest", "Differentiate between doGet() and doPost() methods in form processing", "Apply Jakarta EE architecture principles to debug real-world request issues"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 3}}', '307dba01e492c9b0576a5195dd29f33c031273a74804f218bc6594620cfae249', 'Handling HTTP Requests & Form Data', '2026-04-03 07:11:29.188662', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('2f5cc8c5-22eb-419c-a410-f7ebe0c24d61', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '143b43ff-7373-4be2-b387-155aa7232cee', NULL, 'The Servlet Heist: Code in the Server Room', 'active', 'easy', 'standard', '{"clues": [{"name": "Flickering Log Entry #7A", "type": "log_entry", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "URL mapping is misconfigured — the client-facing path doesn’t match what’s registered in the container.", "description": "A timestamped log line showing ''Servlet not found for path /onboard'' — but the WAR file contains a class named OnboardingServlet.class. The container logs show no initialization errors.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "GlassFish Deployment Descriptor Snippet", "type": "configuration_file", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The servlet name ''OnboardHandler'' is referenced in mapping but never declared — a classic URL mapping breakage.", "description": "A fragment of web.xml recovered from the exploded WAR: <servlet-mapping><servlet-name>OnboardHandler</servlet-name><url-pattern>/v1/onboard</url-pattern></servlet-mapping>. No matching <servlet> entry exists.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_001"]}, {"name": "Container Thread Trace (Thread-42)", "type": "execution_trace", "clueId": "CLUE_B1_003", "foundBy": "CHAR_003", "reveals": "The request reached the servlet, but the doPost() method either threw silently or returned without writing — consistent with a missing or empty implementation.", "description": "A JVM thread dump captured mid-failure: ''Thread-42 RUNNABLE — waiting for response.getOutputStream() — but HttpServletResponse.isCommitted()==true''. Suggests doPost() was called but never wrote to output.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "Debug Chamber Simulation Snapshot", "type": "runtime_visualization", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "The servlet instance exists and is invoked, but its doPost() body is effectively empty — confirming deletion, not misrouting.", "description": "A frame-by-frame visualization of the HTTP lifecycle: HttpServletRequest created → servlet located → service() invoked → dispatch to doPost() → thread exits *before* response.write() is called. No exception thrown.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "HttpServletRequest Parameter Trace Log", "type": "log_entry", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The servlet received the request but failed to extract form data — pointing to either missing doPost() logic or misconfigured request binding.", "description": "A raw log snippet showing HttpServletRequest.getParameter(''customerName'') returning null during form submission, despite the field being present in the HTML.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Response Stream Initialization Warning", "type": "container_log", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "A servlet attempted to write to HttpServletResponse using both PrintWriter and ServletOutputStream — violating servlet contract and causing silent failure.", "description": "GlassFish container log: ''WARNING: Attempted to get Writer after OutputStream was already acquired.'' Appears just before response timeout.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Missing doPost Override Signature", "type": "source_code_snippet", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Kaito’s refactoring removed the doPost handler entirely — explaining why form submissions (POST) reach the container but produce no output.", "description": "Decompiled servlet class shows only doGet() defined; the doPost() method is absent — not even an empty override. Compiler bytecode confirms no invokevirtual instruction targeting doPost.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Web Container Lifecycle Diagram (Annotated)", "type": "diagram_fragment", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Dr. Hale understood the container’s object creation responsibility — suggesting her changes were intentional architectural interventions, not oversights.", "description": "Hand-scribbled GlassFish lifecycle diagram on a lab whiteboard, with arrows labeled ''→ creates HttpServletRequest'' and ''→ creates HttpServletResponse'' before service() dispatch — crossed out in red next to Dr. Hale’s initials.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_008"]}, {"name": "Fragmented Form Submission Log", "type": "log_file", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Client-side form data was successfully transmitted — the failure must occur during servlet parameter extraction or handling, not network or routing.", "description": "A truncated HTTP request log showing raw parameter data from a failed onboarding form submission: ''name=Alex&company_size=100-200&ide=eclipse&ide=netbean&newsletter=true''. Parameters appear correctly parsed but lack evidence of server-side processing.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Checkbox Handling Snippet (Deleted)", "type": "code_fragment", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Kaito attempted to process multi-value checkbox input but deleted the critical getParameterValues() call — explaining why IDE preferences never reached business logic.", "description": "A commented-out Java snippet recovered from Git history in the servlet’s doPost() method: ''// String[] ides = request.getParameterValues(\"ide\"); // if (ides != null) { ... }''. The surrounding lines were removed in Kaito’s last commit.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Radio Button Mapping Mismatch", "type": "configuration_file", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Dr. Hale’s URL mapping change silently diverted all form POSTs away from the intended handler — meaning no doPost() was ever invoked, regardless of its content.", "description": "A misconfigured @WebServlet annotation on Dr. Hale’s logging interceptor: @WebServlet(urlPatterns = \"/onboard/*\") — but the HTML form submits to \"/onboard/submit\", causing the container to route requests to the wrong servlet before parameter extraction even begins.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_004"]}, {"name": "Empty Parameter Trace", "type": "debug_output", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The HttpServletRequest object *does* contain single-value parameters, but getParameterValues() returns null for ''ide'' — indicating either the form didn’t submit checkboxes (client issue) or the request was intercepted *before* reaching the correct servlet (server mapping issue).", "description": "A live-debug console capture from the Debug Chamber showing: ''request.getParameter(\"name\") → \"Alex\" | request.getParameter(\"employee\") → \"100-200\" | request.getParameterValues(\"ide\") → null''. Confirms radio/text values arrive, but checkbox array is missing — pointing to either client misconfiguration or server-side suppression.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}], "title": "The Servlet Heist: Code in the Server Room", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Report", "sceneId": "SCENE_001", "location": "Server Monitoring Room", "description": "Flickering monitors display error logs from the enterprise portal. Detective Lin arrives to investigate the sudden failure of the customer onboarding system. Dr. Hale claims a container crash; Kaito insists it''s a missing doPost() call. Initial clues point to misconfigured servlet behavior.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Inside the Web Container", "sceneId": "SCENE_002", "location": "Development Lab (Indoor)", "description": "The team examines the deployed WAR file inside the web container. Logs show requests reaching the server but no responses generated. Suspicion grows around URL mapping errors and unhandled form submissions. A turning point occurs when a hidden configuration file reveals inconsistent servlet mappings.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Request-Response Trial", "sceneId": "SCENE_003", "location": "Debug Chamber (Secure Indoor Facility)", "description": "Using a live simulation of the HTTP request-response lifecycle, Detective Lin reconstructs the exact moment of failure. Evidence proves that both suspects made changes—but only one caused the fatal break. The truth emerges through analysis of HttpServletRequest state and HttpServletResponse output streams.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth in the Threads", "content": "Detective Lin exposes that both suspects made risky changes: Kaito deleted doPost(), but Dr. Hale’s hidden logger intercepted requests first, corrupting the input stream. Her unauthorized module was the root cause. The system is restored after removing the rogue component and restoring proper URL mappings.", "debrief": "Understanding servlet lifecycle and container behavior helps isolate faults. Security and transparency are vital in enterprise systems.", "summary": "The real culprit was a combination of poor oversight and hidden complexity. Proper use of doGet/doPost, clean URL mapping, and adherence to Jakarta EE standards prevent such failures.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame Assigned, Truth Lost", "content": "Kaito is fired for deleting doPost(). However, the system remains unstable because the underlying interception by Dr. Hale’s logger persists. The real issue stays buried.", "debrief": "Jumping to conclusions without full lifecycle analysis leads to incomplete fixes. Always verify all components in the request chain.", "summary": "Partial understanding results in misattribution. Mastery requires seeing beyond surface-level code errors.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-tech indoor server facility, a critical enterprise web application has been sabotaged. A detective and two suspects must uncover how servlets work, trace HTTP lifecycles, and decode URL mappings to reveal who disrupted the Jakarta EE system—and why.", "version": "1.0", "evidence": [{"name": "Corrupted web.xml File", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "Deployment descriptor showing incorrect servlet-to-URL mappings. One entry points ''/submit'' to a non-existent class.", "foundLocation": "Development Lab Server", "relatedKnowledge": ["CONC_004", "CONC_001"]}, {"name": "Missing doPost() Implementation", "type": "Code Artifact", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Version control log shows deletion of doPost() in RegistrationServlet.java by Kaito Tanaka.", "foundLocation": "Git Repository Backup Drive", "relatedKnowledge": ["CONC_007", "CONC_009"]}, {"name": "Hidden AI Logger Module", "type": "Binary Component", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Undocumented JAR file intercepting HttpServletRequest objects before they reach target servlets.", "foundLocation": "Web Container Lib Directory", "relatedKnowledge": ["CONC_005", "CONC_008", "CONC_002"]}, {"name": "Request Flow Diagram", "type": "Whiteboard Sketch", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "Hand-drawn diagram revealing where the response generation fails—after container routing but before servlet processing.", "foundLocation": "Debug Chamber Whiteboard", "relatedKnowledge": ["CONC_003", "CONC_006"]}], "has_quiz": true, "scriptId": "SCRIPT_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the flickering monitor showing ''Servlet not found for path /onboard''. Dr. Hale insists the container crashed; Kaito says the doPost() call is missing. But the logs confirm the container is running — and the WAR file contains OnboardingServlet.class. What core component *must* be involved for the request to reach a servlet at all?", "options": [{"content": "The Jakarta EE application server’s database connector", "feedback": "Incorrect. The database connector handles data persistence — it''s not involved in routing HTTP requests to servlets. The failure occurs before any database interaction.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The web container — it maps URLs to servlets and manages their lifecycle", "feedback": "Correct. The web container is responsible for receiving the HTTP request, locating the correct servlet via URL mapping, instantiating it if needed, and invoking its methods. Without proper container configuration, even a valid servlet class won’t respond.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "The client-side browser’s JavaScript engine", "feedback": "Incorrect. The browser only sends the request — it has no role in determining which server-side component handles it. This is entirely a server/container concern.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The enterprise portal’s load balancer", "feedback": "Incorrect. While a load balancer may route traffic between servers, it doesn’t resolve ''/onboard'' to a specific Java class — that’s the web container’s job.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Web Container", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Hale claims the crash was caused by a container failure. Detective Lin checks the GlassFish logs and sees: ''INFO: Starting Servlet Engine'' followed by ''INFO: Deploying web application archive [onboard.war]''. What does this tell Lin about the servlet’s status *before* the first request?", "options": [{"content": "The servlet failed to compile and was never loaded", "feedback": "Incorrect. A compilation failure would appear as an ERROR or SEVERE log — not INFO-level deployment messages. These logs confirm successful loading and initialization.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet was loaded and initialized by the container — it exists and is ready to handle requests", "feedback": "Correct. ''Deploying web application archive'' means the container successfully unpacked the WAR, loaded servlet classes, instantiated them, and called init(). The servlet is live — so the issue lies elsewhere, like URL mapping or request handling logic.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "The servlet was deployed but disabled via security constraints", "feedback": "Incorrect. Security constraints would result in a 403 Forbidden response — not ''Servlet not found''. That error indicates the container couldn’t locate *any* servlet bound to that path.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The servlet requires manual activation via JMX console", "feedback": "Incorrect. Jakarta Servlets are automatically activated on deployment unless explicitly annotated @WebServlet(loadOnStartup = -1) or disabled in web.xml — neither is indicated here.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Servlet", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Inside the Development Lab, Detective Lin opens the web.xml file and finds this snippet: <servlet-mapping><servlet-name>OnboardHandler</servlet-name><url-pattern>/onboard</url-pattern></servlet-mapping>. But searching the entire project reveals *no* <servlet> declaration with name ''OnboardHandler''. What fundamental servlet concept explains why the request fails — even though the servlet class exists?", "options": [{"content": "The servlet class lacks the @WebServlet annotation, so it can’t be auto-discovered", "feedback": "Partially true — but insufficient. Even without @WebServlet, a servlet can be declared in web.xml. Here, the *mapping exists* but the *declaration is missing*, breaking the two-step binding process.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "URL mapping requires *both* a servlet declaration AND a servlet-mapping — one missing link breaks the chain", "feedback": "Correct. URL mapping is a two-layer abstraction: first, bind a public URL to an internal name (e.g., ''OnboardHandler''); second, bind that internal name to a real Java class. If the internal name isn’t declared, the container has no way to resolve it — resulting in ''Servlet not found'', even if the class is present.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "The url-pattern must always start with ''/v1/'' to comply with REST conventions", "feedback": "Incorrect. URL patterns are arbitrary — ''/onboard'' is perfectly valid. REST conventions aren’t enforced by the container; they’re developer guidelines.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The servlet name must exactly match the class filename (e.g., ''OnboardingServlet'')", "feedback": "Incorrect. Servlet names are logical identifiers — they’re decoupled from filenames by design. This abstraction enables refactoring without breaking clients.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: URL Mapping", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Kaito admits he refactored OnboardingServlet.java — but insists ''the doPost() method is still there''. Lin runs a bytecode analyzer and confirms the method signature exists: ''public void doPost(HttpServletRequest req, HttpServletResponse resp) throws IOException, ServletException''. Yet logs show zero output. What critical detail about servlet execution does this reveal?", "options": [{"content": "The container skipped doPost() because the request used GET instead of POST", "feedback": "Incorrect. The logs explicitly show ''POST /onboard HTTP/1.1'', and the container’s service() method correctly dispatched to doPost(). The method *was* called.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The doPost() method body is empty — it received the request and response objects but wrote nothing to the output stream", "feedback": "Correct. The servlet lifecycle completed successfully (no exceptions), yet no response was generated. Since the method signature is present and invoked, the only explanation is that its body contains no logic — e.g., it’s been accidentally deleted or left blank. This matches Kaito’s secret.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_003"]}, {"content": "The HttpServletRequest object was null, causing silent failure", "feedback": "Incorrect. The container *always* provides valid, non-null HttpServletRequest and HttpServletResponse objects. Passing null would violate the servlet specification and cause an immediate NullPointerException.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The response was written but immediately flushed by a filter upstream", "feedback": "Incorrect. While filters exist, no filter configuration appears in the logs or deployment descriptors — and a flushed-but-empty response would still show ''HTTP 200 OK'' with zero body, not ''Servlet not found''.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: HTTP Request-Response Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "The container creates HttpServletRequest and HttpServletResponse objects"}, {"itemId": "ITEM_B1_002", "content": "The user clicks ''Submit'' on the HTML form with method=''POST''"}, {"itemId": "ITEM_B1_003", "content": "The container calls the servlet’s service() method"}, {"itemId": "ITEM_B1_004", "content": "The container allocates a thread and passes request/response to the servlet"}, {"itemId": "ITEM_B1_005", "content": "The servlet’s doPost() method executes business logic and writes to response.getWriter()"}, {"itemId": "ITEM_B1_006", "content": "The container serializes the response and sends HTTP 200 back to the browser"}], "order": 5, "content": "Detective Lin reconstructs the exact HTTP request-response flow inside the Debug Chamber. Arrange these events in the precise order they occur when a user submits the onboarding form via POST.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: HTTP Request-Response Lifecycle", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_001", "ITEM_B1_004", "ITEM_B1_003", "ITEM_B1_005", "ITEM_B1_006"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect reconstruction. This sequence confirms the lifecycle completed — meaning the servlet was invoked and ran. The absence of output points squarely to an empty doPost() body, not a routing failure.", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_006"], "feedbackIncorrect": "Not quite. Remember: the user action triggers everything; then the container prepares objects *before* allocating a thread; service() is called *after* thread allocation; and response serialization happens *only after* doPost() finishes. Review the six-step lifecycle.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "In the Debug Chamber simulation, Lin observes that the container invokes service(), which then dispatches to doPost(). But the final frame shows the response object’s buffer is empty — and the servlet’s doPost() method contains only two lines: ''protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws IOException, ServletException {'' and ''}''. What is the *minimum required code* to generate a valid HTTP response? Fill in the blank with the missing statement (use exact syntax, no extra spaces): resp.setContentType(\"text/html\"); PrintWriter out = resp.getWriter(); ________", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: HttpServletResponse", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B1_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["out.println(\"<html><body>Success</body></html>\");", "out.println(\"<html><body>Success</body></html>\")"], "feedbackCorrect": "Exactly right. This line writes HTML content to the response body using the PrintWriter obtained from HttpServletResponse. Without it, the response remains empty — explaining the silent failure.", "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": "Try again. You need a single statement that writes HTML content to the PrintWriter ''out''. Remember: it must use println() and valid HTML syntax. Check CHUNK_013 for the pattern.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the initial crash report. The logs show requests arriving at the server — but no responses are sent back. Dr. Hale insists it''s a container crash; Kaito blames a missing doPost() call. Which statement best explains *why* HttpServletRequest is central to diagnosing this discrepancy?", "options": [{"content": "Because HttpServletRequest contains the HTTP method (GET/POST), and if the container sees POST but no doPost() exists, it throws ServletException — which would appear in logs.", "feedback": "Incorrect. While true, the logs show *no error thrown* — just silence. A missing doPost() without exception handling typically results in default 405 Method Not Allowed *if* the servlet is mapped correctly. But here, the request reaches the container — meaning mapping succeeded.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Because HttpServletRequest holds the client’s form data — and if it arrives but parameters like ''email'' return null, that signals either malformed HTML, incorrect encoding, or the request never reached the intended doPost() handler.", "feedback": "Correct. HttpServletRequest is the *only* source of submitted form values. If logs show requests arriving but parameters are null or missing, it means either the request wasn’t routed to the right servlet (mapping issue) or the servlet didn’t process it (e.g., no doPost()). This makes HttpServletRequest the first diagnostic checkpoint for form failures.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "Because HttpServletRequest manages session state — and if the session ID is invalid, the container drops the request before invoking any servlet method.", "feedback": "Incorrect. Session validation happens *after* the request object is created and passed to the servlet — and would generate explicit session-related errors or redirects, not silent failure. The logs show no such activity.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Because HttpServletRequest is immutable — so if its headers are malformed, the container rejects the request before creating the response object.", "feedback": "Incorrect. Malformed headers cause early HTTP 400 Bad Request responses — which *would* appear in logs. Here, the container receives the request and attempts processing — meaning headers were syntactically valid.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: HttpServletRequest", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Hale points to a GlassFish log entry: ''Container initialized response stream for /onboard''. Kaito counters, ''But nothing was written to it!'' Detective Lin knows HttpServletResponse governs what leaves the server. Which constraint is *most critical* when debugging why no content appears in the browser?", "options": [{"content": "HttpServletResponse.getWriter() must be called *before* getOutputStream(), or else an IllegalStateException is thrown — and that exception would be logged.", "feedback": "Correct. This is a hard runtime constraint: once you acquire one output stream, the other becomes unavailable. If code accidentally calls both (e.g., logging middleware + servlet logic), it fails silently *unless* the exception is caught and suppressed — which matches the ''no logs, no response'' symptom.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "The Content-Type header must match the actual bytes written — otherwise browsers ignore the response body.", "feedback": "Incorrect. Mismatched Content-Type causes rendering issues (e.g., plain text shown as code), not total absence of response. The browser would still receive and display *something*.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "HttpServletResponse.sendRedirect() must be called before any output is written — or else IllegalStateException occurs.", "feedback": "Incorrect. While true, redirect is not happening here — there’s no 302 status in logs, and the browser shows a blank page, not a redirect loop.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The response buffer size must exceed the payload — otherwise data is truncated silently.", "feedback": "Incorrect. Buffer overflow triggers IOException or flushes automatically — both would appear in logs. Also, truncation would show *partial* content, not total silence.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: HttpServletResponse", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Inside the WAR file, Detective Lin finds two conflicting clues: (1) A @WebServlet annotation mapping ''/onboard'' to MyOnboardServlet, and (2) An empty MyOnboardServlet.class — no doPost() method defined. Kaito admits he ''cleaned up unused methods.'' What is the *exact behavioral consequence* when a browser submits a form with method=''post'' to /onboard?", "options": [{"content": "The container calls HttpServlet.service(), which checks for doPost() — finds none — and returns HTTP 405 Method Not Allowed with an empty body.", "feedback": "Correct. HttpServlet’s default service() implementation explicitly checks for overridden doPost(). If absent, it sends 405 — but crucially, *only if the servlet is registered to handle POST*. Since the mapping is generic (@WebServlet(\"/onboard\")), the container *does* route POST to it — then fails inside service(). However, if error pages are suppressed or logging is minimal, this may appear as ''no response''.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_003"]}, {"content": "The container forwards the request to doGet() automatically — since doPost() is missing — causing unexpected GET-style behavior.", "feedback": "Incorrect. No automatic fallback exists. HttpServlet does *not* delegate POST to doGet(); it throws ServletException or returns 405. This misconception leads to subtle bugs.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The request is dropped at the web container level — never reaching the servlet — because URL mapping only supports GET by default.", "feedback": "Incorrect. @WebServlet maps *all* HTTP methods unless restricted. The container routes both GET and POST to the servlet — then dispatches internally via service().", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The container instantiates a new servlet instance and calls init(), then service() — but without doPost(), the thread exits silently with no response.", "feedback": "Incorrect. HttpServlet.service() *always* attempts to call the appropriate doXxx() method. Absence triggers defined behavior (405), not silence — unless the exception is swallowed.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: doGet() and doPost()", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Detective Lin compares Dr. Hale’s architecture diagram (CHUNK_002) with the live container behavior. She notes: ''The web container *must* create both HttpServletRequest and HttpServletResponse *before* calling service() — yet our logs show the request object created, but no evidence of response initialization.'' What architectural principle from Jakarta EE explains why this sequence is non-negotiable?", "options": [{"content": "Jakarta EE enforces strict separation of concerns: the container handles infrastructure (request/response objects), while servlets handle business logic — so objects must exist *before* delegation.", "feedback": "Correct. Jakarta EE’s container model mandates that cross-cutting concerns — including object lifecycle, threading, and protocol binding — are fully managed *by the container*. HttpServletRequest and HttpServletResponse are container-managed artifacts; their creation is part of the contract that enables portable, secure, and scalable enterprise deployments. Without them, the servlet has no input or output channel.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_004"]}, {"content": "Because EJB containers require transaction context to be established before any web layer interaction — and HttpServletRequest carries that context.", "feedback": "Incorrect. Transaction context is injected separately (e.g., via @TransactionAttribute) and is not stored in HttpServletRequest. This is unrelated to the immediate request-response object creation.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The MVC pattern requires the controller (servlet) to receive pre-constructed view (response) and model (request) objects — otherwise the pattern breaks.", "feedback": "Incorrect. While MVC is *supported*, Jakarta EE doesn’t enforce it. The container creates these objects regardless of architectural pattern — it’s a low-level servlet API requirement, not an MVC constraint.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Security constraints in web.xml are evaluated against HttpServletRequest *before* response generation — so the request object must exist first.", "feedback": "Incorrect. Security filters run *before* the servlet — but they operate on the raw request, not the HttpServletRequest object. Container-managed security (e.g., <security-constraint>) is enforced earlier in the pipeline.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Jakarta EE Web Architecture", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Container creates HttpServletRequest and HttpServletResponse objects."}, {"itemId": "ITEM_B2_002", "content": "Container identifies the target servlet using URL mapping (e.g., @WebServlet)."}, {"itemId": "ITEM_B2_003", "content": "User submits HTML form with method=''post''."}, {"itemId": "ITEM_B2_004", "content": "Container calls the servlet''s service() method."}, {"itemId": "ITEM_B2_005", "content": "Container allocates a thread and passes request/response objects to it."}], "order": 5, "content": "Detective Lin reconstructs the exact moment a POST request enters the container. Arrange these steps in the correct order — from network arrival to servlet execution — based on CHUNK_008 and CHUNK_009.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B2_003", "ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_005", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. This matches the Jakarta EE container specification: the request arrives → container resolves mapping → creates request/response → allocates thread → invokes service(). Understanding this flow reveals where failure occurred — e.g., if request is created but response isn''t initialized, the bug lies *inside* service(), not in routing.", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"], "feedbackIncorrect": "Not quite. Remember: the container must resolve the servlet *before* creating objects (to know which class to instantiate), and it creates request/response *before* allocating the thread (since those objects are passed *to* the thread). Review CHUNK_008 for the canonical six-step flow.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "In the Debug Chamber simulation, Detective Lin isolates the failing line: ''response.getWriter().println(\"Success\");''. The stack trace shows java.lang.IllegalStateException: getWriter() has already been called. To fix this, the developer must ensure all calls to ________ happen *before* any call to getWriter() or getOutputStream().", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["setHeader", "setContentType", "setStatus", "setDateHeader", "addCookie", "addHeader"], "feedbackCorrect": "Correct. HttpServletResponse headers and status codes must be set *before* acquiring an output stream — because the HTTP protocol requires headers to precede the body. Once getWriter() or getOutputStream() is called, the container assumes headers are finalized and locks them.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Try again. Think about what part of the HTTP response must be sent *first*: the status line and headers. Methods that configure those — like setContentType() or setStatus() — must be called before any body-writing method.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the fragmented log from the crashed onboarding form. The raw query string shows ''name=Alex&company_size=100-200&ide=eclipse&ide=netbean&newsletter=true''. Which conclusion is *immediately supported* by this evidence?", "options": [{"content": "The browser sent checkbox values correctly — ''ide'' appears twice, matching HTML checkbox behavior.", "feedback": "Correct. Multiple identical parameter names (ide=eclipse&ide=netbean) is how browsers encode checked checkboxes — proving the client submitted them properly. The issue lies downstream in servlet handling.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "The form used GET instead of POST — visible in the URL-encoded parameters.", "feedback": "Incorrect. While GET places parameters in the URL, this log fragment alone doesn’t prove the HTTP method. POST requests can also include URL-encoded bodies (e.g., application/x-www-form-urlencoded), and the log shows raw data — not the full request line. Method identification requires headers or context.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The server rejected the ''newsletter'' parameter because it’s a boolean — servlets only accept strings.", "feedback": "Incorrect. Servlets *only* receive string parameters — booleans, numbers, and dates must be parsed manually from strings. ''newsletter=true'' is a perfectly valid parameter; its interpretation as a boolean happens in application code, not the container.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "The ''ide'' parameter conflict caused a parsing error — servlets cannot handle duplicate keys.", "feedback": "Incorrect. Duplicate parameter names are not an error — they’re expected behavior for checkboxes and multi-selects. Servlets handle this via getParameter() (returns first value) and getParameterValues() (returns all values as a String[]).", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the Development Lab, Detective Lin compares two HTML forms: one with radio buttons for company size, another with checkboxes for IDEs. She notes both use ''name=\"employee\"'' and ''name=\"ide\"'', respectively. What is the *key difference* in how the servlet must retrieve these values?", "options": [{"content": "Use getParameter() for radio buttons (single selection) and getParameterValues() for checkboxes (multiple selections).", "feedback": "Correct. Radio buttons share a name but only one can be selected — getParameter() returns that single value. Checkboxes share a name but allow multiple selections — getParameterValues() returns an array of all checked values. Using getParameter() for checkboxes would only return the first checked item.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Both require getParameterValues() — radio buttons still send multiple values if JavaScript modifies them.", "feedback": "Incorrect. Standard HTML radio button behavior ensures only *one* value is submitted per name — getParameter() is sufficient and idiomatic. Relying on getParameterValues() adds unnecessary complexity and obscures intent.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Use getParameter() for both — checkboxes are treated as comma-separated strings by default.", "feedback": "Incorrect. Servlets do *not* auto-join checkbox values into a comma string. getParameter() returns only the first value encountered; subsequent values are lost unless getParameterValues() is used.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The servlet must parse the raw request body manually — HttpServletRequest doesn’t provide helper methods for forms.", "feedback": "Incorrect. HttpServletRequest provides high-level, encoding-aware methods like getParameter() and getParameterValues() precisely to avoid manual parsing. Raw body access (getInputStream()) is low-level, error-prone, and bypasses container-managed character encoding (e.g., UTF-8).", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin discovers Dr. Hale’s @WebServlet annotation maps to ''/onboard/*'', while Kaito’s HTML form submits to ''/onboard/submit''. What happens to the form’s POST request *before* any parameter extraction occurs?", "options": [{"content": "The container routes it to Dr. Hale’s interceptor servlet — so doPost() is never called on the intended onboarding servlet.", "feedback": "Correct. URL pattern matching happens *first* in the request lifecycle. ''/onboard/submit'' matches ''/onboard/*'', so the container dispatches to Dr. Hale’s servlet — bypassing Kaito’s handler entirely. No parameter extraction occurs in the *intended* servlet, making the missing doPost() irrelevant to the failure.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "The container throws a 404 error — the pattern ''/onboard/*'' doesn’t match ''/onboard/submit''.", "feedback": "Incorrect. ''/onboard/*'' is a valid path-mapping pattern that matches any path starting with ''/onboard/'', including ''/onboard/submit''. A 404 would only occur if *no* servlet matched the request.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The container forwards the request to the correct servlet after normalizing the URL.", "feedback": "Incorrect. Containers do *not* normalize or rewrite URLs for servlet dispatch. Matching is literal and pattern-based — ''/onboard/submit'' matches ''/onboard/*'', not ''/onboard/submit''.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The request reaches Kaito’s servlet, but getParameterValues() fails because the URL path contains ''submit''.", "feedback": "Incorrect. The URL path has no effect on parameter extraction methods. getParameterValues() depends solely on the request body’s form-encoded data, not the path segment.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "In the Debug Chamber simulation, Detective Lin observes: getParameter(''name'') → ''Alex'', getParameter(''employee'') → ''100-200'', but getParameterValues(''ide'') → null. All three fields were checked/submitted. What is the *most likely root cause*?", "options": [{"content": "The request was routed to the wrong servlet — Dr. Hale’s interceptor — which doesn’t call getParameterValues(''ide'') and discards the parameter.", "feedback": "Correct. This explains the asymmetry: single-value parameters (''name'', ''employee'') are present because the interceptor likely calls getParameter() for logging, but it ignores multi-value parameters like ''ide'' — never invoking getParameterValues(). The null result confirms the intended servlet never ran.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_004"]}, {"content": "The browser encoded checkboxes incorrectly — ''ide'' values should appear as ''ide[]=eclipse&ide[]=netbean''.", "feedback": "Incorrect. Standard HTML form submission uses repeated parameter names (''ide=eclipse&ide=netbean''), not bracket notation. That syntax is PHP-specific and unsupported by Jakarta EE servlets.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Kaito’s servlet has a null check: if (request.getParameterValues(''ide'') == null) { throw new RuntimeException(); } — causing early failure.", "feedback": "Incorrect. While possible, this would crash the servlet *after* reaching it — but the logs show no response generation at all. Also, robust code checks for null *before* using the array, not to throw errors.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "The form’s enctype was set to ''multipart/form-data'', requiring getParts() instead of getParameterValues().", "feedback": "Incorrect. ''multipart/form-data'' is only required for file uploads. Plain text/checkbox forms use ''application/x-www-form-urlencoded'' — the default — which is fully handled by getParameter() and getParameterValues().", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Container calls doPost() on the target servlet."}, {"itemId": "ITEM_B3_002", "content": "Servlet calls request.getParameter(''name'') to extract the applicant''s name."}, {"itemId": "ITEM_B3_003", "content": "Servlet calls request.getParameterValues(''ide'') to collect all selected IDEs."}, {"itemId": "ITEM_B3_004", "content": "Servlet writes HTML response using response.getWriter().println()."}], "order": 5, "content": "Detective Lin reconstructs the exact sequence of events when a user submits the onboarding form with name, company size (radio), and IDEs (checkboxes). Order these steps as they occur *inside the servlet* — from receiving the request to populating the response.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The container invokes doPost() first. Inside that method, parameter extraction (getParameter / getParameterValues) must happen *before* writing to the response — otherwise, headers may be committed and output corrupted. Business logic and response generation follow.", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_003"], "feedbackIncorrect": "Incorrect. Remember: doPost() is the entry point — everything else happens inside it. Parameter extraction must precede response writing to ensure data is available for business logic and safe output generation.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin sees the HTML form uses <input type=\"checkbox\" name=\"ide\" value=\"eclipse\">. To retrieve *all* selected IDEs in the servlet’s doPost() method, she must call request.__________(\"ide\") — not getParameter().", "options": null, "sceneId": "SCENE_001", "learnMore": null, "difficulty": 2, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["getParameterValues", "getparametervalues", "getparametervalues()"], "feedbackCorrect": "Correct. getParameterValues() returns a String[] containing all values for the named parameter — essential for checkboxes and multi-selects. Using getParameter() would only return the first checked value.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. The method is getParameterValues (with capital V and plural ''Values''). It’s specifically designed for parameters that can have multiple values — like checkboxes sharing the same ''name'' attribute.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the sabotage by reconstructing the servlet execution flow.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once worked on the same project as Dr. Hale but left due to ethical disagreements about code transparency.", "background": "A seasoned digital forensic analyst with deep expertise in Java-based enterprise systems. Known for solving complex middleware failures.", "occupation": "System Integrity Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and curious.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_007", "CONC_008", "CONC_009"]}, {"age": 42, "goal": "Protect her reputation and prevent exposure of unauthorized code changes.", "name": "Dr. Elara Hale", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Modified URL mappings to hide an experimental AI logging module that violates compliance policies.", "background": "Pioneer of the company''s Jakarta EE migration. Designed the core servlet framework now under investigation.", "occupation": "Lead Architect, Enterprise Systems", "characterId": "CHAR_002", "personality": "Brilliant but secretive, values control over collaboration.", "knowledgePoints": ["CONC_004", "CONC_008", "CONC_001", "CONC_002"]}, {"age": 29, "goal": "Avoid being blamed for the outage while proving he can fix it.", "name": "Kaito Tanaka", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Accidentally deleted a key doPost() method during refactoring and tried to cover it up.", "background": "Recent hire tasked with maintaining form-handling servlets. Has shown frustration with legacy design patterns.", "occupation": "Junior Backend Developer", "characterId": "CHAR_003", "personality": "Eager, idealistic, slightly anxious when challenged.", "knowledgePoints": ["CONC_005", "CONC_006", "CONC_007", "CONC_009", "CONC_003"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Servlet", "category": "Core Concept", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A Java class that extends functionality of a server, handling client requests and generating dynamic responses in enterprise applications.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_007", "CONC_008"]}, {"name": "Web Container", "category": "Infrastructure", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "Runtime environment that manages servlets, handles threading, and enforces security policies in Jakarta EE applications.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_008"]}, {"name": "HTTP Request-Response Lifecycle", "category": "Process", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Sequence of events from client request initiation to server response delivery, including parsing, processing, and rendering phases.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"]}, {"name": "URL Mapping", "category": "Configuration", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Configuration that binds incoming URLs to specific servlets or methods using annotations or deployment descriptors.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "HttpServletRequest", "category": "API", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Interface providing access to client request data such as parameters, headers, and session information.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_009", "CONC_003"]}, {"name": "HttpServletResponse", "category": "API", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Interface used to send responses back to clients, including status codes, headers, and output content.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "doGet() and doPost() Methods", "category": "Methodology", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Servlet methods that handle HTTP GET and POST requests respectively, defining logic for retrieving and submitting data.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_009"]}, {"name": "Jakarta EE Web Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 4, "description": "Enterprise platform standard for building scalable, secure, and maintainable web applications using servlets and related technologies.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004"]}, {"name": "Form Data Handling", "category": "Application Logic", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Process of capturing, validating, and processing user input from HTML forms via servlets using request objects.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_005", "CONC_007", "CONC_003"]}], "educational_goals": ["Understand the role of servlets in enterprise systems development", "Explain the HTTP request-response lifecycle within a web container", "Apply knowledge of HttpServletRequest and HttpServletResponse for form data handling", "Map URLs to servlet methods using doGet() and doPost()", "Synthesize understanding of Jakarta EE web architecture through problem-solving"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 3}}', '307dba01e492c9b0576a5195dd29f33c031273a74804f218bc6594620cfae249', 'Servlet Advantages & Use Cases', '2026-04-03 14:32:12.572976', NULL, 'ITP4511') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('475cd301-cb19-4389-b98f-ef731a0ff99f', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '085d88c2-a840-4562-a7f0-7f8fdd0e9d5c', NULL, 'The ABAP Archives: A Data Breach Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "SE11 Transaction Snapshot", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The victim was actively configuring a transaction table — consistent with APPL1 (frequently changed data) — and had deliberately disabled buffering, suggesting urgency or performance trade-offs.", "description": "A frozen terminal screen showing the ABAP Dictionary (SE11) open to a table definition named ZMM_INVOICE_HDR. The ''Technical Settings'' tab is visible, with Data Class set to APPL1 and Size Category ''0''. Buffering is disabled.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Domain Definition Printout", "type": "physical", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Marcus was auditing domain reuse and noticed inconsistent foreign key enforcement — a red flag for referential integrity violations.", "description": "A crumpled A4 printout from SAP GUI showing domain ZDOM_CURRENCY_CODE. It defines data type CHAR, length 5, no decimal places, and includes fixed values: ''USD'', ''EUR'', ''GBP'', ''JPY''. A handwritten note reads: ''Used in 3 tables — but only 2 have FKs.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_009"]}, {"name": "Data Element Metadata Overlay", "type": "digital", "clueId": "CLUE_B1_003", "foundBy": "CHAR_003", "reveals": "Nina flagged this during peer review: the data element inherits domain constraints but lacks search help — increasing risk of invalid manual entry, especially without foreign key validation.", "description": "A screenshot overlay of SE11’s Data Element view for ZDE_INVOICE_AMT. Shows ''Domain: ZDOM_CURRENCY_CODE'', ''Short Description: Invoice Amount in Local Currency'', and a warning triangle icon next to ''Search Help'' — labeled ''Not assigned''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_011"]}, {"name": "Table Field Attribute Log", "type": "system_log", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Marcus discovered the critical misconfiguration *in real time*: a key field using a currency domain but missing its required foreign key — enabling invalid currency codes to be saved as primary keys.", "description": "A timestamped excerpt from system log SM21: ''Field ZINV_CURR_KEY in ZMM_INVOICE_HDR — Key Flag = X, Initial Value Indicator = blank. Domain ZDOM_CURRENCY_CODE applied. No foreign key defined.'' Timestamp: 23:47:12 — 2 minutes before Marcus’s last system login.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_009"]}, {"name": "ABAP Dictionary Activation Timeline", "type": "system_log", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Dr. Grant activated all core objects — including the domain and data element — but skipped defining the foreign key on the table field, violating his own architectural standards.", "description": "A filtered activation history from SE09: ZMM_INVOICE_HDR activated at 23:45:03; ZDE_INVOICE_AMT activated at 23:45:11; ZDOM_CURRENCY_CODE activated at 23:44:55. All by user EGRANT — not Marcus.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"name": "Corrupted View Definition Snippet", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Marcus was debugging a misconfigured database view — specifically, he’d noticed it used an outer join where an inner join was required, violating the intended referential integrity.", "description": "A fragment of ABAP Dictionary source code recovered from Marcus’s unsaved session. Shows a view definition with inconsistent join types and missing table aliases.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Structure Interface Log", "type": "digital", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Nina was validating how the structure mapped to module pool screens — confirming she understood its role as a work area template, not a persistent table.", "description": "A timestamped SAP GUI trace showing Nina’s recent use of SE11 to inspect structure ZSTR_SALES_HEADER — including field components and usage in screen PAI logic.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006"]}, {"name": "Table Type Activation Report", "type": "digital", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Dr. Grant approved a table type with a hashed access mode but assigned a non-unique line type — a technical violation that would break range-table functionality in selection screens.", "description": "An automated system log showing failed activation of table type ZTT_SALES_RANGES due to mismatched line type and access mode configuration.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Technical Settings Audit Snapshot", "type": "digital", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Marcus had annotated ‘Buffering off for APPL1? Risky at scale’ — indicating he’d spotted Dr. Grant’s decision to disable buffering on a high-write transaction table without justification.", "description": "A side-by-side comparison of technical settings between table ZTAB_CUSTOMERS (buffering enabled, APPL0) and ZTAB_TRANSACTIONS (buffering disabled, APPL1) — with red-flagged size category mismatches.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "Corrupted Foreign Key Definition", "type": "system_log", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Dr. Grant disabled the foreign key constraint to bypass validation during deployment — violating referential integrity.", "description": "A screenshot from Marcus''s terminal showing an ABAP Dictionary transaction (SE11) where the foreign key relationship for ZFLIGHT_CARRIER was defined but the ''Check Table'' field is blank and the ''Cardinality'' dropdown shows ''1..n'' with a warning icon.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Value Table Mismatch", "type": "dictionary_object", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The system *could* have enforced data integrity via a foreign key using the existing value table — but it wasn’t configured, enabling invalid carrier IDs to be entered.", "description": "A printed ABAP Dictionary export snippet showing domain ZCARR_ID linked to value table SCARR, yet no foreign key is assigned to the ZFLIGHT-CARRID field — meaning input validation is inactive despite valid values being defined.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_010", "CONC_009"]}, {"name": "F4 Help Failure Log", "type": "application_log", "clueId": "CLUE_B3_003", "foundBy": "CHAR_003", "reveals": "Search help (F4) was never activated because the foreign key — which would auto-provide the check table as the default source — was omitted. This degraded usability *and* data accuracy.", "description": "An SAP GUI trace log showing repeated ''No search help available'' errors when Nina attempted to enter CARRID on transaction ZFLIGHT_MAINT — indicating missing or mislinked search help despite a domain with a value table existing.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_011", "CONC_009"]}, {"name": "ENQUEUE/DEQUEUE Call Stack", "type": "debug_trace", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The lock object for ZFLIGHT was never generated — meaning concurrent edits were uncontrolled. Marcus discovered this while tracing why corrupted flight records appeared after parallel test runs.", "description": "A stack trace from Marcus’s last debug session showing an ENQUEUE_EZFLIGHT call failing with ''LOCK_OBJECT_NOT_FOUND'', followed by an immediate INSERT into ZFLIGHT without lock acquisition — exposing a race condition.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_012"]}, {"name": "Incomplete Delivery Class Setting", "type": "digital", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The table was improperly classified for transport and upgrade handling, indicating a deliberate bypass of standard procedures.", "description": "A partial configuration in the ABAP Dictionary shows that the new table''s delivery class was set to ''C'' but never finalized. This suggests customizing data meant to be customer-maintained, yet no transport request was logged.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}, {"name": "Transport Log Anomaly", "type": "system_log", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Someone used a restricted delivery class to block data inclusion during transport, hiding changes from audit review.", "description": "System logs show that while the table structure was transported, its data records were excluded—consistent with delivery class ''S'' or ''C''. However, the development team had no authorization to transport system tables.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Hidden Upgrade Override Flag", "type": "configuration_flag", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "The delivery class was manipulated not just for transport control, but to ensure faulty data survived system updates.", "description": "Deep within the technical settings, an override flag labeled ''No Data Overwrite During Upgrade'' is active. This only applies to delivery classes A and C, but combined with missing foreign keys, it allowed corrupted data to persist.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_013"]}], "title": "The ABAP Archives: A Data Breach Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Body in the Server Room", "sceneId": "SCENE_001", "location": "Indoor - Locked Development Office, Floor 3", "description": "Detective Chen arrives at the crime scene where senior developer Marcus Reed was found dead at his desk. His terminal is still open, displaying an incomplete ABAP Dictionary transaction. Nina Patel is present, visibly shaken. Initial signs suggest no forced entry. The focus shifts to Marcus’s last actions in the system.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Interrogation in the War Room", "sceneId": "SCENE_002", "location": "Indoor - Conference Room, SAP Governance Suite", "description": "Chen interviews both suspects. Dr. Grant defends his architectural decisions while downplaying any risks. Nina reveals that Marcus was finalizing a new database table with unusual technical settings and had questioned a missing foreign key. Tensions rise as conflicting stories emerge about system access and change approvals.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Lock Object Paradox", "sceneId": "SCENE_003", "location": "Indoor - Central Control Terminal, Data Center", "description": "Using evidence from the system logs and dictionary definitions, Chen reconstructs Marcus’s final steps. She reveals how a misconfigured lock object allowed unauthorized changes, and how a missing foreign key relationship enabled corrupted data entry. Both suspects are confronted with their roles in the systemic failure that led to Marcus’s fatal discovery.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth in the Metadata", "content": "Dr. Grant confesses: he disabled the foreign key and altered the lock object to meet a deadline. Marcus discovered the breach and threatened exposure. While Grant didn’t intend murder, his negligence created the conditions for sabotage. Nina provides the final log proof. System integrity is restored, and governance reforms are initiated.", "debrief": "You’ve mastered how SAP dictionary objects enforce data integrity. Misconfigurations in foreign keys, lock objects, or delivery classes can lead to catastrophic failures.", "summary": "The killer was not a person, but poor governance—exposed through understanding SAP’s foundational concepts.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation", "content": "Without full evidence, Nina is wrongly suspected of tampering to cover her inexperience. The real flaws in the system remain hidden. Months later, a data corruption crisis erupts, traced back to the same unpatched configurations.", "debrief": "Jumping to conclusions without analyzing all components—like technical settings and lock mechanisms—leads to systemic risk.", "summary": "Incomplete investigation results in repeated failure. Mastery of all SAP dictionary concepts is essential.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In the quiet halls of a corporate SAP development office, a senior developer is found dead under suspicious circumstances. The detective must unravel the truth hidden in metadata, foreign keys, and technical settings—where every database object tells a story and only those who understand the ABAP Dictionary can uncover the killer.", "version": "1.0", "evidence": [{"name": "Incomplete Table Definition Draft", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A saved draft of a new database table showing missing foreign key constraints and unusual buffering settings.", "foundLocation": "Victim''s workstation", "relatedKnowledge": ["CONC_004", "CONC_008", "CONC_009"]}, {"name": "System Log Excerpt", "type": "Digital Record", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Log showing unauthorized modification of a lock object shortly before the victim’s death.", "foundLocation": "Server audit trail", "relatedKnowledge": ["CONC_012", "CONC_001"]}, {"name": "Email Chain on Delivery Class Dispute", "type": "Communication", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Internal emails revealing conflict between Dr. Grant and the victim over transport-safe delivery class settings.", "foundLocation": "Email server archive", "relatedKnowledge": ["CONC_013", "CONC_008"]}], "has_quiz": false, "scriptId": "SAP_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines Marcus’s open SE11 session. The screen shows a table definition with fields like ZINV_ID, ZINV_DATE, and ZINV_CURR_KEY — all defined with data elements. She notes that each field’s technical attributes (data type, length, description) are *not* defined directly on the table, but inherited. What ABAP Dictionary object serves as the semantic and technical bridge between the domain’s value range and the table field’s usage?", "options": [{"content": "Domain", "feedback": "A domain defines *only* the value range and technical basics (like data type and length), but it doesn’t provide semantic meaning or screen-level metadata. It’s a foundation — not the bridge.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Data Element", "feedback": "Correct. A data element inherits technical properties from a domain (e.g., CHAR(5)) but adds semantic meaning (e.g., ''Currency Key'') and UI metadata (e.g., short description, search help). This ensures consistent, meaningful field definitions across all tables using it — exactly what Chen sees here.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_003"]}, {"content": "Transparent Table", "feedback": "A transparent table is the physical database representation — it holds data, not definitions. Its fields reference data elements, but the table itself doesn’t mediate semantics.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Structure", "feedback": "Structures group fields for program interfaces or screens, but they don’t link domains to table fields or carry semantic documentation like data elements do.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_001", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Chen zooms in on the domain ZDOM_CURRENCY_CODE used by ZDE_INVOICE_AMT. Its definition shows ''Data Type: CHAR'', ''Length: 5'', and under ''Value Range'', two entries: ''Lower limit: USD'', ''Upper limit: USD'' — plus discrete values ''EUR'', ''GBP'', ''JPY''. What is the *primary purpose* of defining such a value range in a domain?", "options": [{"content": "To assign a default value when the field is empty", "feedback": "Domains do not define defaults — initial values are controlled by field attributes (e.g., ''Initial Value Indicator'') or program logic, not domain value ranges.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "To enforce data integrity by restricting allowable field entries across all dependent fields", "feedback": "Exactly. By defining fixed values (EUR, GBP, etc.) and limits (USD–USD), the domain guarantees that *any* field using ZDE_INVOICE_AMT — across every table and program — can only accept those valid currency codes. This is central to SAP’s consistency model.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "To determine how the field appears on selection screens", "feedback": "Screen appearance (e.g., dropdown vs. free text) is governed by search helps or input templates — not domain value ranges. A domain restricts *what* can be entered, not *how* it''s entered.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "To map the field to an ABAP data type in programs", "feedback": "Data type mapping (e.g., CHAR → c(5)) happens automatically during activation — it’s handled by the ABAP runtime, not configured in the domain’s value range.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "During interrogation, Dr. Grant insists: ''All tables follow SAP standards — ZMM_INVOICE_HDR is a transparent table, fully mapped to the database.'' Nina counters: ''But it’s missing a foreign key on ZINV_CURR_KEY — so nothing stops someone from entering \"XYZ\" as a currency, even though ZDOM_CURRENCY_CODE only allows USD/EUR/GBP/JPY.'' What critical role does a foreign key play *beyond* what the domain already enforces?", "options": [{"content": "It enforces the domain’s value range at the database level during INSERT/UPDATE operations", "feedback": "False. Domains enforce value ranges *at the application layer* (e.g., via input checks), but they don’t create database-level constraints. A foreign key does — and it’s enforced by the RDBMS itself.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It ensures referential integrity by validating field values against a check table — preventing orphaned or invalid entries, even if domain validation is bypassed", "feedback": "Yes. While the domain restricts input *in SAP GUI*, a foreign key creates an actual database constraint. If someone inserts ''XYZ'' via direct SQL or a custom program that skips domain checks, the foreign key will reject it — protecting data integrity at the deepest layer. That’s why Marcus called it ''fatal''.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B1_004"]}, {"content": "It automatically assigns the correct data element to the field during table activation", "feedback": "No — data elements are manually assigned to fields in SE11. Foreign keys are defined separately and do not auto-assign metadata.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It enables buffering for improved performance on frequently accessed tables", "feedback": "Buffering is configured in Technical Settings — independent of foreign keys. In fact, buffered tables require special handling for foreign key checks.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 4, "questionId": "Q_B1_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Define domain ZDOM_CURRENCY_CODE (data type, length, value range)"}, {"itemId": "ITEM_B1_002", "content": "Create data element ZDE_INVOICE_AMT (assign ZDOM_CURRENCY_CODE, add description)"}, {"itemId": "ITEM_B1_003", "content": "Define table ZMM_INVOICE_HDR and add field ZINV_CURR_KEY"}, {"itemId": "ITEM_B1_004", "content": "Assign ZDE_INVOICE_AMT to ZINV_CURR_KEY field"}], "order": 4, "content": "Nina pulls up the activation history for ZMM_INVOICE_HDR. To reconstruct Marcus’s final workflow, Chen must sequence the *logical dependency order* of ABAP Dictionary object creation — what must exist *before* a table field can correctly reference a data element, which in turn relies on a domain. Arrange these steps in the correct build order:", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. ABAP Dictionary follows strict dependency hierarchy: domains (foundation) → data elements (semantic layer) → table fields (usage). You cannot assign a data element until it exists, and you cannot assign a domain to a data element until the domain is defined.", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"], "feedbackIncorrect": "Remember: dependencies flow upward. A data element requires a domain to exist first; a table field requires a data element to exist first. Reordering reveals where the chain broke — and who bypassed it.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "At the control terminal, Chen runs a diagnostic query and confirms: ZMM_INVOICE_HDR has no foreign key on ZINV_CURR_KEY — but the domain ZDOM_CURRENCY_CODE *does* specify valid values. She types into the command line: ''The ABAP Dictionary object that centrally manages these definitions — domains, data elements, tables, views — and ensures consistent data usage across all system components is the ________.''", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["ABAP Dictionary", "ABAP Data Dictionary"], "feedbackCorrect": "Correct. The ABAP Dictionary is the single source of truth — it defines logical structures, maps them to physical database objects, and propagates changes (e.g., domain updates) across all dependent components. Its failure to enforce the foreign key was the systemic crack Marcus died uncovering.", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"], "feedbackIncorrect": "Hint: It’s the foundational repository — referenced by transaction code SE11 — that unifies data definitions across development, runtime, and administration layers.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines Marcus’s open ABAP Dictionary tab. The view ZVW_CUSTOMER_ORDERS shows two tables joined — but the join condition references SCARR~CARRID = SPFLI~CARRID *without* specifying JOIN TYPE. Based on the metadata panel, SCARR is flagged as ''value table'' for S_CARR_ID, while SPFLI has no foreign key to SCARR. What type of view is this most likely — and why is it dangerous here?", "options": [{"content": "A database view — but incorrectly implemented: it''s attempting an inner join without declaring it, and lacks a foreign key to enforce referential integrity.", "feedback": "Correct. Database views require explicit inner joins and rely on foreign keys for data consistency. Without them, this view could return orphaned or invalid carrier IDs — exactly what Marcus was investigating before his death.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "A maintenance view — designed for multi-table editing, so missing foreign keys are acceptable for flexibility.", "feedback": "Incorrect. Maintenance views *do* use outer joins, but they still require foreign keys to ensure meaningful relationships during data entry. Missing them risks corrupting master data — which contradicts Marcus’s notes about ''integrity failure''.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A help view — meant only for search helps, so join correctness isn’t critical for runtime behavior.", "feedback": "Incorrect. Help views *must* use outer joins to display all possible values — but even then, missing foreign keys undermine their purpose by allowing invalid selections. Marcus’s annotations show he treated this as a systemic risk, not a UI convenience.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Chen reviews Nina’s recent SE11 activity. She opened structure ZSTR_SALES_HEADER — which contains fields like ORDER_ID (data element DEMO_ORDER_ID), CUST_NAME (data element DEMO_CUST_NAME), and NET_VALUE (data element DEMO_NET_VALUE). In the Attributes tab, ''Delivery Class'' is blank and ''Data Browser Display'' is disabled. What is the *primary functional purpose* of this structure — and why wouldn’t it appear in database storage?", "options": [{"content": "It defines a reusable composite data type for screen interfaces and function module parameters — and has no database representation because structures don’t generate physical tables.", "feedback": "Correct. Structures are purely logical ABAP constructs — they serve as templates for work areas and interface definitions. That’s why Delivery Class is irrelevant and Data Browser access is disabled: there’s no underlying table to display or maintain.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_002"]}, {"content": "It’s a lightweight alternative to a transparent table — used when buffering isn’t needed, so it skips database persistence for performance.", "feedback": "Incorrect. Transparent tables *always* have physical database counterparts. Structures do not map to tables at all — they exist only in the ABAP layer. Confusing them with tables undermines data governance, which Marcus rigorously upheld.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It’s a type alias for a table type — enabling internal table reuse across programs without redefining components.", "feedback": "Incorrect. Table types reference structures as line types — but structures themselves are not aliases. They’re independent composite types. This distinction matters: Marcus flagged misuse of structures as ''interface drift'' in his audit notes.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "During interrogation, Dr. Grant insists ZTT_SALES_RANGES was ''fully compliant'' — yet Chen pulls up its definition: Line Type = ZSTR_SALES_HEADER, Access Mode = Hashed, Key = NON-UNIQUE. Why does this configuration violate ABAP Dictionary rules — and what real-world impact would it cause in a sales order selection screen?", "options": [{"content": "Hashed access mode requires a UNIQUE key to guarantee O(1) lookup — using NON-UNIQUE breaks hash algorithm integrity, causing unpredictable crashes or duplicate entries in ranges tables.", "feedback": "Correct. Hashed table types demand unique keys to compute unambiguous hash values. With NON-UNIQUE, collisions occur — leading to data loss or runtime dumps in selection screens. Marcus’s fatal discovery was that this flaw allowed malicious range overrides.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "It’s acceptable — hashed mode only requires a key; uniqueness is optional for ranges tables since they support multiple value intervals.", "feedback": "Incorrect. Ranges tables *depend* on deterministic lookups. Non-unique hashed keys break the fundamental contract of hashing — resulting in silent data corruption. This matches Marcus’s log entry: ''ZTT crash on SELECT... WHERE IN RANGE''.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "The error is in Line Type: ZSTR_SALES_HEADER must be replaced with a data element for scalar ranges — structures aren’t valid for table types.", "feedback": "Incorrect. Structures are *valid and common* line types for table types — especially for complex ranges. The flaw is strictly the key/access mode mismatch. Dr. Grant’s attempt to blame the structure reveals his lack of foundational ABAP Dictionary knowledge.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Buffering disabled on ZTAB_TRANSACTIONS (APPL1) despite 500+ daily updates"}, {"itemId": "ITEM_B2_002", "content": "Size Category set to 0 for ZTAB_CUSTOMERS (APPL0), risking rapid extent fragmentation"}, {"itemId": "ITEM_B2_003", "content": "Logging disabled on ZTAB_TRANSACTIONS, hiding unauthorized changes"}, {"itemId": "ITEM_B2_004", "content": "Data Class set to APPL0 for ZTAB_TRANSACTIONS — misclassifying volatile data as master data"}], "order": 4, "content": "Chen reconstructs Marcus’s final technical settings review. He compared four configuration decisions across two tables. Order these settings by *priority of risk impact* — from MOST immediately dangerous (e.g., causes data corruption or security breach) to LEAST (e.g., performance nuisance).", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": ["ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_001", "ITEM_B2_002"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Logging disabled is most dangerous — it erases forensic trails of tampering. Misclassifying transaction data as master data (APPL0) violates transport and upgrade logic, risking system instability. Disabled buffering harms performance but doesn’t corrupt data. Size Category 0 is suboptimal but recoverable via reorganization.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Prioritize by *integrity and traceability* first: logging loss hides evidence; wrong data class breaks transports; buffering affects speed; size category is a tuning parameter. Marcus’s notes show he escalated logging and data class issues to Governance before his death.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "Nina nervously confirms Marcus asked her: ''If a view uses an outer join to link SCARR and SPFLI, but SCARR has no primary key defined in the Dictionary — what type of view is it *technically*, and what critical capability does it lose?'' Fill in the blank with the precise ABAP Dictionary term: ''It’s a ________ view — and it loses reliable input validation.''", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["help", "Help", "HELP"], "feedbackCorrect": "Correct. A help view uses an outer join to display all possible values (e.g., all carriers, even if no flights exist). But without a primary key in SCARR, the view can’t enforce input validation — meaning users could enter invalid carrier IDs with no system check. This is the ''missing foreign key'' Marcus warned about.", "relatedKnowledge": ["CONC_009"], "feedbackIncorrect": "Incorrect. The view type is ''help view'' — defined by its outer join purpose for search helps. Its inability to validate inputs stems directly from the missing primary key (and thus missing foreign key relationship). Marcus’s terminal showed this exact scenario before he died.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines Marcus’s open SE11 session. She sees that field ZFLIGHT-CARRID references domain ZCARR_ID — which has SCARR listed as its value table — yet no foreign key is defined. What critical safeguard is *missing*, allowing invalid carrier IDs to be saved?", "options": [{"content": "A foreign key relationship linking ZFLIGHT-CARRID to SCARR as the check table", "feedback": "Correct. Without an explicitly defined foreign key, the value table SCARR remains inert — no referential integrity, no input validation, and no automatic F4 help. The domain’s value table is only a proposal; the foreign key activates it.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "A search help (F4 help) manually assigned to the ZFLIGHT-CARRID field", "feedback": "Incorrect. While a search help *could* provide input assistance, it wouldn’t enforce referential integrity or prevent invalid entries — only a foreign key does that. Also, without a foreign key, the system won’t auto-suggest SCARR as the source.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A secondary index on ZFLIGHT-CARRID to improve query performance", "feedback": "Incorrect. Indexes optimize read performance but do nothing to validate data or maintain consistency. This is about data correctness — not speed.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A domain-level fixed value list instead of a value table", "feedback": "Incorrect. Fixed value lists in domains restrict entries at the domain level, but they’re static and hard to maintain. A foreign key leverages the live, updatable check table (SCARR) — enabling cascading updates, navigation, and dynamic validation.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Foreign Key Relationship", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During interrogation, Dr. Grant insists, ''The value table SCARR was already assigned — that’s enough for data integrity.'' Nina counters, ''But without the foreign key, it’s just documentation.'' Who is technically correct — and why?", "options": [{"content": "Nina is correct: A value table only becomes an active check table once a foreign key is defined. Until then, no validation occurs.", "feedback": "Correct. As CHUNK_025 states: ''The check against the value table only takes effect when a foreign key has been defined.'' The value table is merely a suggestion — the foreign key is the enforcement mechanism.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Dr. Grant is correct: Assigning a value table automatically enables input validation and prevents invalid entries.", "feedback": "Incorrect. Value tables define *valid values*, but they don’t enforce them unless bound via a foreign key. Without it, users can freely type any value — even ''XXXX'' — into CARRID.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Both are partially right: Value tables enable F4 help, while foreign keys handle database constraints — but neither replaces the other.", "feedback": "Partially true but misleading. F4 help does *not* activate automatically from a value table alone — it requires either a foreign key (which auto-links the check table) or an explicit search help assignment. So without the foreign key, F4 also fails.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Neither is correct: Data integrity is enforced by the lock object, not foreign keys or value tables.", "feedback": "Incorrect. Lock objects manage *concurrent access*, not data validity. Referential integrity is exclusively the domain of foreign keys — locking prevents two users from overwriting each other, but doesn’t stop either from entering ''ZZZZ'' as a carrier ID.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Value Table", "knowledgeId": "CONC_010"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Nina mentions that when she tried entering a carrier ID in ZFLIGHT_MAINT, no dropdown appeared — just a blank field. Detective Chen checks the field’s data element and sees it uses domain ZCARR_ID (with value table SCARR), but no foreign key exists. What component is *missing* that would normally provide the dropdown (F4 help)?", "options": [{"content": "A search help linked to the data element — or, more simply, a foreign key (which auto-provides the check table as the default search help source)", "feedback": "Correct. Per CHUNK_026 and CHUNK_025: Search helps deliver F4 assistance, and defining a foreign key automatically makes the check table available as the default source. No foreign key = no auto-F4. Manual search help could be added, but it wasn’t.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "A maintenance view that includes both ZFLIGHT and SCARR tables", "feedback": "Incorrect. Maintenance views support multi-table editing, but they don’t provide field-level input assistance like F4 help. That’s the role of search helps or foreign keys.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "A domain-level ''Parameter ID'' for user-specific defaults", "feedback": "Incorrect. Parameter IDs store user preferences (e.g., default printer), not input value lists. They have no role in F4 functionality.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "A secondary index on ZFLIGHT-CARRID to accelerate value lookups", "feedback": "Incorrect. Indexes improve SELECT performance but do not generate UI features like dropdowns. F4 help requires logic — not structure.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Search Help", "knowledgeId": "CONC_011"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Domain ZCARR_ID is created with SCARR assigned as its value table"}, {"itemId": "ITEM_B3_002", "content": "Foreign key is defined on ZFLIGHT-CARRID pointing to SCARR~CARRID"}, {"itemId": "ITEM_B3_003", "content": "ZFLIGHT table is activated, generating the foreign key check logic in the database layer"}, {"itemId": "ITEM_B3_004", "content": "User presses F4 on ZFLIGHT-CARRID field → SCARR data appears in dropdown"}], "order": 4, "content": "Detective Chen reconstructs Marcus’s final debugging session. Arrange these steps in the order they *must* occur for a foreign key to fully enforce referential integrity and enable F4 help — from definition to runtime behavior.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The value table must exist first (as a domain property), then the foreign key is defined to bind it to the field, then activation makes it operational in the system, and finally — at runtime — F4 triggers the now-active check table.", "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": "Incorrect. Remember: Value table is a prerequisite, not a substitute. The foreign key is the binding step — without it, activation does nothing for validation or F4, and pressing F4 yields no results.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "At the control terminal, Chen runs a diagnostic that reveals the root cause: the ZFLIGHT table allows inserts with invalid CARRID values *and* permits concurrent edits without conflict detection. She concludes: ''The system failed because two safeguards were absent — a ________ relationship to ensure data validity, and a properly generated ________ object to protect concurrent access.'' Fill in both blanks.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["foreign key", "lock"], "feedbackCorrect": "Correct. A foreign key enforces referential integrity (preventing invalid CARRID), and a lock object synchronizes concurrent access (preventing race conditions during parallel inserts). Their absence created both data corruption and timing vulnerabilities — the exact failure Marcus uncovered.", "relatedKnowledge": ["CONC_012"], "feedbackIncorrect": "Incorrect. The first blank refers to the structural safeguard for data correctness — ''foreign key''. The second refers to the runtime safeguard for concurrency — ''lock'' (as in ''lock object''). These are distinct but complementary layers of SAP data governance.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines Marcus’s open terminal. The incomplete table definition shows a delivery class set to ''C'', but the maintenance view is disabled. What does this imply about the table''s intended use and behavior?", "options": [{"content": "It is an application table for transaction data, meant to be fully editable and transported with data.", "feedback": "Incorrect. Class ''A'' is used for application tables. Class ''C'' restricts maintenance and transport behavior.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It is a customizing table, meant to be maintained only by the customer, with data excluded from automatic transport.", "feedback": "Correct. Delivery class ''C'' defines customer-specific customizing data that is not overwritten during upgrades and typically not transported with data.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_001"]}, {"content": "It is a system table maintained only by SAP, preventing any customer modifications.", "feedback": "Incorrect. System tables use delivery class ''S'', not ''C''. Class ''C'' allows customer maintenance but controls transport behavior.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "It is a temporary table for debugging, with no impact on transport or upgrade processes.", "feedback": "Incorrect. There is no delivery class for temporary debugging tables. All persistent tables have defined transport and upgrade behaviors.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During interrogation, Dr. Grant claims he never touched the table’s delivery settings. But Chen notices the transport logs exclude data despite the table holding critical master records. Which delivery class setting would explain this behavior while violating protocol?", "options": [{"content": "Class ''A'' – Application table: data is transported and can be changed freely, ideal for master data.", "feedback": "Incorrect. Class ''A'' includes data in transports. If this were used, the logs would show data migration, which they don’t.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Class ''C'' – Customizing table: data is customer-maintained but excluded from standard transports and protected during upgrades.", "feedback": "Correct. Using class ''C'' for master data is a misuse—it hides data from transport logs and prevents overwrite, enabling stealthy corruption.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B4_002"]}, {"content": "Class ''S'' – System table: maintained only by SAP, data never transported or changed by customers.", "feedback": "Incorrect. While this excludes data from transport, only SAP can define such tables. A developer cannot legally assign this class.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Class ''W'' – System with transportable contents: allows selective transport of system data, commonly used for configuration.", "feedback": "Incorrect. Class ''W'' is rare and tightly controlled. It doesn’t align with hiding master data changes in a custom module.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 4, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Chen reconstructs Marcus’s final actions. He discovered that the delivery class was set to ''C'', blocking data transport, and no foreign key enforced referential integrity. Why would combining these two misconfigurations allow long-term data corruption to go undetected?", "options": [{"content": "Because class ''C'' tables are automatically buffered, improving performance at the cost of real-time consistency.", "feedback": "Incorrect. Buffering is a technical setting, not directly tied to delivery class. This doesn’t explain undetected corruption.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Because class ''C'' prevents data from being overwritten during upgrades, preserving invalid entries, while missing foreign keys allow incorrect data input.", "feedback": "Correct. Delivery class ''C'' protects data during upgrades, so bad data persists. Without foreign keys, there’s no validation—enabling silent corruption.", "optionId": "OPT_B4_010", "showHint": null, "isCorrect": true, "nextSceneId": null, "unlockClues": ["CLUE_B4_003"]}, {"content": "Because class ''C'' disables logging, making it impossible to trace who made changes to the table.", "feedback": "Incorrect. Logging is controlled by technical settings, not delivery class. This option confuses two separate configurations.", "optionId": "OPT_B4_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}, {"content": "Because class ''C'' requires client-specific customization, delaying deployment until manual approval, which slowed detection.", "feedback": "Incorrect. While class ''C'' relates to customizing, the delay in detection stems from data persistence and lack of validation, not approval workflows.", "optionId": "OPT_B4_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_003", "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 5, "questionId": "Q_B4_003", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_009", "CONC_008"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "Define fields and assign data elements"}, {"itemId": "ITEM_B4_002", "content": "Set delivery class to ''C'' under technical settings"}, {"itemId": "ITEM_B4_003", "content": "Assign table to a development class"}, {"itemId": "ITEM_B4_004", "content": "Define foreign key relationship to validate entries"}, {"itemId": "ITEM_B4_005", "content": "Activate the table to generate database object"}], "order": 4, "content": "Reconstruct the correct sequence Marcus would have followed when defining the table in SE11. Pay attention to how delivery class fits into the activation workflow.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 5, "questionId": "Q_B4_004", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": ["ITEM_B4_001", "ITEM_B4_002", "ITEM_B4_004", "ITEM_B4_003", "ITEM_B4_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The proper order ensures structural definition before technical settings, followed by referential integrity, packaging, and activation.", "relatedKnowledge": ["CONC_004", "CONC_008"], "feedbackIncorrect": "Incorrect. Remember: fields and keys are defined first, then delivery class and development assignment, finally activation. Missteps here enabled the vulnerability.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "To prevent data from being overwritten during system upgrades, the attacker set the delivery class to ___. This class is typically used for customizing data and excludes data from standard transport mechanisms.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B4_005", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["C", "c"], "feedbackCorrect": "Correct. Delivery class ''C'' is designed for customer-specific customizing tables, protecting data during upgrades—exactly what was exploited here.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Think about which delivery class protects data during upgrades and is meant for customer-maintained customizing data. The answer is a single letter.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the developer''s death and preserve the integrity of the SAP system.", "name": "Detective Lara Chen", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She once bypassed a lock object to retrieve critical data during an audit, which could jeopardize her career if revealed.", "background": "Former SAP security auditor turned internal investigator after exposing a major data leak at a rival firm.", "occupation": "Corporate Security Investigator", "characterId": "CHAR_001", "personality": "Analytical, observant, calm under pressure, with a sharp eye for inconsistencies.", "knowledgePoints": ["CONC_001", "CONC_009", "CONC_012"]}, {"age": 52, "goal": "Protect his reputation and ensure no one discovers his shortcut that compromised data integrity.", "name": "Dr. Elias Grant", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003"], "secret": "He secretly disabled a foreign key constraint to speed up a deployment, violating protocol.", "background": "Pioneer of the company’s ERP migration; known for strict adherence to SAP standards.", "occupation": "Lead SAP Architect", "characterId": "CHAR_002", "personality": "Authoritative, meticulous, dismissive of junior staff, values precision above all.", "knowledgePoints": ["CONC_004", "CONC_008", "CONC_013"]}, {"age": 29, "goal": "Clear her name and ensure proper SAP governance is upheld without causing a scandal.", "name": "Nina Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She discovered the victim was planning to expose Dr. Grant’s configuration flaw and fears she’ll be blamed if it comes out.", "background": "Recent hire with a passion for clean data design; worked closely with the victim on a new module.", "occupation": "Junior ABAP Developer", "characterId": "CHAR_003", "personality": "Eager, idealistic, slightly nervous around seniors, deeply ethical about coding practices.", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_011"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "ABAP Dictionary", "category": "Core Concept", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Central repository in SAP for defining and managing data structures such as tables, views, and data elements.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_006"]}, {"name": "Domain", "category": "Data Definition", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "Defines technical attributes of a field, such as data type, length, and value range, used across multiple data elements.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_003", "CONC_010"]}, {"name": "Data Element", "category": "Data Definition", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "Describes the semantic meaning of a field and links a domain to a table field, providing documentation and formatting.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Database Table", "category": "Storage", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Physical storage structure in the database defined via the ABAP Dictionary, containing rows and columns of business data.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_009", "CONC_008", "CONC_013"]}, {"name": "View", "category": "Data Access", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Virtual table derived from one or more database tables, used to simplify queries or restrict data access.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_009"]}, {"name": "Structure", "category": "Logical Design", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Grouping of fields without physical existence, used in programs or interfaces to pass data.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_007", "CONC_004"]}, {"name": "Table Type", "category": "Programming", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Definition of a line type and table key used to declare internal tables in ABAP programs.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_006", "CONC_004"]}, {"name": "Technical Settings", "category": "Performance", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Configuration options for a database table including buffering, logging, and data class that affect performance and behavior.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_004", "CONC_013"]}, {"name": "Foreign Key Relationship", "category": "Integrity", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Link between two tables ensuring referential integrity by validating entries against a primary key in another table.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_004", "CONC_005", "CONC_010"]}, {"name": "Value Table", "category": "Validation", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Table assigned to a domain to automatically validate input values, enforced only when no foreign key exists.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_002", "CONC_009"]}, {"name": "Search Help", "category": "Usability", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "User assistance tool that provides valid value suggestions during data entry, enhancing usability and accuracy.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_003"]}, {"name": "Lock Object", "category": "Concurrency", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Mechanism to prevent concurrent access to data records during transactions, ensuring data consistency.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Delivery Class", "category": "Transport", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Specifies how a table’s data is handled during client copies and transports, affecting system lifecycle management.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_004", "CONC_008"]}], "educational_goals": ["Understand the core components of the ABAP Dictionary and their interrelationships", "Differentiate between domains, data elements, and database tables", "Explain how views, structures, and table types are used in SAP data modeling", "Apply knowledge of foreign key relationships, value tables, and search helps in real-world scenarios", "Analyze technical settings, delivery classes, and lock objects for system integrity"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 2}}', '3379edcbeeff9688ed8fca4310b051da982376435f31c355279da028540ffa40', 'all concepts', '2026-04-03 16:58:08.862331', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('d4157013-d5af-42b4-9db4-500c155d3aa0', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '1e596437-5301-42c0-8fa9-8997411d998e', NULL, 'The Case of the Corrupted Web App', 'active', 'easy', 'standard', '{"clues": [{"name": "Fragment of q1.jsp with Scriptlet", "type": "code_snippet", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Jia Chen used a JSP scriptlet to dynamically generate HTML content, indicating embedded Java logic in the view layer.", "description": "A partial JSP file showing a table structure and an incomplete scriptlet block. The getAllMedals() method is referenced but not yet implemented in the loop.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "medalDB.jsp Declaration Block", "type": "code_definition", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The getAllMedals() method is declared at the class level in a JSP, confirming use of JSP declarations for shared functionality.", "description": "A JSP file containing a declaration using <%! %> syntax that defines a reusable method getAllMedals(), which returns an array of image paths for medals.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "Output Trace from q1Handler.jsp", "type": "log_entry", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Dynamic values like user input are displayed using JSP expressions, exposing potential risks if unvalidated.", "description": "Log output shows the value of ''mark'' being rendered directly into the page via <%= mark %>, confirming use of JSP expressions for dynamic display.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_001"]}, {"name": "Execution Flow Map", "type": "diagram", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "The correct sequence of JSP components interacting reveals where responsibility lies for input handling and output generation.", "description": "A whiteboard sketch mapping how request flows from q1.jsp → q1Handler.jsp, including inclusion, parameter passing, and response rendering steps.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"]}, {"name": "JSP Directive Found in q1.jsp", "type": "code_evidence", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The frontend improperly included a utility JSP using a directive, violating clean separation of concerns.", "description": "A JSP directive <%@ include file=''medalDB.jsp'' %> was discovered in the q1.jsp source. This allowed access to the getAllMedals() method but exposed business logic in the view layer.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Servlet Lifecycle Misalignment", "type": "log_trace", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "The backend servlet did not complete its lifecycle setup, making it unable to handle requests even if frontend data was valid.", "description": "Log entries show that the ProductController servlet failed to initialize properly during deployment. The init() method threw an exception due to missing configuration parameters.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006", "CONC_011"]}, {"name": "JavaBean Validation Skipped", "type": "object_state", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "The backend assumed input sanitization would be done upstream, but the frontend passed raw user input directly.", "description": "The ict.bean.Product JavaBean was instantiated with null values for required fields. No validation occurred upon setProperty calls, allowing malformed data into the processing pipeline.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_007", "CONC_013"]}, {"name": "Error Handling Directive Missing", "type": "configuration_defect", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Improper use of JSP directives led to unhandled runtime errors propagating to the server core.", "description": "The q1Handler.jsp lacks the page directive specifying errorPage=''handleError.jsp'', meaning exceptions were not redirected and instead crashed the thread.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_010"]}, {"name": "Fragment: q1.jsp Includes medalDB.jsp", "type": "code_fragment", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The frontend relies on included JSP components to access shared methods, violating clean separation of concerns.", "description": "A partial JSP directive found in the server cache: <%@ include file=''medalDB.jsp'' %>. This confirms that q1.jsp explicitly includes shared logic for medal retrieval.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_005"]}, {"name": "Log Entry: Unvalidated Input in Handler", "type": "log_entry", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "q1Handler.jsp fails to validate user input before processing, leading to runtime exceptions.", "description": "Server logs show q1Handler.jsp received a non-integer value for ''mark'' and crashed during parsing. No input validation was performed before type conversion.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010", "CONC_004"]}, {"name": "Trace: ProductController Queries ProductDB", "type": "execution_trace", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The backend properly delegates database operations to the ProductDB class, maintaining separation of concerns.", "description": "Execution flow shows ProductController servlet calling ProductDB.getProductByCode() with an array of product codes. The method returns full Product objects used in HTML rendering.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_011", "CONC_012"]}, {"name": "Evidence: Scriptlet Renders Medal Table", "type": "code_evidence", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Dynamic content in q1.jsp is generated using Java logic embedded directly in the presentation layer.", "description": "A recovered scriptlet from q1.jsp uses a for-each loop over getAllMedals() to dynamically generate table cells containing medal images.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_003"]}, {"name": "Fragmented Stack Trace Showing Bean Initialization", "type": "digital", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The Product JavaBean was used in the workflow but may not have been correctly bound to user input.", "description": "A partial server log showing the instantiation of ict.bean.Product during request processing. The bean is created but never properly populated from form data.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "Scope Misalignment in Request Flow", "type": "diagnostic", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Improper use of JEE scope types led to missing data in downstream components.", "description": "Log entries indicate that a critical object was stored in request scope but accessed later in a redirected session, causing data loss.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_016"]}, {"name": "Missing Input Validation in Handler Logic", "type": "code_snippet", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "User input was not validated for type or bounds, leading to parsing exceptions under edge cases.", "description": "A snippet from q1Handler.jsp shows parameter retrieval without range checking before numeric conversion.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_015"]}, {"name": "Architectural Flowchart with Component Roles", "type": "document", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "The intended separation of concerns between presentation, control, and model layers in the application architecture.", "description": "A whiteboard diagram recovered from the server lab illustrating how JSP, Servlet, and JavaBean should interact following MVC principles.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_014"]}], "title": "The Case of the Corrupted Web App", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Report", "sceneId": "SCENE_001", "location": "Development Team Meeting Room", "description": "The team gathers after an automated test suite fails during deployment. The application crashes when submitting product data. Detective Lin arrives to lead the investigation.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Audit Under Fire", "sceneId": "SCENE_002", "location": "Server Lab - Workstation Terminal", "description": "Lin examines log files and partial stack traces. The suspects provide conflicting explanations about responsibility: frontend vs backend. A deeper look reveals inconsistencies in scope handling and unvalidated inputs.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: Truth in the Logs", "sceneId": "SCENE_003", "location": "Server Lab - Debug Console", "description": "With time running out, Lin reconstructs the execution flow using evidence. One suspect''s flawed implementation caused cascading failures. All parties must defend their code under scrutiny.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Compiled", "content": "The failure originated in q1Handler.jsp, where scriptlets were used to manage business logic and input validation was skipped. This violated MVC principles and allowed malformed data to crash the servlet.", "debrief": "Best practices require separating concerns: JSPs for presentation, Servlets for control, and JavaBeans for data. Input validation must occur on the server regardless of frontend checks.", "summary": "Architectural integrity and validation discipline prevent systemic failures.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame Shifted", "content": "The team blames the ProductController Servlet, claiming it cannot handle valid input. No code changes are made to the JSP layer.", "debrief": "Without addressing the real issue—poorly structured JSPs and missing validation—the same error will recur under similar conditions.", "summary": "Misdiagnosis leads to recurring failures and eroded trust in the system.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "When a critical web application suddenly fails during deployment, three developers must work with a detective to uncover which component was improperly implemented—before the launch deadline expires.", "version": "1.0", "evidence": [{"name": "Stack Trace Log Snippet", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A fragment of the server log showing a NullPointerException during form submission.", "foundLocation": "Server Lab Terminal", "relatedKnowledge": ["CONC_010", "CONC_015"]}, {"name": "q1Handler.jsp Source Code", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Reveals use of scriptlets for business logic and absence of input validation checks.", "foundLocation": "Version Control Archive", "relatedKnowledge": ["CONC_003", "CONC_010", "CONC_015"]}, {"name": "Session Scope Misuse Note", "type": "Physical", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A sticky note found on a monitor indicating manual session attribute manipulation without cleanup.", "foundLocation": "Development Desk", "relatedKnowledge": ["CONC_016", "CONC_003"]}], "has_quiz": false, "scriptId": "IT114115_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the initial crash report and notices that dynamic content on the product submission page was generated using server-side Java code embedded in HTML. She suspects improper use of JSP technologies. Which of the following best describes what Java Server Pages (JSP) are used for in web development?", "options": [{"content": "Client-side scripting to enhance UI interactivity using JavaScript within HTML.", "feedback": "Incorrect. JSP is not client-side; it runs on the server to generate dynamic HTML before sending it to the browser.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Server-side technology that embeds Java code in HTML to generate dynamic web content and is compiled into servlets.", "feedback": "Correct. JSP allows embedding Java logic in HTML pages, which are compiled into servlets at runtime for dynamic response generation.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "A database query language used to retrieve product data from backend systems.", "feedback": "Incorrect. This describes SQL or similar query languages, not JSP.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "A frontend framework like React or Angular for building single-page applications.", "feedback": "Incorrect. JSP is a server-side templating technology, not a modern client-side framework.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JSP", "knowledgeId": "CONC_001"}, "difficulty": 4, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "While auditing Jia Chen’s code, Detective Lin finds a block defined with <%! %> that contains the method getAllMedals(). What is the purpose and scope of this JSP element?", "options": [{"content": "It defines a variable or method that exists only during a single HTTP request.", "feedback": "Incorrect. Variables in scriptlets (<% %>) are request-scoped. Declarations (<%! %>) are class-level and persist across requests.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It declares a method or variable as part of the generated servlet class, making it available across multiple requests.", "feedback": "Correct. JSP declarations using <%! %> become members of the servlet class and can be reused across requests.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_002"]}, {"content": "It outputs the result of a Java expression directly into the HTML response.", "feedback": "Incorrect. That describes a JSP Expression (<%= %>), not a declaration.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It executes Java logic each time the page is accessed, such as processing form input.", "feedback": "Incorrect. That refers to scriptlets (<% %>), not declarations.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JSP Declarations", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_008"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Lin discovers a line in q1Handler.jsp: <%= mark %>. This snippet displays the user-submitted score on the results page. What type of JSP construct is this, and what does it do?", "options": [{"content": "JSP Scriptlet – runs Java code to control flow or process data on the server.", "feedback": "Incorrect. A scriptlet uses <% %> syntax. This is an expression, which outputs values directly.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "JSP Expression – evaluates a Java expression and writes the result to the response output stream.", "feedback": "Correct. <%= expression %> evaluates and outputs the value directly into the HTML sent to the browser.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_003"]}, {"content": "JSP Declaration – defines methods or variables at the servlet class level.", "feedback": "Incorrect. Declarations use <%! %> syntax and do not produce output.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "JSP Directive – controls how the JSP is translated into a servlet (e.g., include, page).", "feedback": "Incorrect. Directives use <%@ %> syntax and affect translation, not runtime output.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JSP Expressions", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "User accesses q1.jsp, which includes medalDB.jsp and displays a form."}, {"itemId": "ITEM_B1_002", "content": "User submits a mark value through the HTML form."}, {"itemId": "ITEM_B1_003", "content": "q1Handler.jsp retrieves the ''mark'' parameter using request.getParameter()."}, {"itemId": "ITEM_B1_004", "content": "The getAllMedals() method from medalDB.jsp is used to fetch image paths."}, {"itemId": "ITEM_B1_005", "content": "The mark is parsed, validated, and its value is displayed using <%= mark %>"}], "order": 4, "content": "To reconstruct how the medal display system works, Detective Lin must piece together the correct execution order of components when a user submits a mark. Arrange the following steps in the proper sequence.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The flow follows the expected JSP request lifecycle: page load → form submission → parameter handling → data access → dynamic output.", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_002"], "feedbackIncorrect": "Incorrect. Re-examine the dependency chain: the form must be shown first, then submitted, then processed with helper methods and output rendered.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B1_001", "content": "Look at the log entries showing code blocks that execute loops or conditional logic inside the JSP.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "During the final review, Detective Lin isolates a critical flaw: Jia Chen used inline Java code within the JSP to handle logic that should have been in a servlet. Specifically, she used a scriptlet enclosed in <% and %> to iterate over medal images. What is the correct syntax delimiter for a JSP scriptlet? Use angle brackets and percent signs (e.g., <x> ... </x>).", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Scriptlets", "knowledgeId": "CONC_003"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["<% %>", "<%  %>"], "feedbackCorrect": "Correct. JSP scriptlets are enclosed in <% %> and allow execution of Java code within the page.", "relatedKnowledge": ["CONC_001", "CONC_004"], "feedbackIncorrect": "Incorrect. Remember: scriptlets use <% %> delimiters. Declarations use <%! %>, and expressions use <%= %>", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash report and notices that medal images stopped rendering after a form submission. She suspects a missing configuration in one of the JSP files. Which JSP directive should be used to embed the utility functions from medalDB.jsp into q1.jsp?", "options": [{"content": "<%@ include file=''medalDB.jsp'' %>", "feedback": "Correct. The @include directive statically inserts the content of another JSP at translation time, which is how q1.jsp gains access to getAllMedals().", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "<% include file=''medalDB.jsp'' %>", "feedback": "Incorrect. This syntax uses scriptlet delimiters (<% %>), which are not valid for directives. Use <%@ %> for JSP directives.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "<jsp:include page=''medalDB.jsp'' />", "feedback": "This is a dynamic include using a standard action, which includes output at request time—not suitable for sharing method declarations like getAllMedals(). Static inclusion via directive is needed here.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JSP Directives", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008", "CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin examines the backend logs and sees that ProductController failed early in its lifecycle. She knows servlets follow a strict sequence of container-managed methods. What is the correct order of key servlet lifecycle methods?", "options": [{"content": "init() → service() → destroy()", "feedback": "Exactly right. The servlet container calls init() once on startup, then service() for each request, and finally destroy() before unloading.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_002"]}, {"content": "service() → init() → destroy()", "feedback": "No. The init() method must succeed before the servlet can begin handling requests via service().", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "destroy() → service() → init()", "feedback": "That’s backwards. destroy() is called only when the servlet is being unloaded from memory.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Servlet Lifecycle", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_011", "CONC_012"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "While analyzing the data flow, Lin identifies that the Product object used across layers must conform to JavaBean standards to work correctly with JSP and servlet frameworks. Which of the following defines a valid JavaBean?", "options": [{"content": "A serializable class with a no-arg constructor and public getter/setter methods for properties.", "feedback": "Yes. These conventions allow tools and containers to introspect and manipulate the bean automatically.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_003"]}, {"content": "Any Java class that has private fields and public methods.", "feedback": "Too broad. While good practice, this doesn’t meet the formal JavaBean specification without serialization, no-arg constructor, and property accessors.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "A class annotated with @Bean and managed by Spring context.", "feedback": "That''s a framework-specific definition. A JavaBean is a POJO following naming and structural conventions, independent of any framework.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006", "CONC_013"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "User submits mark via HTML form in q1.jsp"}, {"itemId": "ITEM_B2_002", "content": "Request is sent to q1Handler.jsp"}, {"itemId": "ITEM_B2_003", "content": "q1Handler.jsp retrieves parameter ''mark'' using request.getParameter()"}, {"itemId": "ITEM_B2_004", "content": "Input is parsed to integer and validated within range (50–100)"}, {"itemId": "ITEM_B2_005", "content": "System attempts to call getAllMedals() to retrieve image paths"}], "order": 4, "content": "To reconstruct the execution path leading to the crash, Detective Lin must piece together the correct sequence of events from log fragments. Arrange the steps showing how a request flows through the system when submitting a mark value.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. You''ve reconstructed the full request flow. Any break in this chain—like missing validation or broken method inclusion—could cause failure.", "relatedKnowledge": ["CONC_005", "CONC_010"], "feedbackIncorrect": "Close, but the order matters. The request starts at the frontend form, moves to handler, extracts input, validates, then accesses resources. Double-check the dependency chain.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "To prevent future crashes, Detective Lin insists that all JSPs forward unexpected errors to handleError.jsp. What JSP page directive accomplishes this? Write the full line of code.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Error Handling in JSP", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["<%@ page errorPage=\"handleError.jsp\" %>", "<%@page errorPage=\"handleError.jsp\"%>", "<%@ page errorPage=''handleError.jsp'' %>", "<%@page errorPage=''handleError.jsp''%>"], "feedbackCorrect": "Correct. This directive ensures that any uncaught exception in the JSP triggers a redirect to handleError.jsp instead of crashing the response.", "relatedKnowledge": ["CONC_010", "CONC_008"], "feedbackIncorrect": "Not quite. Remember, the page directive uses <%@ page %> syntax and the attribute ''errorPage'' to specify the target error handler.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the crash report and identifies q1.jsp as the entry point. She needs to determine how it accesses medal data. Which directive must be present in q1.jsp to use the getAllMedals() method defined in another file?", "options": [{"content": "<%@ include file=''medalDB.jsp'' %>", "feedback": "Correct. The include directive embeds medalDB.jsp at translation time, making its declarations available to q1.jsp.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "<jsp:include page=''medalDB.jsp'' />", "feedback": "Incorrect. This is a runtime inclusion and does not make JSP declarations accessible. The method would not be available during translation.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "<% import ''medalDB'' %>", "feedback": "Incorrect. There is no such JSP syntax. Importing classes is done via page directives, not scriptlets.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About q1.jsp", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005", "CONC_008"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin examines q1Handler.jsp and finds it crashes when non-numeric input is submitted. What should the code do immediately after retrieving the ''mark'' parameter to prevent this?", "options": [{"content": "Check if the parameter is null or empty, then validate it is numeric before parsing.", "feedback": "Correct. Input validation must occur before type conversion to avoid NumberFormatException and ensure robustness.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_002"]}, {"content": "Use Double.parseDouble() instead of Integer.parseInt().", "feedback": "Incorrect. While more flexible, this doesn''t solve the core issue—unvalidated input can still cause exceptions. Validation is required.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Redirect to handleError.jsp without any checks.", "feedback": "Incorrect. This bypasses necessary validation and provides no feedback to the user. Proper error handling requires context.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About q1Handler.jsp", "knowledgeId": "CONC_010"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "During the final confrontation, Lin asks Raj to explain how ProductController interacts with the database. Which statement accurately describes the relationship between ProductController and ProductDB?", "options": [{"content": "ProductController calls methods on ProductDB to query the database and retrieve Product objects for display.", "feedback": "Correct. The servlet acts as a controller, delegating data access to the ProductDB class, which encapsulates persistence logic.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B3_003"]}, {"content": "ProductDB extends ProductController to gain HTTP handling capabilities.", "feedback": "Incorrect. This reverses the dependency. ProductDB is a data access class, not a servlet subclass.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "ProductController contains hardcoded SQL queries and directly connects to the database.", "feedback": "Incorrect. This would violate separation of concerns. The ProductDB class is responsible for database operations.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About ProductController Servlet", "knowledgeId": "CONC_011"}, "difficulty": 4, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_012", "CONC_006"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Include medalDB.jsp using a directive"}, {"itemId": "ITEM_B3_002", "content": "Declare a JSP scriptlet to iterate over getAllMedals()"}, {"itemId": "ITEM_B3_003", "content": "Output <td> elements containing each medal image"}, {"itemId": "ITEM_B3_004", "content": "Begin rendering an HTML table with border"}], "order": 4, "content": "Lin reconstructs the execution flow in q1.jsp to show how the medal table is dynamically rendered. Arrange the correct sequence of operations:", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_004", "ITEM_B3_002", "ITEM_B3_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The inclusion must happen first, followed by table setup, iteration, and dynamic cell generation.", "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": "Incorrect. Remember: include the logic first, then structure the table, then loop through medals to populate cells.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "To complete the ProductDB implementation, Lin inspects the method signature for retrieving a product. What is the return type of the getProductByCode(String code) method in the ict.db.ProductDB class?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About ProductDB Class", "knowledgeId": "CONC_012"}, "difficulty": 4, "questionId": "Q_B3_005", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["ict.bean.Product", "Product"], "feedbackCorrect": "Correct. The method returns a Product object containing details retrieved from the database.", "relatedKnowledge": ["CONC_011", "CONC_013"], "feedbackIncorrect": "Incorrect. Consider the role of ProductDB—it retrieves full product information, so it must return a Product object.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the system blueprint and notices three core components: a JSP page for input, a servlet for processing, and a JavaBean for data handling. Which architectural pattern does this structure best represent?", "options": [{"content": "Monolithic Design", "feedback": "Incorrect. Monolithic design refers to tightly integrated systems without clear layering. This system uses distinct components with defined roles.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Client-Server Model", "feedback": "Close, but too broad. While the app uses client-server communication, the internal structure follows a more specific pattern based on component responsibility.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "MVC (Model-View-Controller)", "feedback": "Correct. The JSP acts as View, the Servlet as Controller, and the JavaBean as Model—classic MVC separation of concerns.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_004"]}, {"content": "Event-Driven Architecture", "feedback": "No. Event-driven systems respond to asynchronous events. Here, execution follows a direct request-response flow across layered components.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Web Application Architecture", "knowledgeId": "CONC_014"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_014", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_006", "CONC_007"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin examines the ict.bean.Product class used in the form submission. It has private fields for code, description, and price, along with getters and setters. What is the primary role of this class in the JSP-servlet workflow?", "options": [{"content": "To handle HTTP requests and route them to the correct view", "feedback": "No. That’s the job of the servlet. The JavaBean is a passive data container, not a controller.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "To store product data and support form binding between JSP and servlet", "feedback": "Correct. The JavaBean serves as a data transfer object, allowing seamless population from form parameters and access in the servlet.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_001"]}, {"content": "To generate dynamic HTML content on the frontend", "feedback": "No. That’s the role of JSP scriptlets or expressions. The JavaBean holds data, not presentation logic.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "To manage database connections and execute SQL queries", "feedback": "Incorrect. Database operations are handled by a separate DAO class like ict.db.ProductDB. The JavaBean only represents data.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Product JavaBean", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_012"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "In q1Handler.jsp, the ''mark'' parameter is retrieved and parsed into an integer. However, no validation occurs before parsing. What security and stability issue does this create?", "options": [{"content": "It increases network latency due to larger payloads", "feedback": "No. Latency isn''t directly affected by lack of validation. The real risk is runtime errors from malformed input.", "optionId": "OPT_B4_009", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It can cause NumberFormatException if non-numeric input is submitted", "feedback": "Correct. Without validating that the input is numeric, attempting Integer.parseInt() will throw an exception on invalid strings.", "optionId": "OPT_B4_010", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_003"]}, {"content": "It prevents the use of CSS styling on the response page", "feedback": "No. Styling is unrelated to input parsing. The failure occurs in backend logic, not presentation.", "optionId": "OPT_B4_011", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "It automatically encrypts user data for privacy", "feedback": "No. Lack of validation provides no encryption benefits. In fact, it makes the system less secure overall.", "optionId": "OPT_B4_012", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Input Validation", "knowledgeId": "CONC_015"}, "difficulty": 3, "questionId": "Q_B4_003", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "Page Scope – accessible only within the current JSP page"}, {"itemId": "ITEM_B4_002", "content": "Request Scope – available during a single HTTP request"}, {"itemId": "ITEM_B4_003", "content": "Session Scope – persists for the duration of a user''s session"}, {"itemId": "ITEM_B4_004", "content": "Application Scope – shared across all users and components for the entire web app"}], "order": 4, "content": "Reconstruct the correct sequence of object lifecycle stages across JEE scopes as the request flows from q1.jsp to q1Handler.jsp. Arrange the scope types from shortest to longest lifespan.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Scope in JEE", "knowledgeId": "CONC_016"}, "difficulty": 4, "questionId": "Q_B4_004", "knowledgeId": "CONC_016", "maxAttempts": 3, "correctOrder": ["ITEM_B4_001", "ITEM_B4_002", "ITEM_B4_003", "ITEM_B4_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Page scope has the shortest lifetime, followed by request, session, and finally application scope which lives for the entire deployment.", "relatedKnowledge": [], "feedbackIncorrect": "Incorrect. Remember: page < request < session < application in terms of lifespan. Data stored in shorter scopes disappears faster.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "During the final reconstruction, Detective Lin identifies that the crash occurred because Raj skipped input validation in q1Handler.jsp, assuming Jia would validate on the frontend. What fundamental principle of secure software design did this violate? Enter the two-word term.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Input Validation", "knowledgeId": "CONC_015"}, "difficulty": 5, "questionId": "Q_B4_005", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["defense in depth", "Defense in Depth"], "feedbackCorrect": "Exactly right. ''Defense in depth'' means never relying on a single layer for security—both frontend and backend must validate inputs independently.", "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": "Not quite. The issue wasn''t just missing validation, but the assumption that one layer could be trusted alone. The correct principle is ''defense in depth''.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Identify the root cause of the system failure and ensure all components follow best practices.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once failed to catch a bug before launch, causing a major outage—this case is personal redemption.", "background": "A seasoned troubleshooter hired to audit mission-critical web applications before production release.", "occupation": "System Integrity Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and detail-oriented.", "knowledgePoints": ["CONC_014", "CONC_016"]}, {"age": 29, "goal": "Protect her coding approach and avoid being blamed for the crash.", "name": "Jia Chen", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Used scriptlets in JSPs to handle business logic instead of delegating to servlets, violating MVC.", "background": "Specializes in JSP pages and UI logic; proud of writing ''efficient'' inline code.", "occupation": "Frontend Developer", "characterId": "CHAR_002", "personality": "Confident, slightly defensive, believes frontend logic should be flexible.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_004", "CONC_005", "CONC_008", "CONC_009"]}, {"age": 34, "goal": "Shift blame to frontend if possible, while defending architectural integrity.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Skipped input validation in one handler to meet a tight deadline, assuming frontend would catch errors.", "background": "Designed the servlet and JavaBean architecture; advocates strict separation of concerns.", "occupation": "Backend Engineer", "characterId": "CHAR_003", "personality": "Precise, principled, occasionally rigid in his adherence to design patterns.", "knowledgePoints": ["CONC_006", "CONC_007", "CONC_010", "CONC_011", "CONC_012", "CONC_013", "CONC_015"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Java Server Page (JSP)", "category": "JSP Basics", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A technology that allows embedding Java code into HTML pages for dynamic content generation on the server side.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_003", "CONC_004", "CONC_005"]}, {"name": "JSP Declaration", "category": "JSP Elements", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Used to declare variables and methods within a JSP page that persist across multiple requests.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "JSP Scriptlet", "category": "JSP Elements", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Blocks of Java code embedded in a JSP page, executed at request time.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "JSP Expression", "category": "JSP Elements", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A Java expression enclosed in <%= %> that evaluates and outputs the result to the response.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "JSP Directive", "category": "JSP Elements", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Instructions to the JSP container, such as including files or setting page behavior using <%@ directive %>. ", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "Servlet", "category": "Backend Components", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A Java class that handles client requests and generates dynamic responses in a web application.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_011", "CONC_010"]}, {"name": "JavaBean", "category": "Data Objects", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A reusable Java object following naming conventions, used to encapsulate data in web applications.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_013", "CONC_012"]}, {"name": "medalDB.jsp", "category": "Application Files", "appearsIn": ["SCENE_001"], "difficulty": 3, "description": "A sample JSP file likely involved in database interaction for medal-related data display.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_005", "CONC_001"]}, {"name": "q1.jsp", "category": "Application Files", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A JSP page handling a specific user query, possibly part of a quiz or form interface.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_003", "CONC_010"]}, {"name": "q1Handler.jsp", "category": "Application Files", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A JSP responsible for processing input from q1.jsp, potentially misusing business logic.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_003", "CONC_015"]}, {"name": "ProductController Servlet", "category": "Backend Components", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A servlet managing product-related operations, acting as a controller in MVC pattern.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_006", "CONC_012"]}, {"name": "ProductDB Class", "category": "Backend Components", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "A utility class handling database operations for product data access.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_007", "CONC_013"]}, {"name": "Product JavaBean", "category": "Data Objects", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A JavaBean representing product data with properties and getter/setter methods.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_007", "CONC_012"]}, {"name": "Web Application Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "The structural design of a web application, typically involving presentation, business, and data layers.", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_001", "CONC_006", "CONC_007"]}, {"name": "Input Validation", "category": "Security & Best Practices", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "The process of ensuring user input meets expected formats and constraints before processing.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "Scope in JEE", "category": "Core Concepts", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Defines the lifecycle and visibility of objects (page, request, session, application) in JEE web apps.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_001", "CONC_003"]}], "educational_goals": ["Understand the structure and components of a JSP-based web application", "Differentiate between JSP elements such as declarations, scriptlets, expressions, and directives", "Explain the role of Servlets, JavaBeans, and database classes in MVC architecture", "Apply input validation and scope management principles in JEE environments"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 2}}', '5ba912836d9a68b5cb405a383708f42b31e55d22f7fbf8d33dc2671e81e2d9df', 'all concepts', '2026-04-03 17:06:25.353561', NULL, 'IVE-IT114115') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('675fd0ec-ce3e-46b7-8e3e-8ea0071a6f8b', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '2a7da247-2b88-467c-a6e2-e32077162d3c', NULL, 'Murder at SAP Central: The Disappearance of the Master Key', 'active', 'easy', 'standard', '{"clues": [{"name": "Strategic Directive Fragment", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Dr. Vance made a top-level decision that contradicted technical advice, prioritizing short-term financial goals over long-term platform growth.", "description": "A torn memo from Dr. Vance''s personal folder titled ''Platform Expansion Strategy – Internal Use Only''. It outlines a decision to delay mobile expansion despite team recommendations.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "Tactical Resource Log", "type": "digital", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Mid-term planning decisions were made under pressure, shifting focus based on constrained resources and executive influence.", "description": "An encrypted log file recovered from the server backup showing reallocated developer hours away from multiplayer mode development toward single-player content during Q3.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002"]}, {"name": "Operational Support Ticket", "type": "system alert", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "A day-to-day operational choice was manipulated—preferring human staffing over automation despite efficiency data.", "description": "An auto-generated ticket flagged in red: ''High Volume Surge Post-Launch – AI Chatbot Disabled by Manual Override''. Timestamp matches live deployment.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003"]}, {"name": "Marketing Mix Draft", "type": "note", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Elements of the 4Ps framework were informally applied to increase player engagement and monetization potential.", "description": "A sticky note on Nina’s terminal with handwritten ideas: ''Boost hype via Twitch influencers (Promotion) + launch limited-edition skins (Product)''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004"]}, {"name": "CRM Integration Log Snippet", "type": "document", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Evidence of tampering with customer data flows, suggesting sabotage in CRM integration points.", "description": "A torn printout from a system log showing failed synchronization attempts between the customer support module and the marketing database. Timestamps align with suspicious ABAP report executions.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "DSS Configuration Backup", "type": "digital", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Proof that decision models were manipulated to justify delaying the SAP upgrade.", "description": "A hidden configuration file labeled ''DSS_Model_Backup_v3'' found in the server cache. It contains alternate financial projections that contradict official reports presented to executives.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "NetWeaver Integration Diagram", "type": "diagram", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Visual evidence of how SAP NetWeaver''s integration capabilities were exploited to create backdoor access.", "description": "A hand-drawn network sketch on a whiteboard behind the overheating server. Arrows show data flow bypassing standard authentication layers via deprecated services.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "ERP Process Flowchart Annotated", "type": "document", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Motivation for sabotage—deliberate misalignment of ERP processes to inflate short-term profits.", "description": "A printed ERP workflow diagram with handwritten notes highlighting bottlenecks in procurement and inventory sync. One section is circled: ''Delay here = Q3 profit boost.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_008"]}, {"name": "ABAP Editor Transaction Code", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The suspect used the ABAP Editor to modify system code.", "description": "A torn sticky note found under a keyboard with ''SE38'' written in haste.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_011"]}, {"name": "Three-Tier Architecture Diagram", "type": "diagram", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The system''s architecture was understood by the missing architect, suggesting intentional sabotage at a specific layer.", "description": "A whiteboard sketch behind the desk showing three distinct layers labeled ''GUI'', ''App Server'', and ''DB''. Arrows indicate data flow between them.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Primary Key Definition Note", "type": "note", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The integrity of sales and product records depends on correct primary key enforcement.", "description": "A handwritten note on a notepad: ''SAL_NO must be unique. PROD_SN is key. No duplicates allowed.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_012"]}, {"name": "ABAP Program ZSALESMON Source Snippet", "type": "code", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Custom reporting logic was implemented that relies on proper foreign key relationships.", "description": "A printed fragment of ABAP code showing a SELECT statement joining ZSALES and ZPRODUCT tables using PROD_SN.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010"]}, {"name": "Mismatched Product Serial in Sales Record", "type": "digital", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "Evidence of potential schema manipulation to allow invalid transactions.", "description": "A corrupted sales entry in table ZSALES contains a PROD_SN that does not exist in ZPRODUCT. This orphaned record violates referential integrity and suggests either data tampering or a disabled foreign key constraint.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_013"]}, {"name": "ZPRODUCT Table Classification Anomaly", "type": "database_log", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "Suspicious activity indicating possible misuse of master data for transactional purposes.", "description": "Database metadata shows ZPRODUCT was recently accessed with high-frequency write operations—unusual for a master data table, which should be read-heavy and rarely updated.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_014"]}, {"name": "Hidden ABAP Selection Screen Definition", "type": "code_fragment", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "Evidence of a hidden interface potentially used to bypass audit controls.", "description": "Recovered from a backup log, this fragment of program ZSALESMON defines a selection screen using PARAMETERS and SELECT-OPTIONS for SALES_NO and PERIOD, but includes an undocumented TSCR initialization flagged ''Internal Debug Mode''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_015"]}, {"name": "JOIN Logic in ZSALESMON Report", "type": "execution_trace", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "A vulnerability in reporting logic that could be exploited to generate fraudulent financial summaries.", "description": "An execution trace of ABAP report ZSALESMON shows a JOIN between ZSALES and ZPRODUCT on PROD_SN, calculating Amount as SAL_QTY multiplied by PROD_PRICE. However, the WHERE clause excludes period validation when a debug flag is set.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_016"]}, {"name": "Printed Function Module Trace", "type": "document", "clueId": "CLUE_B5_001", "foundBy": "CHAR_001", "reveals": "Evidence of abnormal ABAP execution patterns involving error-prone function calls.", "description": "A printed system trace showing a function module Z_FM_MEAL_PROFIT being called repeatedly with invalid input parameters. The exception INPUT_ERROR was raised multiple times, suggesting either faulty data or intentional misuse.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_017"]}, {"name": "Macro Expansion Log Snippet", "type": "log", "clueId": "CLUE_B5_002", "foundBy": "CHAR_001", "reveals": "Proof that macros were used in critical financial calculations, bypassing standard modular safeguards.", "description": "A fragment from the ABAP compiler log showing macro expansion for DEFINE get_meal_profit. The preprocessor replaced each invocation with inline code before runtime, increasing code size but avoiding call overhead.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_018"]}, {"name": "Unauthorized Macro Declaration", "type": "code artifact", "clueId": "CLUE_B5_003", "foundBy": "CHAR_001", "reveals": "Direct evidence linking Nina Patel to rogue coding practices that could manipulate system outputs.", "description": "Recovered source snippet containing DEFINE get_meal_profit — an unregistered macro used across daily profit reports. It lacks type safety and was never reviewed by security audit tools.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_018", "CONC_017"]}], "title": "Murder at SAP Central: The Disappearance of the Master Key", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Empty Office", "sceneId": "SCENE_001", "location": "SAP Development Wing - Lead Architect''s Office", "description": "The team arrives at the ransacked office of the missing SAP architect. Screens are dark, papers scattered. A sticky note reads ''Keys don''t match... check JOIN logic.'' Detective Lena begins questioning Dr. Vance and Nina Patel, both present during the last system test.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Server Room Anomalies", "sceneId": "SCENE_002", "location": "On-Premise Data Center - SAP Server Rack", "description": "Lena leads the group into the secure server room. One node is overheating. Logs show abnormal ABAP report executions. A printed trace reveals a function module calling a deprecated transaction code. Tensions rise as technical details emerge.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Audit Room", "sceneId": "SCENE_003", "location": "Executive Audit Chamber - Secure Conference Room", "description": "All suspects gather as Lena presents evidence. She reconstructs the timeline using database logs, access patterns, and code anomalies. The final revelation hinges on understanding how master data, foreign keys, and ABAP macros were manipulated to sabotage the system without detection.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Unlocked: The Rogue Macro", "content": "Nina Patel confesses: she created an ABAP macro to speed up testing, but it corrupted foreign key constraints. To hide it, she sabotaged the launch. Dr. Vance’s delay compounded the risk. The system is fixed using proper JOIN logic and master data governance.", "debrief": "The solution required understanding ABAP programming risks, data integrity principles, and how strategic decisions impact technical outcomes.", "summary": "Sabotage stemmed from misaligned incentives and poor code governance. Enterprise success requires harmony between strategy, operations, and technical excellence.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: Blaming the Executive", "content": "You accuse Dr. Vance of deleting the master key. He admits to delaying the project but proves he lacked technical access. The real culprit escapes. System fails at launch.", "debrief": "Jumping to conclusions without technical evidence leads to injustice. Strategic actors aren’t always technically capable.", "summary": "Misdiagnosing the problem results in failed resolution. Technical literacy is essential in modern enterprises.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Incomplete", "title": "Case Closed: No Culprit Found", "content": "Without deeper investigation, the team declares the disappearance accidental. The SAP rollout halts indefinitely.", "debrief": "Superficial analysis fails organizations. Real solutions require probing beneath surface symptoms.", "summary": "Avoiding complexity leads to stagnation. Mastery of enterprise systems demands persistence and depth.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001"], "requiredQuestions": []}}], "logline": "In a high-stakes indoor corporate setting, a lead SAP architect vanishes just before launching a critical ERP upgrade. Players must solve the mystery by uncovering clues tied to SAP architecture, decision-making layers, and ABAP programming concepts to reveal the truth behind the sabotage.", "version": "1.0", "evidence": [{"name": "Sticky Note with JOIN Hint", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A yellow sticky note found on the keyboard with handwritten text: ''Keys don''t match... check JOIN logic.''", "foundLocation": "Lead Architect''s Office Desk", "relatedKnowledge": ["CONC_016", "CONC_013"]}, {"name": "ABAP Trace Log", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Server log showing repeated execution of ZREPORT_SALES_JOIN with invalid foreign key references.", "foundLocation": "Application Server Console", "relatedKnowledge": ["CONC_016", "CONC_017"]}, {"name": "Deprecated Transaction Code Usage", "type": "System Record", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Audit trail shows use of transaction code /nSE38 late at night to run unauthorized ABAP macros.", "foundLocation": "Security Audit Dashboard", "relatedKnowledge": ["CONC_011", "CONC_018"]}, {"name": "Email Draft: Delay Justification", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "Unsent email from Dr. Vance to CFO citing ''technical instability'' as reason to delay SAP go-live.", "foundLocation": "Architect''s Email Draft Folder", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Custom Macro Source Code", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_005", "description": "Hidden ABAP macro definition that alters master data validation rules during batch processing.", "foundLocation": "Developer Workspace Backup", "relatedKnowledge": ["CONC_018", "CONC_014"]}], "has_quiz": false, "scriptId": "SAP_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lena examines the sticky note on Nina’s desk about influencer campaigns and limited-edition skins. She turns to Dr. Vance and asks: ''Was this part of an official strategy, or just grassroots marketing?'' To assess intent, she must classify the decision level. Which category does focusing on promotional tactics and product features fall under?", "options": [{"content": "Strategic Decision Making – it defines the company’s overall direction.", "feedback": "Incorrect. While important, these choices don’t set long-term vision. They are tools to execute broader goals, not define them.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Tactical Decision Making – it involves medium-term planning within departments.", "feedback": "Close, but no. These actions aren''t about resource allocation across timelines—they''re specific levers within a known framework.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Operational Decision Making – it deals with daily execution and customer touchpoints.", "feedback": "Not quite. Though implemented operationally, the use of Product and Promotion reflects structured marketing design, not routine execution.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Marketing Mix (4Ps) – it uses controllable variables to shape market positioning.", "feedback": "Correct. The mention of Product (skins) and Promotion (influencers) directly aligns with the 4Ps framework used to craft targeted marketing strategies.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_004"]}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About the Marketing Mix", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lena reviews the missing architect’s last message: ''Keys don''t match... check JOIN logic.'' Then she finds a draft email from Dr. Vance stating: ''We must commit exclusively to PC/console for Galactic Wars to maintain quality standards.'' What level of decision is this?", "options": [{"content": "Operational – it affects how the game is supported after launch.", "feedback": "No. This isn’t about daily operations like staffing or server tuning—it’s about platform commitment.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Tactical – it allocates resources between game modes.", "feedback": "Not exactly. While resource-related, this decision shapes multi-year direction, not mid-term feature trade-offs.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Strategic – it defines the long-term platform footprint and competitive positioning.", "feedback": "Correct. Choosing PC/console over mobile is a high-impact, long-term decision affecting investment, audience reach, and technological roadmap.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B1_001"]}, {"content": "Marketing Mix – it influences where the product is distributed.", "feedback": "Partially true—''Place'' in the 4Ps relates to distribution—but this goes deeper, defining core business scope, which is strategic.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Strategic Decisions", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Strategic Decision Making"}, {"itemId": "ITEM_B1_002", "content": "Tactical Decision Making"}, {"itemId": "ITEM_B1_003", "content": "Operational Decision Making"}], "order": 3, "content": "Lena reconstructs the chain of decisions leading up to the system failure. Arrange the following types of decision-making in order from highest-level (broadest impact) to lowest-level (most immediate execution):", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. Strategic decisions set the vision, tactical ones implement it through planning, and operational decisions handle day-to-day execution.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Remember: Strategy comes first (long-term), then tactics (medium-term), then operations (short-term).", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 4, "content": "While analyzing server logs, Lena notices a recurring pattern: support queries spiked post-launch, yet the AI chatbot remained offline. A comment in the config reads: ''Prefer live agents for better player experience.'' This represents a classic example of a ________ decision, focused on short-term responsiveness and service delivery.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 2, "questionId": "Q_B1_004", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["operational", "operational decision making", "operational decision"], "feedbackCorrect": "Correct. This is an operational decision—routine, execution-focused, and designed to maintain service levels using real-time conditions.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Incorrect. Think about the timescale and scope: decisions about staffing vs automation right after launch are about immediate execution, not long-term planning.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lena examines the sticky note: ''Keys don''t match... check JOIN logic.'' She recalls that CRM systems rely on clean data integration. Which TWO CRM features would most directly suffer if master data keys are mismatched across tables?", "options": [{"content": "Customer segmentation and personalized campaign triggers", "feedback": "Correct. Mismatched keys disrupt accurate customer profiles, breaking segmentation and personalization logic.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B2_001"]}, {"content": "Real-time server monitoring and code version control", "feedback": "Incorrect. These are development operations tools, not core CRM engagement features.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "ABAP macro execution and function module logging", "feedback": "Incorrect. These relate to backend programming, not customer relationship management functionality.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Player session analytics and frontend UI rendering", "feedback": "Incorrect. While related to user experience, these are not primary CRM functions focused on relationship management.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About CRM", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008", "CONC_015"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lena reviews the overheating node’s logs and finds a DSS was used to simulate upgrade impacts. At what decision level does a DSS primarily operate, and why?", "options": [{"content": "Tactical/Strategic level — because it supports semi-structured decisions using modeling and ''what-if'' analysis", "feedback": "Correct. DSS augments managerial judgment by simulating outcomes, ideal for complex trade-offs like upgrades vs. features.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B2_002"]}, {"content": "Operational level — because it automates routine tasks like report generation", "feedback": "Incorrect. Automation of daily tasks falls under transaction processing systems, not DSS.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "Strategic level only — because it replaces human decision-making with AI predictions", "feedback": "Incorrect. DSS supports but does not replace human judgment; it doesn’t fully automate decisions.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}, {"content": "All levels equally — because it integrates data from every system layer", "feedback": "Incorrect. While DSS uses broad data, its strength lies in tactical and strategic modeling, not operational automation.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "nextSceneId": null, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About DSS", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Enterprise Portal provides role-based access for users"}, {"itemId": "ITEM_B2_002", "content": "Application Server processes business logic and service requests"}, {"itemId": "ITEM_B2_003", "content": "Integration Broker synchronizes data across ERP, CRM, and custom apps"}, {"itemId": "ITEM_B2_004", "content": "Unified database stores consistent transactional and master data"}], "order": 3, "content": "Lena reconstructs how SAP NetWeaver integrates people, information, and process. Arrange these components in the correct order of integration flow based on the platform’s architecture.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The flow starts with user access (Portal), moves through logic processing (App Server), enables cross-system sync (Broker), and relies on a unified data store (Database).", "relatedKnowledge": ["CONC_009", "CONC_008"], "feedbackIncorrect": "Incorrect. Remember: integration begins with user access and ends with synchronized data storage across systems.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 4, "content": "While reviewing the architect''s notes, Lena sees a reference to ''ERP importance in cross-functional processes.'' One key reason ERP is vital in large companies is that it ensures ________ across departments like finance, HR, and supply chain.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About ERP Systems", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["cross-functional integration", "real-time reporting", "unified database", "process standardization", "regulatory compliance"], "feedbackCorrect": "Correct. ERP systems unify operations across departments, ensuring consistency, compliance, and real-time visibility.", "relatedKnowledge": ["CONC_007", "CONC_004"], "feedbackIncorrect": "Incorrect. Think about what ERP solves in big organizations — siloed data, inconsistent records, or delayed reporting across teams.", "nextSceneIdCorrect": "SCENE_002", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lena examines a terminal logged into SAP GUI. She sees several transaction codes recently used. One stands out as the tool for editing ABAP programs. Which transaction code would allow someone to alter core business logic?", "options": [{"content": "SE16N - General Table Display", "feedback": "Incorrect. SE16N allows viewing table data but not modifying program code. This is a read-only tool often used for debugging, not development.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "SE11 - ABAP Dictionary", "feedback": "Close, but not quite. SE11 is used to define database tables and fields, not to write or edit executable ABAP code.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "SE38 - ABAP Editor", "feedback": "Correct. SE38 is the primary transaction code for creating and editing ABAP reports and programs. This access could enable deep system manipulation.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_001"]}, {"content": "SM50 - Work Process Overview", "feedback": "No. SM50 monitors active processes on application servers. It’s useful for performance analysis but doesn’t allow code changes.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Transaction Codes", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_009"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lena studies the system architecture diagram left on the whiteboard. To understand where the breach might have originated, she needs to identify which layer handles business logic execution like ABAP processing and workflow engines. Which layer is responsible?", "options": [{"content": "Presentation Layer", "feedback": "Incorrect. The Presentation Layer handles user interface tasks like input/output via SAP GUI or Fiori. It does not execute business logic.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Application Layer", "feedback": "Correct. The Application Layer runs ABAP programs, enforces business rules, and manages transactions. Any logic-level sabotage would likely originate here.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B3_002"]}, {"content": "Database Layer", "feedback": "Incorrect. The Database Layer stores persistent data and program source code but does not execute logic. It’s passive storage, not processing.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Network Layer", "feedback": "Incorrect. There is no ''Network Layer'' in SAP’s three-tier model. Communication is handled across the defined three layers, not as a separate tier.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Three-Tier Architecture", "knowledgeId": "CONC_009"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Use SE11 to modify table structure in ABAP Dictionary"}, {"itemId": "ITEM_B3_002", "content": "Open SE38 to edit and save an ABAP report"}, {"itemId": "ITEM_B3_003", "content": "Run the custom program to execute the logic"}, {"itemId": "ITEM_B3_004", "content": "Execute SE16N to view updated records in the database"}], "order": 1, "content": "Lena reconstructs the sequence of events based on server logs. She finds traces of an unauthorized change: first accessing the dictionary, then editing code, executing it, and finally viewing altered data. Arrange these actions in the correct chronological order based on standard ABAP development workflow.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The logical flow is: define data (SE11), write logic (SE38), run it (execute), then verify results (SE16N). This matches standard ABAP development practice.", "relatedKnowledge": ["CONC_011", "CONC_012"], "feedbackIncorrect": "Incorrect. Remember: you must define your data model before writing code that uses it. Execution comes after coding, and verification follows execution.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 2, "content": "While analyzing the ZSALES table, Lena identifies the field that uniquely identifies each sales record. Based on standard naming conventions and data integrity principles, what is the primary key field in the ZSALES table? (Enter the field name exactly as it appears in the schema)", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["SAL_NO"], "feedbackCorrect": "Correct. SAL_NO is the natural primary key for the ZSALES table, ensuring each sales order is uniquely identifiable and preventing duplicate entries.", "relatedKnowledge": ["CONC_013", "CONC_014"], "feedbackIncorrect": "Incorrect. Consider which field represents a unique identifier for each sales transaction. MANDT is client-specific, PROD_SN links to another table, and SAL_QTY is quantitative data—not an identifier.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lena examines the sticky note: ''Keys don''t match... check JOIN logic.'' She pulls up the ZSALES and ZPRODUCT tables. One record in ZSALES references a PROD_SN that doesn’t exist in ZPRODUCT. What database concept has been violated?", "options": [{"content": "Primary Key Uniqueness", "feedback": "Incorrect. While primary keys must be unique, the issue here is not duplication but a missing referenced value. The problem lies in the relationship between tables, not within a single table’s key.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Foreign Key Referential Integrity", "feedback": "Correct. A foreign key must reference an existing primary key in another table. This violation indicates either bad data entry, incomplete deletion, or intentional bypass of constraints.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_001"]}, {"content": "Data Type Compatibility", "feedback": "Incorrect. Data types may affect JOINs, but the core issue here is the absence of a matching record in the referenced table, not type mismatch.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}, {"content": "Index Fragmentation", "feedback": "Incorrect. Index fragmentation affects performance, not data validity. The issue here is logical data consistency, not physical storage efficiency.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_001", "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More: Foreign Key", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_014", "CONC_016"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lena reviews access logs. ZPRODUCT, meant to store stable product information, shows hundreds of write operations over the past week—more than any other table. Based on its role, what type of table should ZPRODUCT be classified as?", "options": [{"content": "Transaction Table", "feedback": "Incorrect. Transaction tables handle frequent inserts like sales orders. ZPRODUCT holds reference data (product prices, descriptions) and should change infrequently.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Master Table", "feedback": "Correct. Master tables store relatively static, shared reference data. High write volume on ZPRODUCT is suspicious and suggests misuse—possibly to hide transactional activity.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_002", "unlockClues": ["CLUE_B4_002"]}, {"content": "Temporary Internal Table", "feedback": "Incorrect. Temporary tables are used during processing and cleared after execution. ZPRODUCT is a persistent custom table designed for long-term data storage.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "Cluster Table", "feedback": "Incorrect. Cluster tables group related small records for storage efficiency. ZPRODUCT is a standard transparent table and not part of a cluster.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Master vs Transaction Table", "knowledgeId": "CONC_014"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_014", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_013", "CONC_016"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "PARAMETERS: SALES_NO TYPE zsales-sal_no."}, {"itemId": "ITEM_B4_002", "content": "SELECT-OPTIONS: PERIOD FOR zsales-sal_date."}, {"itemId": "ITEM_B4_003", "content": "TSCR = ''Sales Records''."}, {"itemId": "ITEM_B4_004", "content": "SELECTION-SCREEN BEGIN OF BLOCK b1 WITH FRAME TITLE TSCR."}], "order": 3, "content": "Lena recovers fragments of ABAP code for ZSALESMON. To reconstruct the correct sequence of how the selection screen is built, arrange these code statements in the proper order.", "options": null, "sceneId": "SCENE_002", "learnMore": null, "difficulty": 4, "questionId": "Q_B4_003", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": ["ITEM_B4_003", "ITEM_B4_004", "ITEM_B4_001", "ITEM_B4_002"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The title is initialized first, then the block begins, followed by parameter definitions. This structure ensures a clean, labeled input interface.", "relatedKnowledge": ["CONC_016", "CONC_010"], "feedbackIncorrect": "Incorrect. Remember: the title (TSCR) must be set before it''s used in the SELECTION-SCREEN block. Parameters and select-options are declared inside the block.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 4, "content": "In the final reconstruction, Lena analyzes the ABAP report ZSALESMON. To join ZSALES and ZPRODUCT and calculate revenue, the SQL statement must include a JOIN condition. What is the correct ON clause based on the foreign key relationship?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: ABAP Report with JOIN", "knowledgeId": "CONC_016"}, "difficulty": 4, "questionId": "Q_B4_004", "knowledgeId": "CONC_016", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["zsales-prod_sn = zproduct-prod_sn", "zsales-prod_sn EQ zproduct-prod_sn", "zsales-prod_sn == zproduct-prod_sn"], "feedbackCorrect": "Correct. The JOIN uses PROD_SN as the linking field—ZSALES'' foreign key matching ZPRODUCT''s primary key—to ensure only valid product sales are reported.", "relatedKnowledge": ["CONC_013", "CONC_015"], "feedbackIncorrect": "Incorrect. Recall that PROD_SN in ZSALES references the same field in ZPRODUCT. The JOIN condition must equate these two fields to maintain data accuracy.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_001", "content": "Think about how function modules enforce structure — what happens at the interface level when bad data comes in?", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Lena examines the overheating server node and isolates a suspicious function module: Z_FM_MEAL_PROFIT. She sees it’s being called frequently with negative values, triggering INPUT_ERROR exceptions. Which characteristic of ABAP function modules makes them suitable for encapsulating such logic — yet also vulnerable when misused?", "options": [{"content": "They are stateful and retain data between calls, making debugging easier.", "feedback": "Incorrect. Function modules are actually stateless — each call is independent. Their strength lies in controlled interfaces, not memory retention.", "optionId": "OPT_B5_001", "showHint": "HINT_B5_001", "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They use CALL FUNCTION syntax and support exception handling, allowing clean error responses like INPUT_ERROR.", "feedback": "Correct. Function modules define strict interfaces with IMPORTING/EXPORTING parameters and EXCEPTIONS, enabling robust error handling — crucial for reliable business logic.", "optionId": "OPT_B5_002", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B5_001"]}, {"content": "They execute at compile time, reducing runtime load on the application server.", "feedback": "No. That describes macros. Function modules run at runtime and are compiled separately in SE37.", "optionId": "OPT_B5_003", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "They can be modified directly in production without transport requests.", "feedback": "False. This would violate SAP change control protocols. All function modules require proper transport management via CTS.", "optionId": "OPT_B5_004", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_017"}, "difficulty": 4, "questionId": "Q_B5_001", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_002", "content": "Consider which ABAP construct gets expanded before the program runs — not during execution.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "While analyzing the ABAP logs, Lena notices repeated blocks of identical code related to meal profit calculations. There’s no subroutine or function module call — just raw statements reappearing. What likely caused this pattern?", "options": [{"content": "A recursive subroutine calling itself excessively.", "feedback": "Unlikely. Recursion would show up as nested calls in the stack trace. Here, we see flat duplication — a sign of compile-time expansion.", "optionId": "OPT_B5_005", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "An ABAP macro using DEFINE that got expanded inline during compilation.", "feedback": "Exactly. Macros are expanded at compile time into repetitive code blocks. This improves performance slightly but increases code bloat and reduces maintainability.", "optionId": "OPT_B5_006", "showHint": null, "isCorrect": true, "nextSceneId": "SCENE_003", "unlockClues": ["CLUE_B5_002"]}, {"content": "A loop mistakenly printing the same line over and over.", "feedback": "No. A loop wouldn’t generate full statement blocks — only repeated output. We’re seeing actual duplicated logic in the source flow.", "optionId": "OPT_B5_007", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}, {"content": "A virus injecting duplicate code into memory.", "feedback": "Too speculative. The pattern matches known ABAP behavior — macro expansion — not malware activity.", "optionId": "OPT_B5_008", "showHint": null, "isCorrect": false, "nextSceneId": "SCENE_002", "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_018"}, "difficulty": 3, "questionId": "Q_B5_002", "knowledgeId": "CONC_018", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_017"], "feedbackIncorrect": null, "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B5_001", "content": "Macro get_meal_profit is invoked with parameters: ''Donut'', ''22'', ''5'', ''150''"}, {"itemId": "ITEM_B5_002", "content": "Compiler expands macro body inline during compilation"}, {"itemId": "ITEM_B5_003", "content": "CALL FUNCTION ''Z_FM_MEAL_PROFIT'' executes with validated inputs"}, {"itemId": "ITEM_B5_004", "content": "SY-SUBRC checked; if 0, MealProfit added to daily_profit total"}, {"itemId": "ITEM_B5_005", "content": "ABAP program begins execution after successful compilation"}], "order": 3, "content": "To prove how the rogue macro manipulated daily profits, Lena must reconstruct the correct sequence of events in the Z_DAILY_PROFIT report execution. Arrange these steps in the order they occur during runtime.", "options": null, "sceneId": "SCENE_003", "learnMore": null, "difficulty": 4, "questionId": "Q_B5_003", "knowledgeId": "CONC_018", "maxAttempts": 3, "correctOrder": ["ITEM_B5_002", "ITEM_B5_005", "ITEM_B5_001", "ITEM_B5_003", "ITEM_B5_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. You’ve traced the lifecycle accurately: macro expansion happens first (compile time), then execution flows through invocation, function call, and aggregation.", "relatedKnowledge": ["CONC_017", "CONC_010"], "feedbackIncorrect": "Not quite. Remember: macro expansion occurs at compile time — before any execution starts. The rest follows a logical call-and-check pattern.", "nextSceneIdCorrect": "SCENE_003", "nextSceneIdIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B5_003", "content": "It''s a five-letter keyword beginning with ''D''. Think: defining a template, not a function.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "To expose the hidden macro, Lena needs to recall the exact ABAP keyword used to declare a reusable block of code that gets expanded at compile time. What is the keyword that starts a macro definition in ABAP?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_018"}, "difficulty": 3, "questionId": "Q_B5_004", "knowledgeId": "CONC_018", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DEFINE"], "feedbackCorrect": "Correct! DEFINE is used to start a macro block in ABAP. Unlike functions, macros are expanded at compile time, making them fast but harder to debug.", "relatedKnowledge": ["CONC_017"], "feedbackIncorrect": "Incorrect. The right answer is DEFINE. This keyword declares a macro that will be expanded inline during compilation — a technique used here to hide repetitive logic.", "nextSceneIdCorrect": null, "nextSceneIdIncorrect": null}], "characters": [{"age": 38, "goal": "Uncover the truth behind the missing architect and prevent system failure.", "name": "Detective Lena Reed", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She once reported a flaw in SAP NetWeaver that was ignored—this case could vindicate her past warnings.", "background": "Former SAP consultant turned corporate investigator after a data breach scandal. Known for her methodical logic and deep understanding of enterprise systems.", "occupation": "Internal Systems Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, detail-oriented", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_003", "CONC_006", "CONC_009"]}, {"age": 52, "goal": "Protect his reputation and avoid accountability for delaying the project.", "name": "Dr. Elias Vance", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He secretly delayed the SAP upgrade to protect his bonus, which depends on short-term profits.", "background": "Longtime executive pushing aggressive digital transformation. Advocates for top-down strategic control over IT decisions.", "occupation": "Chief Strategy Officer", "characterId": "CHAR_002", "personality": "Charismatic but authoritarian, values big-picture vision over technical details", "knowledgePoints": ["CONC_001", "CONC_004", "CONC_005"]}, {"age": 29, "goal": "Prevent the system audit from revealing her rogue code implementation.", "name": "Nina Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She wrote an unauthorized macro that bypassed security checks—fearing exposure if the audit proceeds.", "background": "Brilliant coder who built much of the custom logic in the SAP system. Fiercely protective of code integrity.", "occupation": "Lead ABAP Developer", "characterId": "CHAR_003", "personality": "Intense, passionate about clean programming, distrusts management interference", "knowledgePoints": ["CONC_010", "CONC_011", "CONC_015", "CONC_016", "CONC_017", "CONC_018"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Strategic Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "High-level decisions made by executives that shape long-term organizational goals and resource allocation within enterprise systems.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_008"]}, {"name": "Tactical Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Mid-level planning that translates strategic goals into actionable projects, often involving department heads and system configuration.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Operational Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "Day-to-day choices made by end users and developers that affect system transactions and data entry processes.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_003", "CONC_014"]}, {"name": "Marketing Mix (4Ps)", "category": "Business Strategy", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Product, Price, Place, Promotion framework used in CRM integration with SAP to align sales strategy with backend operations.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Customer Relationship Management (CRM)", "category": "ERP Modules", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Module within SAP that manages customer interactions, integrated with ERP for unified data flow across sales and service.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_008"]}, {"name": "Decision Support System (DSS)", "category": "Systems", "appearsIn": ["SCENE_001"], "difficulty": 3, "description": "Analytical tools within SAP that assist managers in making informed decisions using real-time data and modeling.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "SAP NetWeaver", "category": "Architecture", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "Integration platform that connects SAP applications and enables data exchange across heterogeneous systems.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_009", "CONC_008"]}, {"name": "ERP System", "category": "Core Concept", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "Enterprise Resource Planning system that integrates core business functions like finance, HR, and logistics into a unified database.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_005", "CONC_007"]}, {"name": "SAP Three-Tier Architecture", "category": "Architecture", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "Presentation, Application, and Database layers that separate user interface, processing logic, and data storage in SAP systems.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_007", "CONC_008"]}, {"name": "ABAP Programming Language", "category": "Programming", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Advanced Business Application Programming language used for custom development in SAP environments.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_015", "CONC_016"]}, {"name": "SAP Transaction Codes", "category": "Navigation", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Short alphanumeric commands used to navigate and execute functions within SAP GUI.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_010", "CONC_017"]}, {"name": "Primary Key", "category": "Database", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "Unique identifier for a record in a database table, ensuring data integrity and enabling efficient retrieval.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Foreign Key", "category": "Database", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Field in one table that links to the primary key in another, establishing relationships between master and transaction data.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_012", "CONC_014"]}, {"name": "Master vs Transaction Table", "category": "Database", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "Master tables store static data (e.g., customer info), while transaction tables record dynamic events (e.g., sales orders).", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_012", "CONC_013"]}, {"name": "ABAP Selection Screen", "category": "Programming", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "User interface element in ABAP programs that allows input parameters before report execution.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_010", "CONC_016"]}, {"name": "ABAP Report with JOIN", "category": "Programming", "appearsIn": ["SCENE_003"], "difficulty": 4, "description": "ABAP program that combines data from multiple tables using SQL JOIN operations for comprehensive analysis.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_013", "CONC_015"]}, {"name": "ABAP Function Module", "category": "Programming", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "Reusable subroutine in ABAP that performs specific tasks and can be called from other programs.", "knowledgeId": "CONC_017", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "ABAP Macro", "category": "Programming", "appearsIn": ["SCENE_003"], "difficulty": 4, "description": "Code substitution tool in ABAP that replaces text patterns during compilation; not executable at runtime.", "knowledgeId": "CONC_018", "relatedKnowledge": ["CONC_010", "CONC_017"]}], "educational_goals": ["Understand the hierarchy of decision-making in enterprise systems (strategic, tactical, operational)", "Explain core components of SAP including ERP, NetWeaver, and three-tier architecture", "Differentiate between master and transaction tables, primary and foreign keys", "Apply knowledge of ABAP programming elements such as reports, function modules, macros, and selection screens", "Connect CRM and marketing mix strategies to enterprise software functionality"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '6c750947a6d95e5cd1cdd30210d996f8dd9ee0b01d90006409e1dca1e542e6ec', 'all concepts', '2026-04-05 03:35:12.476684', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('189d9a2e-e6c9-4b5e-aa6e-8c6a6e829b76', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '8f652d0f-9cb5-4612-b101-ad1fa47a0916', NULL, 'Code and Consequence: A SAP ABAP Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "Fragmented Log Entry", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The victim was working on a financial calculation module involving conditional logic and decimal precision when interrupted.", "description": "A torn printout recovered from the server room trash bin shows a partial ABAP code snippet: ''DATA result TYPE p DECIMALS 2. IF flag EQ space.'' The rest is missing, but the syntax suggests an incomplete conditional block.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Misplaced Comment Tag", "type": "digital_artifact", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Someone with knowledge of modularization keywords introduced a fatal syntax error by misusing comment notation to disable a key event block.", "description": "In the version control diff of the corrupted program, a line reads ''* START-OF-SELECTION'' — using an asterisk instead of a quotation mark. This accidentally commented out the main processing block, disabling critical initialization routines.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_010"]}, {"name": "Loop Without Declaration", "type": "code_anomaly", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "The fatal loop exploited undocumented behavior and lacked proper variable declaration—only someone familiar with both control structures and legacy quirks could have written it this way.", "description": "The debugger reveals a DO loop executing 100 times, incrementing SY-INDEX, but no corresponding DATA declaration for any counter variable. The loop relies solely on system fields, bypassing standard practice.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "Fragmented Log Entry: PERFORM Invocation", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The program used modularization via FORM routines, and someone invoked one using a calling keyword.", "description": "A truncated system log shows a call to ''PERFORM validate_user'' deep within the halted ABAP program. The timestamp aligns with the last successful execution block before the crash.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Undeclared Variable Trace", "type": "code_analysis", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "A critical operational keyword (WRITE) failed due to missing data declaration, suggesting either oversight or intentional sabotage.", "description": "Memory dump analysis reveals an attempt to WRITE to a variable ''flight_total'' that was never declared with DATA. The runtime error SY-SUBRC = 4 occurred at this point.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006", "CONC_007"]}, {"name": "Local Type Definition in Backup File", "type": "file_fragment", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Someone defined a local data type for consistency, indicating advanced knowledge of ABAP typing systems and scope control.", "description": "Recovered from a temporary backup, this snippet defines a local type: TYPES flight_code TYPE c LENGTH 6. It was not present in the main program but referenced in a subroutine.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "Execution Flow Reconstruction", "type": "debugger_output", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "An operational keyword (MOVE) acted on improperly scoped data, exposing a fatal flaw only someone familiar with both data declaration and processing order could exploit.", "description": "Debugger replay shows the program attempted to MOVE value from an undeclared counter before initializing it. This caused cascading failure in a DO loop guarded by the same variable.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_006", "CONC_007"]}, {"name": "Commented-Out Debug Line", "type": "digital", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The murder involved deliberate obfuscation of code behavior using comments to hide a dangerous shortcut.", "description": "A single line in the victim''s ABAP program was commented out using an asterisk (*) at column 1. It reads: ''* Final validation bypassed - urgent deploy required''. This suggests someone intentionally hid a critical logic skip from review.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_010"]}, {"name": "Global Type Reference in Crash Module", "type": "digital", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The error originated in a context dependent on globally defined data types, indicating deep SAP knowledge was required to exploit it.", "description": "The failed subroutine uses ''LIKE mara-matnr'' to define a key field. This links it directly to the global ABAP Dictionary type MATNR, which only authorized developers should modify. Unauthorized changes here could destabilize the entire system.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Chained Output Masking Errors", "type": "digital", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The culprit used syntactic compactness (chaining) to obscure abnormal runtime behavior during logs review.", "description": "A WRITE statement chains three outputs: system status, user name (sy-uname), and counter value. During debugging, this masked an overflow condition because all values appeared normal in sequence—hiding the real anomaly in execution flow.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_011", "CONC_012"]}, {"name": "Incomplete Comment Discipline", "type": "procedural", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The tampering developer neglected proper commenting standards, exposing their lack of formal training and urgency.", "description": "While most internal documentation follows best practices, one inline comment appears mid-line with crucial logic: ''...MOVE temp TO target \" fix for missing init''. This violates standard formatting and suggests rushed, unauthorized modification.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_010", "CONC_015"]}, {"name": "Fragmented Constant Declaration", "type": "code_snippet", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "Someone attempted to declare a constant but forgot to initialize it, violating ABAP syntax rules.", "description": "A torn piece of ABAP code recovered from the server room trash bin. It shows an incomplete CONSTANTS declaration with a missing VALUE clause and references to ''max_no''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_013"]}, {"name": "System Field Audit Log", "type": "log_entry", "clueId": "CLUE_B4_002", "foundBy": "CHAR_001", "reveals": "The killer accessed system context information via SY-UNAME shortly before the fatal error occurred.", "description": "Server access logs show that SY-UNAME was queried just before the system crash. The user ID matches Dr. Finch’s login, but the timestamp conflicts with his alibi.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_014"]}, {"name": "Poorly Formatted Code Block", "type": "code_snippet", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "The code was altered by someone who ignored ABAP best practices, possibly to hide changes.", "description": "A section of the victim''s last edited program lacks indentation and comments. The logic is correct but violates SAP layout standards, suggesting rushed or unauthorized modification.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_015"]}, {"name": "Function Call Anomaly", "type": "debug_trace", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "A built-in function was misused in a way only someone familiar with ABAP syntax but not its semantics would do.", "description": "Debugger output reveals a TO_UPPER function call on a numeric field—operationally invalid. This caused a type mismatch exception during execution.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_016"]}, {"name": "Corrupted Loop Fragment", "type": "digital", "clueId": "CLUE_B5_001", "foundBy": "CHAR_001", "reveals": "The program crash was caused by a loop without proper termination logic, suggesting either negligence or intentional sabotage.", "description": "A snippet of ABAP code recovered from the victim''s terminal showing a DO loop with an unhandled exit condition. The loop uses SY-INDEX but lacks safeguards against infinite execution.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_017"]}, {"name": "Hidden Conditional Bypass", "type": "digital", "clueId": "CLUE_B5_002", "foundBy": "CHAR_001", "reveals": "Someone inserted a conditional backdoor that could disable safety checks for specific users, possibly to hide unauthorized modifications.", "description": "An obfuscated IF block found in the debug log that evaluates user roles before allowing access to critical functions. One branch contains a suspicious CHECK statement tied to a non-existent flag.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_018", "CONC_019"]}, {"name": "Execution Flow Anomaly", "type": "system_log", "clueId": "CLUE_B5_003", "foundBy": "CHAR_001", "reveals": "The fatal error occurred because a relational operator (EQ) was used incorrectly, causing the loop to continue past its intended stopping point.", "description": "Debugger output shows the program entered a loop 20 times instead of terminating at iteration 5 as expected. The EXIT command was bypassed when a relational check failed.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_017", "CONC_019"]}], "title": "Code and Consequence: A SAP ABAP Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Server Room Incident", "sceneId": "SCENE_001", "location": "Indoor - SAP Development Server Room", "description": "Detective Hayes arrives at the dimly lit server room where Senior Developer Mr. Vance was found dead. His terminal displays a halted ABAP program with strange syntax errors. Dr. Finch and Nina are already present, visibly shaken. The air hums with tension and cooling fans.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Review and Confessions", "sceneId": "SCENE_002", "location": "Indoor - SAP Team Conference Room", "description": "Hayes gathers the suspects in the conference room to review logs and code snippets. Tensions rise as inconsistencies emerge in their stories. A deeper analysis of the ABAP logic reveals branching paths and hidden conditions that mirror personal motives.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Compilation", "sceneId": "SCENE_003", "location": "Indoor - Main Development Lab", "description": "With all evidence compiled, Hayes reconstructs the final moments using the ABAP debugger interface projected on screen. She walks through the execution flow, exposing how a seemingly innocent loop combined with a missing declaration led to system collapse—and murder. The culprit is revealed through a fatal flaw only someone with specific knowledge could have exploited.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Compiled", "content": "The investigation concludes that Nina Patel attempted to fix a performance bug by altering a global constant, unaware it was used in a critical financial calculation. The resulting crash caused system failure and panic. Dr. Finch covered up prior flaws, but Nina’s unauthorized change was the trigger. No murder occurred—Vance died of a heart attack induced by stress. The real crime was reckless code modification.", "debrief": "Understanding ABAP syntax and discipline in changes prevents disasters. Always follow change management protocols.", "summary": "Educational resolution emphasizing responsible coding, use of constants, and impact of control structures.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Syntax", "content": "You accuse Dr. Finch of deliberate sabotage. However, forensic code analysis proves the error originated from an unapproved patch. Your conclusion ignores key evidence of junior intervention and misattributes intent based on pride alone.", "debrief": "Jumping to conclusions without full evidence leads to injustice. Technical skill doesn’t imply malice.", "summary": "Failure to synthesize all evidence results in wrongful accusation.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In the quiet hum of a corporate IT server room, a senior developer is found dead beside a corrupted ABAP program. With time running out before a critical system go-live, a detective must unravel syntax, secrets, and statements to expose the killer hidden among the coders.", "version": "1.0", "evidence": [{"name": "Corrupted ABAP Program Printout", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A hardcopy of the last executed ABAP program showing a missing DATA declaration and an infinite loop.", "foundLocation": "Beside victim''s desk", "relatedKnowledge": ["CONC_007", "CONC_017"]}, {"name": "Terminal Access Log", "type": "Digital Record", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "System log showing unauthorized access to the production program two hours before the incident by a user with elevated privileges.", "foundLocation": "Server audit trail", "relatedKnowledge": ["CONC_014", "CONC_005"]}, {"name": "Handwritten Algorithm Sketch", "type": "Note", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A napkin with a sketch of a nested IF-ELSE structure and a note about ''fixing the output''.", "foundLocation": "Trash bin near conference room", "relatedKnowledge": ["CONC_018", "CONC_012"]}, {"name": "Version Control Anomaly Report", "type": "System Report", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "Git-like system shows a last-minute change to a constant value that triggered a division-by-zero error.", "foundLocation": "Development repository", "relatedKnowledge": ["CONC_013", "CONC_006"]}], "has_quiz": false, "scriptId": "SAP_ABAP_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_001", "content": "Look at the first word of the statement. Does it define something or perform an action?", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Hayes examines the terminal where Mr. Vance’s last program crashed. She sees a line: ''DATA total_amount TYPE p DECIMALS 2 VALUE ''99.99''.'' What kind of ABAP keyword is ''DATA'', and why is its placement critical?", "options": [{"content": "DATA is a control keyword; it determines program flow based on conditions.", "feedback": "Incorrect. Control keywords like IF or WHILE manage execution flow. DATA defines data objects—it''s a declarative keyword, not a control structure.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "DATA is a declarative keyword; it must appear before any use of the variable in the program.", "feedback": "Correct. DATA declares variables and their attributes. In ABAP, all declarations must precede usage to ensure proper memory allocation and type safety.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "DATA is a modularization keyword; it groups related statements into blocks.", "feedback": "No. Modularization keywords like FORM or MODULE define processing blocks. DATA belongs to the declarative category, used exclusively for defining data.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "DATA is an operational keyword; it modifies existing values during runtime.", "feedback": "Not quite. Operational keywords like WRITE or MOVE process data. DATA creates it—this is a foundational distinction in ABAP syntax.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Declarative Keywords", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Well done. Recognizing declarative keywords helps trace how data is defined before being used in logic or calculations.", "relatedKnowledge": ["CONC_001", "CONC_007"], "feedbackIncorrect": "Review the types of ABAP keywords. Focus on which ones introduce new data elements versus those that execute actions."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Hayes examines the terminal and spots the line: ''PERFORM validate_user.'' She knows this isn''t a function module or screen call. What kind of ABAP keyword is PERFORM, and what does its presence imply about the program structure?", "options": [{"content": "It''s a control keyword; it means there''s a conditional branch based on user input.", "feedback": "Incorrect. Control keywords like IF or WHILE manage flow, but PERFORM is used to invoke predefined blocks, not control logic directly.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It''s a calling keyword; it indicates the program is invoking a FORM routine named ''validate_user''.", "feedback": "Correct. PERFORM is a calling keyword used to execute a previously defined FORM routine. Its presence confirms modular design and suggests deeper investigation into that subroutine.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "It''s a declarative keyword; it defines a new processing block for validation logic.", "feedback": "Incorrect. Declarative keywords like DATA or TYPES define structure, but PERFORM executes existing code—it doesn’t declare anything new.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It''s an operational keyword; it writes validation status to the output.", "feedback": "Incorrect. Operational keywords like WRITE or MOVE process data, but PERFORM calls routines. It doesn’t perform data operations itself.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Calling Keywords", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You''ve identified a key piece of the program’s architecture—modular execution through calling keywords.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Review how different keyword types shape ABAP programs. Focus on what actions they trigger versus what they define."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Hayes spots a line in the dead developer’s code that starts with an asterisk (*) in the first column. She knows this isn’t executable—but why would someone leave such a mark? What does this syntax indicate?", "options": [{"content": "It defines a new variable dynamically at runtime.", "feedback": "No—asterisks in column 1 don’t define variables. They’re ignored by the system entirely. This is a common misconception among junior developers unfamiliar with ABAP syntax rules.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It marks a full-line comment, used to document or disable code without deletion.", "feedback": "Correct. In ABAP, an asterisk (*) in column 1 flags the entire line as a non-executable comment. This is often used to temporarily disable code or add explanatory notes.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "It triggers a debug breakpoint when the program runs.", "feedback": "Incorrect. While some systems use special markers for breakpoints, ABAP does not use the asterisk (*) for this purpose. Breakpoints are set via the debugger interface, not source code symbols.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It declares a global constant visible across all programs.", "feedback": "No—global constants are declared with CONSTANTS, not comments. The asterisk has no impact on data declaration or visibility.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About ABAP Comments", "knowledgeId": "CONC_010"}, "difficulty": 1, "questionId": "Q_B3_001", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You’ve identified how comments can be weaponized—not just to explain code, but to hide its true intent.", "relatedKnowledge": ["CONC_015"], "feedbackIncorrect": "Remember: comments don''t run. But they can mislead those who trust them too much."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Hayes examines the corrupted ABAP snippet on Vance’s terminal. One line reads: ''CONSTANTS max_no TYPE i.'' She frowns—this won’t compile. What critical element is missing from this constant declaration?", "options": [{"content": "The TYPE specification", "feedback": "Incorrect. The TYPE is already specified as ''i'' (integer). The real issue lies in initialization requirements for constants.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The VALUE clause", "feedback": "Correct. In ABAP, CONSTANTS must include a VALUE clause because they are immutable and evaluated at compile time.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B4_001"]}, {"content": "The DATA statement", "feedback": "No. DATA declares variables; CONSTANTS is a separate declarative keyword. They serve different purposes.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The LIKE reference", "feedback": "Unnecessary. LIKE links to existing data objects, but constants can be self-contained with explicit types and values.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Constant Declaration", "knowledgeId": "CONC_013"}, "difficulty": 2, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Exactly. Without VALUE, the compiler cannot assign a fixed value to the constant, leading to a syntax error.", "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": "Review the syntax: CONSTANTS requires a VALUE to ensure immutability at compile time."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_001", "content": "Look for keywords that terminate loop execution early based on a condition.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Hayes examines the halted program and isolates a DO loop that runs indefinitely. She notices it relies on SY-INDEX but has no EXIT or WHILE condition. Which control statement is missing to prevent infinite execution?", "options": [{"content": "CONTINUE", "feedback": "CONTINUE skips to the next iteration but doesn''t stop the loop. The program would still run 20 times regardless.", "optionId": "OPT_B5_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "CHECK", "feedback": "CHECK acts like a conditional CONTINUE, not a terminator. It doesn’t solve the infinite loop issue.", "optionId": "OPT_B5_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "EXIT", "feedback": "Correct. EXIT terminates the loop immediately when triggered, which should have been used to break out after five iterations.", "optionId": "OPT_B5_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B5_001"]}, {"content": "ENDLOOP", "feedback": "ENDLOOP marks the end of a LOOP block over internal tables, not a DO loop. This isn''t the right context.", "optionId": "OPT_B5_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_017"}, "difficulty": 3, "questionId": "Q_B5_001", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Exactly. Without EXIT, the loop had no way to stop early, leading to system overload.", "relatedKnowledge": ["CONC_004", "CONC_018"], "feedbackIncorrect": "Review how DO loops must include explicit termination logic using EXIT under certain conditions."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_002", "content": "Consider when this event triggers. Is it during startup, user input, or background processing?", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "During code review, Hayes spots a block labeled ''AT SELECTION SCREEN.'' Finch insists it''s harmless, but Nina looks nervous. What role does this keyword phrase play in ABAP?", "options": [{"content": "It defines a subroutine that can be called multiple times using PERFORM.", "feedback": "Close, but not exact. FORM...ENDFORM defines such subroutines. AT SELECTION SCREEN is an event keyword triggered automatically before the selection screen appears.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It is an event keyword that executes code just before the user inputs selections.", "feedback": "Exactly right. AT SELECTION SCREEN allows preprocessing before user input, such as setting default values or validating entries. Misuse here could sabotage input handling.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "It declares global types accessible across all programs in the system.", "feedback": "No. That would involve TYPES or dictionary definitions. AT SELECTION SCREEN controls execution timing, not data typing.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It outputs text directly to the user interface during report generation.", "feedback": "That’s the role of WRITE or similar operational keywords. AT SELECTION SCREEN doesn’t output—it reacts to lifecycle events.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Modularization Keywords", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Excellent. Event-driven modularization is central to SAP reports. Tampering with these can silently alter program behavior.", "relatedKnowledge": ["CONC_001", "CONC_008"], "feedbackIncorrect": "Remember: modularization includes both defining blocks (like FORM) and responding to system events (like AT SELECTION SCREEN)."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B1_003", "content": "ABAP control structures start with the keyword and end with ENDIF. Conditions follow IF, then optional ELSEIF/ELSE branches.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B1_001", "content": "ENDIF."}, {"itemId": "ITEM_B1_002", "content": "IF adjustment_flag IS INITIAL."}, {"itemId": "ITEM_B1_003", "content": "ADD base_amount TO total_revenue."}, {"itemId": "ITEM_B1_004", "content": "ELSE."}, {"itemId": "ITEM_B1_005", "content": "MULTIPLY total_revenue BY 1.1."}], "order": 3, "content": "Hayes reconstructs a suspicious IF block from fragmented logs. Arrange the lines in correct ABAP syntax order to reveal whether the condition could cause unintended financial adjustments.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Control Keywords", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005", "ITEM_B1_001"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. This sequence shows how an uninitialized flag could trigger incorrect revenue inflation—a subtle but dangerous flaw.", "relatedKnowledge": ["CONC_001", "CONC_018"], "feedbackIncorrect": "Check the structure: IF starts the block, THEN comes the true branch, ELSE handles the alternative, and ENDIF closes it."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the conference room, Hayes projects a failing code segment: ''WRITE flight_total.'' There''s no prior DATA declaration for flight_total. Which category of keyword is ''WRITE'', and why did this cause a runtime error?", "options": [{"content": "WRITE is a declarative keyword; it should have created the variable automatically.", "feedback": "Incorrect. Declarative keywords like DATA define variables, but WRITE is operational—it outputs values and requires pre-declared data objects.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "WRITE is an operational keyword; it processes data and failed because flight_total wasn’t declared with DATA first.", "feedback": "Correct. WRITE is an operational keyword that acts on already-declared data. Without a prior DATA statement, the variable doesn’t exist in memory, causing a runtime error.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "WRITE is a control keyword; it controls output formatting and ignores missing variables.", "feedback": "Incorrect. Control keywords manage program flow (e.g., IF, DO), while WRITE handles output. It cannot proceed without valid data sources.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "WRITE is a calling keyword; it tried to launch a report named ''flight_total''.", "feedback": "Incorrect. Calling keywords like SUBMIT or CALL invoke external units. WRITE outputs data—it doesn’t call anything.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Operational Keywords", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You’ve pinpointed how operational keywords depend on proper data declarations—a crucial vulnerability in the code.", "relatedKnowledge": ["CONC_001", "CONC_007"], "feedbackIncorrect": "Remember: operational keywords act on data, but they don’t create it. That’s the job of declarative statements."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B2_001", "content": "Local types must be defined before they can be used in DATA statements.", "unlockAfterAttempts": 1}, {"hintId": "HINT_B2_002", "content": "A variable inherits the length and type from its referenced local type. If the value exceeds that length, SAP throws an error.", "unlockAfterAttempts": 2}], "items": [{"itemId": "ITEM_B2_001", "content": "Declare a variable using the local type: DATA conn_id TYPE flight_conn."}, {"itemId": "ITEM_B2_002", "content": "Define a local data type: TYPES flight_conn TYPE c LENGTH 8."}, {"itemId": "ITEM_B2_003", "content": "Attempt to MOVE a 10-character string into conn_id."}, {"itemId": "ITEM_B2_004", "content": "Runtime error occurs: value too long for field conn_id."}], "order": 3, "content": "Hayes reconstructs a sequence of events from logs. Arrange these steps in the correct order to show how a local type definition could lead to a hidden error when misused:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Local Data Types", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": ["ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. You’ve traced how a local type, once defined, enforces strict typing across all uses—and how exceeding its limits causes failure.", "relatedKnowledge": ["CONC_007", "CONC_002"], "feedbackIncorrect": "Think about ABAP’s two-phase process: first define types, then declare variables, then use them. Missteps in order or size assumptions break the chain."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Hayes reviews a corrupted module where a field is declared as ''DATA mat_id LIKE mara-matnr''. She recalls that MATNR is defined globally in SE11. Why is this significant in tracing responsibility for the crash?", "options": [{"content": "Because local types cannot reference table fields, proving this was a manual override.", "feedback": "Not quite. Local types *can* reference fields via LIKE, but the key issue is whether the underlying type is global. The distinction lies in maintenance scope, not syntax legality.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because global types like MATNR are centrally managed in the ABAP Dictionary, only senior architects typically have authority to influence their usage in critical modules.", "feedback": "Exactly. Global data types (like MATNR) are maintained in transaction SE11 and affect system-wide consistency. Their use implies adherence to strict governance—so misuse points to someone with elevated access and knowledge.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "Because LIKE can only reference local variables, making this declaration invalid and causing the crash.", "feedback": "Incorrect. LIKE can reference both local and global fields—including components of database tables like mara-matnr. This syntax is valid and commonly used.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because TYPE must be used instead of LIKE when referencing dictionary objects.", "feedback": "No—both TYPE and LIKE can reference dictionary elements. TYPE refers to the data element directly, while LIKE inherits properties from an existing field. Both are valid; the choice depends on design intent.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Global Data Types", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You''re connecting architectural design patterns to access control—key to uncovering who had both motive and means.", "relatedKnowledge": ["CONC_007", "CONC_002"], "feedbackIncorrect": "Think about ownership: who controls global definitions? That’s where power—and suspicion—lies."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B3_001", "content": "Look for the logical flow: status comes before user, and each piece is output on the same line.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B3_001", "content": "Write the literal string ''Status:''"}, {"itemId": "ITEM_B3_002", "content": "Write the contents of variable sy-subrc"}, {"itemId": "ITEM_B3_003", "content": "Write the literal string ''User:''"}, {"itemId": "ITEM_B3_004", "content": "Write the contents of variable sy-uname"}], "order": 3, "content": "To demonstrate how output can mask errors, Hayes reconstructs a chain statement from the victim’s log display routine. Reconstruct the original chained WRITE statement from these component actions:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Chain Statements", "knowledgeId": "CONC_011"}, "difficulty": 2, "questionId": "Q_B3_003", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. Chaining keeps related outputs together—but also lets anomalies blend in.", "relatedKnowledge": ["CONC_012", "CONC_010"], "feedbackIncorrect": "Review how colon syntax groups multiple items under one command. Simplicity hides complexity."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Hayes reviews the access log and sees a line: ''WRITE: / ''User:'', SY-UNAME.'' She knows SY-UNAME is a special kind of variable. What category does SY-UNAME belong to in ABAP?", "options": [{"content": "Local Data Object", "feedback": "No. Local data objects are declared with DATA and exist within a program scope. SY-UNAME is predefined globally.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "ABAP System Field", "feedback": "Correct. SY-UNAME is a system field automatically populated by the runtime environment with the current user name.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B4_002"]}, {"content": "Global Type Definition", "feedback": "Not quite. Global types are defined in the ABAP Dictionary. SY-UNAME is part of the runtime context, not a type.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Built-in Function", "feedback": "No. Functions return values based on input. SY-UNAME is a read-only field containing current session data.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About System Fields", "knowledgeId": "CONC_014"}, "difficulty": 2, "questionId": "Q_B4_002", "knowledgeId": "CONC_014", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Yes. System fields like SY-UNAME provide contextual runtime data without requiring explicit initialization.", "relatedKnowledge": ["CONC_012"], "feedbackIncorrect": "Remember: SY-prefixed identifiers are system-maintained fields reflecting the current execution state."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B4_001", "content": "Use modularization tools like FORM/ENDFORM for logical blocks"}, {"itemId": "ITEM_B4_002", "content": "Indent each block by at least two columns"}, {"itemId": "ITEM_B4_003", "content": "Place comments on separate lines above code"}, {"itemId": "ITEM_B4_004", "content": "Structure program flow using event keywords like START-OF-SELECTION"}], "order": 3, "content": "To prove the code was tampered with, Hayes wants to reconstruct the proper ABAP layout standard. Arrange these best practices in the order they should be applied when writing clean, maintainable ABAP code.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About ABAP Layout Standards", "knowledgeId": "CONC_015"}, "difficulty": 2, "questionId": "Q_B4_003", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": ["ITEM_B4_004", "ITEM_B4_002", "ITEM_B4_001", "ITEM_B4_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. Structuring first, then indenting, modularizing, and finally commenting ensures maximum readability and reliability.", "relatedKnowledge": ["CONC_010", "CONC_003"], "feedbackIncorrect": "Think step-by-step: structure defines flow, indentation shows hierarchy, modularization separates logic, and comments explain intent."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_002", "content": "Recall what happens when CHECK evaluates to false.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "During code review, Hayes finds this fragment:\nDATA rem TYPE i.\nDO 20 TIMES.\n  rem = SY-INDEX MOD 5.\n  CHECK rem EQ 0.\n  WRITE (2) SY-INDEX.\nENDDO.\nWhy does this loop only print numbers divisible by 5?", "options": [{"content": "Because EXIT stops the loop when rem is not zero", "feedback": "No, there''s no EXIT here. The loop runs all 20 times, but only prints under certain conditions.", "optionId": "OPT_B5_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because CONTINUE skips printing when rem is not zero", "feedback": "CLOSE! But remember: there’s no explicit CONTINUE. However, CHECK implicitly behaves like one.", "optionId": "OPT_B5_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because CHECK causes a skip when rem EQ 0 is false", "feedback": "Yes. When rem EQ 0 returns false, CHECK triggers an automatic skip to the next iteration—no need for CONTINUE.", "optionId": "OPT_B5_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B5_002"]}, {"content": "Because WRITE only outputs even numbers", "feedback": "No, WRITE has no built-in filtering. The selection is controlled entirely by the CHECK statement above it.", "optionId": "OPT_B5_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_017"}, "difficulty": 3, "questionId": "Q_B5_002", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Precisely. CHECK acts as a gatekeeper: if the condition fails, the rest of the loop body is skipped.", "relatedKnowledge": ["CONC_018", "CONC_019"], "feedbackIncorrect": "Remember: CHECK is a conditional skip—it doesn’t terminate the loop, just bypasses remaining statements."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B1_004", "content": "This keyword is often paired with TIMES or ENDDO. It doesn''t check a condition at the top.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "In the final debugging session, Hayes isolates a loop meant to run only if ''counter > 0''. But the original coder used a keyword that runs unconditionally. Fill in the blank with the correct ABAP keyword that creates an unconditional loop: _____.\n\n(Hint: It runs until explicitly stopped with EXIT.)", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Control Keywords", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DO", "do"], "feedbackCorrect": "Correct. DO creates an unconditional loop—exactly the kind that can spiral out of control without proper exit conditions. This matches the crash pattern perfectly.", "relatedKnowledge": ["CONC_017", "CONC_019"], "feedbackIncorrect": "Think again. The keyword you''re looking for is ''DO''. WHILE checks a condition; DO runs blindly until EXIT or CHECK intervenes."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_003", "content": "This keyword starts with ''D'' and is used to assign names, types, and lengths to variables.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "In the final debugger walkthrough, Hayes highlights a fatal line: ''MOVE 1 TO counter.'' The program crashes here because ''counter'' was never declared with the ______ statement. What keyword was omitted?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Data Object Declaration", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_B2_004", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DATA"], "feedbackCorrect": "Exactly. Without a DATA statement, ''counter'' has no memory allocation or type definition—so any operational keyword acting on it will fail.", "relatedKnowledge": ["CONC_006", "CONC_008"], "feedbackIncorrect": "Remember: in ABAP, you must declare variables with DATA before using them in MOVE, WRITE, or arithmetic operations."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B3_002", "content": "This quality metric ensures others can understand your code quickly and safely.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "In her final reconstruction, Detective Hayes highlights a violation of coding standards: a comment embedded within a line using a double quote (\"). According to best practices shown in the team’s style guide, comments should appear on a separate line to improve ________.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Comment Best Practices", "knowledgeId": "CONC_010"}, "difficulty": 2, "questionId": "Q_B3_004", "knowledgeId": "CONC_010", "maxAttempts": 2, "correctOrder": null, "masteryReward": null, "correctAnswers": ["readability", "Readability"], "feedbackCorrect": "Yes—separating comments improves readability, making code easier to test, change, and trust. Nina’s shortcut betrayed her panic.", "relatedKnowledge": ["CONC_015"], "feedbackIncorrect": "Think about clarity: mixing code and comments makes both harder to follow. The goal is clean separation."}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 4, "content": "In the final debugger trace, Hayes spots a fatal line: ''result = TO_UPPER( amount ).'' She mutters, \"You can''t convert a number to uppercase...\" What category of ABAP feature is TO_UPPER an example of?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Built-in Functions", "knowledgeId": "CONC_016"}, "difficulty": 3, "questionId": "Q_B4_004", "knowledgeId": "CONC_016", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["ABAP Built-in Function", "built-in function", "ABAP intrinsic function", "intrinsic function"], "feedbackCorrect": "Correct. TO_UPPER is a built-in string function that fails when passed a non-string argument, causing a runtime type exception.", "relatedKnowledge": ["CONC_006", "CONC_017"], "feedbackIncorrect": "Hint: These are predeclared routines like SQRT, FIND, or TO_UPPER that operate on specific data types."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B5_003", "content": "Start with the loop initialization, then follow the flow through condition check, processing, and exit logic.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B5_001", "content": "Program enters DO 20 TIMES loop"}, {"itemId": "ITEM_B5_002", "content": "SY-INDEX MOD 5 is calculated and stored in rem"}, {"itemId": "ITEM_B5_003", "content": "IF rem EQ 0 check is performed"}, {"itemId": "ITEM_B5_004", "content": "Since rem ≠ 0, condition fails and loop continues"}, {"itemId": "ITEM_B5_005", "content": "WRITE outputs current SY-INDEX value"}, {"itemId": "ITEM_B5_006", "content": "Loop repeats until 20 iterations complete"}], "order": 3, "content": "Hayes reconstructs the final moments of the program. Arrange these execution steps in the correct order to show how the loop led to system failure.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_017"}, "difficulty": 3, "questionId": "Q_B5_003", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": ["ITEM_B5_001", "ITEM_B5_002", "ITEM_B5_003", "ITEM_B5_005", "ITEM_B5_004", "ITEM_B5_006"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. You''ve traced the exact path that overloaded the system—each iteration printed a number because the exit condition was never met.", "relatedKnowledge": ["CONC_018", "CONC_019"], "feedbackIncorrect": "Check again: the key flaw is that the IF condition didn’t lead to an EXIT, so every number was printed despite the modulo check."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B5_004", "content": "This operator checks whether two values are identical.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "To fix the infinite loop, the developer should have added an EXIT statement inside the IF block. Complete the corrected code:\nIF rem ___ 0.\n  EXIT.\nENDIF.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_019"}, "difficulty": 3, "questionId": "Q_B5_004", "knowledgeId": "CONC_019", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["EQ", "eq", "Eq"], "feedbackCorrect": "Correct. ''EQ'' ensures the loop exits only when rem equals zero, preventing unnecessary iterations.", "relatedKnowledge": ["CONC_017", "CONC_018"], "feedbackIncorrect": "Remember: in ABAP, ''EQ'' is used for equality comparison in conditional statements—not ''='' or ''=='' like in other languages."}], "characters": [{"age": 38, "goal": "Solve the murder by decoding technical clues and uncovering the truth behind the corrupted ABAP program.", "name": "Detective Lara Hayes", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She once worked at the same company years ago under a different name after a failed project ruined her early career.", "background": "Former software engineer turned forensic investigator specializing in enterprise system crimes.", "occupation": "Corporate Cybercrime Investigator", "characterId": "CHAR_001", "personality": "Analytical, observant, calm under pressure, with a dry wit.", "knowledgePoints": []}, {"age": 52, "goal": "Protect his reputation and prevent exposure of his shortcuts.", "name": "Dr. Elias Finch", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He falsified test results to meet the project deadline, risking system failure.", "background": "A pioneer in SAP development with decades of experience. Known for strict coding standards and intolerance for errors.", "occupation": "Lead ABAP Architect", "characterId": "CHAR_002", "personality": "Proud, meticulous, authoritative, slightly condescending.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_008", "CONC_009", "CONC_010"]}, {"age": 29, "goal": "Avoid blame for tampering with the code and keep her job.", "name": "Nina Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She secretly modified the victim''s code to ''fix'' it, violating protocol and potentially introducing the fatal error.", "background": "Self-taught coder who rose quickly through talent but lacks formal training in SAP best practices.", "occupation": "Junior ABAP Developer", "characterId": "CHAR_003", "personality": "Energetic, creative, impulsive, eager to prove herself.", "knowledgePoints": ["CONC_003", "CONC_004", "CONC_005", "CONC_006", "CONC_017", "CONC_018"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "ABAP Keyword", "category": "Syntax", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Reserved words in ABAP used to define operations, structures, or directives within a program.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_004", "CONC_006"]}, {"name": "Declarative Keyword", "category": "Declaration", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Keywords such as DATA, CONSTANTS, TYPES used to define variables, constants, and types in ABAP.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_007", "CONC_013"]}, {"name": "Modularization Keyword", "category": "Structure", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Keywords like FORM, ENDFORM, FUNCTION, PERFORM that allow breaking code into reusable blocks.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_005"]}, {"name": "Control Keyword", "category": "Flow Control", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Keywords such as IF, ELSE, CASE, ENDIF that manage conditional execution flow.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_018", "CONC_019"]}, {"name": "Calling Keyword", "category": "Execution", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Keywords like CALL FUNCTION, PERFORM, SUBMIT used to invoke procedures or programs.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_003"]}, {"name": "Operational Keyword", "category": "Operations", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Keywords involved in data manipulation such as MOVE, ADD, COMPUTE, WRITE.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_012"]}, {"name": "Data Object Declaration", "category": "Data", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "The process of defining a variable with a type and optional initial value using DATA or similar keywords.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_002", "CONC_008"]}, {"name": "Local Data Type", "category": "Data", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A type defined within a program or subroutine using TYPES, accessible only in its scope.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_009"]}, {"name": "Global Data Type", "category": "Data", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "A type defined in the ABAP Dictionary (SE11) available across multiple programs.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_008"]}, {"name": "ABAP Comment", "category": "Syntax", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Text annotations in code using * or \" that are ignored during execution.", "knowledgeId": "CONC_010", "relatedKnowledge": []}, {"name": "Chain Statement", "category": "Syntax", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Grouping multiple declarations or assignments in one line using commas.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_007"]}, {"name": "WRITE Statement", "category": "Output", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Output command used to display data on the screen during program execution.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_006"]}, {"name": "Constant Declaration", "category": "Data", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Defining unchangeable values using CONSTANTS keyword.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_002", "CONC_007"]}, {"name": "ABAP System Fields", "category": "Runtime", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Predefined fields like SY-DATUM, SY-UNAME that hold runtime information.", "knowledgeId": "CONC_014", "relatedKnowledge": []}, {"name": "ABAP Layout Standard", "category": "Style", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Formatting conventions for readable and maintainable ABAP code.", "knowledgeId": "CONC_015", "relatedKnowledge": []}, {"name": "ABAP Built-in Function", "category": "Functions", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Predefined functions like strlen(), conv(), or arithmetic helpers available without external calls.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_005"]}, {"name": "ABAP Loop Statement", "category": "Flow Control", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "LOOP AT ... ENDLOOP construct used to iterate over internal tables.", "knowledgeId": "CONC_017", "relatedKnowledge": ["CONC_004"]}, {"name": "ABAP Conditional Statement", "category": "Flow Control", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Logical constructs like IF/ELSE or CASE used to make decisions in code.", "knowledgeId": "CONC_018", "relatedKnowledge": ["CONC_004", "CONC_019"]}, {"name": "ABAP Relational Operator", "category": "Operations", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "Operators such as EQ, NE, GT, LT used in comparisons within conditions.", "knowledgeId": "CONC_019", "relatedKnowledge": ["CONC_018"]}], "educational_goals": ["Understand core ABAP language elements including keywords and statement types", "Differentiate between declarative, operational, control, and modularization constructs", "Apply knowledge of data declarations, system fields, and built-in functions in context", "Synthesize ABAP programming concepts to solve logical puzzles"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 3, "puzzle_sorting": 2}}', 'e136cf79e52a8786b9369e845eafcc8d4b6cfaa5492f5d0e9ef723a36812c984', 'all concepts', '2026-04-13 12:10:47.981634', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('6d39578a-4286-4fac-ae5d-e63d9f3ede2f', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '523be50a-a3b5-4361-b4bc-f77e1a24dcdb', NULL, 'The Framework Heist: A Web Architecture Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "Fragmented MVC Flow Log", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The system follows an MVC pattern where the Controller handles the request and delegates to the Model before forwarding to the View.", "description": "A partial server log showing request flow: ''POST /SelectCoffee → Servlet CoffeeSelection → Model: getTypes() → Forward to result.jsp''. The sequence suggests a clean separation of components, but lacks error handling traces.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003", "CONC_004"]}, {"name": "JSP with Scriptlet Anomaly", "type": "code", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "The View is not purely passive—it contains scriptlets that manipulate data, indicating a breach of MVC principles.", "description": "A recovered fragment of result.jsp contains embedded Java code: <% List styles = (List)request.getAttribute(\"styles\"); for(String s : styles) out.print(\"Try: \" + s); %>. This violates pure MVC by placing display logic in the View layer.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_006"]}, {"name": "Bean Scope Declaration", "type": "code", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Data flows from the Controller to the View using request-scoped attributes, consistent with proper MVC implementation.", "description": "A configuration snippet shows: <jsp:useBean id=\"styles\" type=\"java.util.List\" scope=\"request\"/>. This confirms data is shared via request scope from Controller to View.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_004", "CONC_008"]}, {"name": "Architectural Violation Report", "type": "document", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "A developer bypassed the Controller''s role by embedding logic in the JSP, undermining the MVC architecture.", "description": "An internal audit note states: ''Frontend templates directly invoke business logic via scriptlets. Controller does not fully mediate Model-View interaction.'' Points to developer override of design standards.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004"]}, {"name": "Suspicious Scriptlet in JSP", "type": "digital_artifact", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Kai used scriptlets in JSPs, mixing business logic with presentation.", "description": "A fragment of a JSP file recovered from the server cache shows embedded Java code using scriptlets to calculate business logic directly in the view layer. This violates MVC separation principles.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006", "CONC_004"]}, {"name": "Request Scope Data Flow Diagram", "type": "diagram", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "The correct pattern for transferring data between controller and view using request scope.", "description": "A whiteboard sketch in the war room illustrates how data moves from Servlet to JSP via request.setAttribute() and is accessed using jsp:useBean with scope=''request''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_007", "CONC_008"]}, {"name": "Hardcoded URL in JavaBean", "type": "code_snippet", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Morgan Vale embedded a critical dependency directly into a model object.", "description": "A JavaBean class contains a hardcoded service endpoint URL instead of reading from configuration. This makes the system fragile to environment changes.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007", "CONC_002"]}, {"name": "Incomplete Forward Chain", "type": "log_entry", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "A failure in the RequestDispatcher flow prevented the view from rendering despite valid model data.", "description": "Server logs show that a servlet processed a request and set attributes, but no corresponding JSP rendering occurred afterward—indicating a broken dispatch chain.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Session Leak Indicator", "type": "log_entry", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Evidence that session scope management is flawed, leading to memory exhaustion.", "description": "A log snippet from the application server shows HttpSession objects accumulating over time without being invalidated. The count grows linearly with user activity, suggesting disabled cleanup mechanisms.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Framework Misuse Note", "type": "annotation", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The web framework’s standard flow was intentionally circumvented, violating architectural integrity.", "description": "A sticky note found near Dr. Reed''s workstation reads: ''Struts config bypassed for faster routing – temporary fix until post-launch review.'' Handwriting matches internal team logs.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010"]}, {"name": "Scope Chain Evidence", "type": "code_trace", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Demonstrates improper reliance on session scope for state persistence without synchronization.", "description": "A reconstructed execution trace shows a JavaBean stored in session scope after login, then accessed across three separate requests before timeout. The same bean was later overwritten due to concurrent access.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Hardcoded Framework Path", "type": "configuration_file", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Shows deliberate weakening of framework safeguards, increasing risk of runtime failure.", "description": "A deployment descriptor contains an embedded Spring Boot profile reference hardcoded as ''spring.profiles.active=legacy-mode'', which disables auto-configuration safety checks.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_010"]}], "title": "The Framework Heist: A Web Architecture Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Server Room Shutdown", "sceneId": "SCENE_001", "location": "Enterprise Data Center - Server Room", "description": "Lights flicker as alarms blare. The primary application server is down. Logs show abnormal traffic before shutdown. Detective Lin arrives to find Dr. Reed already analyzing console output while Kai checks display dashboards and Morgan reviews deployment scripts.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Audit in the War Room", "sceneId": "SCENE_002", "location": "Development Team Conference Room", "description": "The team gathers around a large screen displaying fragmented logs and code snippets. Tensions rise as each developer defends their component. Detective Lin probes inconsistencies in request handling and state management across layers.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Deployment Log", "sceneId": "SCENE_003", "location": "Secure Review Chamber", "description": "With all evidence compiled, Detective Lin reconstructs the timeline of the failure. Each suspect’s actions are mapped to system behaviors. The true cause emerges from the interaction of flawed scopes, misused components, and architectural violations.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003", "CHAR_004"]}], "endings": [{"type": "Correct", "title": "Architectural Collapse", "content": "The system failed due to cumulative violations of MVC principles: session scope misuse, embedded logic in views, and hardcoded dependencies. No single person was solely responsible—but the lack of adherence to component roles caused the crash.", "debrief": "MVC integrity depends on strict role separation. Controllers must route, Models must manage logic, Views must render. Scopes must be managed appropriately, and frameworks used correctly.", "summary": "The truth is systemic: architectural discipline prevents failure.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "Blame the Framework", "content": "You conclude the web framework was inherently unstable. But deeper investigation would have revealed human deviations from its intended use.", "debrief": "Frameworks are tools, not scapegoats. Misuse of components—even with powerful tools—leads to failure.", "summary": "The real flaw wasn''t the framework—it was ignoring its design.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "One Bad Actor", "content": "You pin the failure on one developer’s mistake. But the logs show multiple contributing factors across layers.", "debrief": "Enterprise systems fail due to interactions, not isolation. Root causes often span components and scopes.", "summary": "Complex systems require holistic understanding—not singular blame.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "When a critical enterprise system vanishes from the server room, a detective must interrogate three developers to uncover how MVC architecture was compromised—and who sabotaged the deployment.", "version": "1.0", "evidence": [{"name": "Corrupted Deployment Log", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A partial log showing a successful build but failed initialization due to a missing session listener.", "foundLocation": "Server Room Terminal", "relatedKnowledge": ["CONC_009", "CONC_001"]}, {"name": "JSP with Embedded Logic", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A JSP file containing scriptlet code that modifies database records directly, bypassing the model.", "foundLocation": "Developer Workstation Backup", "relatedKnowledge": ["CONC_004", "CONC_006", "CONC_008"]}, {"name": "Hardcoded Service URL in JavaBean", "type": "Configuration Artifact", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A JavaBean class with a fixed endpoint URL instead of environment-based configuration.", "foundLocation": "Source Code Repository", "relatedKnowledge": ["CONC_003", "CONC_007"]}, {"name": "Framework Initialization Error", "type": "Error Log", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "Stack trace indicating a conflict between custom servlets and framework controllers during startup.", "foundLocation": "Application Server Logs", "relatedKnowledge": ["CONC_002", "CONC_005", "CONC_010"]}, {"name": "Memory Dump Showing Stale Sessions", "type": "System Snapshot", "clueIds": [], "evidenceId": "EVIDENCE_005", "description": "Heap analysis reveals thousands of inactive user sessions never cleaned up.", "foundLocation": "Server Memory Image", "relatedKnowledge": ["CONC_009", "CONC_001"]}], "has_quiz": false, "scriptId": "ESD_MVC_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the initial logs and sees a request hitting a servlet, which then forwards to a JSP. She suspects this follows a standard web architecture. Which pattern best describes this flow?", "options": [{"content": "Model-View-Presenter (MVP)", "feedback": "Incorrect. While similar, MVP typically involves more direct View-Presenter communication. The observed flow matches MVC’s Controller-mediated approach.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Model-View-Controller (MVC)", "feedback": "Correct. The flow—request → Servlet (Controller) → Model → forward to JSP (View)—aligns perfectly with MVC architecture.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "Client-Server Pattern", "feedback": "Incorrect. While the system uses client-server communication, this doesn’t explain the internal component interactions seen in the logs.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Singleton Pattern", "feedback": "Incorrect. Singleton governs object instantiation, not application flow between UI, logic, and data layers.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About MVC Architecture", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the JSP templates and finds embedded Java code performing calculations normally handled by backend services. Which technology was misused in a way that breaks MVC principles?", "options": [{"content": "Servlet", "feedback": "Incorrect. Servlets are controllers and should handle requests, not display logic. The issue lies in the presentation layer.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Java Bean", "feedback": "Incorrect. Java Beans are meant to carry data, not execute business rules in the view. The problem is where the code was placed.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "JSP with scriptlets", "feedback": "Correct. Using scriptlets in JSPs embeds business logic in the View layer, violating MVC separation. This makes systems harder to maintain and debug.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "Request Scope", "feedback": "Incorrect. Request scope is a valid mechanism for sharing data—it''s not the misuse itself. The real issue is how JSPs were programmed.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About JSP", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_008"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "In the server logs, Detective Lin sees that temporary data was shared between the servlet and JSP for a single request cycle. This data existed only during the request and was destroyed after the response. What is this called? (Hint: two words, e.g., ''session scope'')", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Scopes in MVC", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["request scope"], "feedbackCorrect": "Correct. Request scope ensures data is available only for the duration of a single HTTP request and is ideal for transient data passed from controller to view.", "relatedKnowledge": ["CONC_005", "CONC_007"], "feedbackIncorrect": "Incorrect. Consider the lifecycle: if data disappears after one request-response cycle and isn''t stored globally or per-user, it must be in request scope."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the server logs and notices thousands of active sessions piling up despite low user traffic. She suspects a flaw in how user state is managed between requests. Which concept best explains the lifecycle phase where data persists across multiple interactions from the same client?", "options": [{"content": "Request Scope – data exists only for a single HTTP request and its forward.", "feedback": "Incorrect. While request scope handles short-lived data, it does not persist across multiple client interactions. Session scope is designed specifically for maintaining state like login status or shopping carts over several requests.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Application Scope – data shared globally among all users and sessions.", "feedback": "Incorrect. Application scope is global and long-lived, but it doesn''t isolate user-specific data. This would cause cross-user contamination rather than individual session buildup.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Session Scope – data tied to a specific user’s interaction timeline.", "feedback": "Correct. Session scope maintains state for a particular user across multiple requests during a defined period. Improper handling—like disabling cleanup—can lead to memory leaks, exactly what the logs suggest.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "Page Scope – data limited to a single JSP page rendering.", "feedback": "Incorrect. Page scope is extremely short-lived and confined to one JSP instance. It cannot support multi-request state tracking.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Session Scope", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_008"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Reed insists the framework enforces strict separation: ''The View must never create or modify data.'' Detective Lin reviews result.jsp and finds scriptlets manipulating a list. Which principle has been violated?", "options": [{"content": "The Model should notify the View on state change.", "feedback": "Incorrect. While part of MVC, this relates to dynamic updates, not the misuse of the View layer.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The View should only retrieve and display data from beans.", "feedback": "Correct. The View’s role is presentation only. Using scriptlets to process data breaks this rule and introduces logic into the display layer.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "The Controller must handle authentication.", "feedback": "Incorrect. Authentication is a Controller responsibility, but not what’s being violated here.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "JavaBeans must be serializable.", "feedback": "Incorrect. While good practice, serializability isn''t the issue; it''s the improper use of the View component.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About the View Component", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_006"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Morgan argues that the Controller must set up beans and place them in scope before forwarding. Kai counters that JSPs can instantiate beans. Detective Lin checks the JSP: <jsp:useBean id=\"styles\" type=\"java.util.List\" scope=\"request\"/>. What does this imply?", "options": [{"content": "The JSP creates its own data model independently.", "feedback": "Incorrect. The ''type'' attribute without ''class'' means it only retrieves an existing bean, not creates one.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The bean was placed in request scope by the Controller.", "feedback": "Correct. The JSP expects the bean to already exist in request scope, confirming the Controller’s responsibility to prepare and pass data.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "The data is stored globally across all users.", "feedback": "Incorrect. ''scope=request'' means it''s only available for this single request chain, not globally.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The View modifies the bean’s state.", "feedback": "Incorrect. <jsp:useBean> with ''type'' only accesses the bean; no modification occurs in this tag.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About the Controller Component", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_008"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Dr. Reed insists the framework is sound, but Detective Lin reviews a log showing data passed from a servlet to a JSP that never rendered it. What role does the Servlet play in ensuring this handoff works correctly?", "options": [{"content": "It serves as the Model to store application state.", "feedback": "Incorrect. The Model holds data, but the Servlet is not primarily a data container—it’s a coordinator.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It acts as the Controller, processing requests and forwarding to views.", "feedback": "Correct. The Servlet is the Controller that processes input, invokes business logic, sets data in scope, and uses RequestDispatcher to forward to the JSP View.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "It functions as the View to generate HTML output.", "feedback": "Incorrect. The JSP is the View. Servlets don’t typically generate raw HTML—they delegate rendering.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It replaces JavaBeans for data transfer.", "feedback": "Incorrect. JavaBeans are still used to encapsulate data. The Servlet uses them but doesn’t replace their purpose.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Servlets", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008", "CONC_007"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Morgan argues his backend logic is flawless, yet a JavaBean he wrote contains a fixed URL. What is the primary purpose of a JavaBean in an MVC architecture?", "options": [{"content": "To serve as the main entry point for HTTP requests.", "feedback": "Incorrect. That role belongs to the Servlet. JavaBeans do not handle incoming requests.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To act as reusable data carriers between layers.", "feedback": "Correct. JavaBeans (or POJOs) are used to transport data from the Controller to the View, especially via request or session scopes.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "To define the structure of database tables.", "feedback": "Incorrect. While JavaBeans can map to tables, their role in MVC is broader—they transfer any kind of application data.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To render dynamic content on web pages.", "feedback": "Incorrect. Rendering is done by JSPs. JavaBeans provide data, not formatting.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About JavaBeans", "knowledgeId": "CONC_007"}, "difficulty": 2, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_005"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During the code audit, Detective Lin discovers that the team used Apache Struts but bypassed its standard controller routing to implement custom shortcuts. What is the primary purpose of using established web frameworks like Struts or Spring Boot in enterprise applications?", "options": [{"content": "To eliminate the need for databases by embedding storage in views.", "feedback": "Incorrect. Web frameworks do not replace databases; they help organize application layers including data access, but don’t remove backend dependencies.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To provide standardized solutions for common problems like MVC separation, testing, and configuration management.", "feedback": "Correct. Web frameworks offer reusable architectures that enforce best practices such as separation of concerns, facilitate unit testing, and improve maintainability—exactly why bypassing them introduces technical debt.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "To allow developers to write all logic inside JSP files for faster rendering.", "feedback": "Incorrect. Writing logic in JSPs violates MVC principles and undermines framework benefits. Frameworks aim to prevent this kind of anti-pattern.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To automatically generate frontend UI designs based on model annotations.", "feedback": "Incorrect. While some frameworks support templating, their main value lies in structural consistency and backend organization—not visual design automation.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Web Frameworks", "knowledgeId": "CONC_010"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 3, "content": "Detective Lin examines a suspicious line in the login servlet: `session.setAttribute(\"userProfile\", profile);`. No expiration or invalidation logic follows. This indicates misuse of the _______ scope, which should be carefully managed to avoid memory overload.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Session Scope", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["session", "Session", "SESSION", "HttpSession", "httpsession"], "feedbackCorrect": "Correct. Storing objects in session scope without proper timeout or cleanup can accumulate memory usage over time—especially dangerous in high-traffic systems.", "relatedKnowledge": ["CONC_007", "CONC_008"], "feedbackIncorrect": "Incorrect. The key clue is the use of `session.setAttribute`, which directly relates to session scope. Unlike request or page scopes, session persists per user and must be actively managed to prevent leaks."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "User submits form requesting coffee advice"}, {"itemId": "ITEM_B1_002", "content": "Servlet (Controller) receives request and reads parameters"}, {"itemId": "ITEM_B1_003", "content": "Controller calls CoffeeExpert (Model) to get recommendations"}, {"itemId": "ITEM_B1_004", "content": "Controller places result in request attribute and forwards to JSP"}, {"itemId": "ITEM_B1_005", "content": "JSP (View) retrieves list and displays recommendations"}], "order": 4, "content": "To reconstruct the failure timeline, Detective Lin must verify the correct MVC control cycle. Arrange these steps in order based on standard Servlet-centric MVC flow.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About MVC Architecture", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. This sequence reflects the proper MVC flow: User action → Controller → Model → Data passing → View rendering.", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004"], "feedbackIncorrect": "Incorrect. Remember: the Controller mediates between the user input, the Model for logic, and the View for output. Ensure data flows through request attributes."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B1_001", "content": "This component corresponds to domain objects and handles core application logic, like generating coffee recommendations.", "unlockAfterAttempts": 1}], "items": null, "order": 5, "content": "Detective Lin concludes that the root cause wasn''t faulty architecture, but a violation of MVC principles: the View was used to perform logic that should have remained in the ________ layer.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About MVC Architecture", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["Model", "model"], "feedbackCorrect": "Correct. Business logic belongs in the Model layer. Placing it in the View breaks separation of concerns and makes the system harder to maintain and debug.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Think about which component is responsible for encapsulating business rules and data processing—the answer is the central data and logic layer."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "User submits form data to a Servlet"}, {"itemId": "ITEM_B2_002", "content": "Servlet processes request and creates a JavaBean"}, {"itemId": "ITEM_B2_003", "content": "Servlet stores Bean in request scope using setAttribute()"}, {"itemId": "ITEM_B2_004", "content": "Servlet forwards request to JSP using RequestDispatcher"}, {"itemId": "ITEM_B2_005", "content": "JSP uses jsp:useBean with scope=''request'' to retrieve data"}, {"itemId": "ITEM_B2_006", "content": "JSP displays results to the user"}], "order": 4, "content": "To reconstruct the final moments before the crash, Detective Lin must verify the correct sequence of events in the request lifecycle. Arrange the steps showing how data flows from user input to page display in a proper Servlet-JSP MVC flow.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Request Scope", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_005", "ITEM_B2_006"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. This sequence shows the standard MVC flow: request → servlet (controller) → bean population → request scope → forward → JSP (view) → display.", "relatedKnowledge": ["CONC_005", "CONC_006", "CONC_007"], "feedbackIncorrect": "Incorrect. Remember: the Servlet must set the attribute before forwarding, and the JSP retrieves it using the same scope. The flow must follow the request lifecycle strictly."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Developer disables auto-configuration safety in Spring Boot via hardcoded profile."}, {"itemId": "ITEM_B3_002", "content": "Framework fails to initialize connection pool properly during startup."}, {"itemId": "ITEM_B3_003", "content": "Application accepts user sessions but cannot validate them against database."}, {"itemId": "ITEM_B3_004", "content": "Orphaned sessions accumulate until memory threshold is exceeded."}], "order": 4, "content": "In the final reconstruction, Detective Lin traces how a misconfigured framework setting led to cascading failures. Arrange these events in chronological order to reveal the root cause progression.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Web Frameworks", "knowledgeId": "CONC_010"}, "difficulty": 4, "questionId": "Q_B3_004", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The chain starts with a violation of framework best practices (hardcoding), leading to initialization failure, broken session validation, and eventual system collapse due to unmanaged state.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Incorrect. Remember: the root cause begins with human intervention in framework settings. From there, technical failures cascade—first in setup, then in operation, finally in resource management."}], "characters": [{"age": 38, "goal": "Reconstruct the sequence of events leading to the system failure and identify the culprit.", "name": "Detective Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once bypassed security protocols to fix a production bug, leaving a hidden backdoor that still exists.", "background": "A seasoned troubleshooter for enterprise software failures, known for solving complex technical mysteries by reconstructing system behavior from logs and testimonies.", "occupation": "System Integrity Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and deeply curious about how systems break.", "knowledgePoints": ["CONC_001", "CONC_010"]}, {"age": 45, "goal": "Protect her reputation and prove the framework wasn’t flawed—someone misused it.", "name": "Dr. Elena Reed", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She secretly disabled automatic session cleanup to preserve debugging data, causing memory leaks.", "background": "Designed the original MVC framework used in the system. Advocates for pure architectural separation and despises shortcuts.", "occupation": "Lead Architect", "characterId": "CHAR_002", "personality": "Precise, authoritative, intolerant of inefficiency, but hides anxiety about legacy code.", "knowledgePoints": ["CONC_001", "CONC_009", "CONC_010"]}, {"age": 29, "goal": "Avoid blame for poor coding practices and shift suspicion toward infrastructure issues.", "name": "Kai Tanaka", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Used scriptlets in JSPs to handle business logic, violating MVC principles to meet a deadline.", "background": "Responsible for JSP templates and client-side integration. Prefers rapid iteration over strict patterns.", "occupation": "Frontend Developer", "characterId": "CHAR_003", "personality": "Creative, impulsive, values user experience over backend purity, often cuts corners.", "knowledgePoints": ["CONC_004", "CONC_006", "CONC_008"]}, {"age": 34, "goal": "Prove that improper use of components by others caused the collapse, not his code.", "name": "Morgan Vale", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Hardcoded a critical service URL in a JavaBean instead of using configuration files.", "background": "Built the core services and servlets. Believes business logic belongs firmly in the model layer.", "occupation": "Backend Engineer", "characterId": "CHAR_004", "personality": "Logical, reserved, speaks in precise technical terms, distrusts frontend decisions.", "knowledgePoints": ["CONC_002", "CONC_003", "CONC_005", "CONC_007"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "MVC Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A design pattern that separates an application into three interconnected components: Model (data and logic), View (user interface), and Controller (input handling).", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_004", "CONC_010"]}, {"name": "Controller Component", "category": "Component", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Handles user input, updates the model, and selects views. In Java web apps, often implemented as Servlets.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_005"]}, {"name": "Model Component", "category": "Component", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Manages data, business rules, and application logic. Independent of user interface concerns.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "View Component", "category": "Component", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Presents data to the user and sends user actions to the controller. In Java, often implemented with JSP.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Servlet", "category": "Technology", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Java classes that handle requests and responses in web applications. Commonly used as controllers in MVC.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_002"]}, {"name": "JavaServer Pages (JSP)", "category": "Technology", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Templating technology for creating dynamic web content. Used to implement view components.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_004", "CONC_008"]}, {"name": "Java Bean", "category": "Technology", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "Reusable Java component with private fields, getters/setters, and no-argument constructor. Often used in models.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_003"]}, {"name": "Request Scope", "category": "Scope", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Lifespan of data tied to a single HTTP request. Objects are created and destroyed per request.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_006", "CONC_009"]}, {"name": "Session Scope", "category": "Scope", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Lifespan of data tied to a user''s session. Persists across multiple requests until timeout or logout.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "Web Frameworks", "category": "Framework", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Software frameworks that support web application development, often implementing MVC or similar patterns.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_001", "CONC_002"]}], "educational_goals": ["Understand the components and flow of MVC architecture in enterprise systems", "Differentiate between Model, View, and Controller responsibilities", "Explain the roles of Servlets, JSPs, and JavaBeans in web applications", "Compare request and session scope behaviors", "Evaluate the impact of web frameworks on system design"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 2, "puzzle_sorting": 2}}', 'fba2463e290cb744d8c1f27d6a6d964d52b55d2974b247581720ed880a316b54', 'all concepts', '2026-04-27 15:04:45.121427', NULL, 'ITP4511') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('85cdccad-053a-4a01-990a-6265142dc053', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '2a7da247-2b88-467c-a6e2-e32077162d3c', NULL, 'The ABAP Enigma: A Corporate Code Crisis', 'active', 'easy', 'standard', '{"clues": [{"name": "Suppressed Integration Warning Log", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Marcus made a strategic decision to suppress automation alerts to preserve legacy workflows.", "description": "A hidden log entry shows Marcus manually disabled a DSS alert related to CRM-SAP field mismatches. Timestamped just before the ZLOG_FAIL crash.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_001", "CONC_005"]}, {"name": "Unapproved Macro Reuse Note", "type": "code_annotation", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Tanya made an operational-level coding shortcut that introduced data corruption.", "description": "Tanya’s personal development notebook contains a scribbled note: ''Reused ZMACRO_LEGACY in ZLOG_FAIL – validation skipped due to deadline pressure.''", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_003", "CONC_018"]}, {"name": "CRM Field Mapping Discrepancy Report", "type": "diagram", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "The integration failure originated from a tactical decision to prioritize speed over schema alignment.", "description": "A printout from the Data Integration Hub highlights mismatched key fields between CRM customer IDs and SAP shipment records. Marked with tactical planning stamps.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "CRM Integration Log Excerpt", "type": "document", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The CRM system is feeding inconsistent customer data into transactional processes due to a schema misalignment.", "description": "A printed log snippet shows CRM data sync attempts with the SAP ERP system. One entry reads: ''WARNING: Customer ID mismatch in interface Z_CRM_SHIP — field CUST_ID length differs between systems.''", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "DSS Decision Trace Report", "type": "digital", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "A tactical decision made via DSS was ignored, leading to suppressed warnings in the data pipeline.", "description": "An internal DSS output file labeled ''Integration Risk Assessment Q3'' reveals that a recommendation to disable automated validation checks was overruled by ''senior integration lead.'' The justification cited ''workflow continuity over precision.''", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_006", "CONC_007"]}, {"name": "NetWeaver Architecture Annotation", "type": "diagram", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "NetWeaver is being used as a pass-through without enforcing data integrity between CRM and ERP layers.", "description": "Handwritten notes on the SAP landscape diagram highlight the NetWeaver integration broker layer. An arrow points to the message interface with the label: ''All CRM payloads routed through here — no payload schema validation enabled.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007", "CONC_008"]}, {"name": "ERP Module Dependency Map", "type": "diagram", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "The ERP system''s unified database integrity is compromised by an approved bypass, enabling unverified data propagation.", "description": "A wall-mounted flowchart shows how master data flows from CRM to ERP modules. A red stamp reads: ''Approved under legacy exception — compliance review waived.'' The path bypasses standard validation gates in finance and logistics.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008", "CONC_005"]}, {"name": "ABAP Editor Access Log", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Tanya had direct access and made recent changes to the faulty ABAP report using standard development tools.", "description": "A log entry showing that Tanya accessed transaction code SE38 (ABAP Editor) late at night to modify ZLOG_FAIL. The timestamp correlates with the last known change before the system failure.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "Three-Tier Architecture Diagram Annotated", "type": "diagram", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The root cause must originate in either the Application or Database layer; Presentation layer cannot independently cause execution halts.", "description": "Lena''s annotated sketch of the SAP three-tier model, highlighting how a database layer issue could propagate upward only if triggered by an application layer process.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Foreign Key Constraint Missing Report", "type": "system alert", "clueId": "CLUE_B3_003", "foundBy": "CHAR_003", "reveals": "The corrupted data entries were possible due to missing constraints — a structural flaw in table design.", "description": "Database monitoring output showing that no foreign key enforces referential integrity between ZLOG_FAIL’s customer and shipment tables, allowing invalid joins.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_012"]}, {"name": "Execution Flow Sequence Log", "type": "log file", "clueId": "CLUE_B3_004", "foundBy": "CHAR_002", "reveals": "The error occurred during the database query phase, but was initiated through normal transactional flow from application logic.", "description": "Chronological trace of system events leading up to ZLOG_FAIL’s crash: user input → presentation layer → ABAP processor → database query → error return.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "Missing Foreign Key Constraint", "type": "document", "clueId": "CLUE_B4_001", "foundBy": "CHAR_001", "reveals": "The absence of referential integrity enforcement enabled data corruption in transactional reports.", "description": "A database schema analysis reveals that the PROD_SN field in ZSALES references ZPRODUCT, but no foreign key constraint is defined in the ABAP Dictionary. This allowed invalid product serial numbers to be entered into sales records.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_013"]}, {"name": "Master vs Transaction Table Classification", "type": "diagram", "clueId": "CLUE_B4_002", "foundBy": "CHAR_003", "reveals": "Understanding table volatility helps identify appropriate validation and integration strategies.", "description": "A labeled data model shows ZPRODUCT as a master table with stable attributes like PROD_PRICE, while ZSALES is marked as transactional due to high-frequency inserts and event-driven nature.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_014"]}, {"name": "ABAP Selection Screen Definition", "type": "code snippet", "clueId": "CLUE_B4_003", "foundBy": "CHAR_001", "reveals": "The report accepts filtered criteria, but bypasses backend validation during data retrieval.", "description": "The source code for ZLOG_FAIL includes PARAMETERS for SALES_NO and SELECT-OPTIONS for PERIOD, confirming user input filtering occurs before execution.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_015"]}, {"name": "JOIN Logic in Corrupted Report", "type": "code trace", "clueId": "CLUE_B4_004", "foundBy": "CHAR_001", "reveals": "Data enrichment failed because the JOIN relied on potentially invalid keys not enforced by dictionary constraints.", "description": "An execution trace shows the ABAP report performs an INNER JOIN between ZSALES and ZPRODUCT on PROD_SN, yet returns incomplete results due to unvalidated inputs.", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_016"]}, {"name": "Macro Expansion Log Fragment", "type": "digital", "clueId": "CLUE_B5_001", "foundBy": "CHAR_001", "reveals": "The use of ABAP macros introduces hidden risks due to compile-time substitution without parameter validation.", "description": "A partial compile-time log from the ABAP Workbench showing macro expansion for Z_DAILY_PROFIT. It reveals that the DEFINE block was expanded inline before execution, with no type checking on parameters.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_018"]}, {"name": "Function Module Interface Record", "type": "system", "clueId": "CLUE_B5_002", "foundBy": "CHAR_002", "reveals": "Function modules provide reusable, stateless logic with strict interfaces and error handling—ideal for shared business calculations.", "description": "Metadata extracted from SE37 for function module Z_FM_MEAL_PROFIT, including IMPORTING/EXPORTING parameters and exception INPUT_ERROR. Shows clean interface contract used across programs.", "foundInScene": "SCENE_004", "relatedKnowledge": ["CONC_017"]}, {"name": "Code Reuse Pattern Mismatch", "type": "analysis", "clueId": "CLUE_B5_003", "foundBy": "CHAR_001", "reveals": "Macros were misused where function modules should have been directly invoked, increasing complexity and reducing maintainability.", "description": "Side-by-side comparison showing Tanya’s report using a macro to call Z_FM_MEAL_PROFIT repeatedly versus proper CALL FUNCTION usage in other modules. Highlights inconsistent reuse strategy.", "foundInScene": "SCENE_005", "relatedKnowledge": ["CONC_017", "CONC_018"]}, {"name": "Corrupted Output Trace", "type": "log", "clueId": "CLUE_B5_004", "foundBy": "CHAR_003", "reveals": "Lack of runtime type safety in macros allowed malformed input to corrupt financial calculations.", "description": "Execution trace from Z_DAILY_PROFIT showing incorrect profit values for ''Donut'' and ''Coffee''. Traced back to unvalidated string-to-number conversion inside macro.", "foundInScene": "SCENE_006", "relatedKnowledge": ["CONC_018"]}], "title": "The ABAP Enigma: A Corporate Code Crisis", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "System Failure Alert", "sceneId": "SCENE_001", "location": "SAP Control Room", "description": "An emergency alert flashes across the main monitor: ''Critical ABAP Report ZLOG_FAIL halted execution.'' Lena arrives to find Marcus reviewing logs and Tanya frantically typing. The trio must assess the immediate damage and begin tracing the error path.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 1, "clues": [], "order": 2, "title": "Architecture Audit", "sceneId": "SCENE_002", "location": "Network Operations Center", "description": "Lena reviews the SAP landscape diagram. Marcus explains how NetWeaver integrates ERP functions across departments. They examine the three-tier model and discuss how disruptions can propagate from presentation to database layer.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 1, "clues": [], "order": 3, "title": "Code Repository Dive", "sceneId": "SCENE_003", "location": "Development Lab", "description": "Tanya shows Lena the ABAP source code for ZLOG_FAIL. They inspect the selection screen parameters and notice unusual JOIN logic between customer and shipment tables. Something feels off about the table relationships.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 4, "title": "Integration Anomalies", "sceneId": "SCENE_004", "location": "Data Integration Hub", "description": "Marcus reveals that recent CRM updates triggered unexpected behavior in transactional data flow. He demonstrates how tactical decisions in DSS affected operational outputs. Lena suspects misaligned key fields are corrupting reports.", "charactersPresent": ["CHAR_001", "CHAR_002"]}, {"act": 2, "clues": [], "order": 5, "title": "Table Truths", "sceneId": "SCENE_005", "location": "Database Monitoring Station", "description": "Tanya accesses the data dictionary. Lena guides her through distinguishing master data (customers) from transactional records (shipments). They discover a missing foreign key constraint that allowed invalid entries to slip through.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 3, "clues": [], "order": 6, "title": "Final Confrontation: The Corrupted Macro", "sceneId": "SCENE_006", "location": "Executive Briefing Room", "description": "All three reconvene. Lena presents evidence showing that a reused ABAP macro bypassed validation checks. While Tanya admits her oversight, Marcus is revealed to have suppressed warnings to maintain control over integration workflows. The truth emerges: both contributed to the failure through different levels of decision-making.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct Resolution", "title": "Truth Uncompiled", "content": "Lena reveals that while Tanya’s use of an outdated macro introduced the bug, Marcus’s suppression of integration warnings allowed it to escalate unchecked. Both are accountable in different ways. The company implements code review policies and transparency protocols.", "debrief": "The solution highlights how technical errors and managerial decisions interact in enterprise systems. Understanding both ABAP fundamentals and architectural context is crucial for system health.", "summary": "The mystery resolves through synthesis of programming knowledge and system awareness. No single villain exists—only systemic gaps in communication and oversight.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004", "SCENE_005", "SCENE_006"], "requiredQuestions": []}}, {"type": "Partial Resolution", "title": "Code Fixed, Truth Hidden", "content": "Tanya fixes the macro and restores the report. However, Marcus’s role in suppressing warnings remains undiscovered. The system works—for now—but vulnerabilities persist.", "debrief": "Fixing symptoms without addressing root causes leads to recurring failures. Technical skill alone isn’t enough without ethical transparency.", "summary": "A functional but incomplete resolution. The player solved the coding issue but missed the human factor.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_005"], "requiredQuestions": []}}, {"type": "Incorrect Accusation", "title": "Fall Guy Compiled", "content": "Lena blames Tanya entirely. She is reassigned to documentation duty. Marcus breathes easy, but six weeks later, the same error returns—worse than before.", "debrief": "Rushing to judgment without full data leads to injustice and repeated failure. Always trace problems across people, process, and technology.", "summary": "A cautionary ending where surface-level analysis leads to wrong conclusions and future breakdowns.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_004"], "requiredQuestions": []}}], "logline": "When a critical SAP system fails at a global logistics firm, three IT professionals must uncover the truth behind a sabotaged ABAP program—using their knowledge of SAP architecture and programming fundamentals to expose the culprit before the company collapses.", "version": "1.0", "evidence": [{"name": "Corrupted ABAP Source Code", "type": "Digital File", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "The source code of report ZLOG_FAIL containing a malformed JOIN and an unvalidated macro.", "foundLocation": "Development Lab", "relatedKnowledge": ["CONC_010", "CONC_016", "CONC_018"]}, {"name": "Missing Foreign Key Constraint", "type": "Database Schema Anomaly", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A gap in referential integrity between SHIPMENT and CUSTOMER tables allowing orphaned records.", "foundLocation": "Database Monitoring Station", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Suppressed Integration Warning Log", "type": "System Log", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Hidden log entry showing Marcus disabled alerts from the CRM integration module two days prior.", "foundLocation": "Data Integration Hub", "relatedKnowledge": ["CONC_002", "CONC_006"]}, {"name": "Outdated Macro Definition", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A reusable macro copied from an obsolete project that lacks modern validation rules.", "foundLocation": "Code Repository", "relatedKnowledge": ["CONC_018", "CONC_010"]}, {"name": "SAP Three-Tier Diagram", "type": "Technical Schematic", "clueIds": [], "evidenceId": "EVIDENCE_005", "description": "Official architecture blueprint highlighting separation of presentation, application, and database layers.", "foundLocation": "Network Operations Center", "relatedKnowledge": ["CONC_009", "CONC_007"]}], "has_quiz": false, "scriptId": "MS001", "questions": [{"type": "fill_in_blank", "hints": [], "items": null, "order": 1, "content": "During the architecture review, Lena asks Marcus how marketing initiatives are aligned across channels. He explains they use a framework called the ''4Ps'' — which stand for Product, Price, Place, and ________.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More: Marketing Mix (4Ps)", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["Promotion"], "feedbackCorrect": "Correct. The four Ps of Marketing Mix are Product, Price, Place, and Promotion — a foundational framework for aligning marketing efforts.", "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": "Incorrect. Think about how companies communicate value to customers — advertising, campaigns, influencer outreach. That’s the missing P: Promotion."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B2_003", "content": "Start from where the user interacts, then follow the logic processing and data storage path. NetWeaver acts as the bridge between external systems and the core ERP.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B2_001", "content": "CRM System sends updated customer record"}, {"itemId": "ITEM_B2_002", "content": "NetWeaver Integration Broker receives and routes the message"}, {"itemId": "ITEM_B2_003", "content": "Presentation Layer displays the updated data to the user"}, {"itemId": "ITEM_B2_004", "content": "Application Layer processes the data and executes business logic"}, {"itemId": "ITEM_B2_005", "content": "Database Layer stores the updated customer record"}], "order": 3, "content": "Lena reviews the SAP architecture diagram and wants to reconstruct how a change in customer data propagates through the system. Arrange the layers and components in the correct order of data flow when a CRM update triggers an ERP process via NetWeaver.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_004", "ITEM_B2_005", "ITEM_B2_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You’ve accurately traced the data flow: CRM → NetWeaver → Application Layer → Database → Presentation. This shows how integration platforms mediate cross-system communication.", "relatedKnowledge": ["CONC_008", "CONC_005"], "feedbackIncorrect": "Remember: data enters via integration (NetWeaver), is processed in the application layer, stored in the database, and only then displayed. The presentation layer is last."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_004", "content": "Think about what makes ERP different from standalone systems — it eliminates data silos by using one shared repository.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Lena studies the SAP three-tier architecture and realizes that despite having separate servers, all business functions are coordinated through a single source of truth. She concludes: ''The ERP system’s greatest value lies in maintaining a ________ database that ensures consistency across finance, HR, and logistics.''", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["unified", "centralized", "integrated", "single", "shared"], "feedbackCorrect": "Correct. The unified database is the cornerstone of ERP, ensuring data consistency and eliminating redundancy across departments.", "relatedKnowledge": ["CONC_007", "CONC_005"], "feedbackIncorrect": "The key idea is that ERP integrates functions into one coherent system. The missing word describes a single, shared data source."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_001", "content": "Think about where calculations, validations, and program execution happen — not where data is stored or displayed.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Lena examines the SAP landscape diagram Marcus provided. She notices three distinct layers handling different responsibilities. To isolate where the ZLOG_FAIL error could have originated, she needs to identify which layer executes ABAP programs like this report. Which layer is responsible for processing business logic and running ABAP code?", "options": [{"content": "Presentation Layer", "feedback": "Incorrect. The Presentation Layer handles user interface interactions, such as displaying forms and capturing inputs via SAP GUI or Fiori. It does not execute ABAP logic.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Application Layer", "feedback": "Correct. The Application Layer runs ABAP programs, processes business logic, and coordinates requests between the user interface and database. This is where ZLOG_FAIL would be executed.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "Database Layer", "feedback": "Incorrect. While the Database Layer stores both business data and program source code, it does not execute ABAP reports. Execution happens in the Application Layer.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 4, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Well deduced. The Application Layer is central to ABAP processing and must be scrutinized for logic flaws.", "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": "Review the roles of each tier: presentation for UI, application for logic, database for storage."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Tanya admits she reused an old ABAP macro (ZMACRO_LEGACY) in the ZLOG_FAIL report without testing its impact on current data structures. She did this under tight deadlines. Which level of decision-making does this reflect?", "options": [{"content": "Strategic Decision Making", "feedback": "Incorrect. Strategic decisions define long-term vision. This was a short-term execution choice made under time pressure — not a top-level directive.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Tactical Decision Making", "feedback": "Incorrect. Tactical decisions involve medium-term planning across teams. This was a direct, immediate coding action — more granular than tactical.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Operational Decision Making", "feedback": "Correct. This was a short-term, execution-focused choice made during development — a textbook example of operational decision making.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: Operational Decisions", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_B1_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_018", "CONC_010"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B3_002", "content": "This transaction code starts with ''SE'' and is one of the most frequently used tools in ABAP development.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Tanya shows Lena the ABAP source for ZLOG_FAIL. Lena asks which transaction code developers typically use to write and edit such reports. What is the correct T-code for accessing the ABAP Editor?", "options": [{"content": "SE11", "feedback": "Incorrect. SE11 is used for ABAP Dictionary maintenance, not editing reports.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "SE16N", "feedback": "Incorrect. SE16N allows viewing table data directly but does not support code editing.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "SE38", "feedback": "Correct. SE38 is the standard transaction code for the ABAP Editor, where developers create and modify reports like ZLOG_FAIL.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_011"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_011", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Exactly right. SE38 is the gateway to ABAP development and critical for investigating code-level issues.", "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": "Remember: SE38 = Editor, SE11 = Dictionary, SE16N = Data Browser."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B4_003", "content": "This statement declares a single-value input field on the selection screen.", "unlockAfterAttempts": 1}], "items": null, "order": 3, "content": "While reviewing the ABAP code for ZLOG_FAIL, Lena spots the user input section. She knows that selection screens are built using specific ABAP keywords. Fill in the blank: To allow users to enter a single value like SALES_NO, developers use the keyword ________.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_015"}, "difficulty": 4, "questionId": "Q_B4_003", "knowledgeId": "CONC_015", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["PARAMETERS", "parameters"], "feedbackCorrect": "Correct! PARAMETERS is used to define single-value input fields on an ABAP selection screen, such as document numbers or flags.", "relatedKnowledge": ["CONC_016"], "feedbackIncorrect": "Incorrect. The correct answer is PARAMETERS. SELECT-OPTIONS is used for ranges, while PARAMETERS handles individual inputs."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_001", "content": "This code block isn''t executed—it''s copied into place during compilation.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Tanya shows you her ABAP program Z_DAILY_PROFIT. You notice it uses a DEFINE statement to standardize calls to calculate meal profits. What is the key technical characteristic of this approach?", "options": [{"content": "It creates a reusable function module accessible system-wide.", "feedback": "Incorrect. Function modules are created in SE37 and called at runtime. This is a macro—expanded at compile time, not a standalone callable unit.", "optionId": "OPT_B5_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It defines a subroutine that can be called multiple times within the program.", "feedback": "No. Subroutines (FORM/ENDFORM) are runtime-callable blocks. Macros are textually substituted during compilation and do not support RETURN or local stacks.", "optionId": "OPT_B5_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It performs compile-time code expansion with no parameter type checking.", "feedback": "Correct. ABAP macros are expanded during compilation, replacing the macro call with its body. They lack type safety, making them risky for complex logic.", "optionId": "OPT_B5_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B5_001"]}, {"content": "It enables object-oriented inheritance through method overriding.", "feedback": "No. ABAP macros are procedural constructs and unrelated to classes or inheritance.", "optionId": "OPT_B5_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More: ABAP Macro", "knowledgeId": "CONC_018"}, "difficulty": 3, "questionId": "Q_B5_001", "knowledgeId": "CONC_018", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_017"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B1_001", "content": "Ask yourself: Did this decision shape long-term direction and involve executive-level consequences? If yes, it''s strategic.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Lena reviews the integration logs and finds that Marcus delayed implementing a new automated validation system after the CRM update. Instead, he kept manual checks in place to maintain control over data flow. What level of decision-making does this represent?", "options": [{"content": "Strategic Decision Making", "feedback": "Correct. This was a long-term, top-level choice affecting platform strategy and resource allocation — classic strategic decision making.", "optionId": "OPT_B1_001", "showHint": "HINT_B1_001", "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "Tactical Decision Making", "feedback": "Incorrect. While it involves planning, this wasn’t about mid-term execution trade-offs. It was a high-level choice to resist change for organizational control — a strategic move.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Operational Decision Making", "feedback": "Incorrect. Operational decisions are day-to-day executions. This was a deliberate, long-term shift in integration policy — far beyond routine operations.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More: Strategic Decisions", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_005"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_001", "content": "Think about what kind of data CRM specializes in managing — it''s focused on interactions and profiles, not transactions or inventory.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Lena examines the CRM integration logs and notices repeated mismatches in customer identifiers during data sync. She suspects the CRM system is not properly aligned with the ERP’s master data model. Which of the following BEST describes the primary purpose of a CRM system in this context?", "options": [{"content": "To manage financial reporting and compliance across departments", "feedback": "Incorrect. While CRM data can influence financial outcomes, financial reporting is handled by ERP modules like FI. CRM focuses on customer engagement, not accounting.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To centralize customer data for segmentation, personalization, and retention strategies", "feedback": "Correct. CRM systems are designed to collect and analyze customer data across touchpoints to improve relationships and drive revenue through targeted engagement.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "To automate warehouse inventory updates based on sales orders", "feedback": "Incorrect. Inventory management is part of SCM or MM modules in ERP, not CRM. CRM does not handle physical logistics.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To provide real-time analytics for server performance and uptime monitoring", "feedback": "Incorrect. System performance monitoring falls under technical operations or ITIL frameworks, not CRM functionality.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You''ve identified the core role of CRM: managing customer relationships through data-driven personalization and retention.", "relatedKnowledge": ["CONC_006", "CONC_008"], "feedbackIncorrect": "Review how CRM supports customer-centric strategies versus operational systems like ERP or SCM."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B2_002", "content": "Recall that DSS doesn''t make decisions but helps analyze complex scenarios where outcomes are uncertain.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Marcus explains that a Decision Support System (DSS) was used to evaluate the risks of changing the CRM integration method. However, the final decision ignored the DSS recommendation. At which level of decision-making does a DSS primarily support, and why?", "options": [{"content": "Operational — because it automates daily tasks like data entry and report generation", "feedback": "Incorrect. Operational decisions are routine and often automated; DSS is not used for automation but for analysis.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Strategic — because it provides long-term forecasts for market expansion and investment", "feedback": "Incorrect. While DSS can inform strategic decisions, its main strength is in tactical, semi-structured decisions involving trade-offs and modeling.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Tactical — because it enables interactive ''what-if'' analysis for mid-level managers facing semi-structured problems", "feedback": "Correct. DSS supports tactical decision-makers by modeling data and simulating outcomes, especially when decisions involve uncertainty and partial structure.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "Executive — because it replaces human judgment with algorithmic recommendations", "feedback": "Incorrect. DSS augments human judgment; it does not replace it. It supports, not supersedes, executive discretion.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "You’ve correctly identified that DSS supports tactical decision-making by enabling evidence-based analysis of complex, semi-structured problems.", "relatedKnowledge": ["CONC_007", "CONC_005"], "feedbackIncorrect": "Remember, DSS is not about automation or replacing leaders — it’s about supporting informed choices under uncertainty."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B3_003", "content": "This term refers to a rule that ensures every record in a child table corresponds to a valid record in a parent table.", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "Marcus explains that while CRM updates flowed into SAP, a misaligned field allowed bad data into ZLOG_FAIL. Lena realizes this wouldn’t have been possible if a proper ________ constraint had been enforced between the customer and shipment records.", "options": null, "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_012"}, "difficulty": 4, "questionId": "Q_B3_004", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["foreign key", "foreign-key", "referential integrity"], "feedbackCorrect": "Excellent insight. A missing foreign key constraint allowed orphaned or invalid entries to corrupt the dataset.", "relatedKnowledge": ["CONC_009", "CONC_010"], "feedbackIncorrect": "Consider what mechanism links two tables and prevents mismatched references — it starts with ''F'' and ends with ''key''."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B5_002", "content": "Think about consistency, testing, and error handling across programs.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Marcus pulls up transaction SE37 and shows you Z_FM_MEAL_PROFIT. He explains it''s used across several reports. Why is this design superior to embedding the logic directly in each report?", "options": [{"content": "Because it runs faster than inline code due to caching.", "feedback": "Not quite. While efficient, the main advantage isn’t speed—it’s about modular design, reusability, and centralized maintenance.", "optionId": "OPT_B5_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because it allows compile-time code duplication across programs.", "feedback": "No. That describes macros. Function modules are called at runtime and avoid code duplication by centralizing logic.", "optionId": "OPT_B5_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Because it provides a reusable interface with exception handling and consistent behavior.", "feedback": "Correct. Function modules encapsulate logic behind a defined interface (IMPORTING, EXPORTING), support exceptions like INPUT_ERROR, and ensure consistent results wherever they’re called.", "optionId": "OPT_B5_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B5_002"]}, {"content": "Because it stores data between calls like a global variable.", "feedback": "Incorrect. Function modules are stateless—they don’t retain data between calls, which makes them safe for concurrent use.", "optionId": "OPT_B5_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_004", "learnMore": {"buttonText": "Learn More: ABAP Function Module", "knowledgeId": "CONC_017"}, "difficulty": 4, "questionId": "Q_B5_002", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_018"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Marcus chooses to delay full CRM-SAP schema alignment, opting for partial field mapping to meet quarterly goals."}, {"itemId": "ITEM_B1_002", "content": "Leadership decides to expand market reach by integrating external CRM platforms with SAP ERP."}, {"itemId": "ITEM_B1_003", "content": "Tanya reuses an outdated macro in ZLOG_FAIL, bypassing validation checks due to time constraints."}], "order": 1, "content": "Lena reconstructs the chain of decisions that led to the corrupted report. Arrange the following events in chronological and logical order — from strategic foundation to operational consequence.", "options": null, "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More: Tactical Decisions", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": ["ITEM_B1_002", "ITEM_B1_001", "ITEM_B1_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence starts with a strategic expansion decision, followed by a tactical compromise in integration, and ends with an operational coding shortcut that triggered the failure.", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"], "feedbackIncorrect": "Incorrect. Remember: Strategic decisions set the direction, tactical decisions implement them under constraints, and operational decisions execute the daily tasks. The root cause began at the top."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Define fields and assign data types based on business requirements"}, {"itemId": "ITEM_B3_002", "content": "Mark the appropriate field(s) as the primary key to ensure uniqueness"}, {"itemId": "ITEM_B3_003", "content": "Activate the table to make it available in the database"}, {"itemId": "ITEM_B3_004", "content": "Set up foreign key relationships to enforce referential integrity"}], "order": 3, "content": "Lena guides Tanya through verifying data integrity in the ABAP Dictionary. They need to reconstruct the logical sequence of steps taken when defining a new database table with proper primary keys and constraints. Arrange these actions in the correct order:", "options": null, "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_012"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_012", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_004", "ITEM_B3_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. Defining structure, setting PK, linking FKs, then activation ensures robust table design.", "relatedKnowledge": ["CONC_010", "CONC_011"], "feedbackIncorrect": "Primary keys must be set before foreign key relationships can be established. Activation comes last after all definitions are complete."}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_001", "content": "This concept ensures that every sales record points to an actual product in the catalog.", "unlockAfterAttempts": 1}], "items": null, "order": 1, "content": "Lena examines the relationship between ZSALES and ZPRODUCT. She notices that PROD_SN exists in both tables, but there''s no system-enforced link. Which concept explains how this missing rule allowed invalid entries to corrupt the report?", "options": [{"content": "Primary Key", "feedback": "A primary key uniquely identifies a record within its own table, but doesn''t enforce cross-table relationships. Think about what links one table to another.", "optionId": "OPT_B4_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Foreign Key", "feedback": "Correct! A foreign key enforces referential integrity by ensuring values in one table match those in another. Its absence allowed invalid PROD_SN entries to go undetected.", "optionId": "OPT_B4_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B4_001"]}, {"content": "Index", "feedback": "An index improves query performance but does not enforce data validity or relationships between tables.", "optionId": "OPT_B4_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Data Class", "feedback": "Data class categorizes tables for storage optimization, but doesn’t control relational integrity.", "optionId": "OPT_B4_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_013"}, "difficulty": 3, "questionId": "Q_B4_001", "knowledgeId": "CONC_013", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_014", "CONC_016"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [{"hintId": "HINT_B4_002", "content": "Master tables contain reference data that changes infrequently, like product details or customer info.", "unlockAfterAttempts": 1}], "items": null, "order": 2, "content": "Tanya reviews ZPRODUCT and ZSALES in the data dictionary. Lena asks her: ''Which of these is a master table, and why?'' What should Tanya conclude based on data volatility and usage?", "options": [{"content": "ZSALES is a master table because it contains sales records used across departments.", "feedback": "Incorrect. While widely used, ZSALES contains frequently changing transactional data, which is characteristic of a transaction table, not a master one.", "optionId": "OPT_B4_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "ZPRODUCT is a master table because its content (e.g., prices) changes rarely and serves as reference data.", "feedback": "Exactly right. Master tables store stable, shared reference data. ZPRODUCT fits this role perfectly, supporting consistent reporting and pricing logic.", "optionId": "OPT_B4_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B4_002"]}, {"content": "Both are transaction tables because they involve business operations.", "feedback": "No. Only ZSALES qualifies as transactional due to frequent updates. ZPRODUCT holds foundational data that supports transactions but isn’t itself event-driven.", "optionId": "OPT_B4_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Neither is a master table since both are part of the same module.", "feedback": "All modules use both types. The classification depends on data behavior, not module affiliation.", "optionId": "OPT_B4_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_014"}, "difficulty": 3, "questionId": "Q_B4_002", "knowledgeId": "CONC_014", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_013", "CONC_016"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B5_003", "content": "Start by preparing inputs, then invoke the function, and finally check the result.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B5_001", "content": "Set importing parameters: SellingPrice = lv_price, Costs = lv_cost, NumberOfMealsSold = lv_qty"}, {"itemId": "ITEM_B5_002", "content": "CALL FUNCTION ''Z_FM_MEAL_PROFIT''"}, {"itemId": "ITEM_B5_003", "content": "Check SY-SUBRC value after the call"}, {"itemId": "ITEM_B5_004", "content": "Define local variables to hold input and output values"}, {"itemId": "ITEM_B5_005", "content": "If SY-SUBRC = 0, retrieve MealProfit and add to total; else display ''Input invalid''"}], "order": 3, "content": "Lena wants to demonstrate best practices for integrating Z_FM_MEAL_PROFIT into a new report. Arrange the correct sequence of steps to safely call the function module and handle errors.", "options": null, "sceneId": "SCENE_005", "learnMore": {"buttonText": "Learn More: ABAP Function Module", "knowledgeId": "CONC_017"}, "difficulty": 4, "questionId": "Q_B5_003", "knowledgeId": "CONC_017", "maxAttempts": 3, "correctOrder": ["ITEM_B5_004", "ITEM_B5_001", "ITEM_B5_002", "ITEM_B5_003", "ITEM_B5_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Well done. You''ve followed the proper ABAP pattern: prepare data, call function, check return code, and respond appropriately.", "relatedKnowledge": ["CONC_018"], "feedbackIncorrect": "Review the flow: always declare variables first, set inputs, call the function, then inspect SY-SUBRC to determine success or failure."}, {"type": "sequencing", "hints": [{"hintId": "HINT_B4_004", "content": "Start with user interaction, then move to data retrieval, joining, and finally display.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B4_001", "content": "User enters SALES_NO and date range on selection screen"}, {"itemId": "ITEM_B4_002", "content": "ABAP program reads input parameters from selection screen"}, {"itemId": "ITEM_B4_003", "content": "SELECT statement joins ZSALES and ZPRODUCT on PROD_SN"}, {"itemId": "ITEM_B4_004", "content": "Report computes Amount = SAL_QTY × PROD_PRICE for each matching record"}, {"itemId": "ITEM_B4_005", "content": "Formatted output is displayed showing enriched sales data"}], "order": 4, "content": "Lena prepares to explain how the corrupted report executes. Arrange the steps of the ABAP report ZLOG_FAIL in the correct order of processing to show how data flows from user input to final output.", "options": null, "sceneId": "SCENE_006", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_016"}, "difficulty": 4, "questionId": "Q_B4_004", "knowledgeId": "CONC_016", "maxAttempts": 3, "correctOrder": ["ITEM_B4_001", "ITEM_B4_002", "ITEM_B4_003", "ITEM_B4_004", "ITEM_B4_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Perfect. You''ve reconstructed the full data flow: input → parameter read → JOIN → calculation → output. This shows how integrated reporting relies on accurate underlying structures.", "relatedKnowledge": ["CONC_015", "CONC_013"], "feedbackIncorrect": "Not quite. The process starts with user input, followed by parameter reading, then the JOIN operation, computation of derived values, and finally display. Each step builds on the previous one."}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B5_004", "content": "When does the ABAP preprocessor run?", "unlockAfterAttempts": 1}], "items": null, "order": 4, "content": "In the final briefing, Lena points out that the macro in Z_DAILY_PROFIT used DEFINE and was expanded at ________ time, not runtime—this meant errors weren''t caught until execution.", "options": null, "sceneId": "SCENE_006", "learnMore": {"buttonText": "Learn More: ABAP Macro", "knowledgeId": "CONC_018"}, "difficulty": 3, "questionId": "Q_B5_004", "knowledgeId": "CONC_018", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["compile", "compilation"], "feedbackCorrect": "Exactly. Macros are processed during compilation—the source code is literally replaced before the program runs, so there''s no runtime overhead but also no dynamic checks.", "relatedKnowledge": ["CONC_017"], "feedbackIncorrect": "Think about when the macro text is inserted into the code. It happens before the program executes, during the build phase."}], "characters": [{"age": 38, "goal": "Identify the source of the corrupted ABAP report and restore system integrity.", "name": "Dr. Lena Richter", "role": "Detective/Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003", "SCENE_004", "SCENE_005", "SCENE_006"], "secret": "She once reported a colleague for code tampering, which ended their career. Fears being seen as ruthless.", "background": "A former SAP consultant turned internal systems auditor, Lena was brought in to evaluate system stability after repeated outages. She has an analytical mind and deep expertise in ABAP and system design.", "occupation": "Lead SAP Architect", "characterId": "CHAR_001", "personality": "Calm, methodical, and highly observant. Prefers logic over emotion but respects team input.", "knowledgePoints": ["CONC_009", "CONC_010", "CONC_015", "CONC_016", "CONC_017", "CONC_018"]}, {"age": 45, "goal": "Protect his position by ensuring old integration methods remain essential.", "name": "Marcus Bell", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_004", "SCENE_006"], "secret": "He secretly disabled a new automation feature because it threatened his department''s relevance.", "background": "Longtime employee responsible for connecting SAP modules with external CRM and marketing platforms. Known for his strategic thinking but resents newer developers bypassing legacy protocols.", "occupation": "Senior ERP Integration Specialist", "characterId": "CHAR_002", "personality": "Authoritative, traditional, slightly defensive when challenged.", "knowledgePoints": ["CONC_001", "CONC_006", "CONC_007", "CONC_008", "CONC_005", "CONC_004"]}, {"age": 31, "goal": "Avoid blame while helping fix the issue she unknowingly contributed to.", "name": "Tanya Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_003", "SCENE_005", "SCENE_006"], "secret": "She reused a macro from an outdated project without proper testing, causing hidden data corruption.", "background": "A recent hire with strong coding skills but limited experience in enterprise-scale debugging. She wrote the original version of the failed ABAP report under pressure.", "occupation": "Junior ABAP Developer", "characterId": "CHAR_003", "personality": "Eager, nervous, detail-oriented. Wants to prove herself but fears making mistakes.", "knowledgePoints": ["CONC_011", "CONC_012", "CONC_013", "CONC_014", "CONC_018", "CONC_010"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Strategic Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_002", "SCENE_006"], "difficulty": 2, "description": "High-level decisions that shape long-term organizational direction, often made by executives or senior managers.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_006"]}, {"name": "Tactical Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_004", "SCENE_006"], "difficulty": 2, "description": "Mid-level decisions focused on implementing strategy, typically handled by department leads or specialists.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Operational Decision Making", "category": "Decision Making", "appearsIn": ["SCENE_003", "SCENE_005"], "difficulty": 1, "description": "Day-to-day decisions involving execution of tasks, usually performed by frontline staff or developers.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_002", "CONC_014"]}, {"name": "Marketing Mix (4Ps)", "category": "Marketing", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "Product, Price, Place, Promotion—the foundational elements of marketing strategy influencing CRM integration.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Customer Relationship Management (CRM)", "category": "Business Systems", "appearsIn": ["SCENE_002", "SCENE_004"], "difficulty": 2, "description": "Systems and strategies used to manage interactions with customers, often integrated into ERP platforms like SAP.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_004", "CONC_008"]}, {"name": "Decision Support System (DSS)", "category": "IT Systems", "appearsIn": ["SCENE_004"], "difficulty": 2, "description": "Information systems that support business decisions at tactical and strategic levels using data analysis tools.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "SAP NetWeaver", "category": "SAP Infrastructure", "appearsIn": ["SCENE_002", "SCENE_004"], "difficulty": 2, "description": "Integrated technology platform that enables application integration and data exchange across SAP and non-SAP systems.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_008", "CONC_009"]}, {"name": "ERP System", "category": "Business Systems", "appearsIn": ["SCENE_002", "SCENE_004"], "difficulty": 1, "description": "Enterprise Resource Planning systems integrate core business processes such as finance, HR, and logistics into a unified platform.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_005", "CONC_007"]}, {"name": "SAP Three-Tier Architecture", "category": "SAP Infrastructure", "appearsIn": ["SCENE_002", "SCENE_004"], "difficulty": 2, "description": "Presentation, Application, and Database layers that separate user interface, processing logic, and data storage in SAP systems.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_007", "CONC_011"]}, {"name": "ABAP Programming Language", "category": "Programming", "appearsIn": ["SCENE_003", "SCENE_005"], "difficulty": 1, "description": "Advanced Business Application Programming language used for developing applications within the SAP environment.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_015", "CONC_018"]}, {"name": "SAP Transaction Codes", "category": "Navigation", "appearsIn": ["SCENE_003"], "difficulty": 1, "description": "Short alphanumeric commands used to navigate directly to specific functions or reports in SAP GUI.", "knowledgeId": "CONC_011", "relatedKnowledge": ["CONC_009", "CONC_015"]}, {"name": "Primary Key", "category": "Data Modeling", "appearsIn": ["SCENE_005"], "difficulty": 1, "description": "A unique identifier for a record in a database table, ensuring no duplicate entries exist.", "knowledgeId": "CONC_012", "relatedKnowledge": ["CONC_013", "CONC_014"]}, {"name": "Foreign Key", "category": "Data Modeling", "appearsIn": ["SCENE_005"], "difficulty": 2, "description": "A field in one table that links to the primary key in another, enforcing referential integrity between related tables.", "knowledgeId": "CONC_013", "relatedKnowledge": ["CONC_012", "CONC_014"]}, {"name": "Master vs Transaction Table", "category": "Data Modeling", "appearsIn": ["SCENE_003", "SCENE_005"], "difficulty": 2, "description": "Master tables store static, long-term data (e.g., customers), while transaction tables record dynamic events (e.g., orders).", "knowledgeId": "CONC_014", "relatedKnowledge": ["CONC_012", "CONC_013"]}, {"name": "ABAP Selection Screen", "category": "Programming", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "User interface element in ABAP reports that allows users to input parameters before executing a query.", "knowledgeId": "CONC_015", "relatedKnowledge": ["CONC_010", "CONC_011"]}, {"name": "ABAP Report with JOIN", "category": "Programming", "appearsIn": ["SCENE_003", "SCENE_005"], "difficulty": 3, "description": "An ABAP program that combines data from multiple tables using SQL JOIN operations to produce comprehensive output.", "knowledgeId": "CONC_016", "relatedKnowledge": ["CONC_014", "CONC_013"]}, {"name": "ABAP Function Module", "category": "Programming", "appearsIn": ["SCENE_004"], "difficulty": 3, "description": "Reusable procedural unit in ABAP that performs a specific task and can be called from other programs.", "knowledgeId": "CONC_017", "relatedKnowledge": ["CONC_010", "CONC_018"]}, {"name": "ABAP Macro", "category": "Programming", "appearsIn": ["SCENE_003", "SCENE_006"], "difficulty": 3, "description": "A code substitution tool in ABAP that inserts predefined lines during compilation; not checked for correctness until runtime.", "knowledgeId": "CONC_018", "relatedKnowledge": ["CONC_010", "CONC_017"]}], "educational_goals": ["Understand the components and layers of SAP Three-Tier Architecture", "Differentiate between master and transaction tables in SAP systems", "Apply core ABAP programming concepts including selection screens, JOINs, function modules, and macros", "Navigate SAP using transaction codes and understand ERP integration via SAP NetWeaver", "Recognize the role of primary and foreign keys in data integrity"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '6c750947a6d95e5cd1cdd30210d996f8dd9ee0b01d90006409e1dca1e542e6ec', 'SAP Architecture & ABAP Fundamentals', '2026-04-13 12:21:46.850488', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('729a393c-6d12-47f5-8999-8744b2eb9f41', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '523be50a-a3b5-4361-b4bc-f77e1a24dcdb', NULL, 'The Case of the Broken Microservice', 'active', 'easy', 'standard', '{"clues": [{"name": "RestTemplate Configuration Snippet", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Evidence that RestTemplate was intentionally configured in the system, possibly as part of legacy architecture maintenance.", "description": "A fragment of Java configuration code found in version control history showing the setup of a RestTemplate bean with @Bean annotation. Timestamp suggests it was last modified just before the crash.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Autowired Field in PaymentService", "type": "code_trace", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Indicates dependency injection via field injection, which can lead to tight coupling and harder testing—consistent with outdated practices.", "description": "Log trace from decompiled bytecode reveals an @Autowired RestTemplate field inside the Core Payment Service class. No constructor injection used—suggests older Spring pattern usage.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Post Entity Class Definition", "type": "source_file", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Confirms the use of standard data carrier objects in inter-service communication, likely deserialized by RestTemplate from JSON responses.", "description": "Java file defining a ''Post'' class with private fields, getters, setters, and no-arg constructor—classic example of a Java Bean used for REST data transfer.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004"]}, {"name": "Sequence Diagram: HTTP Call Flow", "type": "diagram", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Visual confirmation of how synchronous HTTP calls are structured using RestTemplate within the application layer stack.", "description": "Whiteboard sketch recovered from Development War Room showing step-by-step flow: Controller → Service → @Autowired RestTemplate → External API → Java Bean mapping.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_004"]}, {"name": "Fragmented JSON Log Entry", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "The system failed to deserialize an incoming JSON payload, suggesting a misconfigured or missing HTTP message converter.", "description": "A corrupted log snippet shows a failed HTTP response with raw JSON: {\"error\":\"Failed to parse\",\"rawPayload\":\"{\\\"userId\\\":5,\\\"title\\\":\\\"Update Docs\\\",\\\"body\\\":\\\"Final draft ready\\\"}\"}. No Java object was instantiated on receipt.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Service Call Map Diagram", "type": "diagram", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "A direct HTTP call bypasses service discovery, making the system fragile to instance changes and network shifts.", "description": "A whiteboard sketch in the Development War Room shows service dependencies. One arrow from ''Order Service'' to ''Inventory Service'' is labeled ''http://10.4.3.15:8080/check-stock''—a hardcoded IP instead of a logical service name.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Resilience Configuration Gap", "type": "configuration", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Client-side resiliency mechanisms were intentionally disabled, increasing vulnerability to cascading failures.", "description": "Git diff output reveals that retry logic and circuit breaker annotations were commented out in WebClientConfig.java during a late-night commit. The comment reads: ''// Temp disable for performance testing - J.P.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "WebClient vs RestTemplate Migration Plan", "type": "document", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "The transition to modern communication practices was incomplete, leaving critical services exposed to failure.", "description": "An internal memo outlines a phased migration from RestTemplate to WebClient. Step 3 states: ''Ensure all services use Eureka for discovery before decommissioning direct URLs.'' This step was skipped in the Payment Service.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_006", "CONC_007"]}, {"name": "WebClient Configuration Snippet", "type": "digital", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Evidence of unauthorized use of WebClient without resiliency or registry integration.", "description": "A fragment of Java code recovered from Jasmine Park''s workstation showing a manually configured WebClient instance that bypasses Eureka service discovery and lacks fallback mechanisms.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "HTTP Response Metadata Log", "type": "log", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Lack of proper error handling using full HTTP response metadata, indicating possible misuse of basic getForObject() instead of getForEntity().", "description": "Server access logs show a series of failed inter-service calls with status codes 503 (Service Unavailable) but no retry attempts. The response headers were never inspected for retry-after directives.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_010"]}, {"name": "Architectural Decision Record Draft", "type": "document", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Motivation to resist modernization efforts, suggesting potential sabotage through opposition to WebClient adoption.", "description": "An unsent email draft from Dr. Reed criticizing the adoption of reactive clients, stating ''WebClient undermines system visibility and control flow''. He advocates for maintaining RestTemplate across all services.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Failed Circuit Breaker Initialization", "type": "configuration", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Missed opportunity to apply resiliency to WebClient usage, contributing to cascade failure.", "description": "A commented-out block in the cloud gateway configuration reveals an attempted integration of resilience patterns with WebClient, later removed due to ''incompatibility concerns''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009", "CONC_010"]}], "title": "The Case of the Broken Microservice", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Site", "sceneId": "SCENE_001", "location": "Server Room B - Central Operations Hub", "description": "Lights flicker as alarms blare. Dr. Reed is found unconscious beside a server rack labeled ''Core Payment Service''. Logs show a sudden cascade failure. Detective Lin arrives to investigate the technical cause and potential foul play.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Audit Under Pressure", "sceneId": "SCENE_002", "location": "Development War Room", "description": "Lin reviews recent commits with both suspects present. Tension rises as conflicting philosophies emerge: legacy sync vs. modern async communication. A hidden configuration file suggests unauthorized changes to service-to-service calls.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Configuration Reveal", "sceneId": "SCENE_003", "location": "Executive Briefing Room", "description": "Lin presents evidence showing a misconfigured WebClient instance that ignored service discovery and lacked resiliency fallbacks. One suspect breaks under scrutiny. The true cause—a mix of sabotage and negligence—is exposed.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Exposed: The Perils of Ignoring Resiliency", "content": "Jasmine Park’s eagerness to modernize led her to deploy a WebClient configuration that bypassed service discovery and omitted resiliency safeguards. When the payment service moved, her client failed silently—triggering the cascade. Dr. Reed’s condition was stress-induced, not fatal. Jasmine admits fault but argues innovation requires risk.", "debrief": "While WebClient is powerful, skipping service discovery and resiliency patterns can destabilize entire systems. Proper use of @Bean, service discovery, and fallback mechanisms is essential.", "summary": "Modernization must balance innovation with stability. Understanding enterprise concepts prevents catastrophic failures.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: Legacy Code Scapegoat", "content": "Detective Lin blames Dr. Reed’s RestTemplate usage as outdated and dangerous. However, logs confirm his implementation was stable. The real flaw—Jasmine’s WebClient bypass—remains hidden. The system crashes again days later.", "debrief": "Legacy tools like RestTemplate are not inherently flawed. Misuse of modern tools like WebClient without proper patterns causes greater harm.", "summary": "Blaming technology instead of practice leads to repeated failures. Context matters in system design.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes tech office, a critical service failure leads to the mysterious collapse of the lead architect. Detective Lin must uncover which enterprise system concept was misused—and who sabotaged the codebase.", "version": "1.0", "evidence": [{"name": "Corrupted RestTemplate Config", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A configuration file showing RestTemplate being manually instantiated without proper HTTP message converters.", "foundLocation": "Server Room B", "relatedKnowledge": ["CONC_001", "CONC_005"]}, {"name": "Unauthorized WebClient Bean Definition", "type": "Digital", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A Spring @Bean definition creating a WebClient instance that skips service discovery and lacks timeout settings.", "foundLocation": "Development War Room", "relatedKnowledge": ["CONC_009", "CONC_003", "CONC_007"]}, {"name": "Missing Resilience Annotations", "type": "Code Annotation", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "Critical service calls lack @Retryable or @CircuitBreaker annotations despite network instability warnings.", "foundLocation": "Executive Briefing Room", "relatedKnowledge": ["CONC_008", "CONC_006"]}], "has_quiz": false, "scriptId": "ESD_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the crashed Core Payment Service and finds a field annotated with @Autowired RestTemplate. What is the primary purpose of the @Autowired annotation here?", "options": [{"content": "To define a new instance of RestTemplate directly in the class.", "feedback": "Incorrect. @Autowired does not create instances—it injects existing beans managed by Spring. The actual creation happens elsewhere, typically via @Bean or component scanning.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To automatically inject a pre-configured RestTemplate bean from the Spring container.", "feedback": "Correct. @Autowired enables Spring to resolve and inject the appropriate RestTemplate bean, promoting loose coupling and easier testing.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "To serialize Java objects into JSON when making HTTP requests.", "feedback": "Incorrect. That role belongs to message converters like MappingJackson2HttpMessageConverter. @Autowired handles dependency injection, not data transformation.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To enable asynchronous communication between microservices.", "feedback": "Incorrect. RestTemplate is inherently synchronous. Asynchronous behavior requires WebClient or other reactive tools.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Among the wreckage of logs, Detective Lin spots a class named ''Post'' with private fields, public getters/setters, and a no-argument constructor. What kind of object is this most likely intended to be?", "options": [{"content": "A Spring configuration class used to set up beans.", "feedback": "Incorrect. Configuration classes are marked with @Configuration and contain @Bean methods. This class follows Java Bean conventions for data transport.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A utility class with static helper methods.", "feedback": "Incorrect. There''s no indication of static methods. The structure matches a data-holding object, not a utility.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A Java Bean designed to carry data from REST API responses.", "feedback": "Correct. The Post class adheres to Java Bean conventions—private fields, getters/setters, no-arg constructor—making it ideal for mapping JSON responses via RestTemplate.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "An exception handler for HTTP errors.", "feedback": "Incorrect. Exception handlers usually extend ResponseEntityExceptionHandler or use @ControllerAdvice. This is clearly a data model class.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "Detective Lin identifies that the failing service used a synchronous HTTP client for inter-service communication. What is the name of this Spring Framework component? (Hint: Two words, commonly used in legacy systems)", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["RestTemplate", "rest template"], "feedbackCorrect": "Correct. RestTemplate is the legacy synchronous HTTP client in Spring, widely used before the adoption of WebClient for reactive programming.", "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": "Incorrect. Consider the clues: it''s a Spring component, used synchronously, and often paired with @Autowired. The answer is RestTemplate."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the server logs and finds a recurring error: ''Could not read JSON: no suitable constructor found''. The payload is valid JSON but fails to map to a Java object. What core mechanism is likely misconfigured or absent?", "options": [{"content": "HTTP Message Converter", "feedback": "Correct. The MappingJackson2HttpMessageConverter is responsible for deserializing JSON into Java objects. If missing or improperly configured, this error occurs even with valid payloads.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "@Autowired Dependency Injection", "feedback": "Incorrect. While @Autowired handles bean injection, it doesn''t manage JSON parsing. That role belongs to HTTP message converters.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Service Discovery Registry", "feedback": "Incorrect. Service discovery resolves service locations but does not handle data serialization. The issue here is object mapping, not network routing.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "WebClient Reactive Stream", "feedback": "Incorrect. WebClient handles asynchronous communication, but the deserialization process still relies on message converters—just like RestTemplate.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_009"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "During autopsy of the crash, Lin identifies that the system failed to convert incoming JSON into Java objects. The key component responsible for this in Spring Boot, which automatically registers converters like MappingJackson2HttpMessageConverter, is the __________.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["HTTP message converter", "message converter"], "feedbackCorrect": "Correct. HTTP message converters handle the serialization and deserialization of request/response bodies. Spring Boot auto-configures them, including support for JSON via Jackson.", "relatedKnowledge": ["CONC_001", "CHUNK_010"], "feedbackIncorrect": "Incorrect. The component responsible for transforming HTTP payloads into Java objects is the HTTP message converter. Examples include MappingJackson2HttpMessageConverter for JSON processing."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin reviews the initial crash logs and notices repeated HTTP 503 errors between payment and inventory services. She suspects poor error handling. Which approach would have allowed the calling service to inspect the HTTP status code and act accordingly?", "options": [{"content": "Using restTemplate.getForObject(url, Post.class) to directly extract the body.", "feedback": "This only retrieves the response body and ignores status codes and headers. It cannot handle 503 errors gracefully.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Using restTemplate.getForEntity(url, Post.class) and checking response.getStatusCode().", "feedback": "Correct. ResponseEntity provides full access to status, headers, and body—essential for conditional logic on failures like 503.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "Using WebClient.create().get().retrieve().bodyToMono(Post.class).", "feedback": "While WebClient is modern, this chain doesn''t handle error inspection explicitly. You''d need additional operators like onStatus() to react to 503s.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Using @Autowired to inject the target service directly.", "feedback": "@Autowired is for dependency injection within Spring context, not for inter-service HTTP communication. This would tightly couple services and break microservice boundaries.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_001", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 5, "content": "To properly handle HTTP status codes and headers when making REST calls, Detective Lin recommends using ResponseEntity instead of just returning the object directly. What method should be used with RestTemplate to obtain a ResponseEntity?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["getForEntity", "postForEntity", "exchange"], "feedbackCorrect": "Correct. Methods like getForEntity(), postForEntity(), or exchange() return a ResponseEntity, giving access to status, headers, and body for robust error handling.", "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": "Incorrect. Remember: getForObject() returns only the body. To access full HTTP response details like status codes, you need getForEntity() or exchange()."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin reviews a configuration file where RestTemplate is defined inside a method marked with @Bean. What is the significance of using @Bean in this context?", "options": [{"content": "It marks the class as a Spring Boot application entry point.", "feedback": "Incorrect. That role belongs to @SpringBootApplication. @Bean defines individual beans within a configuration class.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It tells Spring to manage the object returned by the method as a bean in the application context.", "feedback": "Correct. @Bean indicates that the method returns an object to be registered and managed by Spring, such as a customized RestTemplate instance.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "It automatically generates documentation for the RestTemplate usage.", "feedback": "Incorrect. @Bean has no documentation function. It''s purely for configuration and dependency management.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It enables asynchronous execution of HTTP requests made by RestTemplate.", "feedback": "Incorrect. RestTemplate remains synchronous regardless of how it’s configured. Asynchronicity requires WebClient or CompletableFuture patterns.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "RestTemplate sends an HTTP GET request to the blog service endpoint."}, {"itemId": "ITEM_B1_002", "content": "The external API returns a JSON response containing post data."}, {"itemId": "ITEM_B1_003", "content": "Spring’s MappingJackson2HttpMessageConverter deserializes the JSON into a Post object."}, {"itemId": "ITEM_B1_004", "content": "The controller receives the Post object and processes it."}, {"itemId": "ITEM_B1_005", "content": "@Autowired injects the RestTemplate instance into the service class."}], "order": 4, "content": "Reconstruct the correct sequence of events when the Core Payment Service uses RestTemplate to fetch a Post object from an external blog API.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_005", "ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The process begins with dependency injection, followed by the HTTP call, response receipt, deserialization, and final processing.", "relatedKnowledge": ["CONC_002", "CONC_004"], "feedbackIncorrect": "Incorrect. Remember: injection comes first, then the request flow. Deserialization happens after receiving JSON but before the object is used."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin reviews a recent code change where Dr. Reed insisted on using ''http://10.4.3.15:8080/inventory'' instead of ''inventory-service'' in a service call. Jasmine argues this breaks best practices. What architectural principle is being violated?", "options": [{"content": "Service Discovery", "feedback": "Correct. Using hardcoded IPs violates service discovery principles. Services should use logical names resolved at runtime via registries like Eureka.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "HTTP Message Conversion", "feedback": "Incorrect. Message conversion deals with data format transformation, not how services locate each other on the network.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Client-Side Resiliency", "feedback": "Incorrect. Resiliency focuses on handling failures (retries, fallbacks), not on how services are addressed or discovered.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Synchronous Communication", "feedback": "Incorrect. Synchronous calls are valid; the problem isn''t sync vs async, but the lack of dynamic service resolution.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006", "CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Jasmine defends her decision to disable retry logic in the WebClient configuration, claiming it improved latency. Detective Lin knows this increases risk. Which pattern should be used to maintain reliability without sacrificing user experience during partial outages?", "options": [{"content": "Client-Side Resiliency with Circuit Breaker and Fallback", "feedback": "Correct. Implementing patterns like circuit breakers and fallback responses allows the system to degrade gracefully under stress while maintaining responsiveness.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "Hardcoded Endpoints for Speed", "feedback": "Incorrect. Hardcoding may reduce lookup time slightly but eliminates fault tolerance and scalability—making the system more brittle.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Disabling SSL for Performance", "feedback": "Incorrect. Security should never be compromised for speed. This introduces serious vulnerabilities without meaningful performance gains.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Monolithic Integration", "feedback": "Incorrect. Reverting to monoliths contradicts microservices architecture and doesn’t solve the resiliency issue.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_003", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006", "CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During the code audit, Lin discovers a new WebClient being used in the payment service. Which advantage does WebClient offer over RestTemplate in a high-concurrency microservices environment?", "options": [{"content": "It uses blocking I/O by default, ensuring predictable execution order.", "feedback": "Incorrect. WebClient is non-blocking and reactive—its strength lies in scalability under load, not blocking behavior.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It supports asynchronous, non-blocking requests and integrates with reactive streams for better scalability.", "feedback": "Correct. WebClient is designed for reactive programming with WebFlux, enabling efficient handling of many concurrent requests without thread blocking.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "It automatically integrates with Eureka without any configuration.", "feedback": "No. Like RestTemplate, WebClient requires explicit setup (e.g., via WebClient.Builder with LoadBalancerExchangeFilterFunction) to work with service discovery.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It simplifies JSON parsing by returning strings by default.", "feedback": "Incorrect. WebClient deserializes to objects just like RestTemplate. Its API is functional and stream-oriented, not string-focused.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 4, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Lin finds conflicting philosophies: Reed defends RestTemplate while Park pushes WebClient. What is a valid reason Jasmine might argue for migrating from RestTemplate to WebClient?", "options": [{"content": "WebClient is easier to debug because it uses synchronous calls.", "feedback": "Incorrect. WebClient is asynchronous and reactive, which can make debugging more complex, not simpler.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "WebClient supports non-blocking I/O, improving performance under heavy load in reactive systems.", "feedback": "Correct. In modern cloud-native applications, non-blocking I/O allows better resource utilization and higher throughput under concurrency.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_003"]}, {"content": "WebClient requires less configuration to integrate with service discovery.", "feedback": "False. Both clients require configuration to work with Eureka or similar registries. WebClient does not simplify this out of the box.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "WebClient automatically adds circuit breaker logic to every call.", "feedback": "No. Resilience features like circuit breakers must be added separately (e.g., via resilience4j), regardless of client choice.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 4, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Service Registry (Eureka) returns available instances"}, {"itemId": "ITEM_B2_002", "content": "Calling service initiates request using logical name"}, {"itemId": "ITEM_B2_003", "content": "Load-balanced client selects healthy instance"}, {"itemId": "ITEM_B2_004", "content": "Resiliency layer applies retry/fallback if needed"}], "order": 4, "content": "To prevent future crashes, Detective Lin proposes a secure and resilient service-to-service communication flow. Arrange these components in the correct order of interaction when a service makes a call:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": ["ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The calling service uses a logical name, queries the registry, selects an instance via load balancing, and applies resiliency measures as needed—ensuring robust inter-service communication.", "relatedKnowledge": ["CONC_007", "CONC_008", "CONC_001"], "feedbackIncorrect": "Incorrect. Remember: communication starts with a logical request, then discovery, then routing, then protection. Follow the data path from caller to target."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Jasmine deploys a WebClient that directly targets a fixed URL instead of using service discovery."}, {"itemId": "ITEM_B3_002", "content": "The targeted inventory service instance becomes overloaded and returns 503 errors."}, {"itemId": "ITEM_B3_003", "content": "WebClient fails to detect alternative healthy instances due to lack of LoadBalancer integration."}, {"itemId": "ITEM_B3_004", "content": "Payment service threads block waiting for responses, exhausting the thread pool."}, {"itemId": "ITEM_B3_005", "content": "Core Payment Service crashes, triggering alarms in Server Room B."}], "order": 4, "content": "Lin reconstructs the timeline of how the misconfigured WebClient led to the cascade failure. Arrange these events in chronological order:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 5, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004", "ITEM_B3_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence shows how a poorly configured WebClient, lacking service discovery and resiliency, led to a cascading failure when the target service failed.", "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": "Incorrect. Remember: the root cause started with a static WebClient configuration, followed by service failure, inability to failover, thread exhaustion, and finally system crash."}], "characters": [{"age": 38, "goal": "Uncover the truth behind the system failure and identify the responsible party.", "name": "Detective Mira Lin", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once caused a production outage due to improper use of @Autowired, leading to her career shift.", "background": "Former software engineer turned digital crime investigator, known for solving complex technical failures with precision logic.", "occupation": "Systems Forensic Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, detail-oriented", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_009"]}, {"age": 52, "goal": "Protect his architectural legacy and prevent blame for the system crash.", "name": "Dr. Elias Reed", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Fiercely opposed the migration from RestTemplate to WebClient, fearing obsolescence.", "background": "Architect of the company''s microservices framework; recently passed over for promotion.", "occupation": "Lead Enterprise Architect", "characterId": "CHAR_002", "personality": "Brilliant but arrogant, protective of legacy design choices.", "knowledgePoints": ["CONC_001", "CONC_005", "CONC_006"]}, {"age": 29, "goal": "Ensure credit for pushing forward modern architecture—even if it means covering up a mistake.", "name": "Jasmine Park", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Secretly deployed an untested WebClient configuration that bypassed service discovery.", "background": "Rising star advocating for modern reactive systems using WebClient and resilience patterns.", "occupation": "Cloud Integration Developer", "characterId": "CHAR_003", "personality": "Innovative, ambitious, slightly reckless in pursuit of progress.", "knowledgePoints": ["CONC_009", "CONC_008", "CONC_007"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "RestTemplate", "category": "HTTP Client", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "A synchronous client in Spring used to perform HTTP requests. Now considered legacy in favor of non-blocking alternatives.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_009", "CONC_005", "CONC_006"]}, {"name": "@Autowired", "category": "Dependency Injection", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "Spring annotation used to inject dependencies automatically by type. Critical for inversion of control in enterprise applications.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_003", "CONC_004"]}, {"name": "@Bean", "category": "Configuration", "appearsIn": ["SCENE_001"], "difficulty": 2, "description": "Annotation used in configuration classes to define a bean managed by the Spring container.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "Java Bean", "category": "Core Java", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A reusable Java class with no-argument constructor, private fields, and public getters/setters. Foundation for Spring-managed components.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_003", "CONC_002"]}, {"name": "HTTP Message Converter", "category": "Serialization", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 3, "description": "Converts HTTP requests and responses to and from Java objects. Used by RestTemplate and other web clients.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_010"]}, {"name": "Service-to-Service Communication", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Interaction pattern where microservices exchange data via APIs, often using REST or messaging.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_009", "CONC_007"]}, {"name": "Service Discovery", "category": "Microservices", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Mechanism allowing services to locate each other dynamically in a distributed environment, often via registries like Eureka.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_006", "CONC_008"]}, {"name": "Client-Side Resiliency", "category": "Resiliency", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 4, "description": "Patterns like retry, circuit breaker, and fallback implemented on the calling service to handle downstream failures.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_007", "CONC_009"]}, {"name": "WebClient", "category": "HTTP Client", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "Non-blocking, reactive client in Spring WebFlux for performing HTTP requests with support for asynchronous operations.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_008", "CONC_006"]}, {"name": "ResponseEntity", "category": "HTTP Response", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Class representing an entire HTTP response including status, headers, and body. Used in controllers and clients.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_001", "CONC_005"]}], "educational_goals": ["Understand core concepts in Enterprise Systems Development including dependency injection, service communication, and resiliency patterns", "Differentiate between RestTemplate and WebClient for HTTP communication", "Apply knowledge of Spring annotations such as @Autowired and @Bean", "Analyze how Service Discovery and Client-Side Resiliency impact system stability"], "template_difficulty": {"puzzle_mcq": 8, "puzzle_fill": 2, "puzzle_sorting": 2}}', '0e716bda602966cb7edddc9ae1e69be3f622916dcfe8a08917d37681d1d05823', 'all concepts', '2026-04-28 02:45:57.526606', NULL, 'ITP4511') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('1d7b1adf-bc50-4c84-936e-40a92662a54b', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '2a7da247-2b88-467c-a6e2-e32077162d3c', NULL, 'Code & Consequences: A SAP ABAP Mystery', 'active', 'easy', 'standard', '{"clues": [{"name": "ERP System Diagram", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "The company relies on a unified ERP system to manage core operations, explaining why a failure in one module could cascade.", "description": "A whiteboard sketch showing how SAP ERP integrates financial, CRM, and inventory modules. Handwritten labels emphasize ''centralized data flow'' and ''real-time processing''.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_001"]}, {"name": "ABAP Editor Screenshot", "type": "digital", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Evidence of manual code intervention in a critical ABAP program, suggesting unauthorized changes were made prior to the crash.", "description": "A frozen screen capture from the ABAP development environment showing a corrupted report program with syntax errors and commented-out security checks.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004"]}, {"name": "CRM Integration Log Snippet", "type": "log", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "An unauthorized CRM update was attempted during off-hours, possibly triggering system instability.", "description": "A truncated server log showing a failed CRM transaction attempt at 2:17 AM. Contains references to ''ZCRM_UPDATE'' and ''authorization bypass''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003"]}, {"name": "Work Process Configuration Table", "type": "technical", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Critical background processes were disabled to preserve legacy functionality, increasing system vulnerability.", "description": "A printed table listing SAP work process types: Dialog, Update, Enqueue, Background, Spool. One row is highlighted—''Update''—with a note: ''disabled for compatibility''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "Function Module Call Chain", "type": "diagram", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "A pattern of modular ABAP design where function modules are reused via macros, indicating advanced coding practices were in play.", "description": "A hand-drawn flowchart on a sticky note showing Z_FM_FRUIT_PRICE being called by Z_FRUIT_SELLING_PRICE, with macro cal_selling_price in use.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004"]}, {"name": "Log Entry: Suspicious Work Process Spike", "type": "system_log", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Unusual system load from non-dialog processes during off-hours suggests automated or rogue execution.", "description": "A server log excerpt shows an abnormal spike in background work processes at the time of the crash. The entries correlate with unauthorized CRM update attempts.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Whiteboard Note: Decision Hierarchy Draft", "type": "handwritten_note", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "The CRM update was intended to support mid-level management decisions, not executive strategy.", "description": "A sticky note on the monitoring room whiteboard outlines three levels: ''Strategic – Board Level'', ''Tactical – Managers'', ''Operational – Daily Ops''. Arrows point to CRM integration labeled ''Tactical Support''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "ABAP Dictionary Snippet: ZINV Table Definition", "type": "code_excerpt", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "The invoice table relies on referential integrity through foreign keys—any tampering would risk system failure.", "description": "Printout showing structure of table ZINV: fields include MANDT (Client), INV_NUM (Primary Key), PROD_ID (Foreign Key → ZPROD), QUANTITY, and CURRENCY. Notes indicate it''s transaction data.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007"]}, {"name": "Function Module Call Trace: Z_FM_FRUIT_PRICE", "type": "execution_trace", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Poor exception handling in a custom function module could cascade into larger system instability if reused elsewhere.", "description": "Debug trace shows a call to function module Z_FM_FRUIT_PRICE with negative cost input. Exception ''INVALID_COST'' was raised but not handled properly in calling program.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008"]}, {"name": "Sequence Log: Server Crash Timeline", "type": "timeline_diagram", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "The crash followed a specific chain of technical events involving function modules and resource exhaustion.", "description": "Hand-drawn sequence chart on a napkin: starts with ''User Login'', then ''FM Call'', followed by ''Work Proc Overload'', ''Enqueue Lock Fail'', ends with ''System Crash''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Printed Macro Definition Snippet", "type": "document", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Evidence of unauthorized macro usage in production code that could mask logic errors or malicious behavior.", "description": "A crumpled printout found near the ABAP editor showing a DEFINE block for cal_selling_price, used in a fruit pricing report. The macro takes cost and applies a markup formula.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Log Entry: Macro Expansion Trace", "type": "system_log", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "The macro was actively processed just before the system failure, suggesting it played a role in triggering the error.", "description": "A server log fragment recovered from backup storage showing preprocessor output where the cal_selling_price macro was expanded during compilation. Timestamp matches the night of the crash.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Annotated Code Comment on Macro Risks", "type": "note", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Nina was aware of the dangers of macros but may have still used them recklessly.", "description": "A sticky note attached to Nina''s monitor with handwritten warnings: ''Macros expand before compile → hard to debug. No runtime checks. Can hide side effects.''", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "ABAP Preprocessor Output Snapshot", "type": "digital_artifact", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "Improper macro use led to excessive code bloat, contributing to the work process overload and eventual crash.", "description": "A saved terminal capture showing the result of /SAPAPO/TRACE_PREPROC, revealing how the cal_selling_price macro was replaced inline during preprocessing, inflating memory usage.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Final Compilation Report Excerpt", "type": "report", "clueId": "CLUE_B3_005", "foundBy": "CHAR_001", "reveals": "The macro significantly increased code complexity without review, violating change control policies.", "description": "Excerpt from the post-mortem compilation log showing ''Macro expansion completed – 147 lines generated from 3-line definition''. Flagged as high-risk by internal audit standards.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}], "title": "Code & Consequences: A SAP ABAP Mystery", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash and the Code", "sceneId": "SCENE_001", "location": "SAP Development Lab", "description": "Detective Reed arrives at the locked-down SAP lab after a fatal server crash. The body of a temporary contractor has been removed, but the scene is littered with printouts, sticky notes, and an open ABAP editor showing corrupted code. Dr. Lin and Nina are being questioned at their desks.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Tracing the Transaction", "sceneId": "SCENE_002", "location": "Server Monitoring Room", "description": "Reed reviews system logs and transaction traces with Lin and Patel. They discover conflicting entries around the time of the crash—one pointing to a rogue CRM update, another to a misconfigured work process. Tensions rise as blame shifts.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Compilation", "sceneId": "SCENE_003", "location": "Executive Briefing Room", "description": "In a closed-door meeting, Reed confronts both suspects with evidence. She reconstructs the sequence of events using system artifacts, forcing the truth to surface: sabotage masked as technical failure. One character breaks down, revealing their motive.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Compiled", "content": "Reed reveals that Nina attempted to patch a vulnerability in Lin’s legacy code but triggered a cascade failure due to incompatible macros. Lin had disabled updates, making the system fragile. No malice, only flawed decisions.", "debrief": "The real culprit was technical debt and poor governance. Both characters acted out of loyalty—to innovation or legacy—but failed to communicate.", "summary": "Understanding SAP systems requires not just coding skills but awareness of architecture, security, and collaboration.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Termination", "content": "Reed blames Lin entirely, citing his resistance to change. He is fired, but the system remains unstable. Later, another crash occurs due to the same unpatched issue.", "debrief": "Jumping to conclusions without full evidence leads to unjust outcomes and repeated failures.", "summary": "Technical investigations require complete understanding of all components and motivations.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "When a critical ERP system fails during a major product launch, a detective must unravel the truth behind a developer''s suspicious death by navigating the complex world of SAP ABAP, enterprise systems, and corporate secrets hidden in code and configuration.", "version": "1.0", "evidence": [{"name": "Corrupted ABAP Source Code Printout", "type": "Document", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A printed section of ABAP code with syntax errors and an unauthorized macro insertion near a critical database write operation.", "foundLocation": "SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_009"]}, {"name": "System Log Excerpt - Work Process Overflow", "type": "Digital Record", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Log entry showing multiple failed dialog work processes attempting to execute a CRM-related function module simultaneously.", "foundLocation": "SCENE_002", "relatedKnowledge": ["CONC_005", "CONC_003", "CONC_008"]}, {"name": "Unauthorized Database Table Modification Request", "type": "Audit Trail", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A flagged change request to alter a core ERP table definition, submitted under a shared account but traced to a specific workstation.", "foundLocation": "SCENE_003", "relatedKnowledge": ["CONC_007", "CONC_006"]}], "has_quiz": false, "scriptId": "SAP_ABAP_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Reed examines a whiteboard labeled ''ERP Integration Map''. She needs to confirm what kind of system this represents. Which best describes an Enterprise Resource Planning (ERP) system?", "options": [{"content": "A standalone accounting software used only for payroll processing.", "feedback": "Incorrect. ERP systems are not standalone; they integrate multiple business functions across departments.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A suite of integrated applications that manage data across business activities like sales, finance, and inventory.", "feedback": "Correct. ERP systems centralize data and processes across various business units for real-time coordination.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "A customer service chatbot powered by AI to handle support tickets.", "feedback": "Incorrect. While AI chatbots can be part of a CRM, they do not define an ERP system.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A cloud storage platform for backing up employee files.", "feedback": "Incorrect. Cloud storage supports IT infrastructure but is not equivalent to an ERP system.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_008"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Reed opens the corrupted ABAP editor. She sees keywords like ''REPORT'', ''DATA'', and ''WRITE''. What is ABAP primarily used for within the SAP environment?", "options": [{"content": "Designing user interface mockups for mobile apps.", "feedback": "Incorrect. ABAP is not a UI design tool; it''s a programming language for backend logic.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Developing custom programs and reports to manage enterprise data and business logic in SAP.", "feedback": "Correct. ABAP enables developers to build tailored solutions within the SAP ERP framework.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "Encrypting network traffic between servers.", "feedback": "Incorrect. Network encryption is handled at the infrastructure level, not via ABAP.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Generating marketing emails from customer databases.", "feedback": "Incorrect. While CRM systems may send emails, ABAP itself is not an email marketing tool.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_007"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "On a sticky note near the workstation, Detective Reed reads: ''Centralized data from sales, finance, and inventory flows through the __________ system.'' What term completes this description?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_006", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["ERP", "erp", "ERP system", "erp system"], "feedbackCorrect": "Correct. The ERP system integrates data across key business functions for unified management.", "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": "Incorrect. Think about the integrated software suite that connects financial, sales, and inventory operations."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Reed examines a printout labeled ''ZINV Table Structure''. She notices that PROD_ID references another table, ZPROD. What does this relationship ensure, and why is it critical?", "options": [{"content": "Ensures data normalization so reports run faster.", "feedback": "While normalization helps performance, the primary purpose of a foreign key is to enforce referential integrity—not speed.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Maintains referential integrity by linking transactions to valid products, preventing orphaned records.", "feedback": "Correct. Foreign keys like PROD_ID → ZPROD ensure only valid product IDs are used in invoices, preserving data consistency.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "Allows Open SQL to join tables without explicit syntax.", "feedback": "Open SQL still requires explicit JOINs. Foreign keys define relationships but don’t automate queries.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Identifies master data versus transaction data for backup purposes.", "feedback": "While ZINV is transactional and ZPROD may be master data, the foreign key’s main role is integrity, not classification or backups.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_001", "content": "This process type runs ABAP programs and is often associated with dialog or background execution.", "unlockAfterAttempts": 1}], "items": null, "order": 6, "content": "Detective Reed finds a sticky note listing SAP work process types. One is missing: Dialog, Update, Enqueue, Background, Spool, Message, Batch Input, Update 1, Update 2, and ________. What is the eighth standard type?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["Worker"], "feedbackCorrect": "Correct. The eight standard SAP work processes include Worker (sometimes called ''Update'') though some contexts group them differently. Here, Worker completes the set.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Recall that SAP Application Layer work processes include eight types. The missing one is ''Worker'', responsible for executing ABAP programs."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Reed examines a torn printout labeled ''Z_FRUIT_SELLING_PRICE''. It contains a block starting with DEFINE cal_selling_price. What is the purpose of this structure in ABAP?", "options": [{"content": "It defines a function module that can be called remotely.", "feedback": "Incorrect. Function modules are defined using FUNCTION, not DEFINE. Macros are preprocessor constructs, not callable procedures.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It creates a reusable code snippet that gets inserted wherever the macro is invoked.", "feedback": "Correct. ABAP macros using DEFINE create inline code templates that are expanded before compilation, promoting reuse but increasing complexity.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "It declares a global variable accessible across all programs.", "feedback": "Incorrect. Global variables are declared with DATA statements in shared classes or INCLUDEs, not via macros.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It sets up an event handler for user interface interactions.", "feedback": "Incorrect. UI events are handled through PBO/PAI modules or GUI event loops, not macros.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Reed finds a comment next to the macro: ''* No input validation – trust caller''. Why is this dangerous in an ABAP macro?", "options": [{"content": "Macros cannot be debugged step-by-step, so errors inside them are harder to trace.", "feedback": "Correct. Since macros are expanded before compilation, they don’t appear as separate units in the debugger, making issues within them difficult to isolate.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_003"]}, {"content": "Macros require database commits after execution, risking data inconsistency.", "feedback": "Incorrect. Macros do not inherently require database operations; they are purely syntactic replacements.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They automatically roll back changes if an exception occurs.", "feedback": "Incorrect. Macros have no built-in exception handling or rollback mechanisms.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They only work in background jobs, not online transactions.", "feedback": "Incorrect. Macros can be used in any ABAP program regardless of execution context.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Reed reviews a failed transaction log tagged ''ZCRM_UPDATE''. She recalls that CRM systems help companies manage relationships. What is the primary goal of Customer Relationship Management (CRM)?", "options": [{"content": "To automate factory machinery and improve production speed.", "feedback": "Incorrect. That relates more to manufacturing execution systems, not CRM.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To centralize customer information and improve sales, service, and profitability.", "feedback": "Correct. CRM systems consolidate customer interactions to enhance relationship management and revenue growth.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "To monitor server uptime and prevent system crashes.", "feedback": "Incorrect. System monitoring falls under IT operations, not CRM.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To manage employee payroll and benefits administration.", "feedback": "Incorrect. Payroll is typically part of HR or Financial modules, not CRM.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_B1_003", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": [], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Reed finds a document listing SAP work processes. She knows some were disabled. Which combination correctly identifies standard SAP work process types?", "options": [{"content": "Dialog, Update, Enqueue, Background, Spool", "feedback": "Correct. These are the five standard work process types in SAP application servers.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_004"]}, {"content": "Web, Mobile, Desktop, API, Batch", "feedback": "Incorrect. These describe application platforms, not SAP-specific work processes.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Compiler, Debugger, Editor, Runner, Tester", "feedback": "Incorrect. These are development tools, not runtime work processes.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Login, Logout, Reset, Sync, Backup", "feedback": "Incorrect. These are user actions, not SAP work process types.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Reed reviews a log showing excessive background work processes running during the crash window. Which type of SAP work process handles scheduled jobs and might explain this surge?", "options": [{"content": "Dialog", "feedback": "Dialog processes handle interactive user requests. A spike here would suggest many users logged in—not applicable here.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Background", "feedback": "Yes. Background work processes execute scheduled tasks. An unexpected surge could indicate a runaway job or malicious automation.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "Enqueue", "feedback": "Enqueue manages lock tables. While critical, it doesn’t process full transactions or cause high CPU like background jobs.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Spool", "feedback": "Spool handles print requests. Unlikely to cause system-wide crashes unless massively overloaded, which isn''t indicated.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "On a whiteboard, Reed sees a diagram dividing decision-making into three layers. One level focuses on day-to-day activities like order processing and inventory updates. Which level is this?", "options": [{"content": "Strategic", "feedback": "Strategic decisions involve long-term planning like market expansion. Not related to daily operations.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Tactical", "feedback": "Tactical decisions allocate resources over months—like staffing or budgets—not real-time execution.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Operational", "feedback": "Correct. Operational decisions govern daily tasks such as processing orders or updating stock levels.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "Executive", "feedback": "Executive is not one of the standard three decision levels in SAP organizational theory.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_003", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Reed analyzes a debug trace where a function module Z_FM_FRUIT_PRICE fails due to invalid input. How should exceptions be properly handled when calling such a module in ABAP?", "options": [{"content": "Use CALL FUNCTION ... EXCEPTIONS to catch errors and respond appropriately in the calling program.", "feedback": "Exactly. Proper use of EXCEPTIONS in CALL FUNCTION allows graceful error handling instead of system dumps.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_004"]}, {"content": "Ignore exceptions; the system will auto-correct invalid values.", "feedback": "No. Unhandled exceptions can lead to short dumps or data corruption. They must be explicitly managed.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Redefine the function module each time to avoid reuse issues.", "feedback": "That defeats the purpose of reusability. Function modules are designed to be shared safely with proper parameter and exception handling.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Pass all parameters via EXPORTING to prevent input errors.", "feedback": "EXPORTING is for output, not input. Input uses IMPORTING. Misusing these won’t prevent errors and can break logic.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "System logs show the cal_selling_price macro was invoked 217 times in a loop. What likely consequence would this have on system resources?", "options": [{"content": "Increased CPU usage due to repeated interpretation at runtime.", "feedback": "Incorrect. Macros are expanded at compile time, so there’s no runtime interpretation overhead per call.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Memory bloat because each invocation inserts a full copy of the macro code.", "feedback": "Correct. Each macro call results in duplicated code during preprocessing, which increases the size of the compiled program and consumes more memory.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_004"]}, {"content": "Database lock contention from concurrent access to the macro definition.", "feedback": "Incorrect. Macro definitions are not stored in the database like tables or views; they reside in source code and pose no locking risk.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Network latency spikes when fetching macro logic from the repository.", "feedback": "Incorrect. Macros are local to the program and do not involve network calls during execution.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Lin argues that macros improve efficiency. But Reed recalls her past case where unchecked macros caused a financial miscalculation. Which principle should govern macro use in enterprise systems?", "options": [{"content": "Maximize reuse even at the cost of readability to speed up development.", "feedback": "Incorrect. While reuse is valuable, sacrificing readability and maintainability risks system stability, especially in critical environments.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Use macros only when performance gains outweigh debugging complexity.", "feedback": "Correct. Macros should be used judiciously—only when benefits clearly exceed the risks of reduced transparency and increased troubleshooting difficulty.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "Replace all repetitive code with macros regardless of context.", "feedback": "Incorrect. Blind replacement ignores potential side effects and maintenance burdens. Not all repetition warrants macro abstraction.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Allow developers full freedom to decide on macro usage without oversight.", "feedback": "Incorrect. Enterprise systems require governance. Uncontrolled macro use can lead to unreviewed, opaque logic entering production.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Developer writes ABAP code in the Report Program."}, {"itemId": "ITEM_B1_002", "content": "Code is saved and syntax-checked in the ABAP Editor."}, {"itemId": "ITEM_B1_003", "content": "Program is executed using a Transaction Code."}, {"itemId": "ITEM_B1_004", "content": "System processes logic and accesses data via Data Dictionary."}, {"itemId": "ITEM_B1_005", "content": "Output is displayed to the user or written to a log."}], "order": 5, "content": "Reed reconstructs the sequence of events leading to the crash. Arrange the following technical steps in the correct chronological order based on ABAP development and execution principles.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. This reflects the standard lifecycle of an ABAP program from creation to execution.", "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": "Incorrect. Remember: code must be written and checked before execution, and output occurs last after data processing."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Unauthorized CRM integration triggers a function module with invalid data."}, {"itemId": "ITEM_B2_002", "content": "Function module raises an unhandled exception due to negative cost input."}, {"itemId": "ITEM_B2_003", "content": "Background work process overload causes enqueue contention."}, {"itemId": "ITEM_B2_004", "content": "System enters emergency shutdown after failed lock resolution."}, {"itemId": "ITEM_B2_005", "content": "Developer attempts silent fix using custom function module without approval."}], "order": 5, "content": "Reconstruct the sequence of events leading to the server crash based on system logs and code traces. Arrange the following steps in chronological order.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 4, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_005", "ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The chain began with an unauthorized change, escalated via poor error handling, and culminated in system collapse due to resource contention.", "relatedKnowledge": ["CONC_008", "CONC_007"], "feedbackIncorrect": "Incorrect. Remember: the root cause was a well-intentioned but unapproved code change that introduced faulty logic into a critical path."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Nina implements cal_selling_price macro to simplify pricing logic."}, {"itemId": "ITEM_B3_002", "content": "Macro is invoked repeatedly in a large loop processing thousands of records."}, {"itemId": "ITEM_B3_003", "content": "Preprocessor expands macro into hundreds of duplicate code lines."}, {"itemId": "ITEM_B3_004", "content": "Work process exceeds memory limit due to bloated program size."}, {"itemId": "ITEM_B3_005", "content": "Server crashes with short dump related to resource exhaustion."}], "order": 5, "content": "Reconstruct the sequence of events that led to the server crash, based on forensic analysis of the macro-related artifacts.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_003", "ITEM_B3_002", "ITEM_B3_004", "ITEM_B3_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The macro was defined, expanded during preprocessing, then executed at scale—leading to memory overflow and system failure.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Remember: macros are expanded before runtime. The code bloat happens at compile/preprocess stage, not during loop iteration itself."}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "To define a reusable code block in ABAP that processes before compilation, you use the keyword ______ followed by the macro name and parameters.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DEFINE"], "feedbackCorrect": "Correct. The DEFINE statement begins a macro definition in ABAP, which is processed during the preprocessing phase before actual compilation.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Remember, ABAP uses DEFINE...END-OF-DEFINITION to create macros. This is different from FUNCTION or FORM for subroutines."}], "characters": [{"age": 38, "goal": "Uncover the truth behind the developer''s death and prevent further system sabotage.", "name": "Detective Elena Reed", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She once reported a flaw in an SAP module that was ignored—leading to a financial scandal she still feels responsible for.", "background": "Former IT auditor turned internal investigator for multinational firms. Known for solving technical mysteries with precision.", "occupation": "Corporate Systems Investigator", "characterId": "CHAR_001", "personality": "Analytical, observant, calm under pressure, methodical.", "knowledgePoints": []}, {"age": 52, "goal": "Protect his reputation and legacy code from scrutiny.", "name": "Dr. Marcus Lin", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He secretly disabled a security patch to preserve compatibility with his outdated custom ABAP programs.", "background": "Longtime SAP expert who designed the company’s ERP backbone. Respected but known for being territorial about his code.", "occupation": "Lead SAP Architect", "characterId": "CHAR_002", "personality": "Brilliant, arrogant, protective of legacy systems, resistant to change.", "knowledgePoints": ["CONC_001", "CONC_004", "CONC_007"]}, {"age": 29, "goal": "Clear her name and expose systemic flaws without losing her job.", "name": "Nina Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She discovered a backdoor in the ABAP code and tried to fix it without authorization—altering logs to cover her tracks.", "background": "Recent hire pushing for modernization. Was working late the night of the incident on a high-priority CRM integration.", "occupation": "Junior ABAP Developer", "characterId": "CHAR_003", "personality": "Energetic, idealistic, technically sharp, eager to prove herself.", "knowledgePoints": ["CONC_003", "CONC_008", "CONC_009"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Enterprise Resource Planning (ERP)", "category": "System Architecture", "appearsIn": ["SCENE_001"], "difficulty": 1, "description": "A centralized system integrating core business processes such as finance, HR, manufacturing, and supply chain into a unified platform.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_003", "CONC_005"]}, {"name": "Decision Support System (DSS)", "category": "Information Systems", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "An information system that supports business or organizational decision-making activities, often using data from ERP systems.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_006", "CONC_001"]}, {"name": "Customer Relationship Management (CRM)", "category": "Business Applications", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "A system for managing a company’s interactions with current and potential customers, often integrated with ERP.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_008"]}, {"name": "ABAP Programming", "category": "Development", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "Advanced Business Application Programming, the primary language used to develop applications in SAP systems.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_007", "CONC_009"]}, {"name": "SAP Work Process", "category": "System Architecture", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "A component of the SAP application server that handles specific types of tasks such as dialog, update, or background processing.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Decision Levels", "category": "Security & Access", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Hierarchical access tiers in enterprise systems that determine what data users can view or modify based on their role.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_002", "CONC_005"]}, {"name": "Database Table Definitions", "category": "Data Modeling", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Structural blueprints in SAP that define how data is stored, including fields, data types, and relationships.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_004", "CONC_001"]}, {"name": "Function Module", "category": "Development", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "A reusable ABAP routine that performs a specific task and can be called from other programs, promoting modular design.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "Macro Definition", "category": "Development", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A code substitution tool in ABAP that allows developers to define reusable blocks of code expanded at compile time.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_004", "CONC_008"]}], "educational_goals": ["Understand the role of Enterprise Resource Planning (ERP) in business operations", "Differentiate between CRM, DSS, and ERP systems", "Explain the function of ABAP programming within SAP environments", "Describe how SAP work processes manage system requests", "Identify decision levels in organizational data access", "Interpret database table definitions and their importance", "Utilize function modules for modular programming", "Apply macro definitions to streamline ABAP development"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '975c2117279abf3781d6b17466a328b16341f215ad57572a36755d3017e51e39', 'all concepts', '2026-04-13 15:22:07.513224', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('7a02bed8-50f4-40fe-acc8-4bc6aeac3122', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '2a7da247-2b88-467c-a6e2-e32077162d3c', NULL, 'The ABAP Architect''s Demise', 'active', 'easy', 'standard', '{"clues": [{"name": "Incomplete ABAP Program Fragment", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Suggests rushed or unauthorized development work related to CRM customization.", "description": "A partially written ABAP report (ZCRM_ENHANCEMENT) found on the terminal in the server room. It contains syntax errors and references a CRM module update but lacks proper authorization checks.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_003", "CONC_004"]}, {"name": "Access Log Discrepancy", "type": "system_log", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Indicates possible privilege escalation or misuse of credentials involving decision support systems.", "description": "Log entries show that user NINA_P accessed the DSS analytics module at 2:15 AM, but her access level should not permit this. The entry is timestamped just before the system crash.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Hidden Macro Definition", "type": "code_artifact", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Evidence of code reuse without authorization, potentially violating intellectual property within ABAP development.", "description": "Inside the debug sandbox, a macro named Z_CALC_REVENUE_TIER was discovered in Nina’s temporary workspace. It matches one from the victim’s private code library, including a unique comment tag ''//VP-Legacy''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004", "CONC_003"]}, {"name": "Disabled DSS Integration Flag", "type": "configuration", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Dr. Grant intentionally limited automated decision support functionality to retain control over strategic reporting.", "description": "A configuration flag in the ERP integration layer (SAP_CUSTOMIZING_TABLE) shows that the DSS-to-CRM data sync was manually disabled by user GRANT_E two weeks ago with a comment: ''Preserve manual override capability.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_001"]}, {"name": "ERP Module Dependency Map", "type": "diagram", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Illustrates how tampering with one module can cascade into failures across business functions like sales and finance.", "description": "A whiteboard diagram in the war room shows how SAP modules interconnect. Handwritten notes highlight that CRM depends on Financial and DSS modules for revenue forecasting accuracy.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_002"]}, {"name": "Corrupted Work Process Log", "type": "digital", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Someone exploited non-Dialog work processes to run hidden background tasks.", "description": "A system log excerpt shows abnormal termination of a Background work process during off-hours. The timestamp matches the time of unauthorized code deployment.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Decision-Level Access Mismatch", "type": "document", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Access rights were manipulated to allow lower-level staff to influence strategic decisions.", "description": "An internal audit memo reveals that operational-level users were granted tactical reporting permissions, bypassing standard hierarchy controls.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "ZPROD Table Definition Anomaly", "type": "database", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Data integrity was compromised through improper table design.", "description": "The ABAP Dictionary entry for table ZPROD shows a missing foreign key constraint on CURRENCY field, allowing invalid currency codes to be entered.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_007"]}, {"name": "Function Module Exception Trail", "type": "code_trace", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "The sabotage involved deliberate misuse of function modules to destabilize financial calculations.", "description": "A stack trace shows repeated calls to Z_FM_FRUIT_PRICE with negative cost values, triggering exception handling routines.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_008"]}, {"name": "Work Process Configuration Schematic", "type": "diagram", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "The attacker focused on non-interactive processes to avoid detection.", "description": "A whiteboard sketch in the server room details all SAP work process types and their roles, with ''Update'' and ''Background'' circled in red ink.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Corrupted Macro Definition", "type": "digital", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "Evidence of unauthorized or incorrect macro usage in critical reporting code.", "description": "A malformed ABAP macro definition was found in the Z_FRUIT_SELLING_PRICE program. The syntax uses DEFINE but lacks proper ENDOFDEFINITION, suggesting either an incomplete upload or intentional sabotage.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Duplicate Macro Logic in Nina''s Workspace", "type": "digital", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "Nina reused protected code without authorization, potentially to accelerate her CRM module delivery.", "description": "An identical copy of the victim’s proprietary cal_selling_price macro appears in Nina Patel’s personal development package with a creation timestamp predating the victim’s official release.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}, {"name": "Macro Preprocessing Anomaly", "type": "system_log", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "The macro was used improperly, leading to unstable behavior during execution and possible system crash triggers.", "description": "The ABAP preprocessor log shows that the cal_selling_price macro was expanded before compilation but flagged a warning due to undefined variables—indicating it was copied without full context.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_009"]}], "title": "The ABAP Architect''s Demise", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Server Room Discovery", "sceneId": "SCENE_001", "location": "SAP Data Center - Main Control Room", "description": "Detective Chen arrives at the locked server room where the senior ABAP developer was found unconscious. Lights flicker across server racks. A terminal displays an incomplete ABAP program with syntax errors. Nina appears shaken, claiming she discovered the body while testing a CRM enhancement.", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Interrogation in the War Room", "sceneId": "SCENE_002", "location": "Executive Conference Room", "description": "Chen questions both suspects in a secure meeting space filled with dashboards showing ERP performance metrics. Dr. Grant defends his stance on decision autonomy, while Nina struggles to explain discrepancies in recent code commits. Logs show conflicting access times to critical SAP modules.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation at the Debug Console", "sceneId": "SCENE_003", "location": "SAP Development Sandbox", "description": "All characters gather at a central debugging station where the final ABAP routine is being reconstructed. Evidence converges: corrupted function modules, altered macro definitions, and mismatched decision-level permissions point to a deliberate sabotage masked as a system crash.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct Resolution", "title": "Truth in the Code", "content": "The detective reveals that the victim had discovered Nina''s unauthorized use of proprietary macros. Before he could report it, Dr. Grant exploited the situation—manipulating logs and disabling safeguards to frame Nina and eliminate oversight on DSS controls. The murder was not personal, but a calculated move to preserve power.", "debrief": "The case underscores how technical knowledge, when misused, can mask unethical behavior. Understanding ERP architecture and ABAP practices is essential for accountability.", "summary": "Dr. Grant is arrested for obstruction and conspiracy. Nina faces disciplinary action but avoids criminal charges. System audits are mandated across departments.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect Resolution", "title": "False Confession", "content": "Under pressure, Nina admits to tampering with code, believing she caused the crash. But inconsistencies in the timeline and overlooked system logs suggest another actor was involved.", "debrief": "Jumping to conclusions without full technical analysis risks punishing the wrong person. Deep understanding of SAP workflows prevents misjudgment.", "summary": "Nina is suspended. The real culprit remains free, and vulnerabilities persist in the ERP system.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In the quiet hum of a corporate SAP server room, a lead developer is found dead under mysterious circumstances. The detective must unravel technical secrets hidden in ERP architecture and ABAP code to expose the truth behind the murder.", "version": "1.0", "evidence": [{"name": "Corrupted ABAP Program Draft", "type": "Digital Artifact", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "An unfinished ABAP program on the victim''s workstation containing malformed macro calls and incorrect table references.", "foundLocation": "Victim''s Terminal - SCENE_001", "relatedKnowledge": ["CONC_004", "CONC_009", "CONC_007"]}, {"name": "Access Log Anomaly", "type": "System Log", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Server logs show unauthorized access to the DSS configuration module during off-hours, traced to Dr. Grant''s credentials.", "foundLocation": "Security Console - SCENE_002", "relatedKnowledge": ["CONC_002", "CONC_006"]}, {"name": "Duplicate Macro Definition File", "type": "Code Repository", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "A version-controlled file shows identical macro definitions in two developers'' folders, suggesting intellectual property duplication.", "foundLocation": "Version Control Dashboard - SCENE_003", "relatedKnowledge": ["CONC_009", "CONC_004"]}, {"name": "Misaligned Function Module Call", "type": "Runtime Error Log", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A critical function module failed due to parameter mismatch, triggering a system halt shortly before the incident.", "foundLocation": "Application Monitor - SCENE_003", "relatedKnowledge": ["CONC_008", "CONC_005"]}], "has_quiz": false, "scriptId": "ERP_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines the incomplete ABAP program on the terminal. It''s designed to enhance customer data handling in the CRM system. Which of the following BEST describes what CRM stands for and its primary purpose?", "options": [{"content": "Customer Relationship Management – to centralize customer interactions and improve sales relationships.", "feedback": "Correct. CRM systems are designed to manage all aspects of customer interaction to boost revenue and retention.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "Central Reporting Module – to generate financial summaries for executives.", "feedback": "Incorrect. While reporting is part of ERP, CRM specifically focuses on managing customer interactions, not general financial reporting.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Code Repository Manager – to store and version-control ABAP programs.", "feedback": "Incorrect. This describes a development tool, not CRM. CRM deals with business processes around customers.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Cross-Regional Monitoring – to track global server performance in real time.", "feedback": "Incorrect. That sounds more like an IT operations dashboard. CRM is focused on business relationships, not infrastructure monitoring.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Chen reviews the syntax error in the ABAP code: ''FIELD-SYMBOLS <fs> TYPE ANY without ASSIGNMENT.'' What does ABAP primarily serve within an SAP environment?", "options": [{"content": "It is the programming language used to build custom reports and logic in SAP ERP systems.", "feedback": "Correct. ABAP allows developers to customize SAP functionality, such as CRM enhancements or financial reports.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "It is a database management system used to replace Oracle in SAP installations.", "feedback": "Incorrect. ABAP is not a database system; it''s a high-level programming language tailored for SAP application development.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It is a security protocol for encrypting data between SAP modules.", "feedback": "Incorrect. ABAP is not a security protocol. It’s used for writing business logic and interface code within SAP.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It is a user interface framework for building web-based dashboards.", "feedback": "Incorrect. While ABAP can create UIs, it is fundamentally a backend programming language for enterprise logic, not just front-end design.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines the server logs and notices several failed Background work processes. She recalls that SAP Application Layer work processes handle different types of requests. Which type is specifically designed to execute scheduled jobs without user interaction?", "options": [{"content": "Dialog", "feedback": "Incorrect. Dialog work processes handle interactive user requests, not automated tasks.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Spool", "feedback": "Incorrect. Spool processes manage print output, not job execution.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Background", "feedback": "Correct. Background work processes are used for executing long-running or scheduled tasks without user interaction.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "Enqueue", "feedback": "Incorrect. Enqueue processes manage lock management across the system.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [{"hintId": "HINT_B2_001", "content": "Think about when user interaction ends and automated processing begins.", "unlockAfterAttempts": 1}], "items": [{"itemId": "ITEM_B2_001", "content": "Dialog Work Process receives initial user input"}, {"itemId": "ITEM_B2_002", "content": "Background Work Process executes the bulk import job"}, {"itemId": "ITEM_B2_003", "content": "Update Work Process commits changes to database"}, {"itemId": "ITEM_B2_004", "content": "Spool Work Process generates confirmation report"}], "order": 5, "content": "Chen reconstructs the sequence of events based on work process activity. Arrange these SAP Application Layer work processes in the order they would typically handle a batch invoice upload task.", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence follows the logical flow: user initiation → background processing → data persistence → output generation.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Consider the lifecycle of a batch operation: it starts with user action, runs asynchronously, updates data, then produces output."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Chen examines the incomplete ABAP program on the terminal. One block starts with ''DEFINE cal_selling_price.'' What is the purpose of this structure, and what must follow it to be valid?", "options": [{"content": "It defines a reusable code snippet; it must end with ENDOFDEFINITION.", "feedback": "Correct. In ABAP, macros are defined using DEFINE and must be closed with ENDOFDEFINITION for proper preprocessing.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "It declares a function module; it must end with ENDFUNCTION.", "feedback": "Incorrect. Function modules use FUNCTION/ENDFUNCTION. This is a macro, not a function.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It creates a class method; it must end with ENDCLASS.", "feedback": "Incorrect. Class definitions use CLASS/ENDCLASS. Macros are simpler preprocessor constructs.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It starts a report section; it must end with END-OF-SELECTION.", "feedback": "Incorrect. That controls output flow. DEFINE is specifically for macro code reuse.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "On the flickering terminal, Detective Chen spots a keyword used to begin a macro in ABAP: ______. What is the missing keyword?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["DEFINE"], "feedbackCorrect": "Correct. In ABAP, macros start with the DEFINE statement and must end with ENDOFDEFINITION.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Recall that ABAP uses DEFINE to initiate a macro block for code reuse before compilation."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "During interrogation, Dr. Grant claims he only uses analytics for ''tactical decisions.'' Detective Chen recalls that DSS supports which level(s) of organizational decision-making?", "options": [{"content": "Management, operations, and professional levels – especially semi-structured or unstructured decisions.", "feedback": "Correct. Decision Support Systems assist various levels in making complex decisions where clear procedures don’t exist.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_004"]}, {"content": "Only executive-level strategic planning with fully structured workflows.", "feedback": "Incorrect. DSS is meant for semi-structured problems, not rigidly defined ones typically handled by standard ERP reports.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Only operational tasks like invoice processing and inventory counting.", "feedback": "Incorrect. Those are routine activities managed by transactional ERP modules, not DSS.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Only customer service representatives using scripted responses.", "feedback": "Incorrect. That’s a front-line operational role; DSS supports higher-level analysis and judgment calls.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Chen studies the whiteboard showing interconnected SAP modules. She asks: What is the core idea behind an Enterprise Resource Planning (ERP) system?", "options": [{"content": "An integrated software suite that manages multiple business processes like finance, HR, and CRM in one system.", "feedback": "Correct. ERP integrates key business functions into a unified platform to streamline operations and data flow.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_005"]}, {"content": "A standalone tool for creating PowerPoint presentations for board meetings.", "feedback": "Incorrect. That’s office productivity software. ERP handles real-time business operations across departments.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A cloud storage service for backing up employee personal files.", "feedback": "Incorrect. Cloud storage isn''t ERP. ERP coordinates business processes, not file backups.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A social media platform for internal company communication.", "feedback": "Incorrect. Tools like Slack or Teams handle internal chat, but ERP manages financial, supply chain, and customer data.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_004", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During interrogation, Dr. Grant claims he only influences high-level strategy. Detective Chen reviews access logs and considers organizational decision levels. Which level involves day-to-day operations like processing sales orders or managing inventory?", "options": [{"content": "Strategic", "feedback": "Incorrect. Strategic decisions involve long-term planning and direction setting.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Tactical", "feedback": "Incorrect. Tactical decisions focus on mid-term resource allocation and departmental goals.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Operational", "feedback": "Correct. Operational decisions govern daily activities such as order fulfillment and production scheduling.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "Executive Oversight", "feedback": "Incorrect. This is not one of the standard decision levels in SAP organizational theory.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 2, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Chen analyzes the ZPROD product table definition and suspects data integrity issues. Which component in an ABAP Dictionary table ensures referential integrity by linking to another table''s primary key?", "options": [{"content": "Primary Key", "feedback": "Incorrect. Primary keys uniquely identify records within the same table.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Client Number", "feedback": "Incorrect. Client number enables multi-client architecture but does not enforce cross-table relationships.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Foreign Key", "feedback": "Correct. Foreign keys establish and enforce relationships between tables, ensuring data consistency.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "Quantity Field", "feedback": "Incorrect. Quantity fields store numerical values but do not enforce structural relationships.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004", "CONC_009"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "During interrogation, Nina claims she didn’t write the cal_selling_price macro herself. Chen checks version control and sees her copy matches the victim’s exactly. Why would a developer use such a macro?", "options": [{"content": "To reduce repetitive code by defining a reusable logic block processed before compilation.", "feedback": "Correct. Macros allow developers to define patterns once and reuse them, improving efficiency and consistency.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "To create a runtime function that can be debugged step-by-step like any other subroutine.", "feedback": "Incorrect. Macros are expanded at compile time, not executed as standalone routines.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To store configuration data in shared memory for cross-program access.", "feedback": "Incorrect. Shared data storage uses different mechanisms like buffers or tables.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To replace database views with inline SQL templates for performance tuning.", "feedback": "Incorrect. While macros can include SQL, their primary role isn''t replacing views.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Grant argues that macros complicate audit trails. Chen counters: how do macros actually affect code transparency?", "options": [{"content": "They simplify source code readability but obscure actual compiled logic since expansion happens pre-compilation.", "feedback": "Correct. While source looks cleaner, auditors must examine expanded code to see real behavior.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": true, "unlockClues": []}, {"content": "They make debugging easier because each macro call appears as a separate stack frame.", "feedback": "Incorrect. Macros don’t appear in call stacks—they’re inlined into the calling code.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They have no impact on transparency since they are just comments ignored by the compiler.", "feedback": "Incorrect. Macros are active code structures, not comments.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They enhance security by encrypting repeated logic blocks during preprocessing.", "feedback": "Incorrect. Macros offer no encryption or obfuscation features.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Nina copies the proprietary macro Z_CALC_REVENUE_TIER from the victim’s workspace."}, {"itemId": "ITEM_B1_002", "content": "The macro is embedded into a new CRM enhancement program without proper documentation."}, {"itemId": "ITEM_B1_003", "content": "Dr. Grant disables the DSS integration flag to limit automated decision outputs."}, {"itemId": "ITEM_B1_004", "content": "Conflicting logic causes a runtime error during nightly batch processing."}, {"itemId": "ITEM_B1_005", "content": "System crash triggers alarm and locks server room access."}], "order": 5, "content": "At the debug console, Chen reconstructs the sequence of events leading to the system failure. Arrange these technical actions in the correct chronological order based on log evidence and code artifacts.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": ["ITEM_B1_001", "ITEM_B1_002", "ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sabotage originated from unauthorized code reuse combined with deliberate system misconfiguration, culminating in a critical failure.", "relatedKnowledge": ["CONC_003", "CONC_002"], "feedbackIncorrect": "Incorrect. Re-examine the timeline: code theft came first, followed by integration issues caused by disabled DSS syncing, leading to the crash."}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "To finalize the investigation, Chen must identify the root cause term: The combination of unauthorized ABAP macro usage and disabled DSS integration represents a case of ________ within the ERP environment.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_006", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["systemic sabotage", "deliberate sabotage", "intentional sabotage", "malicious configuration", "unauthorized modification"], "feedbackCorrect": "Correct. The incident wasn''t accidental—it involved deliberate actions that compromised both code integrity and system architecture.", "relatedKnowledge": ["CONC_002", "CONC_001"], "feedbackIncorrect": "Incorrect. Think about the intent behind the actions: unauthorized code copying and disabling critical integrations point to intentional harm, not random error."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "At the debug console, Chen traces a corrupted pricing calculation back to a function module. What is the correct ABAP syntax for calling a function module while handling potential errors?", "options": [{"content": "PERFORM Z_CALC_PRICE", "feedback": "Incorrect. PERFORM is used for subroutines, not function modules.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "CALL FUNCTION ''Z_CALC_PRICE'' EXCEPTIONS error_occurred = 1", "feedback": "Correct. CALL FUNCTION is the proper syntax, and EXCEPTIONS allows global error handling.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_004"]}, {"content": "EXECUTE Z_CALC_PRICE ON COMMIT", "feedback": "Incorrect. ON COMMIT is used for update tasks, not general function calls.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "RUN FUNCTION Z_CALC_PRICE", "feedback": "Incorrect. There is no RUN FUNCTION statement in ABAP.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [{"hintId": "HINT_B2_002", "content": "This parameter type allows bidirectional data flow between caller and callee.", "unlockAfterAttempts": 1}], "items": null, "order": 6, "content": "To prevent future sabotage, Chen implements strict checks in all function modules. In ABAP, what keyword is used to define parameters that can be modified and returned to the calling program?", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_008"}, "difficulty": 4, "questionId": "Q_B2_006", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["CHANGING", "changing"], "feedbackCorrect": "Correct. The CHANGING parameter interface allows values to be passed into and modified by the function module.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Remember, IMPORTING passes data in, EXPORTING returns data out, and CHANGING allows two-way data transfer."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "At the debug console, Chen reconstructs the final ABAP routine. He notices the macro cal_selling_price references variables not declared in its scope. What happens when such a macro is processed?", "options": [{"content": "The preprocessor replaces the macro call with raw code, but compilation fails if variables are undefined.", "feedback": "Correct. Macros are textually inserted before compilation, so missing declarations cause errors later.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_003"]}, {"content": "The system automatically imports required variables from global memory.", "feedback": "Incorrect. ABAP does not auto-resolve variable dependencies across scopes.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The macro runs independently and returns null values for unknowns.", "feedback": "Incorrect. Macros aren''t runtime entities—they’re compile-time insertions.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It triggers a dynamic lookup in the ABAP Dictionary to infer types.", "feedback": "Incorrect. No such automatic inference occurs for macro variables.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "Nina copies the cal_selling_price macro from the victim’s workspace."}, {"itemId": "ITEM_B3_002", "content": "She implements it in her CRM enhancement without verifying variable scope."}, {"itemId": "ITEM_B3_003", "content": "The ABAP preprocessor expands the macro during compilation."}, {"itemId": "ITEM_B3_004", "content": "Undefined variables cause runtime errors during report execution."}, {"itemId": "ITEM_B3_005", "content": "System instability leads to server overload and apparent crash."}], "order": 5, "content": "Reconstruct the correct sequence of events in how the faulty macro contributed to the system failure.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004", "ITEM_B3_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The chain of misuse begins with unauthorized copying and ends in system collapse due to unhandled errors.", "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": "Incorrect. Remember: macro misuse starts with copying, then improper implementation, preprocessing, runtime failure, and finally system impact."}], "characters": [{"age": 38, "goal": "Uncover the truth behind the developer''s death by analyzing digital and interpersonal evidence within the SAP ecosystem.", "name": "Detective Lara Chen", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She once reported a close colleague for exploiting SAP access privileges, causing their termination.", "background": "Former IT auditor turned internal investigator with a sharp eye for system anomalies and behavioral inconsistencies.", "occupation": "Corporate Security Investigator", "characterId": "CHAR_001", "personality": "Analytical, observant, calm under pressure, values logic over emotion.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_006"]}, {"age": 52, "goal": "Protect his authority by ensuring certain SAP functionalities remain limited or misconfigured.", "name": "Dr. Elias Grant", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003"], "secret": "He secretly disabled part of the DSS module to preserve his influence over strategic reports.", "background": "Longtime executive who champions data-driven decisions; skeptical of full ERP integration due to control concerns.", "occupation": "Chief Data Officer", "characterId": "CHAR_002", "personality": "Intellectually arrogant, precise, speaks in technical metaphors.", "knowledgePoints": ["CONC_002", "CONC_006", "CONC_007"]}, {"age": 29, "goal": "Clear her name and avoid being blamed for unauthorized code reuse that could cost her job.", "name": "Nina Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She copied proprietary ABAP macros from the victim’s workspace to accelerate her own project.", "background": "Highly skilled coder recently promoted; worked closely with the victim on CRM customizations.", "occupation": "Junior ABAP Developer", "characterId": "CHAR_003", "personality": "Energetic, idealistic, eager to prove herself but anxious about exposure.", "knowledgePoints": ["CONC_003", "CONC_004", "CONC_009"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Enterprise Resource Planning (ERP)", "category": "System Architecture", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "A unified software platform that integrates core business processes such as finance, HR, supply chain, and manufacturing into a single system for real-time data sharing and process automation.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Decision Support System (DSS)", "category": "Information Systems", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "An information system that supports business or organizational decision-making activities, often using data from ERP systems to model outcomes and recommend actions.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Customer Relationship Management (CRM)", "category": "Business Applications", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 1, "description": "A strategy and technology used to manage all company''s relationships and interactions with customers and potential clients, often integrated within ERP platforms.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_004"]}, {"name": "ABAP Programming", "category": "Development", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "Advanced Business Application Programming (ABAP) is a high-level programming language created by SAP for developing applications within the SAP ecosystem.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_008", "CONC_009"]}, {"name": "SAP Work Process", "category": "System Architecture", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "A component of the SAP application server that handles specific types of tasks such as dialog, update, enqueue, or background processing to ensure efficient system operation.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_007"]}, {"name": "Decision Levels", "category": "Management Systems", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Hierarchical layers in organizations—operational, tactical, and strategic—that determine the type of information and systems used for decision-making.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_002", "CONC_005"]}, {"name": "Database Table Definitions", "category": "Data Management", "appearsIn": ["SCENE_002"], "difficulty": 3, "description": "Structural blueprints in SAP that define how data is stored, accessed, and related across modules, crucial for maintaining data integrity and performance.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_005", "CONC_008"]}, {"name": "Function Module", "category": "Development", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "A reusable subroutine in SAP ABAP that performs a specific task and can be called from other programs, promoting modular and maintainable code design.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_004", "CONC_007"]}, {"name": "Macro Definition", "category": "Development", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "A code shortcut in ABAP that replaces a sequence of statements with a single identifier, improving coding efficiency but requiring careful documentation and scope management.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_004", "CONC_008"]}], "educational_goals": ["Understand the core components and purpose of Enterprise Resource Planning (ERP) systems", "Differentiate between various enterprise decision support systems including DSS and CRM", "Explain the role and structure of SAP work processes and ABAP programming environment", "Identify how database tables, function modules, and macros are used in SAP development"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '975c2117279abf3781d6b17466a328b16341f215ad57572a36755d3017e51e39', 'ERP Systems & SAP Architecture', '2026-04-13 15:24:38.395894', NULL, 'ITP4512') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('f17d3458-d73f-473d-bff3-fe3da7b1d4d2', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '5345dac0-9228-485a-85e1-0139f9b7cd1d', NULL, 'The JSP Heist: A Servlet Sabotage', 'active', 'easy', 'standard', '{"clues": [{"name": "Corrupted JSP File Fragment", "type": "digital", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "Evidence of direct Java code execution within presentation layer, indicating possible misuse of scripting elements.", "description": "A backup snapshot of index.jsp contains a suspicious scriptlet block that writes dynamic content without using proper output methods. The code appears to manipulate response flow directly.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003"]}, {"name": "Malformed Page Directive", "type": "digital", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Intentional misconfiguration of error handling, suggesting sabotage during translation phase.", "description": "The page directive in login.jsp includes an invalid errorPage attribute pointing to a non-existent ''crash.jsp''. This bypasses standard error handling mechanisms.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Execution Flow Anomaly", "type": "log", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "Overreliance on expressions without validation, exposing fragility in dynamic content rendering.", "description": "Request logs show that a JSP page attempted to display a user ID via an expression tag, but the value was null due to failed session binding. No fallback mechanism was implemented.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_004"]}, {"name": "Legacy Servlet Integration Log", "type": "log", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Historical context explaining architectural shift from monolithic servlets to separated JSP layers.", "description": "System logs indicate that business logic and request processing were previously handled entirely within servlets before migration to JSP. Some legacy endpoints still route through old servlet classes.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_002"]}, {"name": "Directive Injection Artifact", "type": "digital", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "Deliberate tampering with JSP directives to disable error recovery, confirming malicious intent.", "description": "Binary diff analysis reveals a rogue <%@ page errorPage=\"null\" %> directive inserted into header.jsp during deployment window. Matches Raj''s access timestamp.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "Malformed Declaration Tag", "type": "digital_artifact", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Evidence of deliberate tampering with JSP class-level declarations that disrupted the translation phase.", "description": "A corrupted JSP snippet recovered from the backup snapshot shows a variable declaration using <%! but missing the closing %>. This syntax error would prevent successful translation into servlet code.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Suspicious Page Directive", "type": "digital_artifact", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Proof of sabotage targeting the JSP directive configuration to bypass safety mechanisms.", "description": "Inside the corrupted JSP file, an unusual <%@ page errorPage=\"null\" %> directive was inserted. This intentionally disables error handling, ensuring uncaught exceptions crash the system without redirection.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Translation Log Entry", "type": "system_log", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Confirms the Translation Phase completed, shifting suspicion to how directives altered runtime behavior.", "description": "Server logs show that the JSP compiler successfully generated a servlet class before the outage. However, no runtime errors were logged during request processing—indicating failure occurred post-compilation.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_007"]}, {"name": "Request Processing Anomaly", "type": "network_trace", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Indicates the errorPage directive was neutralized, allowing fatal exceptions to propagate unchecked during request processing.", "description": "Packet capture reveals HTTP 500 responses being sent directly to clients without invoking any custom error page—even though one is configured in web.xml.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_008"]}, {"name": "Hidden Scriptlet Injection", "type": "code_fragment", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "Direct evidence of intentional code injection designed to trigger failures during the Request Processing Phase.", "description": "A scriptlet containing malicious logic was embedded within a comment block in the JSP header. It executes on every request and throws a NullPointerException under load.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_008", "CONC_006"]}, {"name": "Corrupted JSP Error Page Directive", "type": "digital_artifact", "clueId": "CLUE_B3_001", "foundBy": "CHAR_001", "reveals": "The system was configured to redirect errors to a non-existent page, preventing proper exception handling.", "description": "A fragment of a JSP file header recovered from the backup snapshot. The ''errorPage'' attribute points to ''/error/fatal.jsp'', but the file does not exist in version control.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_010"]}, {"name": "Malformed Scriptlet Accessing ''exception'' Object", "type": "code_evidence", "clueId": "CLUE_B3_002", "foundBy": "CHAR_001", "reveals": "An attempt was made to access the implicit ''exception'' object outside of an error-handling context, which would cause a translation failure.", "description": "A hidden scriptlet block found in the corrupted JSP: <% if(exception != null) out.println(\"Error: \" + exception.getMessage()); %>. This should only be accessible on an error page.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009", "CONC_010"]}, {"name": "Missing Session Validation in Request Flow", "type": "log_excerpt", "clueId": "CLUE_B3_003", "foundBy": "CHAR_001", "reveals": "Improper use of implicit objects contributed to instability during peak traffic.", "description": "Request logs show that user session data was accessed via the ''session'' implicit object without null-checking, leading to a NullPointerException under high load.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_009"]}, {"name": "Directive Injection Timeline", "type": "forensic_timeline", "clueId": "CLUE_B3_004", "foundBy": "CHAR_001", "reveals": "The error handling mechanism was deliberately sabotaged to trigger a fatal crash instead of graceful recovery.", "description": "Git metadata analysis reveals that a malicious <%@ page errorPage=\"/crash.jsp\" %> directive was injected two hours before the outage, overriding the original safe configuration.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_010"]}, {"name": "Out Object Misuse in Dynamic Output", "type": "code_snippet", "clueId": "CLUE_B3_005", "foundBy": "CHAR_001", "reveals": "The ''out'' implicit object was used improperly, contributing to the server crash during response generation.", "description": "A scriptlet uses ''out.print()'' to inject raw HTML into the response stream after the buffer was flushed, causing an IOException.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_009"]}], "title": "The JSP Heist: A Servlet Sabotage", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The Crash Report", "sceneId": "SCENE_001", "location": "Server Room Control Center", "description": "The detective arrives at the dimly lit server room where alarms are still flashing. Logs show an unexpected JSP compilation failure during peak traffic. Dr. Script and Raj are arguing over root cause. Initial inspection reveals corrupted JSP files and missing error logs.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Code Fragment Analysis", "sceneId": "SCENE_002", "location": "Development Lab", "description": "Inside the secure development lab, the detective examines backup snapshots of the JSP files. Hidden scriptlets and malformed declarations suggest deliberate tampering. Raj claims innocence, while Dr. Script defends her original syntax. A mysterious directive stands out in the page header.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: The Translation Trap", "sceneId": "SCENE_003", "location": "Conference Room Alpha", "description": "All parties gather as the detective reconstructs the timeline of the attack. Using evidence from the translation phase and request processing logs, the truth emerges: a rogue directive triggered a fatal exception that bypassed the error handling page. The suspect is forced to admit their motive.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct Resolution", "title": "The Directive Deception Exposed", "content": "Raj confesses: he inserted a destructive directive to trigger a crash during translation, knowing it would bypass error handling. His goal was to prove JSP’s instability and push for modernization. While his concerns were valid, his methods endangered production systems.", "debrief": "The case highlights the importance of ethical conduct and proper change management. Technological evolution should not come at the cost of system integrity.", "summary": "Sabotage via malicious JSP directive injection revealed. Motive: architectural reform through forced crisis.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect Accusation", "title": "Framing the Architect", "content": "Dr. Script is wrongly blamed for poor coding practices. However, further audit clears her: the damaging code was injected post-approval. The real culprit remains free, and the system stays vulnerable.", "debrief": "Jumping to conclusions without full evidence leads to injustice and unresolved risks. Always verify intent and access logs.", "summary": "False accusation due to incomplete analysis. Root cause unaddressed.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Partial Truth", "title": "Systemic Flaws Acknowledged", "content": "Both parties admit weaknesses: outdated JSP usage and lack of error handling. No individual is held accountable, but improvements are promised. The sabotage remains unsolved.", "debrief": "Acknowledging systemic issues is important, but accountability ensures lasting change.", "summary": "Blame distributed, truth obscured. Educational takeaway emphasized over justice.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}], "logline": "In a high-stakes tech lab, a critical enterprise web application has been sabotaged. The detective must interrogate suspects, uncover hidden code fragments, and trace the digital footprints to expose the culprit who manipulated JSP components to crash the system.", "version": "1.0", "evidence": [{"name": "Corrupted JSP File Backup", "type": "Digital Artifact", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A recovered version of index.jsp containing a malformed scriptlet and an unauthorized page directive pointing to a non-existent error page.", "foundLocation": "Development Lab Server Drive", "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_006"]}, {"name": "Compilation Log Snippet", "type": "System Log", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "Log entry showing a failure during the translation phase due to an invalid directive syntax. Timestamp matches the outage.", "foundLocation": "Application Server Logs", "relatedKnowledge": ["CONC_007", "CONC_006"]}, {"name": "Missing Error Page Configuration", "type": "Configuration File", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "web.xml file lacks the <error-page> entry despite being required by policy. Indicates intentional removal or bypass.", "foundLocation": "Version Control System (Git Repo)", "relatedKnowledge": ["CONC_010", "CONC_008"]}, {"name": "Suspicious Directive Injection", "type": "Code Anomaly", "clueIds": [], "evidenceId": "EVIDENCE_004", "description": "A custom page directive was added to set buffer size to zero, causing immediate flush errors under load.", "foundLocation": "index.jsp - Line 4", "relatedKnowledge": ["CONC_006", "CONC_007"]}], "has_quiz": true, "scriptId": "ESD_MYSTERY_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code reviews the initial crash report and notices that all business logic and UI generation used to be bundled in single Java classes. Which component historically combined request processing, business logic, and response generation—making UI changes difficult without code edits?", "options": [{"content": "Java Server Pages (JSP)", "feedback": "Incorrect. JSP was introduced specifically to separate presentation from logic. It is not the component that originally combined everything.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Servlet", "feedback": "Correct. Servlets traditionally handled all aspects—request processing, business logic, and response generation—in one class, requiring deep Java knowledge for any change.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_004"]}, {"content": "Expression", "feedback": "Incorrect. Expressions are simple output tags in JSP used to display values, not full components for handling requests or logic.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Scriptlet", "feedback": "Incorrect. Scriptlets are blocks of Java code inside JSP pages, but they don’t represent the original architecture that combined all responsibilities.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_001", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "To understand why the system crashed under load, Detective Lin examines the architectural shift. What key advantage does JSP offer over traditional Servlet-only designs?", "options": [{"content": "It allows complete removal of Java from web development.", "feedback": "Incorrect. JSP still uses Java extensively, especially through scriptlets and expressions. It doesn''t eliminate Java.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It separates request processing and business logic from presentation, enabling role specialization.", "feedback": "Correct. JSP enables separation of concerns by placing static HTML in pages and embedding dynamic elements only where needed, allowing designers and developers to work independently.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "It runs faster than Servlets because it compiles at runtime.", "feedback": "Incorrect. Both JSP and Servlets compile to bytecode. JSP adds a translation step, which can slow initial execution slightly.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It eliminates the need for HTTP requests.", "feedback": "Incorrect. JSP operates over HTTP like all web technologies. It does not remove the fundamental client-server communication model.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_002", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code reviews the initial crash report and notices the JSP files failed to compile during peak traffic. She recalls that certain JSP constructs are processed only once at translation time. Which of the following is executed solely during the translation phase and defines class-level members?", "options": [{"content": "<% int count = 0; %>", "feedback": "Incorrect. This is a scriptlet, which runs during each request in the Request Processing Phase, not just once at translation time.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "<%= userName %>", "feedback": "Incorrect. This is an expression, evaluated at runtime for each request to insert dynamic content into the response.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "<%! String appVersion = \"2.1\"; %>", "feedback": "Correct. Declarations enclosed in <%! ... %> are processed once during translation and become class-level variables or methods in the generated servlet.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "<%@ page import=\"java.util.*\" %>", "feedback": "While this directive is processed at translation time, it configures the environment rather than declaring class variables or methods.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Declarations", "knowledgeId": "CONC_005"}, "difficulty": 2, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003", "CONC_007"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "The detective examines server logs showing that the JSP file was converted into a .java servlet source file before the crash. No compilation errors appear. Which phase of JSP processing does this confirm was completed successfully?", "options": [{"content": "Request Processing Phase", "feedback": "Incorrect. The Request Processing Phase occurs after compilation, when the servlet handles actual HTTP requests. Logs suggest this phase failed.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Translation Phase", "feedback": "Correct. The presence of a generated .java file confirms the Translation Phase completed—the JSP was successfully turned into servlet source code.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_003"]}, {"content": "Deployment Phase", "feedback": "There''s no mention of deployment tools or container startup issues. The logs point specifically to translation success and runtime failure.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Initialization Phase", "feedback": "This refers to servlet init() execution, which happens after translation and compilation. The logs don’t indicate whether the servlet initialized.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Translation Phase", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008", "CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin Code reviews the initial crash report and notices that the server failed to display any error message to users. Instead, it returned a blank page. Based on common JSP behavior, which implicit object is primarily responsible for sending dynamic content back to the client''s browser?", "options": [{"content": "request", "feedback": "Incorrect. The ''request'' object contains client-submitted data, but does not handle output rendering.", "optionId": "OPT_B3_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "response", "feedback": "Close, but not quite. While ''response'' configures how data is sent, it doesn''t directly write dynamic content.", "optionId": "OPT_B3_002", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "out", "feedback": "Correct. The ''out'' implicit object (JspWriter) is used to generate dynamic HTML output and send it to the client.", "optionId": "OPT_B3_003", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_003"]}, {"content": "application", "feedback": "No. The ''application'' object represents the ServletContext and is used for application-wide data, not output rendering.", "optionId": "OPT_B3_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Implicit Objects", "knowledgeId": "CONC_009"}, "difficulty": 2, "questionId": "Q_B3_001", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin examines the server logs and sees a NullPointerException involving session data. In JSP, what is the name of the implicit object used to manage user-specific session state across requests?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More About Implicit Objects", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_006", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["session"], "feedbackCorrect": "Correct. The ''session'' implicit object (HttpSession) stores user-specific data across multiple requests.", "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": "Incorrect. Remember, JSP provides several predefined objects. The one that holds user-specific state between requests is called ''session''."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Inside the development lab, Detective Lin isolates a code fragment: <%= request.getAttribute(\"username\") %>. What type of JSP element is this, responsible for inserting evaluated expressions directly into the output?", "options": [{"content": "Scriptlet", "feedback": "Incorrect. Scriptlets use <% ... %> syntax and contain executable Java code, not direct output expressions.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Declaration", "feedback": "Incorrect. Declarations use <%! ... %> and define variables or methods at translation time, not for immediate output.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Expression", "feedback": "Correct. Expressions enclosed in <%= ... %> are evaluated and their string result is inserted directly into the response output stream.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "Directive", "feedback": "Incorrect. Directives (e.g., <%@ page ... %>) configure page behavior during translation and do not produce output.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_B1_003", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_003"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Another fragment shows <% String msg = \"System Online\"; out.println(msg); %>. Detective Lin recognizes this as a block of embedded Java code. What is this construct called?", "options": [{"content": "Expression", "feedback": "Incorrect. Expressions use <%= ... %> and directly insert values. This block contains full Java statements.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Scriptlet", "feedback": "Correct. Scriptlets are enclosed in <% ... %> and allow full Java code execution within a JSP page, often used to control flow or generate output.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "Directive", "feedback": "Incorrect. Directives start with <%@ and affect page configuration, not runtime logic or output.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Action", "feedback": "Incorrect. Actions use standard JSP tags like <jsp:include> and are more structured than raw Java code blocks.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_B1_004", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_004"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "Detective Lin finds a line of code that outputs a dynamic value directly into the HTML: <%= userName %>. What symbol sequence starts and ends a JSP expression like this? Enter the complete delimiter including angle brackets and percent signs.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 2, "questionId": "Q_B1_006", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["<%=", "%>"], "feedbackCorrect": "Correct. JSP expressions are enclosed in <%= and %> to evaluate and insert dynamic content into the output stream.", "relatedKnowledge": ["CONC_003"], "feedbackIncorrect": "Incorrect. Recall that expressions use a special syntax starting with ''<%='' and ending with ''%>'' to distinguish them from scriptlets and directives."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "In the development lab, Detective Lin isolates a suspicious line in the JSP header: <%@ page errorPage=\"null\" %>. She suspects this was added to disable error recovery. What role do such tags play in JSP processing?", "options": [{"content": "They define reusable UI components across multiple pages.", "feedback": "No, that describes JSP actions or tag libraries, not directives. Directives control page-level settings.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They output dynamic values directly into the HTML response.", "feedback": "That’s the function of expressions (<%= ... %>). Directives are instructions for the container, not output generators.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They provide configuration instructions to the JSP container about how to process the page.", "feedback": "Correct. Directives like @page, @include, and @taglib tell the JSP engine how to translate the file, including imports, error handling, and content type.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "They execute Java logic for each incoming HTTP request.", "feedback": "That describes scriptlets. Directives operate at translation time, not per-request.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Directives", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_010"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 6, "content": "While analyzing the corrupted JSP file, Detective Lin finds a hidden scriptlet that throws an exception under high load. She notes that this code runs during the ________ ________, when the generated servlet processes individual HTTP requests.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Request Processing", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["request processing phase", "request processing", "runtime phase"], "feedbackCorrect": "Correct. The Request Processing Phase is where dynamic content is generated per request, and where unhandled exceptions can cause server errors.", "relatedKnowledge": ["CONC_007", "CONC_003"], "feedbackIncorrect": "Incorrect. Think about when Java code inside <% ... %> blocks actually executes—it''s not during translation, but when users access the page."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Inside the development lab, Detective Lin finds a suspicious scriptlet attempting to print the exception message. However, this JSP is not designated as an error page. Why would this code fail during translation?", "options": [{"content": "The ''out'' object cannot print exception messages.", "feedback": "Incorrect. ''out'' can print any string, including exception messages, if properly accessed.", "optionId": "OPT_B3_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The ''exception'' implicit object is only available on pages where isErrorPage=''true''.", "feedback": "Correct. The ''exception'' object is not initialized unless the page is explicitly marked as an error handler with isErrorPage=''true''.", "optionId": "OPT_B3_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_002"]}, {"content": "Exception handling requires try-catch blocks in scriptlets.", "feedback": "Not necessarily. Even with try-catch, the ''exception'' object remains unavailable unless the page is configured as an error page.", "optionId": "OPT_B3_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The request object must first capture the exception.", "feedback": "No. Exceptions are thrown during execution and handled by the container, not captured by the request object.", "optionId": "OPT_B3_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Implicit Objects", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_002", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_010"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Detective Lin discovers that the JSP had an errorPage directive pointing to ''/error/fatal.jsp'', but no such file exists. What will happen when an exception occurs in this JSP?", "options": [{"content": "The server will create a default error page automatically.", "feedback": "Incorrect. If the specified error page is missing, the container cannot redirect and may return a blank or raw error response.", "optionId": "OPT_B3_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The request will proceed to the next available JSP in the directory.", "feedback": "No. There is no fallback mechanism to another random JSP page.", "optionId": "OPT_B3_010", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "The container will fail to redirect, likely resulting in a blank response or HTTP 500.", "feedback": "Correct. Without a valid errorPage target, the exception handling fails silently or returns a server error.", "optionId": "OPT_B3_011", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_001"]}, {"content": "The exception will be logged and then ignored.", "feedback": "Partially true—exceptions are logged—but the response still fails to deliver meaningful output to the user.", "optionId": "OPT_B3_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Error Handling Pages", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_003", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_008"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B3_001", "content": "JSP Translator parses the .jsp file into a servlet template."}, {"itemId": "ITEM_B3_002", "content": "Malicious ''errorPage'' directive is processed, redirecting exceptions to a non-existent page."}, {"itemId": "ITEM_B3_003", "content": "Scriptlet attempts to reference the ''exception'' object despite isErrorPage=''false''."}, {"itemId": "ITEM_B3_004", "content": "Java Compiler fails due to undefined ''exception'' variable, halting translation."}, {"itemId": "ITEM_B3_005", "content": "Container returns incomplete response during request processing under load."}], "order": 5, "content": "Reconstruct the correct sequence of events during the JSP translation phase that led to the crash. Arrange the steps based on forensic evidence from the corrupted file.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More About Implicit Objects", "knowledgeId": "CONC_009"}, "difficulty": 3, "questionId": "Q_B3_005", "knowledgeId": "CONC_009", "maxAttempts": 3, "correctOrder": ["ITEM_B3_001", "ITEM_B3_002", "ITEM_B3_003", "ITEM_B3_004", "ITEM_B3_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence shows how deliberate tampering during translation caused a cascading failure at runtime.", "relatedKnowledge": ["CONC_007", "CONC_010"], "feedbackIncorrect": "Incorrect. Remember: translation happens first, then compilation. The ''exception'' object is only available if the page is marked as an error page."}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "JSP Translator converts .jsp file into Servlet source (.java)"}, {"itemId": "ITEM_B1_002", "content": "Java Compiler generates Servlet Class (.class)"}, {"itemId": "ITEM_B1_003", "content": "Rogue directive disables errorPage during translation"}, {"itemId": "ITEM_B1_004", "content": "JVM executes the servlet to handle incoming request"}, {"itemId": "ITEM_B1_005", "content": "Client request triggers JSP page loading"}], "order": 5, "content": "To prove how the attack unfolded, Detective Lin reconstructs the JSP lifecycle. Arrange these phases in the correct order from source to execution:", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_005", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": ["ITEM_B1_005", "ITEM_B1_001", "ITEM_B1_003", "ITEM_B1_002", "ITEM_B1_004"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence begins with a client request, followed by translation (where sabotage occurs), compilation, and finally execution—proving the vulnerability existed before runtime.", "relatedKnowledge": ["CONC_003", "CONC_006"], "feedbackIncorrect": "Incorrect. Remember: the attack exploited the translation phase. The rogue directive must be injected when the JSP is converted to Java, before compilation and execution."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "During the final confrontation, Detective Lin explains that even though an error page was configured globally, users received raw 500 errors. She demonstrates that a rogue directive disabled per-page error handling. In which phase does the errorPage mechanism normally intercept exceptions?", "options": [{"content": "Translation Phase", "feedback": "No. The Translation Phase converts JSP to Java code but doesn''t handle runtime exceptions. ErrorPage is a runtime feature.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Class Loading Phase", "feedback": "Class loading happens between translation and request processing, but exception interception occurs later, during execution.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Request Processing Phase", "feedback": "Correct. When an uncaught exception occurs during request handling (e.g., in a scriptlet), the container checks for an errorPage directive and forwards control if set.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_004"]}, {"content": "Session Initialization Phase", "feedback": "Session creation is part of request processing, but it''s unrelated to global exception handling via errorPage.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Request Processing Phase", "knowledgeId": "CONC_008"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_008", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_007", "CONC_010"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "JSP Translator generates servlet source (.java)"}, {"itemId": "ITEM_B2_002", "content": "Java Compiler produces servlet class (.class)"}, {"itemId": "ITEM_B2_003", "content": "Container loads and instantiates the servlet"}, {"itemId": "ITEM_B2_004", "content": "HTTP request triggers service() method execution"}, {"itemId": "ITEM_B2_005", "content": "Dynamic response is sent back to client browser"}], "order": 5, "content": "To prove her theory, Detective Lin reconstructs the timeline of JSP processing. Arrange the phases in the correct order from source to response.", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Review JSP Lifecycle Phases", "knowledgeId": "CONC_007"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_007", "maxAttempts": 3, "correctOrder": ["ITEM_B2_001", "ITEM_B2_002", "ITEM_B2_003", "ITEM_B2_004", "ITEM_B2_005"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The sequence follows the full lifecycle: translation → compilation → loading → request processing → response delivery.", "relatedKnowledge": ["CONC_008", "CONC_002"], "feedbackIncorrect": "Incorrect. Remember: the JSP must first be translated to Java, then compiled, loaded, and finally executed when a request arrives."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "During the final confrontation, Detective Lin proves that Raj injected a rogue directive to sabotage the system. Which combination of directives would allow an attacker to both disable normal error handling and expose sensitive exception details?", "options": [{"content": "errorPage=\"null\" and session=\"false\"", "feedback": "Invalid syntax. ''errorPage'' cannot be set to ''null''; it expects a URL path.", "optionId": "OPT_B3_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "errorPage=\"/crash.jsp\" and isErrorPage=\"true\"", "feedback": "Correct. Setting a malicious errorPage and enabling isErrorPage allows interception and exposure of exceptions.", "optionId": "OPT_B3_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B3_004"]}, {"content": "import=\"java.lang.Exception\" and buffer=\"none\"", "feedback": "Irrelevant. Importing Exception doesn''t enable error handling; buffer settings affect performance, not security.", "optionId": "OPT_B3_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "contentType=\"text/plain\" and autoFlush=\"true\"", "feedback": "These control output format and buffering, not error redirection or exception access.", "optionId": "OPT_B3_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More About Error Handling Pages", "knowledgeId": "CONC_010"}, "difficulty": 3, "questionId": "Q_B3_004", "knowledgeId": "CONC_010", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006", "CONC_009"], "feedbackIncorrect": null}], "characters": [{"age": 34, "goal": "Uncover the truth behind the sabotage using technical forensics and logical deduction.", "name": "Detective Lin Code", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Once worked at the same company years ago but left after a failed deployment caused by poor JSP design.", "background": "Former software engineer turned digital crime investigator with deep knowledge of enterprise architectures.", "occupation": "Cyber Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and curious.", "knowledgePoints": ["CONC_001", "CONC_002", "CONC_009"]}, {"age": 41, "goal": "Protect her reputation and prove that the architecture wasn’t at fault.", "name": "Dr. Elena Script", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "She secretly disabled automated testing on JSP pages to meet a tight deadline.", "background": "Pioneer in legacy-to-modern migration projects; known for elegant but complex JSP designs.", "occupation": "Lead JSP Architect", "characterId": "CHAR_002", "personality": "Precise, defensive about her coding style, values tradition over modern frameworks.", "knowledgePoints": ["CONC_001", "CONC_003", "CONC_005", "CONC_006"]}, {"age": 29, "goal": "Expose the fragility of JSP so the company will adopt modern alternatives.", "name": "Raj Servleti", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He injected a malicious directive into a JSP file to force a system failure and justify rewriting the entire frontend.", "background": "Advocate for microservices; believes JSP is outdated and wants to replace it with RESTful APIs.", "occupation": "Backend Integration Developer", "characterId": "CHAR_003", "personality": "Idealistic, impatient with legacy systems, speaks in metaphors about ''clean breaks''.", "knowledgePoints": ["CONC_002", "CONC_006", "CONC_007", "CONC_008"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Java Server Pages (JSP)", "category": "Core Technology", "appearsIn": ["SCENE_001", "SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A technology that allows developers to create dynamically generated web pages based on HTML, XML, or other document types. JSP runs on the server side and can include Java code embedded within tags.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_006"]}, {"name": "Servlet", "category": "Core Component", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 2, "description": "A Java class that runs on the server side to process and respond to client requests, often used as controllers in web applications. JSPs are compiled into servlets during execution.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_008", "CONC_009"]}, {"name": "Scriptlet", "category": "JSP Element", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "A block of Java code embedded in a JSP page, enclosed between <% and %>. Executed during the request processing phase.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_008", "CONC_009"]}, {"name": "Expression", "category": "JSP Element", "appearsIn": ["SCENE_002"], "difficulty": 1, "description": "A JSP element that evaluates a Java expression and outputs the result directly into the response, enclosed in <%= and %>", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_001", "CONC_009"]}, {"name": "Declaration", "category": "JSP Element", "appearsIn": ["SCENE_002"], "difficulty": 2, "description": "Used to declare variables or methods in a JSP page, enclosed in <%! and %>. These are translated into class-level members in the resulting servlet.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Directive", "category": "JSP Element", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "Instructions processed by the JSP engine during translation. Common types include page, include, and taglib directives.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_001", "CONC_007", "CONC_010"]}, {"name": "Translation Phase", "category": "Lifecycle", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 3, "description": "The phase where a JSP page is converted into its corresponding servlet source code by the container before compilation.", "knowledgeId": "CONC_007", "relatedKnowledge": ["CONC_001", "CONC_006", "CONC_008"]}, {"name": "Request Processing Phase", "category": "Lifecycle", "appearsIn": ["SCENE_003"], "difficulty": 3, "description": "After translation and compilation, this phase involves executing the servlet''s service method to handle incoming HTTP requests and generate dynamic responses.", "knowledgeId": "CONC_008", "relatedKnowledge": ["CONC_002", "CONC_003", "CONC_007"]}, {"name": "Implicit Objects", "category": "Runtime Environment", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "Predefined variables in JSP that allow easy access to data associated with the request, response, session, and application context without explicit declaration.", "knowledgeId": "CONC_009", "relatedKnowledge": ["CONC_001", "CONC_002", "CONC_003"]}, {"name": "Error Handling Page", "category": "Exception Management", "appearsIn": ["SCENE_003"], "difficulty": 2, "description": "A designated JSP page configured to catch and display custom error messages when exceptions occur during request processing.", "knowledgeId": "CONC_010", "relatedKnowledge": ["CONC_006", "CONC_008", "CONC_009"]}], "educational_goals": ["Understand the structure and lifecycle of Java Server Pages (JSP)", "Differentiate between JSP elements such as scriptlets, expressions, declarations, and directives", "Explain the role of servlets in processing requests and responses", "Identify how implicit objects function within JSP and servlet environments", "Trace the translation and request processing phases of JSP execution", "Implement proper error handling mechanisms in JSP applications"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', '1bdff197cf420ba37077550e43a447545031b543c3e60a947db5fb0532f5ffb1', 'all concepts', '2026-04-17 13:11:54.38325', NULL, 'ITP4511') ON CONFLICT DO NOTHING;
INSERT INTO scripts (id, user_id, course_id, subject_id, content_item_id, content_parse_id, template_id, source_id, title, status, difficulty_level, target_level, outline_json, document_hash, module_name, created_at, completed_at, subject_code) VALUES ('db0f199e-6c4b-481d-b8d1-f7b8b7835360', '00000000-0000-0000-0000-000000000003', NULL, NULL, NULL, NULL, '775750a3-f2d8-43df-a3be-13cfaa0a83a3', NULL, 'The Case of the Crashed Cluster', 'active', 'easy', 'standard', '{"clues": [{"name": "Eureka Server Log Entry", "type": "document", "clueId": "CLUE_B1_001", "foundBy": "CHAR_001", "reveals": "One critical service failed to register with the naming server, preventing discovery by other services.", "description": "A log snippet from the Eureka server showing only two services registered at startup. The ''payment-service'' is missing despite being required for cluster operation.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_001", "CONC_003"]}, {"name": "Configuration Fragment", "type": "code", "clueId": "CLUE_B1_002", "foundBy": "CHAR_001", "reveals": "Someone intentionally disabled service registration in a deployment configuration.", "description": "A YAML configuration block recovered from a temporary file: eureka.client.register-with-eureka: false. This disables automatic registration with the Eureka server.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "Terminal Command History", "type": "log", "clueId": "CLUE_B1_003", "foundBy": "CHAR_001", "reveals": "A developer bypassed service discovery by using hardcoded URLs, increasing fragility.", "description": "Raj’s terminal history shows repeated use of WebClient.create(''http://localhost:8080'') instead of leveraging service discovery for dynamic routing.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "Architectural Directive Memo", "type": "document", "clueId": "CLUE_B1_004", "foundBy": "CHAR_001", "reveals": "Moss had motive and authority to disable a service she deemed non-compliant.", "description": "An internal memo signed by Dr. Moss states: ''All non-compliant services will be isolated until alignment with Harmony Framework standards.'' Sent one day before the outage.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_001", "CONC_002"]}, {"name": "Service Startup Sequence Diagram", "type": "diagram", "clueId": "CLUE_B1_005", "foundBy": "CHAR_001", "reveals": "The service ran but did not complete registration, indicating a configuration issue rather than failure to launch.", "description": "Whiteboard sketch found in lab showing correct startup order: Eureka Server → Provider Services → Consumer Services. The payment-service was started but never appears in registry.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "WebClient Usage Report", "type": "report", "clueId": "CLUE_B1_006", "foundBy": "CHAR_001", "reveals": "Widespread bypassing of service discovery mechanisms weakened system resilience.", "description": "System audit shows that 70% of inter-service calls in the last week used WebClient with direct URLs instead of load-balanced clients integrated with Eureka.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "Service Independence Log Fragment", "type": "Document", "clueId": "CLUE_B2_001", "foundBy": "CHAR_001", "reveals": "Evidence that services were designed to operate independently, supporting a microservices architecture.", "description": "A torn log entry recovered from Raj''s workstation showing timestamps of independent service startups with no central coordination.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_005"]}, {"name": "Spring Boot Startup Trace", "type": "System Log", "clueId": "CLUE_B2_002", "foundBy": "CHAR_001", "reveals": "Confirms that individual services are built using Spring Boot as self-contained mini-servers.", "description": "A debug trace showing SpringApplication.run() initializing a standalone server instance for the admission-service on port 8082.", "foundInScene": "SCENE_001", "relatedKnowledge": ["CONC_006"]}, {"name": "Eureka Client Configuration Snippet", "type": "Code Fragment", "clueId": "CLUE_B2_003", "foundBy": "CHAR_001", "reveals": "Proof that services are expected to register with Eureka, but this particular service may have bypassed it.", "description": "A YAML configuration file found in version control history: ''eureka.client.serviceUrl.defaultZone: http://localhost:8761/eureka''.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006", "CONC_005"]}, {"name": "Startup Sequence Anomaly Report", "type": "Diagnostic Output", "clueId": "CLUE_B2_004", "foundBy": "CHAR_001", "reveals": "Suggests a flaw in deployment sequencing rather than intentional sabotage.", "description": "Automated system report indicating that student-service started before the Eureka server was fully online, leading to failed registration attempt.", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_005"]}, {"name": "Architectural Design Blueprint", "type": "Diagram", "clueId": "CLUE_B2_005", "foundBy": "CHAR_001", "reveals": "Dr. Moss’s own design emphasizes decoupling and independent deployment—principles violated during the incident.", "description": "Official framework diagram titled ''Harmony Microservices Architecture'' showing discrete services communicating via REST APIs.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005"]}, {"name": "Failed Registration Alert", "type": "Alert Log", "clueId": "CLUE_B2_006", "foundBy": "CHAR_001", "reveals": "Direct evidence of a critical failure in the service discovery mechanism.", "description": "High-severity alert: ''Service [admission-service] failed to register with Discovery Server within 30 seconds of startup.''", "foundInScene": "SCENE_002", "relatedKnowledge": ["CONC_006"]}, {"name": "Post-Mortem Deployment Script", "type": "Script File", "clueId": "CLUE_B2_007", "foundBy": "CHAR_001", "reveals": "Raj prioritized speed over coordination, risking service availability.", "description": "A bash script used to launch services individually without waiting for dependencies: ''nohup java -jar *.jar &''.", "foundInScene": "SCENE_003", "relatedKnowledge": ["CONC_005", "CONC_006"]}], "title": "The Case of the Crashed Cluster", "scenes": [{"act": 1, "clues": [], "order": 1, "title": "The System Goes Dark", "sceneId": "SCENE_001", "location": "Server Room Control Center", "description": "Lights flicker as alarms blare. The central dashboard shows all microservices offline. The body of the chief engineer lies near the main console. Detective Lin Chen arrives as Raj Patel is trying to reboot the cluster. Initial signs point to a cascading failure—but was it accidental or deliberate?", "charactersPresent": ["CHAR_001", "CHAR_003"]}, {"act": 2, "clues": [], "order": 2, "title": "Tracing the Failure Chain", "sceneId": "SCENE_002", "location": "Development Lab", "description": "Lin examines logs and configuration files. Dr. Moss arrives, insisting on protocol compliance. Tensions rise as evidence suggests a missing service registration. Raj defends his use of WebClient over blocking calls. A turning point emerges: one service never registered with Eureka.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}, {"act": 3, "clues": [], "order": 3, "title": "Final Confrontation: Who Killed the Cluster?", "sceneId": "SCENE_003", "location": "Conference Room Alpha", "description": "All suspects gather as Lin presents findings. The fatal flaw: a service failed to register, causing discovery failure across the board. Motives are exposed. Was it Moss’s sabotage? Raj’s shortcut? Or something else? The truth hinges on understanding how Eureka, registration, and discovery interact in Spring Boot microservices.", "charactersPresent": ["CHAR_001", "CHAR_002", "CHAR_003"]}], "endings": [{"type": "Correct", "title": "Truth Revealed: Sabotage in the Stack", "content": "Dr. Moss is exposed. Her decision to disable Service-Y’s registration broke the discovery chain. Without Eureka knowing its location, dependent services failed, causing a cascade. Raj’s WebClient usage was risky but not fatal. Moss acted to discredit a competing team, not realizing the dependency web.", "debrief": "This case illustrates how critical proper service registration and discovery are in microservices. Even one missing registration can collapse an entire system.", "summary": "The murder was virtual—the victim was the system. The real crime was architectural negligence masked as control.", "endingId": "ENDING_001", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "requiredQuestions": []}}, {"type": "Incorrect", "title": "False Accusation: The Fall Guy", "content": "Raj is blamed for using WebClient improperly. He is suspended. But weeks later, another outage occurs following a similar pattern—proving the root cause was never fixed.", "debrief": "Jumping to conclusions without full system understanding leads to misdiagnosis. WebClient isn''t the enemy—poor service registration is.", "summary": "Blaming tools instead of processes only delays the inevitable failure.", "endingId": "ENDING_002", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001", "SCENE_002"], "requiredQuestions": []}}, {"type": "Incomplete", "title": "Case Closed: System Error", "content": "The investigation ends with ''system malfunction'' as the official cause. No individual is held responsible. Morale drops. Development stalls.", "debrief": "Without deep analysis of service interactions, organizations remain vulnerable to repeat failures.", "summary": "When no one takes responsibility, the system stays broken.", "endingId": "ENDING_003", "unlockConditions": {"requiredClues": [], "requiredScenes": ["SCENE_001"], "requiredQuestions": []}}], "logline": "In a high-stakes tech summit held inside a secure server room, a lead architect is found dead under mysterious circumstances—players must use their knowledge of enterprise systems development to uncover the truth behind the fatal system collapse.", "version": "1.0", "evidence": [{"name": "Corrupted Registration Log", "type": "Digital Log", "clueIds": [], "evidenceId": "EVIDENCE_001", "description": "A log file showing that Service-X failed to register with Eureka during startup. Timestamp matches the outage.", "foundLocation": "Development Lab Terminal", "relatedKnowledge": ["CONC_003", "CONC_001"]}, {"name": "Unauthorized WebClient Script", "type": "Code Snippet", "clueIds": [], "evidenceId": "EVIDENCE_002", "description": "A script written by Raj that makes direct HTTP calls without checking service availability through Eureka.", "foundLocation": "Engineer''s Laptop", "relatedKnowledge": ["CONC_004", "CONC_002"]}, {"name": "Shutdown Directive Email", "type": "Email Archive", "clueIds": [], "evidenceId": "EVIDENCE_003", "description": "An encrypted email from Dr. Moss instructing a temporary disable of Service-Y’s registration for ''testing''. Sent minutes before the crash.", "foundLocation": "Secure Mail Server", "relatedKnowledge": ["CONC_001", "CONC_003"]}], "has_quiz": false, "scriptId": "ESD_MURDER_001", "questions": [{"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Detective Lin examines the central dashboard. All microservices are offline, but the first clue lies in understanding how they locate each other. What is the primary role of the Eureka naming server in this architecture?", "options": [{"content": "To authenticate API requests between services using OAuth tokens.", "feedback": "Incorrect. While security is important, Eureka''s main function isn''t authentication. It acts as a registry for service locations.", "optionId": "OPT_B1_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To serve as a central registry where microservices register their network addresses so others can discover them.", "feedback": "Correct. The Eureka Server is a Discovery Server that maintains a registry of all running service instances, including IP addresses and ports.", "optionId": "OPT_B1_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_001"]}, {"content": "To compress HTTP payloads between services to improve performance.", "feedback": "Incorrect. Payload compression is handled separately. Eureka focuses on service location and availability tracking.", "optionId": "OPT_B1_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "To store application logs from all microservices in a centralized database.", "feedback": "Incorrect. Log aggregation would typically be handled by tools like ELK or Splunk. Eureka manages service registration and discovery.", "optionId": "OPT_B1_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 2, "questionId": "Q_B1_001", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "Lin reviews the system design. Before any service can receive traffic, it must announce its presence. What is this process called when a microservice registers itself with the Eureka server?", "options": [{"content": "Service Binding", "feedback": "Close, but not the standard term. The correct technical term is ''Service Registration''.", "optionId": "OPT_B1_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Service Discovery", "feedback": "Incorrect. Service Discovery is what happens when one service looks up another. Registration comes first—services must register before they can be discovered.", "optionId": "OPT_B1_006", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Service Registration", "feedback": "Correct. Service Registration is the process by which a microservice sends its metadata (like IP and port) to the Eureka server to become available for discovery.", "optionId": "OPT_B1_007", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_002"]}, {"content": "Load Balancing", "feedback": "Incorrect. Load balancing distributes requests across instances. It depends on registration and discovery but is not the same process.", "optionId": "OPT_B1_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 2, "questionId": "Q_B1_002", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 7, "content": "Detective Lin checks the default port for the Eureka naming server. To access the dashboard, she navigates to http://localhost:[blank]/. What port number does Eureka typically use?", "options": null, "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_001"}, "difficulty": 3, "questionId": "Q_B1_007", "knowledgeId": "CONC_001", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["8761"], "feedbackCorrect": "Correct. The Eureka Server defaults to port 8761, a key detail for accessing its management interface and verifying service registrations.", "relatedKnowledge": ["CONC_003"], "feedbackIncorrect": "Incorrect. While common web ports like 8080 or 80 are tempting guesses, Eureka specifically uses port 8761 by convention in Spring Cloud setups."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 1, "content": "Lin Chen reviews the initial system logs. She notices each service—student-service, module-service, admission-service—started independently and communicates via REST calls. What architectural style does this suggest?", "options": [{"content": "Monolithic Architecture", "feedback": "Incorrect. In monolithic architectures, all components run as a single process. Here, services start separately and communicate over REST, which is characteristic of microservices.", "optionId": "OPT_B2_001", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Microservices Architecture", "feedback": "Correct. The system uses loosely coupled services that communicate via REST APIs and can be deployed independently—hallmarks of microservices.", "optionId": "OPT_B2_002", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_001"]}, {"content": "Client-Server Model", "feedback": "Close, but not quite. While HTTP is involved, the key detail is multiple independent services with decentralized control—this goes beyond basic client-server.", "optionId": "OPT_B2_003", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Event-Driven Architecture", "feedback": "No. There''s no mention of event queues or asynchronous message passing. Communication appears to be direct REST-based requests between services.", "optionId": "OPT_B2_004", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_001", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 2, "content": "While examining the crash dump, Lin spots SpringApplication.run() being called in each JAR file. What does this indicate about how these services are built?", "options": [{"content": "They are traditional WAR files deployed on Tomcat.", "feedback": "Incorrect. WAR files require external servlet containers. The presence of SpringApplication.run() suggests embedded servers typical of Spring Boot applications.", "optionId": "OPT_B2_005", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Each service is a standalone Spring Boot application.", "feedback": "Correct. Spring Boot allows each microservice to run as its own mini-server with an embedded container, which matches what''s seen in the logs.", "optionId": "OPT_B2_006", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_002"]}, {"content": "They rely on a central application server.", "feedback": "No. Centralized servers are more typical of monoliths. These services are starting independently, indicating decentralization.", "optionId": "OPT_B2_007", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "They use Node.js backend processes.", "feedback": "Unlikely. The code signature points clearly to Java and Spring Boot, not JavaScript runtime environments.", "optionId": "OPT_B2_008", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_001", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_002", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_005"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Dr. Moss insists that all services follow protocol. Lin asks: if Service A wants to call Service B, how does it find the correct instance? Which process enables this lookup?", "options": [{"content": "Service Registration", "feedback": "Incorrect. Registration is what Service B does when it starts up. Service A needs to discover where Service B is running.", "optionId": "OPT_B1_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Service Discovery", "feedback": "Correct. Service Discovery allows a client service to query the Eureka server for available instances of a target service, enabling dynamic routing without hardcoding addresses.", "optionId": "OPT_B1_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_003"]}, {"content": "Instance Mirroring", "feedback": "Incorrect. This is not a standard microservices concept. The correct mechanism is Service Discovery via the Eureka server.", "optionId": "OPT_B1_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Port Forwarding", "feedback": "Incorrect. Port forwarding is a networking technique, not the method used for locating services in a dynamic cloud environment.", "optionId": "OPT_B1_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 3, "questionId": "Q_B1_003", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Lin analyzes Raj’s code. He used WebClient to make HTTP calls directly to ''http://localhost:8080/payment''. Why is this problematic in a microservices architecture with Eureka?", "options": [{"content": "WebClient only works with XML data, not JSON used by microservices.", "feedback": "Incorrect. WebClient fully supports JSON serialization and is widely used in modern Spring applications.", "optionId": "OPT_B1_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It uses blocking I/O, causing thread starvation under high load.", "feedback": "Partially true, but not the main architectural flaw here. The bigger issue is coupling to a fixed address.", "optionId": "OPT_B1_014", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "It hardcodes the service location, bypassing Eureka-based service discovery and eliminating failover capability.", "feedback": "Correct. By using a direct URL, the service loses the benefits of dynamic discovery and load balancing. If the target instance fails, there’s no automatic redirection to a healthy one.", "optionId": "OPT_B1_015", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_006"]}, {"content": "WebClient cannot be used inside Docker containers due to security restrictions.", "feedback": "Incorrect. WebClient works perfectly within containerized environments and is commonly used in cloud-native apps.", "optionId": "OPT_B1_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_004"}, "difficulty": 4, "questionId": "Q_B1_004", "knowledgeId": "CONC_004", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002", "CONC_003"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B1_001", "content": "Provider services register with Eureka Server"}, {"itemId": "ITEM_B1_002", "content": "Consumer services query Eureka to discover providers"}, {"itemId": "ITEM_B1_003", "content": "Eureka Server starts and listens on port 8761"}, {"itemId": "ITEM_B1_004", "content": "Applications configure eureka.client.service-url.defaultZone"}], "order": 6, "content": "Lin reconstructs the proper startup sequence for a resilient microservices cluster. Arrange these steps in the correct order:", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_003"}, "difficulty": 3, "questionId": "Q_B1_006", "knowledgeId": "CONC_003", "maxAttempts": 3, "correctOrder": ["ITEM_B1_003", "ITEM_B1_004", "ITEM_B1_001", "ITEM_B1_002"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The Eureka Server must start first, followed by client configuration, service registration, and finally discovery by consumers.", "relatedKnowledge": ["CONC_001", "CONC_002"], "feedbackIncorrect": "Incorrect. Remember: the server must be running before clients can register. Configuration precedes registration. Discovery happens last, once services are registered."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 3, "content": "Lin discovers a configuration file where ''eureka.client.serviceUrl.defaultZone'' points to localhost:8761, but the service never registers. Which concept is most directly compromised here?", "options": [{"content": "REST API Communication", "feedback": "While REST is used later, the immediate issue is that the service isn''t even registering—so it can''t communicate at all.", "optionId": "OPT_B2_009", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Service Discovery Capability", "feedback": "Correct. Without registration, other services cannot discover it via Eureka, breaking the entire discovery mechanism.", "optionId": "OPT_B2_010", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_006"]}, {"content": "Database Connection Pooling", "feedback": "There''s no evidence of database issues. The logs show startup success except for registration failure.", "optionId": "OPT_B2_011", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Load Balancer Configuration", "feedback": "Load balancing depends on discovery, but the root problem is registration—not distribution of traffic.", "optionId": "OPT_B2_012", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_003", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_002"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 4, "content": "Dr. Moss insists her Harmony Framework ensures stability through strict design rules. Yet Lin finds a diagram showing services like student-service and admission-service operating independently. What principle of microservices does this support?", "options": [{"content": "Tight Coupling", "feedback": "No. Tight coupling would mean services depend heavily on each other’s internal workings. Independence suggests the opposite.", "optionId": "OPT_B2_013", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Decoupling and Independent Deployment", "feedback": "Correct. The ability to deploy and scale services independently is a core benefit of microservices architecture.", "optionId": "OPT_B2_014", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_005"]}, {"content": "Shared Memory Access", "feedback": "Not applicable. Microservices avoid shared memory; they communicate via network protocols like REST.", "optionId": "OPT_B2_015", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Centralized Authentication", "feedback": "While possible, there''s no mention of auth systems here. The focus is on structural independence.", "optionId": "OPT_B2_016", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_004", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001"], "feedbackIncorrect": null}, {"type": "sequencing", "hints": [], "items": [{"itemId": "ITEM_B2_001", "content": "Start Provider Services (e.g., student-service)"}, {"itemId": "ITEM_B2_002", "content": "Launch Eureka Discovery Server"}, {"itemId": "ITEM_B2_003", "content": "Start Consumer Service (e.g., admission-service)"}], "order": 6, "content": "To prevent future failures, Lin reconstructs the correct startup sequence for the microservices environment. Arrange the steps in the proper order.", "options": null, "sceneId": "SCENE_002", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_006"}, "difficulty": 3, "questionId": "Q_B2_006", "knowledgeId": "CONC_006", "maxAttempts": 3, "correctOrder": ["ITEM_B2_002", "ITEM_B2_001", "ITEM_B2_003"], "masteryReward": null, "correctAnswers": null, "feedbackCorrect": "Correct. The Eureka server must be running first so providers can register. Consumers then discover and call providers through the registry.", "relatedKnowledge": ["CONC_005", "CONC_002"], "feedbackIncorrect": "Incorrect. Without the Eureka server running first, services cannot register or be discovered. Always start the discovery server before any microservice."}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "In the final confrontation, Lin must determine who caused the cascade failure. Which combination best explains how the system collapsed?", "options": [{"content": "The Eureka server crashed first, causing all services to lose communication.", "feedback": "Incorrect. Logs show the Eureka server remained online. The issue was not server failure but incomplete registration.", "optionId": "OPT_B1_017", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "A critical service failed to register with Eureka due to a disabled setting, so others couldn’t discover it—leading to cascading timeouts.", "feedback": "Correct. The root cause was a service that started but didn’t register (due to eureka.client.register-with-eureka: false), making it invisible to consumers and triggering failures across dependent services.", "optionId": "OPT_B1_018", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B1_004"]}, {"content": "Raj’s use of WebClient caused a memory leak that brought down the entire JVM cluster.", "feedback": "Incorrect. While misuse of WebClient weakens resilience, there’s no evidence of memory leaks. The core issue was service visibility, not resource exhaustion.", "optionId": "OPT_B1_019", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Network firewall rules were updated, blocking all traffic on port 8761.", "feedback": "Incorrect. Network monitoring shows port 8761 was accessible. The Eureka server responded to queries—it just had incomplete registration data.", "optionId": "OPT_B1_020", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_002"}, "difficulty": 4, "questionId": "Q_B1_005", "knowledgeId": "CONC_002", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_001", "CONC_003", "CONC_004"], "feedbackIncorrect": null}, {"type": "multiple_choice", "hints": [], "items": null, "order": 5, "content": "During the final confrontation, Lin argues that the cluster collapse wasn’t due to malicious sabotage, but flawed deployment practices. Which action most likely caused the initial registration failure?", "options": [{"content": "Using WebClient instead of RestTemplate", "feedback": "WebClient is non-blocking and modern—it improves performance. It doesn’t affect service registration with Eureka.", "optionId": "OPT_B2_017", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Starting services before the Eureka server was ready", "feedback": "Correct. If services start too early, they fail to register. This creates a cascade where dependent services cannot locate their peers.", "optionId": "OPT_B2_018", "showHint": null, "isCorrect": true, "unlockClues": ["CLUE_B2_004"]}, {"content": "Writing code in Java instead of Go", "feedback": "Language choice is irrelevant here. Spring Boot Java apps are perfectly valid for microservices.", "optionId": "OPT_B2_019", "showHint": null, "isCorrect": false, "unlockClues": []}, {"content": "Using JSON instead of XML", "feedback": "Data format doesn’t impact registration. Both are supported by Spring Boot and Eureka clients.", "optionId": "OPT_B2_020", "showHint": null, "isCorrect": false, "unlockClues": []}], "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_005", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": null, "feedbackCorrect": null, "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": null}, {"type": "fill_in_blank", "hints": [], "items": null, "order": 7, "content": "Lin concludes: ''The system didn’t fail because of one person’s intent—it failed because a core principle of microservices was ignored: __________ deployment.''", "options": null, "sceneId": "SCENE_003", "learnMore": {"buttonText": "Learn More", "knowledgeId": "CONC_005"}, "difficulty": 3, "questionId": "Q_B2_007", "knowledgeId": "CONC_005", "maxAttempts": 3, "correctOrder": null, "masteryReward": null, "correctAnswers": ["independent", "Independent"], "feedbackCorrect": "Correct. Independent deployment is a cornerstone of microservices. When services are rushed into production without regard for dependency readiness, cascading failures occur.", "relatedKnowledge": ["CONC_006"], "feedbackIncorrect": "Incorrect. Think about what makes microservices resilient: their ability to be developed, tested, and deployed independently—but only when done correctly."}], "characters": [{"age": 38, "goal": "Uncover the truth behind the architect''s death and prevent further system failures.", "name": "Detective Lin Chen", "role": "Protagonist", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "Lin once caused a minor service outage due to misconfigured service registration during training but covered it up.", "background": "A seasoned investigator with expertise in digital infrastructure crimes, recently transferred to the Tech Crime Division after solving the Cloud Breach case.", "occupation": "Cyber Forensics Investigator", "characterId": "CHAR_001", "personality": "Analytical, calm under pressure, methodical, and deeply curious about system design flaws.", "knowledgePoints": ["CONC_005", "CONC_004"]}, {"age": 45, "goal": "Protect her reputation and ensure her framework is not blamed for the crash.", "name": "Dr. Elena Moss", "role": "Suspect", "scenes": ["SCENE_002", "SCENE_003"], "secret": "She secretly disabled a critical service registration to sabotage a rival team''s deployment, which may have triggered the cascade failure.", "background": "Creator of the ''Harmony Framework'' used across the company’s microservices. Known for her strict adherence to architectural purity.", "occupation": "Lead Enterprise Architect", "characterId": "CHAR_002", "personality": "Brilliant but rigid, intolerant of shortcuts, commands respect through technical authority.", "knowledgePoints": ["CONC_001", "CONC_002"]}, {"age": 32, "goal": "Clear his name and show that innovation shouldn’t be punished.", "name": "Raj Patel", "role": "Suspect", "scenes": ["SCENE_001", "SCENE_002", "SCENE_003"], "secret": "He bypassed Eureka registration in a test environment to speed up deployment, leaving a backdoor that could have been exploited.", "background": "Self-taught coder who rose quickly by automating deployment pipelines. Favored modern reactive patterns using WebClient.", "occupation": "Junior DevOps Engineer", "characterId": "CHAR_003", "personality": "Energetic, idealistic, eager to prove himself, sometimes reckless with legacy protocols.", "knowledgePoints": ["CONC_003", "CONC_006"]}], "puzzleConfig": {"timeLimit": null, "hintPenalty": 10, "masteryRewardBase": 2, "maxAttemptsDefault": 3}, "knowledgeBase": [{"name": "Eureka Naming Server", "category": "Service Discovery", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "A service registry that enables microservices to locate each other dynamically in a distributed system.", "knowledgeId": "CONC_001", "relatedKnowledge": ["CONC_002", "CONC_003"]}, {"name": "Service Discovery", "category": "Communication", "appearsIn": ["SCENE_002", "SCENE_003"], "difficulty": 2, "description": "The process by which client services find available instances of other services via a registry like Eureka.", "knowledgeId": "CONC_002", "relatedKnowledge": ["CONC_001", "CONC_005"]}, {"name": "Service Registration", "category": "Registration", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 2, "description": "The act of a microservice announcing its presence and network location to a naming server upon startup.", "knowledgeId": "CONC_003", "relatedKnowledge": ["CONC_001", "CONC_006"]}, {"name": "WebClient", "category": "Client Communication", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 3, "description": "A non-blocking, reactive client for performing HTTP requests in Spring applications, preferred in microservices for scalability.", "knowledgeId": "CONC_004", "relatedKnowledge": ["CONC_005", "CONC_006"]}, {"name": "Microservices Architecture", "category": "Architecture", "appearsIn": ["SCENE_001", "SCENE_003"], "difficulty": 1, "description": "A design approach where an application is composed of small, independent services that communicate over defined APIs.", "knowledgeId": "CONC_005", "relatedKnowledge": ["CONC_002", "CONC_004"]}, {"name": "Spring Boot", "category": "Framework", "appearsIn": ["SCENE_001", "SCENE_002"], "difficulty": 1, "description": "A framework that simplifies the setup and development of Spring-based applications, especially microservices.", "knowledgeId": "CONC_006", "relatedKnowledge": ["CONC_003", "CONC_004"]}], "educational_goals": ["Understand the role and function of Eureka Naming Server in microservices architecture", "Explain service discovery and registration mechanisms", "Differentiate WebClient from traditional REST clients", "Apply Spring Boot principles in distributed systems", "Analyze how microservices communicate and register within an ecosystem"], "template_difficulty": {"puzzle_mcq": 10, "puzzle_fill": 2, "puzzle_sorting": 2}}', 'f3e0e48674b25417b2ed125f729b96c971270e51ab3f496b5ca1dfed96494fce', 'all concepts', '2026-04-28 06:43:38.769173', NULL, 'ITP4511') ON CONFLICT DO NOTHING;

