INSERT INTO user_learn_later VALUES ('e1022b86-6f98-432f-ad35-ca7653e32f17', '00000000-0000-0000-0000-000000000003', 'CONC_001', 'db0f199e-6c4b-481d-b8d1-f7b8b7835360', NULL, 'Q_B1_001', '2026-04-28 07:55:08.92496', false, NULL, 0, 0, NULL, '{"0": "{", "1": "}", "chatted": true}', '<ul><li><p><span style="color: rgb(236, 106, 106);"><strong>Microservices + Eureka</strong> = Many specialized counters (one for payments, one for inventory, one for shipping). Each counter has its own phone number (IP + port).</span></p></li></ul><p><span style="color: rgb(236, 106, 106);"><strong>Here''s where Eureka comes in:</strong></span></p><ul><li><p>The <strong>Eureka Server</strong> is like a <strong>store directory</strong> at the <span style="color: rgb(215, 147, 147);">entrance. </span>It lists: <em>"Payment counter at booth 5, Shipping counter at booth 12, Inventory counter at booth 3."</em></p></li><li><p>When a new counter opens (a new service starts), it <strong>registers</strong> its phone number with the directory.</p></li><li><p>When the Payment counter needs to call Shipping, it asks the directory: <em>"Where''s Shipping?"</em> → Gets booth 12 → Calls directly.</p></li></ul><p><strong>Your turn:</strong> If the Shipping counter crashes and a new one starts at booth 7 instead of 12, what do you think happens in the Eureka system?</p>', 'unfamiliar', '2026-04-28 08:00:59.917173') ON CONFLICT DO NOTHING;
