INSERT INTO user_learn_later VALUES ('0f193691-e858-46b5-9088-b64dcc628b0d', '00000000-0000-0000-0000-000000000003', 'CONC_013', '941a5400-dfea-46da-a9de-73762beaf60b', NULL, NULL, '2026-04-26 02:18:40.465613', false, NULL, 27, 0, NULL, '{"chatted": true}', '<p><strong>用 </strong><code>Statement</code><strong>：</strong><br>每次都要拼接一个完整的SQL字符串。</p><ul><li><p>第1次：<code>"INSERT INTO log (message) VALUES (''启动成功'')"</code></p></li><li><p>第2次：<code>"INSERT INTO log (message) VALUES (''用户登录'')"</code></p></li><li><p>...</p></li><li><p>第1000次：<code>"INSERT INTO log (message) VALUES (''系统关闭'')"</code></p></li></ul><p>数据库每次收到都是<strong>全新的句子</strong>，必须从头解析、创建执行计划。</p><p><strong>用 </strong><code>PreparedStatement</code><strong>：</strong><br>只用写一次带 <code>?</code> 的框架。</p><pre><code class="language-java">String sql = "INSERT INTO log (message) VALUES (?)";
PreparedStatement pstmt = conn.prepareStatement(sql);
</code></pre><p>然后循环里只做一件事：<strong>换参数</strong>。</p><pre><code class="language-java">for (String msg : messages) {
    pstmt.setString(1, msg);
    pstmt.executeUpdate();
}
</code></pre><p>数据库收到框架后，<strong>解析一次，缓存计划</strong>。后面每次只收到“换了一个新值”的指令，直接套用缓存计划执行。</p>', 'unfamiliar', '2026-04-26 13:05:44.161644') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('83821faa-8a0d-421c-9002-fd930f5fc08f', '00000000-0000-0000-0000-000000000003', 'CONC_005', '189d9a2e-e6c9-4b5e-aa6e-8c6a6e829b76', NULL, 'Q_B2_001', '2026-04-13 12:13:03.51345', false, NULL, 0, 0, NULL, '{}', NULL, 'unfamiliar', '2026-04-13 12:13:07.169722') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('51fa309b-3a4b-4579-bf30-4e31a3939ac3', '00000000-0000-0000-0000-000000000003', 'CONC_010', '189d9a2e-e6c9-4b5e-aa6e-8c6a6e829b76', NULL, NULL, '2026-04-13 12:13:10.860604', false, NULL, 0, 0, NULL, '{}', NULL, 'unfamiliar', '2026-04-13 12:13:10.860604') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('31503579-cdd6-4ace-a68b-471f2f3037e6', '00000000-0000-0000-0000-000000000003', 'CONC_018', '675fd0ec-ce3e-46b7-8e3e-8ea0071a6f8b', NULL, NULL, '2026-04-05 04:33:45.920122', false, NULL, 69, 0, NULL, '{"chatted": true}', '<p><strong>ABAP 宏 (Macro) 完整代码示例</strong><br>基于参考材料，宏定义和调用如下：</p><pre><code class="language-abap">REPORT Z_DAILY_PROFIT.

DATA: MealProfit TYPE p, daily_profit TYPE p.

WRITE: /''Meal Name'', 15 ''Selling Price'', 30 ''Costs''.
WRITE: 38 ''Number of Meals sold'', 60 ''Meal Profit''.

* 宏定义开始
DEFINE get_meal_profit.
  WRITE / &amp;1 UNDER ''Meal Name''.           " &amp;1: 餐名参数
  WRITE: &amp;2 UNDER ''Selling Price'',        " &amp;2: 售价
         &amp;3 UNDER ''Costs'',                " &amp;3: 成本
         &amp;4 UNDER ''Number of Meals sold''. " &amp;4: 销售数量

  * 调用函数模块计算利润
  CALL FUNCTION ''Z_FM_MEAL_PROFIT''
    EXPORTING
      selling_price = &amp;2
      cost          = &amp;3
      quantity      = &amp;4
    IMPORTING
      profit        = MealProfit.

  IF SY-SUBRC EQ 1.
    WRITE ''Input error'' UNDER ''Meal Profit''.
  ELSEIF SY-SUBRC = 0.
    WRITE MealProfit UNDER ''Meal Profit''.  " 显示单餐利润
    daily_profit = daily_profit + MealProfit. " 累加到总利润
  ENDIF.
END-OF-DEFINITION. " 宏定义结束

* 宏调用（多次使用，避免重复代码）
get_meal_profit ''Donut''  ''22'' ''5''  ''150''.
get_meal_profit ''Burger'' ''45'' ''18'' ''80''.
get_meal_profit ''Coffee'' ''12'' ''3''  ''200''.

WRITE: / ''Daily Profit is:'', daily_profit.
</code></pre><hr><p><strong>ABAP 子程序 (Subroutine) 完整代码示例</strong><br>实现相同功能，但使用子程序：</p><pre><code class="language-abap">REPORT Z_DAILY_PROFIT_SUB.

DATA: MealProfit TYPE p, daily_profit TYPE p.

WRITE: /''Meal Name'', 15 ''Selling Price'', 30 ''Costs''.
WRITE: 38 ''Number of Meals sold'', 60 ''Meal Profit''.

* 主逻辑：调用子程序
PERFORM calculate_meal_profit USING ''Donut''  ''22'' ''5''  ''150''.
PERFORM calculate_meal_profit USING ''Burger'' ''45'' ''18'' ''80''.
PERFORM calculate_meal_profit USING ''Coffee'' ''12'' ''3''  ''200''.

WRITE: / ''Daily Profit is:'', daily_profit.

* 子程序定义
FORM calculate_meal_profit USING p_meal  TYPE c
                                 p_sell  TYPE p
                                 p_cost  TYPE p
                                 p_qty   TYPE i.
  WRITE / p_meal UNDER ''Meal Name''.
  WRITE: p_sell UNDER ''Selling Price'',
         p_cost UNDER ''Costs'',
         p_qty  UNDER ''Number of Meals sold''.

  CALL FUNCTION ''Z_FM_MEAL_PROFIT''
    EXPORTING
      selling_price = p_sell
      cost          = p_cost
      quantity      = p_qty
    IMPORTING
      profit        = MealProfit.

  IF SY-SUBRC EQ 1.
    WRITE ''Input error'' UNDER ''Meal Profit''.
  ELSEIF SY-SUBRC = 0.
    WRITE MealProfit UNDER ''Meal Profit''.
    daily_profit = daily_profit + MealProfit.
  ENDIF.
ENDFORM.
</code></pre><hr><p><strong>关键语法对比</strong></p><p>特性宏 (Macro)子程序 (Subroutine)<strong>定义</strong><code>DEFINE ... END-OF-DEFINITION.FORM ... ENDFORM.</code><strong>参数传递</strong>隐式：<code>&amp;1</code>, <code>&amp;2</code>, ...（文本替换）显式：<code>USING ...</code>（类型检查）<strong>调用</strong>直接写宏名 + 参数：<code>macro_name arg1 arg2PERFORM sub_name USING ...</code><strong>作用</strong>代码模板，编译前展开（无运行时开销）独立代码块，运行时调用（可调试）</p><p><strong>简单比喻：</strong></p><ul><li><p><strong>宏</strong> 像 <strong>复印机</strong>：把模板复印多份，每份填入不同数据。</p></li><li><p><strong>子程序</strong> 像 <strong>助手</strong>：你每次喊助手，他带着工具（参数）来执行任务。</p></li></ul><p></p>', 'unfamiliar', '2026-04-05 08:29:25.054315') ON CONFLICT DO NOTHING;
