INSERT INTO user_learn_later VALUES ('be493bb7-e3f0-4508-a8d5-b93d1e5833dd', '00000000-0000-0000-0000-000000000003', 'CONC_008', 'a36ed233-a8fb-4068-9f0e-2c32856c95df', NULL, 'Q_B2_004', '2026-04-15 06:48:43.608004', true, '2026-04-15 08:55:01.748523', 0, 0, NULL, '{}', NULL, 'mastered', '2026-04-15 08:55:01.748523') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('087caed5-ab05-4ec6-b916-30ba61b3cec8', '00000000-0000-0000-0000-000000000003', 'CONC_006', 'a36ed233-a8fb-4068-9f0e-2c32856c95df', NULL, 'Q_B2_003', '2026-04-15 06:45:26.010019', true, '2026-04-15 08:55:02.557505', 0, 0, NULL, '{}', NULL, 'mastered', '2026-04-15 08:55:02.557505') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('fdbb5e14-1f3f-4b71-b232-e4d6f50ef251', '00000000-0000-0000-0000-000000000003', 'CONC_005', '85cdccad-053a-4a01-990a-6265142dc053', NULL, NULL, '2026-04-13 12:23:58.620317', false, NULL, 13, 0, NULL, '{"chatted": true}', NULL, 'unfamiliar', '2026-04-13 12:34:38.998905') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('3cf9150f-f169-4928-a0e0-9f4970d6e5c0', '00000000-0000-0000-0000-000000000003', 'CONC_008', '675fd0ec-ce3e-46b7-8e3e-8ea0071a6f8b', NULL, 'Q_B2_004', '2026-04-05 04:11:44.685162', false, NULL, 50, 0, NULL, '{"chatted": true}', '<p>ERP breaks down<span style="color: rgb(248, 140, 140);"> </span><span style="color: rgb(230, 205, 40);">departmental silos</span>, <span style="color: rgb(230, 40, 40);">integrates cross-functional data and workflows</span>, and <span style="color: rgb(40, 72, 230);">provides a single source of truth</span> for decision-making.</p><p></p><p>SAP ERP (which runs on NetWeaver) is built around a set of integrated core modules. Common ones include:</p><ul><li><p><strong>Financial Accounting (FI)</strong></p></li><li><p><strong>Controlling (CO)</strong></p></li><li><p><strong>Sales and Distribution (SD)</strong></p></li><li><p><strong>Materials Management (MM)</strong></p></li><li><p><strong>Production Planning (PP)</strong></p></li><li><p><strong>Human Resources (HR/HCM)</strong></p></li></ul><p>The key concept from the material is <strong>integration</strong>. These modules aren''t separate silos; they work together to support <strong>cross-functional processes</strong>, which is why ERP is so important for big companies.</p><p></p><p></p>', 'unfamiliar', '2026-04-05 09:47:07.865678') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('12843089-0a4a-442f-a2a8-24dd064bb737', '00000000-0000-0000-0000-000000000003', 'CONC_004', '675fd0ec-ce3e-46b7-8e3e-8ea0071a6f8b', NULL, 'Q_B1_001', '2026-04-05 03:42:52.56263', true, '2026-04-15 07:41:59.20359', 330, 1, '2026-04-05 08:34:31.158689', '{}', '', 'mastered', '2026-04-15 07:41:59.20359') ON CONFLICT DO NOTHING;
INSERT INTO user_learn_later VALUES ('8042a8bb-1e54-4bc3-9ace-a810809691e2', '00000000-0000-0000-0000-000000000003', 'CONC_007', 'c5a46f88-dd35-48eb-8c6c-c0b596babb42', NULL, 'Q_B2_005', '2026-04-01 16:19:04.328395', false, NULL, 20, 0, NULL, '{}', '<p><strong>Key takeaway:</strong></p><ul><li><p><span style="color: rgb(255, 38, 0);"><strong>doGet()</strong> is for retrieving data.</span></p></li><li><p><span style="color: rgb(255, 147, 0);">Information is visible in the URL</span> (like <code>?q=...</code>).</p></li><li><p>Good for bookmarks or sharing links.</p></li></ul><p><strong>Key takeaway:</strong></p><ul><li><p><strong>doPost()</strong> is for sending data to be processed or stored.</p></li><li><p>Information is hidden in the request body.</p></li><li><p>Used for sensitive data (passwords, credit cards) or large data uploads.</p></li></ul><p></p>', 'unfamiliar', '2026-04-15 10:17:09.837528') ON CONFLICT DO NOTHING;
